fn translateConfigKeyValue(kv: []const u8) []const u8 {
    // Translate -c key=value for git 2.43 compat
    // merge.stat=diffstat → merge.stat=true
    // merge.stat=compact → merge.stat=true
    // status.showuntrackedfiles=false → status.showuntrackedfiles=no
    // status.showuntrackedfiles=true → status.showuntrackedfiles=normal
    // help.autocorrect=show → help.autocorrect=0
    // help.autocorrect=immediate → help.autocorrect=-1
    // help.autocorrect=never → help.autocorrect=0
    // help.autocorrect=prompt → help.autocorrect=0
    if (std.ascii.startsWithIgnoreCase(kv, "merge.stat=")) {
        const val = kv["merge.stat=".len..];
        if (std.mem.eql(u8, val, "diffstat") or std.mem.eql(u8, val, "compact")) {
            return "merge.stat=true";
        }
    }
    if (std.ascii.startsWithIgnoreCase(kv, "status.showuntrackedfiles=")) {
        const val = kv["status.showuntrackedfiles=".len..];
        if (std.mem.eql(u8, val, "false") or std.mem.eql(u8, val, "0")) {
            return "status.showuntrackedfiles=no";
        } else if (std.mem.eql(u8, val, "true") or std.mem.eql(u8, val, "1")) {
            return "status.showuntrackedfiles=normal";
        }
    }
    if (std.ascii.startsWithIgnoreCase(kv, "help.autocorrect=")) {
        const val = kv["help.autocorrect=".len..];
        if (std.mem.eql(u8, val, "show") or
            std.mem.eql(u8, val, "false") or std.mem.eql(u8, val, "no") or
            std.mem.eql(u8, val, "off") or
            std.mem.eql(u8, val, "never") or std.mem.eql(u8, val, "prompt")) {
            return "help.autocorrect=0";
        } else if (std.mem.eql(u8, val, "immediate")) {
            return "help.autocorrect=-1";
        }
    }
    return kv;
}

fn translateConfigValues(allocator: std.mem.Allocator, all_args: [][]const u8) ![][]const u8 {
    // Translate config values that newer git (2.46+) accepts but older git (2.43) doesn't.
    // E.g., status.showuntrackedfiles: false→no, true→normal, 0→no, 1→normal
    // Also: advice.statusHints: same treatment
    var new_args = try allocator.alloc([]const u8, all_args.len);
    @memcpy(new_args, all_args);
    
    // Find the config key and value positions
    // Pattern: git [global-flags] config [flags] <key> <value>
    var i: usize = 0;
    var found_config = false;
    var key_idx: ?usize = null;
    var val_idx: ?usize = null;
    while (i < all_args.len) : (i += 1) {
        const arg = all_args[i];
        if (!found_config) {
            if (std.mem.eql(u8, arg, "config")) {
                found_config = true;
            }
            continue;
        }
        // After "config", skip flags
        if (std.mem.startsWith(u8, arg, "-")) continue;
        if (key_idx == null) {
            key_idx = i;
        } else if (val_idx == null) {
            val_idx = i;
            break;
        }
    }
    
    if (key_idx != null and val_idx != null) {
        const key = std.ascii.lowerString(
            try allocator.alloc(u8, all_args[key_idx.?].len),
            all_args[key_idx.?],
        );
        defer allocator.free(key);
        const val = all_args[val_idx.?];
        
        // Translate boolean-style values for keys that expect no/normal/all
        if (std.mem.eql(u8, key, "status.showuntrackedfiles")) {
            if (std.mem.eql(u8, val, "false") or std.mem.eql(u8, val, "0")) {
                new_args[val_idx.?] = "no";
            } else if (std.mem.eql(u8, val, "true") or std.mem.eql(u8, val, "1")) {
                new_args[val_idx.?] = "normal";
            }
        }
        // merge.stat: git 2.46+ supports "diffstat"/"compact", older git only boolean
        if (std.mem.eql(u8, key, "merge.stat")) {
            if (std.mem.eql(u8, val, "diffstat") or std.mem.eql(u8, val, "compact")) {
                new_args[val_idx.?] = "true";
            }
        }
        // help.autocorrect: git 2.47+ supports string values; git 2.43 only numeric
        // false/no/off/show/never/prompt → 0 (show candidates, don't run)
        // immediate → -1 (run immediately)
        if (std.mem.eql(u8, key, "help.autocorrect")) {
            if (std.mem.eql(u8, val, "show") or
                std.mem.eql(u8, val, "false") or std.mem.eql(u8, val, "no") or
                std.mem.eql(u8, val, "off") or
                std.mem.eql(u8, val, "never") or std.mem.eql(u8, val, "prompt")) {
                new_args[val_idx.?] = "0";
            } else if (std.mem.eql(u8, val, "immediate")) {
                new_args[val_idx.?] = "-1";
            }
        }
    }
    
    return new_args;
}




fn translateCommitFlags(allocator: std.mem.Allocator, all_args: [][]const u8, command_index: usize) ![][]const u8 {
    // Translate commit flags for git 2.43 compat
    // Handle --template ":(optional)path" by stripping the prefix if file doesn't exist,
    // or using the real path if it does.
    var new_args = std.array_list.Managed([]const u8).init(allocator);
    var i: usize = 0;
    while (i < all_args.len) : (i += 1) {
        if (i > command_index) {
            // Check for --template with :(optional) prefix
            if (std.mem.eql(u8, all_args[i], "--template") and i + 1 < all_args.len) {
                const template_path = all_args[i + 1];
                if (std.mem.startsWith(u8, template_path, ":(optional)")) {
                    const real_path = template_path[":(optional)".len..];
                    // Check if file exists
                    const file_exists = blk: {
                        std.fs.cwd().access(real_path, .{}) catch break :blk false;
                        break :blk true;
                    };
                    if (file_exists) {
                        try new_args.append(all_args[i]);
                        try new_args.append(real_path);
                    }
                    // else: skip both --template and the path (optional = ignore if missing)
                    i += 1;
                    continue;
                }
            }
            // Check for --template=:(optional)path form
            if (std.mem.startsWith(u8, all_args[i], "--template=:(optional)")) {
                const real_path = all_args[i]["--template=:(optional)".len..];
                const file_exists = blk: {
                    std.fs.cwd().access(real_path, .{}) catch break :blk false;
                    break :blk true;
                };
                if (file_exists) {
                    const new_flag = try std.fmt.allocPrint(allocator, "--template={s}", .{real_path});
                    try new_args.append(new_flag);
                }
                // else: skip (optional = ignore if missing)
                continue;
            }
        }
        try new_args.append(all_args[i]);
    }
    return new_args.toOwnedSlice();
}



fn translateStderrLine(allocator: std.mem.Allocator, line: []const u8) ![]const u8 {
    // Translate git 2.43 error messages to git 2.46+ format
    
    // "fatal: unknown style 'X' given for 'merge.conflictstyle'" → "error: unknown conflict style 'X'"
    if (std.mem.startsWith(u8, line, "fatal: unknown style '")) {
        if (std.mem.indexOf(u8, line, "' given for 'merge.conflictstyle'")) |end_pos| {
            const style_start = "fatal: unknown style '".len;
            const style = line[style_start..end_pos];
            return try std.fmt.allocPrint(allocator, "error: unknown conflict style '{s}'", .{style});
        }
    }
    
    // "fatal: unable to read tree HASH" → "fatal: unable to read tree (HASH)"
    if (std.mem.startsWith(u8, line, "fatal: unable to read tree ")) {
        const rest = line["fatal: unable to read tree ".len..];
        if (rest.len >= 40 and !std.mem.startsWith(u8, rest, "(")) {
            // Check if rest is a hex hash
            var is_hash = true;
            for (rest[0..40]) |c| {
                if (!((c >= '0' and c <= '9') or (c >= 'a' and c <= 'f'))) {
                    is_hash = false;
                    break;
                }
            }
            if (is_hash) {
                return try std.fmt.allocPrint(allocator, "fatal: unable to read tree ({s})", .{rest});
            }
        }
    }

    // "error: core.commentChar should only be one ASCII character" →
    // In git 2.46+, core.commentChar supports multi-byte via core.commentString
    // Just pass through for now
    
    // "fatal: '--ours/--theirs' cannot be used with switching branches" →
    // When used without pathspec: "error: --ours/--theirs needs the paths to check out"
    // Note: this is context-dependent; we'd need to know if paths were given
    
    return try allocator.dupe(u8, line);
}

fn translateStderr(allocator: std.mem.Allocator, stderr_data: []const u8) ![]const u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    var iter = std.mem.splitScalar(u8, stderr_data, '\n');
    var first = true;
    while (iter.next()) |line| {
        if (!first) try result.append('\n');
        first = false;
        const translated = try translateStderrLine(allocator, line);
        try result.appendSlice(translated);
        if (translated.ptr != line.ptr) allocator.free(translated);
    }
    return result.toOwnedSlice();
}



fn findUntrackedFiles(allocator: std.mem.Allocator, repo_root: []const u8, index: *const index_mod.Index, gitignore: *const gitignore_mod.GitIgnore, platform_impl: *const platform_mod.Platform) !std.array_list.Managed([]u8) {
    var untracked_files = std.array_list.Managed([]u8).init(allocator);
    
    // Create a set of tracked file paths for fast lookup
    var tracked_files = std.StringHashMap(void).init(allocator);
    defer tracked_files.deinit();
    
    for (index.entries.items) |entry| {
        try tracked_files.put(entry.path, {});
    }
    
    // Recursively scan directory for files
    scanDirectoryForUntrackedFiles(allocator, repo_root, "", &untracked_files, &tracked_files, gitignore, platform_impl) catch {
        // If scanning fails, return empty list
        for (untracked_files.items) |file| {
            allocator.free(file);
        }
        untracked_files.clearAndFree();
    };
    
    return untracked_files;
}

fn scanDirectoryForUntrackedFiles(
    allocator: std.mem.Allocator,
    repo_root: []const u8,
    relative_path: []const u8,
    untracked_files: *std.array_list.Managed([]u8),
    tracked_files: *const std.StringHashMap(void),
    gitignore: *const gitignore_mod.GitIgnore,
    platform_impl: *const platform_mod.Platform,
) !void {
    const full_path = if (relative_path.len == 0)
        try allocator.dupe(u8, repo_root)
    else
        try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, relative_path });
    defer allocator.free(full_path);

    // Try to open directory
    var dir = std.fs.cwd().openDir(full_path, .{ .iterate = true }) catch |err| switch (err) {
        error.NotDir, error.AccessDenied, error.FileNotFound => return,
        else => return err,
    };
    defer dir.close();

    var iterator = dir.iterate();
    while (iterator.next() catch null) |entry| {
        // Skip .git directory
        if (std.mem.eql(u8, entry.name, ".git")) continue;
        
        const entry_relative_path = if (relative_path.len == 0)
            try allocator.dupe(u8, entry.name)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ relative_path, entry.name });
        defer allocator.free(entry_relative_path);
        
        // Check if ignored
        if (gitignore.isIgnored(entry_relative_path)) continue;
        
        switch (entry.kind) {
            .file, .sym_link => {
                // Check if file/symlink is tracked
                if (!tracked_files.contains(entry_relative_path)) {
                    try untracked_files.append(try allocator.dupe(u8, entry_relative_path));
                }
            },
            .directory => {
                // Check for nested git repo
                const dotgit_full = try std.fmt.allocPrint(allocator, "{s}/{s}/.git", .{ repo_root, entry_relative_path });
                defer allocator.free(dotgit_full);
                if (platform_impl.fs.exists(dotgit_full) catch false) continue;

                // Recursively scan subdirectory
                scanDirectoryForUntrackedFiles(
                    allocator,
                    repo_root,
                    entry_relative_path,
                    untracked_files,
                    tracked_files,
                    gitignore,
                    platform_impl,
                ) catch continue;
            },
            else => continue,
        }
    }
}

/// Match a pathspec against a path, using global pathspec flags.
/// Used by ls-files with --glob-pathspecs, --icase-pathspecs, etc.
///
/// Git pathspec matching behavior:
/// - Default (no flags): glob matching where * matches everything including /
/// - --glob-pathspecs: glob matching where * does NOT match / (WM_PATHNAME)
/// - --literal-pathspecs: no glob matching, literal/prefix only
/// - --noglob-pathspecs: same as literal
/// - --icase-pathspecs: case-insensitive matching
fn matchPathspec(path: []const u8, pathspec: []const u8) bool {
    const use_literal = global_literal_pathspecs or global_noglob_pathspecs;
    const use_icase = global_icase_pathspecs;

    // Always try exact match and prefix match first (literal comparison)
    if (use_icase) {
        if (eqlIgnoreCase(path, pathspec)) return true;
        if (path.len > pathspec.len and path[pathspec.len] == '/' and
            eqlIgnoreCase(path[0..pathspec.len], pathspec)) return true;
    } else {
        if (std.mem.eql(u8, path, pathspec)) return true;
        if (std.mem.startsWith(u8, path, pathspec) and path.len > pathspec.len and path[pathspec.len] == '/') return true;
    }

    if (use_literal) return false;

    // Glob mode (default or --glob-pathspecs)
    var flags: u32 = 0;
    if (global_glob_pathspecs) flags |= wildmatch_mod.WM_PATHNAME;
    if (use_icase) flags |= wildmatch_mod.WM_CASEFOLD;

    // Direct wildmatch
    if (wildmatch_mod.wildmatch(pathspec, path, flags) == wildmatch_mod.WM_MATCH) return true;

    // In pathspec context with --glob-pathspecs, trailing ** after a literal
    // prefix (e.g., "foo**") matches everything under the prefix, equivalent
    // to "foo/**". Only applies when the prefix is purely literal (no globs).
    if ((flags & wildmatch_mod.WM_PATHNAME) != 0 and pathspec.len >= 2 and
        std.mem.endsWith(u8, pathspec, "**"))
    {
        const prefix = pathspec[0 .. pathspec.len - 2];
        // Only apply if prefix has no glob characters
        if (std.mem.indexOfAny(u8, prefix, "*?[") == null) {
            const new_pattern_len = prefix.len + 3; // prefix + "/**"
            if (new_pattern_len <= 4096) {
                var buf: [4096]u8 = undefined;
                @memcpy(buf[0..prefix.len], prefix);
                buf[prefix.len] = '/';
                buf[prefix.len + 1] = '*';
                buf[prefix.len + 2] = '*';
                const new_pattern = buf[0..new_pattern_len];
                if (wildmatch_mod.wildmatch(new_pattern, path, flags) == wildmatch_mod.WM_MATCH) return true;
            }
        }
    }

    return false;
}

fn eqlIgnoreCase(a: []const u8, b: []const u8) bool {
    if (a.len != b.len) return false;
    for (a, b) |ca, cb| {
        const la: u8 = if (ca >= 'A' and ca <= 'Z') ca + 32 else ca;
        const lb: u8 = if (cb >= 'A' and cb <= 'Z') cb + 32 else cb;
        if (la != lb) return false;
    }
    return true;
}

/// Check if a pathspec (which may contain globs) matches a path.
fn pathspecMatchesPath(pathspec: []const u8, path: []const u8, is_dir: bool) bool {
    if (std.mem.eql(u8, pathspec, path)) return true;
    const ps_trimmed = if (std.mem.endsWith(u8, pathspec, "/")) pathspec[0 .. pathspec.len - 1] else pathspec;
    const path_trimmed = if (std.mem.endsWith(u8, path, "/")) path[0 .. path.len - 1] else path;
    if (std.mem.eql(u8, ps_trimmed, path_trimmed)) return true;
    if (std.mem.startsWith(u8, path_trimmed, ps_trimmed) and path_trimmed.len > ps_trimmed.len and path_trimmed[ps_trimmed.len] == '/') return true;
    if (std.mem.startsWith(u8, ps_trimmed, path_trimmed) and ps_trimmed.len > path_trimmed.len and ps_trimmed[path_trimmed.len] == '/') return true;
    const has_glob = std.mem.indexOfAny(u8, pathspec, "*?") != null;
    if (has_glob) {
        if (globMatch(path, pathspec)) return true;
        if (is_dir) {
            const tp = if (std.mem.endsWith(u8, path, "/")) path[0 .. path.len - 1] else path;
            var glob_start: usize = 0;
            while (glob_start < pathspec.len) : (glob_start += 1) {
                if (pathspec[glob_start] == '*' or pathspec[glob_start] == '?') break;
            }
            const pre_glob = pathspec[0..glob_start];
            if (std.mem.lastIndexOfScalar(u8, pre_glob, '/')) |last_slash| {
                const dir_part = pathspec[0..last_slash];
                if (std.mem.eql(u8, dir_part, tp) or std.mem.startsWith(u8, dir_part, tp) or
                    std.mem.startsWith(u8, tp, dir_part) or globMatch(tp, dir_part))
                    return true;
            } else return true;
        }
    }
    return false;
}

fn pathspecIsGlob(pathspec: []const u8) bool {
    return std.mem.indexOfAny(u8, pathspec, "*?[") != null;
}

/// Find untracked directory entries for --directory mode.
fn findUntrackedDirEntries(
    allocator: std.mem.Allocator,
    repo_root: []const u8,
    relative_path: []const u8,
    results: *std.array_list.Managed([]u8),
    index: *const index_mod.Index,
    gitignore: *const gitignore_mod.GitIgnore,
    no_empty_directory: bool,
    pathspecs: []const []const u8,
    platform_impl: *const platform_mod.Platform,
) !void {
    const full_path = if (relative_path.len == 0)
        try allocator.dupe(u8, repo_root)
    else
        try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, relative_path });
    defer allocator.free(full_path);

    var dir = std.fs.cwd().openDir(full_path, .{ .iterate = true }) catch return;
    defer dir.close();

    var tracked_dirs = std.StringHashMap(void).init(allocator);
    defer tracked_dirs.deinit();
    var tracked_files_set = std.StringHashMap(void).init(allocator);
    defer tracked_files_set.deinit();
    for (index.entries.items) |entry| {
        try tracked_files_set.put(entry.path, {});
        var j: usize = 0;
        while (j < entry.path.len) : (j += 1) {
            if (entry.path[j] == '/') try tracked_dirs.put(entry.path[0..j], {});
        }
    }

    var iterator = dir.iterate();
    while (iterator.next() catch null) |entry| {
        if (std.mem.eql(u8, entry.name, ".git")) continue;
        const entry_relative_path = if (relative_path.len == 0)
            try allocator.dupe(u8, entry.name)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ relative_path, entry.name });
        defer allocator.free(entry_relative_path);

        if (gitignore.isIgnored(entry_relative_path)) continue;

        if (pathspecs.len > 0) {
            var relevant = false;
            for (pathspecs) |ps| {
                if (pathspecMatchesPath(ps, entry_relative_path, entry.kind == .directory)) { relevant = true; break; }
                if (entry.kind == .directory) {
                    const dp = try std.fmt.allocPrint(allocator, "{s}/", .{entry_relative_path});
                    defer allocator.free(dp);
                    if (pathspecMatchesPath(ps, dp, true)) { relevant = true; break; }
                }
            }
            if (!relevant) continue;
        }

        switch (entry.kind) {
            .file, .sym_link => {
                if (!tracked_files_set.contains(entry_relative_path)) {
                    try results.append(try allocator.dupe(u8, entry_relative_path));
                }
            },
            .directory => {
                const dotgit_full = try std.fmt.allocPrint(allocator, "{s}/{s}/.git", .{ repo_root, entry_relative_path });
                defer allocator.free(dotgit_full);
                if (platform_impl.fs.exists(dotgit_full) catch false) continue;

                if (tracked_dirs.contains(entry_relative_path)) {
                    try findUntrackedDirEntries(allocator, repo_root, entry_relative_path, results, index, gitignore, no_empty_directory, pathspecs, platform_impl);
                } else {
                    var need_recurse = false;
                    var glob_matches_dir = false;
                    if (pathspecs.len > 0) {
                        const dp = try std.fmt.allocPrint(allocator, "{s}/", .{entry_relative_path});
                        defer allocator.free(dp);
                        for (pathspecs) |ps| {
                            if (std.mem.startsWith(u8, ps, dp) and ps.len > dp.len) { need_recurse = true; break; }
                            if (pathspecIsGlob(ps)) {
                                if (globMatch(entry_relative_path, ps)) { glob_matches_dir = true; break; }
                                if (pathspecMatchesPath(ps, entry_relative_path, true)) { need_recurse = true; break; }
                            }
                        }
                    }
                    if (glob_matches_dir) {
                        try results.append(try std.fmt.allocPrint(allocator, "{s}/", .{entry_relative_path}));
                    } else if (need_recurse) {
                        try findUntrackedDirEntries(allocator, repo_root, entry_relative_path, results, index, gitignore, no_empty_directory, pathspecs, platform_impl);
                    } else {
                        if (no_empty_directory) {
                            const sf = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry_relative_path });
                            defer allocator.free(sf);
                            var sd = std.fs.cwd().openDir(sf, .{ .iterate = true }) catch continue;
                            defer sd.close();
                            var si = sd.iterate();
                            if ((si.next() catch null) == null) continue;
                        }
                        try results.append(try std.fmt.allocPrint(allocator, "{s}/", .{entry_relative_path}));
                    }
                }
            },
            else => {},
        }
    }
}

fn showUsage(platform_impl: *const platform_mod.Platform) !void {
    const target_info = switch (@import("builtin").target.os.tag) {
        .wasi => " (WASI)",
        .freestanding => " (Browser)",
        else => "",
    };
    
    try platform_impl.writeStdout("usage: ziggit <command> [<args>]\n\n");
    try platform_impl.writeStdout("These are common ziggit commands used in various situations:\n\n");
    try platform_impl.writeStdout("start a working area (see also: ziggit help tutorial)\n");
    try platform_impl.writeStdout("   init       Create an empty Git repository or reinitialize an existing one\n\n");
    try platform_impl.writeStdout("work on the current change (see also: ziggit help everyday)\n");
    try platform_impl.writeStdout("   add        Add file contents to the index\n");
    try platform_impl.writeStdout("   status     Show the working tree status\n");
    try platform_impl.writeStdout("   commit     Record changes to the repository\n");
    try platform_impl.writeStdout("   log        Show commit logs\n");
    try platform_impl.writeStdout("   diff       Show changes between commits, commit and working tree, etc\n");
    
    if (@import("builtin").target.os.tag != .freestanding) {
        try platform_impl.writeStdout("\n");
        try platform_impl.writeStdout("collaborate (see also: ziggit help workflows)\n");
        try platform_impl.writeStdout("   fetch      Download objects and refs from another repository\n");
        try platform_impl.writeStdout("   pull       Fetch from and integrate with another repository or a local branch\n");
        try platform_impl.writeStdout("   push       Update remote refs along with associated objects\n");
    }
    
    const fallback_info = if (build_options.enable_git_fallback and @import("builtin").target.os.tag != .freestanding) 
        "\nUnimplemented commands are transparently forwarded to git when available.\n"
    else 
        "";
        
    const suffix_msg = std.fmt.allocPrint(std.heap.page_allocator, "\nziggit{s} - A modern version control system written in Zig\n\nDrop-in replacement for git commands - use 'ziggit' instead of 'git'\nCompatible .git directory format, works with existing git repositories{s}\nOptions:\n  --version, -v       Show version information\n  --version-info      Show detailed version and build information\n  --help, -h          Show this help message\n", .{target_info, fallback_info}) catch return;
    defer std.heap.page_allocator.free(suffix_msg);
    try platform_impl.writeStdout(suffix_msg);
}

fn cmdInit(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform, global_bare: bool) !void {
    var bare = global_bare;
    var template_dir: ?[]const u8 = null;
    var template_dir_set = false;
    var work_dir: ?[]const u8 = null;
    var initial_branch: ?[]const u8 = null;
    var quiet = false;
    var separate_git_dir: ?[]const u8 = null;
    var shared: ?[]const u8 = null;
    
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--bare")) {
            bare = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.startsWith(u8, arg, "--template=")) {
            template_dir = arg["--template=".len..];
            template_dir_set = true;
        } else if (std.mem.eql(u8, arg, "--template")) {
            template_dir = args.next();
            template_dir_set = true;
        } else if (std.mem.startsWith(u8, arg, "--initial-branch=")) {
            initial_branch = arg["--initial-branch=".len..];
        } else if (std.mem.eql(u8, arg, "--initial-branch") or std.mem.eql(u8, arg, "-b")) {
            initial_branch = args.next();
        } else if (std.mem.startsWith(u8, arg, "--separate-git-dir=")) {
            separate_git_dir = arg["--separate-git-dir=".len..];
        } else if (std.mem.eql(u8, arg, "--separate-git-dir")) {
            separate_git_dir = args.next();
        } else if (std.mem.startsWith(u8, arg, "--shared=")) {
            shared = arg["--shared=".len..];
        } else if (std.mem.eql(u8, arg, "--shared")) {
            shared = args.next();
        } else if (std.mem.startsWith(u8, arg, "--object-format=") or
                   std.mem.startsWith(u8, arg, "--ref-format=")) {
            // Silently accept for now (only sha1/files supported)
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            work_dir = arg;
        }
    }
    
    // Check GIT_WORK_TREE
    const env_work_tree = std.process.getEnvVarOwned(allocator, "GIT_WORK_TREE") catch null;
    defer if (env_work_tree) |w| allocator.free(w);
    
    // Check GIT_DIR environment variable
    const env_git_dir = std.process.getEnvVarOwned(allocator, "GIT_DIR") catch null;
    defer if (env_git_dir) |g| allocator.free(g);
    
    if (env_work_tree != null) {
        if (bare) {
            try platform_impl.writeStderr("fatal: GIT_WORK_TREE (or --work-tree=<directory>) not allowed in combination with '--(bare|shared)'\n");
            std.process.exit(128);
        }
        // GIT_WORK_TREE + GIT_DIR together is OK (sets up worktree in separate location)
        // But GIT_WORK_TREE without GIT_DIR during init should fail
        if (env_git_dir == null) {
            try platform_impl.writeStderr("fatal: GIT_WORK_TREE (or --work-tree=<directory>) not allowed without GIT_DIR being set\n");
            std.process.exit(128);
        }
    }
    
    // Check --separate-git-dir + --bare incompatibility
    if (separate_git_dir != null and bare) {
        try platform_impl.writeStderr("fatal: options '--separate-git-dir' and '--bare' cannot be used together\n");
        std.process.exit(128);
    }
    
    // Check --separate-git-dir + implicit bare (GIT_DIR=.) incompatibility 
    if (separate_git_dir != null and env_git_dir != null) {
        // When GIT_DIR is set, it's implicitly bare-like, incompatible with --separate-git-dir
        try platform_impl.writeStderr("fatal: --separate-git-dir incompatible with bare repository\n");
        std.process.exit(128);
    }
    
    // If GIT_DIR is set, use it as the git directory instead of default
    const target_dir = work_dir orelse ".";
    
    if (env_git_dir) |git_dir_env| {
        // When --bare and a positional directory is given, the positional arg overrides GIT_DIR
        if (bare and work_dir != null) {
            try initRepository(target_dir, bare, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
        } else {
            // Use GIT_DIR as the git directory
            try initRepositoryWithGitDir(target_dir, git_dir_env, bare, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
        }
    } else if (separate_git_dir) |sep_dir| {
        // Create repo with separate git dir
        try initRepositoryWithSeparateGitDir(target_dir, sep_dir, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
    } else {
        try initRepository(target_dir, bare, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
    }
}

fn copyTemplateDir(git_dir: []const u8, template_path: []const u8, allocator: std.mem.Allocator) !void {
    // Recursively copy template directory contents to git_dir
    var dir = std.fs.cwd().openDir(template_path, .{ .iterate = true }) catch return;
    defer dir.close();

    var walker = dir.walk(allocator) catch return;
    defer walker.deinit();

    while (walker.next() catch null) |entry| {
        const dest_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, entry.path });
        defer allocator.free(dest_path);

        switch (entry.kind) {
            .directory => {
                std.fs.cwd().makePath(dest_path) catch {};
            },
            .file => {
                // Only copy if destination doesn't exist
                if (std.fs.cwd().access(dest_path, .{})) |_| {
                    continue; // Don't overwrite existing files
                } else |_| {}

                const src_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ template_path, entry.path });
                defer allocator.free(src_path);
                std.fs.cwd().copyFile(src_path, std.fs.cwd(), dest_path, .{}) catch {};
            },
            else => {},
        }
    }
}

fn initRepositoryWithGitDir(work_dir: []const u8, git_dir_path: []const u8, bare: bool, template_dir: ?[]const u8, template_dir_set: bool, initial_branch: ?[]const u8, quiet: bool, shared: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Check if GIT_WORK_TREE is also set  
    const env_work_tree = std.process.getEnvVarOwned(allocator, "GIT_WORK_TREE") catch null;
    defer if (env_work_tree) |w| allocator.free(w);
    
    // When both GIT_DIR and GIT_WORK_TREE are set, create non-bare repo with worktree
    if (env_work_tree) |wt| {
        _ = work_dir;
        try initRepositoryInDir(git_dir_path, false, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
        // Set core.worktree in config
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_dir_path});
        defer allocator.free(config_path);
        if (platform_impl.fs.readFile(allocator, config_path)) |existing| {
            defer allocator.free(existing);
            // Insert worktree before the closing of [core] section
            const abs_wt = std.fs.cwd().realpathAlloc(allocator, wt) catch try allocator.dupe(u8, wt);
            defer allocator.free(abs_wt);
            const new_config = try std.fmt.allocPrint(allocator, "{s}\tworktree = {s}\n", .{ existing, abs_wt });
            defer allocator.free(new_config);
            try platform_impl.fs.writeFile(config_path, new_config);
        } else |_| {}
    } else {
        _ = work_dir;
        // When GIT_DIR is set without GIT_WORK_TREE, detect bare
        const ib = !std.mem.eql(u8, git_dir_path, ".git") and !std.mem.endsWith(u8, git_dir_path, "/.git"); try initRepositoryInDir(git_dir_path, bare or ib, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
    }
}

fn initRepositoryWithSeparateGitDir(work_dir: []const u8, git_dir_path: []const u8, template_dir: ?[]const u8, template_dir_set: bool, initial_branch: ?[]const u8, quiet: bool, shared: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Create the git directory
    try initRepositoryInDir(git_dir_path, false, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
    
    // Create the work tree directory
    createDirectoryRecursive(work_dir, platform_impl, allocator) catch |err| switch (err) {
        error.AlreadyExists => {},
        else => return err,
    };
    
    // Write .git file in work_dir pointing to the separate git dir
    const abs_git_dir = std.fs.cwd().realpathAlloc(allocator, git_dir_path) catch try allocator.dupe(u8, git_dir_path);
    defer allocator.free(abs_git_dir);
    
    const git_file_path = try std.fmt.allocPrint(allocator, "{s}/.git", .{work_dir});
    defer allocator.free(git_file_path);
    const git_file_content = try std.fmt.allocPrint(allocator, "gitdir: {s}\n", .{abs_git_dir});
    defer allocator.free(git_file_content);
    try platform_impl.fs.writeFile(git_file_path, git_file_content);
    
    // Set core.worktree in the git dir config
    const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_dir_path});
    defer allocator.free(config_path);
    const abs_work = std.fs.cwd().realpathAlloc(allocator, work_dir) catch try allocator.dupe(u8, work_dir);
    defer allocator.free(abs_work);
    
    // Read existing config and add worktree
    if (platform_impl.fs.readFile(allocator, config_path)) |existing| {
        defer allocator.free(existing);
        // Add worktree to core section
        const new_config = try std.fmt.allocPrint(allocator, "{s}\tworktree = {s}\n", .{ existing, abs_work });
        defer allocator.free(new_config);
        try platform_impl.fs.writeFile(config_path, new_config);
    } else |_| {}
}

fn initRepositoryInDir(git_dir: []const u8, bare: bool, template_dir: ?[]const u8, template_dir_set: bool, initial_branch: ?[]const u8, quiet: bool, shared: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Create the directory structure
    createDirectoryRecursive(git_dir, platform_impl, allocator) catch |err| switch (err) {
        error.AlreadyExists => {},
        else => return err,
    };
    
    // Check if already exists
    const head_check_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_dir});
    defer allocator.free(head_check_path);
    
    if (platform_impl.fs.exists(head_check_path) catch false) {
        const abs_path = std.fs.cwd().realpathAlloc(allocator, git_dir) catch try allocator.dupe(u8, git_dir);
        defer allocator.free(abs_path);
        if (initial_branch != null) {
            const warn_msg = try std.fmt.allocPrint(allocator, "warning: re-init: ignored --initial-branch={s}\n", .{initial_branch.?});
            defer allocator.free(warn_msg);
            try platform_impl.writeStderr(warn_msg);
        }
        if (!quiet) {
            const msg = try std.fmt.allocPrint(allocator, "Reinitialized existing Git repository in {s}/\n", .{abs_path});
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
        return;
    }
    
    // Determine effective template to decide which dirs to create
    const env_template_dir = std.process.getEnvVarOwned(allocator, "GIT_TEMPLATE_DIR") catch null;
    defer if (env_template_dir) |et| allocator.free(et);
    const use_templates = if (template_dir_set)
        (template_dir != null and template_dir.?.len > 0)
    else if (env_template_dir) |et|
        et.len > 0
    else
        true; // default: use templates

    // Create core subdirectories (always created)
    const core_subdirs = [_][]const u8{
        "objects", "objects/info", "objects/pack", "refs", "refs/heads", "refs/tags",
    };
    for (core_subdirs) |subdir| {
        const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, subdir });
        defer allocator.free(full_path);
        std.fs.cwd().makePath(full_path) catch {};
    }
    // Create template-dependent subdirectories only when templates are in use
    if (use_templates) {
        const template_subdirs = [_][]const u8{ "hooks", "info" };
        for (template_subdirs) |subdir| {
            const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, subdir });
            defer allocator.free(full_path);
            std.fs.cwd().makePath(full_path) catch {};
        }
    }
    
    // Create HEAD
    const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_dir});
    defer allocator.free(head_path);
    const default_branch = if (initial_branch) |ib|
        try allocator.dupe(u8, ib)
    else blk: {
        // Check GIT_TEST_DEFAULT_INITIAL_BRANCH_NAME (non-empty means use it)
        if (std.process.getEnvVarOwned(allocator, "GIT_TEST_DEFAULT_INITIAL_BRANCH_NAME") catch null) |env_val| {
            if (env_val.len > 0) break :blk env_val;
            allocator.free(env_val);
        }
        // Check init.defaultBranch from global config
        const home_dir = std.process.getEnvVarOwned(allocator, "HOME") catch null;
        defer if (home_dir) |h| allocator.free(h);
        if (home_dir) |home| {
            const global_config_path2 = try std.fmt.allocPrint(allocator, "{s}/.gitconfig", .{home});
            defer allocator.free(global_config_path2);
            if (platform_impl.fs.readFile(allocator, global_config_path2)) |gcfg| {
                defer allocator.free(gcfg);
                if (parseConfigValue(gcfg, "init.defaultbranch", allocator) catch null) |db_val| {
                    if (db_val.len > 0) break :blk db_val;
                    allocator.free(db_val);
                }
            } else |_| {}
            // Also check XDG config
            const xdg_config = std.process.getEnvVarOwned(allocator, "XDG_CONFIG_HOME") catch null;
            defer if (xdg_config) |x| allocator.free(x);
            const xdg_base = xdg_config orelse home;
            const xdg_git_config = if (xdg_config != null)
                try std.fmt.allocPrint(allocator, "{s}/git/config", .{xdg_base})
            else
                try std.fmt.allocPrint(allocator, "{s}/.config/git/config", .{xdg_base});
            defer allocator.free(xdg_git_config);
            if (platform_impl.fs.readFile(allocator, xdg_git_config)) |xcfg| {
                defer allocator.free(xcfg);
                if (parseConfigValue(xcfg, "init.defaultbranch", allocator) catch null) |db_val2| {
                    if (db_val2.len > 0) break :blk db_val2;
                    allocator.free(db_val2);
                }
            } else |_| {}
        }
        break :blk try allocator.dupe(u8, "master");
    };
    defer allocator.free(default_branch);

    // Validate branch name
    if (!isValidBranchName(default_branch)) {
        const msg = try std.fmt.allocPrint(allocator, "fatal: invalid branch name: '{s}'\n", .{default_branch});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    }

    const head_content = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{default_branch});
    defer allocator.free(head_content);
    try platform_impl.fs.writeFile(head_path, head_content);
    
    // Create config
    const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_dir});
    defer allocator.free(config_path);
    
    // Determine object format and ref format from environment
    const env_obj_fmt = std.process.getEnvVarOwned(allocator, "GIT_DEFAULT_HASH") catch null;
    defer if (env_obj_fmt) |v| allocator.free(v);
    const env_ref_fmt = std.process.getEnvVarOwned(allocator, "GIT_DEFAULT_REF_FORMAT") catch null;
    defer if (env_ref_fmt) |v| allocator.free(v);
    // Also check _ZIGGIT_INIT_OBJECT_FORMAT and _ZIGGIT_INIT_REF_FORMAT for explicit --object-format/--ref-format
    const explicit_obj_fmt = std.process.getEnvVarOwned(allocator, "_ZIGGIT_INIT_OBJECT_FORMAT") catch null;
    defer if (explicit_obj_fmt) |v| allocator.free(v);
    const explicit_ref_fmt = std.process.getEnvVarOwned(allocator, "_ZIGGIT_INIT_REF_FORMAT") catch null;
    defer if (explicit_ref_fmt) |v| allocator.free(v);
    
    const effective_obj_fmt = explicit_obj_fmt orelse env_obj_fmt;
    const effective_ref_fmt = explicit_ref_fmt orelse env_ref_fmt;
    
    const use_sha256 = if (effective_obj_fmt) |of| std.ascii.eqlIgnoreCase(of, "sha256") else false;
    const use_reftable = if (effective_ref_fmt) |rf| std.ascii.eqlIgnoreCase(rf, "reftable") else false;
    const needs_extensions = use_sha256 or use_reftable;
    
    var config_buf = std.array_list.Managed(u8).init(allocator);
    defer config_buf.deinit();
    try config_buf.appendSlice("[core]\n");
    if (needs_extensions) {
        try config_buf.appendSlice("\trepositoryformatversion = 1\n");
    } else {
        try config_buf.appendSlice("\trepositoryformatversion = 0\n");
    }
    try config_buf.appendSlice("\tfilemode = true\n");
    if (bare) {
        try config_buf.appendSlice("\tbare = true\n");
    } else {
        try config_buf.appendSlice("\tbare = false\n");
    }
    try config_buf.appendSlice("\tlogallrefupdates = true\n");
    if (shared) |s| {
        const shared_line = try std.fmt.allocPrint(allocator, "\tsharedRepository = {s}\n", .{s});
        defer allocator.free(shared_line);
        try config_buf.appendSlice(shared_line);
    }
    if (needs_extensions) {
        try config_buf.appendSlice("[extensions]\n");
        if (use_sha256) {
            try config_buf.appendSlice("\tobjectformat = sha256\n");
        }
        if (use_reftable) {
            try config_buf.appendSlice("\trefstorage = reftable\n");
        }
    }
    try platform_impl.fs.writeFile(config_path, config_buf.items);
    
    // Create description (only when templates are in use, or as default)
    if (use_templates) {
        const desc_path = try std.fmt.allocPrint(allocator, "{s}/description", .{git_dir});
        defer allocator.free(desc_path);
        try platform_impl.fs.writeFile(desc_path, "Unnamed repository; edit this file 'description' to name the repository.\n");
    }
    
    // Copy template directory contents (unless --template= was set to empty)
    if (!template_dir_set or (template_dir != null and template_dir.?.len > 0)) {
        var effective_template: ?[]const u8 = null;
        var template_needs_free = false;
        
        if (template_dir) |td| {
            effective_template = td;
        } else {
            // Check GIT_TEMPLATE_DIR env
            effective_template = std.process.getEnvVarOwned(allocator, "GIT_TEMPLATE_DIR") catch null;
            if (effective_template != null) {
                template_needs_free = true;
            } else {
                // Check init.templatedir from global config
                const home_dir = std.process.getEnvVarOwned(allocator, "HOME") catch null;
                defer if (home_dir) |h| allocator.free(h);
                if (home_dir) |home| {
                    const global_config_path = try std.fmt.allocPrint(allocator, "{s}/.gitconfig", .{home});
                    defer allocator.free(global_config_path);
                    if (platform_impl.fs.readFile(allocator, global_config_path)) |gcfg| {
                        defer allocator.free(gcfg);
                        if (parseConfigValue(gcfg, "init.templatedir", allocator) catch null) |tmpl_val| {
                            // Handle ~ expansion
                            if (tmpl_val.len > 0 and tmpl_val[0] == '~') {
                                const expanded = try std.fmt.allocPrint(allocator, "{s}{s}", .{ home, tmpl_val[1..] });
                                allocator.free(tmpl_val);
                                effective_template = expanded;
                            } else {
                                effective_template = tmpl_val;
                            }
                            template_needs_free = true;
                        }
                    } else |_| {}
                }
            }
        }
        defer if (template_needs_free) if (effective_template) |et| allocator.free(et);
        
        if (effective_template) |tmpl_dir| {
            if (tmpl_dir.len > 0) {
                copyTemplateDir(git_dir, tmpl_dir, allocator) catch {};
            }
        }
    }
    
    // Create info/exclude if not provided by template (only when templates are in use)
    if (use_templates) {
        const exclude_path = try std.fmt.allocPrint(allocator, "{s}/info/exclude", .{git_dir});
        defer allocator.free(exclude_path);
        if (!(std.fs.cwd().access(exclude_path, .{}) catch null != null)) {
            platform_impl.fs.writeFile(exclude_path, "# git ls-files --others --exclude-from=.git/info/exclude\n# Lines that start with '#' are comments.\n") catch {};
        }
    }
    
    // Print success
    const abs_path = std.fs.cwd().realpathAlloc(allocator, git_dir) catch try allocator.dupe(u8, git_dir);
    defer allocator.free(abs_path);
    if (!quiet) {
        const msg = try std.fmt.allocPrint(allocator, "Initialized empty Git repository in {s}/\n", .{abs_path});
        defer allocator.free(msg);
        try platform_impl.writeStdout(msg);
    }
}

fn initRepository(path: []const u8, bare: bool, template_dir: ?[]const u8, template_dir_set: bool, initial_branch: ?[]const u8, quiet: bool, shared: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Create the target directory if it doesn't exist (recursively)
    createDirectoryRecursive(path, platform_impl, allocator) catch |err| switch (err) {
        error.AlreadyExists => {},
        else => return err,
    };
    
    const git_dir = if (bare) 
        try allocator.dupe(u8, path)
    else 
        try std.fmt.allocPrint(allocator, "{s}/.git", .{path});
    defer allocator.free(git_dir);
    
    try initRepositoryInDir(git_dir, bare, template_dir, template_dir_set, initial_branch, quiet, shared, allocator, platform_impl);
}

fn getUpstreamTrackingInfo(git_path: []const u8, branch_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ?[]u8 {
    // Read branch tracking config
    const config_path = std.fmt.allocPrint(allocator, "{s}/config", .{git_path}) catch return null;
    defer allocator.free(config_path);
    const config_data = platform_impl.fs.readFile(allocator, config_path) catch return null;
    defer allocator.free(config_data);
    
    // Find [branch "name"] section
    const section_header = std.fmt.allocPrint(allocator, "[branch \"{s}\"]", .{branch_name}) catch return null;
    defer allocator.free(section_header);
    
    var merge_ref: ?[]const u8 = null;
    var in_section = false;
    var config_lines = std.mem.splitScalar(u8, config_data, '\n');
    while (config_lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        if (std.mem.startsWith(u8, trimmed, section_header)) {
            in_section = true;
            continue;
        }
        if (in_section and trimmed.len > 0 and trimmed[0] == '[') break;
        if (in_section) {
            if (std.mem.indexOf(u8, trimmed, "=")) |eq| {
                const key = std.mem.trim(u8, trimmed[0..eq], " \t");
                const val = std.mem.trim(u8, trimmed[eq+1..], " \t");
                if (std.mem.eql(u8, key, "merge")) {
                    merge_ref = val;
                }
            }
        }
    }
    
    if (merge_ref == null) return null;
    
    // Get upstream branch short name (strip refs/heads/)
    const upstream_short = if (std.mem.startsWith(u8, merge_ref.?, "refs/heads/")) merge_ref.?["refs/heads/".len..] else merge_ref.?;
    
    // Count ahead/behind
    const our_hash = refs.getCurrentCommit(git_path, platform_impl, allocator) catch return std.fmt.allocPrint(allocator, "{s}", .{upstream_short}) catch null;
    defer if (our_hash) |h| allocator.free(h);
    if (our_hash == null) return std.fmt.allocPrint(allocator, "{s}", .{upstream_short}) catch null;
    
    const upstream_ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{git_path, merge_ref.?}) catch return null;
    defer allocator.free(upstream_ref_path);
    const upstream_hash_raw = std.fs.cwd().readFileAlloc(allocator, upstream_ref_path, 4096) catch return std.fmt.allocPrint(allocator, "{s} [gone]", .{upstream_short}) catch null;
    defer allocator.free(upstream_hash_raw);
    const upstream_hash = std.mem.trim(u8, upstream_hash_raw, " \t\r\n");
    
    if (std.mem.eql(u8, our_hash.?, upstream_hash)) {
        return std.fmt.allocPrint(allocator, "{s}", .{upstream_short}) catch null;
    }
    
    // Count commits ahead and behind
    var ahead: u32 = 0;
    var behind: u32 = 0;
    
    // Count ahead: commits in ours not reachable from upstream
    ahead = countUnreachable(git_path, our_hash.?, upstream_hash, allocator, platform_impl);
    behind = countUnreachable(git_path, upstream_hash, our_hash.?, allocator, platform_impl);
    
    if (ahead > 0 and behind > 0) {
        return std.fmt.allocPrint(allocator, "{s} [ahead {d}, behind {d}]", .{upstream_short, ahead, behind}) catch null;
    } else if (ahead > 0) {
        return std.fmt.allocPrint(allocator, "{s} [ahead {d}]", .{upstream_short, ahead}) catch null;
    } else if (behind > 0) {
        return std.fmt.allocPrint(allocator, "{s} [behind {d}]", .{upstream_short, behind}) catch null;
    }
    return std.fmt.allocPrint(allocator, "{s}", .{upstream_short}) catch null;
}

fn countUnreachable(git_path: []const u8, from: []const u8, not_in: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) u32 {
    // Simple BFS to count commits reachable from 'from' but not from 'not_in'
    // First collect all commits reachable from not_in
    var not_in_set = std.StringHashMap(void).init(allocator);
    defer {
        var it = not_in_set.keyIterator();
        while (it.next()) |k| allocator.free(k.*);
        not_in_set.deinit();
    }
    
    var queue = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (queue.items) |item| allocator.free(item);
        queue.deinit();
    }
    queue.append(allocator.dupe(u8, not_in) catch return 0) catch return 0;
    
    var depth: u32 = 0;
    while (queue.items.len > 0 and depth < 1000) {
        const current = queue.orderedRemove(0);
        defer allocator.free(current);
        if (not_in_set.contains(current)) continue;
        not_in_set.put(allocator.dupe(u8, current) catch continue, {}) catch continue;
        depth += 1;
        
        // Get parents
        const obj = objects.GitObject.load(current, git_path, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);
        if (obj.type != .commit) continue;
        var obj_lines = std.mem.splitSequence(u8, obj.data, "\n");
        while (obj_lines.next()) |l| {
            if (std.mem.startsWith(u8, l, "parent ")) {
                queue.append(allocator.dupe(u8, l["parent ".len..]) catch continue) catch {};
            } else if (l.len == 0) break;
        }
    }
    
    // Now count commits reachable from 'from' but not in not_in_set
    var count: u32 = 0;
    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var it2 = visited.keyIterator();
        while (it2.next()) |k| allocator.free(k.*);
        visited.deinit();
    }
    
    var queue2 = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (queue2.items) |item| allocator.free(item);
        queue2.deinit();
    }
    queue2.append(allocator.dupe(u8, from) catch return 0) catch return 0;
    
    while (queue2.items.len > 0 and count < 1000) {
        const current = queue2.orderedRemove(0);
        defer allocator.free(current);
        if (visited.contains(current)) continue;
        if (not_in_set.contains(current)) continue;
        visited.put(allocator.dupe(u8, current) catch continue, {}) catch continue;
        count += 1;
        
        const obj = objects.GitObject.load(current, git_path, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);
        if (obj.type != .commit) continue;
        var obj_lines = std.mem.splitSequence(u8, obj.data, "\n");
        while (obj_lines.next()) |l| {
            if (std.mem.startsWith(u8, l, "parent ")) {
                queue2.append(allocator.dupe(u8, l["parent ".len..]) catch continue) catch {};
            } else if (l.len == 0) break;
        }
    }
    
    return count;
}

fn cmdStatus(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform, _: [][]const u8) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("status: not supported in freestanding mode\n");
        return;
    }

    // Check for flags
    var porcelain = false;
    var show_branch = false;
    var short_format = false;
    var show_untracked = true; // default: show untracked files
    var status_args = std.array_list.Managed([]const u8).init(allocator);
    defer status_args.deinit();
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--porcelain") or std.mem.eql(u8, arg, "--porcelain=v1")) {
            porcelain = true;
        } else if (std.mem.startsWith(u8, arg, "--porcelain=")) {
            const version = arg["--porcelain=".len..];
            if (std.mem.eql(u8, version, "v1") or std.mem.eql(u8, version, "1")) {
                porcelain = true;
            } else if (std.mem.eql(u8, version, "v2") or std.mem.eql(u8, version, "2")) {
                porcelain = true;
            } else {
                const msg = try std.fmt.allocPrint(allocator, "fatal: unsupported porcelain version '{s}'\n", .{version});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }
        } else if (std.mem.eql(u8, arg, "--branch") or std.mem.eql(u8, arg, "-b")) {
            show_branch = true;
        } else if (std.mem.eql(u8, arg, "--short") or std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "-sb") or std.mem.eql(u8, arg, "-bs")) {
            short_format = true;
            porcelain = true; // short format uses same output as porcelain
            if (std.mem.eql(u8, arg, "-sb") or std.mem.eql(u8, arg, "-bs")) {
                show_branch = true;
            }
        } else if (std.mem.eql(u8, arg, "-uno") or std.mem.eql(u8, arg, "-ufalse") or std.mem.eql(u8, arg, "--untracked-files=no") or std.mem.eql(u8, arg, "--untracked-files=false") or std.mem.eql(u8, arg, "-u") or std.mem.eql(u8, arg, "--no-untracked-files")) {
            show_untracked = false;
        } else if (std.mem.eql(u8, arg, "-unormal") or std.mem.eql(u8, arg, "-utrue") or std.mem.eql(u8, arg, "--untracked-files=normal") or std.mem.eql(u8, arg, "--untracked-files=true") or std.mem.eql(u8, arg, "--untracked-files") or std.mem.eql(u8, arg, "-uall") or std.mem.eql(u8, arg, "--untracked-files=all")) {
            show_untracked = true;
        } else if (std.mem.eql(u8, arg, "-h") or std.mem.eql(u8, arg, "--help")) {
            try platform_impl.writeStdout("usage: git status [<options>] [--] [<pathspec>...]\n\n");
            try platform_impl.writeStdout("    -s, --short           show status concisely\n");
            try platform_impl.writeStdout("    -b, --branch          show branch information\n");
            try platform_impl.writeStdout("    --porcelain[=<version>]\n                          machine-readable output\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--")) {
            // End of flags
            while (args.next()) |path_arg| {
                try status_args.append(path_arg);
            }
            break;
        } else if (std.mem.eql(u8, arg, "-z")) {
            // NUL-terminate output entries - accept but treat as no-op for now
            // (porcelain mode already uses line-based output)
        } else if (std.mem.eql(u8, arg, "--column") or std.mem.startsWith(u8, arg, "--column=")) {
            // Column display - accept as no-op
        } else if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            // Verbose mode - accept as no-op (shows diff in commit template)
        } else if (std.mem.eql(u8, arg, "--ignored")) {
            // Show ignored files - accept as no-op for now
        } else if (std.mem.eql(u8, arg, "--renames") or std.mem.eql(u8, arg, "--no-renames") or
            std.mem.eql(u8, arg, "--find-renames"))
        {
            // Rename detection - accept as no-op
        } else if (std.mem.eql(u8, arg, "--ahead-behind") or std.mem.eql(u8, arg, "--no-ahead-behind")) {
            // Ahead/behind display - accept as no-op
        } else if (arg.len > 0 and arg[0] != '-') {
            try status_args.append(arg);
        }
        // Silently ignore other unrecognized flags
    }
    
    // Find .git directory by traversing up
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Get current working directory (repository root)
    const repo_root = std.fs.path.dirname(git_path) orelse {
        try platform_impl.writeStderr("fatal: unable to determine repository root\n");
        std.process.exit(128);
    };

    // Check config for status.showUntrackedFiles (if not overridden by command line)
    if (show_untracked) {
        const config_path_for_ut = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path_for_ut);
        if (platform_impl.fs.readFile(allocator, config_path_for_ut)) |cfg| {
            defer allocator.free(cfg);
            if (parseConfigValue(cfg, "status.showuntrackedfiles", allocator) catch null) |val| {
                defer allocator.free(val);
                if (std.mem.eql(u8, val, "no") or std.mem.eql(u8, val, "false") or std.mem.eql(u8, val, "0")) {
                    show_untracked = false;
                }
            }
        } else |_| {}
    }

    // Get current branch
    const current_branch = refs.getCurrentBranch(git_path, platform_impl, allocator) catch try allocator.dupe(u8, "master");
    defer allocator.free(current_branch);

    // Check if there are any commits
    const current_commit = refs.getCurrentCommit(git_path, platform_impl, allocator) catch null;
    defer if (current_commit) |hash| allocator.free(hash);
    
    if (!porcelain) {
        const branch_msg = try std.fmt.allocPrint(allocator, "On branch {s}\n", .{current_branch});
        defer allocator.free(branch_msg);
        try platform_impl.writeStdout(branch_msg);

        // Display upstream tracking info natively
        if (current_commit != null) upstream_display: {
            const config_path_track = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
            defer allocator.free(config_path_track);
            const cfg = platform_impl.fs.readFile(allocator, config_path_track) catch break :upstream_display;
            defer allocator.free(cfg);
            const track_key = try std.fmt.allocPrint(allocator, "branch \"{s}\".remote", .{current_branch});
            defer allocator.free(track_key);
            const remote_val = (parseConfigValue(cfg, track_key, allocator) catch null) orelse break :upstream_display;
            defer allocator.free(remote_val);

            const merge_key = try std.fmt.allocPrint(allocator, "branch \"{s}\".merge", .{current_branch});
            defer allocator.free(merge_key);
            const merge_val = (parseConfigValue(cfg, merge_key, allocator) catch null) orelse break :upstream_display;
            defer allocator.free(merge_val);

            // Convert refs/heads/foo to remote/origin/foo
            const short_merge = if (std.mem.startsWith(u8, merge_val, "refs/heads/"))
                merge_val["refs/heads/".len..]
            else
                merge_val;

            const is_local = std.mem.eql(u8, remote_val, ".");
            const upstream_ref = if (is_local)
                try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{short_merge})
            else
                try std.fmt.allocPrint(allocator, "refs/remotes/{s}/{s}", .{ remote_val, short_merge });
            defer allocator.free(upstream_ref);
            const upstream_display_name = if (is_local)
                try allocator.dupe(u8, short_merge)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ remote_val, short_merge });
            defer allocator.free(upstream_display_name);

            // Resolve upstream ref to commit hash
            const upstream_hash_opt = refs.resolveRef(git_path, upstream_ref, platform_impl, allocator) catch break :upstream_display;
            const upstream_hash = upstream_hash_opt orelse break :upstream_display;
            defer allocator.free(upstream_hash);

            // Compare commits: count ahead/behind
            if (std.mem.eql(u8, current_commit.?, upstream_hash)) {
                const up_msg = try std.fmt.allocPrint(allocator, "Your branch is up to date with '{s}'.\n\n", .{upstream_display_name});
                defer allocator.free(up_msg);
                try platform_impl.writeStdout(up_msg);
            } else {
                const ahead_count = countUnreachable(git_path, current_commit.?, upstream_hash, allocator, platform_impl);
                const behind_count = countUnreachable(git_path, upstream_hash, current_commit.?, allocator, platform_impl);
                if (ahead_count > 0 and behind_count > 0) {
                    const up_msg = try std.fmt.allocPrint(allocator, "Your branch and '{s}' have diverged,\nand have {d} and {d} different commits each, respectively.\n  (use \"git pull\" if you want to integrate the remote branch with yours)\n\n", .{upstream_display_name, ahead_count, behind_count});
                    defer allocator.free(up_msg);
                    try platform_impl.writeStdout(up_msg);
                } else if (ahead_count > 0) {
                    const up_msg = try std.fmt.allocPrint(allocator, "Your branch is ahead of '{s}' by {d} commit{s}.\n  (use \"git push\" to publish your local commits)\n\n", .{upstream_display_name, ahead_count, if (ahead_count > 1) "s" else ""});
                    defer allocator.free(up_msg);
                    try platform_impl.writeStdout(up_msg);
                } else if (behind_count > 0) {
                    const up_msg = try std.fmt.allocPrint(allocator, "Your branch is behind '{s}' by {d} commit{s}, and can be fast-forwarded.\n  (use \"git pull\" to update your local branch)\n\n", .{upstream_display_name, behind_count, if (behind_count > 1) "s" else ""});
                    defer allocator.free(up_msg);
                    try platform_impl.writeStdout(up_msg);
                }
            }
        }
        
        if (current_commit == null) {
            try platform_impl.writeStdout("\nNo commits yet\n");
        }
    } else if (porcelain and show_branch) {
        // Check if HEAD is detached
        const head_content_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
        defer allocator.free(head_content_path);
        const head_raw = platform_impl.fs.readFile(allocator, head_content_path) catch null;
        defer if (head_raw) |h| allocator.free(h);
        
        if (head_raw) |h| {
            if (std.mem.startsWith(u8, h, "ref: ")) {
                // Read upstream tracking info
                const upstream_info = getUpstreamTrackingInfo(git_path, current_branch, allocator, platform_impl);
                defer if (upstream_info) |info| allocator.free(info);
                if (upstream_info) |info| {
                    const branch_header = try std.fmt.allocPrint(allocator, "## {s}...{s}\n", .{current_branch, info});
                    defer allocator.free(branch_header);
                    try platform_impl.writeStdout(branch_header);
                } else {
                    const branch_header = try std.fmt.allocPrint(allocator, "## {s}\n", .{current_branch});
                    defer allocator.free(branch_header);
                    try platform_impl.writeStdout(branch_header);
                }
            } else {
                try platform_impl.writeStdout("## HEAD (no branch)\n");
            }
        } else {
            const branch_header = try std.fmt.allocPrint(allocator, "## {s}\n", .{current_branch});
            defer allocator.free(branch_header);
            try platform_impl.writeStdout(branch_header);
        }
    }

    // Load index to check for staged files
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.FileNotFound => index_mod.Index.init(allocator),
        else => return err,
    };
    defer index.deinit();

    // Load gitignore
    const gitignore_path = try std.fmt.allocPrint(allocator, "{s}/.gitignore", .{repo_root});
    defer allocator.free(gitignore_path);
    
    var gitignore = gitignore_mod.GitIgnore.loadFromFile(allocator, gitignore_path, platform_impl) catch |err| switch (err) {
        error.OutOfMemory => return err,
        else => gitignore_mod.GitIgnore.init(allocator),
    };
    defer gitignore.deinit();

    // Pre-compute HEAD tree hash and build flat index for O(1) blob lookups
    var cached_head_tree: ?[]u8 = null;
    if (current_commit) |cc| {
        const commit_obj = objects.GitObject.load(cc, git_path, platform_impl, allocator) catch null;
        if (commit_obj) |co| {
            defer co.deinit(allocator);
            var clines = std.mem.splitSequence(u8, co.data, "\n");
            if (clines.next()) |tl| {
                if (std.mem.startsWith(u8, tl, "tree ")) {
                    cached_head_tree = allocator.dupe(u8, tl["tree ".len..]) catch null;
                }
            }
        }
    }
    defer if (cached_head_tree) |h| allocator.free(h);

    // Build flat map: path -> sha1 from HEAD tree (for fast staged detection)
    var head_tree_map = std.StringHashMap([20]u8).init(allocator);
    defer {
        var kit = head_tree_map.keyIterator();
        while (kit.next()) |key| allocator.free(@constCast(key.*));
        head_tree_map.deinit();
    }
    if (cached_head_tree) |ht| {
        buildTreeMap(ht, "", git_path, platform_impl, allocator, &head_tree_map) catch {};
    }

    // Detect staged files vs modified files vs deleted files vs clean files
    var staged_files = std.array_list.Managed(index_mod.IndexEntry).init(allocator);
    var modified_files = std.array_list.Managed(index_mod.IndexEntry).init(allocator);
    var deleted_files = std.array_list.Managed(index_mod.IndexEntry).init(allocator);
    defer staged_files.deinit();
    defer modified_files.deinit();
    defer deleted_files.deinit();

    for (index.entries.items) |entry| {
        // Check if working directory version is different from index version
        const full_path = if (std.fs.path.isAbsolute(entry.path))
            try allocator.dupe(u8, entry.path)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path });
        defer allocator.free(full_path);
        
        // Check if file exists in working directory
        const file_exists = platform_impl.fs.exists(full_path) catch false;
        
        if (!file_exists) {
            // File is in index but not in working directory - it's deleted
            try deleted_files.append(entry);
        } else {
            const working_modified = blk: {
                // OPTIMIZATION: Fast path using mtime/size before computing SHA-1
                const file_stat = std.fs.cwd().statFile(full_path) catch break :blk false;
                
                // Compare mtime and size with index entry
                const work_mtime_sec = @as(u32, @intCast(@divTrunc(file_stat.mtime, 1_000_000_000)));
                const work_size = @as(u32, @intCast(file_stat.size));
                
                // Fast path: if mtime and size match index, file is likely unchanged
                if (work_mtime_sec == entry.mtime_sec and work_size == entry.size) {
                    break :blk false; // File appears unchanged - skip expensive SHA-1 computation
                }
                
                // Slow path: mtime or size differs, need to compute SHA-1 to confirm
                const current_content = platform_impl.fs.readFile(allocator, full_path) catch break :blk false;
                defer allocator.free(current_content);
                
                // Create blob object to get hash
                const blob = objects.createBlobObject(current_content, allocator) catch break :blk false;
                defer blob.deinit(allocator);
                
                const current_hash = blob.hash(allocator) catch break :blk false;
                defer allocator.free(current_hash);
                
                // Compare with index hash
                const index_hash = std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1}) catch break :blk false;
                defer allocator.free(index_hash);
                
                break :blk !std.mem.eql(u8, current_hash, index_hash);
            };
            
            if (working_modified) {
                try modified_files.append(entry);
            } else if (current_commit == null) {
                // No commits yet, so anything in index is staged
                try staged_files.append(entry);
            } else {
                // File is in index and matches working directory.
                // Check if it's different from HEAD tree using cached map (O(1))
                const is_different_from_head = blk: {
                    if (head_tree_map.get(entry.path)) |tree_sha1| {
                        break :blk !std.mem.eql(u8, &tree_sha1, &entry.sha1);
                    }
                    // File not in HEAD tree - it's new (staged)
                    break :blk current_commit != null;
                };
                
                if (is_different_from_head) {
                    try staged_files.append(entry);
                }
                // If same as HEAD, file is clean (don't show it)
            }
        }
    }

    // Determine HEAD tree hash for new-file detection
    var head_tree_hash: ?[]u8 = null;
    if (current_commit) |cc| {
        const cobj = objects.GitObject.load(cc, git_path, platform_impl, allocator) catch null;
        if (cobj) |co| {
            defer co.deinit(allocator);
            if (co.type == .commit) {
                var clines = std.mem.splitSequence(u8, co.data, "\n");
                if (clines.next()) |tl| {
                    if (std.mem.startsWith(u8, tl, "tree ")) {
                        head_tree_hash = allocator.dupe(u8, tl["tree ".len..]) catch null;
                    }
                }
            }
        }
    }
    defer if (head_tree_hash) |h| allocator.free(h);

    // For porcelain output, collect all lines then sort and output together
    var porcelain_lines = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (porcelain_lines.items) |line| allocator.free(line);
        porcelain_lines.deinit();
    }

    // Show staged files
    if (staged_files.items.len > 0) {
        if (porcelain) {
            for (staged_files.items) |entry| {
                const is_new = if (current_commit == null)
                    true
                else if (head_tree_hash) |hth|
                    (lookupBlobInTree(hth, entry.path, git_path, platform_impl, allocator) catch null) == null
                else
                    false;
                
                if (is_new) {
                    try porcelain_lines.append(try std.fmt.allocPrint(allocator, "A  {s}", .{entry.path}));
                } else {
                    try porcelain_lines.append(try std.fmt.allocPrint(allocator, "M  {s}", .{entry.path}));
                }
            }
        } else {
            try platform_impl.writeStdout("\nChanges to be committed:\n");
            if (current_commit == null) {
                try platform_impl.writeStdout("  (use \"git rm --cached <file>...\" to unstage)\n");
            } else {
                try platform_impl.writeStdout("  (use \"git restore --staged <file>...\" to unstage)\n");
            }
            
            for (staged_files.items) |entry| {
                const is_new = if (current_commit == null)
                    true
                else if (head_tree_hash) |hth|
                    (lookupBlobInTree(hth, entry.path, git_path, platform_impl, allocator) catch null) == null
                else
                    false;
                    
                if (is_new) {
                    const msg = try std.fmt.allocPrint(allocator, "\tnew file:   {s}\n", .{entry.path});
                    defer allocator.free(msg);
                    try platform_impl.writeStdout(msg);
                } else {
                    const msg = try std.fmt.allocPrint(allocator, "\tmodified:   {s}\n", .{entry.path});
                    defer allocator.free(msg);
                    try platform_impl.writeStdout(msg);
                }
            }
            try platform_impl.writeStdout("\n");
        }
    }

    // Show modified but unstaged files
    if (modified_files.items.len > 0) {
        if (porcelain) {
            for (modified_files.items) |entry| {
                try porcelain_lines.append(try std.fmt.allocPrint(allocator, " M {s}", .{entry.path}));
            }
        } else {
            try platform_impl.writeStdout("\nChanges not staged for commit:\n");
            try platform_impl.writeStdout("  (use \"git add <file>...\" to update what will be committed)\n");
            try platform_impl.writeStdout("  (use \"git restore <file>...\" to discard changes in working directory)\n");
            
            for (modified_files.items) |entry| {
                const msg = try std.fmt.allocPrint(allocator, "\tmodified:   {s}\n", .{entry.path});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            }
            try platform_impl.writeStdout("\n");
        }
    }

    // Show deleted files
    if (deleted_files.items.len > 0) {
        if (porcelain) {
            for (deleted_files.items) |entry| {
                try porcelain_lines.append(try std.fmt.allocPrint(allocator, " D {s}", .{entry.path}));
            }
        } else {
            if (modified_files.items.len == 0) {
                try platform_impl.writeStdout("\nChanges not staged for commit:\n");
                try platform_impl.writeStdout("  (use \"git add <file>...\" to update what will be committed)\n");
                try platform_impl.writeStdout("  (use \"git restore <file>...\" to discard changes in working directory)\n");
            }
            
            for (deleted_files.items) |entry| {
                const msg = try std.fmt.allocPrint(allocator, "\tdeleted:    {s}\n", .{entry.path});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            }
            try platform_impl.writeStdout("\n");
        }
    }

    // Find untracked files
    var untracked_files = if (show_untracked)
        findUntrackedFiles(allocator, repo_root, &index, &gitignore, platform_impl) catch std.array_list.Managed([]u8).init(allocator)
    else
        std.array_list.Managed([]u8).init(allocator);
    defer {
        for (untracked_files.items) |file| {
            allocator.free(file);
        }
        untracked_files.deinit();
    }

    if (untracked_files.items.len > 0) {
        if (porcelain) {
            for (untracked_files.items) |file| {
                try porcelain_lines.append(try std.fmt.allocPrint(allocator, "?? {s}", .{file}));
            }
        } else {
            try platform_impl.writeStdout("\nUntracked files:\n");
            try platform_impl.writeStdout("  (use \"git add <file>...\" to include in what will be committed)\n");
            
            for (untracked_files.items) |file| {
                const msg = try std.fmt.allocPrint(allocator, "\t{s}\n", .{file});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            }
            try platform_impl.writeStdout("\n");
        }
    }

    // Output sorted porcelain lines
    if (porcelain and porcelain_lines.items.len > 0) {
        // Sort: tracked entries in path order first, then untracked in path order
        std.mem.sort([]u8, porcelain_lines.items, {}, struct {
            fn lessThan(_: void, a: []u8, b: []u8) bool {
                const a_untracked = a.len >= 2 and a[0] == '?' and a[1] == '?';
                const b_untracked = b.len >= 2 and b[0] == '?' and b[1] == '?';
                if (a_untracked != b_untracked) return !a_untracked; // tracked before untracked
                const a_path = if (a.len > 3) a[3..] else a;
                const b_path = if (b.len > 3) b[3..] else b;
                return std.mem.order(u8, a_path, b_path) == .lt;
            }
        }.lessThan);
        for (porcelain_lines.items) |line| {
            const msg = try std.fmt.allocPrint(allocator, "{s}\n", .{line});
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    }

    // Final summary message (only in non-porcelain mode)
    if (!porcelain) {
        if (staged_files.items.len == 0 and modified_files.items.len == 0 and deleted_files.items.len == 0 and untracked_files.items.len == 0) {
            if (current_commit == null) {
                try platform_impl.writeStdout("\nnothing to commit (create/copy files and use \"git add\" to track)\n");
            } else {
                try platform_impl.writeStdout("\nnothing to commit, working tree clean\n");
            }
        } else if (staged_files.items.len == 0 and modified_files.items.len == 0 and deleted_files.items.len == 0 and untracked_files.items.len > 0) {
            try platform_impl.writeStdout("nothing added to commit but untracked files present (use \"git add\" to track)\n");
        } else if (staged_files.items.len == 0 and (modified_files.items.len > 0 or deleted_files.items.len > 0)) {
            try platform_impl.writeStdout("no changes added to commit (use \"git add\" and/or \"git commit -a\")\n");
        }
        if (!show_untracked) {
            try platform_impl.writeStdout("Untracked files not listed (use -u option to show untracked files)\n");
        }
    }
}

/// Resolve a git alias by looking up alias.<name> in config files.
/// Also supports subsection syntax: alias.<name>.command
/// Returns the alias value (caller must free), or null if not found.
fn resolveAlias(allocator: std.mem.Allocator, name: []const u8, platform_impl: *const platform_mod.Platform) !?[]u8 {
    const alias_key = try std.fmt.allocPrint(allocator, "alias.{s}", .{name});
    defer allocator.free(alias_key);
    // Also try subsection syntax: alias.<name>.command
    const alias_subsection_key = try std.fmt.allocPrint(allocator, "alias.{s}.command", .{name});
    defer allocator.free(alias_subsection_key);
    
    // Search config sources in order: local (.git/config), global (~/.gitconfig), system (/etc/gitconfig)
    // Last value wins in git, but for aliases we want first match (local > global > system)
    
    // Try local config (.git/config)
    if (findGitDirectory(allocator, platform_impl)) |git_path| {
        defer allocator.free(git_path);
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        if (platform_impl.fs.readFile(allocator, config_path)) |content| {
            defer allocator.free(content);
            if (parseConfigValue(content, alias_key, allocator) catch null) |val| {
                return val;
            }
            if (parseConfigValue(content, alias_subsection_key, allocator) catch null) |val| {
                return val;
            }
        } else |_| {}
    } else |_| {}
    
    // Try global config (~/.gitconfig)
    if (std.process.getEnvVarOwned(allocator, "HOME")) |home| {
        defer allocator.free(home);
        const global_config = try std.fmt.allocPrint(allocator, "{s}/.gitconfig", .{home});
        defer allocator.free(global_config);
        if (platform_impl.fs.readFile(allocator, global_config)) |content| {
            defer allocator.free(content);
            if (parseConfigValue(content, alias_key, allocator) catch null) |val| {
                return val;
            }
            if (parseConfigValue(content, alias_subsection_key, allocator) catch null) |val| {
                return val;
            }
        } else |_| {}
        
        // Try XDG config
        const xdg_config = try std.fmt.allocPrint(allocator, "{s}/.config/git/config", .{home});
        defer allocator.free(xdg_config);
        if (platform_impl.fs.readFile(allocator, xdg_config)) |content| {
            defer allocator.free(content);
            if (parseConfigValue(content, alias_key, allocator) catch null) |val| {
                return val;
            }
            if (parseConfigValue(content, alias_subsection_key, allocator) catch null) |val| {
                return val;
            }
        } else |_| {}
    } else |_| {}
    
    // Try system config
    {
        if (platform_impl.fs.readFile(allocator, "/etc/gitconfig")) |content| {
            defer allocator.free(content);
            if (parseConfigValue(content, alias_key, allocator) catch null) |val| {
                return val;
            }
            if (parseConfigValue(content, alias_subsection_key, allocator) catch null) |val| {
                return val;
            }
        } else |_| {}
    }
    
    return null;
}

pub fn findGitDirectory(allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    // Check --git-dir override first
    if (global_git_dir_override) |gd| {
        const abs_gd = std.fs.cwd().realpathAlloc(allocator, gd) catch {
            return allocator.dupe(u8, gd);
        };
        return abs_gd;
    }
    // Check GIT_DIR environment variable
    if (std.posix.getenv("GIT_DIR")) |git_dir_env| {
        if (git_dir_env.len > 0) {
            const abs_gd = std.fs.cwd().realpathAlloc(allocator, git_dir_env) catch {
                return allocator.dupe(u8, git_dir_env);
            };
            return abs_gd;
        }
    }

    const current_dir = try platform_impl.fs.getCwd(allocator);
    defer allocator.free(current_dir);
    
    // Walk up the directory tree looking for .git or bare repository
    var dir_to_check = try allocator.dupe(u8, current_dir);
    var is_first = true;
    
    while (true) {
        // Check GIT_CEILING_DIRECTORIES - don't search at or above ceiling dirs
        // (but always check the starting directory itself)
        if (!is_first) {
            if (std.posix.getenv("GIT_CEILING_DIRECTORIES")) |ceilings| {
                var ceil_iter = std.mem.splitScalar(u8, ceilings, ':');
                while (ceil_iter.next()) |ceil| {
                    const trimmed_ceil = std.mem.trimRight(u8, ceil, "/");
                    if (trimmed_ceil.len == 0) continue;
                    if (std.mem.eql(u8, dir_to_check, trimmed_ceil)) {
                        allocator.free(dir_to_check);
                        return error.NotAGitRepository;
                    }
                }
            }
        }
        is_first = false;

        // First check for .git subdirectory (normal repository) or valid gitdir link
        const git_path = try std.fmt.allocPrint(allocator, "{s}/.git", .{dir_to_check});
        const git_is_valid = blk: {
            // Check if it's a directory
            if (std.fs.cwd().openDir(git_path, .{})) |d| {
                var dd = d;
                dd.close();
                break :blk true;
            } else |_| {}
            // Check if it's a file (gitdir link)
            if (std.fs.cwd().readFileAlloc(allocator, git_path, 4096)) |content| {
                defer allocator.free(content);
                const trimmed = std.mem.trim(u8, content, " \t\r\n");
                if (std.mem.startsWith(u8, trimmed, "gitdir: ")) {
                    break :blk true;
                } else {
                    // .git is a file but not valid format - error
                    platform_impl.writeStderr("fatal: invalid gitfile format: ") catch {};
                    platform_impl.writeStderr(git_path) catch {};
                    platform_impl.writeStderr("\n") catch {};
                    allocator.free(dir_to_check);
                    allocator.free(git_path);
                    std.process.exit(128);
                    unreachable;
                }
            } else |_| {}
            break :blk false;
        };
        if (git_is_valid) {
            // If .git is a gitdir file, resolve and validate the target path
            if (std.fs.cwd().readFileAlloc(allocator, git_path, 4096)) |content| {
                defer allocator.free(content);
                const trimmed2 = std.mem.trim(u8, content, " \t\r\n");
                if (std.mem.startsWith(u8, trimmed2, "gitdir: ")) {
                    const target_path = trimmed2["gitdir: ".len..];
                    // Resolve relative path
                    const abs_target = if (std.fs.path.isAbsolute(target_path))
                        try allocator.dupe(u8, target_path)
                    else
                        try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir_to_check, target_path });
                    
                    // Check that the target exists
                    const target_exists = if (std.fs.cwd().access(abs_target, .{})) |_| true else |_| false;
                    if (!target_exists) {
                        platform_impl.writeStderr("fatal: not a git repository: ") catch {};
                        platform_impl.writeStderr(abs_target) catch {};
                        platform_impl.writeStderr("\n") catch {};
                        allocator.free(abs_target);
                        allocator.free(dir_to_check);
                        allocator.free(git_path);
                        std.process.exit(128);
                        unreachable;
                    }
                    allocator.free(git_path);
                    allocator.free(dir_to_check);
                    return abs_target;
                }
            } else |_| {}
            
            allocator.free(dir_to_check);
            return git_path;
        }
        allocator.free(git_path);
        
        // Check if current directory is a bare repository
        // A bare repository has HEAD, config, objects, and refs directly in the directory
        const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{dir_to_check});
        defer allocator.free(head_path);
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{dir_to_check});
        defer allocator.free(config_path);
        const objects_path = try std.fmt.allocPrint(allocator, "{s}/objects", .{dir_to_check});
        defer allocator.free(objects_path);
        const refs_path = try std.fmt.allocPrint(allocator, "{s}/refs", .{dir_to_check});
        defer allocator.free(refs_path);
        
        if ((platform_impl.fs.exists(head_path) catch false) and 
            (platform_impl.fs.exists(config_path) catch false) and
            (platform_impl.fs.exists(objects_path) catch false) and
            (platform_impl.fs.exists(refs_path) catch false)) {
            // This looks like a bare repository
            const bare_path = try allocator.dupe(u8, dir_to_check);
            allocator.free(dir_to_check);
            return bare_path;
        }
        
        // Check if we're at the root
        const parent = std.fs.path.dirname(dir_to_check);
        if (parent == null or std.mem.eql(u8, parent.?, dir_to_check)) {
            break; // We've reached the root directory
        }
        
        // Move to parent directory
        allocator.free(dir_to_check);
        dir_to_check = try allocator.dupe(u8, parent.?);
    }
    
    allocator.free(dir_to_check);
    return error.NotAGitRepository;
}

fn cmdAdd(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("add: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory first (before checking arguments)
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Check if any files were specified
    var has_files = false;
    
    // Load index
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.FileNotFound => index_mod.Index.init(allocator),
        else => return err,
    };
    defer index.deinit();

    // Get current working directory
    const cwd = try platform_impl.fs.getCwd(allocator);
    defer allocator.free(cwd);

    // Pre-scan for flags
    var add_all_flag = false;
    var update_flag = false;
    var force_flag = false;
    var collected_add_paths = std.array_list.Managed([]const u8).init(allocator);
    defer collected_add_paths.deinit();
    while (args.next()) |raw_arg| {
        if (std.mem.eql(u8, raw_arg, "--")) {
            while (args.next()) |p| try collected_add_paths.append(p);
            break;
        } else if (std.mem.eql(u8, raw_arg, "--all") or std.mem.eql(u8, raw_arg, "-A")) {
            add_all_flag = true;
        } else if (std.mem.eql(u8, raw_arg, "--update") or std.mem.eql(u8, raw_arg, "-u")) {
            update_flag = true;
        } else if (std.mem.eql(u8, raw_arg, "--force") or std.mem.eql(u8, raw_arg, "-f")) {
            force_flag = true;
        } else if (raw_arg.len > 0 and raw_arg[0] == '-') {
            // Skip other flags
        } else {
            try collected_add_paths.append(raw_arg);
        }
    }
    if ((add_all_flag or update_flag) and collected_add_paths.items.len == 0) {
        try collected_add_paths.append(".");
    }

    // Process all file arguments
    for (collected_add_paths.items) |file_path| {
        has_files = true;
        
        // Handle special cases like "." for current directory
        if (std.mem.eql(u8, file_path, ".")) {
            // Add all files in current directory (recursively)
            try addDirectoryRecursively(allocator, cwd, "", &index, git_path, platform_impl);
        } else {
            // Resolve file path 
            const full_file_path = if (std.fs.path.isAbsolute(file_path))
                try allocator.dupe(u8, file_path)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cwd, file_path });
            defer allocator.free(full_file_path);
            
            // Convert to path relative to repo root
            const repo_root_for_rel = std.fs.path.dirname(git_path) orelse ".";
            const real_full = std.fs.cwd().realpathAlloc(allocator, full_file_path) catch try allocator.dupe(u8, full_file_path);
            defer allocator.free(real_full);
            const real_root = std.fs.cwd().realpathAlloc(allocator, repo_root_for_rel) catch try allocator.dupe(u8, repo_root_for_rel);
            defer allocator.free(real_root);
            // Compute relative path from repo root
            const relative_file_path = if (std.mem.startsWith(u8, real_full, real_root) and real_full.len > real_root.len and real_full[real_root.len] == '/')
                real_full[real_root.len + 1 ..]
            else
                file_path;

            // Check if path exists (including broken symlinks)
            const path_exists = blk: {
                if (platform_impl.fs.exists(full_file_path) catch false) break :blk true;
                var link_buf: [4096]u8 = undefined;
                _ = std.fs.cwd().readLink(full_file_path, &link_buf) catch break :blk false;
                break :blk true;
            };
            if (!path_exists) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: pathspec '{s}' did not match any files\n", .{file_path});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }

            // Check if it's a directory or file
            const metadata = std.fs.cwd().statFile(full_file_path) catch {
                // If we can't stat it (e.g. broken symlink), try to add it
                try addSingleFile(allocator, relative_file_path, full_file_path, &index, git_path, platform_impl, repo_root_for_rel);
                continue;
            };

            if (metadata.kind == .directory) {
                // Add directory recursively
                try addDirectoryRecursively(allocator, repo_root_for_rel, relative_file_path, &index, git_path, platform_impl);
            } else {
                // Add single file
                try addSingleFile(allocator, relative_file_path, full_file_path, &index, git_path, platform_impl, repo_root_for_rel);
            }
        }
    }

    if (!has_files) {
        try platform_impl.writeStderr("Nothing specified, nothing added.\n");
        try platform_impl.writeStderr("hint: Maybe you wanted to say 'git add .'?\n");
        try platform_impl.writeStderr("hint: Disable this message with \"git config set advice.addEmptyPathspec false\"\n");
        return;
    }

    // When --all or --update, remove index entries for deleted files
    if (add_all_flag or update_flag) {
        const repo_root = std.fs.path.dirname(git_path) orelse ".";
        var i: usize = 0;
        while (i < index.entries.items.len) {
            const entry = index.entries.items[i];
            const fp = if (repo_root.len > 0 and !std.mem.eql(u8, repo_root, "."))
                std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path }) catch { i += 1; continue; }
            else
                allocator.dupe(u8, entry.path) catch { i += 1; continue; };
            defer allocator.free(fp);
            const exists = blk2: {
                std.fs.cwd().access(fp, .{}) catch break :blk2 false;
                break :blk2 true;
            };
            if (!exists) {
                index.entries.items[i].deinit(allocator);
                _ = index.entries.orderedRemove(i);
            } else {
                i += 1;
            }
        }
    }

    // Save index
    try index.save(git_path, platform_impl);
}

fn cmdCommit(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("commit: not supported in freestanding mode\n");
        return;
    }

    var message: ?[]const u8 = null;
    var allow_empty = false;
    var amend = false;
    var add_all = false;
    var quiet = false;
    var signoff = false;
    var msg_source: enum { none, m_flag, f_flag, c_flag } = .none;
    var commit_files = std.array_list.Managed([]const u8).init(allocator);
    defer commit_files.deinit();
    var seen_dashdash = false;

    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-m")) {
            if (msg_source == .f_flag or msg_source == .c_flag) {
                try platform_impl.writeStderr("fatal: Option -m cannot be combined with -F or -C/-c\n");
                std.process.exit(128);
            }
            msg_source = .m_flag;
            message = args.next() orelse {
                try platform_impl.writeStderr("error: option `-m' requires a value\n");
                std.process.exit(129);
            };
        } else if (std.mem.startsWith(u8, arg, "-m")) {
            if (msg_source == .f_flag or msg_source == .c_flag) {
                try platform_impl.writeStderr("fatal: Option -m cannot be combined with -F or -C/-c\n");
                std.process.exit(128);
            }
            msg_source = .m_flag;
            message = arg[2..];
        } else if (std.mem.eql(u8, arg, "-a")) {
            add_all = true;
        } else if (std.mem.eql(u8, arg, "-am") or std.mem.eql(u8, arg, "-ma")) {
            add_all = true;
            message = args.next() orelse {
                try platform_impl.writeStderr("error: option `-am' requires a message\n");
                std.process.exit(129);
            };
        } else if (std.mem.startsWith(u8, arg, "-am")) {
            add_all = true;
            message = arg[3..];
        } else if (std.mem.eql(u8, arg, "--allow-empty")) {
            allow_empty = true;
        } else if (std.mem.eql(u8, arg, "--amend")) {
            amend = true;
        } else if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "-F") or std.mem.eql(u8, arg, "--file")) {
            if (msg_source == .m_flag or msg_source == .c_flag) {
                try platform_impl.writeStderr("fatal: Option -F cannot be combined with -m or -C/-c\n");
                std.process.exit(128);
            }
            msg_source = .f_flag;
            const file_path = args.next() orelse {
                try platform_impl.writeStderr("error: option '-F' requires a value\n");
                std.process.exit(129);
            };
            if (std.mem.eql(u8, file_path, "-")) {
                // Read from stdin
                const stdin_data = readStdin(allocator, 1024 * 1024) catch {
                    try platform_impl.writeStderr("error: could not read from stdin\n");
                    std.process.exit(1);
                };
                message = stdin_data;
            } else {
                message = platform_impl.fs.readFile(allocator, file_path) catch {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: could not read file '{s}'\n", .{file_path});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                };
            }
        } else if (std.mem.startsWith(u8, arg, "-F")) {
            const file_path = arg[2..];
            message = platform_impl.fs.readFile(allocator, file_path) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: could not read file '{s}'\n", .{file_path});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            };
        } else if (std.mem.eql(u8, arg, "-C") or std.mem.eql(u8, arg, "--reuse-message")) {
            if (msg_source == .m_flag or msg_source == .f_flag) {
                try platform_impl.writeStderr("fatal: Option -C cannot be combined with -m or -F\n");
                std.process.exit(128);
            }
            msg_source = .c_flag;
            // Reuse message from another commit
            const commit_ref = args.next() orelse {
                try platform_impl.writeStderr("error: option '-C' requires a value\n");
                std.process.exit(129);
            };
            // Resolve and read the commit's message
            const gp = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository\n");
                std.process.exit(128);
            };
            defer allocator.free(gp);
            const hash = resolveRevision(gp, commit_ref, platform_impl, allocator) catch {
                const err_msg = try std.fmt.allocPrint(allocator, "fatal: could not lookup commit {s}\n", .{commit_ref});
                defer allocator.free(err_msg);
                try platform_impl.writeStderr(err_msg);
                std.process.exit(128);
            };
            defer allocator.free(hash);
            const cobj = objects.GitObject.load(hash, gp, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: could not read commit\n");
                std.process.exit(128);
            };
            defer cobj.deinit(allocator);
            // Extract message body (after blank line)
            if (std.mem.indexOf(u8, cobj.data, "\n\n")) |pos| {
                message = try allocator.dupe(u8, cobj.data[pos + 2 ..]);
            }
        } else if (std.mem.eql(u8, arg, "--cleanup=verbatim") or std.mem.eql(u8, arg, "--cleanup=whitespace") or
            std.mem.eql(u8, arg, "--cleanup=strip") or std.mem.eql(u8, arg, "--cleanup=scissors") or
            std.mem.startsWith(u8, arg, "--cleanup="))
        {
            // Accept cleanup modes (ignore for now)
        } else if (std.mem.eql(u8, arg, "--no-verify") or std.mem.eql(u8, arg, "-n")) {
            // Skip hooks
        } else if (std.mem.eql(u8, arg, "--signoff") or std.mem.eql(u8, arg, "-s")) {
            signoff = true;
        } else if (std.mem.eql(u8, arg, "--no-edit")) {
            // No edit
        } else if (std.mem.eql(u8, arg, "--date")) {
            if (args.next()) |dv| {
                const dv_z = try allocator.dupeZ(u8, dv);
                defer allocator.free(dv_z);
                _ = cSetenv("GIT_AUTHOR_DATE", dv_z, 1);
            }
        } else if (std.mem.startsWith(u8, arg, "--date=")) {
            const dv = arg["--date=".len..];
            const dv_z = try allocator.dupeZ(u8, dv);
            defer allocator.free(dv_z);
            _ = cSetenv("GIT_AUTHOR_DATE", dv_z, 1);
        } else if (std.mem.eql(u8, arg, "--author")) {
            _ = args.next(); // consume but ignore for now
        } else if (std.mem.startsWith(u8, arg, "--author=")) {
            // ignore for now
        } else if (std.mem.eql(u8, arg, "--allow-empty-message")) {
            allow_empty = true; // Close enough
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_dashdash = true;
            while (args.next()) |farg| try commit_files.append(farg);
            break;
        } else if (arg.len > 0 and arg[0] != '-') {
            // Positional argument - could be a file path
            try commit_files.append(arg);
        }
    }

    // Validate: -a and paths don't mix
    if (add_all and commit_files.items.len > 0) {
        try platform_impl.writeStderr("fatal: paths 'file ...' with -a does not make sense\n");
        std.process.exit(128);
    }

    // For --amend without -m, reuse the previous commit's message
    if (message == null and amend) {
        const gp = findGitDirectory(allocator, platform_impl) catch {
            try platform_impl.writeStderr("fatal: not a git repository\n");
            std.process.exit(128);
        };
        defer allocator.free(gp);
        if (refs.getCurrentCommit(gp, platform_impl, allocator) catch null) |cur_hash| {
            defer allocator.free(cur_hash);
            if (objects.GitObject.load(cur_hash, gp, platform_impl, allocator) catch null) |cobj| {
                defer cobj.deinit(allocator);
                if (std.mem.indexOf(u8, cobj.data, "\n\n")) |pos| {
                    message = try allocator.dupe(u8, cobj.data[pos + 2 ..]);
                }
            }
        }
    }

    // Find .git directory (needed for MERGE_MSG check below)
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Check for MERGE_MSG or SQUASH_MSG as default message if no message provided
    if (message == null) {
        const merge_msg_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_MSG", .{git_path});
        defer allocator.free(merge_msg_path);
        if (platform_impl.fs.readFile(allocator, merge_msg_path)) |mmsg| {
            message = mmsg;
        } else |_| {}
    }
    if (message == null) {
        const squash_msg_path = try std.fmt.allocPrint(allocator, "{s}/SQUASH_MSG", .{git_path});
        defer allocator.free(squash_msg_path);
        if (platform_impl.fs.readFile(allocator, squash_msg_path)) |smsg| {
            message = smsg;
        } else |_| {}
    }

    if (message == null) {
        try platform_impl.writeStderr("error: no commit message provided (use -m)\n");
        std.process.exit(1);
    }

    // Check for empty or whitespace-only message (to match git behavior)
    if (message) |msg| {
        const trimmed = std.mem.trim(u8, msg, " \t\n\r");
        if (trimmed.len == 0) {
            try platform_impl.writeStderr("Aborting commit due to empty commit message.\n");
            std.process.exit(1);
        }
    }

    // Load index
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.FileNotFound => index_mod.Index.init(allocator),
        else => return err,
    };

    // If -a flag is set, update all tracked files in the index (pure Zig, no git CLI)
    if (add_all) {
        const repo_root = std.fs.path.dirname(git_path) orelse ".";
        try stageTrackedChanges(allocator, &index, git_path, repo_root, platform_impl);
    }

    // If file paths were specified, stage those files before committing
    if (commit_files.items.len > 0) {
        const cwd = try platform_impl.fs.getCwd(allocator);
        defer allocator.free(cwd);
        for (commit_files.items) |file_arg| {
            const full_path = if (std.fs.path.isAbsolute(file_arg))
                try allocator.dupe(u8, file_arg)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cwd, file_arg });
            defer allocator.free(full_path);
            
            const metadata = std.fs.cwd().statFile(full_path) catch continue;
            if (metadata.kind == .directory) {
                try addDirectoryRecursively(allocator, cwd, file_arg, &index, git_path, platform_impl);
            } else {
                try addSingleFile(allocator, file_arg, full_path, &index, git_path, platform_impl, cwd);
            }
        }
    }
    // seen_dashdash used above
    defer index.deinit();

    // Check if there's anything to commit - compare index tree to HEAD tree
    if (!allow_empty) {
        const new_tree = try buildRecursiveTree(allocator, index.entries.items, "", git_path, platform_impl);
        defer allocator.free(new_tree);
        var has_changes = true;
        if (refs.getCurrentCommit(git_path, platform_impl, allocator) catch null) |head_h| {
            defer allocator.free(head_h);
            if (objects.GitObject.load(head_h, git_path, platform_impl, allocator)) |head_obj| {
                defer head_obj.deinit(allocator);
                const head_tree = extractHeaderField(head_obj.data, "tree");
                if (std.mem.eql(u8, new_tree, head_tree)) has_changes = false;
            } else |_| {}
        } else {
            // No HEAD - has changes if index is not empty
            if (index.entries.items.len == 0) has_changes = false;
        }
        if (!has_changes and !amend) {
            const current_branch = refs.getCurrentBranch(git_path, platform_impl, allocator) catch "master";
            defer allocator.free(current_branch);
            const branch_msg = try std.fmt.allocPrint(allocator, "On branch {s}\n", .{current_branch});
            defer allocator.free(branch_msg);
            try platform_impl.writeStderr(branch_msg);
            try platform_impl.writeStderr("nothing to commit, working tree clean\n");
            std.process.exit(1);
        }
    }

    // Create recursive tree objects from index entries (handles nested directories)
    const tree_hash = try buildRecursiveTree(allocator, index.entries.items, "", git_path, platform_impl);
    defer allocator.free(tree_hash);

    // Get parent commit (if any)
    var parent_hashes = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (parent_hashes.items) |hash| {
            allocator.free(hash);
        }
        parent_hashes.deinit();
    }

    if (amend) {
        // For amend, get the parents of the current commit (grandparents become parents)
        if (refs.getCurrentCommit(git_path, platform_impl, allocator) catch null) |current_hash| {
            defer allocator.free(current_hash);
            
            // Load current commit to get its parents
            const commit_object = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch null;
            if (commit_object) |commit| {
                defer commit.deinit(allocator);
                
                // Parse commit data to find parent lines
                var lines = std.mem.splitSequence(u8, commit.data, "\n");
                while (lines.next()) |line| {
                    if (std.mem.startsWith(u8, line, "parent ")) {
                        const parent_hash = line["parent ".len..];
                        try parent_hashes.append(try allocator.dupe(u8, parent_hash));
                    } else if (line.len == 0) {
                        break; // End of headers
                    }
                }
            }
        }
    } else {
        if (refs.getCurrentCommit(git_path, platform_impl, allocator) catch null) |current_hash| {
            try parent_hashes.append(current_hash);
        }
        
        // Check for MERGE_HEAD (merge parents)
        const merge_head_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_HEAD", .{git_path});
        defer allocator.free(merge_head_path);
        if (platform_impl.fs.readFile(allocator, merge_head_path)) |merge_data| {
            defer allocator.free(merge_data);
            var merge_lines = std.mem.splitScalar(u8, merge_data, '\n');
            while (merge_lines.next()) |mline| {
                const mhash = std.mem.trim(u8, mline, " \t\r");
                if (mhash.len == 40 and isValidHexString(mhash)) {
                    try parent_hashes.append(try allocator.dupe(u8, mhash));
                }
            }
        } else |_| {}
    }

    // Create commit object - use GIT_AUTHOR_DATE/GIT_COMMITTER_DATE if set
    const author_info = getAuthorString(allocator) catch blk: {
        const timestamp = std.time.timestamp();
        const tz_offset = getTimezoneOffset(timestamp);
        const tz_sign: u8 = if (tz_offset < 0) '-' else '+';
        const tz_abs: u32 = @intCast(if (tz_offset < 0) -tz_offset else tz_offset);
        const tz_hours = tz_abs / 3600;
        const tz_minutes = (tz_abs % 3600) / 60;
        break :blk try std.fmt.allocPrint(allocator, "Unknown <unknown@unknown> {d} {c}{d:0>2}{d:0>2}", .{ timestamp, tz_sign, tz_hours, tz_minutes });
    };
    defer allocator.free(author_info);
    const committer_info = getCommitterString(allocator) catch blk: {
        const timestamp = std.time.timestamp();
        const tz_offset = getTimezoneOffset(timestamp);
        const tz_sign: u8 = if (tz_offset < 0) '-' else '+';
        const tz_abs: u32 = @intCast(if (tz_offset < 0) -tz_offset else tz_offset);
        const tz_hours = tz_abs / 3600;
        const tz_minutes = (tz_abs % 3600) / 60;
        break :blk try std.fmt.allocPrint(allocator, "Unknown <unknown@unknown> {d} {c}{d:0>2}{d:0>2}", .{ timestamp, tz_sign, tz_hours, tz_minutes });
    };
    defer allocator.free(committer_info);

    // Add sign-off line if requested
    if (signoff) {
        // Extract name and email from committer info (format: "Name <email> timestamp tz")
        const committer_name_email = blk: {
            // Find the last '>' to get "Name <email>"
            if (std.mem.lastIndexOf(u8, committer_info, ">")) |gt_pos| {
                break :blk committer_info[0..gt_pos + 1];
            }
            break :blk committer_info;
        };
        const signoff_line = try std.fmt.allocPrint(allocator, "Signed-off-by: {s}", .{committer_name_email});
        defer allocator.free(signoff_line);
        // Only add if not already present
        if (message != null and std.mem.indexOf(u8, message.?, signoff_line) == null) {
            const old_msg = message.?;
            const trimmed_msg = std.mem.trimRight(u8, old_msg, "\n");
            // Check if message already ends with a trailer (like another Signed-off-by)
            const has_trailer = blk: {
                // Look at the last line of the trimmed message
                if (std.mem.lastIndexOf(u8, trimmed_msg, "\n")) |last_nl| {
                    const last_line = trimmed_msg[last_nl + 1..];
                    break :blk std.mem.indexOf(u8, last_line, ": ") != null;
                }
                break :blk false;
            };
            if (has_trailer) {
                message = try std.fmt.allocPrint(allocator, "{s}\n{s}\n", .{trimmed_msg, signoff_line});
            } else {
                message = try std.fmt.allocPrint(allocator, "{s}\n\n{s}\n", .{trimmed_msg, signoff_line});
            }
        }
    }

    const commit_object = try objects.createCommitObject(
        tree_hash,
        parent_hashes.items,
        author_info,
        committer_info,
        message.?,
        allocator,
    );
    defer commit_object.deinit(allocator);

    const commit_hash = try commit_object.store(git_path, platform_impl, allocator);
    defer allocator.free(commit_hash);

    // Update current branch
    const current_branch = try refs.getCurrentBranch(git_path, platform_impl, allocator);
    defer allocator.free(current_branch);
    
    // Get old hash before updating
    const old_commit_hash = refs.resolveRef(git_path, current_branch, platform_impl, allocator) catch null;
    defer if (old_commit_hash) |h| allocator.free(h);
    
    try refs.updateRef(git_path, current_branch, commit_hash, platform_impl, allocator);
    
    // Write reflog entries for both the branch and HEAD
    {
        const zero_h = "0000000000000000000000000000000000000000";
        const old_h = old_commit_hash orelse zero_h;
        
        // Determine reflog message
        const reflog_msg = if (amend)
            "commit (amend): "
        else if (old_commit_hash == null)
            "commit (initial): "
        else if (parent_hashes.items.len > 1)
            "commit (merge): "
        else
            "commit: ";
        
        const full_reflog_msg = try std.fmt.allocPrint(allocator, "{s}{s}", .{ reflog_msg, std.mem.trim(u8, message orelse "", " \t\n\r") });
        defer allocator.free(full_reflog_msg);
        
        // Write reflog for branch
        writeReflogEntry(git_path, current_branch, old_h, commit_hash, full_reflog_msg, allocator, platform_impl) catch {};
        // Write reflog for HEAD
        writeReflogEntry(git_path, "HEAD", old_h, commit_hash, full_reflog_msg, allocator, platform_impl) catch {};
    }

    // Clean up merge state files after successful commit
    {
        const mh_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_HEAD", .{git_path});
        defer allocator.free(mh_path);
        std.fs.cwd().deleteFile(mh_path) catch {};
        const mm_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_MSG", .{git_path});
        defer allocator.free(mm_path);
        std.fs.cwd().deleteFile(mm_path) catch {};
        const mmode_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_MODE", .{git_path});
        defer allocator.free(mmode_path);
        std.fs.cwd().deleteFile(mmode_path) catch {};
    }
    
    // After a successful commit, the index should remain but be consistent with the new commit
    // We don't clear the index, but we save it to ensure it's properly persisted
    try index.save(git_path, platform_impl);

    // Output success message (unless --quiet was specified)
    if (!quiet) {
        const short_hash = commit_hash[0..7];
        // Check if this is the first commit (root commit)
        const is_root = blk: {
            const cobj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch break :blk false;
            defer cobj.deinit(allocator);
            break :blk std.mem.indexOf(u8, cobj.data, "parent ") == null;
        };
        
        if (is_root) {
            const success_msg = try std.fmt.allocPrint(allocator, "[{s} (root-commit) {s}] {s}\n", .{ current_branch, short_hash, std.mem.trimRight(u8, message.?, "\n") });
            defer allocator.free(success_msg);
            try platform_impl.writeStdout(success_msg);
        } else {
            const success_msg = try std.fmt.allocPrint(allocator, "[{s} {s}] {s}\n", .{ current_branch, short_hash, std.mem.trimRight(u8, message.?, "\n") });
            defer allocator.free(success_msg);
            try platform_impl.writeStdout(success_msg);
        }
        
        // Add diffstat summary: count files changed
        // Compare current tree with parent tree to get stats
        const cobj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch null;
        if (cobj) |co| {
            defer co.deinit(allocator);
            var commit_tree_h: ?[]const u8 = null;
            var commit_parent_h: ?[]const u8 = null;
            var clines2 = std.mem.splitSequence(u8, co.data, "\n");
            while (clines2.next()) |line| {
                if (line.len == 0) break;
                if (std.mem.startsWith(u8, line, "tree ")) commit_tree_h = line["tree ".len..];
                if (std.mem.startsWith(u8, line, "parent ") and commit_parent_h == null) commit_parent_h = line["parent ".len..];
            }
            
            if (commit_tree_h) |_| {
                // Count files that changed (simplified)
                const file_count = index.entries.items.len;
                if (is_root and file_count > 0) {
                    // Root commit: all files are new
                    var total_lines: usize = 0;
                    for (index.entries.items) |entry| {
                        const repo_root_path = std.fs.path.dirname(git_path) orelse ".";
                        const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root_path, entry.path });
                        defer allocator.free(full_path);
                        if (platform_impl.fs.readFile(allocator, full_path)) |content| {
                            defer allocator.free(content);
                            var line_count: usize = 0;
                            for (content) |c| {
                                if (c == '\n') line_count += 1;
                            }
                            if (content.len > 0 and content[content.len - 1] != '\n') line_count += 1;
                            total_lines += line_count;
                        } else |_| {}
                    }
                    const stat_msg = try std.fmt.allocPrint(allocator, " {d} file{s} changed, {d} insertion{s}(+)\n", .{
                        file_count,
                        if (file_count != 1) @as([]const u8, "s") else "",
                        total_lines,
                        if (total_lines != 1) @as([]const u8, "s") else "",
                    });
                    defer allocator.free(stat_msg);
                    try platform_impl.writeStdout(stat_msg);
                }
            }
        }
    }
}

fn cmdLog(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("log: not supported in freestanding mode\n");
        return;
    }

    var oneline = false;
    var format_string: ?[]const u8 = null;
    var format_is_separator = false; // true for "format:", false for "tformat:" / "--format="
    var max_count: ?u32 = null;
    var committish: ?[]const u8 = null;
    
    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--oneline")) {
            oneline = true;
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            format_string = arg["--format=".len..]; 
        } else if (std.mem.startsWith(u8, arg, "--pretty=format:")) {
            format_string = arg["--pretty=format:".len..];
            format_is_separator = true;
        } else if (std.mem.startsWith(u8, arg, "--pretty=tformat:")) {
            format_string = arg["--pretty=tformat:".len..];
            format_is_separator = false;
        } else if (std.mem.eql(u8, arg, "--pretty=oneline") or std.mem.eql(u8, arg, "--pretty=short")) {
            oneline = true;
        } else if (std.mem.eql(u8, arg, "--pretty=medium") or std.mem.eql(u8, arg, "--pretty=full") or std.mem.eql(u8, arg, "--pretty=fuller") or std.mem.eql(u8, arg, "--pretty=email") or std.mem.eql(u8, arg, "--pretty=raw") or std.mem.eql(u8, arg, "--pretty=reference") or std.mem.eql(u8, arg, "--pretty=mboxrd")) {
            // Named formats - use default for now
        } else if (std.mem.startsWith(u8, arg, "--pretty=")) {
            // Custom format string without "format:" prefix - treat as tformat
            const fmt_val = arg["--pretty=".len..];
            if (fmt_val.len > 0) {
                format_string = fmt_val;
                format_is_separator = false;
            }
        } else if (std.mem.eql(u8, arg, "--first-parent")) {
            // first-parent flag - already the default behavior (we only follow first parent)
        } else if (std.mem.eql(u8, arg, "-S")) {
            // -S requires an argument
            try platform_impl.writeStderr("error: switch `S' requires a value\n");
            std.process.exit(1);
        } else if (std.mem.startsWith(u8, arg, "-S")) {
            // -Sstring - pickaxe search, ignore for now
        } else if (std.mem.startsWith(u8, arg, "-") and arg.len > 1 and std.ascii.isDigit(arg[1])) {
            // Parse -n format like -1, -5, etc.
            const count_str = arg[1..];
            max_count = std.fmt.parseInt(u32, count_str, 10) catch null;
        } else if (std.mem.eql(u8, arg, "-n")) {
            // Parse -n followed by number
            if (args.next()) |count_str| {
                max_count = std.fmt.parseInt(u32, count_str, 10) catch null;
            }
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            // This is likely a committish (commit hash, branch name, etc.)
            committish = arg;
        }
    }

    // Find .git directory
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Resolve starting commit
    var start_commit: []u8 = undefined;
    if (committish) |commit_ref| {
        // Try to resolve committish (branch, tag, or commit hash)
        start_commit = resolveCommittish(git_path, commit_ref, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: ambiguous argument '{s}': unknown revision or path not in the working tree.\n", .{commit_ref});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
    } else {
        // Get current HEAD commit
        const current_commit = refs.getCurrentCommit(git_path, platform_impl, allocator) catch null;
        if (current_commit == null) {
            try platform_impl.writeStderr("fatal: your current branch does not have any commits yet\n");
            std.process.exit(128);
        }
        start_commit = current_commit.?;
    }
    defer allocator.free(start_commit);

    // Fast path for common case: log --format=%H -1 (just output HEAD commit hash)
    if (format_string != null and std.mem.eql(u8, format_string.?, "%H") and 
        (max_count == 1) and committish == null) {
        const output = try std.fmt.allocPrint(allocator, "{s}\n", .{start_commit});
        defer allocator.free(output);
        try platform_impl.writeStdout(output);
        return;
    }
    
    // Walk the commit history using priority queue (sorted by committer date)
    const CommitQueueEntry = struct {
        hash: []const u8,
        timestamp: i64,
    };
    var queue = std.array_list.Managed(CommitQueueEntry).init(allocator);
    defer {
        for (queue.items) |entry| allocator.free(@constCast(entry.hash));
        queue.deinit();
    }

    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var iterator = visited.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
        }
        visited.deinit();
    }

    // Seed the queue with the start commit
    const start_ts = getCommitTimestamp(start_commit, git_path, platform_impl, allocator);
    try queue.append(.{ .hash = try allocator.dupe(u8, start_commit), .timestamp = start_ts });
    try visited.put(try allocator.dupe(u8, start_commit), {});

    var count: u32 = 0;
    while (queue.items.len > 0 and (max_count == null or count < max_count.?)) {
        // Find the entry with the highest timestamp (most recent commit)
        var best_idx: usize = 0;
        for (queue.items, 0..) |entry, i| {
            if (entry.timestamp > queue.items[best_idx].timestamp) {
                best_idx = i;
            }
        }
        const current = queue.orderedRemove(best_idx);
        const cur_hash = current.hash;
        defer allocator.free(@constCast(cur_hash));

        // Load commit object
        const commit_object = objects.GitObject.load(cur_hash, git_path, platform_impl, allocator) catch |err| switch (err) {
            error.ObjectNotFound => {
                const msg = try std.fmt.allocPrint(allocator, "fatal: bad object {s}\n", .{cur_hash});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                return;
            },
            else => return err,
        };
        defer commit_object.deinit(allocator);

        if (commit_object.type != .commit) {
            try platform_impl.writeStderr("fatal: not a commit object\n");
            return;
        }

        // Parse commit data
        const commit_data = commit_object.data;
        
        // Extract commit message and author
        var lines_it = std.mem.splitSequence(u8, commit_data, "\n");
        var parent_hashes = std.array_list.Managed([]const u8).init(allocator);
        defer parent_hashes.deinit();
        var author_line: ?[]const u8 = null;
        var empty_line_found = false;
        var message = std.array_list.Managed(u8).init(allocator);
        defer message.deinit();

        while (lines_it.next()) |line| {
            if (empty_line_found) {
                try message.appendSlice(line);
                try message.append('\n');
            } else if (line.len == 0) {
                empty_line_found = true;
            } else if (std.mem.startsWith(u8, line, "parent ")) {
                try parent_hashes.append(line["parent ".len..]);
            } else if (std.mem.startsWith(u8, line, "author ")) {
                author_line = line["author ".len..];
            }
        }

        // Display commit based on format
        if (format_string) |fmt| {
            if (format_is_separator and count > 0) {
                try platform_impl.writeStdout("\n");
            }
            try outputFormattedCommit(fmt, cur_hash, allocator, platform_impl);
            if (!format_is_separator) {
                try platform_impl.writeStdout("\n");
            }
        } else if (oneline) {
            const short_hash = cur_hash[0..@min(7, cur_hash.len)];
            const first_line = blk: {
                var msg_lines = std.mem.splitSequence(u8, std.mem.trimRight(u8, message.items, "\n"), "\n");
                if (msg_lines.next()) |line| {
                    break :blk line;
                } else {
                    break :blk "";
                }
            };
            const oneline_output = try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ short_hash, first_line });
            defer allocator.free(oneline_output);
            try platform_impl.writeStdout(oneline_output);
        } else {
            const commit_header = try std.fmt.allocPrint(allocator, "commit {s}\n", .{cur_hash});
            defer allocator.free(commit_header);
            try platform_impl.writeStdout(commit_header);

            // Show Merge line for merge commits (commits with 2+ parents)
            if (parent_hashes.items.len > 1) {
                var merge_line = std.array_list.Managed(u8).init(allocator);
                defer merge_line.deinit();
                try merge_line.appendSlice("Merge:");
                for (parent_hashes.items) |ph| {
                    try merge_line.appendSlice(" ");
                    try merge_line.appendSlice(ph[0..@min(7, ph.len)]);
                }
                try merge_line.appendSlice("\n");
                try platform_impl.writeStdout(merge_line.items);
            }

            if (author_line) |author| {
                // Parse author into name <email> and date
                const a_name = parseAuthorName(author);
                const a_email = parseAuthorEmail(author);
                const author_output = try std.fmt.allocPrint(allocator, "Author: {s} <{s}>\n", .{ a_name, a_email });
                defer allocator.free(author_output);
                try platform_impl.writeStdout(author_output);
                
                // Date line
                const date_str = parseAuthorDateGitFmt(author, allocator);
                defer if (date_str) |d| allocator.free(d);
                if (date_str) |d| {
                    const date_output = try std.fmt.allocPrint(allocator, "Date:   {s}\n", .{d});
                    defer allocator.free(date_output);
                    try platform_impl.writeStdout(date_output);
                }
            }

            try platform_impl.writeStdout("\n");
            // Output message with 4-space indent, handling multi-line messages
            const trimmed_msg = std.mem.trimRight(u8, message.items, "\n");
            var msg_iter = std.mem.splitScalar(u8, trimmed_msg, '\n');
            while (msg_iter.next()) |line| {
                if (line.len == 0) {
                    try platform_impl.writeStdout("\n");
                } else {
                    const indented = try std.fmt.allocPrint(allocator, "    {s}\n", .{line});
                    defer allocator.free(indented);
                    try platform_impl.writeStdout(indented);
                }
            }
            try platform_impl.writeStdout("\n");
        }

        count += 1;

        // Add all parents to the queue
        for (parent_hashes.items) |parent| {
            if (!visited.contains(parent)) {
                try visited.put(try allocator.dupe(u8, parent), {});
                const pts = getCommitTimestamp(parent, git_path, platform_impl, allocator);
                try queue.append(.{ .hash = try allocator.dupe(u8, parent), .timestamp = pts });
            }
        }
    }
}

fn getCommitTimestamp(hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) i64 {
    const obj = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch return 0;
    defer obj.deinit(allocator);
    var line_iter = std.mem.splitScalar(u8, obj.data, '\n');
    while (line_iter.next()) |line| {
        if (line.len == 0) break;
        if (std.mem.startsWith(u8, line, "committer ")) {
            if (std.mem.indexOf(u8, line, "> ")) |gt| {
                const rest = line[gt + 2 ..];
                if (std.mem.indexOf(u8, rest, " ")) |sp| {
                    return std.fmt.parseInt(i64, rest[0..sp], 10) catch 0;
                }
                return std.fmt.parseInt(i64, rest, 10) catch 0;
            }
        }
    }
    return 0;
}

fn resolveHeadRelative(git_path: []const u8, steps: u32, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // Start from HEAD
    var current_hash = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
        return error.UnknownRevision;
    };
    
    if (current_hash == null) {
        return error.UnknownRevision;
    }
    
    // Walk back 'steps' number of parents
    var i: u32 = 0;
    while (i < steps) {
        const commit_obj = objects.GitObject.load(current_hash.?, git_path, platform_impl, allocator) catch {
            allocator.free(current_hash.?);
            return error.UnknownRevision;
        };
        defer commit_obj.deinit(allocator);
        
        if (commit_obj.type != .commit) {
            allocator.free(current_hash.?);
            return error.UnknownRevision;
        }
        
        // Parse commit data to find the first parent
        var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
        var parent_hash: ?[]const u8 = null;
        
        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                parent_hash = line["parent ".len..];
                break;
            } else if (line.len == 0) {
                break; // End of headers
            }
        }
        
        if (parent_hash == null) {
            // No parent found, can't go further back
            allocator.free(current_hash.?);
            return error.UnknownRevision;
        }
        
        const new_hash = try allocator.dupe(u8, parent_hash.?);
        allocator.free(current_hash.?);
        current_hash = new_hash;
        
        i += 1;
    }
    
    return current_hash.?;
}

fn resolveCommittish(git_path: []const u8, committish: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // Use the comprehensive resolveRevision which handles all ref formats,
    // ~, ^, ^{type}, hashes, branches, tags, remotes, packed-refs
    return resolveRevision(git_path, committish, platform_impl, allocator) catch error.UnknownRevision;
}

fn outputFormattedCommit(format: []const u8, commit_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // We need access to the full commit object for format specifiers
    const git_path = findGitDirectory(allocator, platform_impl) catch return;
    defer allocator.free(git_path);
    
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch return;
    defer commit_obj.deinit(allocator);
    
    // Parse commit fields
    var tree_hash: []const u8 = "";
    var parent_hashes = std.array_list.Managed([]const u8).init(allocator);
    defer parent_hashes.deinit();
    var author_full: []const u8 = "";
    var committer_full: []const u8 = "";
    var subject: []const u8 = "";
    var body = std.array_list.Managed(u8).init(allocator);
    defer body.deinit();
    // Raw message for %B
    var raw_message: []const u8 = "";
    
    if (std.mem.indexOf(u8, commit_obj.data, "\n\n")) |sep_pos| {
        raw_message = commit_obj.data[sep_pos + 2 ..];
    }
    var lines_iter = std.mem.splitSequence(u8, commit_obj.data, "\n");
    var in_body = false;
    var first_body_line = true;
    while (lines_iter.next()) |line| {
        if (in_body) {
            if (first_body_line) {
                subject = line;
                first_body_line = false;
            } else {
                if (body.items.len > 0) body.append('\n') catch {};
                body.appendSlice(line) catch {};
            }
        } else if (line.len == 0) {
            in_body = true;
        } else if (std.mem.startsWith(u8, line, "tree ")) {
            tree_hash = line["tree ".len..];
        } else if (std.mem.startsWith(u8, line, "parent ")) {
            parent_hashes.append(line["parent ".len..]) catch {};
        } else if (std.mem.startsWith(u8, line, "author ")) {
            author_full = line["author ".len..];
        } else if (std.mem.startsWith(u8, line, "committer ")) {
            committer_full = line["committer ".len..];
        }
    }
    
    var output = std.array_list.Managed(u8).init(allocator);
    defer output.deinit();
    
    var i: usize = 0;
    while (i < format.len) {
        if (format[i] == '%' and i + 1 < format.len) {
            const c = format[i + 1];
            if (c == 'H') {
                try output.appendSlice(commit_hash);
                i += 2;
            } else if (c == 'h') {
                try output.appendSlice(if (commit_hash.len >= 7) commit_hash[0..7] else commit_hash);
                i += 2;
            } else if (c == 'T') {
                try output.appendSlice(tree_hash);
                i += 2;
            } else if (c == 't') {
                try output.appendSlice(if (tree_hash.len >= 7) tree_hash[0..7] else tree_hash);
                i += 2;
            } else if (c == 'P') {
                for (parent_hashes.items, 0..) |ph, pi| {
                    if (pi > 0) try output.append(' ');
                    try output.appendSlice(ph);
                }
                i += 2;
            } else if (c == 'p') {
                for (parent_hashes.items, 0..) |ph, pi| {
                    if (pi > 0) try output.append(' ');
                    try output.appendSlice(if (ph.len >= 7) ph[0..7] else ph);
                }
                i += 2;
            } else if (c == 's') {
                try output.appendSlice(subject);
                i += 2;
            } else if (c == 'b') {
                try output.appendSlice(std.mem.trimRight(u8, body.items, "\n"));
                i += 2;
            } else if (c == 'B') {
                const trimmed_raw = std.mem.trimRight(u8, raw_message, "\n");
                try output.appendSlice(trimmed_raw);
                try output.append('\n');
                i += 2;
            } else if (c == 'n') {
                try output.append('\n');
                i += 2;
            } else if (c == '%') {
                try output.append('%');
                i += 2;
            } else if (c == 'a' and i + 2 < format.len) {
                // %an = author name, %ae = author email, %ad = author date, %aI = ISO date
                const spec = format[i + 2];
                const parsed = parseIdentField(author_full);
                if (spec == 'n') {
                    try output.appendSlice(parsed.name);
                } else if (spec == 'e') {
                    try output.appendSlice(parsed.email);
                } else if (spec == 'd' or spec == 'D' or spec == 'i' or spec == 'I') {
                    try output.appendSlice(parsed.date);
                } else {
                    try output.appendSlice(author_full);
                }
                i += 3;
            } else if (c == 'c' and i + 2 < format.len) {
                // %cn, %ce, %cd, %cI
                const spec = format[i + 2];
                const parsed = parseIdentField(committer_full);
                if (spec == 'n') {
                    try output.appendSlice(parsed.name);
                } else if (spec == 'e') {
                    try output.appendSlice(parsed.email);
                } else if (spec == 'd' or spec == 'D' or spec == 'i' or spec == 'I') {
                    try output.appendSlice(parsed.date);
                } else {
                    try output.appendSlice(committer_full);
                }
                i += 3;
            } else if (c == 'd') {
                // %d = decorations (simplified - just empty for now)
                i += 2;
            } else if (c == 'D') {
                // %D = decorations without wrapping
                i += 2;
            } else if (c == 'G' and i + 2 < format.len) {
                // %G? = GPG signature placeholders
                i += 3;
            } else if (c == 'C' and i + 2 < format.len) {
                // %C(...) = color codes - skip
                if (i + 2 < format.len and format[i + 2] == '(') {
                    // Find closing paren
                    var j = i + 3;
                    while (j < format.len and format[j] != ')') : (j += 1) {}
                    i = if (j < format.len) j + 1 else j;
                } else {
                    i += 3;
                }
            } else if (c == 'x' and i + 3 < format.len) {
                // %x00 = hex byte
                const hex_str = format[i + 2 .. i + 4];
                const byte_val = std.fmt.parseInt(u8, hex_str, 16) catch 0;
                try output.append(byte_val);
                i += 4;
            } else {
                try output.append(format[i]);
                try output.append(format[i + 1]);
                i += 2;
            }
        } else if (format[i] == '\\' and i + 1 < format.len) {
            if (format[i + 1] == 'n') {
                try output.append('\n');
                i += 2;
            } else if (format[i + 1] == 't') {
                try output.append('\t');
                i += 2;
            } else {
                try output.append(format[i]);
                i += 1;
            }
        } else {
            try output.append(format[i]);
            i += 1;
        }
    }
    
    // Note: caller is responsible for adding newlines (separator vs terminator)
    try platform_impl.writeStdout(output.items);
}

const ParsedIdent = struct {
    name: []const u8,
    email: []const u8,
    date: []const u8,
};

fn parseIdentField(ident: []const u8) ParsedIdent {
    // Parse "Name <email> timestamp timezone"
    if (std.mem.indexOf(u8, ident, " <")) |lt_pos| {
        const name = ident[0..lt_pos];
        if (std.mem.indexOf(u8, ident[lt_pos..], "> ")) |gt_pos| {
            const email = ident[lt_pos + 2 .. lt_pos + gt_pos];
            const date = ident[lt_pos + gt_pos + 2 ..];
            return .{ .name = name, .email = email, .date = date };
        }
        return .{ .name = name, .email = ident[lt_pos + 2 ..], .date = "" };
    }
    return .{ .name = ident, .email = "", .date = "" };
}

fn cmdDiff(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("diff: not supported in freestanding mode\n");
        return;
    }

    // Collect all args first to check for --no-index
    var all_diff_args = std.array_list.Managed([]const u8).init(allocator);
    defer all_diff_args.deinit();
    while (args.next()) |arg| {
        try all_diff_args.append(arg);
    }

    // Check for --no-index
    var no_index = false;
    for (all_diff_args.items) |arg| {
        if (std.mem.eql(u8, arg, "--no-index")) {
            no_index = true;
            break;
        }
    }

    if (no_index) {
        try cmdDiffNoIndex(allocator, all_diff_args.items, platform_impl);
        return;
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Check for flags
    var cached = false;
    var quiet = false;
    var exit_code = false;
    var diff_output_mode: enum { patch, stat, shortstat, numstat, name_only, name_status, raw, no_patch, summary, dirstat, patch_with_stat, patch_with_raw } = .patch;
    var check_mode = false;
    var positional = std.array_list.Managed([]const u8).init(allocator);
    defer positional.deinit();
    var pathspec_args = std.array_list.Managed([]const u8).init(allocator);
    defer pathspec_args.deinit();
    var seen_dashdash = false;
    // Re-parse args (need an iterator)
    var diff_arg_idx: usize = 0;
    while (diff_arg_idx < all_diff_args.items.len) : (diff_arg_idx += 1) {
        const arg = all_diff_args.items[diff_arg_idx];
        if (seen_dashdash) {
            try pathspec_args.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_dashdash = true;
        } else if (std.mem.eql(u8, arg, "--cached") or std.mem.eql(u8, arg, "--staged")) {
            cached = true;
        } else if (std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
            exit_code = true;
        } else if (std.mem.eql(u8, arg, "--exit-code")) {
            exit_code = true;
        } else if (std.mem.eql(u8, arg, "--stat") or std.mem.startsWith(u8, arg, "--stat=")) {
            diff_output_mode = .stat;
        } else if (std.mem.eql(u8, arg, "--shortstat")) {
            diff_output_mode = .shortstat;
        } else if (std.mem.eql(u8, arg, "--numstat")) {
            diff_output_mode = .numstat;
        } else if (std.mem.eql(u8, arg, "--name-only")) {
            diff_output_mode = .name_only;
        } else if (std.mem.eql(u8, arg, "--name-status")) {
            diff_output_mode = .name_status;
        } else if (std.mem.eql(u8, arg, "--raw")) {
            diff_output_mode = .raw;
        } else if (std.mem.eql(u8, arg, "--no-patch") or std.mem.eql(u8, arg, "-s")) {
            diff_output_mode = .no_patch;
        } else if (std.mem.eql(u8, arg, "-p") or std.mem.eql(u8, arg, "--patch") or std.mem.eql(u8, arg, "-u")) {
            // default patch mode (already default)
        } else if (std.mem.eql(u8, arg, "--no-pager")) {
            // ignore
        } else if (std.mem.eql(u8, arg, "-w") or std.mem.eql(u8, arg, "--ignore-all-space") or
            std.mem.eql(u8, arg, "--ignore-space-at-eol") or std.mem.eql(u8, arg, "--ignore-space-change") or
            std.mem.eql(u8, arg, "-b") or std.mem.eql(u8, arg, "--ignore-blank-lines"))
        {
            // whitespace options - accept but don't fully implement
        } else if (std.mem.eql(u8, arg, "--summary") or std.mem.eql(u8, arg, "--compact-summary")) {
            diff_output_mode = .summary;
        } else if (std.mem.eql(u8, arg, "--dirstat") or std.mem.eql(u8, arg, "--cumulative") or std.mem.eql(u8, arg, "--dirstat-by-file")) {
            diff_output_mode = .dirstat;
        } else if (std.mem.eql(u8, arg, "--patch-with-stat")) {
            diff_output_mode = .patch_with_stat;
        } else if (std.mem.eql(u8, arg, "--patch-with-raw")) {
            diff_output_mode = .patch_with_raw;
        } else if (std.mem.eql(u8, arg, "--check")) {
            check_mode = true;
        } else if (std.mem.eql(u8, arg, "--full-index") or std.mem.eql(u8, arg, "--binary") or
            std.mem.eql(u8, arg, "--abbrev") or std.mem.startsWith(u8, arg, "--abbrev=") or
            std.mem.eql(u8, arg, "--no-renames") or std.mem.eql(u8, arg, "-M") or std.mem.startsWith(u8, arg, "-M") or
            std.mem.eql(u8, arg, "-C") or std.mem.startsWith(u8, arg, "-C") or
            std.mem.eql(u8, arg, "--find-copies-harder") or
            std.mem.eql(u8, arg, "--color") or std.mem.startsWith(u8, arg, "--color=") or
            std.mem.eql(u8, arg, "--no-color") or
            std.mem.startsWith(u8, arg, "-U") or std.mem.startsWith(u8, arg, "--unified=") or
            std.mem.startsWith(u8, arg, "--diff-filter=") or
            std.mem.startsWith(u8, arg, "--submodule") or std.mem.startsWith(u8, arg, "--submodule=") or
            std.mem.startsWith(u8, arg, "--dirstat=") or
            std.mem.startsWith(u8, arg, "-G") or std.mem.startsWith(u8, arg, "-S") or
            std.mem.eql(u8, arg, "--pickaxe-regex") or std.mem.eql(u8, arg, "--pickaxe-all") or
            std.mem.eql(u8, arg, "--relative") or std.mem.startsWith(u8, arg, "--relative=") or
            std.mem.startsWith(u8, arg, "--diff-algorithm=") or
            std.mem.eql(u8, arg, "--patience") or std.mem.eql(u8, arg, "--histogram") or std.mem.eql(u8, arg, "--minimal") or
            std.mem.eql(u8, arg, "--indent-heuristic") or std.mem.eql(u8, arg, "--no-indent-heuristic") or
            std.mem.startsWith(u8, arg, "--inter-hunk-context=") or
            std.mem.startsWith(u8, arg, "--stat=") or std.mem.startsWith(u8, arg, "--stat-width=") or
            std.mem.startsWith(u8, arg, "--stat-name-width=") or std.mem.startsWith(u8, arg, "--stat-count=") or
            std.mem.startsWith(u8, arg, "--line-prefix=") or
            std.mem.eql(u8, arg, "--function-context") or std.mem.eql(u8, arg, "--ext-diff") or std.mem.eql(u8, arg, "--no-ext-diff") or
            std.mem.eql(u8, arg, "--textconv") or std.mem.eql(u8, arg, "--no-textconv") or
            std.mem.eql(u8, arg, "--word-diff") or std.mem.startsWith(u8, arg, "--word-diff=") or
            std.mem.startsWith(u8, arg, "--word-diff-regex=") or
            std.mem.eql(u8, arg, "--text") or std.mem.eql(u8, arg, "-a") or
            std.mem.eql(u8, arg, "--no-index") or std.mem.eql(u8, arg, "--ita-invisible-in-index") or
            std.mem.eql(u8, arg, "--ita-visible-in-index") or
            std.mem.eql(u8, arg, "-R") or
            std.mem.startsWith(u8, arg, "--output=") or
            std.mem.startsWith(u8, arg, "-O") or std.mem.startsWith(u8, arg, "--diff-filter=") or
            std.mem.eql(u8, arg, "--follow") or std.mem.eql(u8, arg, "--no-follow") or
            std.mem.eql(u8, arg, "--ignore-submodules") or std.mem.startsWith(u8, arg, "--ignore-submodules=") or
            std.mem.eql(u8, arg, "--src-prefix") or std.mem.startsWith(u8, arg, "--src-prefix=") or
            std.mem.eql(u8, arg, "--dst-prefix") or std.mem.startsWith(u8, arg, "--dst-prefix=") or
            std.mem.eql(u8, arg, "--no-prefix") or
            std.mem.eql(u8, arg, "--default-prefix") or
            std.mem.eql(u8, arg, "--cc") or
            std.mem.eql(u8, arg, "--combined-all-paths") or
            std.mem.eql(u8, arg, "--merge-base") or
            std.mem.eql(u8, arg, "--anchored") or std.mem.startsWith(u8, arg, "--anchored=") or
            std.mem.startsWith(u8, arg, "--break-rewrites") or std.mem.startsWith(u8, arg, "-B") or
            std.mem.eql(u8, arg, "--find-renames") or std.mem.startsWith(u8, arg, "--find-renames=") or
            std.mem.eql(u8, arg, "--find-copies") or std.mem.startsWith(u8, arg, "--find-copies=") or
            std.mem.eql(u8, arg, "--irreversible-delete") or std.mem.eql(u8, arg, "-D") or
            std.mem.eql(u8, arg, "-l") or std.mem.startsWith(u8, arg, "-l") or
            std.mem.eql(u8, arg, "--no-rename-empty") or std.mem.eql(u8, arg, "--rename-empty") or
            std.mem.startsWith(u8, arg, "--rotate-to=") or std.mem.startsWith(u8, arg, "--skip-to=") or
            std.mem.startsWith(u8, arg, "--ws-error-highlight=") or
            std.mem.startsWith(u8, arg, "--max-depth=") or
            std.mem.eql(u8, arg, "-r") or // recursive (default for diff, accepted for compat)
            std.mem.eql(u8, arg, "--no-abbrev") or
            std.mem.eql(u8, arg, "-t") or // show tree entries
            std.mem.eql(u8, arg, "--color-moved") or std.mem.startsWith(u8, arg, "--color-moved=") or
            std.mem.eql(u8, arg, "--color-moved-ws") or std.mem.startsWith(u8, arg, "--color-moved-ws=") or
            std.mem.startsWith(u8, arg, "-I") or // ignore matching lines
            std.mem.eql(u8, arg, "--") // catch-all for -- which is handled above
        )
        {
            // Known flags - accept but may not fully implement
        } else if (std.mem.startsWith(u8, arg, "--")) {
            // Unknown long option - accept silently for compat
        } else {
            try positional.append(arg);
        }
    }
    
    // Handle commit-to-commit diff, or treat as pathspecs if unresolvable
    var single_ref: ?[]const u8 = null;
    if (positional.items.len >= 1) {
        var ref1: []const u8 = undefined;
        var ref2: []const u8 = undefined;
        var have_two_refs = false;
        var have_one_ref = false;
        var pos_as_pathspec = false;
        
        if (std.mem.indexOf(u8, positional.items[0], "..")) |dot_pos| {
            ref1 = positional.items[0][0..dot_pos];
            ref2 = positional.items[0][dot_pos + 2 ..];
            if (ref2.len > 0 and ref2[0] == '.') ref2 = ref2[1..];
            have_two_refs = true;
        } else {
            // Try resolving as ref
            const mt = resolveToTree(allocator, positional.items[0], git_path, platform_impl) catch null;
            if (mt) |t1| {
                if (positional.items.len >= 2) {
                    const mt2 = resolveToTree(allocator, positional.items[1], git_path, platform_impl) catch null;
                    if (mt2) |t2| {
                        ref1 = positional.items[0]; ref2 = positional.items[1]; have_two_refs = true;
                        allocator.free(t2);
                        for (positional.items[2..]) |p| try pathspec_args.append(p);
                    } else { allocator.free(t1); pos_as_pathspec = true; }
                } else {
                    // Single ref: compare that ref to working tree (or index if --cached)
                    have_one_ref = true;
                    single_ref = positional.items[0];
                }
                if (!pos_as_pathspec and !have_two_refs and !have_one_ref) allocator.free(t1);
            } else { pos_as_pathspec = true; }
        }
        if (pos_as_pathspec) { for (positional.items) |p| try pathspec_args.append(p); }
        
        if (have_two_refs) {
            const tree1 = resolveToTree(allocator, ref1, git_path, platform_impl) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{ref1});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            };
            defer allocator.free(tree1);
            const tree2 = resolveToTree(allocator, ref2, git_path, platform_impl) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{ref2});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            };
            defer allocator.free(tree2);
            if (diff_output_mode == .name_only or diff_output_mode == .name_status or diff_output_mode == .numstat or diff_output_mode == .stat or diff_output_mode == .shortstat or diff_output_mode == .raw or diff_output_mode == .no_patch or diff_output_mode == .summary or diff_output_mode == .dirstat) {
                // Use tree comparison to get file-level changes, then output in requested format
                var diff_entries = std.array_list.Managed(DiffStatEntry).init(allocator);
                defer {
                    for (diff_entries.items) |*de| {
                        allocator.free(de.path);
                    }
                    diff_entries.deinit();
                }
                try collectTreeDiffEntries(allocator, tree1, tree2, "", git_path, pathspec_args.items, platform_impl, &diff_entries);
                if (diff_output_mode != .no_patch) {
                    try outputDiffEntries(diff_entries.items, diff_output_mode, platform_impl, allocator);
                }
                if ((exit_code or quiet) and diff_entries.items.len > 0) {
                    std.process.exit(1);
                }
            } else {
                const has_diff2 = try diffTwoTreesPatch(allocator, tree1, tree2, "", git_path, quiet or check_mode, pathspec_args.items, platform_impl);
                if (check_mode) {
                    // TODO: check whitespace in tree diff
                }
                if ((exit_code or (quiet and has_diff2)) and has_diff2) {
                    std.process.exit(1);
                }
            }
            return;
        }
    }
    
    // Load index 
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.FileNotFound => index_mod.Index.init(allocator),
        else => return err,
    };
    defer index.deinit();
    
    const cwd = try platform_impl.fs.getCwd(allocator);
    defer allocator.free(cwd);
    
    var has_diff = false;
    const use_stat = diff_output_mode == .stat or diff_output_mode == .shortstat or diff_output_mode == .numstat or diff_output_mode == .name_only or diff_output_mode == .name_status or diff_output_mode == .raw or diff_output_mode == .no_patch or diff_output_mode == .summary or diff_output_mode == .dirstat;
    if (use_stat) {
        // Collect diff entries for stat/name output
        var diff_entries = std.array_list.Managed(DiffStatEntry).init(allocator);
        defer {
            for (diff_entries.items) |e| {
                allocator.free(e.path);
            }
            diff_entries.deinit();
        }
        if (single_ref) |sref| {
            // Compare ref tree to working tree (or index if cached)
            has_diff = collectRefDiffEntries(sref, &index, cwd, git_path, platform_impl, allocator, &diff_entries, cached) catch false;
        } else if (cached) {
            has_diff = collectStagedDiffEntries(&index, git_path, platform_impl, allocator, &diff_entries) catch false;
        } else {
            has_diff = collectWorkingTreeDiffEntries(&index, cwd, git_path, platform_impl, allocator, &diff_entries) catch false;
        }
        try outputDiffEntries(diff_entries.items, diff_output_mode, platform_impl, allocator);
    } else {
        if (single_ref) |sref| {
            // Compare ref tree to working tree
            const tree_hash = resolveToTree(allocator, sref, git_path, platform_impl) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{sref});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            };
            defer allocator.free(tree_hash);
            // For now, compare tree to index and show patch
            // Get HEAD tree for comparison
            has_diff = showRefToWorkingTreeDiff(sref, &index, cwd, git_path, platform_impl, allocator, quiet or check_mode, cached) catch false;
        } else if (cached) {
            // Show differences between index and HEAD (staged changes)
            has_diff = showStagedDiff(&index, git_path, platform_impl, allocator, quiet or check_mode) catch false;
        } else {
            // Show differences between working tree and index
            has_diff = showWorkingTreeDiff(&index, cwd, platform_impl, allocator, quiet or check_mode) catch false;
        }
    }
    
    var ws_errors = false;
    if (check_mode) {
        // In check mode, we need to re-run the diff and check for whitespace errors
        // For now, check working tree for trailing whitespace in modified files
        if (positional.items.len == 0) {
            // Check for whitespace errors in changed files
            for (index.entries.items) |entry| {
                if (pathspec_args.items.len > 0) {
                    var matches = false;
                    for (pathspec_args.items) |ps| {
                        if (pathspecMatch(ps, entry.path)) { matches = true; break; }
                    }
                    if (!matches) continue;
                }
                // Get the content to check
                var check_content: []const u8 = undefined;
                var check_content_owned = false;
                if (cached) {
                    // Cached: check the index (staged) content
                    var idx_hash_buf: [40]u8 = undefined;
                    _ = std.fmt.bufPrint(&idx_hash_buf, "{x}", .{&entry.sha1}) catch continue;
                    const idx_obj = objects.GitObject.load(&idx_hash_buf, git_path, platform_impl, allocator) catch continue;
                    defer idx_obj.deinit(allocator);
                    check_content = try allocator.dupe(u8, idx_obj.data);
                    check_content_owned = true;
                } else {
                    // Working tree: check the file content
                    check_content = platform_impl.fs.readFile(allocator, entry.path) catch continue;
                    check_content_owned = true;
                    // Compare with index to skip unchanged
                    var idx_hash_buf: [40]u8 = undefined;
                    _ = std.fmt.bufPrint(&idx_hash_buf, "{x}", .{&entry.sha1}) catch continue;
                    if (objects.GitObject.load(&idx_hash_buf, git_path, platform_impl, allocator)) |idx_obj| {
                        defer idx_obj.deinit(allocator);
                        if (std.mem.eql(u8, check_content, idx_obj.data)) {
                            allocator.free(check_content);
                            continue;
                        }
                    } else |_| {}
                }
                defer if (check_content_owned) allocator.free(check_content);
                // Check content for whitespace errors
                var lines = std.mem.splitScalar(u8, check_content, '\n');
                var line_num: usize = 0;
                while (lines.next()) |line| {
                    line_num += 1;
                    if (line.len > 0 and (line[line.len - 1] == ' ' or line[line.len - 1] == '\t')) {
                        ws_errors = true;
                        const msg = try std.fmt.allocPrint(allocator, "{s}:{d}: trailing whitespace.\n+{s}\n", .{ entry.path, line_num, line });
                        defer allocator.free(msg);
                        try platform_impl.writeStdout(msg);
                    }
                    // Check for conflict markers
                    if (std.mem.startsWith(u8, line, "<<<<<<<") or
                        std.mem.startsWith(u8, line, "=======") or
                        std.mem.startsWith(u8, line, ">>>>>>>"))
                    {
                        ws_errors = true;
                        const msg = try std.fmt.allocPrint(allocator, "{s}:{d}: leftover conflict marker.\n+{s}\n", .{ entry.path, line_num, line });
                        defer allocator.free(msg);
                        try platform_impl.writeStdout(msg);
                    }
                }
            }
        }
        if (!quiet) {
            // Suppress normal diff output in check mode - it was already suppressed
        }
    }
    
    if (check_mode and exit_code) {
        var code: u8 = 0;
        if (has_diff) code |= 1;
        if (ws_errors) code |= 2;
        if (code != 0) std.process.exit(code);
    } else if (check_mode) {
        if (ws_errors) std.process.exit(2);
    } else if (exit_code and has_diff) {
        std.process.exit(1);
    }
}

fn outputDiffEntries(diff_entries: []const DiffStatEntry, diff_output_mode: anytype, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    if (diff_output_mode == .stat) {
        try formatDiffStat(diff_entries, platform_impl, allocator);
    } else if (diff_output_mode == .shortstat) {
        try formatDiffShortStat(diff_entries, platform_impl, allocator);
    } else if (diff_output_mode == .numstat) {
        try formatDiffNumStat(diff_entries, platform_impl, allocator);
    } else if (diff_output_mode == .name_only) {
        for (diff_entries) |e| {
            const line = try std.fmt.allocPrint(allocator, "{s}\n", .{e.path});
            defer allocator.free(line);
            try platform_impl.writeStdout(line);
        }
    } else if (diff_output_mode == .name_status) {
        for (diff_entries) |e| {
            const status_char: u8 = if (e.is_new) 'A' else if (e.is_deleted) 'D' else 'M';
            const line = try std.fmt.allocPrint(allocator, "{c}\t{s}\n", .{ status_char, e.path });
            defer allocator.free(line);
            try platform_impl.writeStdout(line);
        }
    } else if (diff_output_mode == .raw) {
        for (diff_entries) |e| {
            const status_char: u8 = if (e.is_new) 'A' else if (e.is_deleted) 'D' else 'M';
            const zero_oid = "0000000000000000000000000000000000000000";
            const old_mode_str: []const u8 = if (e.is_new) "000000" else "100644";
            const new_mode_str: []const u8 = if (e.is_deleted) "000000" else "100644";
            const old_hash = if (e.is_new) zero_oid else e.old_hash;
            const new_hash = if (e.is_deleted) zero_oid else e.new_hash;
            const line = try std.fmt.allocPrint(allocator, ":{s} {s} {s} {s} {c}\t{s}\n", .{ old_mode_str, new_mode_str, old_hash, new_hash, status_char, e.path });
            defer allocator.free(line);
            try platform_impl.writeStdout(line);
        }
    } else if (diff_output_mode == .summary) {
        for (diff_entries) |e| {
            if (e.is_new) {
                const line = try std.fmt.allocPrint(allocator, " create mode 100644 {s}\n", .{e.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            } else if (e.is_deleted) {
                const line = try std.fmt.allocPrint(allocator, " delete mode 100644 {s}\n", .{e.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            }
        }
    } else if (diff_output_mode == .dirstat) {
        // Minimal dirstat output
    }
    // no_patch, patch_with_stat, patch_with_raw: no output here
}

fn collectRefDiffEntries(ref_name: []const u8, index: *const index_mod.Index, cwd: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, entries: *std.array_list.Managed(DiffStatEntry), is_cached: bool) !bool {
    // Get the tree for the ref
    const tree_hash = resolveToTree(allocator, ref_name, git_path, platform_impl) catch return false;
    defer allocator.free(tree_hash);

    // Walk the tree to get all entries
    var tree_entries_map = std.StringHashMap(TreeEntryInfo).init(allocator);
    defer {
        var kit = tree_entries_map.keyIterator();
        while (kit.next()) |k| allocator.free(k.*);
        tree_entries_map.deinit();
    }
    try walkTreeForDiffIndex(allocator, git_path, tree_hash, "", &tree_entries_map, platform_impl);

    var has_diff = false;

    if (is_cached) {
        // Compare ref tree to index
        for (index.entries.items) |entry| {
            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);

            if (tree_entries_map.get(entry.path)) |te| {
                var old_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&te.hash}) catch unreachable;
                if (!std.mem.eql(u8, &old_hash_buf, index_hash) or te.mode != entry.mode) {
                    has_diff = true;
                    const old_content = readBlobContent(allocator, git_path, &old_hash_buf, platform_impl) catch "";
                    defer if (old_content.len > 0) allocator.free(old_content);
                    const new_content = getIndexedFileContent(entry, allocator) catch "";
                    defer if (new_content.len > 0) allocator.free(new_content);
                    var ins: usize = 0;
                    var dels: usize = 0;
                    if (te.mode != entry.mode and std.mem.eql(u8, old_content, new_content)) {
                        // mode-only change
                    } else {
                        countInsertionsDeletions(old_content, new_content, &ins, &dels);
                    }
                    try entries.append(.{
                        .path = try allocator.dupe(u8, entry.path),
                        .insertions = ins, .deletions = dels,
                        .is_binary = isBinaryContent(old_content) or isBinaryContent(new_content),
                        .is_new = false, .is_deleted = false,
                        .old_hash = try allocator.dupe(u8, &old_hash_buf),
                        .new_hash = try allocator.dupe(u8, index_hash),
                    });
                }
            } else {
                has_diff = true;
                const new_content = getIndexedFileContent(entry, allocator) catch "";
                defer if (new_content.len > 0) allocator.free(new_content);
                var lines: usize = 0;
                if (new_content.len > 0) {
                    var it = std.mem.splitScalar(u8, new_content, '\n');
                    while (it.next()) |_| lines += 1;
                    if (new_content[new_content.len - 1] == '\n') lines -= 1;
                }
                try entries.append(.{
                    .path = try allocator.dupe(u8, entry.path),
                    .insertions = lines, .deletions = 0,
                    .is_binary = isBinaryContent(new_content),
                    .is_new = true, .is_deleted = false,
                    .old_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                    .new_hash = try allocator.dupe(u8, index_hash),
                });
            }
        }
        // Check for deletions (in tree but not in index)
        var tree_it = tree_entries_map.iterator();
        while (tree_it.next()) |kv| {
            var found = false;
            for (index.entries.items) |entry| {
                if (std.mem.eql(u8, entry.path, kv.key_ptr.*)) { found = true; break; }
            }
            if (!found) {
                has_diff = true;
                var old_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&kv.value_ptr.hash}) catch unreachable;
                const old_content = readBlobContent(allocator, git_path, &old_hash_buf, platform_impl) catch "";
                defer if (old_content.len > 0) allocator.free(old_content);
                var lines: usize = 0;
                if (old_content.len > 0) {
                    var it = std.mem.splitScalar(u8, old_content, '\n');
                    while (it.next()) |_| lines += 1;
                    if (old_content[old_content.len - 1] == '\n') lines -= 1;
                }
                try entries.append(.{
                    .path = try allocator.dupe(u8, kv.key_ptr.*),
                    .insertions = 0, .deletions = lines,
                    .is_binary = isBinaryContent(old_content),
                    .is_new = false, .is_deleted = true,
                    .old_hash = try allocator.dupe(u8, &old_hash_buf),
                    .new_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                });
            }
        }
    } else {
        // Compare ref tree to working tree
        // First collect all working tree files that are tracked
        var seen_paths = std.StringHashMap(void).init(allocator);
        defer seen_paths.deinit();

        for (index.entries.items) |entry| {
            const full_path = if (std.fs.path.isAbsolute(entry.path))
                try allocator.dupe(u8, entry.path)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cwd, entry.path });
            defer allocator.free(full_path);

            const current_content = platform_impl.fs.readFile(allocator, full_path) catch "";
            defer if (current_content.len > 0) allocator.free(current_content);

            const file_exists = current_content.len > 0 or (platform_impl.fs.exists(full_path) catch false);
            
            try seen_paths.put(try allocator.dupe(u8, entry.path), {});

            if (tree_entries_map.get(entry.path)) |te| {
                var old_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&te.hash}) catch unreachable;
                const old_content = readBlobContent(allocator, git_path, &old_hash_buf, platform_impl) catch "";
                defer if (old_content.len > 0) allocator.free(old_content);

                if (file_exists) {
                    if (!std.mem.eql(u8, old_content, current_content)) {
                        has_diff = true;
                        var ins: usize = 0;
                        var dels: usize = 0;
                        countInsertionsDeletions(old_content, current_content, &ins, &dels);
                        const blob = objects.createBlobObject(current_content, allocator) catch continue;
                        defer blob.deinit(allocator);
                        const new_hash = blob.hash(allocator) catch continue;
                        defer allocator.free(new_hash);
                        try entries.append(.{
                            .path = try allocator.dupe(u8, entry.path),
                            .insertions = ins, .deletions = dels,
                            .is_binary = isBinaryContent(old_content) or isBinaryContent(current_content),
                            .is_new = false, .is_deleted = false,
                            .old_hash = try allocator.dupe(u8, &old_hash_buf),
                            .new_hash = try allocator.dupe(u8, new_hash),
                        });
                    }
                } else {
                    // File deleted
                    has_diff = true;
                    var lines: usize = 0;
                    if (old_content.len > 0) {
                        var it = std.mem.splitScalar(u8, old_content, '\n');
                        while (it.next()) |_| lines += 1;
                        if (old_content[old_content.len - 1] == '\n') lines -= 1;
                    }
                    try entries.append(.{
                        .path = try allocator.dupe(u8, entry.path),
                        .insertions = 0, .deletions = lines,
                        .is_binary = isBinaryContent(old_content),
                        .is_new = false, .is_deleted = true,
                        .old_hash = try allocator.dupe(u8, &old_hash_buf),
                        .new_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                    });
                }
            } else if (file_exists) {
                // New file
                has_diff = true;
                var lines: usize = 0;
                if (current_content.len > 0) {
                    var it = std.mem.splitScalar(u8, current_content, '\n');
                    while (it.next()) |_| lines += 1;
                    if (current_content[current_content.len - 1] == '\n') lines -= 1;
                }
                const blob = objects.createBlobObject(current_content, allocator) catch continue;
                defer blob.deinit(allocator);
                const new_hash = blob.hash(allocator) catch continue;
                defer allocator.free(new_hash);
                try entries.append(.{
                    .path = try allocator.dupe(u8, entry.path),
                    .insertions = lines, .deletions = 0,
                    .is_binary = isBinaryContent(current_content),
                    .is_new = true, .is_deleted = false,
                    .old_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                    .new_hash = try allocator.dupe(u8, new_hash),
                });
            }
        }

        // Check for entries in tree but not in index (deleted before staging)
        var tree_it = tree_entries_map.iterator();
        while (tree_it.next()) |kv| {
            if (!seen_paths.contains(kv.key_ptr.*)) {
                has_diff = true;
                var old_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&kv.value_ptr.hash}) catch unreachable;
                const old_content = readBlobContent(allocator, git_path, &old_hash_buf, platform_impl) catch "";
                defer if (old_content.len > 0) allocator.free(old_content);
                var lines: usize = 0;
                if (old_content.len > 0) {
                    var it = std.mem.splitScalar(u8, old_content, '\n');
                    while (it.next()) |_| lines += 1;
                    if (old_content[old_content.len - 1] == '\n') lines -= 1;
                }
                try entries.append(.{
                    .path = try allocator.dupe(u8, kv.key_ptr.*),
                    .insertions = 0, .deletions = lines,
                    .is_binary = isBinaryContent(old_content),
                    .is_new = false, .is_deleted = true,
                    .old_hash = try allocator.dupe(u8, &old_hash_buf),
                    .new_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                });
            }
        }
    }
    return has_diff;
}

fn showRefToWorkingTreeDiff(ref_name: []const u8, index: *const index_mod.Index, cwd: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, quiet: bool, is_cached: bool) !bool {
    // For now, collect entries and show patch-style output
    var diff_entries = std.array_list.Managed(DiffStatEntry).init(allocator);
    defer {
        for (diff_entries.items) |e| allocator.free(e.path);
        diff_entries.deinit();
    }
    const has_diff = try collectRefDiffEntries(ref_name, index, cwd, git_path, platform_impl, allocator, &diff_entries, is_cached);
    if (quiet) return has_diff;

    // Generate patch output for each entry
    const tree_hash = resolveToTree(allocator, ref_name, git_path, platform_impl) catch return false;
    defer allocator.free(tree_hash);
    var tree_entries_map = std.StringHashMap(TreeEntryInfo).init(allocator);
    defer {
        var kit = tree_entries_map.keyIterator();
        while (kit.next()) |k| allocator.free(k.*);
        tree_entries_map.deinit();
    }
    try walkTreeForDiffIndex(allocator, git_path, tree_hash, "", &tree_entries_map, platform_impl);

    for (diff_entries.items) |de| {
        // Get old content from tree
        const old_content = if (de.is_new) try allocator.dupe(u8, "") else blk: {
            if (tree_entries_map.get(de.path)) |te| {
                var hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&hash_buf, "{x}", .{&te.hash}) catch unreachable;
                break :blk readBlobContent(allocator, git_path, &hash_buf, platform_impl) catch try allocator.dupe(u8, "");
            } else break :blk try allocator.dupe(u8, "");
        };
        defer allocator.free(old_content);

        // Get new content
        const new_content = if (de.is_deleted) try allocator.dupe(u8, "") else if (is_cached) blk: {
            // Find in index
            for (index.entries.items) |entry| {
                if (std.mem.eql(u8, entry.path, de.path)) {
                    break :blk getIndexedFileContent(entry, allocator) catch try allocator.dupe(u8, "");
                }
            }
            break :blk try allocator.dupe(u8, "");
        } else blk: {
            const full_path = if (std.fs.path.isAbsolute(de.path))
                try allocator.dupe(u8, de.path)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cwd, de.path });
            defer allocator.free(full_path);
            break :blk platform_impl.fs.readFile(allocator, full_path) catch try allocator.dupe(u8, "");
        };
        defer allocator.free(new_content);

        const short_old = de.old_hash[0..@min(7, de.old_hash.len)];
        const short_new = de.new_hash[0..@min(7, de.new_hash.len)];
        const diff_output = diff_mod.generateUnifiedDiffWithHashes(old_content, new_content, de.path, short_old, short_new, allocator) catch continue;
        defer allocator.free(diff_output);
        try platform_impl.writeStdout(diff_output);
    }

    return has_diff;
}

const DiffStatEntry = struct {
    path: []const u8,
    insertions: usize,
    deletions: usize,
    is_binary: bool,
    is_new: bool,
    is_deleted: bool,
    old_hash: []const u8,
    new_hash: []const u8,
    old_mode: []const u8 = "",
    new_mode: []const u8 = "",
};

fn collectWorkingTreeDiffEntries(index: *const index_mod.Index, cwd: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, entries: *std.array_list.Managed(DiffStatEntry)) !bool {
    _ = git_path;
    var has_diff = false;
    for (index.entries.items) |entry| {
        const full_path = if (std.fs.path.isAbsolute(entry.path))
            try allocator.dupe(u8, entry.path)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cwd, entry.path });
        defer allocator.free(full_path);

        if (platform_impl.fs.exists(full_path) catch false) {
            const current_content = platform_impl.fs.readFile(allocator, full_path) catch continue;
            defer allocator.free(current_content);

            const blob = try objects.createBlobObject(current_content, allocator);
            defer blob.deinit(allocator);
            const current_hash = try blob.hash(allocator);
            defer allocator.free(current_hash);

            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);

            if (!std.mem.eql(u8, current_hash, index_hash)) {
                has_diff = true;
                const indexed_content = getIndexedFileContent(entry, allocator) catch "";
                defer if (indexed_content.len > 0) allocator.free(indexed_content);

                var ins: usize = 0;
                var dels: usize = 0;
                countInsertionsDeletions(indexed_content, current_content, &ins, &dels);

                try entries.append(.{
                    .path = try allocator.dupe(u8, entry.path),
                    .insertions = ins,
                    .deletions = dels,
                    .is_binary = isBinaryContent(current_content) or isBinaryContent(indexed_content),
                    .is_new = false,
                    .is_deleted = false,
                    .old_hash = try allocator.dupe(u8, index_hash),
                    .new_hash = try allocator.dupe(u8, current_hash),
                });
            }
        } else {
            has_diff = true;
            const indexed_content = getIndexedFileContent(entry, allocator) catch "";
            defer if (indexed_content.len > 0) allocator.free(indexed_content);

            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);

            var lines: usize = 0;
            if (indexed_content.len > 0) {
                var it = std.mem.splitScalar(u8, indexed_content, '\n');
                while (it.next()) |_| lines += 1;
                if (indexed_content[indexed_content.len - 1] == '\n') lines -= 1;
            }

            try entries.append(.{
                .path = try allocator.dupe(u8, entry.path),
                .insertions = 0,
                .deletions = lines,
                .is_binary = isBinaryContent(indexed_content),
                .is_new = false,
                .is_deleted = true,
                .old_hash = try allocator.dupe(u8, index_hash),
                .new_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
            });
        }
    }
    return has_diff;
}

fn collectStagedDiffEntries(index: *const index_mod.Index, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, entries: *std.array_list.Managed(DiffStatEntry)) !bool {
    var has_diff = false;

    // Get HEAD tree
    const head_commit = refs.getCurrentCommit(git_path, platform_impl, allocator) catch return false;
    if (head_commit == null) {
        // No HEAD - all index entries are new
        for (index.entries.items) |entry| {
            has_diff = true;
            const content = getIndexedFileContent(entry, allocator) catch "";
            defer if (content.len > 0) allocator.free(content);
            var lines: usize = 0;
            if (content.len > 0) {
                var it = std.mem.splitScalar(u8, content, '\n');
                while (it.next()) |_| lines += 1;
                if (content[content.len - 1] == '\n') lines -= 1;
            }
            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);
            try entries.append(.{
                .path = try allocator.dupe(u8, entry.path),
                .insertions = lines,
                .deletions = 0,
                .is_binary = isBinaryContent(content),
                .is_new = true,
                .is_deleted = false,
                .old_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                .new_hash = try allocator.dupe(u8, index_hash),
            });
        }
        return has_diff;
    }
    defer allocator.free(head_commit.?);

    const tree_hash = resolveToTree(allocator, head_commit.?, git_path, platform_impl) catch return false;
    defer allocator.free(tree_hash);

    var tree_entries_map = std.StringHashMap(TreeEntryInfo).init(allocator);
    defer {
        var kit = tree_entries_map.keyIterator();
        while (kit.next()) |k| allocator.free(k.*);
        tree_entries_map.deinit();
    }
    try walkTreeForDiffIndex(allocator, git_path, tree_hash, "", &tree_entries_map, platform_impl);

    for (index.entries.items) |entry| {
        const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
        defer allocator.free(index_hash);

        if (tree_entries_map.get(entry.path)) |te| {
            var old_hash_buf: [40]u8 = undefined;
            _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&te.hash}) catch unreachable;
            if (!std.mem.eql(u8, &old_hash_buf, index_hash) or te.mode != entry.mode) {
                has_diff = true;
                const old_content = readBlobContent(allocator, git_path, &old_hash_buf, platform_impl) catch "";
                defer if (old_content.len > 0) allocator.free(old_content);
                const new_content = getIndexedFileContent(entry, allocator) catch "";
                defer if (new_content.len > 0) allocator.free(new_content);

                var ins: usize = 0;
                var dels: usize = 0;
                if (te.mode != entry.mode and std.mem.eql(u8, old_content, new_content)) {
                    // Mode-only change
                } else {
                    countInsertionsDeletions(old_content, new_content, &ins, &dels);
                }

                try entries.append(.{
                    .path = try allocator.dupe(u8, entry.path),
                    .insertions = ins,
                    .deletions = dels,
                    .is_binary = isBinaryContent(old_content) or isBinaryContent(new_content),
                    .is_new = false,
                    .is_deleted = false,
                    .old_hash = try allocator.dupe(u8, &old_hash_buf),
                    .new_hash = try allocator.dupe(u8, index_hash),
                });
            }
        } else {
            has_diff = true;
            const new_content = getIndexedFileContent(entry, allocator) catch "";
            defer if (new_content.len > 0) allocator.free(new_content);
            var lines: usize = 0;
            if (new_content.len > 0) {
                var it = std.mem.splitScalar(u8, new_content, '\n');
                while (it.next()) |_| lines += 1;
                if (new_content[new_content.len - 1] == '\n') lines -= 1;
            }
            try entries.append(.{
                .path = try allocator.dupe(u8, entry.path),
                .insertions = lines,
                .deletions = 0,
                .is_binary = isBinaryContent(new_content),
                .is_new = true,
                .is_deleted = false,
                .old_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                .new_hash = try allocator.dupe(u8, index_hash),
            });
        }
    }

    // Check for deletions
    var tree_it = tree_entries_map.iterator();
    while (tree_it.next()) |kv| {
        var found = false;
        for (index.entries.items) |entry| {
            if (std.mem.eql(u8, entry.path, kv.key_ptr.*)) {
                found = true;
                break;
            }
        }
        if (!found) {
            has_diff = true;
            var old_hash_buf: [40]u8 = undefined;
            _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&kv.value_ptr.hash}) catch unreachable;
            const old_content = readBlobContent(allocator, git_path, &old_hash_buf, platform_impl) catch "";
            defer if (old_content.len > 0) allocator.free(old_content);
            var lines: usize = 0;
            if (old_content.len > 0) {
                var it = std.mem.splitScalar(u8, old_content, '\n');
                while (it.next()) |_| lines += 1;
                if (old_content[old_content.len - 1] == '\n') lines -= 1;
            }
            try entries.append(.{
                .path = try allocator.dupe(u8, kv.key_ptr.*),
                .insertions = 0,
                .deletions = lines,
                .is_binary = isBinaryContent(old_content),
                .is_new = false,
                .is_deleted = true,
                .old_hash = try allocator.dupe(u8, &old_hash_buf),
                .new_hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
            });
        }
    }

    return has_diff;
}

fn countInsertionsDeletions(old_content: []const u8, new_content: []const u8, insertions: *usize, deletions: *usize) void {
    // Count lines in old and new
    var old_lines = std.array_list.Managed([]const u8).init(std.heap.page_allocator);
    defer old_lines.deinit();
    var new_lines = std.array_list.Managed([]const u8).init(std.heap.page_allocator);
    defer new_lines.deinit();

    var old_it = std.mem.splitScalar(u8, old_content, '\n');
    while (old_it.next()) |line| old_lines.append(line) catch {};
    var new_it = std.mem.splitScalar(u8, new_content, '\n');
    while (new_it.next()) |line| new_lines.append(line) catch {};

    // Remove trailing empty string from split
    if (old_lines.items.len > 0 and old_lines.items[old_lines.items.len - 1].len == 0 and old_content.len > 0 and old_content[old_content.len - 1] == '\n') {
        _ = old_lines.pop();
    }
    if (new_lines.items.len > 0 and new_lines.items[new_lines.items.len - 1].len == 0 and new_content.len > 0 and new_content[new_content.len - 1] == '\n') {
        _ = new_lines.pop();
    }

    // Simple LCS-based diff count
    const old_len = old_lines.items.len;
    const new_len = new_lines.items.len;

    if (old_len == 0) {
        insertions.* = new_len;
        deletions.* = 0;
        return;
    }
    if (new_len == 0) {
        insertions.* = 0;
        deletions.* = old_len;
        return;
    }

    // Use a simple approach: count matching lines using LCS length
    // LCS via O(min(m,n)) space DP
    const lcs_len = computeLCSLength(old_lines.items, new_lines.items);
    deletions.* = old_len - lcs_len;
    insertions.* = new_len - lcs_len;
}

fn computeLCSLength(a: []const []const u8, b: []const []const u8) usize {
    if (a.len == 0 or b.len == 0) return 0;

    // Use the shorter sequence for the DP row
    const short = if (a.len <= b.len) a else b;
    const long = if (a.len <= b.len) b else a;

    const row = std.heap.page_allocator.alloc(usize, short.len + 1) catch return 0;
    defer std.heap.page_allocator.free(row);
    @memset(row, 0);

    for (long) |long_line| {
        var prev: usize = 0;
        for (short, 0..) |short_line, j| {
            const temp = row[j + 1];
            if (std.mem.eql(u8, long_line, short_line)) {
                row[j + 1] = prev + 1;
            } else {
                row[j + 1] = @max(row[j + 1], row[j]);
            }
            prev = temp;
        }
    }
    return row[short.len];
}

fn isBinaryContent(content: []const u8) bool {
    const check_len = @min(content.len, 8000);
    for (content[0..check_len]) |c| {
        if (c == 0) return true;
    }
    return false;
}

// pathspecMatch is defined elsewhere in the file

fn readBlobContent(allocator: std.mem.Allocator, git_path: []const u8, hash_hex: []const u8, platform_impl: *const platform_mod.Platform) ![]const u8 {
    _ = platform_impl;
    return readGitObjectContent(git_path, hash_hex, allocator) catch return error.FileNotFound;
}

fn formatDiffStat(diff_entries: []const DiffStatEntry, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    if (diff_entries.len == 0) return;

    // Find max path length and max change count for formatting
    var max_path_len: usize = 0;
    var max_changes: usize = 0;
    for (diff_entries) |e| {
        if (e.path.len > max_path_len) max_path_len = e.path.len;
        const total = e.insertions + e.deletions;
        if (total > max_changes) max_changes = total;
    }

    // Cap the bar width
    const terminal_width: usize = 80;
    // " path | N ++++----\n"
    const num_width = countDigitsUsize(max_changes);
    const overhead = 3 + num_width + 1; // " | " + num + " "
    var bar_max: usize = if (terminal_width > max_path_len + overhead + 2) terminal_width - max_path_len - overhead else 10;
    if (bar_max < 1) bar_max = 1;

    var total_ins: usize = 0;
    var total_dels: usize = 0;
    var files_changed: usize = 0;

    for (diff_entries) |e| {
        files_changed += 1;
        total_ins += e.insertions;
        total_dels += e.deletions;

        if (e.is_binary) {
            const line = try std.fmt.allocPrint(allocator, " {s} | Bin\n", .{e.path});
            defer allocator.free(line);
            try platform_impl.writeStdout(line);
        } else {
            const total = e.insertions + e.deletions;
            if (total == 0) {
                // Mode-only change
                const line = try std.fmt.allocPrint(allocator, " {s} | 0\n", .{e.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            } else {
                // Scale the bar
                var plus_count = e.insertions;
                var minus_count = e.deletions;
                if (total > bar_max) {
                    plus_count = (e.insertions * bar_max + total - 1) / total;
                    minus_count = bar_max - plus_count;
                    if (e.deletions > 0 and minus_count == 0) {
                        minus_count = 1;
                        if (plus_count > 1) plus_count -= 1;
                    }
                    if (e.insertions > 0 and plus_count == 0) {
                        plus_count = 1;
                        if (minus_count > 1) minus_count -= 1;
                    }
                }

                var bar_buf: [256]u8 = undefined;
                var bar_idx: usize = 0;
                var i: usize = 0;
                while (i < plus_count and bar_idx < bar_buf.len) : (i += 1) {
                    bar_buf[bar_idx] = '+';
                    bar_idx += 1;
                }
                i = 0;
                while (i < minus_count and bar_idx < bar_buf.len) : (i += 1) {
                    bar_buf[bar_idx] = '-';
                    bar_idx += 1;
                }

                // Pad path
                const padding = if (max_path_len > e.path.len) max_path_len - e.path.len else 0;
                var pad_buf: [256]u8 = undefined;
                const pad_len = @min(padding, pad_buf.len);
                @memset(pad_buf[0..pad_len], ' ');

                const line = try std.fmt.allocPrint(allocator, " {s}{s} | {d} {s}\n", .{ e.path, pad_buf[0..pad_len], total, bar_buf[0..bar_idx] });
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            }
        }
    }

    // Summary line
    try formatDiffStatSummary(files_changed, total_ins, total_dels, platform_impl, allocator);
}

fn formatDiffShortStat(diff_entries: []const DiffStatEntry, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    if (diff_entries.len == 0) return;

    var total_ins: usize = 0;
    var total_dels: usize = 0;
    for (diff_entries) |e| {
        total_ins += e.insertions;
        total_dels += e.deletions;
    }
    try formatDiffStatSummary(diff_entries.len, total_ins, total_dels, platform_impl, allocator);
}

fn formatDiffNumStat(diff_entries: []const DiffStatEntry, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    for (diff_entries) |e| {
        if (e.is_binary) {
            const line = try std.fmt.allocPrint(allocator, "-\t-\t{s}\n", .{e.path});
            defer allocator.free(line);
            try platform_impl.writeStdout(line);
        } else {
            const line = try std.fmt.allocPrint(allocator, "{d}\t{d}\t{s}\n", .{ e.insertions, e.deletions, e.path });
            defer allocator.free(line);
            try platform_impl.writeStdout(line);
        }
    }
}

fn formatDiffStatSummary(files_changed: usize, total_ins: usize, total_dels: usize, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    var parts = std.array_list.Managed(u8).init(allocator);
    defer parts.deinit();

    const w = parts.writer();
    try w.writeAll(" ");
    try w.print("{d} file{s} changed", .{ files_changed, if (files_changed != 1) "s" else "" });
    if (total_ins > 0 or (total_ins == 0 and total_dels == 0)) {
        try w.print(", {d} insertion{s}(+)", .{ total_ins, if (total_ins != 1) "s" else "" });
    }
    if (total_dels > 0 or (total_ins == 0 and total_dels == 0)) {
        try w.print(", {d} deletion{s}(-)", .{ total_dels, if (total_dels != 1) "s" else "" });
    }
    try w.writeAll("\n");
    try platform_impl.writeStdout(parts.items);
}

fn countDigitsUsize(n: usize) usize {
    if (n == 0) return 1;
    var count: usize = 0;
    var v = n;
    while (v > 0) : (v /= 10) count += 1;
    return count;
}

fn cmdDiffNoIndex(allocator: std.mem.Allocator, diff_args: []const []const u8, platform_impl: *const platform_mod.Platform) !void {
    var exit_code = false;
    var quiet = false;
    var paths = std.array_list.Managed([]const u8).init(allocator);
    defer paths.deinit();
    var seen_dashdash = false;

    for (diff_args) |arg| {
        if (seen_dashdash) {
            try paths.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_dashdash = true;
        } else if (std.mem.eql(u8, arg, "--no-index")) {
            // already handled
        } else if (std.mem.eql(u8, arg, "--exit-code")) {
            exit_code = true;
        } else if (std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
            exit_code = true;
        } else if (std.mem.startsWith(u8, arg, "-")) {
            // ignore other flags for now
        } else {
            try paths.append(arg);
        }
    }

    if (paths.items.len < 2) {
        try platform_impl.writeStderr("usage: git diff --no-index <path> <path>\n");
        std.process.exit(129);
    }

    const path_a = paths.items[0];
    const path_b = paths.items[1];

    // Check if paths are directories
    const a_is_dir = if (std.fs.cwd().openDir(path_a, .{})) |d| blk: { var dd = d; dd.close(); break :blk true; } else |_| false;
    const b_is_dir = if (std.fs.cwd().openDir(path_b, .{})) |d| blk: { var dd = d; dd.close(); break :blk true; } else |_| false;

    var has_diff = false;
    if (a_is_dir and b_is_dir) {
        // Compare directories
        has_diff = try diffNoIndexDirs(allocator, path_a, path_b, quiet, platform_impl);
    } else {
        // Compare files
        has_diff = try diffNoIndexFiles(allocator, path_a, path_b, quiet, platform_impl);
    }

    if (exit_code and has_diff) {
        std.process.exit(1);
    }
    if (has_diff and !exit_code) {
        std.process.exit(1);
    }
}

fn diffNoIndexFiles(allocator: std.mem.Allocator, path_a: []const u8, path_b: []const u8, quiet: bool, platform_impl: *const platform_mod.Platform) !bool {
    const content_a = platform_impl.fs.readFile(allocator, path_a) catch "";
    defer if (content_a.len > 0) allocator.free(content_a);
    const content_b = platform_impl.fs.readFile(allocator, path_b) catch "";
    defer if (content_b.len > 0) allocator.free(content_b);

    if (std.mem.eql(u8, content_a, content_b)) return false;
    if (quiet) return true;

    // Generate unified diff
    const diff_output = diff_mod.generateUnifiedDiff(content_a, content_b, path_b, allocator) catch return true;
    defer allocator.free(diff_output);

    // Build proper header
    var out = std.array_list.Managed(u8).init(allocator);
    defer out.deinit();
    try out.appendSlice("diff --git a/");
    try out.appendSlice(path_a);
    try out.appendSlice(" b/");
    try out.appendSlice(path_b);
    try out.appendSlice("\n--- a/");
    try out.appendSlice(path_a);
    try out.appendSlice("\n+++ b/");
    try out.appendSlice(path_b);
    try out.appendSlice("\n");

    // Extract hunks from diff output
    if (std.mem.indexOf(u8, diff_output, "\n@@")) |hs| {
        try out.appendSlice(diff_output[hs + 1 ..]);
    } else if (std.mem.startsWith(u8, diff_output, "@@")) {
        try out.appendSlice(diff_output);
    }

    try platform_impl.writeStdout(out.items);
    return true;
}

fn diffNoIndexDirs(allocator: std.mem.Allocator, dir_a: []const u8, dir_b: []const u8, quiet: bool, platform_impl: *const platform_mod.Platform) !bool {
    // List files in both directories
    var files_a = std.StringHashMap(void).init(allocator);
    defer {
        var kit = files_a.keyIterator();
        while (kit.next()) |k| allocator.free(k.*);
        files_a.deinit();
    }
    var files_b = std.StringHashMap(void).init(allocator);
    defer {
        var kit = files_b.keyIterator();
        while (kit.next()) |k| allocator.free(k.*);
        files_b.deinit();
    }

    if (std.fs.cwd().openDir(dir_a, .{ .iterate = true })) |d| {
        var dir = d;
        defer dir.close();
        var iter = dir.iterate();
        while (try iter.next()) |entry| {
            if (entry.kind == .file) {
                try files_a.put(try allocator.dupe(u8, entry.name), {});
            }
        }
    } else |_| {}

    if (std.fs.cwd().openDir(dir_b, .{ .iterate = true })) |d| {
        var dir = d;
        defer dir.close();
        var iter = dir.iterate();
        while (try iter.next()) |entry| {
            if (entry.kind == .file) {
                try files_b.put(try allocator.dupe(u8, entry.name), {});
            }
        }
    } else |_| {}

    var has_diff = false;

    // Check files in A
    var it_a = files_a.keyIterator();
    while (it_a.next()) |key| {
        const name = key.*;
        const full_a = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir_a, name });
        defer allocator.free(full_a);
        const full_b = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir_b, name });
        defer allocator.free(full_b);
        if (files_b.contains(name)) {
            // Both have the file, diff them
            if (try diffNoIndexFiles(allocator, full_a, full_b, quiet, platform_impl)) {
                has_diff = true;
            }
        } else {
            // Only in A - deleted from B perspective
            has_diff = true;
            if (!quiet) {
                const content_a = platform_impl.fs.readFile(allocator, full_a) catch "";
                defer if (content_a.len > 0) allocator.free(content_a);
                if (try diffNoIndexFiles(allocator, full_a, "/dev/null", quiet, platform_impl)) {}
            }
        }
    }

    // Check files only in B
    var it_b = files_b.keyIterator();
    while (it_b.next()) |key| {
        const name = key.*;
        if (!files_a.contains(name)) {
            has_diff = true;
            if (!quiet) {
                const full_b = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir_b, name });
                defer allocator.free(full_b);
                if (try diffNoIndexFiles(allocator, "/dev/null", full_b, quiet, platform_impl)) {}
            }
        }
    }

    return has_diff;
}

fn showWorkingTreeDiff(index: *const index_mod.Index, cwd: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, quiet: bool) !bool {
    var has_diff = false;
    for (index.entries.items) |entry| {
        const full_path = if (std.fs.path.isAbsolute(entry.path))
            try allocator.dupe(u8, entry.path)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ cwd, entry.path });
        defer allocator.free(full_path);
        
        // Check if file exists and has changed
        if (platform_impl.fs.exists(full_path) catch false) {
            const current_content = platform_impl.fs.readFile(allocator, full_path) catch continue;
            defer allocator.free(current_content);
            
            // Create blob object to get hash
            const blob = try objects.createBlobObject(current_content, allocator);
            defer blob.deinit(allocator);
            
            const current_hash = try blob.hash(allocator);
            defer allocator.free(current_hash);
            
            // Compare with index hash
            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);
            
            if (!std.mem.eql(u8, current_hash, index_hash)) {
                has_diff = true;
                if (quiet) continue;
                // Get indexed content for diff
                const indexed_content = getIndexedFileContent(entry, allocator) catch "";
                defer if (indexed_content.len > 0) allocator.free(indexed_content);
                
                // Generate unified diff
                const short_index_hash = index_hash[0..7];
                const short_current_hash = current_hash[0..7];
                const diff_output = diff_mod.generateUnifiedDiffWithHashes(indexed_content, current_content, entry.path, short_index_hash, short_current_hash, allocator) catch |err| switch (err) {
                    error.OutOfMemory => return err,
                };
                defer allocator.free(diff_output);
                
                try platform_impl.writeStdout(diff_output);
            }
        } else {
            // File was deleted
            has_diff = true;
            if (quiet) continue;
            const indexed_content = getIndexedFileContent(entry, allocator) catch continue;
            defer allocator.free(indexed_content);
            
            // Calculate hash for empty content
            const empty_blob = try objects.createBlobObject("", allocator);
            defer empty_blob.deinit(allocator);
            const empty_hash = try empty_blob.hash(allocator);
            defer allocator.free(empty_hash);
            
            // Get index hash
            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);
            
            const short_index_hash = index_hash[0..7];
            const short_empty_hash = empty_hash[0..7];
            const diff_output = diff_mod.generateUnifiedDiffWithHashes(indexed_content, "", entry.path, short_index_hash, short_empty_hash, allocator) catch |err| switch (err) {
                error.OutOfMemory => return err,
            };
            defer allocator.free(diff_output);
            
            try platform_impl.writeStdout(diff_output);
        }
    }
    return has_diff;
}

fn showStagedDiff(index: *const index_mod.Index, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, quiet: bool) !bool {
    // For --cached diff, we need to compare index against HEAD
    var has_diff = false;
    const current_commit = refs.getCurrentCommit(git_path, platform_impl, allocator) catch null;
    defer if (current_commit) |hash| allocator.free(hash);
    
    if (current_commit == null) {
        // No HEAD commit yet, so all staged files are new
        for (index.entries.items) |entry| {
            has_diff = true;
            if (quiet) continue;
            const content = getIndexedFileContent(entry, allocator) catch continue;
            defer allocator.free(content);
            
            const empty_blob = try objects.createBlobObject("", allocator);
            defer empty_blob.deinit(allocator);
            const empty_hash = try empty_blob.hash(allocator);
            defer allocator.free(empty_hash);
            
            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);
            
            const short_empty_hash = empty_hash[0..7];
            const short_index_hash = index_hash[0..7];
            const diff_output = diff_mod.generateUnifiedDiffWithHashes("", content, entry.path, short_empty_hash, short_index_hash, allocator) catch |err| switch (err) {
                error.OutOfMemory => return err,
            };
            defer allocator.free(diff_output);
            
            try platform_impl.writeStdout(diff_output);
        }
    } else {
        for (index.entries.items) |entry| {
            const index_hash = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
            defer allocator.free(index_hash);
            
            // Check if this file exists in HEAD tree with same hash
            const head_hash = getTreeEntryHashFromCommit(git_path, current_commit.?, entry.path, allocator) catch null;
            defer if (head_hash) |hh| allocator.free(hh);
            
            const is_same = if (head_hash) |hh| std.mem.eql(u8, index_hash, hh) else false;
            
            if (!is_same) {
                has_diff = true;
                if (quiet) continue;
                const content = getIndexedFileContent(entry, allocator) catch continue;
                defer allocator.free(content);
                
                const empty_blob = try objects.createBlobObject("", allocator);
                defer empty_blob.deinit(allocator);
                const empty_hash = try empty_blob.hash(allocator);
                defer allocator.free(empty_hash);
                
                const short_empty_hash = empty_hash[0..7];
                const short_index_hash = index_hash[0..7];
                const diff_output = diff_mod.generateUnifiedDiffWithHashes("", content, entry.path, short_empty_hash, short_index_hash, allocator) catch |err| switch (err) {
                    error.OutOfMemory => return err,
                };
                defer allocator.free(diff_output);
                
                try platform_impl.writeStdout(diff_output);
            }
        }
    }
    return has_diff;
}

pub fn readGitObjectContent(git_path: []const u8, hex_hash: []const u8, allocator: std.mem.Allocator) ![]u8 {
    const objects_dir = try std.fmt.allocPrint(allocator, "{s}/objects", .{git_path});
    defer allocator.free(objects_dir);
    var hash_bytes: [20]u8 = undefined;
    _ = std.fmt.hexToBytes(&hash_bytes, hex_hash) catch return error.InvalidHash;
    const raw = objects.readObject(allocator, objects_dir, &hash_bytes) catch return error.ObjectNotFound;
    defer allocator.free(raw);
    // Skip the header "type size\0"
    if (std.mem.indexOf(u8, raw, "\x00")) |null_pos| {
        return try allocator.dupe(u8, raw[null_pos + 1 ..]);
    }
    return try allocator.dupe(u8, raw);
}

pub fn getTreeEntryHashFromCommit(git_path: []const u8, commit_hash: []const u8, file_path: []const u8, allocator: std.mem.Allocator) ![]u8 {
    // Read the commit to get the tree hash
    const commit_content = readGitObjectContent(git_path, commit_hash, allocator) catch return error.ObjectNotFound;
    defer allocator.free(commit_content);
    
    // Parse "tree <hash>\n" from commit
    if (!std.mem.startsWith(u8, commit_content, "tree ")) return error.InvalidCommit;
    const newline = std.mem.indexOf(u8, commit_content, "\n") orelse return error.InvalidCommit;
    const tree_hash = commit_content[5..newline];
    
    // Now walk the tree to find the entry
    return getTreeEntryHashByPath(git_path, tree_hash, file_path, allocator);
}

fn getTreeEntryHashByPath(git_path: []const u8, tree_hash: []const u8, file_path: []const u8, allocator: std.mem.Allocator) ![]u8 {
    // Read the tree object
    const tree_content = readGitObjectContent(git_path, tree_hash, allocator) catch return error.ObjectNotFound;
    defer allocator.free(tree_content);
    
    // Split file_path into first component and rest
    const sep = std.mem.indexOf(u8, file_path, "/");
    const first_component = if (sep) |s| file_path[0..s] else file_path;
    const rest = if (sep) |s| file_path[s + 1 ..] else null;
    
    // Parse binary tree format: "mode name\0<20-byte-hash>"
    var pos: usize = 0;
    while (pos < tree_content.len) {
        // Find space (between mode and name)
        const space = std.mem.indexOf(u8, tree_content[pos..], " ") orelse break;
        pos += space + 1;
        
        // Find null byte (end of name)
        const null_pos = std.mem.indexOf(u8, tree_content[pos..], "\x00") orelse break;
        const name = tree_content[pos .. pos + null_pos];
        pos += null_pos + 1;
        
        // Read 20-byte hash
        if (pos + 20 > tree_content.len) break;
        const entry_hash_bytes = tree_content[pos .. pos + 20];
        pos += 20;
        
        if (std.mem.eql(u8, name, first_component)) {
            // Convert hash bytes to hex
            var hex_buf: [40]u8 = undefined;
            _ = std.fmt.bufPrint(&hex_buf, "{x}", .{entry_hash_bytes[0..20]}) catch return error.InvalidHash;
            
            if (rest) |remaining_path| {
                // Need to recurse into subtree
                return getTreeEntryHashByPath(git_path, &hex_buf, remaining_path, allocator);
            } else {
                return try allocator.dupe(u8, &hex_buf);
            }
        }
    }
    
    return error.EntryNotFound;
}

fn getIndexedFileContent(entry: index_mod.IndexEntry, allocator: std.mem.Allocator) ![]u8 {
    if (@import("builtin").target.os.tag == .freestanding) {
        return try allocator.dupe(u8, "");
    }
    
    // Find the git directory
    const platform_impl = platform_mod.getCurrentPlatform();
    const git_dir = findGitDirectory(allocator, &platform_impl) catch |err| {
        // Return empty string for graceful degradation in diff/status
        std.log.debug("Could not find git directory: {}", .{err});
        return try allocator.dupe(u8, "");
    };
    defer allocator.free(git_dir);
    
    // Convert hash bytes to hex string
    const hash_str = try allocator.alloc(u8, 40);
    defer allocator.free(hash_str);
    _ = std.fmt.bufPrint(hash_str, "{x}", .{&entry.sha1}) catch |err| {
        std.log.debug("Could not format hash: {}", .{err});
        return try allocator.dupe(u8, "");
    };
    
    // Load the blob object from the git object store
    const git_object = objects.GitObject.load(hash_str, git_dir, &platform_impl, allocator) catch |err| {
        std.log.debug("Could not load blob object {s}: {}", .{ hash_str, err });
        return try allocator.dupe(u8, "");
    };
    defer git_object.deinit(allocator);
    
    // Verify this is actually a blob object
    if (git_object.type != .blob) {
        std.log.warn("Expected blob but got {} for hash {s}", .{ git_object.type, hash_str });
        return try allocator.dupe(u8, "");
    }
    
    // Return a copy of the blob data
    return try allocator.dupe(u8, git_object.data);
}

fn cmdCheckout(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("checkout: not supported in freestanding mode\n");
        return;
    }

    const first_arg = args.next() orelse {
        try platform_impl.writeStderr("error: pathspec '' did not match any file(s) known to git\n");
        std.process.exit(128);
    };

    // Find .git directory
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Handle "checkout -" (switch to previous branch)
    var effective_first_arg = first_arg;
    var resolved_dash: ?[]u8 = null;
    defer if (resolved_dash) |rd| allocator.free(rd);
    if (std.mem.eql(u8, first_arg, "-")) {
        // Read HEAD reflog to find previous branch
        const head_reflog_path = try std.fmt.allocPrint(allocator, "{s}/logs/HEAD", .{git_path});
        defer allocator.free(head_reflog_path);
        if (platform_impl.fs.readFile(allocator, head_reflog_path)) |reflog_content| {
            defer allocator.free(reflog_content);
            // Find the last "checkout: moving from X to Y" entry
            var last_from: ?[]const u8 = null;
            var lines = std.mem.splitScalar(u8, reflog_content, '\n');
            while (lines.next()) |line| {
                if (std.mem.indexOf(u8, line, "checkout: moving from ")) |idx| {
                    const rest = line[idx + "checkout: moving from ".len..];
                    if (std.mem.indexOf(u8, rest, " to ")) |to_idx| {
                        last_from = rest[0..to_idx];
                    }
                }
            }
            if (last_from) |from_branch| {
                resolved_dash = try allocator.dupe(u8, from_branch);
                effective_first_arg = resolved_dash.?;
            } else {
                try platform_impl.writeStderr("error: no previous branch\n");
                std.process.exit(1);
            }
        } else |_| {
            try platform_impl.writeStderr("error: no previous branch\n");
            std.process.exit(1);
        }
    }

    // Handle -t / --track flag
    var want_track = false;
    if (std.mem.eql(u8, effective_first_arg, "-t") or std.mem.eql(u8, effective_first_arg, "--track")) {
        want_track = true;
        effective_first_arg = args.next() orelse {
            try platform_impl.writeStderr("fatal: '--track' requires a value\n");
            std.process.exit(128);
        };
    }

    // Check if this is --orphan flag (create orphan branch)
    if (std.mem.eql(u8, effective_first_arg, "--orphan")) {
        const branch_name = args.next() orelse {
            try platform_impl.writeStderr("fatal: option '--orphan' requires a value\n");
            std.process.exit(128);
        };

        // Set HEAD to point to the new branch (which doesn't exist yet)
        const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
        defer allocator.free(head_path);
        const ref_content = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{branch_name});
        defer allocator.free(ref_content);
        platform_impl.fs.writeFile(head_path, ref_content) catch |err| {
            const msg = try std.fmt.allocPrint(allocator, "error: failed to create orphan branch: {}\n", .{err});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };

        // Remove the index to start fresh
        const index_path = try std.fmt.allocPrint(allocator, "{s}/index", .{git_path});
        defer allocator.free(index_path);
        std.fs.cwd().deleteFile(index_path) catch {};

        const success_msg = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
        defer allocator.free(success_msg);
        try platform_impl.writeStderr(success_msg);
        return;
    }

    // Check if this is a -b flag (create new branch)
    if (std.mem.eql(u8, effective_first_arg, "-b")) {
        const branch_name = args.next() orelse {
            try platform_impl.writeStderr("fatal: option '-b' requires a value\n");
            std.process.exit(128);
        };

        // Get optional start point - resolve it to a hash
        const start_point_arg = args.next();
        var resolved_start: ?[]const u8 = null;
        if (start_point_arg) |sp| {
            resolved_start = resolveRevision(git_path, sp, platform_impl, allocator) catch null;
        }
        defer if (resolved_start) |r| allocator.free(@constCast(r));

        // Create new branch at start point (or current HEAD)
        refs.createBranch(git_path, branch_name, resolved_start orelse start_point_arg, platform_impl, allocator) catch |err| switch (err) {
            error.NoCommitsYet, error.RefNotFound, error.FileNotFound => {
                // On empty repo, just set HEAD to new branch
                const hp = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                defer allocator.free(hp);
                const rc = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{branch_name});
                defer allocator.free(rc);
                platform_impl.fs.writeFile(hp, rc) catch {};
                const sm = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
                defer allocator.free(sm);
                try platform_impl.writeStderr(sm);
                return;
            },
            error.InvalidStartPoint => {
                try platform_impl.writeStderr("fatal: not a valid object name\n");
                std.process.exit(128);
            },
            else => return err,
        };

        // Get old branch name for reflog
        var old_branch_for_b: ?[]u8 = null;
        defer if (old_branch_for_b) |ob| allocator.free(ob);
        var old_hash_for_b: ?[]u8 = null;
        defer if (old_hash_for_b) |oh| allocator.free(oh);
        {
            const hp = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
            defer allocator.free(hp);
            if (platform_impl.fs.readFile(allocator, hp)) |hd| {
                defer allocator.free(hd);
                const tr = std.mem.trim(u8, hd, " \t\r\n");
                if (std.mem.startsWith(u8, tr, "ref: refs/heads/")) {
                    old_branch_for_b = try allocator.dupe(u8, tr["ref: refs/heads/".len..]);
                    const rp = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, tr["ref: ".len..] });
                    defer allocator.free(rp);
                    if (platform_impl.fs.readFile(allocator, rp)) |rd| {
                        defer allocator.free(rd);
                        old_hash_for_b = try allocator.dupe(u8, std.mem.trim(u8, rd, " \t\r\n"));
                    } else |_| {}
                }
            } else |_| {}
        }

        // Switch to the new branch
        refs.updateHEAD(git_path, branch_name, platform_impl, allocator) catch |err| {
            const msg = try std.fmt.allocPrint(allocator, "error: failed to checkout branch '{s}': {}\n", .{ branch_name, err });
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };

        // If start_point was specified, checkout the tree of that commit
        if (start_point_arg != null) {
            const commit_hash = refs.resolveRef(git_path, try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{branch_name}), platform_impl, allocator) catch null;
            if (commit_hash) |ch| {
                defer allocator.free(ch);
                checkoutCommitTree(git_path, ch, allocator, platform_impl) catch {};
            }
        }

        // Write reflog entry
        {
            const from_name = if (old_branch_for_b) |ob| ob else "HEAD";
            const old_h = if (old_hash_for_b) |oh| oh else "0000000000000000000000000000000000000000";
            const reflog_msg_b = try std.fmt.allocPrint(allocator, "checkout: moving from {s} to {s}", .{ from_name, branch_name });
            defer allocator.free(reflog_msg_b);
            writeReflogEntry(git_path, "HEAD", old_h, old_h, reflog_msg_b, allocator, platform_impl) catch {};
        }

        // Set up tracking if -t was specified
        if (want_track) {
            const tracking_branch = if (old_branch_for_b) |ob| ob else "main";
            setTrackingConfig(git_path, branch_name, ".", tracking_branch, allocator, platform_impl);
        }

        const success_msg = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
        defer allocator.free(success_msg);
        try platform_impl.writeStdout(success_msg);
    } else if (std.mem.eql(u8, effective_first_arg, "-B")) {
        // -B: create or reset branch
        const branch_name = args.next() orelse {
            try platform_impl.writeStderr("fatal: option '-B' requires a value\n");
            std.process.exit(128);
        };
        
        // Get optional start point, resolve it
        const start_point_raw = args.next();
        var resolved_start_B: ?[]u8 = null;
        defer if (resolved_start_B) |r| allocator.free(r);
        const start_point: ?[]const u8 = if (start_point_raw) |sp| blk: {
            resolved_start_B = resolveRevision(git_path, sp, platform_impl, allocator) catch null;
            break :blk if (resolved_start_B) |r| r else sp;
        } else null;
        
        // Delete existing branch if it exists (reset)
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, branch_name });
        defer allocator.free(ref_path);
        std.fs.cwd().deleteFile(ref_path) catch {};
        
        // Create the branch
        refs.createBranch(git_path, branch_name, start_point, platform_impl, allocator) catch |err| {
            // For -B on empty repo (no commits yet), just set HEAD
            switch (err) {
                error.NoCommitsYet, error.RefNotFound, error.FileNotFound => {
                    const head_path2 = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                    defer allocator.free(head_path2);
                    const ref_content = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{branch_name});
                    defer allocator.free(ref_content);
                    platform_impl.fs.writeFile(head_path2, ref_content) catch {};
                    const reset_msg2 = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
                    defer allocator.free(reset_msg2);
                    try platform_impl.writeStderr(reset_msg2);
                    return;
                },
                else => return err,
            }
        };
        
        // Switch to the branch
        refs.updateHEAD(git_path, branch_name, platform_impl, allocator) catch {};

        // Checkout the tree of the new branch head
        if (start_point != null) {
            const commit_hash_B = refs.resolveRef(git_path, try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{branch_name}), platform_impl, allocator) catch null;
            if (commit_hash_B) |ch| {
                defer allocator.free(ch);
                checkoutCommitTree(git_path, ch, allocator, platform_impl) catch {};
            }
        }
        
        const reset_msg = try std.fmt.allocPrint(allocator, "Switched to and reset branch '{s}'\n", .{branch_name});
        defer allocator.free(reset_msg);
        try platform_impl.writeStderr(reset_msg);
    } else if (std.mem.eql(u8, effective_first_arg, "--")) {
        // checkout -- <paths>: restore files from index
        var idx = index_mod.Index.load(git_path, platform_impl, allocator) catch return;
        defer idx.deinit();
        const repo_root = std.fs.path.dirname(git_path) orelse ".";
        
        while (args.next()) |path| {
            for (idx.entries.items) |entry| {
                if (std.mem.eql(u8, entry.path, path) or simpleGlobMatch(path, entry.path)) {
                    // Load blob and write to working tree
                    var hash_hex: [40]u8 = undefined;
                    for (entry.sha1, 0..) |byte, bi| {
                        hash_hex[bi * 2] = "0123456789abcdef"[byte >> 4];
                        hash_hex[bi * 2 + 1] = "0123456789abcdef"[byte & 0xf];
                    }
                    const blob = objects.GitObject.load(&hash_hex, git_path, platform_impl, allocator) catch continue;
                    defer blob.deinit(allocator);
                    const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path });
                    defer allocator.free(full_path);
                    platform_impl.fs.writeFile(full_path, blob.data) catch {};
                }
            }
        }
    } else {
        // Parse checkout arguments
        var quiet = std.mem.eql(u8, effective_first_arg, "--quiet") or std.mem.eql(u8, effective_first_arg, "-q");
        var detach = std.mem.eql(u8, effective_first_arg, "--detach");
        var force = std.mem.eql(u8, effective_first_arg, "-f") or std.mem.eql(u8, effective_first_arg, "--force");
        var target: []const u8 = effective_first_arg;
        
        // If the first arg was a flag, consume flags and find the target
        if (quiet or detach or force) {
            var found_target = false;
            while (args.next()) |arg| {
                if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) {
                    quiet = true;
                } else if (std.mem.eql(u8, arg, "--detach")) {
                    detach = true;
                } else if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--force")) {
                    force = true;
                } else {
                    target = arg;
                    found_target = true;
                    break;
                }
            }
            if (!found_target) {
                if (detach) {
                    // --detach with no target means detach at HEAD
                    target = "HEAD";
                } else {
                    try platform_impl.writeStderr("error: pathspec '' did not match any file(s) known to git\n");
                    std.process.exit(128);
                }
            }
        }

        // Check for additional flags
        while (args.next()) |arg| {
            if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) {
                quiet = true;
            } else if (std.mem.eql(u8, arg, "--detach")) {
                detach = true;
            }
        }

        // Handle --detach: resolve target to commit hash and write directly to HEAD
        if (detach) {
            // Resolve the target to a commit hash
            var detach_hash: ?[]const u8 = null;
            
            if (std.mem.eql(u8, target, "HEAD")) {
                // Resolve HEAD to its commit hash
                if (refs.resolveRef(git_path, "HEAD", platform_impl, allocator) catch null) |h| {
                    detach_hash = h;
                }
            } else if (target.len == 40 and isValidHash(target)) {
                detach_hash = try allocator.dupe(u8, target);
            } else {
                // Try as branch name
                const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, target });
                defer allocator.free(ref_path);
                if (std.fs.cwd().readFileAlloc(allocator, ref_path, 1024)) |content| {
                    defer allocator.free(content);
                    const trimmed = std.mem.trim(u8, content, " \t\n\r");
                    if (trimmed.len >= 40) {
                        detach_hash = try allocator.dupe(u8, trimmed[0..40]);
                    }
                } else |_| {
                    // Try resolving as revision expression
                    detach_hash = resolveRevision(git_path, target, platform_impl, allocator) catch null;
                }
            }
            
            if (detach_hash) |hash| {
                defer allocator.free(hash);
                // Write detached HEAD
                const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                defer allocator.free(head_path);
                const head_content = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
                defer allocator.free(head_content);
                platform_impl.fs.writeFile(head_path, head_content) catch {};
                
                if (!quiet) {
                    const det_msg = try std.fmt.allocPrint(allocator, "HEAD is now at {s}...\n", .{hash[0..7]});
                    defer allocator.free(det_msg);
                    try platform_impl.writeStderr(det_msg);
                }
                return;
            } else {
                const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{target});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }
        }

        // Try to resolve revision expressions (like A^0, HEAD~3, etc.)
        // If the target contains special chars, resolve to a hash first
        const resolved_target = if (std.mem.indexOfAny(u8, target, "~^@") != null)
            resolveRevision(git_path, target, platform_impl, allocator) catch null
        else
            null;
        defer if (resolved_target) |rt| allocator.free(rt);
        const actual_target = resolved_target orelse target;

        // For detached HEAD (resolved hash), just update HEAD directly
        if (resolved_target != null) {
            // This is a detached HEAD checkout
            try checkoutCommitTree(git_path, actual_target, allocator, platform_impl);
            
            // Write detached HEAD
            const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
            defer allocator.free(head_path);
            const head_content = try std.fmt.allocPrint(allocator, "{s}\n", .{actual_target});
            defer allocator.free(head_content);
            platform_impl.fs.writeFile(head_path, head_content) catch {};
            
            if (!quiet) {
                const det_msg = try std.fmt.allocPrint(allocator, "Note: switching to '{s}'.\nHEAD is now at {s}\n", .{ target, actual_target[0..7] });
                defer allocator.free(det_msg);
                try platform_impl.writeStderr(det_msg);
            }
            return;
        }

        // Use native ziggit checkout
        const ziggit = @import("ziggit.zig");
        
        // Determine repository root from git_path
        const repo_root = if (std.mem.endsWith(u8, git_path, "/.git"))
            git_path[0 .. git_path.len - 5]
        else
            git_path; // bare repo
        
        var repo = ziggit.Repository.open(allocator, repo_root) catch {
            try platform_impl.writeStderr("fatal: not a git repository\n");
            std.process.exit(128);
        };
        defer repo.close();
        
        // Get current branch name before checkout for reflog
        var old_branch_name: ?[]u8 = null;
        defer if (old_branch_name) |obn| allocator.free(obn);
        var old_head_hash: ?[]u8 = null;
        defer if (old_head_hash) |ohh| allocator.free(ohh);
        {
            const head_path2 = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
            defer allocator.free(head_path2);
            if (platform_impl.fs.readFile(allocator, head_path2)) |head_data| {
                defer allocator.free(head_data);
                const trimmed = std.mem.trim(u8, head_data, " \t\r\n");
                if (std.mem.startsWith(u8, trimmed, "ref: refs/heads/")) {
                    old_branch_name = try allocator.dupe(u8, trimmed["ref: refs/heads/".len..]);
                    // Resolve to hash
                    const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, trimmed["ref: ".len..] });
                    defer allocator.free(ref_path);
                    if (platform_impl.fs.readFile(allocator, ref_path)) |hash_data| {
                        defer allocator.free(hash_data);
                        old_head_hash = try allocator.dupe(u8, std.mem.trim(u8, hash_data, " \t\r\n"));
                    } else |_| {}
                } else if (trimmed.len >= 40) {
                    old_head_hash = try allocator.dupe(u8, trimmed[0..40]);
                }
            } else |_| {}
        }

        repo.checkout(actual_target) catch |err| {
            switch (err) {
                error.CommitNotFound => {
                    const msg = try std.fmt.allocPrint(allocator, "error: pathspec '{s}' did not match any file(s) known to git\n", .{target});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                },
                error.RefNotFound => {
                    const msg = try std.fmt.allocPrint(allocator, "error: pathspec '{s}' did not match any file(s) known to git\n", .{target});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                },
                error.ObjectNotFound => {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: reference is not a tree: {s}\n", .{target});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                },
                error.InvalidCommitObject, error.InvalidTreeObject => {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: corrupt object for '{s}'\n", .{target});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                },
                else => {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: checkout failed: {}\n", .{err});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                },
            }
        };
        
        // Write reflog entry for checkout
        {
            var new_head_hash: ?[]u8 = null;
            defer if (new_head_hash) |nhh| allocator.free(nhh);
            {
                const head_path3 = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                defer allocator.free(head_path3);
                if (platform_impl.fs.readFile(allocator, head_path3)) |hd| {
                    defer allocator.free(hd);
                    const tr = std.mem.trim(u8, hd, " \t\r\n");
                    if (std.mem.startsWith(u8, tr, "ref: ")) {
                        const rp = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, tr["ref: ".len..] });
                        defer allocator.free(rp);
                        if (platform_impl.fs.readFile(allocator, rp)) |rd| {
                            defer allocator.free(rd);
                            new_head_hash = try allocator.dupe(u8, std.mem.trim(u8, rd, " \t\r\n"));
                        } else |_| {}
                    } else if (tr.len >= 40) {
                        new_head_hash = try allocator.dupe(u8, tr[0..40]);
                    }
                } else |_| {}
            }
            const from_name = if (old_branch_name) |obn| obn else "HEAD";
            const reflog_msg = try std.fmt.allocPrint(allocator, "checkout: moving from {s} to {s}", .{ from_name, target });
            defer allocator.free(reflog_msg);
            const oh = if (old_head_hash) |ohh| ohh else "0000000000000000000000000000000000000000";
            const nh = if (new_head_hash) |nhh| nhh else "0000000000000000000000000000000000000000";
            writeReflogEntry(git_path, "HEAD", oh, nh, reflog_msg, allocator, platform_impl) catch {};
        }

        if (!quiet) {
            // Check if this was a branch or detached HEAD
            var ref_check_buf: [std.fs.max_path_bytes]u8 = undefined;
            const branch_ref_path = std.fmt.bufPrint(&ref_check_buf, "{s}/refs/heads/{s}", .{ repo.git_dir, target }) catch {
                return;
            };
            
            if (std.fs.accessAbsolute(branch_ref_path, .{})) |_| {
                const msg = try std.fmt.allocPrint(allocator, "Switched to branch '{s}'\n", .{target});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            } else |_| {
                const msg = try std.fmt.allocPrint(allocator, "HEAD is now at {s}\n", .{target[0..@min(target.len, 7)]});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            }
        }
    }
}

/// Properly restore working tree from a commit tree
fn checkoutCommitTree(git_path: []const u8, commit_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Load the commit object
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch |err| switch (err) {
        error.ObjectNotFound => return error.InvalidCommit,
        else => return err,
    };
    defer commit_obj.deinit(allocator);
    
    if (commit_obj.type != .commit) {
        return error.NotACommit;
    }
    
    // Parse the commit to get the tree hash
    const tree_hash = parseCommitTreeHash(commit_obj.data, allocator) catch {
        return error.InvalidCommit;
    };
    defer allocator.free(tree_hash);
    
    // Load the tree object
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch |err| switch (err) {
        error.ObjectNotFound => return error.InvalidTree,
        else => return err,
    };
    defer tree_obj.deinit(allocator);
    
    if (tree_obj.type != .tree) {
        return error.NotATree;
    }
    
    // Get repository root (parent of .git directory)
    const repo_root = std.fs.path.dirname(git_path) orelse ".";
    
    // Clear working directory first (except .git)
    try clearWorkingDirectory(repo_root, allocator, platform_impl);
    
    // Recursively checkout the tree
    try checkoutTreeRecursive(git_path, tree_obj.data, repo_root, "", allocator, platform_impl);
    
    // Update the index to match the checked out tree
    try updateIndexFromTree(git_path, tree_hash, allocator, platform_impl);
}

/// Parse commit object to extract tree hash
fn parseCommitTreeHash(commit_data: []const u8, allocator: std.mem.Allocator) ![]u8 {
    var lines = std.mem.splitSequence(u8, commit_data, "\n");
    
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "tree ")) {
            const tree_hash = line[5..]; // Skip "tree "
            if (tree_hash.len == 40 and isValidHash(tree_hash)) {
                return try allocator.dupe(u8, tree_hash);
            }
        }
    }
    
    return error.NoTreeInCommit;
}

/// Clear tracked files from working directory (only files in the index)
fn clearWorkingDirectory(repo_root: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Load the current index to know which files are tracked
    const git_path_for_clear = blk: {
        const gp = std.fmt.allocPrint(allocator, "{s}/.git", .{repo_root}) catch return;
        break :blk gp;
    };
    defer allocator.free(git_path_for_clear);
    
    var idx = index_mod.Index.load(git_path_for_clear, platform_impl, allocator) catch return;
    defer idx.deinit();
    
    var dir = std.fs.cwd().openDir(repo_root, .{}) catch return;
    defer dir.close();
    
    // Only delete files that are in the index (tracked files)
    for (idx.entries.items) |entry| {
        dir.deleteFile(entry.path) catch {
            // If it's a directory (file was replaced by dir), remove the directory tree
            dir.deleteTree(entry.path) catch {};
        };
        // Try to remove empty parent directories
        if (std.fs.path.dirname(entry.path)) |parent| {
            dir.deleteDir(parent) catch {};
        }
    }
}

/// Recursively checkout tree entries to working directory
fn checkoutTreeRecursive(git_path: []const u8, tree_data: []const u8, repo_root: []const u8, current_path: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    var i: usize = 0;
    
    while (i < tree_data.len) {
        // Parse tree entry: "<mode> <name>\0<20-byte-hash>"
        const mode_start = i;
        const space_pos = std.mem.indexOf(u8, tree_data[i..], " ") orelse break;
        const mode = tree_data[mode_start..mode_start + space_pos];
        
        i = mode_start + space_pos + 1;
        const name_start = i;
        const null_pos = std.mem.indexOf(u8, tree_data[i..], "\x00") orelse break;
        const name = tree_data[name_start..name_start + null_pos];
        
        i = name_start + null_pos + 1;
        if (i + 20 > tree_data.len) break;
        
        // Extract 20-byte hash and convert to hex string
        const hash_bytes = tree_data[i..i + 20];
        const hash_hex = try allocator.alloc(u8, 40);
        defer allocator.free(hash_hex);
        _ = std.fmt.bufPrint(hash_hex, "{x}", .{hash_bytes}) catch break;
        
        i += 20;
        
        // Build full path
        const full_path = if (current_path.len == 0) 
            try allocator.dupe(u8, name)
        else 
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{current_path, name});
        defer allocator.free(full_path);
        
        const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{repo_root, full_path});
        defer allocator.free(file_path);
        
        // Check if this is a tree (directory) or blob (file)
        if (std.mem.startsWith(u8, mode, "40000")) {
            // This is a tree (subdirectory)
            platform_impl.fs.makeDir(file_path) catch |err| switch (err) {
                error.PathAlreadyExists => {},
                else => return err,
            };
            
            // Load subtree and recurse
            const subtree_obj = objects.GitObject.load(hash_hex, git_path, platform_impl, allocator) catch continue;
            defer subtree_obj.deinit(allocator);
            
            if (subtree_obj.type == .tree) {
                try checkoutTreeRecursive(git_path, subtree_obj.data, repo_root, full_path, allocator, platform_impl);
            }
        } else {
            // This is a blob (file)
            const blob_obj = objects.GitObject.load(hash_hex, git_path, platform_impl, allocator) catch continue;
            defer blob_obj.deinit(allocator);
            
            if (blob_obj.type == .blob) {
                // Create parent directories if needed
                if (std.fs.path.dirname(file_path)) |parent_dir| {
                    platform_impl.fs.makeDir(parent_dir) catch |err| switch (err) {
                        error.PathAlreadyExists => {},
                        else => {},
                    };
                }
                
                // Write file content
                try platform_impl.fs.writeFile(file_path, blob_obj.data);
            }
        }
    }
}

/// Update index to match the checked out tree
fn updateIndexAfterMerge(git_path: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const repo_root = std.fs.path.dirname(git_path) orelse ".";
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch {
        return;
    };
    defer index.deinit();

    var i: usize = 0;
    while (i < index.entries.items.len) {
        const entry = index.entries.items[i];
        const file_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path }) catch {
            i += 1;
            continue;
        };
        defer allocator.free(file_path);

        const file_exists = blk: {
            _ = std.fs.cwd().statFile(file_path) catch break :blk false;
            break :blk true;
        };
        if (!file_exists) {
            allocator.free(index.entries.items[i].path);
            _ = index.entries.orderedRemove(i);
        } else {
            const file_content = platform_impl.fs.readFile(allocator, file_path) catch {
                i += 1;
                continue;
            };
            defer allocator.free(file_content);
            const blob_obj = objects.createBlobObject(file_content, allocator) catch {
                i += 1;
                continue;
            };
            defer blob_obj.deinit(allocator);
            const hash_hex = blob_obj.store(git_path, platform_impl, allocator) catch {
                i += 1;
                continue;
            };
            defer allocator.free(hash_hex);
            var new_sha1: [20]u8 = undefined;
            var bi: usize = 0;
            while (bi < 20) : (bi += 1) {
                new_sha1[bi] = std.fmt.parseInt(u8, hash_hex[bi * 2 .. bi * 2 + 2], 16) catch 0;
            }
            index.entries.items[i].sha1 = new_sha1;
            i += 1;
        }
    }

    var dir = std.fs.cwd().openDir(repo_root, .{ .iterate = true }) catch {
        index.save(git_path, platform_impl) catch {};
        return;
    };
    defer dir.close();
    var it = dir.iterate();
    while (it.next() catch null) |ent| {
        if (ent.kind != .file) continue;
        if (std.mem.startsWith(u8, ent.name, ".")) continue;

        var found_in_index = false;
        for (index.entries.items) |idx_entry| {
            if (std.mem.eql(u8, idx_entry.path, ent.name)) {
                found_in_index = true;
                break;
            }
        }
        if (!found_in_index) {
            const new_file_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, ent.name }) catch continue;
            defer allocator.free(new_file_path);
            const new_content = platform_impl.fs.readFile(allocator, new_file_path) catch continue;
            defer allocator.free(new_content);
            const new_blob = objects.createBlobObject(new_content, allocator) catch continue;
            defer new_blob.deinit(allocator);
            const new_hash_hex = new_blob.store(git_path, platform_impl, allocator) catch continue;
            defer allocator.free(new_hash_hex);
            var sha1_val: [20]u8 = undefined;
            var bj: usize = 0;
            while (bj < 20) : (bj += 1) {
                sha1_val[bj] = std.fmt.parseInt(u8, new_hash_hex[bj * 2 .. bj * 2 + 2], 16) catch 0;
            }
            const stat_val = std.fs.cwd().statFile(new_file_path) catch continue;
            const new_entry = index_mod.IndexEntry.init(allocator.dupe(u8, ent.name) catch continue, stat_val, sha1_val);
            index.entries.append(new_entry) catch continue;
        }
    }

    index.save(git_path, platform_impl) catch {};
}

fn updateIndexFromTree(git_path: []const u8, tree_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Create a new index based on the tree
    var index = index_mod.Index.init(allocator);
    defer index.deinit();
    
    // Load the tree object
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch {
        // Failed to load tree for index update
        return;
    };
    defer tree_obj.deinit(allocator);
    
    if (tree_obj.type != .tree) return;
    
    // Get repository root (parent of .git directory)  
    const repo_root = std.fs.path.dirname(git_path) orelse ".";
    
    // Recursively populate index from tree
    try populateIndexFromTree(git_path, tree_obj.data, repo_root, "", &index, allocator, platform_impl);
    
    // Save the updated index
    try index.save(git_path, platform_impl);
}

/// Recursively populate index entries from tree data
fn populateIndexFromTree(git_path: []const u8, tree_data: []const u8, repo_root: []const u8, current_path: []const u8, index: *index_mod.Index, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    var i: usize = 0;
    
    while (i < tree_data.len) {
        // Parse tree entry: "<mode> <name>\0<20-byte-hash>"
        const mode_start = i;
        const space_pos = std.mem.indexOf(u8, tree_data[i..], " ") orelse break;
        const mode_str = tree_data[mode_start..mode_start + space_pos];
        
        i = mode_start + space_pos + 1;
        const name_start = i;
        const null_pos = std.mem.indexOf(u8, tree_data[i..], "\x00") orelse break;
        const name = tree_data[name_start..name_start + null_pos];
        
        i = name_start + null_pos + 1;
        if (i + 20 > tree_data.len) break;
        
        // Extract 20-byte hash
        const hash_bytes = tree_data[i..i + 20];
        var sha1: [20]u8 = undefined;
        @memcpy(&sha1, hash_bytes);
        
        i += 20;
        
        // Build full path
        const full_path = if (current_path.len == 0) 
            try allocator.dupe(u8, name)
        else 
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{current_path, name});
        defer allocator.free(full_path);
        
        // Parse mode
        const mode = std.fmt.parseInt(u32, mode_str, 8) catch 0;
        
        // Check if this is a tree (directory) or blob (file)
        if (std.mem.startsWith(u8, mode_str, "40000")) {
            // This is a tree (subdirectory) - recurse into it
            const hash_hex = try allocator.alloc(u8, 40);
            defer allocator.free(hash_hex);
            _ = try std.fmt.bufPrint(hash_hex, "{x}", .{hash_bytes});
            
            const subtree_loaded = objects.GitObject.load(hash_hex, git_path, platform_impl, allocator) catch continue;
            defer subtree_loaded.deinit(allocator);
            
            if (subtree_loaded.type == .tree) {
                try populateIndexFromTree(git_path, subtree_loaded.data, repo_root, full_path, index, allocator, platform_impl);
            }
        } else {
            // This is a blob (file) - add to index
            const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, full_path });
            defer allocator.free(file_path);
            
            // Get file stats (or create fake ones)
            const stat = std.fs.cwd().statFile(file_path) catch std.fs.File.Stat{
                .inode = 0,
                .size = 0,
                .mode = mode,
                .kind = .file,
                .atime = 0,
                .mtime = 0,
                .ctime = 0,
            };
            
            // Create index entry
            const entry = index_mod.IndexEntry.init(try allocator.dupe(u8, full_path), stat, sha1);
            try index.entries.append(entry);
        }
    }
}

fn cmdMerge(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("merge: not supported in freestanding mode\n");
        return;
    }

    // Check if we're in a git repository
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Parse merge arguments
    var merge_message: ?[]const u8 = null;
    var allow_unrelated_histories = false;
    var no_ff = false;
    var ff_only = false;
    var branch_to_merge: ?[]const u8 = null;
    var squash = false;
    var no_commit = false;
    var strategy: ?[]const u8 = null;
    var merge_signoff = false;

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-s")) {
            strategy = args.next();
        } else if (std.mem.startsWith(u8, arg, "--strategy=")) {
            strategy = arg["--strategy=".len..];
        } else if (std.mem.eql(u8, arg, "-X") or std.mem.startsWith(u8, arg, "--strategy-option")) {
            // Skip strategy options
            if (std.mem.eql(u8, arg, "-X")) _ = args.next();
        } else if (std.mem.eql(u8, arg, "-m")) {
            merge_message = args.next() orelse {
                try platform_impl.writeStderr("fatal: option '-m' requires a value\n");
                std.process.exit(128);
            };
        } else if (std.mem.startsWith(u8, arg, "-m")) {
            // -mMESSAGE (no space)
            merge_message = arg[2..];
        } else if (std.mem.eql(u8, arg, "--allow-unrelated-histories")) {
            allow_unrelated_histories = true;
        } else if (std.mem.eql(u8, arg, "--no-ff")) {
            no_ff = true;
        } else if (std.mem.eql(u8, arg, "--ff-only")) {
            ff_only = true;
        } else if (std.mem.eql(u8, arg, "--squash")) {
            squash = true;
        } else if (std.mem.eql(u8, arg, "--no-commit")) {
            no_commit = true;
        } else if (std.mem.eql(u8, arg, "--signoff")) {
            merge_signoff = true;
        } else if (std.mem.eql(u8, arg, "--no-signoff")) {
            merge_signoff = false;
        } else if (std.mem.eql(u8, arg, "--no-edit") or std.mem.eql(u8, arg, "--edit")) {
            // Accept
        } else if (std.mem.eql(u8, arg, "--stat") or std.mem.eql(u8, arg, "--no-stat") or std.mem.eql(u8, arg, "-n")) {
            // Accept
        } else if (std.mem.eql(u8, arg, "--log") or std.mem.eql(u8, arg, "--no-log") or std.mem.startsWith(u8, arg, "--log=")) {
            // Accept
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            // Accept
        } else if (std.mem.eql(u8, arg, "--ff") or std.mem.eql(u8, arg, "--progress") or std.mem.eql(u8, arg, "--no-progress")) {
            // Accept
        } else if (std.mem.eql(u8, arg, "--abort")) {
            const merge_head2 = try std.fmt.allocPrint(allocator, "{s}/MERGE_HEAD", .{git_path});
            defer allocator.free(merge_head2);
            const mh_exists = if (std.fs.cwd().access(merge_head2, .{})) |_| true else |_| false;
            if (!mh_exists) {
                try platform_impl.writeStderr("fatal: There is no merge to abort (MERGE_HEAD missing).\n");
                std.process.exit(128);
            }
            if (refs.getCurrentCommit(git_path, platform_impl, allocator) catch null) |hh| {
                defer allocator.free(hh);
                resetIndex(git_path, hh, platform_impl, allocator) catch {};
                checkoutCommitTree(git_path, hh, allocator, platform_impl) catch {};
            }
            std.fs.cwd().deleteFile(merge_head2) catch {};
            const mm2 = try std.fmt.allocPrint(allocator, "{s}/MERGE_MSG", .{git_path});
            defer allocator.free(mm2);
            std.fs.cwd().deleteFile(mm2) catch {};
            return;
        } else if (std.mem.eql(u8, arg, "--continue")) {
            return;
        } else if (std.mem.startsWith(u8, arg, "--") and arg.len > 2) {
            const err_msg = try std.fmt.allocPrint(allocator, "error: unknown option `{s}'\n", .{arg[2..]});
            defer allocator.free(err_msg);
            try platform_impl.writeStderr(err_msg);
            std.process.exit(128);
        } else if (arg.len > 0 and arg[0] == '-' and !std.mem.eql(u8, arg, "--")) {
            const err_msg = try std.fmt.allocPrint(allocator, "error: unknown switch `{c}'\n", .{arg[1]});
            defer allocator.free(err_msg);
            try platform_impl.writeStderr(err_msg);
            std.process.exit(128);
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            branch_to_merge = arg;
        }
    }

    if (branch_to_merge == null) {
        try platform_impl.writeStderr("fatal: no merge target specified\n");
        std.process.exit(128);
    }

    // Get current branch
    const current_branch = refs.getCurrentBranch(git_path, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: unable to determine current branch\n");
        std.process.exit(128);
    };
    defer allocator.free(current_branch);

    const merge_target = branch_to_merge.?;

    // Try to resolve the merge target as a revision (could be branch name, tag, or hash)
    const target_hash_resolved = resolveRevision(git_path, merge_target, platform_impl, allocator) catch blk: {
        // Also try as branch
        if (refs.branchExists(git_path, merge_target, platform_impl, allocator) catch false) {
            break :blk refs.getBranchCommit(git_path, merge_target, platform_impl, allocator) catch null;
        }
        break :blk null;
    };

    if (target_hash_resolved == null) {
        // Check if branch exists using the old logic
        if (!(refs.branchExists(git_path, merge_target, platform_impl, allocator) catch false)) {
            const msg = try std.fmt.allocPrint(allocator, "merge: '{s}' - not something we can merge\n", .{merge_target});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        }
    }

    // Check if trying to merge with itself
    if (std.mem.eql(u8, current_branch, merge_target)) {
        try platform_impl.writeStdout("Already up to date.\n");
        return;
    }

    // Get the current and target commit hashes
    const current_commit_result = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: unable to get current commit\n");
        std.process.exit(1);
    };
    defer if (current_commit_result) |hash| allocator.free(hash);

    const target_hash = if (target_hash_resolved) |h| h else blk: {
        const target_commit_result = refs.getBranchCommit(git_path, merge_target, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: unable to get target branch commit\n");  
            std.process.exit(1);
        };
        break :blk if (target_commit_result) |hash| hash else {
            try platform_impl.writeStderr("fatal: no commits yet on target branch\n");
            std.process.exit(1);
        };
    };
    defer allocator.free(target_hash);

    const current_hash = if (current_commit_result) |hash| hash else {
        // No current commits - if allow_unrelated_histories, just set the ref
        if (allow_unrelated_histories) {
            try refs.updateRef(git_path, current_branch, target_hash, platform_impl, allocator);
            try checkoutCommitTree(git_path, target_hash, allocator, platform_impl);
            try platform_impl.writeStdout("Fast-forward\n");
            return;
        }
        try platform_impl.writeStderr("fatal: no commits yet on current branch\n");
        std.process.exit(1);
    };

    // Check if already up to date (target is ancestor of current)
    if (std.mem.eql(u8, current_hash, target_hash) or (isAncestor(git_path, target_hash, current_hash, allocator, platform_impl) catch false)) {
        try platform_impl.writeStdout("Already up to date.\n");
        return;
    }

    // Handle -s ours strategy: keep our tree, create merge commit
    if (strategy != null and std.mem.eql(u8, strategy.?, "ours")) {
        const current_obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: unable to read current commit\n");
            std.process.exit(1);
        };
        defer current_obj.deinit(allocator);
        const our_tree = extractHeaderField(current_obj.data, "tree");
        if (our_tree.len == 0) {
            try platform_impl.writeStderr("fatal: unable to find tree\n");
            std.process.exit(1);
        }
        const actual_msg = merge_message orelse
            try buildMergeMessage(merge_target, current_branch, git_path, allocator, platform_impl);
        defer if (merge_message == null) allocator.free(actual_msg);
        const author_str = getAuthorString(allocator) catch try allocator.dupe(u8, "Unknown <unknown@unknown>");
        defer allocator.free(author_str);
        const committer_str = getCommitterString(allocator) catch try allocator.dupe(u8, "Unknown <unknown@unknown>");
        defer allocator.free(committer_str);
        const parents = [_][]const u8{ current_hash, target_hash };
        const commit_obj = try objects.createCommitObject(our_tree, &parents, author_str, committer_str, actual_msg, allocator);
        defer commit_obj.deinit(allocator);
        const new_hash = try commit_obj.store(git_path, platform_impl, allocator);
        defer allocator.free(new_hash);
        try refs.updateRef(git_path, current_branch, new_hash, platform_impl, allocator);
        try platform_impl.writeStdout("Merge made by the 'ours' strategy.\n");
        return;
    }

    // Check if this is a fast-forward merge
    if (!no_ff and canFastForward(git_path, current_hash, target_hash, allocator, platform_impl)) {
        // Fast-forward merge
        try refs.updateRef(git_path, current_branch, target_hash, platform_impl, allocator);
        try checkoutCommitTree(git_path, target_hash, allocator, platform_impl);

        const msg2 = try std.fmt.allocPrint(allocator, "Fast-forward\n", .{});
        defer allocator.free(msg2);
        try platform_impl.writeStdout(msg2);
        
        const short_hash = target_hash[0..7];
        const success_msg = try std.fmt.allocPrint(allocator, "Updating {s}..{s}\n", .{ current_hash[0..7], short_hash });
        defer allocator.free(success_msg);
        try platform_impl.writeStdout(success_msg);
    } else {
        // Perform 3-way merge (or merge commit for unrelated histories)
        if (allow_unrelated_histories) {
            // Create a merge commit with both parents
            const actual_message = merge_message orelse blk: {
                break :blk try buildMergeMessage(merge_target, current_branch, git_path, allocator, platform_impl);
            };
            const should_free_msg = merge_message == null;
            defer if (should_free_msg) allocator.free(actual_message);

            // Get tree from current HEAD commit
            const current_obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: unable to read current commit\n");
                std.process.exit(1);
            };
            defer current_obj.deinit(allocator);

            var tree_hash: ?[]const u8 = null;
            var clines = std.mem.splitSequence(u8, current_obj.data, "\n");
            while (clines.next()) |line| {
                if (std.mem.startsWith(u8, line, "tree ")) {
                    tree_hash = line[5..];
                    break;
                }
            }

            if (tree_hash == null) {
                try platform_impl.writeStderr("fatal: unable to find tree in current commit\n");
                std.process.exit(1);
            }

            // Create merge commit with two parents
            const author_str = getAuthorString(allocator) catch try allocator.dupe(u8, "Unknown <unknown@unknown>");
            defer allocator.free(author_str);
            const committer_str = getCommitterString(allocator) catch try allocator.dupe(u8, "Unknown <unknown@unknown>");
            defer allocator.free(committer_str);
            const commit_content = try std.fmt.allocPrint(allocator, "tree {s}\nparent {s}\nparent {s}\nauthor {s}\ncommitter {s}\n\n{s}\n", .{ tree_hash.?, current_hash, target_hash, author_str, committer_str, actual_message });
            defer allocator.free(commit_content);

            const commit_obj = objects.GitObject.init(.commit, commit_content);
            const merge_commit_hash = commit_obj.store(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: unable to write merge commit\n");
                std.process.exit(1);
            };
            defer allocator.free(merge_commit_hash);

            // Update the current branch to point to the merge commit
            try refs.updateRef(git_path, current_branch, merge_commit_hash, platform_impl, allocator);

            const success_msg = try std.fmt.allocPrint(allocator, "Merge made by the 'ort' strategy.\n", .{});
            defer allocator.free(success_msg);
            try platform_impl.writeStdout(success_msg);
        } else {
            try performThreeWayMerge(git_path, current_hash, target_hash, current_branch, merge_target, merge_message, no_commit, squash, merge_signoff, allocator, platform_impl);
        }
    }
}

/// Check if a merge can be done as a fast-forward
fn canFastForward(git_path: []const u8, current_hash: []const u8, target_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) bool {
    // Simple case: if hashes are the same, already up to date
    if (std.mem.eql(u8, current_hash, target_hash)) {
        return true;
    }
    
    // Check if current commit is an ancestor of target commit
    return isAncestor(git_path, current_hash, target_hash, allocator, platform_impl) catch false;
}

/// Check if ancestor_hash is an ancestor of descendant_hash
fn isAncestor(git_path: []const u8, ancestor_hash: []const u8, descendant_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !bool {
    if (std.mem.eql(u8, ancestor_hash, descendant_hash)) return true;
    
    // Load the descendant commit
    const descendant_commit = objects.GitObject.load(descendant_hash, git_path, platform_impl, allocator) catch return false;
    defer descendant_commit.deinit(allocator);
    
    if (descendant_commit.type != .commit) return false;
    
    // Parse commit to find parents
    var lines = std.mem.splitSequence(u8, descendant_commit.data, "\n");
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "parent ")) {
            const parent_hash = line["parent ".len..];
            if (std.mem.eql(u8, parent_hash, ancestor_hash)) {
                return true; // Direct parent
            }
            // Recursively check if ancestor is ancestor of this parent
            if (isAncestor(git_path, ancestor_hash, parent_hash, allocator, platform_impl) catch false) {
                return true;
            }
        } else if (line.len == 0) {
            break; // End of headers
        }
    }
    
    return false;
}

/// Find the merge base (common ancestor) of two commits
fn findMergeBase(git_path: []const u8, hash1: []const u8, hash2: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    // Simplified merge base algorithm - find first common ancestor
    // A proper implementation would use more sophisticated algorithms
    
    // Collect all ancestors of hash1
    var ancestors1 = std.StringHashMap(void).init(allocator);
    defer {
        var iterator = ancestors1.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
        }
        ancestors1.deinit();
    }
    
    try collectAncestors(git_path, hash1, &ancestors1, allocator, platform_impl);
    
    // Walk ancestors of hash2 and find first match
    return findFirstCommonAncestor(git_path, hash2, &ancestors1, allocator, platform_impl) catch try allocator.dupe(u8, hash1);
}

/// Recursively collect all ancestor commit hashes
fn collectAncestors(git_path: []const u8, commit_hash: []const u8, ancestors: *std.StringHashMap(void), allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Avoid infinite loops
    if (ancestors.contains(commit_hash)) return;
    
    try ancestors.put(try allocator.dupe(u8, commit_hash), {});
    
    // Load commit to find parents
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch return;
    defer commit_obj.deinit(allocator);
    
    if (commit_obj.type != .commit) return;
    
    // Parse commit to find parents
    var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "parent ")) {
            const parent_hash = line["parent ".len..];
            try collectAncestors(git_path, parent_hash, ancestors, allocator, platform_impl);
        } else if (line.len == 0) {
            break; // End of headers
        }
    }
}

/// Find first common ancestor by walking commit history
fn findFirstCommonAncestor(git_path: []const u8, commit_hash: []const u8, ancestors: *const std.StringHashMap(void), allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    // Check if this commit is in ancestors
    if (ancestors.contains(commit_hash)) {
        return try allocator.dupe(u8, commit_hash);
    }
    
    // Load commit to find parents
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch return error.NotFound;
    defer commit_obj.deinit(allocator);
    
    if (commit_obj.type != .commit) return error.NotFound;
    
    // Check parents
    var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "parent ")) {
            const parent_hash = line["parent ".len..];
            if (findFirstCommonAncestor(git_path, parent_hash, ancestors, allocator, platform_impl)) |common_ancestor| {
                return common_ancestor;
            } else |_| {
                continue;
            }
        } else if (line.len == 0) {
            break; // End of headers
        }
    }
    
    return error.NotFound;
}

/// Perform a 3-way merge between current branch and target branch
fn writeMergeState(git_path: []const u8, target_hash: []const u8, merge_msg_text: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const merge_head_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_HEAD", .{git_path});
    defer allocator.free(merge_head_path);
    const merge_head_content = try std.fmt.allocPrint(allocator, "{s}\n", .{target_hash});
    defer allocator.free(merge_head_content);
    try platform_impl.fs.writeFile(merge_head_path, merge_head_content);

    const merge_msg_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_MSG", .{git_path});
    defer allocator.free(merge_msg_path);
    try platform_impl.fs.writeFile(merge_msg_path, merge_msg_text);

    const merge_mode_path = try std.fmt.allocPrint(allocator, "{s}/MERGE_MODE", .{git_path});
    defer allocator.free(merge_mode_path);
    try platform_impl.fs.writeFile(merge_mode_path, "");
}

fn performThreeWayMerge(git_path: []const u8, current_hash: []const u8, target_hash: []const u8, current_branch: []const u8, target_branch: []const u8, merge_message: ?[]const u8, no_commit: bool, squash: bool, merge_signoff: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Find common base (merge base) - simplified implementation
    const merge_base = findMergeBase(git_path, current_hash, target_hash, allocator, platform_impl) catch try allocator.dupe(u8, current_hash);
    defer allocator.free(merge_base);
    
    // Get trees for the three commits
    const base_tree = try getCommitTree(git_path, merge_base, allocator, platform_impl);
    defer allocator.free(base_tree);
    
    const current_tree = try getCommitTree(git_path, current_hash, allocator, platform_impl);
    defer allocator.free(current_tree);
    
    const target_tree = try getCommitTree(git_path, target_hash, allocator, platform_impl);  
    defer allocator.free(target_tree);
    
    // Build the merge message
    const actual_msg = merge_message orelse try buildMergeMessage(target_branch, current_branch, git_path, allocator, platform_impl);
    const should_free_msg = merge_message == null;
    defer if (should_free_msg) allocator.free(actual_msg);
    
    // Perform the merge
    const conflicts_found = try mergeTreesWithConflicts(git_path, base_tree, current_tree, target_tree, allocator, platform_impl);
    
    // Update index to reflect merged working tree
    updateIndexAfterMerge(git_path, allocator, platform_impl) catch {};
    
    if (conflicts_found) {
        try writeMergeState(git_path, target_hash, actual_msg, allocator, platform_impl);
        try platform_impl.writeStderr("Automatic merge failed; fix conflicts and then commit the result.\n");
        std.process.exit(1);
    } else if (no_commit or squash) {
        if (!squash) {
            try writeMergeState(git_path, target_hash, actual_msg, allocator, platform_impl);
        } else {
            const squash_msg_path = try std.fmt.allocPrint(allocator, "{s}/SQUASH_MSG", .{git_path});
            defer allocator.free(squash_msg_path);
            try platform_impl.fs.writeFile(squash_msg_path, actual_msg);
        }
        try platform_impl.writeStdout("Automatic merge went well; stopped before committing as requested\n");
    } else {
        // Create merge commit - add signoff if requested
        var final_merge_msg = merge_message;
        if (merge_signoff) {
            const base_msg = merge_message orelse try buildMergeMessage(target_branch, current_branch, git_path, allocator, platform_impl);
            const committer_str2 = getCommitterString(allocator) catch null;
            if (committer_str2) |cs| {
                defer allocator.free(cs);
                const gt = std.mem.lastIndexOf(u8, cs, ">") orelse cs.len;
                const ne = cs[0..@min(gt + 1, cs.len)];
                final_merge_msg = try std.fmt.allocPrint(allocator, "{s}\n\nSigned-off-by: {s}", .{base_msg, ne});
                if (merge_message == null) allocator.free(base_msg);
            }
        }
        try createMergeCommitWithMsg(git_path, current_hash, target_hash, current_branch, target_branch, final_merge_msg, allocator, platform_impl);
        try platform_impl.writeStdout("Merge made by the 'ort' strategy.\n");
    }
}

/// Get the tree hash from a commit
fn getCommitTree(git_path: []const u8, commit_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    const commit_obj = try objects.GitObject.load(commit_hash, git_path, platform_impl, allocator);
    defer commit_obj.deinit(allocator);
    
    if (commit_obj.type != .commit) {
        return error.NotACommit;
    }
    
    return try parseCommitTreeHash(commit_obj.data, allocator);
}

/// Merge three trees and detect conflicts
fn mergeTreesWithConflicts(git_path: []const u8, base_tree: []const u8, current_tree: []const u8, target_tree: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !bool {
    // Load all three trees
    const base_tree_obj = try objects.GitObject.load(base_tree, git_path, platform_impl, allocator);
    defer base_tree_obj.deinit(allocator);
    
    const current_tree_obj = try objects.GitObject.load(current_tree, git_path, platform_impl, allocator);
    defer current_tree_obj.deinit(allocator);
    
    const target_tree_obj = try objects.GitObject.load(target_tree, git_path, platform_impl, allocator);
    defer target_tree_obj.deinit(allocator);
    
    if (base_tree_obj.type != .tree or current_tree_obj.type != .tree or target_tree_obj.type != .tree) {
        return error.NotATree;
    }
    
    // Parse trees into file maps
    var base_files = std.StringHashMap([]const u8).init(allocator);
    defer {
        var iterator = base_files.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.*);
        }
        base_files.deinit();
    }
    try parseTreeIntoMap(base_tree_obj.data, &base_files, allocator);
    
    var current_files = std.StringHashMap([]const u8).init(allocator);
    defer {
        var iterator = current_files.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.*);
        }
        current_files.deinit();
    }
    try parseTreeIntoMap(current_tree_obj.data, &current_files, allocator);
    
    var target_files = std.StringHashMap([]const u8).init(allocator);
    defer {
        var iterator = target_files.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.*);
        }
        target_files.deinit();
    }
    try parseTreeIntoMap(target_tree_obj.data, &target_files, allocator);
    
    // Perform 3-way merge
    return try performThreeWayFileMerge(git_path, &base_files, &current_files, &target_files, allocator, platform_impl);
}

/// Parse tree data into a map of filename -> blob hash
/// Collect all file paths from a tree object recursively
fn collectTreePaths(git_path: []const u8, tree_hash: []const u8, prefix: []const u8, paths: *std.StringHashMap(void), allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    if (tree_obj.type != .tree) return;

    var i: usize = 0;
    while (i < tree_obj.data.len) {
        const space_pos = std.mem.indexOf(u8, tree_obj.data[i..], " ") orelse break;
        const mode = tree_obj.data[i .. i + space_pos];
        i = i + space_pos + 1;
        const null_pos = std.mem.indexOf(u8, tree_obj.data[i..], "\x00") orelse break;
        const name = tree_obj.data[i .. i + null_pos];
        i = i + null_pos + 1;
        if (i + 20 > tree_obj.data.len) break;
        const hash_bytes = tree_obj.data[i .. i + 20];
        i += 20;

        const full_path = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);

        if (std.mem.eql(u8, mode, "40000")) {
            var sub_hash: [40]u8 = undefined;
            for (hash_bytes, 0..) |b, bi| {
                sub_hash[bi * 2] = "0123456789abcdef"[b >> 4];
                sub_hash[bi * 2 + 1] = "0123456789abcdef"[b & 0xf];
            }
            collectTreePaths(git_path, &sub_hash, full_path, paths, allocator, platform_impl) catch {};
            allocator.free(full_path);
        } else {
            try paths.put(full_path, {});
        }
    }
}

fn parseTreeIntoMap(tree_data: []const u8, file_map: *std.StringHashMap([]const u8), allocator: std.mem.Allocator) !void {
    var i: usize = 0;
    
    while (i < tree_data.len) {
        // Parse tree entry: "<mode> <name>\0<20-byte-hash>"
        const mode_start = i;
        const space_pos = std.mem.indexOf(u8, tree_data[i..], " ") orelse break;
        const mode = tree_data[mode_start..mode_start + space_pos];
        _ = mode; // We'll ignore mode for simplicity
        
        i = mode_start + space_pos + 1;
        const name_start = i;
        const null_pos = std.mem.indexOf(u8, tree_data[i..], "\x00") orelse break;
        const name = tree_data[name_start..name_start + null_pos];
        
        i = name_start + null_pos + 1;
        if (i + 20 > tree_data.len) break;
        
        // Extract 20-byte hash and convert to hex string
        const hash_bytes = tree_data[i..i + 20];
        const hash_hex = try allocator.alloc(u8, 40);
        _ = std.fmt.bufPrint(hash_hex, "{x}", .{hash_bytes}) catch {
            allocator.free(hash_hex);
            break;
        };
        
        i += 20;
        
        // Only handle blob files for now (not subtrees)
        if (name.len > 0 and name[0] != '.') {
            const name_copy = try allocator.dupe(u8, name);
            try file_map.put(name_copy, hash_hex);
        } else {
            allocator.free(hash_hex);
        }
    }
}

/// Perform 3-way merge on files and detect conflicts
fn performThreeWayFileMerge(git_path: []const u8, base_files: *std.StringHashMap([]const u8), current_files: *std.StringHashMap([]const u8), target_files: *std.StringHashMap([]const u8), allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !bool {
    var conflicts_found = false;
    const repo_root = std.fs.path.dirname(git_path) orelse ".";
    
    // Get all unique filenames across the three trees
    var all_files = std.StringHashMap(void).init(allocator);
    defer {
        var iterator = all_files.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
        }
        all_files.deinit();
    }
    
    // Collect all filenames
    var base_iterator = base_files.iterator();
    while (base_iterator.next()) |entry| {
        const name_copy = try allocator.dupe(u8, entry.key_ptr.*);
        try all_files.put(name_copy, {});
    }
    
    var current_iterator = current_files.iterator();
    while (current_iterator.next()) |entry| {
        if (!all_files.contains(entry.key_ptr.*)) {
            const name_copy = try allocator.dupe(u8, entry.key_ptr.*);
            try all_files.put(name_copy, {});
        }
    }
    
    var target_iterator = target_files.iterator();
    while (target_iterator.next()) |entry| {
        if (!all_files.contains(entry.key_ptr.*)) {
            const name_copy = try allocator.dupe(u8, entry.key_ptr.*);
            try all_files.put(name_copy, {});
        }
    }
    
    // Process each file
    var all_files_iterator = all_files.iterator();
    while (all_files_iterator.next()) |entry| {
        const filename = entry.key_ptr.*;
        
        const base_hash = base_files.get(filename);
        const current_hash = current_files.get(filename);
        const target_hash = target_files.get(filename);
        
        // Determine merge action
        if (base_hash == null and current_hash == null and target_hash != null) {
            // File added in target branch
            try writeFileFromBlob(git_path, filename, target_hash.?, repo_root, allocator, platform_impl);
        } else if (base_hash == null and current_hash != null and target_hash == null) {
            // File added in current branch  
            try writeFileFromBlob(git_path, filename, current_hash.?, repo_root, allocator, platform_impl);
        } else if (base_hash != null and current_hash == null and target_hash == null) {
            // File deleted in both branches - remove it
            const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, filename });
            defer allocator.free(file_path);
            std.fs.cwd().deleteFile(file_path) catch {};
        } else if (base_hash != null and current_hash != null and target_hash == null) {
            // File deleted in target branch but exists in current
            if (std.mem.eql(u8, base_hash.?, current_hash.?)) {
                // Not modified in current - safe to delete
                const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, filename });
                defer allocator.free(file_path);
                std.fs.cwd().deleteFile(file_path) catch {};
            } else {
                // Modified in current but deleted in target - delete/modify conflict
                conflicts_found = true;
                const msg = try std.fmt.allocPrint(allocator, "CONFLICT (modify/delete): {s} deleted in theirs and modified in ours. Version ours of {s} left in tree.\n", .{ filename, filename });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                // Leave the current version in the working tree
                try writeFileFromBlob(git_path, filename, current_hash.?, repo_root, allocator, platform_impl);
            }
        } else if (base_hash != null and current_hash == null and target_hash != null) {
            // File deleted in current branch but exists in target
            if (std.mem.eql(u8, base_hash.?, target_hash.?)) {
                // Not modified in target - safe to keep deleted
                const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, filename });
                defer allocator.free(file_path);
                std.fs.cwd().deleteFile(file_path) catch {};
            } else {
                // Modified in target but deleted in current - delete/modify conflict
                conflicts_found = true;
                const msg = try std.fmt.allocPrint(allocator, "CONFLICT (modify/delete): {s} deleted in ours and modified in theirs. Version theirs of {s} left in tree.\n", .{ filename, filename });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                // Leave the target version in the working tree
                try writeFileFromBlob(git_path, filename, target_hash.?, repo_root, allocator, platform_impl);
            }
        } else if (current_hash != null and target_hash != null) {
            if (std.mem.eql(u8, current_hash.?, target_hash.?)) {
                // No change needed - both have same content
                try writeFileFromBlob(git_path, filename, current_hash.?, repo_root, allocator, platform_impl);
            } else if (base_hash != null and std.mem.eql(u8, base_hash.?, current_hash.?)) {
                // Only target changed - take target
                try writeFileFromBlob(git_path, filename, target_hash.?, repo_root, allocator, platform_impl);
            } else if (base_hash != null and std.mem.eql(u8, base_hash.?, target_hash.?)) {
                // Only current changed - keep current
                try writeFileFromBlob(git_path, filename, current_hash.?, repo_root, allocator, platform_impl);
            } else if (base_hash != null) {
                // Both sides modified - try content-level 3-way merge
                const base_content = loadBlobForMerge(git_path, base_hash.?, allocator, platform_impl);
                defer if (base_content.len > 0) allocator.free(base_content);
                const current_content = loadBlobForMerge(git_path, current_hash.?, allocator, platform_impl);
                defer if (current_content.len > 0) allocator.free(current_content);
                const target_content = loadBlobForMerge(git_path, target_hash.?, allocator, platform_impl);
                defer if (target_content.len > 0) allocator.free(target_content);

                if (try threeWayContentMerge(base_content, current_content, target_content, allocator)) |merged| {
                    defer allocator.free(merged);
                    const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, filename });
                    defer allocator.free(file_path);
                    if (std.fs.path.dirname(file_path)) |parent_dir| {
                        std.fs.cwd().makePath(parent_dir) catch {};
                    }
                    try platform_impl.fs.writeFile(file_path, merged);
                } else {
                    conflicts_found = true;
                    try createConflictFile(git_path, filename, base_hash, current_hash.?, target_hash.?, repo_root, allocator, platform_impl);
                }
            } else {
                // No base - both added - conflict
                conflicts_found = true;
                try createConflictFile(git_path, filename, base_hash, current_hash.?, target_hash.?, repo_root, allocator, platform_impl);
            }
        }
    }
    
    return conflicts_found;
}

/// Load blob content from a hash for merge
fn loadBlobForMerge(git_path: []const u8, blob_hash: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) []const u8 {
    const blob_obj = objects.GitObject.load(blob_hash, git_path, platform_impl, allocator) catch return "";
    defer blob_obj.deinit(allocator);
    if (blob_obj.type != .blob) return "";
    return allocator.dupe(u8, blob_obj.data) catch return "";
}

/// Perform a simple 3-way content merge. Returns merged content or null if conflict.
/// Perform a simple 3-way content merge. Returns merged content or null if conflict.
fn threeWayContentMerge(base: []const u8, ours: []const u8, theirs: []const u8, allocator: std.mem.Allocator) !?[]const u8 {
    // If ours == base, just take theirs
    if (std.mem.eql(u8, base, ours)) {
        return try allocator.dupe(u8, theirs);
    }
    // If theirs == base, just take ours
    if (std.mem.eql(u8, base, theirs)) {
        return try allocator.dupe(u8, ours);
    }
    // If ours == theirs, both made same change
    if (std.mem.eql(u8, ours, theirs)) {
        return try allocator.dupe(u8, ours);
    }

    // Split into lines
    const base_lines = splitLines(base, allocator) catch return null;
    defer allocator.free(base_lines);
    const ours_lines = splitLines(ours, allocator) catch return null;
    defer allocator.free(ours_lines);
    const theirs_lines = splitLines(theirs, allocator) catch return null;
    defer allocator.free(theirs_lines);

    // Compute LCS of base with ours and theirs
    const ours_lcs = mergeComputeLCS(base_lines, ours_lines, allocator) catch return null;
    defer allocator.free(ours_lcs);
    const theirs_lcs = mergeComputeLCS(base_lines, theirs_lines, allocator) catch return null;
    defer allocator.free(theirs_lcs);

    // Mark which base lines are kept in each
    const ours_kept = allocator.alloc(bool, base_lines.len) catch return null;
    defer allocator.free(ours_kept);
    const theirs_kept = allocator.alloc(bool, base_lines.len) catch return null;
    defer allocator.free(theirs_kept);
    @memset(ours_kept, false);
    @memset(theirs_kept, false);
    for (ours_lcs) |bi| ours_kept[bi] = true;
    for (theirs_lcs) |bi| theirs_kept[bi] = true;

    // Find common anchors (base lines kept in both)
    var common_base = std.array_list.Managed(usize).init(allocator);
    defer common_base.deinit();
    for (0..base_lines.len) |bi| {
        if (ours_kept[bi] and theirs_kept[bi]) {
            try common_base.append(bi);
        }
    }

    // Map common base indices to ours/theirs line indices
    var ours_idx_map = std.array_list.Managed(usize).init(allocator);
    defer ours_idx_map.deinit();
    var theirs_idx_map = std.array_list.Managed(usize).init(allocator);
    defer theirs_idx_map.deinit();

    {
        var oi: usize = 0;
        for (common_base.items) |bi| {
            while (oi < ours_lines.len) : (oi += 1) {
                if (std.mem.eql(u8, ours_lines[oi], base_lines[bi])) {
                    try ours_idx_map.append(oi);
                    oi += 1;
                    break;
                }
            }
        }
    }
    {
        var ti: usize = 0;
        for (common_base.items) |bi| {
            while (ti < theirs_lines.len) : (ti += 1) {
                if (std.mem.eql(u8, theirs_lines[ti], base_lines[bi])) {
                    try theirs_idx_map.append(ti);
                    ti += 1;
                    break;
                }
            }
        }
    }

    if (ours_idx_map.items.len != common_base.items.len or
        theirs_idx_map.items.len != common_base.items.len)
    {
        return null; // Mapping failed
    }

    var result = std.array_list.Managed(u8).init(allocator);
    errdefer result.deinit();

    const anchor_count = common_base.items.len;
    var prev_base: usize = 0;
    var prev_ours: usize = 0;
    var prev_theirs: usize = 0;

    var i: usize = 0;
    while (i <= anchor_count) : (i += 1) {
        const cur_base = if (i < anchor_count) common_base.items[i] else base_lines.len;
        const cur_ours = if (i < anchor_count) ours_idx_map.items[i] else ours_lines.len;
        const cur_theirs = if (i < anchor_count) theirs_idx_map.items[i] else theirs_lines.len;

        const base_gap = base_lines[prev_base..cur_base];
        const ours_gap = ours_lines[prev_ours..cur_ours];
        const theirs_gap = theirs_lines[prev_theirs..cur_theirs];

        if (base_gap.len == 0 and ours_gap.len == 0 and theirs_gap.len == 0) {
            // No gap
        } else if (mergeLineSlicesEqual(base_gap, ours_gap) and mergeLineSlicesEqual(base_gap, theirs_gap)) {
            for (base_gap) |line| {
                try result.appendSlice(line);
                try result.append('\n');
            }
        } else if (mergeLineSlicesEqual(base_gap, ours_gap)) {
            // Only theirs changed
            for (theirs_gap) |line| {
                try result.appendSlice(line);
                try result.append('\n');
            }
        } else if (mergeLineSlicesEqual(base_gap, theirs_gap)) {
            // Only ours changed
            for (ours_gap) |line| {
                try result.appendSlice(line);
                try result.append('\n');
            }
        } else if (mergeLineSlicesEqual(ours_gap, theirs_gap)) {
            // Both made same change
            for (ours_gap) |line| {
                try result.appendSlice(line);
                try result.append('\n');
            }
        } else {
            // Both changed differently - CONFLICT
            return null;
        }

        // Output the anchor line
        if (i < anchor_count) {
            try result.appendSlice(base_lines[common_base.items[i]]);
            try result.append('\n');
            prev_base = common_base.items[i] + 1;
            prev_ours = cur_ours + 1;
            prev_theirs = cur_theirs + 1;
        }
    }

    return try result.toOwnedSlice();
}

fn mergeLineSlicesEqual(a: []const []const u8, b: []const []const u8) bool {
    if (a.len != b.len) return false;
    for (a, b) |x, y| {
        if (!std.mem.eql(u8, x, y)) return false;
    }
    return true;
}

/// Compute LCS indices into `a` for common elements with `b`
fn mergeComputeLCS(a: []const []const u8, b: []const []const u8, allocator: std.mem.Allocator) ![]usize {
    const m = a.len;
    const n = b.len;
    if (m == 0 or n == 0) return try allocator.alloc(usize, 0);

    // For large inputs, use greedy approach
    if (m * n > 1000000) {
        var res = std.array_list.Managed(usize).init(allocator);
        defer res.deinit();
        var bj: usize = 0;
        for (0..m) |ai| {
            while (bj < n) : (bj += 1) {
                if (std.mem.eql(u8, a[ai], b[bj])) {
                    try res.append(ai);
                    bj += 1;
                    break;
                }
            }
        }
        return res.toOwnedSlice();
    }

    // Standard DP LCS
    const dp = try allocator.alloc([]u16, m + 1);
    defer {
        for (dp) |row| allocator.free(row);
        allocator.free(dp);
    }
    for (dp) |*row| {
        row.* = try allocator.alloc(u16, n + 1);
        @memset(row.*, 0);
    }

    for (1..m + 1) |ii| {
        for (1..n + 1) |jj| {
            if (std.mem.eql(u8, a[ii - 1], b[jj - 1])) {
                dp[ii][jj] = dp[ii - 1][jj - 1] + 1;
            } else {
                dp[ii][jj] = @max(dp[ii - 1][jj], dp[ii][jj - 1]);
            }
        }
    }

    var res = std.array_list.Managed(usize).init(allocator);
    defer res.deinit();
    var ii: usize = m;
    var jj: usize = n;
    while (ii > 0 and jj > 0) {
        if (std.mem.eql(u8, a[ii - 1], b[jj - 1])) {
            try res.append(ii - 1);
            ii -= 1;
            jj -= 1;
        } else if (dp[ii - 1][jj] >= dp[ii][jj - 1]) {
            ii -= 1;
        } else {
            jj -= 1;
        }
    }

    std.mem.reverse(usize, res.items);
    return res.toOwnedSlice();
}

fn splitLines(text: []const u8, allocator: std.mem.Allocator) ![][]const u8 {
    if (text.len == 0) return try allocator.alloc([]const u8, 0);
    var lines = std.array_list.Managed([]const u8).init(allocator);
    var iter = std.mem.splitScalar(u8, text, '\n');
    while (iter.next()) |line| {
        // Skip trailing empty line from final newline
        if (line.len == 0 and iter.peek() == null) break;
        try lines.append(line);
    }
    return lines.toOwnedSlice();
}

fn findLineInSlice(lines: []const []const u8, target: []const u8) ?usize {
    for (lines, 0..) |line, i| {
        if (std.mem.eql(u8, line, target)) return i;
    }
    return null;
}

/// Write a file from a blob hash
fn writeFileFromBlob(git_path: []const u8, filename: []const u8, blob_hash: []const u8, repo_root: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const blob_obj = objects.GitObject.load(blob_hash, git_path, platform_impl, allocator) catch return;
    defer blob_obj.deinit(allocator);
    
    if (blob_obj.type != .blob) return;
    
    const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, filename });
    defer allocator.free(file_path);
    
    // Create parent directories if needed
    if (std.fs.path.dirname(file_path)) |parent_dir| {
        std.fs.cwd().makePath(parent_dir) catch {};
    }
    
    try platform_impl.fs.writeFile(file_path, blob_obj.data);
}

/// Create a conflict file with markers
fn createConflictFile(git_path: []const u8, filename: []const u8, base_hash: ?[]const u8, current_hash: []const u8, target_hash: []const u8, repo_root: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Load file contents
    const current_content = blk: {
        const blob_obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch break :blk "";
        defer blob_obj.deinit(allocator);
        if (blob_obj.type != .blob) break :blk "";
        break :blk try allocator.dupe(u8, blob_obj.data);
    };
    defer if (current_content.len > 0) allocator.free(current_content);
    
    const target_content = blk: {
        const blob_obj = objects.GitObject.load(target_hash, git_path, platform_impl, allocator) catch break :blk "";
        defer blob_obj.deinit(allocator);
        if (blob_obj.type != .blob) break :blk "";
        break :blk try allocator.dupe(u8, blob_obj.data);
    };
    defer if (target_content.len > 0) allocator.free(target_content);
    
    // Create conflict content with markers
    var conflict_content = std.array_list.Managed(u8).init(allocator);
    defer conflict_content.deinit();
    
    const writer = conflict_content.writer();
    try writer.print("{s}", .{"<<<<<<< HEAD\n"});
    try writer.writeAll(current_content);
    if (current_content.len > 0 and current_content[current_content.len - 1] != '\n') {
        try writer.writeByte('\n');
    }
    try writer.print("{s}", .{"=======\n"});
    try writer.writeAll(target_content);
    if (target_content.len > 0 and target_content[target_content.len - 1] != '\n') {
        try writer.writeByte('\n');
    }
    try writer.print("{s}", .{">>>>>>> incoming\n"});

    // Write conflict file
    const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, filename });
    defer allocator.free(file_path);
    
    // Create parent directories if needed
    if (std.fs.path.dirname(file_path)) |parent_dir| {
        std.fs.cwd().makePath(parent_dir) catch {};
    }
    
    try platform_impl.fs.writeFile(file_path, conflict_content.items);
    
    _ = base_hash; // TODO: Could use base content for better 3-way merge
}

/// Create a merge commit with two parents
fn buildMergeMessage(merge_target: []const u8, current_branch: []const u8, git_path: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    const is_tag = blk: {
        const tag_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{git_path, merge_target});
        defer allocator.free(tag_path);
        if (std.fs.cwd().access(tag_path, .{})) |_| break :blk true else |_| {}
        const packed_ref = try std.fmt.allocPrint(allocator, "refs/tags/{s}", .{merge_target});
        defer allocator.free(packed_ref);
        const packed_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_path});
        defer allocator.free(packed_path);
        if (std.fs.cwd().readFileAlloc(allocator, packed_path, 10 * 1024 * 1024)) |content| {
            defer allocator.free(content);
            if (std.mem.indexOf(u8, content, packed_ref) != null) break :blk true;
        } else |_| {}
        break :blk false;
    };
    const kind = if (is_tag) "tag" else "branch";
    const is_default = isDefaultBranch(current_branch, allocator, platform_impl);
    if (is_default) {
        return std.fmt.allocPrint(allocator, "Merge {s} '{s}'", .{kind, merge_target});
    } else {
        return std.fmt.allocPrint(allocator, "Merge {s} '{s}' into {s}", .{kind, merge_target, current_branch});
    }
}

fn isDefaultBranch(branch: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) bool {
    const short_name = if (std.mem.startsWith(u8, branch, "refs/heads/")) branch["refs/heads/".len..] else branch;
    if (std.process.getEnvVarOwned(allocator, "GIT_TEST_DEFAULT_INITIAL_BRANCH_NAME") catch null) |ev| {
        defer allocator.free(ev);
        if (ev.len > 0) return std.mem.eql(u8, short_name, ev);
    }
    if (readCfg(allocator, "init.defaultbranch", platform_impl)) |v| {
        defer allocator.free(v);
        return std.mem.eql(u8, short_name, v);
    }
    return std.mem.eql(u8, short_name, "master");
}

fn createMergeCommit(git_path: []const u8, current_hash: []const u8, target_hash: []const u8, current_branch: []const u8, target_branch: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    return createMergeCommitWithMsg(git_path, current_hash, target_hash, current_branch, target_branch, null, allocator, platform_impl);
}

fn createMergeCommitWithMsg(git_path: []const u8, current_hash: []const u8, target_hash: []const u8, current_branch: []const u8, target_branch: []const u8, custom_message: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    // Build tree from current working directory state (after merge)
    const repo_root = std.fs.path.dirname(git_path) orelse ".";

    // Re-add all tracked files to the index to capture merge results
    var idx = index_mod.Index.load(git_path, platform_impl, allocator) catch blk: {
        break :blk index_mod.Index.init(allocator);
    };
    defer idx.deinit();

    // Walk all files from old index and update them from the working tree
    {
        const target_tree_hash = getCommitTree(git_path, target_hash, allocator, platform_impl) catch null;
        defer if (target_tree_hash) |h| allocator.free(h);

        var all_paths = std.StringHashMap(void).init(allocator);
        defer {
            var it = all_paths.iterator();
            while (it.next()) |entry| allocator.free(entry.key_ptr.*);
            all_paths.deinit();
        }

        // Collect paths from existing index
        for (idx.entries.items) |entry| {
            if (!all_paths.contains(entry.path)) {
                try all_paths.put(try allocator.dupe(u8, entry.path), {});
            }
        }

        // Collect paths from target tree
        if (target_tree_hash) |tt| {
            var target_paths = std.StringHashMap(void).init(allocator);
            defer {
                var it2 = target_paths.iterator();
                while (it2.next()) |entry| allocator.free(entry.key_ptr.*);
                target_paths.deinit();
            }
            collectTreePaths(git_path, tt, "", &target_paths, allocator, platform_impl) catch {};
            var tp_it = target_paths.iterator();
            while (tp_it.next()) |entry| {
                if (!all_paths.contains(entry.key_ptr.*)) {
                    try all_paths.put(try allocator.dupe(u8, entry.key_ptr.*), {});
                }
            }
        }

        // Update index entries from working tree
        var path_it = all_paths.iterator();
        while (path_it.next()) |entry| {
            const path = entry.key_ptr.*;
            const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, path });
            defer allocator.free(full_path);

            if (std.fs.cwd().openFile(full_path, .{})) |file| {
                file.close();
                idx.add(path, path, platform_impl, git_path) catch {};
            } else |_| {
                idx.remove(path) catch {};
            }
        }
        idx.save(git_path, platform_impl) catch {};
    }

    const current_tree = try writeTreeFromIndex(allocator, &idx, git_path, platform_impl);
    defer allocator.free(current_tree);
    
    // Create commit message
    const commit_message = custom_message orelse try buildMergeMessage(target_branch, current_branch, git_path, allocator, platform_impl);
    defer if (custom_message == null) allocator.free(commit_message);
    
    // Create author/committer info
    const author_line = getAuthorString(allocator) catch blk: {
        const ts = std.time.timestamp();
        break :blk try std.fmt.allocPrint(allocator, "User <user@example.com> {d} +0000", .{ts});
    };
    defer allocator.free(author_line);
    const committer_line = getCommitterString(allocator) catch blk: {
        const ts = std.time.timestamp();
        break :blk try std.fmt.allocPrint(allocator, "User <user@example.com> {d} +0000", .{ts});
    };
    defer allocator.free(committer_line);
    
    // Create commit object with two parents
    const parents = [_][]const u8{current_hash, target_hash};
    const commit_obj = try objects.createCommitObject(current_tree, &parents, author_line, committer_line, commit_message, allocator);
    defer commit_obj.deinit(allocator);
    
    // Store commit object
    const commit_hash = try commit_obj.store(git_path, platform_impl, allocator);
    defer allocator.free(commit_hash);
    
    // Update current branch to point to merge commit
    try refs.updateRef(git_path, current_branch, commit_hash, platform_impl, allocator);
}

/// Simplified merge function for pull operations
fn mergeCommits(git_path: []const u8, current_hash: []const u8, target_hash: []const u8, repo_root: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !bool {
    _ = repo_root; // unused in this simplified implementation
    // Check if already up to date
    if (std.mem.eql(u8, current_hash, target_hash)) {
        return false; // No conflicts, already up to date
    }
    
    // For now, use a simple merge strategy similar to the existing merge code
    // Find merge base
    const merge_base = findMergeBase(git_path, current_hash, target_hash, allocator, platform_impl) catch current_hash;
    defer if (!std.mem.eql(u8, merge_base, current_hash)) allocator.free(merge_base);
    
    // Get trees for the three commits
    const base_tree = getCommitTree(git_path, merge_base, allocator, platform_impl) catch {
        return error.MergeConflict;
    };
    defer allocator.free(base_tree);
    
    const current_tree = getCommitTree(git_path, current_hash, allocator, platform_impl) catch {
        return error.MergeConflict; 
    };
    defer allocator.free(current_tree);
    
    const target_tree = getCommitTree(git_path, target_hash, allocator, platform_impl) catch {
        return error.MergeConflict;
    };
    defer allocator.free(target_tree);
    
    // Perform the merge
    return mergeTreesWithConflicts(git_path, base_tree, current_tree, target_tree, allocator, platform_impl) catch true;
}

fn cmdFetch(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("fetch: not supported in freestanding mode\n");
        return;
    }

    // Check if we're in a git repository
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Parse arguments for flags, remote, and refspecs
    var quiet = false;
    var fetch_tags: enum { auto, yes, no } = .auto;
    var remote_name: []const u8 = "origin";
    var cmd_refspecs = std.array_list.Managed([]const u8).init(allocator);
    defer cmd_refspecs.deinit();
    var got_remote = false;
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--all") or std.mem.eql(u8, arg, "--prune") or std.mem.eql(u8, arg, "--force") or std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--verbose") or std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--update-head-ok") or std.mem.eql(u8, arg, "--append") or std.mem.eql(u8, arg, "-a") or std.mem.eql(u8, arg, "--dry-run")) {
            if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) quiet = true;
        } else if (std.mem.eql(u8, arg, "--tags") or std.mem.eql(u8, arg, "-t")) {
            fetch_tags = .yes;
        } else if (std.mem.eql(u8, arg, "--no-tags") or std.mem.eql(u8, arg, "-n")) {
            fetch_tags = .no;
        } else if (std.mem.eql(u8, arg, "--depth") or std.mem.eql(u8, arg, "--deepen") or std.mem.eql(u8, arg, "-j") or std.mem.eql(u8, arg, "--jobs") or std.mem.eql(u8, arg, "--upload-pack") or std.mem.eql(u8, arg, "--refmap") or std.mem.eql(u8, arg, "-o") or std.mem.eql(u8, arg, "--server-option") or std.mem.eql(u8, arg, "--recurse-submodules") or std.mem.eql(u8, arg, "--filter") or std.mem.eql(u8, arg, "--negotiation-tip")) {
            _ = args.next();
        } else if (std.mem.startsWith(u8, arg, "-")) {
            // other flags
        } else if (!got_remote) { remote_name = arg; got_remote = true;
        } else { try cmd_refspecs.append(arg); }
    }
    // Resolve remote URL
    var remote_url_owned: ?[]u8 = null;
    defer if (remote_url_owned) |u| allocator.free(u);
    const remote_url: []const u8 = blk: {
        if (getRemoteUrl(git_path, remote_name, platform_impl, allocator)) |url| { remote_url_owned = url; break :blk url; } else |_| break :blk remote_name;
    };

    // For HTTPS URLs, use native Zig fetch
    if (std.mem.startsWith(u8, remote_url, "https://") or std.mem.startsWith(u8, remote_url, "http://")) {
        const ziggit = @import("ziggit.zig");
        // Determine the repo path: for bare repos git_path IS the repo, for normal repos it's the parent
        const is_bare_repo = !std.mem.endsWith(u8, git_path, "/.git");
        const repo_path = if (is_bare_repo) git_path else (std.fs.path.dirname(git_path) orelse ".");
        var repo = ziggit.Repository.open(allocator, repo_path) catch |err| {
            const msg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        defer repo.close();

        repo.fetch(remote_url) catch |err| {
            const msg = try std.fmt.allocPrint(allocator, "fatal: could not fetch from '{s}': {}\n", .{ remote_url, err });
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };

        if (!quiet) {
            // Mimic git's quiet fetch output (no output on success with --quiet is default git behavior,
            // but without --quiet we print nothing extra either since git fetch is normally quiet on success)
        }
        return;
    }

    // For non-HTTPS URLs, not yet supported natively
    // Try local fetch
    var is_local = false;
    var local_path = remote_url;
    if (std.mem.startsWith(u8, remote_url, "file://")) { is_local = true; local_path = remote_url["file://".len..]; }
    else if (std.mem.startsWith(u8, remote_url, "/") or std.mem.startsWith(u8, remote_url, "./") or std.mem.startsWith(u8, remote_url, "../") or std.mem.eql(u8, remote_url, ".") or std.mem.eql(u8, remote_url, "..")) { is_local = true; }
    else if (!std.mem.startsWith(u8, remote_url, "git://") and !std.mem.startsWith(u8, remote_url, "ssh://")) {
        if (resolveSourceGitDir(allocator, remote_url)) |sgd| { allocator.free(sgd); is_local = true; } else |_| {}
    }
    if (is_local) {
        // Determine effective tag behavior: check remote.<name>.tagopt config
        var effective_tags = fetch_tags;
        if (effective_tags == .auto) {
            const cfgp2 = std.fmt.allocPrint(allocator, "{s}/config", .{git_path}) catch "";
            defer if (cfgp2.len > 0) allocator.free(cfgp2);
            if (cfgp2.len > 0) {
                if (std.fs.cwd().readFileAlloc(allocator, cfgp2, 1024 * 1024)) |cfgc2| {
                    defer allocator.free(cfgc2);
                    const tagopt_key = std.fmt.allocPrint(allocator, "remote.{s}.tagopt", .{remote_name}) catch "";
                    defer if (tagopt_key.len > 0) allocator.free(tagopt_key);
                    if (tagopt_key.len > 0) {
                        if (parseConfigValue(cfgc2, tagopt_key, allocator) catch null) |tagopt_val| {
                            defer allocator.free(tagopt_val);
                            if (std.mem.eql(u8, tagopt_val, "--no-tags")) effective_tags = .no
                            else if (std.mem.eql(u8, tagopt_val, "--tags")) effective_tags = .yes;
                        }
                    }
                } else |_| {}
            }
        }
        try performLocalFetch(allocator, git_path, local_path, remote_name, quiet, cmd_refspecs.items, platform_impl, effective_tags != .no);
        return;
    }

    try platform_impl.writeStderr("fatal: non-HTTPS/non-local fetch not supported natively yet\n");
    std.process.exit(128);
}

fn cmdPull(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("pull: not supported in freestanding mode\n");
        return;
    }

    // Check if we're in a git repository
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    var pull_flags = std.array_list.Managed([]const u8).init(allocator);
    defer pull_flags.deinit();
    var pull_positionals = std.array_list.Managed([]const u8).init(allocator);
    defer pull_positionals.deinit();
    var no_rebase = false;
    var do_rebase = false;
    var pull_strategy: ?[]const u8 = null;
    
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--no-rebase")) {
            no_rebase = true;
        } else if (std.mem.eql(u8, arg, "--rebase")) {
            do_rebase = true;
        } else if (std.mem.eql(u8, arg, "-s")) {
            pull_strategy = args.next();
        } else if (std.mem.startsWith(u8, arg, "--strategy=")) {
            pull_strategy = arg["--strategy=".len..];
        } else if (std.mem.eql(u8, arg, "--log") or std.mem.startsWith(u8, arg, "--log=") or 
                   std.mem.eql(u8, arg, "--no-log") or std.mem.eql(u8, arg, "--ff-only") or
                   std.mem.eql(u8, arg, "--no-ff") or std.mem.eql(u8, arg, "--ff") or
                   std.mem.eql(u8, arg, "--squash") or std.mem.eql(u8, arg, "--no-squash") or
                   std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet") or
                   std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            try pull_flags.append(arg);
        } else if (std.mem.startsWith(u8, arg, "-")) {
            try pull_flags.append(arg);
        } else {
            try pull_positionals.append(arg);
        }
    }
    
    const remote = if (pull_positionals.items.len > 0) pull_positionals.items[0] else "origin";
    const branch = if (pull_positionals.items.len > 1)
        pull_positionals.items[1]
    else
        refs.getCurrentBranch(git_path, platform_impl, allocator) catch try allocator.dupe(u8, "master");
    defer if (pull_positionals.items.len <= 1) allocator.free(branch);
    
    // Resolve remote URL: if remote looks like a path, use directly
    var remote_url: []const u8 = undefined;
    var remote_url_owned = false;
    var remote_is_path = false;
    
    if (std.mem.startsWith(u8, remote, "/") or std.mem.startsWith(u8, remote, "./") or std.mem.startsWith(u8, remote, "../") or std.mem.eql(u8, remote, ".") or std.mem.eql(u8, remote, "..") or std.mem.startsWith(u8, remote, "file://")) {
        remote_url = remote;
        remote_is_path = true;
    } else if (resolveSourceGitDir(allocator, remote)) |sgd| {
        allocator.free(sgd);
        remote_url = remote;
        remote_is_path = true;
    } else |_| {
        remote_url = getRemoteUrl(git_path, remote, platform_impl, allocator) catch |err| switch (err) {
            error.RemoteNotFound => {
                const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' does not appear to be a git repository\n", .{remote});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            },
            else => return err,
        };
        remote_url_owned = true;
    }
    defer if (remote_url_owned) allocator.free(remote_url);
    
    // Try local fetch first
    var pull_is_local = false;
    if (std.mem.startsWith(u8, remote_url, "file://") or std.mem.startsWith(u8, remote_url, "/") or std.mem.startsWith(u8, remote_url, "./") or std.mem.startsWith(u8, remote_url, "../") or std.mem.eql(u8, remote_url, ".") or std.mem.eql(u8, remote_url, "..")) {
        pull_is_local = true;
    } else if (!std.mem.startsWith(u8, remote_url, "http://") and !std.mem.startsWith(u8, remote_url, "https://")) {
        if (resolveSourceGitDir(allocator, remote_url)) |sgd| { allocator.free(sgd); pull_is_local = true; } else |_| {}
    }
    if (pull_is_local) {
        const lp = if (std.mem.startsWith(u8, remote_url, "file://")) remote_url["file://".len..] else remote_url;
        const empty_refspecs: []const []const u8 = &.{};
        performLocalFetch(allocator, git_path, lp, remote, false, empty_refspecs, platform_impl, true) catch |err| {
            const emsg = try std.fmt.allocPrint(allocator, "fatal: fetch failed: {}\n", .{err});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
        };
    } else {
        network.fetchRepository(allocator, remote_url, git_path, platform_impl) catch |err| switch (err) {
            error.RepositoryNotFound => {
                try platform_impl.writeStderr("fatal: repository not found\n");
                std.process.exit(128);
            },
            error.InvalidUrl => {
                try platform_impl.writeStderr("fatal: invalid remote URL\n");
                std.process.exit(128);
            },
            error.HttpError => {
                try platform_impl.writeStderr("fatal: unable to access remote repository\n");
                std.process.exit(128);
            },
            else => return err,
        };
    }
    
    // Now try to merge the remote branch
    // For path-based remotes, use FETCH_HEAD; for named remotes, use tracking ref
    var remote_commit: []const u8 = undefined;
    var remote_commit_owned = false;
    
    if (remote_is_path) {
        // For path-based remotes, resolve the branch from the source repo directly
        const lp = if (std.mem.startsWith(u8, remote_url, "file://")) remote_url["file://".len..] else remote_url;
        const source_git_dir = resolveSourceGitDir(allocator, lp) catch null;
        defer if (source_git_dir) |sgd| allocator.free(sgd);
        const sgd = source_git_dir orelse git_path;
        
        // Try to resolve the branch from the source repo
        var resolved_from_source = false;
        if (refs.getBranchCommit(sgd, branch, platform_impl, allocator) catch null) |hash| {
            remote_commit = hash;
            remote_commit_owned = true;
            resolved_from_source = true;
        }
        if (!resolved_from_source) {
            // Fallback: read FETCH_HEAD
            const fetch_head_path = try std.fmt.allocPrint(allocator, "{s}/FETCH_HEAD", .{git_path});
            defer allocator.free(fetch_head_path);
            if (std.fs.cwd().readFileAlloc(allocator, fetch_head_path, 4096)) |fh_content| {
                defer allocator.free(fh_content);
                const first_line = if (std.mem.indexOf(u8, fh_content, "\n")) |nl| fh_content[0..nl] else fh_content;
                if (first_line.len >= 40) {
                    remote_commit = try allocator.dupe(u8, first_line[0..40]);
                    remote_commit_owned = true;
                } else {
                    try platform_impl.writeStderr("fatal: couldn't find remote ref\n");
                    std.process.exit(1);
                }
            } else |_| {
                try platform_impl.writeStderr("fatal: couldn't find remote ref\n");
                std.process.exit(1);
            }
        }
    } else {
        const remote_branch = try std.fmt.allocPrint(allocator, "remotes/{s}/{s}", .{remote, branch});
        defer allocator.free(remote_branch);
        if (refs.getRef(git_path, remote_branch, platform_impl, allocator)) |ref_val| {
            remote_commit = try allocator.dupe(u8, ref_val);
            remote_commit_owned = true;
            allocator.free(ref_val);
        } else |_| {
            // Try FETCH_HEAD as fallback
            const fetch_head_path = try std.fmt.allocPrint(allocator, "{s}/FETCH_HEAD", .{git_path});
            defer allocator.free(fetch_head_path);
            if (std.fs.cwd().readFileAlloc(allocator, fetch_head_path, 4096)) |fh_content| {
                defer allocator.free(fh_content);
                const first_line = if (std.mem.indexOf(u8, fh_content, "\n")) |nl| fh_content[0..nl] else fh_content;
                if (first_line.len >= 40) {
                    remote_commit = try allocator.dupe(u8, first_line[0..40]);
                    remote_commit_owned = true;
                } else {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: couldn't find remote ref {s}\n", .{branch});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                }
            } else |_| {
                const msg = try std.fmt.allocPrint(allocator, "fatal: couldn't find remote ref {s}\n", .{branch});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            }
        }
    }
    defer if (remote_commit_owned) allocator.free(remote_commit);
    
    // Get current commit
    const current_commit_opt = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: no current branch\n");
        std.process.exit(128);
    };
    
    if (current_commit_opt == null) {
        try platform_impl.writeStderr("fatal: no current commit\n");
        std.process.exit(128);
    }
    
    const current_commit = current_commit_opt.?;
    defer allocator.free(current_commit);
    
    // Check if we need to merge (if commits are different)
    if (std.mem.eql(u8, current_commit, remote_commit)) {
        try platform_impl.writeStdout("Already up to date.\n");
    } else if (pull_strategy != null and std.mem.eql(u8, pull_strategy.?, "ours")) {
        // "ours" strategy: keep our tree, just create merge commit
        const current_obj = objects.GitObject.load(current_commit, git_path, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: unable to read current commit\n");
            std.process.exit(1);
        };
        defer current_obj.deinit(allocator);
        const our_tree = extractHeaderField(current_obj.data, "tree");
        if (our_tree.len == 0) {
            try platform_impl.writeStderr("fatal: unable to find tree\n");
            std.process.exit(1);
        }
        const current_branch = try refs.getCurrentBranch(git_path, platform_impl, allocator);
        defer allocator.free(current_branch);
        const merge_msg = try buildMergeMessage(branch, current_branch, git_path, allocator, platform_impl);
        defer allocator.free(merge_msg);
        const author_str = getAuthorString(allocator) catch try allocator.dupe(u8, "Unknown <unknown@unknown>");
        defer allocator.free(author_str);
        const committer_str = getCommitterString(allocator) catch try allocator.dupe(u8, "Unknown <unknown@unknown>");
        defer allocator.free(committer_str);
        const parents = [_][]const u8{ current_commit, remote_commit };
        const commit_obj = try objects.createCommitObject(our_tree, &parents, author_str, committer_str, merge_msg, allocator);
        defer commit_obj.deinit(allocator);
        const new_hash = try commit_obj.store(git_path, platform_impl, allocator);
        defer allocator.free(new_hash);
        try refs.updateRef(git_path, current_branch, new_hash, platform_impl, allocator);
        try platform_impl.writeStdout("Merge made by the 'ours' strategy.\n");
    } else {
        // Perform merge
        try platform_impl.writeStdout("Merging changes...\n");
        
        const repo_root = std.fs.path.dirname(git_path) orelse git_path;
        const current_branch = try refs.getCurrentBranch(git_path, platform_impl, allocator);
        defer allocator.free(current_branch);
        
        const conflicts = mergeCommits(git_path, current_commit, remote_commit, repo_root, platform_impl, allocator) catch |err| switch (err) {
            error.MergeConflict => true,
            else => return err,
        };
        
        if (conflicts) {
            try platform_impl.writeStderr("Automatic merge failed; fix conflicts and then commit the result.\n");
            std.process.exit(1);
        } else {
            // Create merge commit
            createMergeCommit(git_path, current_commit, remote_commit, current_branch, branch, allocator, platform_impl) catch |err| switch (err) {
                else => return err,
            };
            try platform_impl.writeStdout("Merge completed successfully.\n");
        }
    }
}

/// Resolve a path to its .git directory. Handles bare repos, .git files (worktrees/submodules),
/// and file:// URLs. Returns the path to the git directory (objects, refs, etc.).
fn urlDecodePath(allocator: std.mem.Allocator, input: []const u8) ![]u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    errdefer result.deinit();
    var i: usize = 0;
    while (i < input.len) {
        if (input[i] == '%' and i + 2 < input.len) {
            const high = std.fmt.charToDigit(input[i + 1], 16) catch {
                try result.append(input[i]);
                i += 1;
                continue;
            };
            const low = std.fmt.charToDigit(input[i + 2], 16) catch {
                try result.append(input[i]);
                i += 1;
                continue;
            };
            try result.append(@as(u8, high) * 16 + low);
            i += 3;
        } else {
            try result.append(input[i]);
            i += 1;
        }
    }
    return try result.toOwnedSlice();
}

fn resolveSourceGitDir(allocator: std.mem.Allocator, source_path: []const u8) ![]const u8 {
    // Strip file:// prefix if present and URL-decode
    const path = if (std.mem.startsWith(u8, source_path, "file://")) blk: {
        const decoded = urlDecodePath(allocator, source_path["file://".len..]) catch
            return error.RepositoryNotFound;
        break :blk decoded;
    } else
        try allocator.dupe(u8, source_path);
    defer allocator.free(path);

    // Resolve to absolute path (try original, then with .git suffix)
    const abs_path = std.fs.cwd().realpathAlloc(allocator, path) catch blk: {
        // Try with /.git suffix (for worktree paths like ".")
        const with_slash_git = try std.fmt.allocPrint(allocator, "{s}/.git", .{path});
        defer allocator.free(with_slash_git);
        break :blk std.fs.cwd().realpathAlloc(allocator, with_slash_git) catch blk2: {
            const with_git_sfx = std.fmt.allocPrint(allocator, "{s}.git", .{path}) catch return error.RepositoryNotFound;
            defer allocator.free(with_git_sfx);
            break :blk2 std.fs.cwd().realpathAlloc(allocator, with_git_sfx) catch {
                return error.RepositoryNotFound;
            };
        };
    };
    errdefer allocator.free(abs_path);

    // Check if it's a bare repo (has objects/ and refs/ directly)
    const objects_path = try std.fmt.allocPrint(allocator, "{s}/objects", .{abs_path});
    defer allocator.free(objects_path);
    const refs_path = try std.fmt.allocPrint(allocator, "{s}/refs", .{abs_path});
    defer allocator.free(refs_path);

    // Check for .git subdirectory FIRST (prefer worktree .git over bare repo contents)
    const git_subdir = try std.fmt.allocPrint(allocator, "{s}/.git", .{abs_path});
    defer allocator.free(git_subdir);

    const git_objects = try std.fmt.allocPrint(allocator, "{s}/.git/objects", .{abs_path});
    defer allocator.free(git_objects);
    const git_objs_exist = if (std.fs.cwd().access(git_objects, .{})) |_| true else |_| false;
    // Debug
    {
        if (std.fs.cwd().createFile("/tmp/zdbg.log", .{})) |df| {
            defer df.close();
            const msg2 = std.fmt.allocPrint(allocator, "src={s} abs={s} gitobj={s} exist={}\n", .{source_path, abs_path, git_objects, git_objs_exist}) catch "";
            if (msg2.len > 0) { df.writeAll(msg2) catch {}; allocator.free(msg2); }
        } else |_| {}
    }
    if (git_objs_exist) {
        const result = try std.fmt.allocPrint(allocator, "{s}/.git", .{abs_path});
        allocator.free(abs_path);
        return result;
    }

    // Check if it's a bare repo (has objects/ and refs/ directly)
    const has_objects = if (std.fs.cwd().access(objects_path, .{})) |_| true else |_| false;
    const has_refs = if (std.fs.cwd().access(refs_path, .{})) |_| true else |_| false;

    if (has_objects and has_refs) {
        // This is a bare repo or .git directory
        return abs_path;
    }
    
    // .git could be a file (gitlink)
    if (std.fs.cwd().openFile(git_subdir, .{})) |file| {
        defer file.close();
        // Check it's a regular file (not a directory)
        const stat = file.stat() catch {
            // Can't stat, try reading
            var buf: [4096]u8 = undefined;
            const n = file.readAll(&buf) catch return error.RepositoryNotFound;
            const content = std.mem.trim(u8, buf[0..n], " \t\r\n");
            if (std.mem.startsWith(u8, content, "gitdir: ")) {
                const gitdir_ref = content["gitdir: ".len..];
                if (std.fs.path.isAbsolute(gitdir_ref)) {
                    allocator.free(abs_path);
                    return try allocator.dupe(u8, gitdir_ref);
                } else {
                    const resolved = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ abs_path, gitdir_ref });
                    allocator.free(abs_path);
                    return resolved;
                }
            }
            return error.RepositoryNotFound;
        };
        if (stat.kind != .directory) {
            // It's a gitlink file
            var buf: [4096]u8 = undefined;
            const n = file.readAll(&buf) catch return error.RepositoryNotFound;
            const content = std.mem.trim(u8, buf[0..n], " \t\r\n");
            if (std.mem.startsWith(u8, content, "gitdir: ")) {
                const gitdir_ref = content["gitdir: ".len..];
                if (std.fs.path.isAbsolute(gitdir_ref)) {
                    allocator.free(abs_path);
                    return try allocator.dupe(u8, gitdir_ref);
                } else {
                    const resolved = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ abs_path, gitdir_ref });
                    allocator.free(abs_path);
                    return resolved;
                }
            }
        }
    } else |_| {}

    allocator.free(abs_path);

    // Try adding .git suffix
    const with_git = try std.fmt.allocPrint(allocator, "{s}.git", .{path});
    defer allocator.free(with_git);

    const abs_with_git = std.fs.cwd().realpathAlloc(allocator, with_git) catch {
        return error.RepositoryNotFound;
    };
    errdefer allocator.free(abs_with_git);

    // Check if it's a bare repo
    const obj2 = try std.fmt.allocPrint(allocator, "{s}/objects", .{abs_with_git});
    defer allocator.free(obj2);
    const ref2 = try std.fmt.allocPrint(allocator, "{s}/refs", .{abs_with_git});
    defer allocator.free(ref2);
    const has_obj2 = if (std.fs.cwd().access(obj2, .{})) |_| true else |_| false;
    const has_ref2 = if (std.fs.cwd().access(ref2, .{})) |_| true else |_| false;
    if (has_obj2 and has_ref2) return abs_with_git;

    // Check for .git subdir of .git-suffixed path
    const git_obj2 = try std.fmt.allocPrint(allocator, "{s}/.git/objects", .{abs_with_git});
    defer allocator.free(git_obj2);
    if (std.fs.cwd().access(git_obj2, .{})) |_| {
        const result = try std.fmt.allocPrint(allocator, "{s}/.git", .{abs_with_git});
        allocator.free(abs_with_git);
        return result;
    } else |_| {}

    allocator.free(abs_with_git);
    return error.RepositoryNotFound;
}

/// Copy a directory recursively from src to dst
fn copyDirectoryRecursive(allocator: std.mem.Allocator, src_path: []const u8, dst_path: []const u8) !void {
    std.fs.cwd().makePath(dst_path) catch {};

    var src_dir = std.fs.cwd().openDir(src_path, .{ .iterate = true }) catch return;
    defer src_dir.close();

    var iter = src_dir.iterate();
    while (try iter.next()) |entry| {
        const src_child = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ src_path, entry.name });
        defer allocator.free(src_child);
        const dst_child = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dst_path, entry.name });
        defer allocator.free(dst_child);

        switch (entry.kind) {
            .directory => {
                try copyDirectoryRecursive(allocator, src_child, dst_child);
            },
            .file => {
                std.fs.cwd().copyFile(src_child, std.fs.cwd(), dst_child, .{}) catch {};
            },
            .sym_link => {
                // Read and recreate symlink
                var link_buf: [std.fs.max_path_bytes]u8 = undefined;
                const link_target = std.fs.cwd().readLink(src_child, &link_buf) catch continue;
                // Delete existing file/link at destination if any
                std.fs.cwd().deleteFile(dst_child) catch {};
                const dst_dir = std.fs.cwd().openDir(dst_path, .{}) catch continue;
                // Use the directory-relative createSymLink
                var dst_dir_m = dst_dir;
                dst_dir_m.symLink(link_target, entry.name, .{}) catch {};
            },
            else => {},
        }
    }
}

/// Perform a local clone (copy objects and refs from source git dir to destination)
fn performLocalClone(
    allocator: std.mem.Allocator,
    source_url: []const u8,
    target_dir: []const u8,
    is_bare: bool,
    is_no_checkout: bool,
    branch: ?[]const u8,
    origin_name: ?[]const u8,
    platform_impl: *const platform_mod.Platform,
    is_shared: bool,
    is_mirror: bool,
) !void {
    // Resolve source git directory
    const src_git_dir = try resolveSourceGitDir(allocator, source_url);
    defer allocator.free(src_git_dir);

    const remote_name = origin_name orelse "origin";

    // Determine the target .git directory
    const dst_git_dir = if (is_bare)
        try allocator.dupe(u8, target_dir)
    else
        try std.fmt.allocPrint(allocator, "{s}/.git", .{target_dir});
    defer allocator.free(dst_git_dir);

    // Create destination directory structure
    std.fs.cwd().makePath(dst_git_dir) catch |err| {
        const msg = try std.fmt.allocPrint(allocator, "fatal: cannot mkdir {s}: {}\n", .{ dst_git_dir, err });
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    };

    // Create standard git directory structure
    const dirs_to_create = [_][]const u8{
        "objects", "objects/info", "objects/pack", "refs", "refs/heads", "refs/tags", "info", "hooks",
    };
    for (dirs_to_create) |subdir| {
        const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dst_git_dir, subdir });
        defer allocator.free(full_path);
        std.fs.cwd().makePath(full_path) catch {};
    }

    // Copy or share objects (loose objects + pack files)
    const src_objects = try std.fmt.allocPrint(allocator, "{s}/objects", .{src_git_dir});
    defer allocator.free(src_objects);
    const dst_objects = try std.fmt.allocPrint(allocator, "{s}/objects", .{dst_git_dir});
    defer allocator.free(dst_objects);

    if (is_shared) {
        // Create alternates file pointing to source objects
        const alt_dir = try std.fmt.allocPrint(allocator, "{s}/objects/info", .{dst_git_dir});
        defer allocator.free(alt_dir);
        std.fs.cwd().makePath(alt_dir) catch {};
        const alt_path = try std.fmt.allocPrint(allocator, "{s}/objects/info/alternates", .{dst_git_dir});
        defer allocator.free(alt_path);
        const abs_src_objects = std.fs.cwd().realpathAlloc(allocator, src_objects) catch try allocator.dupe(u8, src_objects);
        defer allocator.free(abs_src_objects);
        {
            const f = try std.fs.cwd().createFile(alt_path, .{});
            defer f.close();
            try f.writeAll(abs_src_objects);
            try f.writeAll("\n");
        }
    } else {
        try copyDirectoryRecursive(allocator, src_objects, dst_objects);
    }

    // Copy packed-refs if it exists
    const src_packed_refs = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{src_git_dir});
    defer allocator.free(src_packed_refs);

    // Read source HEAD to determine default branch
    const src_head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{src_git_dir});
    defer allocator.free(src_head_path);
    const src_head_content = std.fs.cwd().readFileAlloc(allocator, src_head_path, 4096) catch "ref: refs/heads/master\n";
    defer if (src_head_content.ptr != @as([*]const u8, "ref: refs/heads/master\n")) allocator.free(src_head_content);

    const src_head_trimmed = std.mem.trim(u8, src_head_content, " \t\r\n");

    // Determine the default branch from source HEAD
    var default_branch: []const u8 = "master";
    if (std.mem.startsWith(u8, src_head_trimmed, "ref: refs/heads/")) {
        default_branch = src_head_trimmed["ref: refs/heads/".len..];
    }

    // If --branch was specified, use that
    const checkout_branch = branch orelse default_branch;

    if (is_bare) {
        // For bare repos, copy all refs directly and set HEAD
        const src_refs = try std.fmt.allocPrint(allocator, "{s}/refs", .{src_git_dir});
        defer allocator.free(src_refs);
        const dst_refs = try std.fmt.allocPrint(allocator, "{s}/refs", .{dst_git_dir});
        defer allocator.free(dst_refs);
        try copyDirectoryRecursive(allocator, src_refs, dst_refs);

        // Copy packed-refs
        const dst_packed_refs = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{dst_git_dir});
        defer allocator.free(dst_packed_refs);
        std.fs.cwd().copyFile(src_packed_refs, std.fs.cwd(), dst_packed_refs, .{}) catch {};

        // Set HEAD
        const dst_head = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{dst_git_dir});
        defer allocator.free(dst_head);
        {
            const f = try std.fs.cwd().createFile(dst_head, .{});
            defer f.close();
            const head_ref = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{checkout_branch});
            defer allocator.free(head_ref);
            try f.writeAll(head_ref);
        }

        // Write config
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{dst_git_dir});
        defer allocator.free(config_path);
        {
            const f = try std.fs.cwd().createFile(config_path, .{});
            defer f.close();
            // Resolve the source URL to an absolute path for the remote
            const abs_source = std.fs.cwd().realpathAlloc(allocator, if (std.mem.startsWith(u8, source_url, "file://")) source_url["file://".len..] else source_url) catch try allocator.dupe(u8, source_url);
            defer allocator.free(abs_source);
            const cfg = if (is_mirror)
                try std.fmt.allocPrint(allocator, "[core]\n\trepositoryformatversion = 0\n\tfilemode = true\n\tbare = true\n[remote \"{s}\"]\n\turl = {s}\n\tfetch = +refs/*:refs/*\n\tmirror = true\n", .{ remote_name, abs_source })
            else
                try std.fmt.allocPrint(allocator, "[core]\n\trepositoryformatversion = 0\n\tfilemode = true\n\tbare = true\n[remote \"{s}\"]\n\turl = {s}\n\tfetch = +refs/heads/*:refs/heads/*\n", .{ remote_name, abs_source });
            defer allocator.free(cfg);
            try f.writeAll(cfg);
        }

        // Write description
        const desc_path = try std.fmt.allocPrint(allocator, "{s}/description", .{dst_git_dir});
        defer allocator.free(desc_path);
        {
            const f = std.fs.cwd().createFile(desc_path, .{}) catch return;
            defer f.close();
            f.writeAll("Unnamed repository; edit this file 'description' to name the repository.\n") catch {};
        }

    } else {
        // Non-bare clone: source refs become remote tracking refs
        // Map source refs/heads/* to refs/remotes/<origin>/*
        const remote_refs_dir = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}", .{ dst_git_dir, remote_name });
        defer allocator.free(remote_refs_dir);
        std.fs.cwd().makePath(remote_refs_dir) catch {};

        // Copy source heads to remote tracking
        const src_heads = try std.fmt.allocPrint(allocator, "{s}/refs/heads", .{src_git_dir});
        defer allocator.free(src_heads);

        // Read all source branch refs (loose)
        var branch_map = std.StringHashMap([]const u8).init(allocator);
        defer {
            var it = branch_map.iterator();
            while (it.next()) |entry| {
                allocator.free(entry.key_ptr.*);
                allocator.free(entry.value_ptr.*);
            }
            branch_map.deinit();
        }

        if (std.fs.cwd().openDir(src_heads, .{ .iterate = true })) |*dir_handle| {
            var d = dir_handle.*;
            defer d.close();
            var iter = d.iterate();
            while (try iter.next()) |entry| {
                if (entry.kind == .file) {
                    const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ src_heads, entry.name });
                    defer allocator.free(ref_path);
                    const hash = std.fs.cwd().readFileAlloc(allocator, ref_path, 256) catch continue;
                    const hash_trimmed = std.mem.trim(u8, hash, " \t\r\n");
                    const ht = try allocator.dupe(u8, hash_trimmed);
                    allocator.free(hash);
                    try branch_map.put(try allocator.dupe(u8, entry.name), ht);
                }
            }
        } else |_| {}

        // Also read packed-refs from source
        if (std.fs.cwd().readFileAlloc(allocator, src_packed_refs, 10 * 1024 * 1024)) |packed_content| {
            defer allocator.free(packed_content);
            var lines = std.mem.splitScalar(u8, packed_content, '\n');
            while (lines.next()) |line| {
                if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
                // Format: <hash> <refname>
                if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                    const hash = line[0..space_idx];
                    const refname = line[space_idx + 1..];
                    if (std.mem.startsWith(u8, refname, "refs/heads/")) {
                        const bname = refname["refs/heads/".len..];
                        if (!branch_map.contains(bname)) {
                            try branch_map.put(
                                try allocator.dupe(u8, bname),
                                try allocator.dupe(u8, hash),
                            );
                        }
                    }
                }
            }
        } else |_| {}

        // Write remote tracking refs
        var branch_iter = branch_map.iterator();
        while (branch_iter.next()) |entry| {
            const dst_ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ remote_refs_dir, entry.key_ptr.* });
            defer allocator.free(dst_ref_path);
            const f = std.fs.cwd().createFile(dst_ref_path, .{}) catch continue;
            defer f.close();
            f.writeAll(entry.value_ptr.*) catch continue;
            f.writeAll("\n") catch continue;
        }

        // Copy tags
        const src_tags = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{src_git_dir});
        defer allocator.free(src_tags);
        const dst_tags = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{dst_git_dir});
        defer allocator.free(dst_tags);
        copyDirectoryRecursive(allocator, src_tags, dst_tags) catch {};

        // Also copy packed-refs but rewrite heads to remotes
        if (std.fs.cwd().readFileAlloc(allocator, src_packed_refs, 10 * 1024 * 1024)) |packed_content| {
            defer allocator.free(packed_content);
            var new_packed = std.array_list.Managed(u8).init(allocator);
            defer new_packed.deinit();
            var lines = std.mem.splitScalar(u8, packed_content, '\n');
            while (lines.next()) |line| {
                if (line.len == 0) continue;
                if (line[0] == '#') {
                    try new_packed.appendSlice(line);
                    try new_packed.append('\n');
                    continue;
                }
                if (std.mem.indexOf(u8, line, "refs/heads/")) |_| {
                    // Rewrite refs/heads/X to refs/remotes/<origin>/X
                    if (std.mem.indexOfScalar(u8, line, ' ')) |sp| {
                        try new_packed.appendSlice(line[0 .. sp + 1]);
                        const refname = line[sp + 1..];
                        if (std.mem.startsWith(u8, refname, "refs/heads/")) {
                            const bname = refname["refs/heads/".len..];
                            const new_ref = try std.fmt.allocPrint(allocator, "refs/remotes/{s}/{s}", .{ remote_name, bname });
                            defer allocator.free(new_ref);
                            try new_packed.appendSlice(new_ref);
                        } else {
                            try new_packed.appendSlice(refname);
                        }
                        try new_packed.append('\n');
                    }
                } else if (std.mem.indexOf(u8, line, "refs/tags/")) |_| {
                    try new_packed.appendSlice(line);
                    try new_packed.append('\n');
                } else if (line[0] == '^') {
                    // Peeled tag ref - keep it
                    try new_packed.appendSlice(line);
                    try new_packed.append('\n');
                }
            }
            if (new_packed.items.len > 0) {
                const dst_packed = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{dst_git_dir});
                defer allocator.free(dst_packed);
                const f = std.fs.cwd().createFile(dst_packed, .{}) catch unreachable;
                defer f.close();
                f.writeAll(new_packed.items) catch {};
            }
        } else |_| {}

        // Create refs/remotes/origin/HEAD symbolic ref pointing to default branch
        {
            const remote_head_path = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}/HEAD", .{ dst_git_dir, remote_name });
            defer allocator.free(remote_head_path);
            const remote_head_content = try std.fmt.allocPrint(allocator, "ref: refs/remotes/{s}/{s}\n", .{ remote_name, default_branch });
            defer allocator.free(remote_head_content);
            const rhf = std.fs.cwd().createFile(remote_head_path, .{}) catch null;
            if (rhf) |f| {
                defer f.close();
                f.writeAll(remote_head_content) catch {};
            }
        }

        // Validate -b branch exists if specified
        if (branch != null) {
            if (branch_map.get(checkout_branch) == null) {
                if (branch_map.count() == 0) {
                    // Empty repo
                    const msg = try std.fmt.allocPrint(allocator, "fatal: you do not appear to have cloned an empty repository.\nwarning: You appear to have cloned an empty repository.\n", .{});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    // Clean up the created directory
                    std.fs.cwd().deleteTree(target_dir) catch {};
                    std.process.exit(128);
                } else {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: Remote branch {s} not found in upstream origin\n", .{checkout_branch});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    // Clean up the created directory
                    std.fs.cwd().deleteTree(target_dir) catch {};
                    std.process.exit(128);
                }
            }
        }

        // Create local branch from the checkout branch
        const branch_hash = branch_map.get(checkout_branch) orelse blk: {
            // Try default_branch if checkout_branch not found
            if (branch_map.get(default_branch)) |h| break :blk h;
            // Use first available branch
            var first_iter = branch_map.iterator();
            if (first_iter.next()) |entry| break :blk entry.value_ptr.*;
            break :blk null;
        };

        if (branch_hash) |hash| {
            // Create local branch ref
            const local_ref = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ dst_git_dir, checkout_branch });
            defer allocator.free(local_ref);
            {
                const f = try std.fs.cwd().createFile(local_ref, .{});
                defer f.close();
                try f.writeAll(hash);
                try f.writeAll("\n");
            }

            // Set HEAD to point to the branch
            const dst_head = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{dst_git_dir});
            defer allocator.free(dst_head);
            {
                const f = try std.fs.cwd().createFile(dst_head, .{});
                defer f.close();
                const head_content = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{checkout_branch});
                defer allocator.free(head_content);
                try f.writeAll(head_content);
            }
        } else {
            // Empty repository or no branches
            const dst_head = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{dst_git_dir});
            defer allocator.free(dst_head);
            {
                const f = try std.fs.cwd().createFile(dst_head, .{});
                defer f.close();
                try f.writeAll("ref: refs/heads/master\n");
            }
            try platform_impl.writeStderr("warning: You appear to have cloned an empty repository.\n");
        }

        // Write config
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{dst_git_dir});
        defer allocator.free(config_path);
        {
            const f = try std.fs.cwd().createFile(config_path, .{});
            defer f.close();
            const abs_source = std.fs.cwd().realpathAlloc(allocator, if (std.mem.startsWith(u8, source_url, "file://")) source_url["file://".len..] else source_url) catch try allocator.dupe(u8, source_url);
            defer allocator.free(abs_source);
            const cfg = try std.fmt.allocPrint(allocator, "[core]\n\trepositoryformatversion = 0\n\tfilemode = true\n\tbare = false\n\tlogallrefupdates = true\n[remote \"{s}\"]\n\turl = {s}\n\tfetch = +refs/heads/*:refs/remotes/{s}/*\n[branch \"{s}\"]\n\tremote = {s}\n\tmerge = refs/heads/{s}\n", .{ remote_name, abs_source, remote_name, checkout_branch, remote_name, checkout_branch });
            defer allocator.free(cfg);
            try f.writeAll(cfg);
        }

        // Write description
        const desc_path = try std.fmt.allocPrint(allocator, "{s}/description", .{dst_git_dir});
        defer allocator.free(desc_path);
        {
            const f = std.fs.cwd().createFile(desc_path, .{}) catch return;
            defer f.close();
            f.writeAll("Unnamed repository; edit this file 'description' to name the repository.\n") catch {};
        }

        // Checkout working tree (unless --no-checkout)
        if (!is_no_checkout and branch_hash != null) {
            checkoutCommitTree(dst_git_dir, branch_hash.?, allocator, platform_impl) catch |err| {
                const emsg = try std.fmt.allocPrint(allocator, "warning: checkout failed: {}, repository cloned but working tree not populated\n", .{err});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
            };
        }
    }
}

fn cmdClone(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform, _: [][]const u8) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("clone: not supported in freestanding mode\n");
        return;
    }

    // Collect all arguments first
    var all_args = std.array_list.Managed([]const u8).init(allocator);
    defer all_args.deinit();
    
    while (args.next()) |arg| {
        try all_args.append(arg);
    }

    // Check flags
    var is_bare = false;
    var is_no_checkout = false;
    var is_shared = false;
    var is_mirror = false;
    var clone_depth: u32 = 0;
    {
        var i: usize = 0;
        while (i < all_args.items.len) : (i += 1) {
            const arg = all_args.items[i];
            if (std.mem.eql(u8, arg, "--bare")) is_bare = true;
            if (std.mem.eql(u8, arg, "--mirror")) { is_mirror = true; is_bare = true; }
            if (std.mem.eql(u8, arg, "--no-checkout") or std.mem.eql(u8, arg, "-n")) is_no_checkout = true;
            if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--shared")) is_shared = true;
            if (std.mem.eql(u8, arg, "--depth")) {
                if (i + 1 < all_args.items.len) {
                    clone_depth = std.fmt.parseInt(u32, all_args.items[i + 1], 10) catch 0;
                    i += 1; // skip the value
                }
            } else if (std.mem.startsWith(u8, arg, "--depth=")) {
                clone_depth = std.fmt.parseInt(u32, arg["--depth=".len..], 10) catch 0;
            }
        }
    }

    // For --bare with HTTPS URLs, use our native smart HTTP clone
    if (is_bare) {
        // Find the URL in args (skip flags and their values)
        var clone_url: ?[]const u8 = null;
        var clone_target: ?[]const u8 = null;
        {
            var i: usize = 0;
            while (i < all_args.items.len) : (i += 1) {
                const arg = all_args.items[i];
                if (std.mem.eql(u8, arg, "--depth") or std.mem.eql(u8, arg, "-b") or
                    std.mem.eql(u8, arg, "--branch") or std.mem.eql(u8, arg, "--origin") or
                    std.mem.eql(u8, arg, "-o") or std.mem.eql(u8, arg, "--reference") or
                    std.mem.eql(u8, arg, "--separate-git-dir"))
                {
                    i += 1; // skip the next arg (value)
                    continue;
                }
                if (std.mem.startsWith(u8, arg, "-")) continue;
                if (clone_url == null) {
                    clone_url = arg;
                } else if (clone_target == null) {
                    clone_target = arg;
                }
            }
        }

        if (clone_url) |url_val| {
            if (std.mem.startsWith(u8, url_val, "https://") or std.mem.startsWith(u8, url_val, "http://")) {
                const final_target = clone_target orelse blk: {
                    if (std.mem.lastIndexOfScalar(u8, url_val, '/')) |last_slash| {
                        const repo_name = url_val[last_slash + 1..];
                        if (std.mem.endsWith(u8, repo_name, ".git")) {
                            break :blk repo_name[0..repo_name.len - 4];
                        } else {
                            break :blk repo_name;
                        }
                    } else {
                        break :blk "repository";
                    }
                };

                const clone_msg = try std.fmt.allocPrint(allocator, "Cloning into bare repository '{s}'...\n", .{final_target});
                defer allocator.free(clone_msg);
                try platform_impl.writeStderr(clone_msg);

                const ziggit = @import("ziggit.zig");
                var repo = if (clone_depth > 0)
                    ziggit.Repository.cloneBareShallow(allocator, url_val, final_target, clone_depth) catch |err| {
                        const emsg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
                        defer allocator.free(emsg);
                        try platform_impl.writeStderr(emsg);
                        std.process.exit(128);
                    }
                else
                    ziggit.Repository.cloneBare(allocator, url_val, final_target) catch |err| {
                        const emsg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
                        defer allocator.free(emsg);
                        try platform_impl.writeStderr(emsg);
                        std.process.exit(128);
                    };
                repo.close();
                return;
            }
        }
    }

    // Handle --no-checkout with HTTPS URLs natively
    if (is_no_checkout) {
        var clone_url: ?[]const u8 = null;
        var clone_target: ?[]const u8 = null;
        for (all_args.items) |arg| {
            if (std.mem.startsWith(u8, arg, "-")) continue;
            if (clone_url == null) {
                clone_url = arg;
            } else if (clone_target == null) {
                clone_target = arg;
            }
        }

        if (clone_url) |url_val| {
            if (std.mem.startsWith(u8, url_val, "https://") or std.mem.startsWith(u8, url_val, "http://")) {
                const final_target = clone_target orelse blk: {
                    if (std.mem.lastIndexOfScalar(u8, url_val, '/')) |last_slash| {
                        const repo_name = url_val[last_slash + 1..];
                        if (std.mem.endsWith(u8, repo_name, ".git")) {
                            break :blk repo_name[0..repo_name.len - 4];
                        } else {
                            break :blk repo_name;
                        }
                    } else {
                        break :blk "repository";
                    }
                };

                const clone_msg = try std.fmt.allocPrint(allocator, "Cloning into '{s}'...\n", .{final_target});
                defer allocator.free(clone_msg);
                try platform_impl.writeStderr(clone_msg);

                // Use cloneBare to download everything into a temp bare dir, then convert to non-bare
                const ziggit = @import("ziggit.zig");
                const bare_target = try std.fmt.allocPrint(allocator, "{s}/.git", .{final_target});
                defer allocator.free(bare_target);

                // Create the worktree directory first
                std.fs.cwd().makePath(final_target) catch |err| switch (err) {
                    error.PathAlreadyExists => {
                        const msg = try std.fmt.allocPrint(allocator, "fatal: destination path '{s}' already exists and is not an empty directory.\n", .{final_target});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(128);
                    },
                    else => return err,
                };

                // Clone bare into .git subdirectory
                var repo = ziggit.Repository.cloneBare(allocator, url_val, bare_target) catch |err| {
                    // Clean up on failure
                    std.fs.cwd().deleteTree(final_target) catch {};
                    const emsg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
                    defer allocator.free(emsg);
                    try platform_impl.writeStderr(emsg);
                    std.process.exit(128);
                };
                repo.close();

                // Convert bare repo to non-bare: update config to set bare = false
                const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{bare_target});
                defer allocator.free(config_path);
                const config_content = std.fs.cwd().readFileAlloc(allocator, config_path, 1024 * 1024) catch |err| {
                    const emsg = try std.fmt.allocPrint(allocator, "fatal: failed to read config: {}\n", .{err});
                    defer allocator.free(emsg);
                    try platform_impl.writeStderr(emsg);
                    std.process.exit(128);
                };
                defer allocator.free(config_content);

                // Replace bare = true with bare = false
                var new_config = std.array_list.Managed(u8).init(allocator);
                defer new_config.deinit();
                var config_lines = std.mem.splitSequence(u8, config_content, "\n");
                var first = true;
                while (config_lines.next()) |cline| {
                    if (!first) try new_config.appendSlice("\n");
                    first = false;
                    const trimmed = std.mem.trim(u8, cline, " \t\r");
                    if (std.mem.eql(u8, trimmed, "bare = true")) {
                        // Preserve leading whitespace
                        for (cline) |c| {
                            if (c == ' ' or c == '\t') {
                                try new_config.append(c);
                            } else break;
                        }
                        try new_config.appendSlice("bare = false");
                    } else {
                        try new_config.appendSlice(cline);
                    }
                }

                const cf = try std.fs.cwd().createFile(config_path, .{});
                defer cf.close();
                try cf.writeAll(new_config.items);

                return; // --no-checkout means skip checkout
            }
        }

        // Non-HTTPS --no-checkout: fall through to git
    }

    // For non-HTTPS --bare, handle locally
    if (is_bare) {
        // Find URL and target for bare clone
        var bare_url: ?[]const u8 = null;
        var bare_target: ?[]const u8 = null;
        {
            var i: usize = 0;
            while (i < all_args.items.len) : (i += 1) {
                const arg = all_args.items[i];
                if (std.mem.eql(u8, arg, "--depth") or std.mem.eql(u8, arg, "-b") or
                    std.mem.eql(u8, arg, "--branch") or std.mem.eql(u8, arg, "--origin") or
                    std.mem.eql(u8, arg, "-o") or std.mem.eql(u8, arg, "--reference") or
                    std.mem.eql(u8, arg, "--separate-git-dir"))
                {
                    i += 1;
                    continue;
                }
                if (std.mem.startsWith(u8, arg, "-")) continue;
                if (bare_url == null) {
                    bare_url = arg;
                } else if (bare_target == null) {
                    bare_target = arg;
                }
            }
        }
        if (bare_url) |burl| {
            if (!(std.mem.startsWith(u8, burl, "https://") or std.mem.startsWith(u8, burl, "http://") or
                std.mem.startsWith(u8, burl, "ssh://") or std.mem.startsWith(u8, burl, "git://")))
            {
                const bfinal_target = bare_target orelse bt: {
                    if (std.mem.lastIndexOfScalar(u8, burl, '/')) |ls| {
                        const rn = burl[ls + 1..];
                        if (std.mem.endsWith(u8, rn, ".git")) break :bt rn else {
                            const bn = try std.fmt.allocPrint(allocator, "{s}.git", .{rn});
                            break :bt bn;
                        }
                    } else break :bt "repository.git";
                };

                const bare_msg = try std.fmt.allocPrint(allocator, "Cloning into bare repository '{s}'...\n", .{bfinal_target});
                defer allocator.free(bare_msg);
                try platform_impl.writeStderr(bare_msg);

                performLocalClone(allocator, burl, bfinal_target, true, false, null, null, platform_impl, false, is_mirror) catch {
                    try platform_impl.writeStderr("fatal: repository does not exist\n");
                    std.process.exit(128);
                };
                return;
            }
        }
    }

    // Parse arguments for our internal implementation
    var url: ?[]const u8 = null;
    var target_dir: ?[]const u8 = null;

    {
        var i: usize = 0;
        while (i < all_args.items.len) : (i += 1) {
            const arg = all_args.items[i];
            // Skip flags that take a value argument
            if (std.mem.eql(u8, arg, "--depth") or std.mem.eql(u8, arg, "-b") or
                std.mem.eql(u8, arg, "--branch") or std.mem.eql(u8, arg, "--origin") or
                std.mem.eql(u8, arg, "-o") or std.mem.eql(u8, arg, "--reference") or
                std.mem.eql(u8, arg, "--separate-git-dir") or std.mem.eql(u8, arg, "-j") or
                std.mem.eql(u8, arg, "--jobs") or std.mem.eql(u8, arg, "--filter"))
            {
                i += 1; // skip value
                continue;
            }
            if (std.mem.startsWith(u8, arg, "-")) continue;
            if (url == null) {
                url = arg;
            } else if (target_dir == null) {
                target_dir = arg;
            } else {
                const emsg = try std.fmt.allocPrint(allocator, "fatal: Too many arguments.\n\nusage: git clone [<options>] [--] <repo> [<dir>]\n", .{});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(128);
            }
        }
    }

    if (url == null) {
        try platform_impl.writeStderr("fatal: You must specify a repository to clone.\n");
        std.process.exit(128);
    }

    const raw_target_dir = target_dir orelse blk: {
        // Extract directory name from URL
        if (std.mem.lastIndexOfScalar(u8, url.?, '/')) |last_slash| {
            const repo_name = url.?[last_slash + 1..];
            if (std.mem.endsWith(u8, repo_name, ".git")) {
                break :blk repo_name[0..repo_name.len - 4];
            } else {
                break :blk repo_name;
            }
        } else {
            break :blk "repository";
        }
    };
    
    // Strip trailing slashes from target directory
    const final_target_dir = std.mem.trimRight(u8, raw_target_dir, "/");
    
    // For non-HTTP URLs (local paths, ssh://, git://), handle local clone natively
    if (!(std.mem.startsWith(u8, url.?, "https://") or std.mem.startsWith(u8, url.?, "http://"))) {
        // Parse --branch and --origin flags
        var clone_branch: ?[]const u8 = null;
        var clone_origin: ?[]const u8 = null;
        {
            var i: usize = 0;
            while (i < all_args.items.len) : (i += 1) {
                const arg = all_args.items[i];
                if ((std.mem.eql(u8, arg, "-b") or std.mem.eql(u8, arg, "--branch")) and i + 1 < all_args.items.len) {
                    clone_branch = all_args.items[i + 1];
                    i += 1;
                } else if (std.mem.startsWith(u8, arg, "--branch=")) {
                    clone_branch = arg["--branch=".len..];
                } else if ((std.mem.eql(u8, arg, "-o") or std.mem.eql(u8, arg, "--origin")) and i + 1 < all_args.items.len) {
                    clone_origin = all_args.items[i + 1];
                    i += 1;
                } else if (std.mem.startsWith(u8, arg, "--origin=")) {
                    clone_origin = arg["--origin=".len..];
                }
            }
        }

        // Validate origin name
        if (clone_origin) |origin| {
            if (!isValidRemoteName(origin)) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' is not a valid remote name\n", .{origin});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }
        }

        // For SSH and git:// protocols, show error (SSH transport not yet fully integrated into clone)
        if (std.mem.startsWith(u8, url.?, "ssh://") or std.mem.startsWith(u8, url.?, "git://") or
            (std.mem.indexOf(u8, url.?, ":") != null and std.mem.indexOf(u8, url.?, "/") != null and
             (std.mem.indexOf(u8, url.?, ":").? < std.mem.indexOf(u8, url.?, "/").?) and !std.mem.startsWith(u8, url.?, "/") and !std.mem.startsWith(u8, url.?, "file://")))
        {
            try platform_impl.writeStderr("fatal: SSH/git:// clone not yet supported natively\n");
            std.process.exit(128);
        }

        // Check if target directory already exists and is non-empty
        if (platform_impl.fs.exists(final_target_dir) catch false) {
            // Check if it's a directory
            const is_dir = blk: {
                var dir = std.fs.cwd().openDir(final_target_dir, .{ .iterate = true }) catch break :blk false;
                defer dir.close();
                // Check if empty
                var iter = dir.iterate();
                if (iter.next() catch null) |_| break :blk false; // has entries = not empty
                break :blk true; // empty dir is OK
            };
            if (!is_dir) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: destination path '{s}' already exists and is not an empty directory.\n", .{final_target_dir});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }
        }

        const clone_msg = try std.fmt.allocPrint(allocator, "Cloning into '{s}'...\n", .{final_target_dir});
        defer allocator.free(clone_msg);
        try platform_impl.writeStderr(clone_msg);

        performLocalClone(allocator, url.?, final_target_dir, false, is_no_checkout, clone_branch, clone_origin, platform_impl, is_shared, is_mirror) catch |err| {
            // Clean up on failure
            std.fs.cwd().deleteTree(final_target_dir) catch {};
            const emsg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
        };
        return;
    }

    // Check if target directory already exists
    if (platform_impl.fs.exists(final_target_dir) catch false) {
        const msg = try std.fmt.allocPrint(allocator, "fatal: destination path '{s}' already exists and is not an empty directory.\n", .{final_target_dir});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    }
    
    const clone_msg = try std.fmt.allocPrint(allocator, "Cloning into '{s}'...\n", .{final_target_dir});
    defer allocator.free(clone_msg);
    try platform_impl.writeStderr(clone_msg);
    
    // For HTTPS URLs, use native smart HTTP clone + checkout
    if (std.mem.startsWith(u8, url.?, "https://") or std.mem.startsWith(u8, url.?, "http://")) {
        const ziggit = @import("ziggit.zig");
        const bare_target = try std.fmt.allocPrint(allocator, "{s}/.git", .{final_target_dir});
        defer allocator.free(bare_target);

        // Create the worktree directory first
        std.fs.cwd().makePath(final_target_dir) catch |err| switch (err) {
            error.PathAlreadyExists => {
                const msg = try std.fmt.allocPrint(allocator, "fatal: destination path '{s}' already exists and is not an empty directory.\n", .{final_target_dir});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            },
            else => return err,
        };

        // Clone bare into .git subdirectory (with optional shallow depth)
        var repo = if (clone_depth > 0)
            ziggit.Repository.cloneBareShallow(allocator, url.?, bare_target, clone_depth) catch |err| {
                std.fs.cwd().deleteTree(final_target_dir) catch {};
                const emsg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(128);
            }
        else
            ziggit.Repository.cloneBare(allocator, url.?, bare_target) catch |err| {
                std.fs.cwd().deleteTree(final_target_dir) catch {};
                const emsg = try std.fmt.allocPrint(allocator, "fatal: {}\n", .{err});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(128);
            };
        repo.close();

        // Convert bare repo to non-bare: update config to set bare = false
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{bare_target});
        defer allocator.free(config_path);
        const config_content = std.fs.cwd().readFileAlloc(allocator, config_path, 1024 * 1024) catch |err| {
            const emsg = try std.fmt.allocPrint(allocator, "fatal: failed to read config: {}\n", .{err});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
        };
        defer allocator.free(config_content);

        // Replace bare = true with bare = false
        var new_config = std.array_list.Managed(u8).init(allocator);
        defer new_config.deinit();
        var config_lines = std.mem.splitSequence(u8, config_content, "\n");
        var first = true;
        while (config_lines.next()) |cline| {
            if (!first) try new_config.appendSlice("\n");
            first = false;
            const trimmed = std.mem.trim(u8, cline, " \t\r");
            if (std.mem.eql(u8, trimmed, "bare = true")) {
                for (cline) |c| {
                    if (c == ' ' or c == '\t') {
                        try new_config.append(c);
                    } else break;
                }
                try new_config.appendSlice("bare = false");
            } else {
                try new_config.appendSlice(cline);
            }
        }

        {
            const cf = try std.fs.cwd().createFile(config_path, .{});
            defer cf.close();
            try cf.writeAll(new_config.items);
        }

        // Checkout HEAD into worktree
        const head_commit = refs.getCurrentCommit(bare_target, platform_impl, allocator) catch {
            // Empty repository - no checkout needed
            return;
        };
        if (head_commit) |commit_hash| {
            defer allocator.free(commit_hash);
            checkoutCommitTree(bare_target, commit_hash, allocator, platform_impl) catch |err| {
                const emsg = try std.fmt.allocPrint(allocator, "warning: checkout failed: {}, repository cloned but working tree not populated\n", .{err});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
            };
        }

        return;
    }

    // Perform clone using dumb HTTP protocol (non-HTTPS fallback)
    network.cloneRepository(allocator, url.?, final_target_dir, platform_impl) catch |err| switch (err) {
        error.RepositoryNotFound => {
            try platform_impl.writeStderr("fatal: repository not found\n");
            std.process.exit(128);
        },
        error.InvalidUrl => {
            try platform_impl.writeStderr("fatal: invalid repository URL\n");
            std.process.exit(128);
        },
        error.HttpError => {
            try platform_impl.writeStderr("fatal: unable to access remote repository\n");
            std.process.exit(128);
        },
        error.NoValidBranch => {
            try platform_impl.writeStderr("warning: remote HEAD refers to nonexistent ref, unable to checkout.\n");
            std.process.exit(128);
        },
        error.AlreadyExists => {
            try platform_impl.writeStderr("fatal: destination path already exists\n");
            std.process.exit(128);
        },
        else => return err,
    };
}

fn cmdConfig(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("config: not supported in freestanding mode\n");
        return;
    }

    // Collect all remaining args
    var config_args = std.array_list.Managed([]const u8).init(allocator);
    defer config_args.deinit();
    while (args.next()) |arg| {
        try config_args.append(arg);
    }

    const CfgAction = enum {
        none, get, get_all, get_regexp, set, replace_all, add,
        unset, unset_all, list, rename_section, remove_section,
        edit, get_color, get_colorbool,
    };

    var action: CfgAction = .none;
    var config_type: ConfigType = .none;
    var type_count: u32 = 0;
    var config_comment: ?[]const u8 = null;
    var use_global = false;
    var use_system = false;
    var use_local = false;
    var use_worktree = false;
    var config_file: ?[]const u8 = null;
    var null_terminator = false;
    var show_names = false;
    var show_origin = false;
    var show_scope = false;
    var default_value: ?[]const u8 = null;
    var fixed_value = false;
    var sub_value_pattern: ?[]const u8 = null;
    var positionals = std.array_list.Managed([]const u8).init(allocator);
    defer positionals.deinit();
    var new_style_sub = false;
    var do_all = false;

    var i: usize = 0;
    while (i < config_args.items.len) : (i += 1) {
        const arg = config_args.items[i];
        if (std.mem.eql(u8, arg, "--list") or std.mem.eql(u8, arg, "-l")) {
            action = .list;
        } else if (std.mem.eql(u8, arg, "--get")) {
            action = .get;
        } else if (std.mem.eql(u8, arg, "--get-all")) {
            action = .get_all;
        } else if (std.mem.eql(u8, arg, "--get-regexp")) {
            action = .get_regexp;
        } else if (std.mem.eql(u8, arg, "--unset")) {
            action = .unset;
        } else if (std.mem.eql(u8, arg, "--unset-all")) {
            action = .unset_all;
        } else if (std.mem.eql(u8, arg, "--add") or std.mem.eql(u8, arg, "--append")) {
            action = .add;
        } else if (std.mem.eql(u8, arg, "--remove-section")) {
            action = .remove_section;
        } else if (std.mem.eql(u8, arg, "--rename-section")) {
            action = .rename_section;
        } else if (std.mem.eql(u8, arg, "--replace-all")) {
            action = .replace_all;
        } else if (std.mem.eql(u8, arg, "--bool")) {
            const new_t: ConfigType = .bool_type;
            if (type_count > 0 and config_type != new_t) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t;
            type_count += 1;
        } else if (std.mem.eql(u8, arg, "--int")) {
            const new_t: ConfigType = .int_type;
            if (type_count > 0 and config_type != new_t) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t;
            type_count += 1;
        } else if (std.mem.eql(u8, arg, "--bool-or-int")) {
            const new_t: ConfigType = .bool_or_int;
            if (type_count > 0 and config_type != new_t) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t;
            type_count += 1;
        } else if (std.mem.eql(u8, arg, "--path")) {
            const new_t: ConfigType = .path_type;
            if (type_count > 0 and config_type != new_t) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t;
            type_count += 1;
        } else if (std.mem.eql(u8, arg, "--expiry-date")) {
            const new_t: ConfigType = .expiry_date;
            if (type_count > 0 and config_type != new_t) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t;
            type_count += 1;
        } else if (std.mem.eql(u8, arg, "--type")) {
            i += 1;
            if (i >= config_args.items.len) { try platform_impl.writeStderr("error: --type requires a value\n"); std.process.exit(129); }
            const type_str = config_args.items[i];
            const new_t2: ConfigType = if (std.mem.eql(u8, type_str, "bool"))
                .bool_type
            else if (std.mem.eql(u8, type_str, "int"))
                .int_type
            else if (std.mem.eql(u8, type_str, "bool-or-int"))
                .bool_or_int
            else if (std.mem.eql(u8, type_str, "path"))
                .path_type
            else if (std.mem.eql(u8, type_str, "expiry-date"))
                .expiry_date
            else if (std.mem.eql(u8, type_str, "color"))
                .color_type
            else {
                const emsg2 = try std.fmt.allocPrint(allocator, "error: unrecognized --type argument, {s}\n", .{type_str});
                defer allocator.free(emsg2);
                try platform_impl.writeStderr(emsg2);
                std.process.exit(1);
            };
            if (type_count > 0 and config_type != new_t2) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t2;
            type_count += 1;
        } else if (std.mem.startsWith(u8, arg, "--type=")) {
            const type_str = arg["--type=".len..];
            const new_t: ConfigType = if (std.mem.eql(u8, type_str, "bool"))
                .bool_type
            else if (std.mem.eql(u8, type_str, "int"))
                .int_type
            else if (std.mem.eql(u8, type_str, "bool-or-int"))
                .bool_or_int
            else if (std.mem.eql(u8, type_str, "path"))
                .path_type
            else if (std.mem.eql(u8, type_str, "expiry-date"))
                .expiry_date
            else if (std.mem.eql(u8, type_str, "color"))
                .color_type
            else {
                const emsg = try std.fmt.allocPrint(allocator, "error: unrecognized --type argument, {s}\n", .{type_str});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(1);
            };
            if (type_count > 0 and config_type != new_t) {
                try platform_impl.writeStderr("error: only one type at a time\n");
                std.process.exit(129);
            }
            config_type = new_t;
            type_count += 1;
        } else if (std.mem.eql(u8, arg, "--no-type")) {
            config_type = .none;
            type_count = 0;
        } else if (std.mem.eql(u8, arg, "--global")) {
            use_global = true;
        } else if (std.mem.eql(u8, arg, "--system")) {
            use_system = true;
        } else if (std.mem.eql(u8, arg, "--local")) {
            use_local = true;
        } else if (std.mem.eql(u8, arg, "--worktree")) {
            use_worktree = true;
        } else if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--file")) {
            i += 1;
            if (i < config_args.items.len) config_file = config_args.items[i];
        } else if (std.mem.startsWith(u8, arg, "--file=")) {
            config_file = arg["--file=".len..];
        } else if (std.mem.startsWith(u8, arg, "-f") and arg.len > 2) {
            config_file = arg[2..];
        } else if (std.mem.eql(u8, arg, "-z") or std.mem.eql(u8, arg, "--null")) {
            null_terminator = true;
        } else if (std.mem.eql(u8, arg, "--name-only") or std.mem.eql(u8, arg, "--name")) {
            show_names = true;
        } else if (std.mem.eql(u8, arg, "--show-names")) {
            // subcommand mode: show names with values (not name-only)
        } else if (std.mem.eql(u8, arg, "--show-origin")) {
            show_origin = true;
        } else if (std.mem.eql(u8, arg, "--show-scope")) {
            show_scope = true;
        } else if (std.mem.startsWith(u8, arg, "--default=")) {
            default_value = arg["--default=".len..];
        } else if (std.mem.eql(u8, arg, "--default")) {
            i += 1;
            if (i < config_args.items.len) default_value = config_args.items[i];
        } else if (std.mem.eql(u8, arg, "--fixed-value")) {
            fixed_value = true;
        } else if (std.mem.eql(u8, arg, "--edit") or std.mem.eql(u8, arg, "-e")) {
            action = .edit;
        } else if (std.mem.eql(u8, arg, "--get-color")) {
            action = .get_color;
        } else if (std.mem.eql(u8, arg, "--get-colorbool")) {
            action = .get_colorbool;
        } else if (std.mem.startsWith(u8, arg, "--comment=")) {
            config_comment = arg["--comment=".len..];
        } else if (std.mem.eql(u8, arg, "--comment")) {
            i += 1;
            if (i < config_args.items.len) config_comment = config_args.items[i];
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git config [<options>]\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--")) {
            i += 1;
            while (i < config_args.items.len) : (i += 1) {
                try positionals.append(config_args.items[i]);
            }
        } else if (std.mem.eql(u8, arg, "--all") and new_style_sub) {
            do_all = true;
        } else if (std.mem.eql(u8, arg, "--regexp") and new_style_sub and action == .get) {
            action = .get_regexp;
        } else if ((std.mem.eql(u8, arg, "--value") or std.mem.startsWith(u8, arg, "--value=")) and new_style_sub) {
            if (std.mem.startsWith(u8, arg, "--value=")) {
                sub_value_pattern = arg["--value=".len..];
            } else {
                i += 1;
                if (i < config_args.items.len) sub_value_pattern = config_args.items[i];
            }
        } else if (std.mem.eql(u8, arg, "set") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .set;
        } else if (std.mem.eql(u8, arg, "get") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .get;
        } else if (std.mem.eql(u8, arg, "unset") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .unset;
        } else if (std.mem.eql(u8, arg, "list") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .list;
        } else if (std.mem.eql(u8, arg, "rename-section") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .rename_section;
        } else if (std.mem.eql(u8, arg, "remove-section") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .remove_section;
        } else if (std.mem.eql(u8, arg, "edit") and positionals.items.len == 0 and action == .none) {
            new_style_sub = true;
            action = .edit;
        } else {
            try positionals.append(arg);
        }
    }

    // --worktree requires repo
    if (use_worktree) {
        const gpc: ?[]const u8 = findGitDirectory(allocator, platform_impl) catch null;
        if (gpc) |gp2| allocator.free(gp2) else {
            try platform_impl.writeStderr("fatal: --worktree can only be used inside a git repository\n");
            std.process.exit(128);
        }
    }

    // Subcommand mode adjustments
    if (new_style_sub and action == .get and do_all) action = .get_all;
    if (new_style_sub and action == .set and do_all) action = .replace_all;
    if (new_style_sub and action == .unset and do_all) action = .unset_all;
    // get --regexp already sets action to .get_regexp via the --regexp flag handler

    // Validate --fixed-value usage
    if (fixed_value) {
        switch (action) {
            .get, .get_all, .get_regexp, .set, .replace_all, .unset, .unset_all => {},
            else => {
                try platform_impl.writeStderr("error: --fixed-value only applies with 'get', 'set', 'unset'\n");
                std.process.exit(129);
            },
        }
    }

    // Infer action from positionals
    if (action == .none) {
        if (positionals.items.len == 0) {
            try platform_impl.writeStderr("error: no action specified\n");
            std.process.exit(2);
        } else if (positionals.items.len == 1) {
            action = .get;
        } else {
            action = .set;
        }
    }

    const git_path_opt: ?[]const u8 = findGitDirectory(allocator, platform_impl) catch null;
    defer if (git_path_opt) |gp| allocator.free(gp);

    // --local requires repo
    if ((use_local or use_worktree) and git_path_opt == null) {
        try platform_impl.writeStderr("fatal: --local can only be used inside a git repository\n");
        std.process.exit(128);
    }

    // Env vars
    const env_cfg_global = std.process.getEnvVarOwned(allocator, "GIT_CONFIG_GLOBAL") catch null;
    defer if (env_cfg_global) |eg| allocator.free(eg);
    const env_cfg_system = std.process.getEnvVarOwned(allocator, "GIT_CONFIG_SYSTEM") catch null;
    defer if (env_cfg_system) |es| allocator.free(es);
    const env_cfg_nosystem = std.process.getEnvVarOwned(allocator, "GIT_CONFIG_NOSYSTEM") catch null;
    defer if (env_cfg_nosystem) |en| allocator.free(en);

    // GIT_CONFIG overrides config file
    const env_git_config_owned = if (config_file == null)
        (std.process.getEnvVarOwned(allocator, "GIT_CONFIG") catch null)
    else
        null;
    defer if (env_git_config_owned) |egc| allocator.free(egc);
    if (env_git_config_owned) |egc| config_file = egc;

    // Stdin restrictions
    if (config_file != null and std.mem.eql(u8, config_file.?, "-")) {
        switch (action) {
            .set, .replace_all, .add, .unset, .unset_all, .rename_section, .remove_section => {
                try platform_impl.writeStderr("fatal: writing to stdin is not supported\n");
                std.process.exit(128);
            },
            .edit => {
                try platform_impl.writeStderr("fatal: editing stdin is not supported\n");
                std.process.exit(128);
            },
            else => {},
        }
    }

    // Build source list
    var sources = std.array_list.Managed(ConfigSource).init(allocator);
    defer {
        for (sources.items) |s| { if (s.needs_free) allocator.free(s.path); }
        sources.deinit();
    }
    const home_dir = std.process.getEnvVarOwned(allocator, "HOME") catch null;
    defer if (home_dir) |h| allocator.free(h);

    if (config_file) |cf| {
        try sources.append(.{ .path = cf, .scope = "command", .needs_free = false });
    } else if (use_system) {
        if (env_cfg_system) |es| {
            try sources.append(.{ .path = es, .scope = "system", .needs_free = false });
        } else {
            try sources.append(.{ .path = "/etc/gitconfig", .scope = "system", .needs_free = false });
        }
    } else if (use_global) {
        if (env_cfg_global) |eg| {
            try sources.append(.{ .path = eg, .scope = "global", .needs_free = false });
        } else if (home_dir) |h| {
            const p = try std.fmt.allocPrint(allocator, "{s}/.gitconfig", .{h});
            try sources.append(.{ .path = p, .scope = "global", .needs_free = true });
        }
    } else if (use_local) {
        if (git_path_opt) |gp| {
            const abs_p = try std.fmt.allocPrint(allocator, "{s}/config", .{gp});
            defer allocator.free(abs_p);
            const p = try cfgMakeRelativePath(abs_p, allocator);
            try sources.append(.{ .path = p, .scope = "local", .needs_free = true });
        }
    } else {
        // Default: system + global + local
        const nosystem = env_cfg_nosystem != null;
        if (!nosystem) {
            if (env_cfg_system) |es| {
                if (!std.mem.eql(u8, es, "/dev/null"))
                    try sources.append(.{ .path = es, .scope = "system", .needs_free = false });
            } else {
                try sources.append(.{ .path = "/etc/gitconfig", .scope = "system", .needs_free = false });
            }
        }
        if (env_cfg_global) |eg| {
            if (!std.mem.eql(u8, eg, "/dev/null"))
                try sources.append(.{ .path = eg, .scope = "global", .needs_free = false });
        } else {
            const xdg = std.process.getEnvVarOwned(allocator, "XDG_CONFIG_HOME") catch null;
            defer if (xdg) |x| allocator.free(x);
            if (xdg) |x| {
                const p = try std.fmt.allocPrint(allocator, "{s}/git/config", .{x});
                try sources.append(.{ .path = p, .scope = "global", .needs_free = true });
            } else if (home_dir) |h| {
                const p = try std.fmt.allocPrint(allocator, "{s}/.config/git/config", .{h});
                try sources.append(.{ .path = p, .scope = "global", .needs_free = true });
            }
            if (home_dir) |h| {
                const p = try std.fmt.allocPrint(allocator, "{s}/.gitconfig", .{h});
                try sources.append(.{ .path = p, .scope = "global", .needs_free = true });
            }
        }
        if (git_path_opt) |gp| {
            const abs_p = try std.fmt.allocPrint(allocator, "{s}/config", .{gp});
            defer allocator.free(abs_p);
            const p = try cfgMakeRelativePath(abs_p, allocator);
            try sources.append(.{ .path = p, .scope = "local", .needs_free = true });
        }
    }

    // Write path helper
    const getWritePath2 = struct {
        fn f(alloc: std.mem.Allocator, cf: ?[]const u8, ug: bool, us: bool, home: ?[]const u8, gp: ?[]const u8, ecg: ?[]const u8, ecs: ?[]const u8, pi2: *const platform_mod.Platform) ![]u8 {
            if (cf) |file| return try alloc.dupe(u8, file);
            if (ug) {
                if (ecg) |eg| return try alloc.dupe(u8, eg);
                if (home) |h| return try std.fmt.allocPrint(alloc, "{s}/.gitconfig", .{h});
                try pi2.writeStderr("fatal: $HOME not set\n");
                std.process.exit(128);
            }
            if (us) {
                if (ecs) |es| return try alloc.dupe(u8, es);
                return try alloc.dupe(u8, "/etc/gitconfig");
            }
            if (gp) |g| return try std.fmt.allocPrint(alloc, "{s}/config", .{g});
            try pi2.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
            std.process.exit(128);
        }
    };

    // For --file, check that file exists for read operations
    if (config_file) |cf| {
        if (!std.mem.eql(u8, cf, "-")) {
            switch (action) {
                .list, .get, .get_all, .get_regexp => {
                    _ = platform_impl.fs.readFile(allocator, cf) catch |err| switch (err) {
                        error.FileNotFound => {
                            if (default_value != null and action == .get) {
                                const dv = default_value.?;
                                if (config_type == .expiry_date) {
                                    const trimmed_dv = std.mem.trim(u8, dv, " \t");
                                    const valid_exp = std.mem.eql(u8, trimmed_dv, "never") or
                                        std.mem.eql(u8, trimmed_dv, "false") or
                                        std.mem.eql(u8, trimmed_dv, "now") or
                                        (std.fmt.parseInt(i64, trimmed_dv, 10) catch null) != null;
                                    if (!valid_exp) {
                                        try platform_impl.writeStderr("error: failed to format default config value\n");
                                        std.process.exit(1);
                                    }
                                }
                                const fmt_dv = cfgFormatType(dv, config_type, allocator, platform_impl) catch {
                                    try platform_impl.writeStderr("error: failed to format default config value\n");
                                    std.process.exit(1);
                                };
                                defer allocator.free(fmt_dv);
                                const dv_term: []const u8 = if (null_terminator) "\x00" else "\n";
                                const dv_out = try std.fmt.allocPrint(allocator, "{s}{s}", .{ fmt_dv, dv_term });
                                defer allocator.free(dv_out);
                                try platform_impl.writeStdout(dv_out);
                                return;
                            }
                            const em = try std.fmt.allocPrint(allocator, "fatal: unable to read config file '{s}': No such file or directory\n", .{cf});
                            defer allocator.free(em);
                            try platform_impl.writeStderr(em);
                            std.process.exit(1);
                        },
                        else => {},
                    };
                },
                else => {},
            }
        }
    }

    if (default_value != null) {
        switch (action) {
            .get, .get_all, .get_regexp => {},
            else => {
                try platform_impl.writeStderr("error: --default is only applicable to --get\n");
                std.process.exit(129);
            },
        }
    }

    // GIT_CONFIG_COUNT is processed globally (before -c) in zigzitMain

        // Validate --fixed-value requires value-pattern
    if (fixed_value) {
        const has_vpat = sub_value_pattern != null or (positionals.items.len >= 2 and (action == .get or action == .get_all or action == .get_regexp or action == .unset or action == .unset_all)) or (positionals.items.len >= 3 and (action == .set or action == .replace_all));
        if (!has_vpat) {
            switch (action) {
                .get, .get_all, .get_regexp, .set, .replace_all, .unset, .unset_all => {
                    try platform_impl.writeStderr("error: --fixed-value requires a value argument\n");
                    std.process.exit(129);
                },
                else => {},
            }
        }
    }

        switch (action) {
        .list => {
            for (sources.items) |source| {
                if (std.mem.eql(u8, source.path, "-")) {
                    const content = readStdin(allocator, 10 * 1024 * 1024) catch continue;
                    defer allocator.free(content);
                    try cfgOutputList(content, "standard input", source.scope, null_terminator, show_names, show_origin, show_scope, config_type, allocator, platform_impl);
                } else {
                    const content = platform_impl.fs.readFile(allocator, source.path) catch continue;
                    defer allocator.free(content);
                    try cfgOutputList(content, source.path, source.scope, null_terminator, show_names, show_origin, show_scope, config_type, allocator, platform_impl);
                }
            }
            // Also list config overrides
            if (global_config_overrides) |overrides| {
                for (overrides.items) |ov| {
                    const term3: []const u8 = if (null_terminator) "\x00" else "\n";
                    var out3 = std.array_list.Managed(u8).init(allocator);
                    defer out3.deinit();
                    if (show_scope) { try out3.appendSlice("command"); try out3.append('\t'); }
                    if (show_origin) { try out3.appendSlice("command line:"); try out3.append('\t'); }
                    if (show_names) {
                        try out3.appendSlice(ov.key);
                    } else {
                        try out3.appendSlice(ov.key);
                        if (null_terminator) try out3.append('\n') else try out3.append('=');
                        try out3.appendSlice(ov.value);
                    }
                    try out3.appendSlice(term3);
                    try platform_impl.writeStdout(out3.items);
                }
            }
            return;
        },
        .edit => {
            const cfg_path = try getWritePath2.f(allocator, config_file, use_global, use_system, home_dir, git_path_opt, env_cfg_global, env_cfg_system, platform_impl);
            defer allocator.free(cfg_path);
            _ = platform_impl.fs.readFile(allocator, cfg_path) catch |err| blk: {
                if (err == error.FileNotFound) try platform_impl.fs.writeFile(cfg_path, "");
                break :blk @as([]u8, "");
            };
            // Editor priority: GIT_EDITOR env, core.editor config, VISUAL env, EDITOR env, vi
            const editor = blk_editor: {
                if (std.process.getEnvVarOwned(allocator, "GIT_EDITOR")) |e| break :blk_editor e else |_| {}
                if (cfgLookup(sources.items, "core.editor", allocator, platform_impl)) |e| break :blk_editor e else |_| {}
                if (std.process.getEnvVarOwned(allocator, "VISUAL")) |e| break :blk_editor e else |_| {}
                if (std.process.getEnvVarOwned(allocator, "EDITOR")) |e| break :blk_editor e else |_| {}
                break :blk_editor try allocator.dupe(u8, "vi");
            };
            defer allocator.free(editor);
            // Run editor through shell to handle complex editor commands (redirections, etc.)
            const shell_cmd = try std.fmt.allocPrint(allocator, "{s} \"{s}\"", .{ editor, cfg_path });
            defer allocator.free(shell_cmd);
            const shell_argv = [_][]const u8{ "/bin/sh", "-c", shell_cmd };
            var child = std.process.Child.init(&shell_argv, allocator);
            child.spawn() catch { try platform_impl.writeStderr("error: could not launch editor\n"); std.process.exit(1); };
            _ = child.wait() catch {};
            return;
        },
        .rename_section => {
            if (positionals.items.len < 2) { try platform_impl.writeStderr("usage: git config --rename-section <old-name> <new-name>\n"); std.process.exit(2); }
            const old_s = positionals.items[0];
            const new_s = positionals.items[1];
            if (old_s.len == 0) { try platform_impl.writeStderr("error: invalid section name: \n"); std.process.exit(2); }
            if (!cfgIsValidSectionName(new_s)) {
                const em = try std.fmt.allocPrint(allocator, "error: invalid section name: {s}\n", .{new_s});
                defer allocator.free(em);
                try platform_impl.writeStderr(em);
                std.process.exit(2);
            }
            const cfg_path = try getWritePath2.f(allocator, config_file, use_global, use_system, home_dir, git_path_opt, env_cfg_global, env_cfg_system, platform_impl);
            defer allocator.free(cfg_path);
            try cfgRenameSection(cfg_path, old_s, new_s, allocator, platform_impl);
            return;
        },
        .remove_section => {
            if (positionals.items.len < 1) { try platform_impl.writeStderr("error: missing section name\n"); std.process.exit(2); }
            const cfg_path = try getWritePath2.f(allocator, config_file, use_global, use_system, home_dir, git_path_opt, env_cfg_global, env_cfg_system, platform_impl);
            defer allocator.free(cfg_path);
            try cfgRemoveSection(cfg_path, positionals.items[0], allocator, platform_impl);
            return;
        },
        .get_color => {
            const key2 = if (positionals.items.len >= 1) positionals.items[0] else { try platform_impl.writeStderr("error: --get-color requires a key\n"); std.process.exit(2); };
            const def = if (positionals.items.len >= 2) positionals.items[1] else "";
            const val = cfgLookup(sources.items, key2, allocator, platform_impl) catch null;
            defer if (val) |v| allocator.free(v);
            const color_str = val orelse def;
            const ansi = colorToAnsiAlloc(allocator, color_str) catch {
                std.process.exit(1);
            };
            defer allocator.free(ansi);
            try platform_impl.writeStdout(ansi);
            return;
        },
        .get_colorbool => {
            try platform_impl.writeStdout("false\n");
            return;
        },
        .get, .get_all => {
            if (positionals.items.len < 1) { try platform_impl.writeStderr("error: missing key\n"); std.process.exit(2); }
            const key2 = positionals.items[0];
            const vpat = sub_value_pattern orelse (if (positionals.items.len >= 2) positionals.items[1] else null);
            if (action == .get_all) {
                var found_any = false;
                for (sources.items) |source| {
                    const content = cfgReadSource(source.path, allocator, platform_impl) orelse continue;
                    defer allocator.free(content);
                    var ents = std.array_list.Managed(CfgEntry).init(allocator);
                    defer { for (ents.items) |*e| e.deinit(allocator); ents.deinit(); }
                    cfgValidateAndReport(content, source.path, allocator, platform_impl) catch {}; cfgParseEntries(content, &ents, allocator) catch continue;
                    for (ents.items) |e| {
                        if (!cfgKeyMatches(e.full_key, key2)) continue;
                        if (vpat) |vp| {
                            if (!cfgValueMatchesPattern(e.value, vp, fixed_value)) continue;
                        }
                        found_any = true;
                        const fmt2 = try cfgFormatTypeWithContext(cfgEffectiveValue(e), config_type, key2, source.path, allocator, platform_impl);
                        defer allocator.free(fmt2);
                        const term: []const u8 = if (null_terminator) "\x00" else "\n";
                        var out = std.array_list.Managed(u8).init(allocator);
                        defer out.deinit();
                        if (show_scope) { try out.appendSlice(source.scope); try out.append('\t'); }
                        if (show_origin) { try cfgAppendOrigin(&out, source.path); try out.append('\t'); }
                        try out.appendSlice(fmt2);
                        try out.appendSlice(term);
                        try platform_impl.writeStdout(out.items);
                    }
                }
                if (!found_any) std.process.exit(1);
            } else {
                // --get: return last
                var last_val: ?[]u8 = null;
                var last_scope: []const u8 = "";
                var last_origin: []const u8 = "";
                var last_has_equals: bool = true;
                defer if (last_val) |v| allocator.free(v);
                for (sources.items) |source| {
                    const content = cfgReadSource(source.path, allocator, platform_impl) orelse continue;
                    defer allocator.free(content);
                    var ents = std.array_list.Managed(CfgEntry).init(allocator);
                    defer { for (ents.items) |*e| e.deinit(allocator); ents.deinit(); }
                    cfgValidateAndReport(content, source.path, allocator, platform_impl) catch {}; cfgParseEntries(content, &ents, allocator) catch continue;
                    for (ents.items) |e| {
                        if (!cfgKeyMatches(e.full_key, key2)) continue;
                        if (vpat) |vp| {
                            if (!cfgValueMatchesPattern(e.value, vp, fixed_value)) continue;
                        }
                        if (last_val) |v| allocator.free(v);
                        last_val = try allocator.dupe(u8, cfgEffectiveValue(e));
                        last_has_equals = e.has_equals;
                        last_scope = source.scope;
                        last_origin = source.path;
                    }
                }
                if (getConfigOverride(key2)) |ov| {
                    if (last_val) |v| allocator.free(v);
                    last_val = try allocator.dupe(u8, ov);
                    last_scope = "command";
                    last_origin = "";
                }
                const eff = last_val orelse if (default_value) |dv| blk: {
                    last_scope = "command";
                    break :blk try allocator.dupe(u8, dv);
                } else null;
                defer if (last_val == null) { if (eff) |ev| allocator.free(ev); };
                if (eff) |v| {
                    const fmt2 = try cfgFormatTypeWithContext(v, config_type, key2, if (last_origin.len > 0) last_origin else null, allocator, platform_impl);
                    defer allocator.free(fmt2);
                    const term: []const u8 = if (null_terminator) "\x00" else "\n";
                    var out = std.array_list.Managed(u8).init(allocator);
                    defer out.deinit();
                    if (show_scope) { try out.appendSlice(last_scope); try out.append('\t'); }
                    if (show_origin) {
                        if (last_origin.len > 0) { try cfgAppendOrigin(&out, last_origin); }
                        else try out.appendSlice("command line:");
                        try out.append('\t');
                    }
                    try out.appendSlice(fmt2);
                    try out.appendSlice(term);
                    try platform_impl.writeStdout(out.items);
                } else std.process.exit(1);
            }
            return;
        },
        .get_regexp => {
            if (positionals.items.len < 1) { try platform_impl.writeStderr("error: missing key pattern\n"); std.process.exit(2); }
            const pattern = positionals.items[0];
            const vpat = sub_value_pattern orelse (if (positionals.items.len >= 2) positionals.items[1] else null);
            var found_any = false;
            for (sources.items) |source| {
                const content = cfgReadSource(source.path, allocator, platform_impl) orelse continue;
                defer allocator.free(content);
                var ents = std.array_list.Managed(CfgEntry).init(allocator);
                defer { for (ents.items) |*e| e.deinit(allocator); ents.deinit(); }
                cfgValidateAndReport(content, source.path, allocator, platform_impl) catch {}; cfgParseEntries(content, &ents, allocator) catch continue;
                for (ents.items) |e| {
                    if (!simpleRegexMatch(e.full_key, pattern)) continue;
                    if (vpat) |vp| { if (!simpleRegexMatch(e.value, vp)) continue; }
                    found_any = true;
                    const term: []const u8 = if (null_terminator) "\x00" else "\n";
                    var out = std.array_list.Managed(u8).init(allocator);
                    defer out.deinit();
                    if (show_scope) { try out.appendSlice(source.scope); try out.append('\t'); }
                    if (show_origin) { try cfgAppendOrigin(&out, source.path); try out.append('\t'); }
                    if (show_names) {
                        try out.appendSlice(e.full_key);
                    } else {
                        const fmt2 = try cfgFormatType(cfgEffectiveValue(e), config_type, allocator, platform_impl);
                        defer allocator.free(fmt2);
                        try out.appendSlice(e.full_key);
                        if (e.value.len > 0 or e.has_equals or config_type != .none) {
                            const sep: u8 = if (null_terminator) '\n' else ' ';
                            try out.append(sep);
                            try out.appendSlice(fmt2);
                        }
                    }
                    try out.appendSlice(term);
                    try platform_impl.writeStdout(out.items);
                }
            }
            // Also check config overrides (-c and GIT_CONFIG_COUNT)
            if (global_config_overrides) |overrides| {
                for (overrides.items) |ov| {
                    if (!simpleRegexMatch(ov.key, pattern)) continue;
                    if (vpat) |vp| { if (!simpleRegexMatch(ov.value, vp)) continue; }
                    found_any = true;
                    const term2: []const u8 = if (null_terminator) "\x00" else "\n";
                    var out2 = std.array_list.Managed(u8).init(allocator);
                    defer out2.deinit();
                    if (show_scope) { try out2.appendSlice("command"); try out2.append('\t'); }
                    if (show_origin) { try out2.appendSlice("command line:"); try out2.append('\t'); }
                    if (show_names) {
                        try out2.appendSlice(ov.key);
                    } else {
                        try out2.appendSlice(ov.key);
                        try out2.append(if (null_terminator) '\n' else ' ');
                        try out2.appendSlice(ov.value);
                    }
                    try out2.appendSlice(term2);
                    try platform_impl.writeStdout(out2.items);
                }
            }
            if (!found_any) std.process.exit(1);
            return;
        },
        .set, .replace_all, .add => {
            if (positionals.items.len < 2) { try platform_impl.writeStderr("error: wrong number of arguments, should be 2\n"); std.process.exit(2); }
            const key2 = positionals.items[0];
            const value2 = positionals.items[1];
            const vreg = sub_value_pattern orelse (if (positionals.items.len >= 3) positionals.items[2] else null);
            if (!cfgIsValidKey(key2)) {
                const em = try std.fmt.allocPrint(allocator, "error: invalid key: {s}\n", .{key2});
                defer allocator.free(em);
                try platform_impl.writeStderr(em);
                std.process.exit(1);
            }
            if (config_comment) |cc| {
                if (std.mem.indexOfScalar(u8, cc, '\n') != null) {
                    try platform_impl.writeStderr("error: invalid comment character: '\\n'\n");
                    std.process.exit(1);
                }
            }
            // Normalize value based on --type
            const effective_value = if (config_type == .color_type) blk: {
                if (!cfgValidateColor(std.mem.trim(u8, value2, " \t"))) {
                    const em2 = try std.fmt.allocPrint(allocator, "error: cannot parse color '{s}'\n", .{value2});
                    defer allocator.free(em2);
                    try platform_impl.writeStderr(em2);
                    std.process.exit(1);
                }
                break :blk try allocator.dupe(u8, value2);
            } else if (config_type != .none and config_type != .path_type and config_type != .expiry_date) blk: {
                const norm = try cfgFormatType(value2, config_type, allocator, platform_impl);
                break :blk norm;
            } else try allocator.dupe(u8, value2);
            defer allocator.free(effective_value);

            const cfg_path = try getWritePath2.f(allocator, config_file, use_global, use_system, home_dir, git_path_opt, env_cfg_global, env_cfg_system, platform_impl);
            defer allocator.free(cfg_path);
            try cfgSetValue(cfg_path, key2, effective_value, action == .add, action == .replace_all, vreg, fixed_value, config_comment, allocator, platform_impl);
            return;
        },
        .unset, .unset_all => {
            if (positionals.items.len < 1) { try platform_impl.writeStderr("error: missing key\n"); std.process.exit(2); }
            const key2 = positionals.items[0];
            const vreg = sub_value_pattern orelse (if (positionals.items.len >= 2) positionals.items[1] else null);
            const cfg_path = try getWritePath2.f(allocator, config_file, use_global, use_system, home_dir, git_path_opt, env_cfg_global, env_cfg_system, platform_impl);
            defer allocator.free(cfg_path);
            try cfgUnsetValue(cfg_path, key2, action == .unset_all, vreg, fixed_value, allocator, platform_impl);
            return;
        },
        .none => {
            try platform_impl.writeStderr("usage: git config [<options>]\n");
            std.process.exit(129);
        },
    }
}

const ConfigType = enum { none, bool_type, int_type, bool_or_int, path_type, expiry_date, color_type };

const ConfigSource = struct {
    path: []const u8,
    scope: []const u8,
    needs_free: bool,
};

const CfgEntry = struct {
    full_key: []u8,
    value: []u8,
    has_equals: bool,
    fn deinit(self: *CfgEntry, alloc: std.mem.Allocator) void {
        alloc.free(self.full_key);
        alloc.free(self.value);
    }
};

fn cfgReadSource(path: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ?[]u8 {
    if (std.mem.eql(u8, path, "-")) {
        return readStdin(allocator, 10 * 1024 * 1024) catch null;
    }
    return platform_impl.fs.readFile(allocator, path) catch null;
}

const CfgParseError = struct {
    line_number: usize,
    message: []const u8,
};

/// Validate config content and return error info if invalid.
/// Returns null if config is valid.
fn cfgValidateConfig(content: []const u8, allocator: std.mem.Allocator) ?CfgParseError {
    _ = allocator;
    var line_iter = std.mem.splitSequence(u8, content, "\n");
    var line_num: usize = 0;
    while (line_iter.next()) |raw_line| {
        line_num += 1;
        const line = std.mem.trimRight(u8, raw_line, "\r");
        const trimmed = std.mem.trim(u8, line, " \t");
        if (trimmed.len == 0 or trimmed[0] == '#' or trimmed[0] == ';') continue;

        if (trimmed[0] == '[') {
            // Check for incomplete section header
            if (std.mem.indexOfScalar(u8, trimmed, ']') == null) {
                return .{ .line_number = line_num, .message = "bad section header" };
            }
            continue;
        }

        // Check for incomplete quoted strings
        if (std.mem.indexOfScalar(u8, trimmed, '=')) |eq_pos| {
            var raw_value = trimmed[eq_pos + 1 ..];
            // Check for unterminated quotes across continuation lines
            var in_quotes = false;
            while (true) {
                const tv = std.mem.trimRight(u8, raw_value, " \t");
                var ii: usize = 0;
                while (ii < tv.len) : (ii += 1) {
                    if (tv[ii] == '\\' and ii + 1 < tv.len) { ii += 1; continue; }
                    if (tv[ii] == '"') in_quotes = !in_quotes;
                }
                // Check for continuation
                if (tv.len > 0 and tv[tv.len - 1] == '\\') {
                    if (line_iter.next()) |nl| {
                        line_num += 1;
                        raw_value = std.mem.trimRight(u8, nl, "\r");
                    } else break;
                } else break;
            }
            if (in_quotes) {
                return .{ .line_number = line_num, .message = "bad config line" };
            }
        } else {
            // No = sign - could be boolean key or garbage
            const cp = std.mem.indexOfScalar(u8, trimmed, '#') orelse std.mem.indexOfScalar(u8, trimmed, ';');
            const clean = if (cp) |c| std.mem.trimRight(u8, trimmed[0..c], " \t") else trimmed;
            if (clean.len > 0) {
                // Check if this looks like a valid boolean key (single word, no spaces)
                if (std.mem.indexOfScalar(u8, clean, ' ') != null or std.mem.indexOfScalar(u8, clean, '\t') != null) {
                    return .{ .line_number = line_num, .message = "bad config line" };
                }
            }
        }
    }
    return null;
}

fn cfgValidateAndReport(content: []const u8, source_path: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    if (cfgValidateConfig(content, allocator)) |err| {
        const is_stdin = std.mem.eql(u8, source_path, "-") or std.mem.eql(u8, source_path, "standard input");
        const source_name = if (is_stdin) "standard input" else source_path;
        const em = try std.fmt.allocPrint(allocator, "fatal: bad config line {d} in {s}{s}\n", .{
            err.line_number,
            if (is_stdin) @as([]const u8, "") else @as([]const u8, "file "),
            source_name,
        });
        defer allocator.free(em);
        try platform_impl.writeStderr(em);
        std.process.exit(128);
    }
}

fn cfgParseEntries(content: []const u8, entries: *std.array_list.Managed(CfgEntry), allocator: std.mem.Allocator) !void {
    var line_iter = std.mem.splitSequence(u8, content, "\n");
    var current_section: ?[]u8 = null;
    defer if (current_section) |s| allocator.free(s);
    while (line_iter.next()) |raw_line| {
        const line = std.mem.trimRight(u8, raw_line, "\r");
        const trimmed = std.mem.trim(u8, line, " \t");
        if (trimmed.len == 0 or trimmed[0] == '#' or trimmed[0] == ';') continue;
        if (trimmed[0] == '[') {
            if (current_section) |s| allocator.free(s);
            current_section = try cfgParseSectionToKey(trimmed, allocator);
            // Check for inline key=value after ]
            const close = std.mem.indexOf(u8, trimmed, "]") orelse continue;
            const after = std.mem.trim(u8, trimmed[close + 1 ..], " \t");
            if (after.len == 0 or after[0] == '#' or after[0] == ';') continue;
            if (std.mem.indexOf(u8, after, "=")) |eq| {
                const k = std.mem.trim(u8, after[0..eq], " \t");
                var vbuf = std.array_list.Managed(u8).init(allocator);
                defer vbuf.deinit();
                try cfgAppendValuePart(&vbuf, after[eq + 1 ..]);
                try entries.append(.{
                    .full_key = try cfgMakeKey(current_section, k, allocator),
                    .value = try vbuf.toOwnedSlice(),
                    .has_equals = true,
                });
            }
            continue;
        }
        if (current_section == null) continue;
        if (std.mem.indexOf(u8, trimmed, "=")) |eq_pos| {
            const k = std.mem.trim(u8, trimmed[0..eq_pos], " \t");
            var raw_value = trimmed[eq_pos + 1 ..];
            var vbuf = std.array_list.Managed(u8).init(allocator);
            defer vbuf.deinit();
            while (true) {
                const tv = std.mem.trimRight(u8, raw_value, " \t");
                if (tv.len > 0 and tv[tv.len - 1] == '\\' and cfgIsContinuation(tv)) {
                    try cfgAppendValuePart(&vbuf, tv[0 .. tv.len - 1]);
                    raw_value = if (line_iter.next()) |nl|
                        std.mem.trim(u8, std.mem.trimRight(u8, nl, "\r"), " \t")
                    else break;
                } else {
                    try cfgAppendValuePart(&vbuf, raw_value);
                    break;
                }
            }
            try entries.append(.{
                .full_key = try cfgMakeKey(current_section, k, allocator),
                .value = try vbuf.toOwnedSlice(),
                .has_equals = true,
            });
        } else {
            // Boolean key
            const cp = std.mem.indexOf(u8, trimmed, "#") orelse std.mem.indexOf(u8, trimmed, ";");
            const clean = if (cp) |c| std.mem.trimRight(u8, trimmed[0..c], " \t") else trimmed;
            if (clean.len > 0 and clean[0] != '[') {
                try entries.append(.{
                    .full_key = try cfgMakeKey(current_section, clean, allocator),
                    .value = try allocator.dupe(u8, ""),
                    .has_equals = false,
                });
            }
        }
    }
}

fn cfgMakeKey(section: ?[]const u8, variable: []const u8, allocator: std.mem.Allocator) ![]u8 {
    const sec = section orelse return try allocator.dupe(u8, variable);
    const full = try std.fmt.allocPrint(allocator, "{s}.{s}", .{ sec, variable });
    const last_dot = std.mem.lastIndexOfScalar(u8, full, '.') orelse return full;
    for (full[last_dot + 1 ..]) |*c| c.* = std.ascii.toLower(c.*);
    return full;
}

/// Normalize a config key like "Section.SubSection.Variable" ->
/// lowercase section, preserve subsection case, lowercase variable
fn cfgNormalizeKey(key_raw: []const u8, allocator: std.mem.Allocator) ![]u8 {
    const key = try allocator.dupe(u8, key_raw);
    const last_dot = std.mem.lastIndexOfScalar(u8, key, '.') orelse {
        // No dot - lowercase everything
        for (key) |*c| c.* = std.ascii.toLower(c.*);
        return key;
    };
    const first_dot = std.mem.indexOfScalar(u8, key, '.');
    if (first_dot) |fd| {
        if (fd < last_dot) {
            // Three-level key: section.subsection.variable
            // Lowercase section (before first dot) and variable (after last dot)
            for (key[0..fd]) |*c| c.* = std.ascii.toLower(c.*);
            for (key[last_dot + 1 ..]) |*c| c.* = std.ascii.toLower(c.*);
        } else {
            // Two-level key: section.variable - lowercase both
            for (key[0..fd]) |*c| c.* = std.ascii.toLower(c.*);
            for (key[last_dot + 1 ..]) |*c| c.* = std.ascii.toLower(c.*);
        }
    }
    return key;
}

fn cfgParseSectionToKey(header: []const u8, allocator: std.mem.Allocator) ![]u8 {
    const close = std.mem.indexOf(u8, header, "]") orelse return try allocator.dupe(u8, "");
    const inner = header[1..close];
    if (std.mem.indexOf(u8, inner, "\"")) |q_start| {
        const section = std.mem.trim(u8, inner[0..q_start], " \t");
        var rest = inner[q_start + 1 ..];
        if (std.mem.lastIndexOfScalar(u8, rest, '"')) |q_end| rest = rest[0..q_end];
        var sub = std.array_list.Managed(u8).init(allocator);
        defer sub.deinit();
        var si: usize = 0;
        while (si < rest.len) : (si += 1) {
            if (rest[si] == '\\' and si + 1 < rest.len) { si += 1; try sub.append(rest[si]); }
            else try sub.append(rest[si]);
        }
        const sec_lower = try allocator.dupe(u8, section);
        defer allocator.free(sec_lower);
        for (sec_lower) |*c| c.* = std.ascii.toLower(c.*);
        return try std.fmt.allocPrint(allocator, "{s}.{s}", .{ sec_lower, sub.items });
    }
    // Old-style [section.sub] (no quotes)
    const section = std.mem.trim(u8, inner, " \t");
    if (std.mem.indexOf(u8, section, ".")) |dot| {
        const sec_lower = try allocator.dupe(u8, section[0..dot]);
        defer allocator.free(sec_lower);
        for (sec_lower) |*c| c.* = std.ascii.toLower(c.*);
        // Old-style subsection is lowercased (unlike quoted subsections)
        const sub_lower = try allocator.dupe(u8, section[dot + 1 ..]);
        defer allocator.free(sub_lower);
        for (sub_lower) |*c| c.* = std.ascii.toLower(c.*);
        return try std.fmt.allocPrint(allocator, "{s}.{s}", .{ sec_lower, sub_lower });
    }
    const lower = try allocator.dupe(u8, section);
    for (lower) |*c| c.* = std.ascii.toLower(c.*);
    return lower;
}

/// Quote a config value if needed (for writing to config file)
fn cfgQuoteValue(value: []const u8, allocator: std.mem.Allocator) ![]u8 {
    var needs_quoting = false;
    if (value.len > 0 and (value[0] == ' ' or value[0] == '\t')) needs_quoting = true;
    if (value.len > 0 and (value[value.len - 1] == ' ' or value[value.len - 1] == '\t')) needs_quoting = true;
    for (value) |c| {
        if (c == '#' or c == ';' or c == '\n' or c == '\\' or c == '"') { needs_quoting = true; break; }
    }
    if (!needs_quoting) return try allocator.dupe(u8, value);
    var buf = std.array_list.Managed(u8).init(allocator);
    defer buf.deinit();
    try buf.append('"');
    for (value) |c| {
        switch (c) {
            '\n' => try buf.appendSlice("\\n"),
            '\t' => try buf.appendSlice("\\t"),
            '\\' => try buf.appendSlice("\\\\"),
            '"' => try buf.appendSlice("\\\""),
            else => try buf.append(c),
        }
    }
    try buf.append('"');
    return try buf.toOwnedSlice();
}

/// Check if trailing backslash is a real continuation (not inside a comment)
fn cfgIsContinuation(tv: []const u8) bool {
    var in_quotes = false;
    var ii: usize = 0;
    while (ii < tv.len) : (ii += 1) {
        const c = tv[ii];
        if (c == '\\' and ii + 1 < tv.len) { ii += 1; continue; }
        if (c == '"') in_quotes = !in_quotes;
        if (!in_quotes and (c == '#' or c == ';')) return false;
    }
    return true;
}

fn cfgEffectiveValue(e: CfgEntry) []const u8 {
    if (!e.has_equals and e.value.len == 0) return "true";
    return e.value;
}

fn cfgValueMatchesPattern(val: []const u8, pattern: []const u8, fixed_val: bool) bool {
    const negated = pattern.len > 0 and pattern[0] == '!';
    const actual = if (negated) pattern[1..] else pattern;
    const m = if (fixed_val) std.mem.eql(u8, val, actual) else simpleRegexMatch(val, actual);
    return if (negated) !m else m;
}

fn cfgAppendValuePart(buf: *std.array_list.Managed(u8), raw: []const u8) !void {
    const trimmed = std.mem.trimLeft(u8, raw, " \t");
    var in_quotes = false;
    var last_quoted_end: usize = 0;
    var ii: usize = 0;
    while (ii < trimmed.len) : (ii += 1) {
        const c = trimmed[ii];
        if (c == '\\' and ii + 1 < trimmed.len) {
            ii += 1;
            switch (trimmed[ii]) {
                'n' => try buf.append('\n'),
                't' => try buf.append('\t'),
                'b' => try buf.append(0x08),
                '"' => try buf.append('"'),
                '\\' => try buf.append('\\'),
                else => { try buf.append('\\'); try buf.append(trimmed[ii]); },
            }
            if (in_quotes) last_quoted_end = buf.items.len;
        } else if (c == '"') {
            if (in_quotes) last_quoted_end = buf.items.len;
            in_quotes = !in_quotes;
        } else if (!in_quotes and (c == '#' or c == ';')) {
            break;
        } else {
            try buf.append(c);
            if (in_quotes) last_quoted_end = buf.items.len;
        }
    }
    if (!in_quotes) {
        while (buf.items.len > last_quoted_end and
            (buf.items[buf.items.len - 1] == ' ' or buf.items[buf.items.len - 1] == '\t'))
            _ = buf.pop();
    }
}

fn cfgKeyMatches(full_key: []const u8, query: []const u8) bool {
    const q_last = std.mem.lastIndexOfScalar(u8, query, '.') orelse return false;
    const k_last = std.mem.lastIndexOfScalar(u8, full_key, '.') orelse return false;
    if (!std.ascii.eqlIgnoreCase(full_key[k_last + 1 ..], query[q_last + 1 ..])) return false;
    const q_prefix = query[0..q_last];
    const k_prefix = full_key[0..k_last];
    const q_first = std.mem.indexOfScalar(u8, q_prefix, '.');
    const k_first = std.mem.indexOfScalar(u8, k_prefix, '.');
    if (q_first != null and k_first != null) {
        if (!std.ascii.eqlIgnoreCase(q_prefix[0..q_first.?], k_prefix[0..k_first.?])) return false;
        return std.mem.eql(u8, k_prefix[k_first.? + 1 ..], q_prefix[q_first.? + 1 ..]);
    }
    if (q_first == null and k_first == null) return std.ascii.eqlIgnoreCase(k_prefix, q_prefix);
    return false;
}

fn cfgFormatType(value: []const u8, config_type: ConfigType, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    switch (config_type) {
        .bool_type => {
            const lower = try std.ascii.allocLowerString(allocator, value);
            defer allocator.free(lower);
            if (value.len == 0) return try allocator.dupe(u8, "false");
            if (std.mem.eql(u8, lower, "true") or std.mem.eql(u8, lower, "yes") or std.mem.eql(u8, lower, "on") or std.mem.eql(u8, lower, "1"))
                return try allocator.dupe(u8, "true");
            if (std.mem.eql(u8, lower, "false") or std.mem.eql(u8, lower, "no") or std.mem.eql(u8, lower, "off") or std.mem.eql(u8, lower, "0"))
                return try allocator.dupe(u8, "false");
            const tbm2 = std.mem.trim(u8, value, " \t");
            if (std.fmt.parseInt(i64, tbm2, 10)) |num|
                return try allocator.dupe(u8, if (num != 0) "true" else "false")
            else |_| {
                if (tbm2.len > 1) {
                    const lbm2 = tbm2[tbm2.len - 1];
                    if (lbm2 == 'k' or lbm2 == 'K' or lbm2 == 'm' or lbm2 == 'M' or lbm2 == 'g' or lbm2 == 'G') {
                        if (std.fmt.parseInt(i64, tbm2[0 .. tbm2.len - 1], 10)) |n3|
                            return try allocator.dupe(u8, if (n3 != 0) "true" else "false")
                        else |_| {}
                    }
                }
            }
            const em = try std.fmt.allocPrint(allocator, "fatal: bad boolean config value '{s}'\n", .{value});
            defer allocator.free(em);
            try platform_impl.writeStderr(em);
            std.process.exit(128);
        },
        .int_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len == 0) {
                try platform_impl.writeStderr("fatal: bad numeric config value\n");
                std.process.exit(128);
            }
            const last = trimmed[trimmed.len - 1];
            if (last == 'k' or last == 'K' or last == 'm' or last == 'M' or last == 'g' or last == 'G') {
                if (std.fmt.parseInt(i64, trimmed[0 .. trimmed.len - 1], 10)) |num| {
                    const mult: i64 = switch (last) { 'k', 'K' => 1024, 'm', 'M' => 1048576, 'g', 'G' => 1073741824, else => 1 };
                    return try std.fmt.allocPrint(allocator, "{d}", .{num * mult});
                } else |_| {}
            }
            if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            const em = try std.fmt.allocPrint(allocator, "fatal: bad numeric config value '{s}'\n", .{value});
            defer allocator.free(em);
            try platform_impl.writeStderr(em);
            std.process.exit(128);
        },
        .bool_or_int => {
            const lower = try std.ascii.allocLowerString(allocator, value);
            defer allocator.free(lower);
            if (value.len == 0) return try allocator.dupe(u8, "false");
            if (std.mem.eql(u8, lower, "true") or std.mem.eql(u8, lower, "yes") or std.mem.eql(u8, lower, "on"))
                return try allocator.dupe(u8, "true");
            if (std.mem.eql(u8, lower, "false") or std.mem.eql(u8, lower, "no") or std.mem.eql(u8, lower, "off"))
                return try allocator.dupe(u8, "false");
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len > 0) {
                const l = trimmed[trimmed.len - 1];
                if (l == 'k' or l == 'K' or l == 'm' or l == 'M' or l == 'g' or l == 'G') {
                    if (std.fmt.parseInt(i64, trimmed[0 .. trimmed.len - 1], 10)) |num| {
                        const mult: i64 = switch (l) { 'k', 'K' => 1024, 'm', 'M' => 1048576, 'g', 'G' => 1073741824, else => 1 };
                        return try std.fmt.allocPrint(allocator, "{d}", .{num * mult});
                    } else |_| {}
                }
                if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            }
            return try allocator.dupe(u8, value);
        },
        .path_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len == 0) { try platform_impl.writeStderr("fatal: no path for 'path' type\n"); std.process.exit(128); }
            if (trimmed[0] == '~' and (trimmed.len == 1 or trimmed[1] == '/')) {
                const h = std.process.getEnvVarOwned(allocator, "HOME") catch { try platform_impl.writeStderr("fatal: could not expand '~'\n"); std.process.exit(128); };
                defer allocator.free(h);
                if (trimmed.len == 1) return try allocator.dupe(u8, h);
                return try std.fmt.allocPrint(allocator, "{s}{s}", .{ h, trimmed[1..] });
            }
            return try allocator.dupe(u8, trimmed);
        },
        .expiry_date => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (std.mem.eql(u8, trimmed, "never") or std.mem.eql(u8, trimmed, "false")) return try allocator.dupe(u8, "0");
            if (std.mem.eql(u8, trimmed, "now")) return try std.fmt.allocPrint(allocator, "{d}", .{std.time.timestamp()});
            if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            const em = try std.fmt.allocPrint(allocator, "fatal: '{s}' is not a valid timestamp\n", .{value});
            defer allocator.free(em);
            try platform_impl.writeStderr(em);
            std.process.exit(128);
        },
        .color_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (cfgValidateColor(trimmed)) return try cfgColorToAnsiAlloc(trimmed, allocator);
            const em = try std.fmt.allocPrint(allocator, "error: invalid color value: {s}\n", .{value});
            defer allocator.free(em);
            try platform_impl.writeStderr(em);
            std.process.exit(1);
        },
        .none => return try allocator.dupe(u8, value),
    }
}

fn cfgFormatTypeWithContext(value: []const u8, config_type: ConfigType, key_name: ?[]const u8, source_path: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    switch (config_type) {
        .bool_type => {
            const r = cfgFormatTypeSilent(value, config_type, allocator) catch {
                if (key_name) |kn| {
                    const em = try std.fmt.allocPrint(allocator, "fatal: bad boolean config value '{s}' for '{s}'\n", .{ value, kn });
                    defer allocator.free(em);
                    try platform_impl.writeStderr(em);
                } else {
                    const em = try std.fmt.allocPrint(allocator, "fatal: bad boolean config value '{s}'\n", .{value});
                    defer allocator.free(em);
                    try platform_impl.writeStderr(em);
                }
                std.process.exit(128);
            };
            return r;
        },
        .int_type => {
            const r = cfgFormatTypeSilent(value, config_type, allocator) catch {
                if (key_name) |kn| {
                    if (source_path) |sp| {
                        const em = try std.fmt.allocPrint(allocator, "fatal: bad numeric config value '{s}' for '{s}' in file {s}: invalid unit\n", .{ value, kn, sp });
                        defer allocator.free(em);
                        try platform_impl.writeStderr(em);
                    } else {
                        const em = try std.fmt.allocPrint(allocator, "fatal: bad numeric config value '{s}' for '{s}': invalid unit\n", .{ value, kn });
                        defer allocator.free(em);
                        try platform_impl.writeStderr(em);
                    }
                } else {
                    const em = try std.fmt.allocPrint(allocator, "fatal: bad numeric config value '{s}'\n", .{value});
                    defer allocator.free(em);
                    try platform_impl.writeStderr(em);
                }
                std.process.exit(128);
            };
            return r;
        },
        .path_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len == 0) return try allocator.dupe(u8, "");
            if (trimmed[0] == '~' and (trimmed.len == 1 or trimmed[1] == '/')) {
                const h = std.process.getEnvVarOwned(allocator, "HOME") catch {
                    if (key_name) |kn| {
                        const em = try std.fmt.allocPrint(allocator, "fatal: failed to expand user dir in: '{s}'\n", .{kn});
                        defer allocator.free(em);
                        try platform_impl.writeStderr(em);
                    } else try platform_impl.writeStderr("fatal: could not expand '~'\n");
                    std.process.exit(128);
                };
                defer allocator.free(h);
                if (trimmed.len == 1) return try allocator.dupe(u8, h);
                return try std.fmt.allocPrint(allocator, "{s}{s}", .{ h, trimmed[1..] });
            }
            return try allocator.dupe(u8, trimmed);
        },
        else => return cfgFormatType(value, config_type, allocator, platform_impl),
    }
}

fn cfgFormatTypeSilent(value: []const u8, config_type: ConfigType, allocator: std.mem.Allocator) ![]u8 {
    switch (config_type) {
        .bool_type => {
            const lower = try std.ascii.allocLowerString(allocator, value);
            defer allocator.free(lower);
            if (value.len == 0) return try allocator.dupe(u8, "false");
            if (std.mem.eql(u8, lower, "true") or std.mem.eql(u8, lower, "yes") or std.mem.eql(u8, lower, "on") or std.mem.eql(u8, lower, "1"))
                return try allocator.dupe(u8, "true");
            if (std.mem.eql(u8, lower, "false") or std.mem.eql(u8, lower, "no") or std.mem.eql(u8, lower, "off") or std.mem.eql(u8, lower, "0"))
                return try allocator.dupe(u8, "false");
            const tb2 = std.mem.trim(u8, value, " \t");
            if (std.fmt.parseInt(i64, tb2, 10)) |num|
                return try allocator.dupe(u8, if (num != 0) "true" else "false")
            else |_| {
                if (tb2.len > 1) {
                    const lb2 = tb2[tb2.len - 1];
                    if (lb2 == 'k' or lb2 == 'K' or lb2 == 'm' or lb2 == 'M' or lb2 == 'g' or lb2 == 'G') {
                        if (std.fmt.parseInt(i64, tb2[0 .. tb2.len - 1], 10)) |n2|
                            return try allocator.dupe(u8, if (n2 != 0) "true" else "false")
                        else |_| {}
                    }
                }
            }
            return error.InvalidValue;
        },
        .int_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len == 0) return error.InvalidValue;
            // Must start with a digit or sign
            if (trimmed.len > 0 and !std.ascii.isDigit(trimmed[0]) and trimmed[0] != '-' and trimmed[0] != '+') return error.InvalidValue;
            const last = trimmed[trimmed.len - 1];
            if (last == 'k' or last == 'K' or last == 'm' or last == 'M' or last == 'g' or last == 'G') {
                if (std.fmt.parseInt(i64, trimmed[0 .. trimmed.len - 1], 10)) |num| {
                    const mult: i64 = switch (last) { 'k', 'K' => 1024, 'm', 'M' => 1048576, 'g', 'G' => 1073741824, else => 1 };
                    return try std.fmt.allocPrint(allocator, "{d}", .{num * mult});
                } else |_| {}
            }
            if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            return error.InvalidValue;
        },
        .bool_or_int => {
            const lower = try std.ascii.allocLowerString(allocator, value);
            defer allocator.free(lower);
            if (value.len == 0) return try allocator.dupe(u8, "false");
            if (std.mem.eql(u8, lower, "true") or std.mem.eql(u8, lower, "yes") or std.mem.eql(u8, lower, "on"))
                return try allocator.dupe(u8, "true");
            if (std.mem.eql(u8, lower, "false") or std.mem.eql(u8, lower, "no") or std.mem.eql(u8, lower, "off"))
                return try allocator.dupe(u8, "false");
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len > 0) {
                const l = trimmed[trimmed.len - 1];
                if (l == 'k' or l == 'K' or l == 'm' or l == 'M' or l == 'g' or l == 'G') {
                    if (std.fmt.parseInt(i64, trimmed[0 .. trimmed.len - 1], 10)) |num| {
                        const mult: i64 = switch (l) { 'k', 'K' => 1024, 'm', 'M' => 1048576, 'g', 'G' => 1073741824, else => 1 };
                        return try std.fmt.allocPrint(allocator, "{d}", .{num * mult});
                    } else |_| {}
                }
                if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            }
            return error.InvalidValue;
        },
        .path_type => return try allocator.dupe(u8, std.mem.trim(u8, value, " \t")),
        .expiry_date => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (std.mem.eql(u8, trimmed, "never") or std.mem.eql(u8, trimmed, "false")) return try allocator.dupe(u8, "0");
            if (std.mem.eql(u8, trimmed, "now")) return try std.fmt.allocPrint(allocator, "{d}", .{std.time.timestamp()});
            if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            if (cfgParseDate(trimmed, allocator)) |ts| return ts;
            return error.InvalidValue;
        },
        .color_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (cfgValidateColor(trimmed)) return try cfgColorToAnsiAlloc(trimmed, allocator);
            return error.InvalidValue;
        },
        .none => return try allocator.dupe(u8, value),
    }
}

fn cfgParseDate(date_str: []const u8, allocator: std.mem.Allocator) ?[]u8 {
    const result = std.process.Child.run(.{
        .allocator = allocator,
        .argv = &[_][]const u8{ "date", "-d", date_str, "+%s" },
    }) catch return null;
    defer allocator.free(result.stdout);
    defer allocator.free(result.stderr);
    if (result.term.Exited != 0) return null;
    const trimmed = std.mem.trimRight(u8, result.stdout, " \t\n\r");
    if (trimmed.len == 0) return null;
    return allocator.dupe(u8, trimmed) catch null;
}

fn cfgMakeRelativePath(abs_path: []const u8, allocator: std.mem.Allocator) ![]u8 {
    const cwd = std.fs.cwd().realpathAlloc(allocator, ".") catch return try allocator.dupe(u8, abs_path);
    defer allocator.free(cwd);
    if (std.mem.startsWith(u8, abs_path, cwd)) {
        const rel = abs_path[cwd.len..];
        if (rel.len > 0 and rel[0] == '/') return try allocator.dupe(u8, rel[1..]);
        if (rel.len == 0) return try allocator.dupe(u8, ".");
    }
    return try allocator.dupe(u8, abs_path);
}

fn cfgRemoveEmptySections(cont: []const u8, allocator: std.mem.Allocator) ![]u8 {
    var lines_list = std.array_list.Managed([]const u8).init(allocator);
    defer lines_list.deinit();
    var iter_sec = std.mem.splitSequence(u8, cont, "\n");
    while (iter_sec.next()) |line| try lines_list.append(line);
    const lines_arr = lines_list.items;
    var res = std.array_list.Managed(u8).init(allocator);
    defer res.deinit();
    var idx_s: usize = 0;
    while (idx_s < lines_arr.len) {
        const line = lines_arr[idx_s];
        const tr = std.mem.trim(u8, line, " \t\r");
        if (tr.len > 0 and tr[0] == '[') {
            // Check for inline content after ] on same line
            const close_b = std.mem.indexOf(u8, tr, "]");
            if (close_b) |cb| {
                const after = std.mem.trim(u8, tr[cb + 1 ..], " \t");
                if (after.len > 0 and after[0] != '#' and after[0] != ';') {
                    // Has inline content, keep this section
                    if (res.items.len > 0) try res.append('\n');
                    try res.appendSlice(line);
                    idx_s += 1;
                    continue;
                }
            }
            var has_c = false;
            var has_cm = false;
            var j: usize = idx_s + 1;
            while (j < lines_arr.len) {
                const nl = std.mem.trim(u8, lines_arr[j], " \t\r");
                if (nl.len > 0 and nl[0] == '[') break;
                if (nl.len > 0 and (nl[0] == '#' or nl[0] == ';')) { has_cm = true; }
                else if (nl.len > 0) { has_c = true; break; }
                j += 1;
            }
            if (!has_c and !has_cm) { idx_s = j; continue; }
        }
        if (res.items.len > 0) try res.append('\n');
        try res.appendSlice(line);
        idx_s += 1;
    }
    if (cont.len > 0 and cont[cont.len - 1] == '\n') {
        if (res.items.len > 0 and res.items[res.items.len - 1] != '\n')
            try res.append('\n');
    }
    return try res.toOwnedSlice();
}

fn cfgAppendOrigin(out: *std.array_list.Managed(u8), source_path: []const u8) !void {
    if (std.mem.eql(u8, source_path, "standard input")) {
        try out.appendSlice("standard input:");
    } else if (std.mem.eql(u8, source_path, "command line")) {
        try out.appendSlice("command line:");
    } else {
        var needs_quote = false;
        for (source_path) |c| {
            if (c == '"' or c == ' ' or c == '(' or c == ')') { needs_quote = true; break; }
        }
        if (needs_quote) {
            try out.appendSlice("file:\"");
            for (source_path) |c| {
                if (c == '"') { try out.appendSlice("\\\""); }
                else try out.append(c);
            }
            try out.append('"');
        } else {
            try out.appendSlice("file:");
            try out.appendSlice(source_path);
        }
    }
}

fn cfgValidateColor(color: []const u8) bool {
    if (color.len == 0) return true;
    const valid = [_][]const u8{ "normal", "black", "red", "green", "yellow", "blue", "magenta", "cyan", "white", "default", "reset", "bold", "dim", "ul", "blink", "reverse", "italic", "strike", "nobold", "nodim", "noul", "noblink", "noreverse", "noitalic", "nostrike", "no-bold", "no-dim", "no-ul", "no-blink", "no-reverse", "no-italic", "no-strike", "brightred", "brightgreen", "brightyellow", "brightblue", "brightmagenta", "brightcyan", "brightwhite" };
    var parts = std.mem.splitSequence(u8, color, " ");
    while (parts.next()) |part| {
        if (part.len == 0) continue;
        var found = false;
        for (valid) |vc| { if (std.ascii.eqlIgnoreCase(part, vc)) { found = true; break; } }
        if (!found) {
            if (part[0] == '#' and part.len == 7) { found = true; }
            else if (std.fmt.parseInt(u8, part, 10)) |_| { found = true; } else |_| {}
        }
        if (!found) return false;
    }
    return true;
}

fn cfgColorToAnsiAlloc(color: []const u8, allocator: std.mem.Allocator) ![]u8 {
    if (color.len == 0) return try allocator.dupe(u8, "");
    var buf = std.array_list.Managed(u8).init(allocator);
    defer buf.deinit();
    try buf.appendSlice("\x1b[");
    var first = true;
    var have_fg = false;
    var parts = std.mem.splitSequence(u8, color, " ");
    while (parts.next()) |part| {
        if (part.len == 0) continue;
        if (!first) try buf.append(';');
        first = false;
        if (std.ascii.eqlIgnoreCase(part, "reset") or std.ascii.eqlIgnoreCase(part, "normal")) {
            // reset
        } else if (std.ascii.eqlIgnoreCase(part, "bold")) { try buf.appendSlice("1"); }
        else if (std.ascii.eqlIgnoreCase(part, "dim")) { try buf.appendSlice("2"); }
        else if (std.ascii.eqlIgnoreCase(part, "italic")) { try buf.appendSlice("3"); }
        else if (std.ascii.eqlIgnoreCase(part, "ul")) { try buf.appendSlice("4"); }
        else if (std.ascii.eqlIgnoreCase(part, "blink")) { try buf.appendSlice("5"); }
        else if (std.ascii.eqlIgnoreCase(part, "reverse")) { try buf.appendSlice("7"); }
        else if (std.ascii.eqlIgnoreCase(part, "strike")) { try buf.appendSlice("9"); }
        else if (std.ascii.eqlIgnoreCase(part, "black")) { try buf.appendSlice(if (!have_fg) "30" else "40"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "red")) { try buf.appendSlice(if (!have_fg) "31" else "41"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "green")) { try buf.appendSlice(if (!have_fg) "32" else "42"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "yellow")) { try buf.appendSlice(if (!have_fg) "33" else "43"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "blue")) { try buf.appendSlice(if (!have_fg) "34" else "44"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "magenta")) { try buf.appendSlice(if (!have_fg) "35" else "45"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "cyan")) { try buf.appendSlice(if (!have_fg) "36" else "46"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "white")) { try buf.appendSlice(if (!have_fg) "37" else "47"); have_fg = true; }
        else if (std.ascii.eqlIgnoreCase(part, "default")) { try buf.appendSlice(if (!have_fg) "39" else "49"); have_fg = true; }
        else {}
    }
    try buf.append('m');
    return try buf.toOwnedSlice();
}

fn cfgOutputList(content: []const u8, source_path: []const u8, scope: []const u8, null_term: bool, name_only: bool, show_origin: bool, show_scope: bool, config_type: ConfigType, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    try cfgValidateAndReport(content, source_path, allocator, platform_impl);
    var entries = std.array_list.Managed(CfgEntry).init(allocator);
    defer { for (entries.items) |*e| e.deinit(allocator); entries.deinit(); }
    try cfgParseEntries(content, &entries, allocator);
    for (entries.items) |e| {
        const term: []const u8 = if (null_term) "\x00" else "\n";
        var out = std.array_list.Managed(u8).init(allocator);
        defer out.deinit();
        if (show_scope) { try out.appendSlice(scope); try out.append('\t'); }
        if (show_origin) {
            try cfgAppendOrigin(&out, source_path);
            try out.append('\t');
        }
        if (name_only) {
            try out.appendSlice(e.full_key);
        } else if (config_type != .none) {
            const fmt2 = cfgFormatTypeSilent(cfgEffectiveValue(e), config_type, allocator) catch continue;
            defer allocator.free(fmt2);
            try out.appendSlice(e.full_key);
            if (null_term) try out.append('\n') else try out.append('=');
            try out.appendSlice(fmt2);
        } else if (e.has_equals) {
            try out.appendSlice(e.full_key);
            if (null_term) try out.append('\n') else try out.append('=');
            try out.appendSlice(e.value);
        } else {
            try out.appendSlice(e.full_key);
            if (!null_term) try out.append('=');
        }
        try out.appendSlice(term);
        try platform_impl.writeStdout(out.items);
    }
}

fn cfgLookup(sources: []const ConfigSource, key: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    var result: ?[]u8 = null;
    for (sources) |source| {
        const content = cfgReadSource(source.path, allocator, platform_impl) orelse continue;
        defer allocator.free(content);
        var entries = std.array_list.Managed(CfgEntry).init(allocator);
        defer { for (entries.items) |*e| e.deinit(allocator); entries.deinit(); }
        cfgParseEntries(content, &entries, allocator) catch continue;
        for (entries.items) |e| {
            if (cfgKeyMatches(e.full_key, key)) {
                if (result) |prev| allocator.free(prev);
                result = try allocator.dupe(u8, e.value);
            }
        }
    }
    if (getConfigOverride(key)) |ov| {
        if (result) |prev| allocator.free(prev);
        return try allocator.dupe(u8, ov);
    }
    return result orelse error.KeyNotFound;
}

fn cfgIsValidKey(key: []const u8) bool {
    const dot = std.mem.indexOfScalar(u8, key, '.') orelse return false;
    if (dot == 0) return false;
    if (!std.ascii.isAlphanumeric(key[0])) return false;
    for (key[0..dot]) |c| { if (!std.ascii.isAlphanumeric(c) and c != '-') return false; }
    const last_dot = std.mem.lastIndexOfScalar(u8, key, '.') orelse return false;
    if (last_dot + 1 >= key.len) return false;
    const vn = key[last_dot + 1 ..];
    if (!std.ascii.isAlphabetic(vn[0])) return false;
    for (vn) |c| { if (!std.ascii.isAlphanumeric(c) and c != '-') return false; }
    return true;
}

fn cfgIsValidSectionName(name: []const u8) bool {
    if (name.len == 0) return false;
    const dot = std.mem.indexOfScalar(u8, name, '.');
    const section = if (dot) |d| name[0..d] else name;
    if (section.len == 0) return false;
    if (!std.ascii.isAlphabetic(section[0])) return false;
    for (section) |c| { if (!std.ascii.isAlphanumeric(c) and c != '-') return false; }
    return true;
}

fn cfgFormatComment(comment_raw: ?[]const u8, allocator: std.mem.Allocator) ![]u8 {
    if (comment_raw) |c| {
        if (c.len > 0 and c[0] == '#') return try std.fmt.allocPrint(allocator, " {s}", .{c});
        if (c.len > 0 and c[0] == '\t') return try allocator.dupe(u8, c);
        return try std.fmt.allocPrint(allocator, " # {s}", .{c});
    }
    return try allocator.dupe(u8, "");
}

const CfgParsedKey = struct { section: []u8, subsection: ?[]u8, variable: []u8 };

fn cfgParseKey(key: []const u8, allocator: std.mem.Allocator) !CfgParsedKey {
    const last_dot = std.mem.lastIndexOfScalar(u8, key, '.') orelse return error.InvalidKey;
    const variable = key[last_dot + 1 ..];
    const prefix = key[0..last_dot];
    if (std.mem.indexOfScalar(u8, prefix, '.')) |first_dot| {
        return .{
            .section = try allocator.dupe(u8, prefix[0..first_dot]),
            .subsection = try allocator.dupe(u8, prefix[first_dot + 1 ..]),
            .variable = try allocator.dupe(u8, variable),
        };
    }
    return .{ .section = try allocator.dupe(u8, prefix), .subsection = null, .variable = try allocator.dupe(u8, variable) };
}

fn cfgSectionMatches(file_section: []const u8, file_subsection: ?[]const u8, parsed: CfgParsedKey) bool {
    return cfgSectionMatchesEx(file_section, file_subsection, false, parsed);
}

fn cfgSectionMatchesEx(file_section: []const u8, file_subsection: ?[]const u8, is_old_style: bool, parsed: CfgParsedKey) bool {
    if (!std.ascii.eqlIgnoreCase(file_section, parsed.section)) return false;
    if (parsed.subsection) |ps| {
        if (file_subsection) |fs| {
            // Old-style [section.sub] subsections are case-insensitive
            if (is_old_style) return std.ascii.eqlIgnoreCase(fs, ps);
            return std.mem.eql(u8, fs, ps);
        }
        return false;
    }
    return file_subsection == null;
}

fn cfgSetValue(cfg_path: []const u8, key: []const u8, value: []const u8, do_add: bool, replace_all: bool, value_regex: ?[]const u8, fixed_val: bool, comment: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const pk = cfgParseKey(key, allocator) catch {
        try platform_impl.writeStderr("error: key does not contain a section\n");
        std.process.exit(2);
    };
    defer allocator.free(pk.section);
    defer if (pk.subsection) |s| allocator.free(s);
    defer allocator.free(pk.variable);

    const content = platform_impl.fs.readFile(allocator, cfg_path) catch |err| switch (err) {
        error.FileNotFound => {
            const cs = try cfgFormatComment(comment, allocator);
            defer allocator.free(cs);
            var out = std.array_list.Managed(u8).init(allocator);
            defer out.deinit();
            const qv = try cfgQuoteValue(value, allocator);
            defer allocator.free(qv);
            if (pk.subsection) |sub| { try out.writer().print("[{s} \"{s}\"]\n", .{ pk.section, sub }); }
            else { try out.writer().print("[{s}]\n", .{pk.section}); }
            try out.writer().print("\t{s} = {s}{s}\n", .{ pk.variable, qv, cs });
            try platform_impl.fs.writeFile(cfg_path, out.items);
            return;
        },
        else => return err,
    };
    defer allocator.free(content);

    // Track lines and their properties
    const LI = struct { start: usize, end: usize, cont_end: usize, is_key: bool, regex_ok: bool, inline_on_header: bool };
    var infos = std.array_list.Managed(LI).init(allocator);
    defer infos.deinit();

    var cur_sec: ?[]u8 = null;
    var cur_sub: ?[]u8 = null;
    defer if (cur_sec) |s| allocator.free(s);
    defer if (cur_sub) |s| allocator.free(s);
    var in_target = false;
    var last_target_end: usize = 0;
    var section_found = false;

    var pos: usize = 0;
    while (pos < content.len) {
        const ls = pos;
        const nl = std.mem.indexOfPos(u8, content, pos, "\n") orelse content.len;
        const line = content[pos..nl];
        const le = if (nl < content.len) nl + 1 else nl;
        pos = le;
        const trimmed = std.mem.trim(u8, std.mem.trimRight(u8, line, "\r"), " \t");

        if (trimmed.len > 0 and trimmed[0] == '[') {
            if (cur_sec) |s| allocator.free(s);
            if (cur_sub) |s| allocator.free(s);
            cur_sec = null; cur_sub = null;
            const close = std.mem.indexOf(u8, trimmed, "]");
            if (close) |cl| {
                const inner = trimmed[1..cl];
                if (std.mem.indexOf(u8, inner, "\"")) |q| {
                    cur_sec = try allocator.dupe(u8, std.mem.trim(u8, inner[0..q], " \t"));
                    var r = inner[q + 1 ..];
                    if (std.mem.lastIndexOfScalar(u8, r, '"')) |q2| r = r[0..q2];
                    var sb = std.array_list.Managed(u8).init(allocator);
                    defer sb.deinit();
                    var si: usize = 0;
                    while (si < r.len) : (si += 1) {
                        if (r[si] == '\\' and si + 1 < r.len) { si += 1; try sb.append(r[si]); }
                        else try sb.append(r[si]);
                    }
                    cur_sub = try sb.toOwnedSlice();
                } else if (std.mem.indexOf(u8, inner, ".")) |d| {
                    cur_sec = try allocator.dupe(u8, std.mem.trim(u8, inner[0..d], " \t"));
                    // Old-style [section.sub] - subsection is case-insensitive (lowercased)
                    const oldsub1 = try allocator.dupe(u8, inner[d + 1 ..]);
                    for (oldsub1) |*c| c.* = std.ascii.toLower(c.*);
                    cur_sub = oldsub1;
                } else {
                    cur_sec = try allocator.dupe(u8, std.mem.trim(u8, inner, " \t"));
                }
            }
            in_target = if (cur_sec) |cs| cfgSectionMatches(cs, cur_sub, pk) else false;
            if (in_target) section_found = true;
            // Check for inline key=value after ]
            if (in_target and close != null) {
                const after_bracket = std.mem.trim(u8, trimmed[close.? + 1 ..], " \t");
                if (after_bracket.len > 0 and after_bracket[0] != '#' and after_bracket[0] != ';') {
                    if (std.mem.indexOf(u8, after_bracket, "=")) |aeq| {
                        const ak = std.mem.trim(u8, after_bracket[0..aeq], " \t");
                        if (std.ascii.eqlIgnoreCase(ak, pk.variable)) {
                            var vbuf2 = std.array_list.Managed(u8).init(allocator);
                            defer vbuf2.deinit();
                            cfgAppendValuePart(&vbuf2, after_bracket[aeq + 1 ..]) catch {};
                            var rok2 = true;
                            if (value_regex) |vr| {
                                const neg2 = vr.len > 0 and vr[0] == '!';
                                const act2 = if (neg2) vr[1..] else vr;
                                const m2 = if (fixed_val) std.mem.eql(u8, vbuf2.items, act2) else simpleRegexMatch(vbuf2.items, act2);
                                rok2 = if (neg2) !m2 else m2;
                            }
                            try infos.append(.{ .start = ls, .end = le, .cont_end = le, .is_key = true, .regex_ok = rok2, .inline_on_header = true });
                            last_target_end = le;
                            continue;
                        }
                    }
                }
            }
            try infos.append(.{ .start = ls, .end = le, .cont_end = le, .is_key = false, .regex_ok = false, .inline_on_header = false });
            if (in_target) last_target_end = le;
            continue;
        }

        if (in_target and trimmed.len > 0 and trimmed[0] != '#' and trimmed[0] != ';') {
            if (std.mem.indexOf(u8, trimmed, "=")) |eq| {
                const k = std.mem.trim(u8, trimmed[0..eq], " \t");
                if (std.ascii.eqlIgnoreCase(k, pk.variable)) {
                    var ce = le;
                    // Find continuation end
                    const raw_v = trimmed[eq + 1 ..];
                    const tv = std.mem.trimRight(u8, raw_v, " \t");
                    if (tv.len > 0 and tv[tv.len - 1] == '\\' and cfgIsContinuation(tv)) {
                        var sp = pos;
                        while (sp < content.len) {
                            const cnl = std.mem.indexOfPos(u8, content, sp, "\n") orelse content.len;
                            const cl2 = content[sp..cnl];
                            ce = if (cnl < content.len) cnl + 1 else cnl;
                            sp = ce;
                            const ct = std.mem.trimRight(u8, std.mem.trimRight(u8, cl2, "\r"), " \t");
                            if (ct.len == 0 or ct[ct.len - 1] != '\\') break;
                        }
                    }
                    // Parse value for regex matching
                    var vbuf = std.array_list.Managed(u8).init(allocator);
                    defer vbuf.deinit();
                    // Simple: just parse the first line value for now
                    cfgAppendValuePart(&vbuf, raw_v) catch {};
                    if (ce > le) {
                        // Re-parse with continuations
                        vbuf.clearRetainingCapacity();
                        var vl = trimmed[eq + 1 ..];
                        var vp2 = pos;
                        while (true) {
                            const vt = std.mem.trimRight(u8, vl, " \t");
                            if (vt.len > 0 and vt[vt.len - 1] == '\\') {
                                cfgAppendValuePart(&vbuf, vt[0 .. vt.len - 1]) catch {};
                                if (vp2 < content.len) {
                                    const vnl = std.mem.indexOfPos(u8, content, vp2, "\n") orelse content.len;
                                    vl = std.mem.trim(u8, std.mem.trimRight(u8, content[vp2..vnl], "\r"), " \t");
                                    vp2 = if (vnl < content.len) vnl + 1 else vnl;
                                } else break;
                            } else { cfgAppendValuePart(&vbuf, vl) catch {}; break; }
                        }
                    }
                    var rok = true;
                    if (value_regex) |vr| {
                        const neg = vr.len > 0 and vr[0] == '!';
                        const act = if (neg) vr[1..] else vr;
                        const m = if (fixed_val) std.mem.eql(u8, vbuf.items, act) else simpleRegexMatch(vbuf.items, act);
                        rok = if (neg) !m else m;
                    }
                    try infos.append(.{ .start = ls, .end = le, .cont_end = ce, .is_key = true, .regex_ok = rok, .inline_on_header = false });
                    last_target_end = ce;
                    if (ce > le) pos = ce;
                    continue;
                }
            }
        }
        try infos.append(.{ .start = ls, .end = le, .cont_end = le, .is_key = false, .regex_ok = false, .inline_on_header = false });
        if (in_target) last_target_end = le;
    }

    var match_count: usize = 0;
    var rmatch_count: usize = 0;
    for (infos.items) |li| {
        if (li.is_key) match_count += 1;
        if (li.is_key and li.regex_ok) rmatch_count += 1;
    }

    const cs = try cfgFormatComment(comment, allocator);
    defer allocator.free(cs);
    const qv = try cfgQuoteValue(value, allocator);
    defer allocator.free(qv);
    const new_line = try std.fmt.allocPrint(allocator, "\t{s} = {s}{s}\n", .{ pk.variable, qv, cs });
    defer allocator.free(new_line);

    const writeReplacement = struct {
        fn f(res: *std.array_list.Managed(u8), li: LI, nl: []const u8, cont: []const u8) !void {
            if (li.inline_on_header) {
                const line_data = cont[li.start..li.end];
                const cb = std.mem.indexOf(u8, line_data, "]");
                if (cb) |c| { try res.appendSlice(line_data[0 .. c + 1]); try res.append('\n'); }
                try res.appendSlice(nl);
            } else {
                try res.appendSlice(nl);
            }
        }
    };

    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();

    if (do_add) {
        if (section_found) {
            try result.appendSlice(content[0..last_target_end]);
            try result.appendSlice(new_line);
            if (last_target_end < content.len) try result.appendSlice(content[last_target_end..]);
        } else {
            try result.appendSlice(content);
            if (pk.subsection) |sub| { try result.writer().print("[{s} \"{s}\"]\n", .{ pk.section, sub }); }
            else { try result.writer().print("[{s}]\n", .{pk.section}); }
            try result.appendSlice(new_line);
        }
        try platform_impl.fs.writeFile(cfg_path, result.items);
        return;
    }

    if (replace_all) {
        if (rmatch_count == 0 and match_count == 0) {
            // Add new
            if (section_found) {
                try result.appendSlice(content[0..last_target_end]);
                try result.appendSlice(new_line);
                if (last_target_end < content.len) try result.appendSlice(content[last_target_end..]);
            } else {
                try result.appendSlice(content);
                if (pk.subsection) |sub| { try result.writer().print("[{s} \"{s}\"]\n", .{ pk.section, sub }); }
                else { try result.writer().print("[{s}]\n", .{pk.section}); }
                try result.appendSlice(new_line);
            }
        } else {
            var last_idx: ?usize = null;
            for (infos.items, 0..) |li, idx| { if (li.is_key and li.regex_ok) last_idx = idx; }
            for (infos.items, 0..) |li, idx| {
                if (li.is_key and li.regex_ok) {
                    if (idx == last_idx.?) try writeReplacement.f(&result, li, new_line, content);
                } else try result.appendSlice(content[li.start..li.cont_end]);
            }
        }
        try platform_impl.fs.writeFile(cfg_path, result.items);
        return;
    }

    // Normal set
    if (value_regex != null) {
        if (rmatch_count == 0) {
            // Add new entry
            if (section_found) {
                try result.appendSlice(content[0..last_target_end]);
                try result.appendSlice(new_line);
                if (last_target_end < content.len) try result.appendSlice(content[last_target_end..]);
            } else {
                try result.appendSlice(content);
                if (pk.subsection) |sub| { try result.writer().print("[{s} \"{s}\"]\n", .{ pk.section, sub }); }
                else { try result.writer().print("[{s}]\n", .{pk.section}); }
                try result.appendSlice(new_line);
            }
        } else if (rmatch_count > 1) {
            try platform_impl.writeStderr("warning: key has multiple values matching regex\n");
            std.process.exit(5);
        } else {
            var replaced = false;
            for (infos.items) |li| {
                if (li.is_key and li.regex_ok and !replaced) { try writeReplacement.f(&result, li, new_line, content); replaced = true; }
                else try result.appendSlice(content[li.start..li.cont_end]);
            }
        }
        try platform_impl.fs.writeFile(cfg_path, result.items);
        return;
    }

    // No value_regex
    if (match_count == 0) {
        if (section_found) {
            try result.appendSlice(content[0..last_target_end]);
            try result.appendSlice(new_line);
            if (last_target_end < content.len) try result.appendSlice(content[last_target_end..]);
        } else {
            try result.appendSlice(content);
            if (pk.subsection) |sub| { try result.writer().print("[{s} \"{s}\"]\n", .{ pk.section, sub }); }
            else { try result.writer().print("[{s}]\n", .{pk.section}); }
            try result.appendSlice(new_line);
        }
    } else {
        // Replace last match
        var last_idx: ?usize = null;
        for (infos.items, 0..) |li, idx| { if (li.is_key) last_idx = idx; }
        for (infos.items, 0..) |li, idx| {
            if (li.is_key and idx == last_idx.?) try writeReplacement.f(&result, li, new_line, content)
            else try result.appendSlice(content[li.start..li.cont_end]);
        }
    }
    try platform_impl.fs.writeFile(cfg_path, result.items);
}

fn cfgUnsetValue(cfg_path: []const u8, key: []const u8, unset_all: bool, value_regex: ?[]const u8, fixed_val: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const pk = cfgParseKey(key, allocator) catch { try platform_impl.writeStderr("error: key does not contain a section\n"); std.process.exit(2); };
    defer allocator.free(pk.section);
    defer if (pk.subsection) |s| allocator.free(s);
    defer allocator.free(pk.variable);

    const content = platform_impl.fs.readFile(allocator, cfg_path) catch { std.process.exit(5); };
    defer allocator.free(content);

    // Count matches first
    var match_count: usize = 0;
    var rmatch_count: usize = 0;
    {
        var ents = std.array_list.Managed(CfgEntry).init(allocator);
        defer { for (ents.items) |*e| e.deinit(allocator); ents.deinit(); }
        cfgParseEntries(content, &ents, allocator) catch {};
        for (ents.items) |e| {
            if (cfgKeyMatches(e.full_key, key)) {
                match_count += 1;
                if (value_regex) |vr| {
                    const neg = vr.len > 0 and vr[0] == '!';
                    const act = if (neg) vr[1..] else vr;
                    const m = if (fixed_val) std.mem.eql(u8, e.value, act) else simpleRegexMatch(e.value, act);
                    if (if (neg) !m else m) rmatch_count += 1;
                } else rmatch_count += 1;
            }
        }
    }

    if (match_count == 0 or (value_regex != null and rmatch_count == 0)) std.process.exit(5);
    if (!unset_all and rmatch_count > 1) {
        try platform_impl.writeStderr("warning: ");
        try platform_impl.writeStderr(key);
        try platform_impl.writeStderr(" has multiple values\n");
        std.process.exit(5);
    }

    // Build output
    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();
    var cur_sec: ?[]u8 = null;
    var cur_sub: ?[]u8 = null;
    defer if (cur_sec) |s| allocator.free(s);
    defer if (cur_sub) |s| allocator.free(s);
    var in_target = false;
    var first_line = true;

    var line_iter = std.mem.splitSequence(u8, content, "\n");
    while (line_iter.next()) |raw_line| {
        const ln = std.mem.trimRight(u8, raw_line, "\r");
        const trimmed = std.mem.trim(u8, ln, " \t");

        if (trimmed.len > 0 and trimmed[0] == '[') {
            if (cur_sec) |s| allocator.free(s);
            if (cur_sub) |s| allocator.free(s);
            cur_sec = null; cur_sub = null;
            const close = std.mem.indexOf(u8, trimmed, "]");
            if (close) |cl| {
                const inner = trimmed[1..cl];
                if (std.mem.indexOf(u8, inner, "\"")) |q| {
                    cur_sec = try allocator.dupe(u8, std.mem.trim(u8, inner[0..q], " \t"));
                    var r = inner[q + 1 ..];
                    if (std.mem.lastIndexOfScalar(u8, r, '"')) |q2| r = r[0..q2];
                    var sb = std.array_list.Managed(u8).init(allocator);
                    defer sb.deinit();
                    var si: usize = 0;
                    while (si < r.len) : (si += 1) {
                        if (r[si] == '\\' and si + 1 < r.len) { si += 1; try sb.append(r[si]); }
                        else try sb.append(r[si]);
                    }
                    cur_sub = try sb.toOwnedSlice();
                } else if (std.mem.indexOf(u8, inner, ".")) |d| {
                    cur_sec = try allocator.dupe(u8, std.mem.trim(u8, inner[0..d], " \t"));
                    // Old-style [section.sub] - subsection is case-insensitive (lowercased)
                    const oldsub2 = try allocator.dupe(u8, inner[d + 1 ..]);
                    for (oldsub2) |*c| c.* = std.ascii.toLower(c.*);
                    cur_sub = oldsub2;
                } else {
                    cur_sec = try allocator.dupe(u8, std.mem.trim(u8, inner, " \t"));
                }
            }
            in_target = if (cur_sec) |cs| cfgSectionMatches(cs, cur_sub, pk) else false;
        }

        var skip = false;
        if (in_target and trimmed.len > 0 and trimmed[0] != '[' and trimmed[0] != '#' and trimmed[0] != ';') {
            if (std.mem.indexOf(u8, trimmed, "=")) |eq| {
                const k = std.mem.trim(u8, trimmed[0..eq], " \t");
                if (std.ascii.eqlIgnoreCase(k, pk.variable)) {
                    var should_rm = true;
                    if (value_regex) |vr| {
                        var vbuf = std.array_list.Managed(u8).init(allocator);
                        defer vbuf.deinit();
                        cfgAppendValuePart(&vbuf, trimmed[eq + 1 ..]) catch {};
                        const neg = vr.len > 0 and vr[0] == '!';
                        const act = if (neg) vr[1..] else vr;
                        const m = if (fixed_val) std.mem.eql(u8, vbuf.items, act) else simpleRegexMatch(vbuf.items, act);
                        should_rm = if (neg) !m else m;
                    }
                    if (should_rm and (unset_all or rmatch_count <= 1)) {
                        skip = true;
                        // Skip continuation lines
                        const tv = std.mem.trimRight(u8, raw_line, " \t\r\n");
                        if (tv.len > 0 and tv[tv.len - 1] == '\\' and cfgIsContinuation(tv)) {
                            while (line_iter.next()) |cont| {
                                const ct = std.mem.trimRight(u8, cont, " \t\r\n");
                                if (ct.len == 0 or ct[ct.len - 1] != '\\') break;
                            }
                        }
                    }
                }
            } else {
                const ck = std.mem.trim(u8, trimmed, " \t");
                if (std.ascii.eqlIgnoreCase(ck, pk.variable)) {
                    if (unset_all or rmatch_count <= 1) skip = true;
                }
            }
        }

        if (!skip) {
            if (!first_line) try result.append('\n');
            try result.appendSlice(raw_line);
            first_line = false;
        }
    }

    if (content.len > 0 and content[content.len - 1] == '\n') {
        if (result.items.len == 0 or result.items[result.items.len - 1] != '\n')
            try result.append('\n');
    }

    const cleaned = try cfgRemoveEmptySections(result.items, allocator);
    defer allocator.free(cleaned);
    try platform_impl.fs.writeFile(cfg_path, cleaned);
}

fn cfgRenameSection(cfg_path: []const u8, old_name: []const u8, new_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const content = platform_impl.fs.readFile(allocator, cfg_path) catch {
        try platform_impl.writeStderr("fatal: could not read config file\n");
        std.process.exit(128);
    };
    defer allocator.free(content);

    const old_dot = std.mem.indexOfScalar(u8, old_name, '.');
    const old_sec = if (old_dot) |d| old_name[0..d] else old_name;
    const old_sub = if (old_dot) |d| old_name[d + 1 ..] else null;
    const new_dot = std.mem.indexOfScalar(u8, new_name, '.');
    const new_sec = if (new_dot) |d| new_name[0..d] else new_name;
    const new_sub = if (new_dot) |d| new_name[d + 1 ..] else null;

    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();
    var found = false;
    var first_line = true;

    var line_iter = std.mem.splitSequence(u8, content, "\n");
    while (line_iter.next()) |raw_line| {
        const trimmed = std.mem.trim(u8, std.mem.trimRight(u8, raw_line, "\r"), " \t");
        if (trimmed.len > 0 and trimmed[0] == '[') {
            const close = std.mem.indexOf(u8, trimmed, "]");
            if (close) |cl| {
                const inner = trimmed[1..cl];
                var fsec: ?[]const u8 = null;
                var fsub: ?[]const u8 = null;
                var sub_buf_d: [512]u8 = undefined;
                var slen: usize = 0;

                if (std.mem.indexOf(u8, inner, "\"")) |q| {
                    fsec = std.mem.trim(u8, inner[0..q], " \t");
                    var r = inner[q + 1 ..];
                    if (std.mem.lastIndexOfScalar(u8, r, '"')) |q2| r = r[0..q2];
                    var si: usize = 0;
                    while (si < r.len and slen < sub_buf_d.len) : (si += 1) {
                        if (r[si] == '\\' and si + 1 < r.len) { si += 1; sub_buf_d[slen] = r[si]; slen += 1; }
                        else { sub_buf_d[slen] = r[si]; slen += 1; }
                    }
                    fsub = sub_buf_d[0..slen];
                } else if (std.mem.indexOf(u8, inner, ".")) |d| {
                    fsec = std.mem.trim(u8, inner[0..d], " \t");
                    fsub = inner[d + 1 ..];
                } else {
                    fsec = std.mem.trim(u8, inner, " \t");
                }

                var matches = false;
                if (fsec) |fs| {
                    if (std.ascii.eqlIgnoreCase(fs, old_sec)) {
                        if (old_sub) |os| { if (fsub) |fss| matches = std.mem.eql(u8, fss, os); }
                        else matches = (fsub == null);
                    }
                }

                if (matches) {
                    found = true;
                    if (!first_line) try result.append('\n');
                    if (new_sub) |ns| { try result.writer().print("[{s} \"{s}\"]", .{ new_sec, ns }); }
                    else { try result.writer().print("[{s}]", .{new_sec}); }
                    const after = std.mem.trim(u8, trimmed[cl + 1 ..], " \t");
                    if (after.len > 0 and after[0] != '#' and after[0] != ';') {
                        try result.append('\n');
                        try result.append('\t');
                        try result.appendSlice(after);
                    } else if (after.len > 0) {
                        try result.appendSlice(trimmed[cl + 1 ..]);
                    }
                    first_line = false;
                    continue;
                }
            }
        }
        if (!first_line) try result.append('\n');
        try result.appendSlice(raw_line);
        first_line = false;
    }

    if (!found) {
        const msg = try std.fmt.allocPrint(allocator, "error: no such section: {s}\n", .{old_name});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(2);
    }

    if (content.len > 0 and content[content.len - 1] == '\n') {
        if (result.items.len == 0 or result.items[result.items.len - 1] != '\n') try result.append('\n');
    }
    try platform_impl.fs.writeFile(cfg_path, result.items);
}

fn cfgRemoveSection(cfg_path: []const u8, section_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const content = platform_impl.fs.readFile(allocator, cfg_path) catch {
        try platform_impl.writeStderr("fatal: could not read config file\n");
        std.process.exit(128);
    };
    defer allocator.free(content);

    const sec_dot = std.mem.indexOfScalar(u8, section_name, '.');
    const rm_sec = if (sec_dot) |d| section_name[0..d] else section_name;
    const rm_sub = if (sec_dot) |d| section_name[d + 1 ..] else null;

    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();
    var in_removed = false;
    var found = false;
    var first_line = true;

    var line_iter = std.mem.splitSequence(u8, content, "\n");
    while (line_iter.next()) |raw_line| {
        const trimmed = std.mem.trim(u8, std.mem.trimRight(u8, raw_line, "\r"), " \t");
        if (trimmed.len > 0 and trimmed[0] == '[') {
            const close = std.mem.indexOf(u8, trimmed, "]");
            if (close) |cl| {
                _ = cl;
                const inner2 = trimmed[1..std.mem.indexOf(u8, trimmed, "]").?];
                var fsec: ?[]const u8 = null;
                var fsub: ?[]const u8 = null;
                var sbd: [512]u8 = undefined;
                var sl: usize = 0;

                if (std.mem.indexOf(u8, inner2, "\"")) |q| {
                    fsec = std.mem.trim(u8, inner2[0..q], " \t");
                    var r = inner2[q + 1 ..];
                    if (std.mem.lastIndexOfScalar(u8, r, '"')) |q2| r = r[0..q2];
                    var si: usize = 0;
                    while (si < r.len and sl < sbd.len) : (si += 1) {
                        if (r[si] == '\\' and si + 1 < r.len) { si += 1; sbd[sl] = r[si]; sl += 1; }
                        else { sbd[sl] = r[si]; sl += 1; }
                    }
                    fsub = sbd[0..sl];
                } else if (std.mem.indexOf(u8, inner2, ".")) |d| {
                    fsec = std.mem.trim(u8, inner2[0..d], " \t");
                    fsub = inner2[d + 1 ..];
                } else {
                    fsec = std.mem.trim(u8, inner2, " \t");
                }

                var matches = false;
                if (fsec) |fs| {
                    if (std.ascii.eqlIgnoreCase(fs, rm_sec)) {
                        if (rm_sub) |rs| { if (fsub) |fss| matches = std.mem.eql(u8, fss, rs); }
                        else matches = (fsub == null);
                    }
                }

                if (matches) { in_removed = true; found = true; continue; }
                else in_removed = false;
            }
        }
        if (!in_removed) {
            if (!first_line) try result.append('\n');
            try result.appendSlice(raw_line);
            first_line = false;
        }
    }

    if (!found) {
        const msg = try std.fmt.allocPrint(allocator, "fatal: no such section: {s}\n", .{section_name});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    }

    if (content.len > 0 and content[content.len - 1] == '\n') {
        if (result.items.len == 0 or result.items[result.items.len - 1] != '\n') try result.append('\n');
    }
    try platform_impl.fs.writeFile(cfg_path, result.items);
}

fn colorToAnsi(color_str: []const u8) []const u8 {
    // Legacy static version - kept for any remaining callers
    if (std.mem.eql(u8, color_str, "red")) return "\x1b[31m";
    if (std.mem.eql(u8, color_str, "green")) return "\x1b[32m";
    if (std.mem.eql(u8, color_str, "yellow")) return "\x1b[33m";
    if (std.mem.eql(u8, color_str, "blue")) return "\x1b[34m";
    if (std.mem.eql(u8, color_str, "magenta")) return "\x1b[35m";
    if (std.mem.eql(u8, color_str, "cyan")) return "\x1b[36m";
    if (std.mem.eql(u8, color_str, "white")) return "\x1b[37m";
    if (std.mem.eql(u8, color_str, "reset") or std.mem.eql(u8, color_str, "normal")) return "\x1b[m";
    if (std.mem.eql(u8, color_str, "bold")) return "\x1b[1m";
    if (std.mem.eql(u8, color_str, "bold red")) return "\x1b[1;31m";
    if (std.mem.eql(u8, color_str, "bold green")) return "\x1b[1;32m";
    if (std.mem.eql(u8, color_str, "bold yellow")) return "\x1b[1;33m";
    if (std.mem.eql(u8, color_str, "bold blue")) return "\x1b[1;34m";
    if (color_str.len == 0) return "";
    return "";
}

const ColorParseError = error{InvalidColor};

fn parseColorName(word: []const u8) ?i16 {
    if (std.mem.eql(u8, word, "normal") or std.mem.eql(u8, word, "default")) return -1;
    if (std.mem.eql(u8, word, "black")) return 0;
    if (std.mem.eql(u8, word, "red")) return 1;
    if (std.mem.eql(u8, word, "green")) return 2;
    if (std.mem.eql(u8, word, "yellow")) return 3;
    if (std.mem.eql(u8, word, "blue")) return 4;
    if (std.mem.eql(u8, word, "magenta")) return 5;
    if (std.mem.eql(u8, word, "cyan")) return 6;
    if (std.mem.eql(u8, word, "white")) return 7;
    return null;
}

const ColorAttrEntry = union(enum) {
    code: u8,
    reset: void, // empty entry for reset (produces just ';')
};

fn parseColorWord(word: []const u8, fg_color: *i16, bg_color: *i16, attrs: *std.array_list.AlignedManaged(ColorAttrEntry, null), fg_set: *bool, bg_set: *bool) !void {
    // Check for "bright" prefix colors
    if (word.len > 6 and std.mem.startsWith(u8, word, "bright")) {
        const base = parseColorName(word[6..]);
        if (base) |b| {
            if (b == -1) return error.InvalidColor; // brightnormal/brightdefault invalid
            if (!fg_set.*) {
                fg_color.* = b + 8; // bright colors are 8-15
                fg_set.* = true;
            } else {
                bg_color.* = b + 8;
                bg_set.* = true;
            }
            return;
        }
        return error.InvalidColor;
    }

    // Reset
    if (std.mem.eql(u8, word, "reset")) {
        try attrs.append(.{ .reset = {} });
        return;
    }

    // Attributes
    if (std.mem.eql(u8, word, "bold")) { try attrs.append(.{ .code = 1 }); return; }
    if (std.mem.eql(u8, word, "dim")) { try attrs.append(.{ .code = 2 }); return; }
    if (std.mem.eql(u8, word, "italic")) { try attrs.append(.{ .code = 3 }); return; }
    if (std.mem.eql(u8, word, "ul")) { try attrs.append(.{ .code = 4 }); return; }
    if (std.mem.eql(u8, word, "blink")) { try attrs.append(.{ .code = 5 }); return; }
    if (std.mem.eql(u8, word, "reverse")) { try attrs.append(.{ .code = 7 }); return; }
    if (std.mem.eql(u8, word, "strike")) { try attrs.append(.{ .code = 9 }); return; }

    // Negated attributes
    if (std.mem.eql(u8, word, "nobold") or std.mem.eql(u8, word, "no-bold")) { try attrs.append(.{ .code = 22 }); return; }
    if (std.mem.eql(u8, word, "nodim") or std.mem.eql(u8, word, "no-dim")) { try attrs.append(.{ .code = 22 }); return; }
    if (std.mem.eql(u8, word, "noitalic") or std.mem.eql(u8, word, "no-italic")) { try attrs.append(.{ .code = 23 }); return; }
    if (std.mem.eql(u8, word, "noul") or std.mem.eql(u8, word, "no-ul")) { try attrs.append(.{ .code = 24 }); return; }
    if (std.mem.eql(u8, word, "noblink") or std.mem.eql(u8, word, "no-blink")) { try attrs.append(.{ .code = 25 }); return; }
    if (std.mem.eql(u8, word, "noreverse") or std.mem.eql(u8, word, "no-reverse")) { try attrs.append(.{ .code = 27 }); return; }
    if (std.mem.eql(u8, word, "nostrike") or std.mem.eql(u8, word, "no-strike")) { try attrs.append(.{ .code = 29 }); return; }

    // Color names (normal/default/black/red/etc.)
    if (parseColorName(word)) |c| {
        if (!fg_set.*) {
            fg_color.* = c;
            fg_set.* = true;
        } else {
            bg_color.* = c;
            bg_set.* = true;
        }
        return;
    }

    // RGB color #RRGGBB
    if (word.len > 0 and word[0] == '#') {
        if (word.len != 7) return error.InvalidColor;
        _ = std.fmt.parseInt(u8, word[1..3], 16) catch return error.InvalidColor;
        _ = std.fmt.parseInt(u8, word[3..5], 16) catch return error.InvalidColor;
        _ = std.fmt.parseInt(u8, word[5..7], 16) catch return error.InvalidColor;
        if (!fg_set.*) {
            fg_color.* = -3; // RGB marker
            fg_set.* = true;
        } else {
            bg_color.* = -3;
            bg_set.* = true;
        }
        return;
    }

    // Numeric color 0-255 or -1
    // Must be a valid integer with no trailing characters
    if (std.fmt.parseInt(i16, word, 10)) |n| {
        if (n < -1 or n > 255) return error.InvalidColor;
        if (!fg_set.*) {
            fg_color.* = n;
            fg_set.* = true;
        } else {
            bg_color.* = n;
            bg_set.* = true;
        }
        return;
    } else |_| {}

    return error.InvalidColor;
}

fn colorToAnsiAlloc(allocator: std.mem.Allocator, color_str: []const u8) ![]u8 {
    const trimmed = std.mem.trim(u8, color_str, " \t");
    if (trimmed.len == 0) return try allocator.dupe(u8, "");

    // Check for "normal" special case - produces no color at all
    if (std.mem.eql(u8, trimmed, "normal") or std.mem.eql(u8, trimmed, "-1")) {
        return try allocator.dupe(u8, "");
    }

    var fg_color: i16 = -2; // unset marker
    var bg_color: i16 = -2; // unset marker
    var fg_set = false;
    var bg_set = false;

    var attrs = std.array_list.Managed(ColorAttrEntry).init(allocator);
    defer attrs.deinit();

    // We need to also track RGB values
    var fg_rgb: ?[3]u8 = null;
    var bg_rgb: ?[3]u8 = null;

    // Parse each word
    var word_iter = std.mem.tokenizeAny(u8, trimmed, " \t");
    while (word_iter.next()) |word| {
        // Handle RGB specially before passing to parseColorWord
        if (word.len == 7 and word[0] == '#') {
            const r = std.fmt.parseInt(u8, word[1..3], 16) catch return error.InvalidColor;
            const g = std.fmt.parseInt(u8, word[3..5], 16) catch return error.InvalidColor;
            const b = std.fmt.parseInt(u8, word[5..7], 16) catch return error.InvalidColor;
            if (!fg_set) {
                fg_rgb = .{ r, g, b };
                fg_color = -3; // RGB marker
                fg_set = true;
            } else {
                bg_rgb = .{ r, g, b };
                bg_color = -3; // RGB marker
                bg_set = true;
            }
            continue;
        }
        try parseColorWord(word, &fg_color, &bg_color, &attrs, &fg_set, &bg_set);
    }

    // Build ANSI code
    var codes = std.array_list.Managed(u8).init(allocator);
    defer codes.deinit();

    var first = true;

    // Output attributes
    for (attrs.items) |attr| {
        switch (attr) {
            .code => |code| {
                if (!first) try codes.append(';');
                var buf: [8]u8 = undefined;
                const s = std.fmt.bufPrint(&buf, "{d}", .{code}) catch unreachable;
                try codes.appendSlice(s);
                first = false;
            },
            .reset => {
                if (!first) try codes.append(';');
                first = false;
            },
        }
    }

    // Output foreground color
    if (fg_set) {
        if (fg_color == -3) {
            // RGB
            if (fg_rgb) |rgb| {
                if (!first) try codes.append(';');
                var buf: [32]u8 = undefined;
                const s = std.fmt.bufPrint(&buf, "38;2;{d};{d};{d}", .{ rgb[0], rgb[1], rgb[2] }) catch unreachable;
                try codes.appendSlice(s);
                first = false;
            }
        } else if (fg_color == -1) {
            // default color
            if (!first) try codes.append(';');
            try codes.appendSlice("39");
            first = false;
        } else if (fg_color >= 0 and fg_color <= 7) {
            if (!first) try codes.append(';');
            var buf: [8]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "{d}", .{@as(u16, @intCast(fg_color)) + 30}) catch unreachable;
            try codes.appendSlice(s);
            first = false;
        } else if (fg_color >= 8 and fg_color <= 15) {
            // Bright/aixterm colors
            if (!first) try codes.append(';');
            var buf: [8]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "{d}", .{@as(u16, @intCast(fg_color)) - 8 + 90}) catch unreachable;
            try codes.appendSlice(s);
            first = false;
        } else if (fg_color >= 16 and fg_color <= 255) {
            // 256-color mode
            if (!first) try codes.append(';');
            var buf: [16]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "38;5;{d}", .{@as(u16, @intCast(fg_color))}) catch unreachable;
            try codes.appendSlice(s);
            first = false;
        }
    }

    // Output background color
    if (bg_set) {
        if (bg_color == -3) {
            // RGB
            if (bg_rgb) |rgb| {
                if (!first) try codes.append(';');
                var buf: [32]u8 = undefined;
                const s = std.fmt.bufPrint(&buf, "48;2;{d};{d};{d}", .{ rgb[0], rgb[1], rgb[2] }) catch unreachable;
                try codes.appendSlice(s);
                first = false;
            }
        } else if (bg_color == -1) {
            // default color
            if (!first) try codes.append(';');
            try codes.appendSlice("49");
            first = false;
        } else if (bg_color >= 0 and bg_color <= 7) {
            if (!first) try codes.append(';');
            var buf: [8]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "{d}", .{@as(u16, @intCast(bg_color)) + 40}) catch unreachable;
            try codes.appendSlice(s);
            first = false;
        } else if (bg_color >= 8 and bg_color <= 15) {
            if (!first) try codes.append(';');
            var buf: [8]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "{d}", .{@as(u16, @intCast(bg_color)) - 8 + 100}) catch unreachable;
            try codes.appendSlice(s);
            first = false;
        } else if (bg_color >= 16 and bg_color <= 255) {
            if (!first) try codes.append(';');
            var buf: [16]u8 = undefined;
            const s = std.fmt.bufPrint(&buf, "48;5;{d}", .{@as(u16, @intCast(bg_color))}) catch unreachable;
            try codes.appendSlice(s);
            first = false;
        }
    }

    if (codes.items.len == 0 and !fg_set and !bg_set and attrs.items.len == 0) {
        return try allocator.dupe(u8, "");
    }

    // Build final string: \e[CODESm
    var result = std.array_list.Managed(u8).init(allocator);
    try result.append(0x1b);
    try result.append('[');
    try result.appendSlice(codes.items);
    try result.append('m');

    return try result.toOwnedSlice();
}

// Compatibility wrappers for code that uses old function names
fn parseConfigValue(config_content: []const u8, key: []const u8, allocator: std.mem.Allocator) !?[]u8 {
    var entries = std.array_list.Managed(CfgEntry).init(allocator);
    defer { for (entries.items) |*e| e.deinit(allocator); entries.deinit(); }
    try cfgParseEntries(config_content, &entries, allocator);
    var last_val: ?[]u8 = null;
    for (entries.items) |e| {
        if (cfgKeyMatches(e.full_key, key)) {
            if (last_val) |v| allocator.free(v);
            last_val = try allocator.dupe(u8, e.value);
        }
    }
    if (last_val) |v| return v;
    return error.KeyNotFound;
}

fn isValidConfigKey(key: []const u8) bool { return cfgIsValidKey(key); }

fn formatConfigType(value: []const u8, config_type: ConfigType, allocator: std.mem.Allocator) ![]u8 {
    switch (config_type) {
        .bool_type => {
            const lower = try std.ascii.allocLowerString(allocator, value);
            defer allocator.free(lower);
            if (value.len == 0) return try allocator.dupe(u8, "false");
            if (std.mem.eql(u8, lower, "true") or std.mem.eql(u8, lower, "yes") or std.mem.eql(u8, lower, "on") or std.mem.eql(u8, lower, "1"))
                return try allocator.dupe(u8, "true");
            if (std.mem.eql(u8, lower, "false") or std.mem.eql(u8, lower, "no") or std.mem.eql(u8, lower, "off") or std.mem.eql(u8, lower, "0"))
                return try allocator.dupe(u8, "false");
            return try allocator.dupe(u8, value);
        },
        .int_type => {
            const trimmed = std.mem.trim(u8, value, " \t");
            if (trimmed.len == 0) return try allocator.dupe(u8, value);
            const last = trimmed[trimmed.len - 1];
            if (last == 'k' or last == 'K' or last == 'm' or last == 'M' or last == 'g' or last == 'G') {
                if (std.fmt.parseInt(i64, trimmed[0 .. trimmed.len - 1], 10)) |num| {
                    const mult: i64 = switch (last) { 'k', 'K' => 1024, 'm', 'M' => 1048576, 'g', 'G' => 1073741824, else => 1 };
                    return try std.fmt.allocPrint(allocator, "{d}", .{num * mult});
                } else |_| {}
            }
            if (std.fmt.parseInt(i64, trimmed, 10)) |n| return try std.fmt.allocPrint(allocator, "{d}", .{n}) else |_| {}
            return try allocator.dupe(u8, value);
        },
        else => return try allocator.dupe(u8, value),
    }
}

fn configSetValue(cfg_path: []const u8, key: []const u8, value: []const u8, do_add: bool, replace_all: bool, value_regex: ?[]const u8, comment: ?[]const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    try cfgSetValue(cfg_path, key, value, do_add, replace_all, value_regex, false, comment, allocator, platform_impl);
}

fn configUnsetValue(cfg_path: []const u8, key: []const u8, unset_all: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    try cfgUnsetValue(cfg_path, key, unset_all, null, false, allocator, platform_impl);
}

fn configRenameSection(cfg_path: []const u8, old_name: []const u8, new_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    try cfgRenameSection(cfg_path, old_name, new_name, allocator, platform_impl);
}

fn configRemoveSection(cfg_path: []const u8, section_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    try cfgRemoveSection(cfg_path, section_name, allocator, platform_impl);
}

fn configLookup(sources: []const ConfigSource, key: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    return cfgLookup(sources, key, allocator, platform_impl);
}

fn parseSectionHeader(header: []const u8, allocator: std.mem.Allocator) ![]u8 {
    return cfgParseSectionToKey(header, allocator);
}

fn outputConfigList(content: []const u8, source_path: []const u8, scope: []const u8, null_term: bool, name_only: bool, show_origin: bool, show_scope: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    try cfgOutputList(content, source_path, scope, null_term, name_only, show_origin, show_scope, .none, allocator, platform_impl);
}

fn outputConfigGetRegexp(content: []const u8, pattern: []const u8, name_only: bool, null_term: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !bool {
    var entries = std.array_list.Managed(CfgEntry).init(allocator);
    defer { for (entries.items) |*e| e.deinit(allocator); entries.deinit(); }
    cfgParseEntries(content, &entries, allocator) catch return false;
    var found = false;
    for (entries.items) |e| {
        if (simpleRegexMatch(e.full_key, pattern)) {
            found = true;
            const term: []const u8 = if (null_term) "\x00" else "\n";
            if (name_only) {
                const out = try std.fmt.allocPrint(allocator, "{s}{s}", .{ e.full_key, term });
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            } else {
                const out = try std.fmt.allocPrint(allocator, "{s} {s}{s}", .{ e.full_key, e.value, term });
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            }
        }
    }
    return found;
}

fn parseConfigGetAll(content: []const u8, key: []const u8, results: *std.array_list.Managed([]const u8), allocator: std.mem.Allocator) !void {
    var entries = std.array_list.Managed(CfgEntry).init(allocator);
    defer { for (entries.items) |*e| e.deinit(allocator); entries.deinit(); }
    try cfgParseEntries(content, &entries, allocator);
    for (entries.items) |e| {
        if (cfgKeyMatches(e.full_key, key)) {
            try results.append(try allocator.dupe(u8, e.value));
        }
    }
}

fn formatSectionHeader(section_key: []const u8, allocator: std.mem.Allocator) ![]u8 {
    if (std.mem.indexOf(u8, section_key, ".")) |dot| {
        return try std.fmt.allocPrint(allocator, "{s} \"{s}\"", .{ section_key[0..dot], section_key[dot + 1 ..] });
    }
    return try allocator.dupe(u8, section_key);
}

fn formatConfigComment(comment_raw: ?[]const u8, allocator: std.mem.Allocator) ![]const u8 {
    const r = try cfgFormatComment(comment_raw, allocator);
    return r;
}

fn sectionMatchesKey(config_section: []const u8, key_section: []const u8) bool {
    const cd = std.mem.indexOf(u8, config_section, ".");
    const kd = std.mem.indexOf(u8, key_section, ".");
    if (cd != null and kd != null) {
        if (!std.ascii.eqlIgnoreCase(config_section[0..cd.?], key_section[0..kd.?])) return false;
        return std.mem.eql(u8, config_section[cd.? + 1 ..], key_section[kd.? + 1 ..]);
    }
    if (cd == null and kd == null) return std.ascii.eqlIgnoreCase(config_section, key_section);
    return false;
}

fn parseConfigSectionHeader(header: []const u8, allocator: std.mem.Allocator) !ParsedSection {
    const close = std.mem.lastIndexOf(u8, header, "]") orelse return .{ .section = null, .subsection = null };
    const inner = header[1..close];
    if (std.mem.indexOf(u8, inner, " \"")) |quote_start| {
        const section = std.mem.trim(u8, inner[0..quote_start], " \t");
        var subsection_raw = inner[quote_start + 2 ..];
        if (subsection_raw.len > 0 and subsection_raw[subsection_raw.len - 1] == '"')
            subsection_raw = subsection_raw[0 .. subsection_raw.len - 1];
        var sub_buf = std.array_list.Managed(u8).init(allocator);
        defer sub_buf.deinit();
        var si: usize = 0;
        while (si < subsection_raw.len) : (si += 1) {
            if (subsection_raw[si] == '\\' and si + 1 < subsection_raw.len) { si += 1; try sub_buf.append(subsection_raw[si]); }
            else try sub_buf.append(subsection_raw[si]);
        }
        return .{ .section = try allocator.dupe(u8, section), .subsection = try sub_buf.toOwnedSlice() };
    }
    return .{ .section = try allocator.dupe(u8, inner), .subsection = null };
}

const ParsedSection = struct { section: ?[]u8, subsection: ?[]u8 };

fn parseConfigKey(key: []const u8, allocator: std.mem.Allocator) !ParsedConfigKey {
    const pk = try cfgParseKey(key, allocator);
    return .{ .section = pk.section, .subsection = pk.subsection, .variable = pk.variable };
}

const ParsedConfigKey = struct { section: []u8, subsection: ?[]u8, variable: []u8 };

fn appendConfigValuePart(buf: *std.array_list.Managed(u8), raw: []const u8) !void {
    try cfgAppendValuePart(buf, raw);
}

fn stripInlineComment(value: []const u8) []const u8 {
    var in_quotes = false;
    var ii: usize = 0;
    while (ii < value.len) : (ii += 1) {
        if (value[ii] == '"' and (ii == 0 or value[ii - 1] != '\\')) in_quotes = !in_quotes;
        if (!in_quotes and (value[ii] == '#' or value[ii] == ';')) {
            if (ii == 0 or value[ii - 1] == ' ' or value[ii - 1] == '\t')
                return std.mem.trimRight(u8, value[0..ii], " \t");
        }
    }
    return value;
}

/// Get remote URL from git config
fn getRemoteUrl(git_path: []const u8, remote_name: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
    defer allocator.free(config_path);
    const config_content = platform_impl.fs.readFile(allocator, config_path) catch return error.RemoteNotFound;
    defer allocator.free(config_content);
    const key2 = try std.fmt.allocPrint(allocator, "remote.{s}.url", .{remote_name});
    defer allocator.free(key2);
    const url = parseConfigValue(config_content, key2, allocator) catch return error.RemoteNotFound;
    return url orelse error.RemoteNotFound;
}

fn cmdVersion(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    _ = allocator;
    var show_build_options = false;
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--build-options")) {
            show_build_options = true;
        }
    }
    try platform_impl.writeStdout("git version 2.53.GIT\n");
    if (show_build_options) {
        try platform_impl.writeStdout("cpu: x86_64\n");
        try platform_impl.writeStdout("sizeof-long: 8\n");
        try platform_impl.writeStdout("sizeof-size_t: 8\n");
        try platform_impl.writeStdout("shell-path: /bin/sh\n");
        try platform_impl.writeStdout("feature: fsmonitor--daemon\n");
        try platform_impl.writeStdout("default-hash: sha1\n");
        try platform_impl.writeStdout("default-ref-format: files\n");
    }
}

fn cmdPush(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("push: not supported in freestanding mode\n");
        return;
    }

    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Parse arguments
    var remote_name: ?[]const u8 = null;
    var refspecs = std.array_list.Managed([]const u8).init(allocator);
    defer refspecs.deinit();
    var force_push = false;
    var push_all = false;
    var push_tags = false;
    var push_delete = false;
    var push_mirror = false;
    var set_upstream = false;
    var dry_run = false;
    var verbose = false;
    var quiet = false;
    var follow_tags = false;

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--force")) {
            force_push = true;
        } else if (std.mem.eql(u8, arg, "--all") or std.mem.eql(u8, arg, "--branches")) {
            push_all = true;
        } else if (std.mem.eql(u8, arg, "--tags")) {
            push_tags = true;
        } else if (std.mem.eql(u8, arg, "--mirror")) {
            push_mirror = true;
            force_push = true;
        } else if (std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "--delete")) {
            push_delete = true;
        } else if (std.mem.eql(u8, arg, "-u") or std.mem.eql(u8, arg, "--set-upstream")) {
            set_upstream = true;
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.eql(u8, arg, "--dry-run")) {
            dry_run = true;
        } else if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--follow-tags")) {
            follow_tags = true;
        } else if (std.mem.eql(u8, arg, "--follow-tags")) {
            follow_tags = true;
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git push [<options>] [<repository> [<refspec>...]]\n");
            return;
        } else if (std.mem.startsWith(u8, arg, "-")) {
            // Skip unknown options
        } else {
            if (remote_name == null) {
                remote_name = arg;
            } else {
                try refspecs.append(arg);
            }
        }
    }

    const remote = remote_name orelse "origin";

    if (remote.len == 0) {
        try platform_impl.writeStderr("fatal: bad repository ''\n");
        std.process.exit(128);
    }

    // Check for conflicting options
    if (push_all and refspecs.items.len > 0) {
        try platform_impl.writeStderr("error: --all/--branches can't be combined with refspecs\n");
        std.process.exit(1);
    }
    if (push_all and push_tags) {
        try platform_impl.writeStderr("error: --all/--branches and --tags cannot be used together\n");
        std.process.exit(1);
    }
    if (push_all and push_delete) {
        try platform_impl.writeStderr("error: --all/--branches and --delete cannot be used together\n");
        std.process.exit(1);
    }
    if (push_mirror and (push_all or push_tags or push_delete)) {
        try platform_impl.writeStderr("error: --mirror and --all/--branches/--tags/--delete cannot be used together\n");
        std.process.exit(1);
    }
    if (push_mirror) push_all = true;

    // Resolve remote URL
    var remote_url: []const u8 = undefined;
    var remote_url_allocated = false;

    // Check if remote is actually a path/URL
    if (std.mem.startsWith(u8, remote, "/") or std.mem.startsWith(u8, remote, "./") or std.mem.startsWith(u8, remote, "../") or std.mem.eql(u8, remote, ".") or std.mem.eql(u8, remote, "..") or std.mem.startsWith(u8, remote, "file://")) {
        remote_url = remote;
    } else {
        // Look up remote URL from config first
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const config_content = std.fs.cwd().readFileAlloc(allocator, config_path, 1024 * 1024) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' does not appear to be a git repository\n", .{remote});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        defer allocator.free(config_content);

        const remote_section = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{remote});
        defer allocator.free(remote_section);

        if (std.mem.indexOf(u8, config_content, remote_section)) |section_start| {
            const after_section = config_content[section_start + remote_section.len..];
            var lines = std.mem.splitScalar(u8, after_section, '\n');
            while (lines.next()) |line| {
                const trimmed = std.mem.trim(u8, line, " \t\r");
                if (trimmed.len > 0 and trimmed[0] == '[') break;
                if (std.mem.startsWith(u8, trimmed, "url = ")) {
                    remote_url = try allocator.dupe(u8, trimmed["url = ".len..]);
                    remote_url_allocated = true;
                    break;
                }
            }
        }

        if (!remote_url_allocated) {
            // Fall back to trying as a local git repo path
            if (resolveSourceGitDir(allocator, remote)) |rgd| {
                allocator.free(rgd);
                remote_url = remote;
            } else |_| {
                const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' does not appear to be a git repository\nfatal: Could not read from remote repository.\n", .{remote});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }
        }
    }
    defer if (remote_url_allocated) allocator.free(remote_url);

    // Resolve file:// URLs
    const actual_url = if (std.mem.startsWith(u8, remote_url, "file://"))
        remote_url["file://".len..]
    else
        remote_url;

    // Check if this is an SSH or HTTP URL - not supported
    if (std.mem.startsWith(u8, actual_url, "http://") or std.mem.startsWith(u8, actual_url, "https://") or
        std.mem.startsWith(u8, actual_url, "ssh://") or std.mem.startsWith(u8, actual_url, "git://") or
        std.mem.indexOf(u8, actual_url, ":") != null)
    {
        // Check if it looks like a path with colon (e.g., C:\path on windows) or SSH
        if (!std.mem.startsWith(u8, actual_url, "/") and !std.mem.startsWith(u8, actual_url, ".")) {
            try platform_impl.writeStderr("fatal: remote transport not supported\n");
            std.process.exit(128);
        }
    }

    // Resolve the remote git directory
    const remote_git_dir = resolveSourceGitDir(allocator, actual_url) catch {
        const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' does not appear to be a git repository\nfatal: Could not read from remote repository.\n", .{actual_url});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    };
    defer allocator.free(remote_git_dir);

    // If no refspecs given, figure out what to push
    var had_push_error = false;
    if (refspecs.items.len == 0 and !push_all and !push_tags) {
        // Default: push current branch with matching remote
        const current_branch = refs.getCurrentBranch(git_path, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: not on a branch\n");
            std.process.exit(128);
        };
        defer allocator.free(current_branch);

        // Push current branch to same-named remote branch
        const refspec = try std.fmt.allocPrint(allocator, "refs/heads/{s}:refs/heads/{s}", .{ current_branch, current_branch });
        defer allocator.free(refspec);
        try pushRefspec(allocator, git_path, remote_git_dir, refspec, force_push, dry_run, quiet, platform_impl);
    } else if (push_all) {
        // Push all branches
        const heads_dir = try std.fmt.allocPrint(allocator, "{s}/refs/heads", .{git_path});
        defer allocator.free(heads_dir);
        var dir = std.fs.cwd().openDir(heads_dir, .{ .iterate = true }) catch return;
        defer dir.close();
        var iter = dir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind != .file) continue;
            const rs = try std.fmt.allocPrint(allocator, "refs/heads/{s}:refs/heads/{s}", .{ entry.name, entry.name });
            defer allocator.free(rs);
            try pushRefspec(allocator, git_path, remote_git_dir, rs, force_push, dry_run, quiet, platform_impl);
        }
    } else {
        for (refspecs.items) |refspec_raw| {
            var rs = refspec_raw;
            var force_this = force_push;

            // Handle +refspec (force) prefix
            if (rs.len > 0 and rs[0] == '+') {
                force_this = true;
                rs = rs[1..];
            }

            // Handle delete refspec  :branch
            if (rs.len > 0 and rs[0] == ':') {
                // Empty `:` means push matching (all branches that exist on both sides)
                if (rs.len == 1) {
                    const heads_dir2 = try std.fmt.allocPrint(allocator, "{s}/refs/heads", .{git_path});
                    defer allocator.free(heads_dir2);
                    var dir2 = std.fs.cwd().openDir(heads_dir2, .{ .iterate = true }) catch continue;
                    defer dir2.close();
                    var iter2 = dir2.iterate();
                    while (iter2.next() catch null) |entry2| {
                        if (entry2.kind != .file) continue;
                        const remote_ref_check = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ remote_git_dir, entry2.name });
                        defer allocator.free(remote_ref_check);
                        if (std.fs.cwd().access(remote_ref_check, .{})) {
                            const rspec = try std.fmt.allocPrint(allocator, "refs/heads/{s}:refs/heads/{s}", .{ entry2.name, entry2.name });
                            defer allocator.free(rspec);
                            pushRefspec(allocator, git_path, remote_git_dir, rspec, force_this, dry_run, quiet, platform_impl) catch { had_push_error = true; };
                        } else |_| {}
                    }
                    continue;
                }
                // Delete remote ref
                const remote_ref_name = rs[1..];
                const full_ref = if (std.mem.startsWith(u8, remote_ref_name, "refs/"))
                    try allocator.dupe(u8, remote_ref_name)
                else
                    try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{remote_ref_name});
                defer allocator.free(full_ref);

                if (!dry_run) {
                    const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ remote_git_dir, full_ref });
                    defer allocator.free(ref_path);
                    std.fs.cwd().deleteFile(ref_path) catch {
                        const msg = try std.fmt.allocPrint(allocator, "error: unable to delete '{s}': remote ref does not exist\n", .{full_ref});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                    };
                    if (std.mem.startsWith(u8, full_ref, "refs/heads/")) {
                        const del_branch = full_ref["refs/heads/".len..];
                        const del_track = std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}/{s}", .{ git_path, remote, del_branch }) catch null;
                        defer if (del_track) |dtr| allocator.free(dtr);
                        if (del_track) |dtr| std.fs.cwd().deleteFile(dtr) catch {};
                    }
                }
                if (!quiet) {
                    const msg = try std.fmt.allocPrint(allocator, " - [deleted]         {s}\n", .{remote_ref_name});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                }
                continue;
            }

            // Handle push --delete
            if (push_delete) {
                const full_ref = if (std.mem.startsWith(u8, rs, "refs/"))
                    try allocator.dupe(u8, rs)
                else
                    try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{rs});
                defer allocator.free(full_ref);

                if (!dry_run) {
                    const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ remote_git_dir, full_ref });
                    defer allocator.free(ref_path);
                    std.fs.cwd().deleteFile(ref_path) catch {};
                }
                continue;
            }

            // Normal refspec: src:dst or just src
            if (std.mem.indexOf(u8, rs, ":")) |_| {
                const full_refspec = try std.fmt.allocPrint(allocator, "{s}", .{rs});
                defer allocator.free(full_refspec);
                try pushRefspec(allocator, git_path, remote_git_dir, full_refspec, force_this, dry_run, quiet, platform_impl);
            } else {
                // Just src - push to same-named ref on remote
                var push_src = rs;
                var push_dst = rs;
                var resolved_branch: ?[]u8 = null;
                // If src is HEAD, resolve to current branch
                if (std.mem.eql(u8, rs, "HEAD")) {
                    if (refs.getCurrentBranch(git_path, platform_impl, allocator)) |branch| {
                        resolved_branch = branch;
                        push_src = branch;
                        push_dst = branch;
                    } else |_| {}
                }
                defer if (resolved_branch) |b| allocator.free(b);
                // Check for ambiguous refspec (both branch and tag exist)
                if (!std.mem.startsWith(u8, push_src, "refs/") and !std.mem.eql(u8, push_src, "HEAD")) {
                    const ambig_branch = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, push_src });
                    defer allocator.free(ambig_branch);
                    const ambig_tag = try std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{ git_path, push_src });
                    defer allocator.free(ambig_tag);
                    const ab = if (std.fs.cwd().access(ambig_branch, .{})) true else |_| false;
                    const at = if (std.fs.cwd().access(ambig_tag, .{})) true else |_| false;
                    if (ab and at) {
                        const amsg = try std.fmt.allocPrint(allocator, "error: src refspec {s} matches more than one\nerror: failed to push some refs to '{s}'\n", .{ push_src, actual_url });
                        defer allocator.free(amsg);
                        try platform_impl.writeStderr(amsg);
                        std.process.exit(1);
                    }
                }
                const full_refspec = if (std.mem.startsWith(u8, push_src, "refs/"))
                    try std.fmt.allocPrint(allocator, "{s}:{s}", .{ push_src, push_dst })
                else
                    try std.fmt.allocPrint(allocator, "refs/heads/{s}:refs/heads/{s}", .{ push_src, push_dst });
                defer allocator.free(full_refspec);
                try pushRefspec(allocator, git_path, remote_git_dir, full_refspec, force_this, dry_run, quiet, platform_impl);
            }
        }
    }

    // Handle --follow-tags: push annotated tags
    if (follow_tags) {
        const ftags_dir = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_path});
        defer allocator.free(ftags_dir);
        if (std.fs.cwd().openDir(ftags_dir, .{ .iterate = true })) |ftd_val| {
            var ftd = ftd_val;
            defer ftd.close();
            var ftiter = ftd.iterate();
            while (ftiter.next() catch null) |ftentry| {
                if (ftentry.kind != .file) continue;
                const ft_ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ ftags_dir, ftentry.name }) catch continue;
                defer allocator.free(ft_ref_path);
                const ft_hash_raw = std.fs.cwd().readFileAlloc(allocator, ft_ref_path, 256) catch continue;
                defer allocator.free(ft_hash_raw);
                const ft_hash = std.mem.trim(u8, ft_hash_raw, " \t\r\n");
                const ft_remote_path = std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{ remote_git_dir, ftentry.name }) catch continue;
                defer allocator.free(ft_remote_path);
                if (std.fs.cwd().access(ft_remote_path, .{})) {
                    continue;
                } else |_| {}
                const ft_obj = objects.GitObject.load(ft_hash, git_path, platform_impl, allocator) catch continue;
                defer ft_obj.deinit(allocator);
                if (ft_obj.type != .tag) continue;
                const ft_refspec = std.fmt.allocPrint(allocator, "refs/tags/{s}:refs/tags/{s}", .{ ftentry.name, ftentry.name }) catch continue;
                defer allocator.free(ft_refspec);
                pushRefspec(allocator, git_path, remote_git_dir, ft_refspec, false, dry_run, quiet, platform_impl) catch {};
            }
        } else |_| {}
    }

    // Handle --follow-tags: push annotated tags
    if (follow_tags) {
        const ftags_dir = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_path});
        defer allocator.free(ftags_dir);
        if (std.fs.cwd().openDir(ftags_dir, .{ .iterate = true })) |ftd_val| {
            var ftd = ftd_val;
            defer ftd.close();
            var ftiter = ftd.iterate();
            while (ftiter.next() catch null) |ftentry| {
                if (ftentry.kind != .file) continue;
                const ft_ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ ftags_dir, ftentry.name }) catch continue;
                defer allocator.free(ft_ref_path);
                const ft_hash_raw = std.fs.cwd().readFileAlloc(allocator, ft_ref_path, 256) catch continue;
                defer allocator.free(ft_hash_raw);
                const ft_hash = std.mem.trim(u8, ft_hash_raw, " \t\r\n");
                const ft_remote_path = std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{ remote_git_dir, ftentry.name }) catch continue;
                defer allocator.free(ft_remote_path);
                if (std.fs.cwd().access(ft_remote_path, .{})) {
                    continue;
                } else |_| {}
                const ft_obj = objects.GitObject.load(ft_hash, git_path, platform_impl, allocator) catch continue;
                defer ft_obj.deinit(allocator);
                if (ft_obj.type != .tag) continue;
                const ft_refspec = std.fmt.allocPrint(allocator, "refs/tags/{s}:refs/tags/{s}", .{ ftentry.name, ftentry.name }) catch continue;
                defer allocator.free(ft_refspec);
                pushRefspec(allocator, git_path, remote_git_dir, ft_refspec, false, dry_run, quiet, platform_impl) catch {};
            }
        } else |_| {}
    }

    // Update remote tracking refs - sync refs/remotes/<remote>/* with what remote has
    if (!dry_run and remote_url_allocated) {
        const remote_heads_dir = std.fmt.allocPrint(allocator, "{s}/refs/heads", .{remote_git_dir}) catch null;
        defer if (remote_heads_dir) |d| allocator.free(d);
        if (remote_heads_dir) |rhd| {
            if (std.fs.cwd().openDir(rhd, .{ .iterate = true })) |rd_val| {
                var rd = rd_val;
                defer rd.close();
                var riter = rd.iterate();
                while (riter.next() catch null) |rentry| {
                    if (rentry.kind != .file) continue;
                    const rref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ rhd, rentry.name }) catch continue;
                    defer allocator.free(rref_path);
                    if (std.fs.cwd().readFileAlloc(allocator, rref_path, 256)) |rval| {
                        defer allocator.free(rval);
                        const rh = std.mem.trim(u8, rval, " \t\r\n");
                        const tracking_path = std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}/{s}", .{ git_path, remote, rentry.name }) catch continue;
                        defer allocator.free(tracking_path);
                        if (std.fs.path.dirname(tracking_path)) |dir| std.fs.cwd().makePath(dir) catch {};
                        const tf = std.fs.cwd().createFile(tracking_path, .{}) catch continue;
                        defer tf.close();
                        const thl = std.fmt.allocPrint(allocator, "{s}\n", .{rh}) catch continue;
                        defer allocator.free(thl);
                        tf.writeAll(thl) catch {};
                    } else |_| {}
                }
            } else |_| {}
        }
    }

    if (set_upstream) {
        // TODO: update branch.<name>.remote and branch.<name>.merge
    }
    
    if (had_push_error) {
        std.process.exit(1);
    }
}

fn pushRefspec(allocator: std.mem.Allocator, local_git_dir: []const u8, remote_git_dir: []const u8, refspec: []const u8, force: bool, dry_run: bool, quiet: bool, platform_impl: *const platform_mod.Platform) !void {
    const colon_pos = std.mem.indexOf(u8, refspec, ":") orelse return;
    const src_ref = refspec[0..colon_pos];
    const dst_ref = refspec[colon_pos + 1..];

    // Resolve source ref to hash
    const full_src = if (std.mem.startsWith(u8, src_ref, "refs/"))
        try allocator.dupe(u8, src_ref)
    else
        try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{src_ref});
    defer allocator.free(full_src);

    const src_hash = resolveRevision(local_git_dir, full_src, platform_impl, allocator) catch
        resolveRevision(local_git_dir, src_ref, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "error: src refspec {s} does not match any\n", .{src_ref});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };
    defer allocator.free(src_hash);

    try pushRefspecInner(allocator, local_git_dir, remote_git_dir, src_hash, dst_ref, force, dry_run, quiet, platform_impl);
}

fn pushRefspecInner(allocator: std.mem.Allocator, local_git_dir: []const u8, remote_git_dir: []const u8, src_hash: []const u8, dst_ref: []const u8, force: bool, dry_run: bool, quiet: bool, platform_impl: *const platform_mod.Platform) !void {
    // Check the current value of the remote ref
    const full_dst = if (std.mem.startsWith(u8, dst_ref, "refs/"))
        try allocator.dupe(u8, dst_ref)
    else
        try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{dst_ref});
    defer allocator.free(full_dst);

    // Check receive.denyCurrentBranch for non-bare repos
    {
        const remote_head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{remote_git_dir});
        defer allocator.free(remote_head_path);
        if (std.fs.cwd().readFileAlloc(allocator, remote_head_path, 4096)) |head_content| {
            defer allocator.free(head_content);
            const trimmed_head = std.mem.trim(u8, head_content, " \t\r\n");
            if (std.mem.startsWith(u8, trimmed_head, "ref: ")) {
                const remote_current_ref = trimmed_head["ref: ".len..];
                // Check if this is a non-bare repo (has a working directory)
                const is_bare = blk: {
                    const remote_config_path = std.fmt.allocPrint(allocator, "{s}/config", .{remote_git_dir}) catch break :blk false;
                    defer allocator.free(remote_config_path);
                    const rcfg = std.fs.cwd().readFileAlloc(allocator, remote_config_path, 1024 * 1024) catch break :blk false;
                    defer allocator.free(rcfg);
                    if (std.mem.indexOf(u8, rcfg, "bare = true")) |_| break :blk true;
                    break :blk false;
                };
                if (!is_bare and std.mem.eql(u8, full_dst, remote_current_ref)) {
                    // Check receive.denyCurrentBranch config
                    const remote_config_path = std.fmt.allocPrint(allocator, "{s}/config", .{remote_git_dir}) catch "";
                    defer if (remote_config_path.len > 0) allocator.free(remote_config_path);
                    var deny = true; // default is refuse
                    if (remote_config_path.len > 0) {
                        if (std.fs.cwd().readFileAlloc(allocator, remote_config_path, 1024 * 1024)) |rcfg| {
                            defer allocator.free(rcfg);
                            if (parseConfigValue(rcfg, "receive.denycurrentbranch", allocator) catch null) |val| {
                                defer allocator.free(val);
                                if (std.ascii.eqlIgnoreCase(val, "false") or std.ascii.eqlIgnoreCase(val, "warn") or std.ascii.eqlIgnoreCase(val, "ignore")) deny = false;
                            }
                        } else |_| {}
                    }
                    if (deny) {
                        const branch_short = if (std.mem.startsWith(u8, full_dst, "refs/heads/")) full_dst["refs/heads/".len..] else full_dst;
                        const msg = try std.fmt.allocPrint(allocator, " ! [remote rejected] {s} -> {s} (branch is currently checked out)\nremote: error: refusing to update checked out branch: {s}\nremote: error: By default, updating the current branch in a non-bare repository\nremote: is denied.\nerror: failed to push some refs\n", .{ branch_short, branch_short, full_dst });
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        return error.ObjectNotFound; // Signal denial
                    }
                }
            }
        } else |_| {}
    }

    const dst_ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ remote_git_dir, full_dst });
    defer allocator.free(dst_ref_path);

    // Read current remote ref value
    var old_hash: ?[]const u8 = null;
    if (std.fs.cwd().readFileAlloc(allocator, dst_ref_path, 256)) |content| {
        old_hash = std.mem.trim(u8, content, " \t\r\n");
    } else |_| {
        // Check packed-refs
        const packed_refs_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{remote_git_dir});
        defer allocator.free(packed_refs_path);
        if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 1024 * 1024)) |packed_content| {
            defer allocator.free(packed_content);
            var lines = std.mem.splitScalar(u8, packed_content, '\n');
            while (lines.next()) |line| {
                if (line.len > 0 and line[0] == '#') continue;
                if (line.len > 0 and line[0] == '^') continue;
                if (std.mem.indexOf(u8, line, " ")) |sp| {
                    const hash = line[0..sp];
                    const ref_name = line[sp + 1 ..];
                    if (std.mem.eql(u8, ref_name, full_dst)) {
                        old_hash = try allocator.dupe(u8, hash);
                        break;
                    }
                }
            }
        } else |_| {}
    }

    // Check fast-forward (unless force)
    if (old_hash) |oh| {
        if (std.mem.eql(u8, oh, src_hash)) {
            // Already up to date
            if (!quiet) {
                const msg = try std.fmt.allocPrint(allocator, "Everything up-to-date\n", .{});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            }
            return;
        }

        if (!force) {
            // Check if src_hash is a descendant of old_hash (fast-forward check)
            const is_ff = isAncestor(local_git_dir, oh, src_hash, allocator, platform_impl) catch false;
            if (!is_ff) {
                const msg = try std.fmt.allocPrint(allocator, " ! [rejected]        {s} -> {s} (non-fast-forward)\nerror: failed to push some refs to '{s}'\nhint: Updates were rejected because the tip of your current branch is behind\nhint: its remote counterpart.\n", .{ dst_ref, dst_ref, remote_git_dir });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                return error.ObjectNotFound; // Signal non-FF failure
            }
        }
    }

    if (dry_run) return;

    // Copy objects from local to remote
    try copyObjectsForPush(allocator, local_git_dir, remote_git_dir, src_hash, platform_impl);

    // Write the ref
    const ref_dir = std.fs.path.dirname(dst_ref_path) orelse ".";
    std.fs.cwd().makePath(ref_dir) catch {};
    const f = try std.fs.cwd().createFile(dst_ref_path, .{});
    defer f.close();
    const hash_line = try std.fmt.allocPrint(allocator, "{s}\n", .{src_hash});
    defer allocator.free(hash_line);
    try f.writeAll(hash_line);

    if (!quiet) {
        if (old_hash == null) {
            const msg = try std.fmt.allocPrint(allocator, " * [new branch]      {s} -> {s}\n", .{ dst_ref, dst_ref });
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
        }
    }
}

fn copyObjectsForPush(allocator: std.mem.Allocator, src_git_dir: []const u8, dst_git_dir: []const u8, commit_hash: []const u8, platform_impl: *const platform_mod.Platform) !void {
    // Walk commit chain and copy all reachable objects
    var to_visit = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (to_visit.items) |item| allocator.free(item);
        to_visit.deinit();
    }
    var visited = std.StringHashMap(void).init(allocator);
    defer visited.deinit();

    try to_visit.append(try allocator.dupe(u8, commit_hash));

    while (to_visit.items.len > 0) {
        const hash = to_visit.orderedRemove(0);
        defer allocator.free(hash);

        if (visited.contains(hash)) continue;
        visited.put(hash, {}) catch continue;

        // Try to copy the loose object
        const src_path = try std.fmt.allocPrint(allocator, "{s}/objects/{s}/{s}", .{ src_git_dir, hash[0..2], hash[2..] });
        defer allocator.free(src_path);
        const dst_path = try std.fmt.allocPrint(allocator, "{s}/objects/{s}/{s}", .{ dst_git_dir, hash[0..2], hash[2..] });
        defer allocator.free(dst_path);

        // Create destination directory
        const dst_dir = try std.fmt.allocPrint(allocator, "{s}/objects/{s}", .{ dst_git_dir, hash[0..2] });
        defer allocator.free(dst_dir);
        std.fs.cwd().makePath(dst_dir) catch {};

        // Copy the object if it doesn't exist at destination (loose or pack)
        if (std.fs.cwd().access(dst_path, .{})) {
            // Already exists as loose object at destination - skip
        } else |_| {
            std.fs.cwd().copyFile(src_path, std.fs.cwd(), dst_path, .{}) catch {
                // Object might be in pack file - need to extract and write it
                const obj = objects.GitObject.load(hash, src_git_dir, platform_impl, allocator) catch continue;
                defer obj.deinit(allocator);
                _ = obj.store(dst_git_dir, platform_impl, allocator) catch continue;
            };
        }

        // Parse the object to find referenced objects
        const obj = objects.GitObject.load(hash, src_git_dir, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);

        switch (obj.type) {
            .commit => {
                var line_iter = std.mem.splitScalar(u8, obj.data, '\n');
                while (line_iter.next()) |line| {
                    if (line.len == 0) break;
                    if (std.mem.startsWith(u8, line, "tree ")) {
                        const tree_hash = line["tree ".len..];
                        if (!visited.contains(tree_hash)) {
                            try to_visit.append(try allocator.dupe(u8, tree_hash));
                        }
                    } else if (std.mem.startsWith(u8, line, "parent ")) {
                        const parent_hash = line["parent ".len..];
                        if (!visited.contains(parent_hash)) {
                            try to_visit.append(try allocator.dupe(u8, parent_hash));
                        }
                    }
                }
            },
            .tree => {
                var entries = tree_mod.parseTree(obj.data, allocator) catch continue;
                defer entries.deinit();
                for (entries.items) |entry| {
                    if (!visited.contains(entry.hash)) {
                        try to_visit.append(try allocator.dupe(u8, entry.hash));
                    }
                }
            },
            .tag => {
                var line_iter = std.mem.splitScalar(u8, obj.data, '\n');
                while (line_iter.next()) |line| {
                    if (std.mem.startsWith(u8, line, "object ")) {
                        const obj_hash = line["object ".len..];
                        if (!visited.contains(obj_hash)) {
                            try to_visit.append(try allocator.dupe(u8, obj_hash));
                        }
                        break;
                    }
                }
            },
            .blob => {},
        }
    }

    // Also copy pack files if needed
    const src_pack_dir = try std.fmt.allocPrint(allocator, "{s}/objects/pack", .{src_git_dir});
    defer allocator.free(src_pack_dir);
    const dst_pack_dir = try std.fmt.allocPrint(allocator, "{s}/objects/pack", .{dst_git_dir});
    defer allocator.free(dst_pack_dir);
    std.fs.cwd().makePath(dst_pack_dir) catch {};
}

fn isValidRemoteName(name: []const u8) bool {
    if (name.len == 0) return false;
    if (name[0] == '-') return false;
    if (std.mem.eql(u8, name, ".") or std.mem.eql(u8, name, "..")) return false;
    // Check for .. sequences
    if (std.mem.indexOf(u8, name, "..") != null) return false;
    // Check for invalid characters
    for (name) |c| {
        if (c == ' ' or c == '~' or c == '^' or c == ':' or c == '?' or c == '*' or c == '[' or c == '\\') return false;
        if (c < 0x20 or c == 0x7f) return false;
    }
    if (name[name.len - 1] == '.') return false;
    if (std.mem.endsWith(u8, name, ".lock")) return false;
    return true;
}

fn isValidHash(hash: []const u8) bool {
    if (hash.len != 40) return false;
    for (hash) |c| {
        if (!std.ascii.isHex(c)) return false;
    }
    return true;
}

fn isValidHashPrefix(hash: []const u8) bool {
    if (hash.len < 4 or hash.len > 40) return false;
    for (hash) |c| {
        if (!std.ascii.isHex(c)) return false;
    }
    return true;
}

fn isValidBranchName(name: []const u8) bool {
    if (name.len == 0) return false;
    if (name[0] == '-') return false;
    if (name[0] == '.') return false;
    if (std.mem.endsWith(u8, name, ".lock")) return false;
    if (std.mem.endsWith(u8, name, ".")) return false;
    if (std.mem.eql(u8, name, "@")) return false;
    for (name) |c| {
        if (c <= 0x20 or c == 0x7f) return false; // control chars and space
        if (c == '~' or c == '^' or c == ':' or c == '\\') return false;
        if (c == '?' or c == '*' or c == '[') return false;
    }
    // Check for ".." and "@{"
    if (std.mem.indexOf(u8, name, "..") != null) return false;
    if (std.mem.indexOf(u8, name, "@{") != null) return false;
    if (std.mem.indexOf(u8, name, "//") != null) return false;
    return true;
}

fn isValidHexString(s: []const u8) bool {
    for (s) |c| {
        if (!std.ascii.isHex(c)) return false;
    }
    return s.len > 0;
}

fn resolveCommitHash(git_path: []const u8, hash_prefix: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // If it's already a full hash, just validate it exists
    if (hash_prefix.len == 40) {
        // Try to load the object to verify it exists
        const obj = objects.GitObject.load(hash_prefix, git_path, platform_impl, allocator) catch return error.CommitNotFound;
        obj.deinit(allocator);
        return try allocator.dupe(u8, hash_prefix);
    }
    
    // For short hashes, we need to scan the objects directory
    // This is a simplified implementation - a full implementation would be more efficient
    const objects_path = try std.fmt.allocPrint(allocator, "{s}/objects", .{git_path});
    defer allocator.free(objects_path);
    
    // Get the first two characters for the directory
    if (hash_prefix.len < 2) return error.CommitNotFound;
    const dir_name = hash_prefix[0..2];
    const file_prefix = hash_prefix[2..];
    
    const subdir_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_path, dir_name });
    defer allocator.free(subdir_path);
    
    var dir = std.fs.cwd().openDir(subdir_path, .{ .iterate = true }) catch return error.CommitNotFound;
    defer dir.close();
    
    var found_hash: ?[]u8 = null;
    var iterator = dir.iterate();
    while (try iterator.next()) |entry| {
        if (entry.kind != .file) continue;
        
        if (std.mem.startsWith(u8, entry.name, file_prefix)) {
            if (found_hash != null) {
                // Ambiguous hash prefix
                allocator.free(found_hash.?);
                return error.CommitNotFound;
            }
            
            // Reconstruct full hash
            const full_hash = try std.fmt.allocPrint(allocator, "{s}{s}", .{ dir_name, entry.name });
            
            // Verify this is a commit object
            const obj = objects.GitObject.load(full_hash, git_path, platform_impl, allocator) catch {
                allocator.free(full_hash);
                continue;
            };
            defer obj.deinit(allocator);
            
            if (obj.type == .commit) {
                found_hash = full_hash;
            } else {
                allocator.free(full_hash);
            }
        }
    }
    
    return found_hash orelse error.CommitNotFound;
}

fn lookupBlobInTree(tree_hash: []const u8, path: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !?[20]u8 {
    // Load tree object
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return null;
    defer tree_obj.deinit(allocator);
    
    if (tree_obj.type != .tree) return null;
    
    // Split path into first component and rest
    const slash_pos = std.mem.indexOfScalar(u8, path, '/');
    const name_to_find = if (slash_pos) |pos| path[0..pos] else path;
    const remaining = if (slash_pos) |pos| path[pos + 1 ..] else null;
    
    // Parse tree entries
    var i: usize = 0;
    while (i < tree_obj.data.len) {
        const space_pos = std.mem.indexOfScalarPos(u8, tree_obj.data, i, ' ') orelse break;
        const null_pos = std.mem.indexOfScalarPos(u8, tree_obj.data, space_pos + 1, 0) orelse break;
        const name = tree_obj.data[space_pos + 1 .. null_pos];
        
        const hash_start = null_pos + 1;
        if (hash_start + 20 > tree_obj.data.len) break;
        const hash_bytes = tree_obj.data[hash_start .. hash_start + 20];
        
        if (std.mem.eql(u8, name, name_to_find)) {
            if (remaining) |rest| {
                // This is a directory - recurse
                const sub_tree_hash = try std.fmt.allocPrint(allocator, "{x}", .{hash_bytes});
                defer allocator.free(sub_tree_hash);
                return try lookupBlobInTree(sub_tree_hash, rest, git_path, platform_impl, allocator);
            } else {
                // This is the file - return its hash
                var result: [20]u8 = undefined;
                @memcpy(&result, hash_bytes);
                return result;
            }
        }
        
        i = hash_start + 20;
    }
    
    return null; // Not found
}

fn checkIfDifferentFromHEAD(entry: index_mod.IndexEntry, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !bool {
    // Get current HEAD commit
    const head_hash_opt = refs.getCurrentCommit(git_path, platform_impl, allocator) catch return false;
    const head_hash = head_hash_opt orelse return false;
    defer allocator.free(head_hash);
    
    // Load HEAD commit
    const commit_obj = objects.GitObject.load(head_hash, git_path, platform_impl, allocator) catch return false;
    defer commit_obj.deinit(allocator);
    
    if (commit_obj.type != .commit) return false;
    
    // Parse commit to get tree hash
    var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
    const tree_line = lines.next() orelse return false;
    if (!std.mem.startsWith(u8, tree_line, "tree ")) return false;
    const tree_hash = tree_line["tree ".len..];
    
    // Look up the blob hash in the tree (recursively handles subdirectories)
    const tree_blob_hash = try lookupBlobInTree(tree_hash, entry.path, git_path, platform_impl, allocator);
    
    if (tree_blob_hash) |hash_bytes| {
        // Compare with index entry hash
        return !std.mem.eql(u8, &hash_bytes, &entry.sha1);
    }
    
    // File not found in tree - it's new, so it's staged
    return true;
}

fn addSingleFile(allocator: std.mem.Allocator, relative_path: []const u8, full_path: []const u8, index: *index_mod.Index, git_path: []const u8, platform_impl: *const platform_mod.Platform, repo_root: []const u8) !void {
    // Check if file is ignored
    const gitignore_path = try std.fmt.allocPrint(allocator, "{s}/.gitignore", .{repo_root});
    defer allocator.free(gitignore_path);
    
    var gitignore = gitignore_mod.GitIgnore.loadFromFile(allocator, gitignore_path, platform_impl) catch |err| switch (err) {
        error.OutOfMemory => return err,
        else => gitignore_mod.GitIgnore.init(allocator), // If there's any issue loading, just use empty gitignore
    };
    defer gitignore.deinit();
    
    if (gitignore.isIgnored(relative_path)) {
        // Just skip ignored files instead of erroring
        return;
    }

    // Add to index
    index.add(relative_path, full_path, platform_impl, git_path) catch |err| switch (err) {
        error.OutOfMemory => return err,
        else => {
            const msg = try std.fmt.allocPrint(allocator, "error: failed to add '{s}' to index\n", .{relative_path});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            return err;
        },
    };
}

fn addDirectoryRecursively(allocator: std.mem.Allocator, repo_root: []const u8, relative_dir: []const u8, index: *index_mod.Index, git_path: []const u8, platform_impl: *const platform_mod.Platform) !void {
    const full_dir_path = if (relative_dir.len == 0)
        try allocator.dupe(u8, repo_root)
    else
        try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, relative_dir });
    defer allocator.free(full_dir_path);

    // Try to open directory
    var dir = std.fs.cwd().openDir(full_dir_path, .{ .iterate = true }) catch |err| switch (err) {
        error.NotDir, error.AccessDenied, error.FileNotFound => return,
        else => return err,
    };
    defer dir.close();

    var iterator = dir.iterate();
    while (iterator.next() catch null) |entry| {
        // Skip .git directory
        if (std.mem.eql(u8, entry.name, ".git")) continue;
        
        const entry_relative_path = if (relative_dir.len == 0)
            try allocator.dupe(u8, entry.name)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ relative_dir, entry.name });
        defer allocator.free(entry_relative_path);
        
        const entry_full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ full_dir_path, entry.name });
        defer allocator.free(entry_full_path);
        
        switch (entry.kind) {
            .file => {
                addSingleFile(allocator, entry_relative_path, entry_full_path, index, git_path, platform_impl, repo_root) catch continue;
            },
            .sym_link => {
                // Add symlink - index.add handles symlinks natively
                const repo_root_dir = std.fs.path.dirname(git_path) orelse ".";
                const rel_to_repo = if (std.mem.startsWith(u8, entry_full_path, repo_root_dir))
                    entry_full_path[repo_root_dir.len + 1 ..]
                else
                    entry_relative_path;
                index.add(rel_to_repo, rel_to_repo, platform_impl, git_path) catch continue;
            },
            .directory => {
                // Recursively add subdirectory
                addDirectoryRecursively(allocator, repo_root, entry_relative_path, index, git_path, platform_impl) catch continue;
            },
            else => continue, // Skip other types
        }
    }
}

/// Build recursive tree objects from a list of index entries.
/// For entries with paths like "src/main.zig", creates subtree objects for each directory level,
/// matching git's expected tree format.
fn buildRecursiveTree(allocator: std.mem.Allocator, entries: []const index_mod.IndexEntry, prefix: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) ![]u8 {
    const TreeItem = struct {
        name: []const u8,
        mode: []const u8,
        hash_bytes: [20]u8,
    };
    var items = std.array_list.Managed(TreeItem).init(allocator);
    defer {
        for (items.items) |item| {
            allocator.free(item.name);
            allocator.free(item.mode);
        }
        items.deinit();
    }

    // Track subdirectories we've already processed
    var seen_dirs = std.StringHashMap(void).init(allocator);
    defer {
        var kit = seen_dirs.keyIterator();
        while (kit.next()) |key| allocator.free(key.*);
        seen_dirs.deinit();
    }

    for (entries) |entry| {
        // Only consider entries under our prefix
        const rel_path = if (prefix.len == 0)
            entry.path
        else blk: {
            if (std.mem.startsWith(u8, entry.path, prefix) and
                entry.path.len > prefix.len and
                entry.path[prefix.len] == '/')
            {
                break :blk entry.path[prefix.len + 1 ..];
            } else continue;
        };

        // Check if this is a direct child or lives in a subdirectory
        if (std.mem.indexOfScalar(u8, rel_path, '/')) |slash_pos| {
            // It's inside a subdirectory — record the dir name
            const dir_name = rel_path[0..slash_pos];
            if (!seen_dirs.contains(dir_name)) {
                const duped = try allocator.dupe(u8, dir_name);
                try seen_dirs.put(duped, {});
            }
        } else {
            // Direct child (blob)
            const mode_str = try std.fmt.allocPrint(allocator, "{o}", .{entry.mode});
            try items.append(.{
                .name = try allocator.dupe(u8, rel_path),
                .mode = mode_str,
                .hash_bytes = entry.sha1,
            });
        }
    }

    // Recurse into each subdirectory
    var dir_it = seen_dirs.keyIterator();
    while (dir_it.next()) |dir_name_ptr| {
        const dir_name = dir_name_ptr.*;
        const sub_prefix = if (prefix.len == 0)
            try allocator.dupe(u8, dir_name)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, dir_name });
        defer allocator.free(sub_prefix);

        const sub_hash_hex = try buildRecursiveTree(allocator, entries, sub_prefix, git_path, platform_impl);
        defer allocator.free(sub_hash_hex);

        var sub_hash: [20]u8 = undefined;
        _ = try std.fmt.hexToBytes(&sub_hash, sub_hash_hex);

        try items.append(.{
            .name = try allocator.dupe(u8, dir_name),
            .mode = try allocator.dupe(u8, "40000"),
            .hash_bytes = sub_hash,
        });
    }

    // Sort items by name (git requires sorted tree entries; dirs get trailing '/' for comparison)
    std.sort.block(TreeItem, items.items, {}, struct {
        fn lessThan(_: void, a: TreeItem, b: TreeItem) bool {
            const a_is_dir = std.mem.eql(u8, a.mode, "40000");
            const b_is_dir = std.mem.eql(u8, b.mode, "40000");
            // Git tree sort: compare as if dirs have trailing '/'
            if (a_is_dir and !b_is_dir) {
                // Compare a.name + "/" vs b.name
                const order = std.mem.order(u8, a.name, b.name[0..@min(a.name.len, b.name.len)]);
                if (order != .eq) return order == .lt;
                if (a.name.len < b.name.len) {
                    return '/' < b.name[a.name.len];
                }
                return a.name.len < b.name.len;
            } else if (!a_is_dir and b_is_dir) {
                const order = std.mem.order(u8, a.name[0..@min(a.name.len, b.name.len)], b.name);
                if (order != .eq) return order == .lt;
                if (b.name.len < a.name.len) {
                    return a.name[b.name.len] < '/';
                }
                return a.name.len < b.name.len;
            } else {
                return std.mem.lessThan(u8, a.name, b.name);
            }
        }
    }.lessThan);

    // Build tree content
    var tree_content = std.array_list.Managed(u8).init(allocator);
    defer tree_content.deinit();

    for (items.items) |item| {
        try tree_content.appendSlice(item.mode);
        try tree_content.append(' ');
        try tree_content.appendSlice(item.name);
        try tree_content.append(0);
        try tree_content.appendSlice(&item.hash_bytes);
    }

    // Create and store the tree object
    const tree_data = try allocator.dupe(u8, tree_content.items);
    var tree_object = objects.GitObject.init(.tree, tree_data);
    defer tree_object.deinit(allocator);

    return try tree_object.store(git_path, platform_impl, allocator);
}

/// Stage all tracked file changes into the index (pure Zig replacement for `git add -u`).
/// For each entry in the index, check if the working-tree file was modified or deleted,
/// then update or remove the index entry accordingly.
fn stageTrackedChanges(allocator: std.mem.Allocator, index: *index_mod.Index, git_path: []const u8, repo_root: []const u8, platform_impl: *const platform_mod.Platform) !void {
    // Collect paths to remove (deleted files) and paths to re-add (modified files).
    // We collect first to avoid mutating the list while iterating.
    var to_remove = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (to_remove.items) |p| allocator.free(p);
        to_remove.deinit();
    }
    var to_readd = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (to_readd.items) |p| allocator.free(p);
        to_readd.deinit();
    }

    for (index.entries.items) |entry| {
        const full_path = if (repo_root.len > 0 and !std.mem.eql(u8, repo_root, "."))
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path })
        else
            try allocator.dupe(u8, entry.path);
        defer allocator.free(full_path);

        // Check if file still exists
        const file_exists = if (std.fs.path.isAbsolute(full_path))
            blk: {
                std.fs.accessAbsolute(full_path, .{}) catch break :blk false;
                break :blk true;
            }
        else
            blk: {
                std.fs.cwd().access(full_path, .{}) catch break :blk false;
                break :blk true;
            };

        if (!file_exists) {
            try to_remove.append(try allocator.dupe(u8, entry.path));
            continue;
        }

        // Read file content and hash it to see if it changed
        const content = platform_impl.fs.readFile(allocator, full_path) catch continue;
        defer allocator.free(content);

        // Compute blob hash
        const header = try std.fmt.allocPrint(allocator, "blob {d}\x00", .{content.len});
        defer allocator.free(header);

        var hasher = std.crypto.hash.Sha1.init(.{});
        hasher.update(header);
        hasher.update(content);
        var new_hash: [20]u8 = undefined;
        hasher.final(&new_hash);

        if (!std.mem.eql(u8, &new_hash, &entry.sha1)) {
            try to_readd.append(try allocator.dupe(u8, entry.path));
        }
    }

    // Remove deleted files from index
    for (to_remove.items) |path| {
        try index.remove(path);
    }

    // Re-add modified files (this re-hashes and stores the blob)
    for (to_readd.items) |path| {
        const full_path = if (repo_root.len > 0 and !std.mem.eql(u8, repo_root, "."))
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, path })
        else
            try allocator.dupe(u8, path);
        defer allocator.free(full_path);
        index.add(path, full_path, platform_impl, git_path) catch continue;
    }

    // Save the updated index
    try index.save(git_path, platform_impl);
}

/// Get timezone offset in seconds from UTC.
/// Reads from the TZ environment variable or /etc/timezone, /etc/localtime.
/// For simplicity, uses the TZ env var if set (e.g. "EST+5" or numeric offset),
/// otherwise returns 0.
fn getTimezoneOffset(timestamp: i64) i32 {
    _ = timestamp;
    // Try TZ environment variable for simple offset formats
    if (std.posix.getenv("TZ")) |tz| {
        // Handle formats like "UTC-5", "EST+5", or just "+0530"
        return parseTzOffset(tz);
    }
    return 0;
}

fn parseTzOffset(tz: []const u8) i32 {
    // Find first +/- that indicates offset
    var i: usize = 0;
    while (i < tz.len) : (i += 1) {
        if (tz[i] == '+' or tz[i] == '-') {
            const sign: i32 = if (tz[i] == '-') 1 else -1; // TZ convention: UTC-5 means +5 hours ahead... actually POSIX TZ is inverted
            // Actually in POSIX, TZ=EST5EDT means EST is UTC-5. The number is positive for west of UTC.
            // So TZ offset sign is inverted: positive number = west = negative UTC offset
            const rest = tz[i + 1 ..];
            // Parse hours (and optional :minutes)
            var colon_pos: ?usize = null;
            for (rest, 0..) |c, j| {
                if (c == ':') {
                    colon_pos = j;
                    break;
                }
            }
            if (colon_pos) |cp| {
                const hours = std.fmt.parseInt(i32, rest[0..cp], 10) catch return 0;
                const minutes = std.fmt.parseInt(i32, rest[cp + 1 ..], 10) catch return 0;
                return sign * (hours * 3600 + minutes * 60);
            } else {
                // Just hours
                var end: usize = rest.len;
                for (rest, 0..) |c, j| {
                    if (!std.ascii.isDigit(c)) {
                        end = j;
                        break;
                    }
                }
                if (end == 0) return 0;
                const hours = std.fmt.parseInt(i32, rest[0..end], 10) catch return 0;
                return sign * hours * 3600;
            }
        }
    }
    return 0;
}

/// Resolve author name from environment or git config.
fn resolveAuthorName(allocator: std.mem.Allocator, git_path: []const u8) ![]const u8 {
    // 1. GIT_AUTHOR_NAME env var takes highest precedence
    if (std.posix.getenv("GIT_AUTHOR_NAME")) |name| {
        return try allocator.dupe(u8, name);
    }
    // 2. Git config user.name
    if (readConfigUserName(allocator, git_path)) |name| {
        return name;
    }
    return error.NotFound;
}

/// Resolve author email from environment or git config.
fn resolveAuthorEmail(allocator: std.mem.Allocator, git_path: []const u8) ![]const u8 {
    if (std.posix.getenv("GIT_AUTHOR_EMAIL")) |email| {
        return try allocator.dupe(u8, email);
    }
    if (readConfigUserEmail(allocator, git_path)) |email| {
        return email;
    }
    return error.NotFound;
}

/// Resolve committer name from environment, config, or fall back to author name.
fn resolveCommitterName(allocator: std.mem.Allocator, git_path: []const u8, fallback: []const u8) ![]const u8 {
    if (std.posix.getenv("GIT_COMMITTER_NAME")) |name| {
        return try allocator.dupe(u8, name);
    }
    if (readConfigUserName(allocator, git_path)) |name| {
        return name;
    }
    _ = fallback;
    return error.NotFound;
}

/// Resolve committer email from environment, config, or fall back to author email.
fn resolveCommitterEmail(allocator: std.mem.Allocator, git_path: []const u8, fallback: []const u8) ![]const u8 {
    if (std.posix.getenv("GIT_COMMITTER_EMAIL")) |email| {
        return try allocator.dupe(u8, email);
    }
    if (readConfigUserEmail(allocator, git_path)) |email| {
        return email;
    }
    _ = fallback;
    return error.NotFound;
}

/// Read user.name from git config (local then global).
fn readConfigUserName(allocator: std.mem.Allocator, git_path: []const u8) ?[]const u8 {
    var config = config_mod.loadGitConfig(git_path, allocator) catch return null;
    defer config.deinit();
    const name = config.getUserName() orelse return null;
    return allocator.dupe(u8, name) catch null;
}

/// Read user.email from git config (local then global).
fn readConfigUserEmail(allocator: std.mem.Allocator, git_path: []const u8) ?[]const u8 {
    var config = config_mod.loadGitConfig(git_path, allocator) catch return null;
    defer config.deinit();
    const email = config.getUserEmail() orelse return null;
    return allocator.dupe(u8, email) catch null;
}

fn createDirectoryRecursive(path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Try to create the directory directly first
    platform_impl.fs.makeDir(path) catch |err| switch (err) {
        error.AlreadyExists => return,
        error.FileNotFound => {
            // Parent doesn't exist, create it recursively
            if (std.fs.path.dirname(path)) |parent| {
                if (!std.mem.eql(u8, parent, path)) {
                    try createDirectoryRecursive(parent, platform_impl, allocator);
                    // Now try to create the directory again
                    return platform_impl.fs.makeDir(path);
                }
            }
            return err;
        },
        else => return err,
    };
}

fn cmdBranch(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("branch: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    const first_arg = args.next();

    if (first_arg == null) {
        // List branches
        const current_branch = refs.getCurrentBranch(git_path, platform_impl, allocator) catch "master";
        defer allocator.free(current_branch);

        var branches = try refs.listBranches(git_path, platform_impl, allocator);
        defer {
            for (branches.items) |branch| {
                allocator.free(branch);
            }
            branches.deinit();
        }

        for (branches.items) |branch| {
            const prefix = if (std.mem.eql(u8, branch, current_branch)) "* " else "  ";
            const msg = try std.fmt.allocPrint(allocator, "{s}{s}\n", .{ prefix, branch });
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    } else if (std.mem.startsWith(u8, first_arg.?, "--set-upstream-to=") or std.mem.eql(u8, first_arg.?, "--set-upstream-to") or std.mem.eql(u8, first_arg.?, "-u")) {
        // Set upstream tracking branch
        const upstream_name = if (std.mem.startsWith(u8, first_arg.?, "--set-upstream-to="))
            first_arg.?["--set-upstream-to=".len..]
        else
            args.next() orelse {
                try platform_impl.writeStderr("fatal: no upstream branch specified\n");
                std.process.exit(128);
                unreachable;
            };
        const branch_name = args.next() orelse blk: {
            break :blk refs.getCurrentBranch(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: no branch specified and no current branch\n");
                std.process.exit(128);
                unreachable;
            };
        };
        // branch_name may need freeing if allocated
        
        // Write tracking config: [branch "name"] remote = . merge = refs/heads/upstream
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const existing = platform_impl.fs.readFile(allocator, config_path) catch try allocator.dupe(u8, "");
        defer allocator.free(existing);
        
        // Remove existing [branch "name"] section if present
        var new_config = std.array_list.Managed(u8).init(allocator);
        defer new_config.deinit();
        var skip_section = false;
        const section_header = try std.fmt.allocPrint(allocator, "[branch \"{s}\"]", .{branch_name});
        defer allocator.free(section_header);
        var lines = std.mem.splitScalar(u8, existing, '\n');
        while (lines.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (std.mem.startsWith(u8, trimmed, section_header)) {
                skip_section = true;
                continue;
            }
            if (skip_section and trimmed.len > 0 and trimmed[0] == '[') {
                skip_section = false;
            }
            if (!skip_section) {
                new_config.appendSlice(line) catch {};
                new_config.append('\n') catch {};
            }
        }
        // Add new section
        const tracking_section = try std.fmt.allocPrint(allocator, "[branch \"{s}\"]\n\tremote = .\n\tmerge = refs/heads/{s}\n", .{branch_name, upstream_name});
        defer allocator.free(tracking_section);
        new_config.appendSlice(tracking_section) catch {};
        
        std.fs.cwd().writeFile(.{ .sub_path = config_path, .data = new_config.items }) catch {};
        
        const success_msg = try std.fmt.allocPrint(allocator, "branch '{s}' set up to track '{s}'.\n", .{branch_name, upstream_name});
        defer allocator.free(success_msg);
        try platform_impl.writeStdout(success_msg);
    } else if (std.mem.eql(u8, first_arg.?, "--unset-upstream")) {
        // Unset upstream
        const branch_name = args.next() orelse blk: {
            break :blk refs.getCurrentBranch(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: no branch specified\n");
                std.process.exit(128);
                unreachable;
            };
        };
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const existing = platform_impl.fs.readFile(allocator, config_path) catch try allocator.dupe(u8, "");
        defer allocator.free(existing);
        var new_config = std.array_list.Managed(u8).init(allocator);
        defer new_config.deinit();
        var skip_section = false;
        const section_header = try std.fmt.allocPrint(allocator, "[branch \"{s}\"]", .{branch_name});
        defer allocator.free(section_header);
        var line_iter = std.mem.splitScalar(u8, existing, '\n');
        while (line_iter.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (std.mem.startsWith(u8, trimmed, section_header)) { skip_section = true; continue; }
            if (skip_section and trimmed.len > 0 and trimmed[0] == '[') { skip_section = false; }
            if (!skip_section) { new_config.appendSlice(line) catch {}; new_config.append('\n') catch {}; }
        }
        std.fs.cwd().writeFile(.{ .sub_path = config_path, .data = new_config.items }) catch {};

    } else if (std.mem.eql(u8, first_arg.?, "-d") or std.mem.eql(u8, first_arg.?, "-D")) {
        // Delete branch - may have -r flag and/or multiple branch names
        var is_remote = false;
        var names_to_delete = std.array_list.Managed([]const u8).init(allocator);
        defer names_to_delete.deinit();
        while (args.next()) |darg| {
            if (std.mem.eql(u8, darg, "-r") or std.mem.eql(u8, darg, "--remotes")) {
                is_remote = true;
            } else if (std.mem.startsWith(u8, darg, "@{-")) {
                // Resolve @{-N} to previous branch name
                if (std.mem.indexOf(u8, darg, "}")) |close| {
                    const n_str = darg[3..close];
                    const n = std.fmt.parseInt(u32, n_str, 10) catch {
                        try names_to_delete.append(darg);
                        continue;
                    };
                    const prev_branch = resolvePreviousBranch(git_path, n, allocator, platform_impl) catch {
                        const emsg = try std.fmt.allocPrint(allocator, "error: branch '{s}' not found.\n", .{darg});
                        defer allocator.free(emsg);
                        try platform_impl.writeStderr(emsg);
                        std.process.exit(1);
                    };
                    try names_to_delete.append(prev_branch);
                } else {
                    try names_to_delete.append(darg);
                }
            } else if (std.mem.eql(u8, darg, "-")) {
                // "-" is alias for @{-1}
                const prev_branch = resolvePreviousBranch(git_path, 1, allocator, platform_impl) catch {
                    const emsg = try std.fmt.allocPrint(allocator, "error: branch '-' not found.\n", .{});
                    defer allocator.free(emsg);
                    try platform_impl.writeStderr(emsg);
                    std.process.exit(1);
                };
                try names_to_delete.append(prev_branch);
            } else {
                try names_to_delete.append(darg);
            }
        }
        if (names_to_delete.items.len == 0) {
            try platform_impl.writeStderr("fatal: branch name required\n");
            std.process.exit(128);
        }

        const current_branch = refs.getCurrentBranch(git_path, platform_impl, allocator) catch "master";
        defer allocator.free(current_branch);

        for (names_to_delete.items) |branch_name| {
            if (!is_remote and std.mem.eql(u8, branch_name, current_branch)) {
                const msg = try std.fmt.allocPrint(allocator, "error: cannot delete branch '{s}' used by worktree at '{s}'\n", .{ branch_name, "." });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            }

            if (is_remote) {
                // Delete remote tracking branch
                const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}", .{ git_path, branch_name });
                defer allocator.free(ref_path);
                std.fs.cwd().deleteFile(ref_path) catch |err| switch (err) {
                    error.FileNotFound => {
                        // Try packed-refs
                        const msg = try std.fmt.allocPrint(allocator, "error: remote-tracking branch '{s}' not found.\n", .{branch_name});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(1);
                    },
                    else => return err,
                };
                const success_msg = try std.fmt.allocPrint(allocator, "Deleted remote-tracking branch {s}.\n", .{branch_name});
                defer allocator.free(success_msg);
                try platform_impl.writeStdout(success_msg);
            } else {
                refs.deleteBranch(git_path, branch_name, platform_impl, allocator) catch |err| switch (err) {
                    error.FileNotFound => {
                        const msg = try std.fmt.allocPrint(allocator, "error: branch '{s}' not found.\n", .{branch_name});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(1);
                    },
                    else => return err,
                };
                const success_msg = try std.fmt.allocPrint(allocator, "Deleted branch {s}.\n", .{branch_name});
                defer allocator.free(success_msg);
                try platform_impl.writeStdout(success_msg);
            }
        }
    } else if (std.mem.eql(u8, first_arg.?, "-m") or std.mem.eql(u8, first_arg.?, "-M")) {
        // Rename branch
        const arg1 = args.next() orelse {
            try platform_impl.writeStderr("fatal: branch name required\n");
            std.process.exit(128);
        };
        const arg2 = args.next();

        // If only one argument: rename current branch to arg1
        // If two arguments: rename arg1 to arg2
        const old_name = if (arg2 != null) arg1 else blk: {
            break :blk refs.getCurrentBranch(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: no branch to rename\n");
                std.process.exit(128);
                unreachable;
            };
        };
        defer if (arg2 == null) allocator.free(old_name);
        const new_name = arg2 orelse arg1;

        // Read old branch hash
        const old_ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, old_name });
        defer allocator.free(old_ref_path);
        const old_hash_result = std.fs.cwd().readFileAlloc(allocator, old_ref_path, 4096);
        const is_unborn = if (old_hash_result) |_| false else |_| true;
        const old_hash = if (old_hash_result) |h| h else |_| try allocator.dupe(u8, "");
        defer allocator.free(old_hash);

        if (!is_unborn) {
            // Write new branch ref
            const new_ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, new_name });
            defer allocator.free(new_ref_path);
            // Create parent directories if needed (for branch names with slashes)
            if (std.fs.path.dirname(new_ref_path)) |parent_dir| {
                std.fs.cwd().makePath(parent_dir) catch {};
            }
            try std.fs.cwd().writeFile(.{ .sub_path = new_ref_path, .data = old_hash });

            // Delete old branch ref (if different name)
            if (!std.mem.eql(u8, old_name, new_name)) {
                std.fs.cwd().deleteFile(old_ref_path) catch {};
            }
        }

        // Update HEAD if it pointed to the old branch
        const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
        defer allocator.free(head_path);
        const head_content = std.fs.cwd().readFileAlloc(allocator, head_path, 4096) catch "";
        defer if (head_content.len > 0) allocator.free(head_content);
        const head_trimmed = std.mem.trimRight(u8, head_content, "\r\n");
        const expected_old = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}", .{old_name});
        defer allocator.free(expected_old);
        if (std.mem.eql(u8, head_trimmed, expected_old)) {
            const new_head = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{new_name});
            defer allocator.free(new_head);
            try std.fs.cwd().writeFile(.{ .sub_path = head_path, .data = new_head });
        }
    } else if (std.mem.eql(u8, first_arg.?, "-c") or std.mem.eql(u8, first_arg.?, "-C")) {
        // Copy branch
        const arg1 = args.next() orelse {
            try platform_impl.writeStderr("fatal: branch name required\n");
            std.process.exit(128);
        };
        const arg2 = args.next();
        const src_name = if (arg2 != null) arg1 else blk: {
            break :blk refs.getCurrentBranch(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: no branch to copy\n");
                std.process.exit(128);
                unreachable;
            };
        };
        defer if (arg2 == null) allocator.free(src_name);
        const dst_name = arg2 orelse arg1;

        const src_ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, src_name });
        defer allocator.free(src_ref_path);
        const src_hash = std.fs.cwd().readFileAlloc(allocator, src_ref_path, 4096) catch {
            const msg = try std.fmt.allocPrint(allocator, "error: refname refs/heads/{s} not found\n", .{src_name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(src_hash);
        const dst_ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, dst_name });
        defer allocator.free(dst_ref_path);
        try std.fs.cwd().writeFile(.{ .sub_path = dst_ref_path, .data = src_hash });
    } else if (std.mem.eql(u8, first_arg.?, "--force") or std.mem.eql(u8, first_arg.?, "-f")) {
        // Force create/reset branch
        const branch_name = args.next() orelse {
            try platform_impl.writeStderr("fatal: branch name required\n");
            std.process.exit(128);
        };
        const start_point = args.next();
        // Resolve start_point using resolveRevision for complex refs like HEAD~1
        const resolved_sp_force: ?[]const u8 = if (start_point) |sp|
            resolveRevision(git_path, sp, platform_impl, allocator) catch null
        else
            null;
        defer if (resolved_sp_force) |rsp| allocator.free(rsp);
        
        if (start_point != null and resolved_sp_force == null) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{start_point.?});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        }
        refs.createBranch(git_path, branch_name, resolved_sp_force, platform_impl, allocator) catch |err| switch (err) {
            error.NoCommitsYet => {
                try platform_impl.writeStderr("fatal: not a valid object name: 'master'\n");
                std.process.exit(128);
            },
            else => return err,
        };
    } else if (std.mem.eql(u8, first_arg.?, "--list") or std.mem.eql(u8, first_arg.?, "-l")) {
        // List branches (with optional pattern)
        const current_branch2 = refs.getCurrentBranch(git_path, platform_impl, allocator) catch "master";
        defer allocator.free(current_branch2);
        var branches2 = try refs.listBranches(git_path, platform_impl, allocator);
        defer {
            for (branches2.items) |branch| allocator.free(branch);
            branches2.deinit();
        }
        const pattern = args.next();
        for (branches2.items) |branch| {
            if (pattern) |p| {
                // Simple glob matching
                if (!simpleGlobMatch(p, branch)) continue;
            }
            const prefix2 = if (std.mem.eql(u8, branch, current_branch2)) "* " else "  ";
            const msg2 = try std.fmt.allocPrint(allocator, "{s}{s}\n", .{ prefix2, branch });
            defer allocator.free(msg2);
            try platform_impl.writeStdout(msg2);
        }
    } else if (std.mem.eql(u8, first_arg.?, "--create-reflog")) {
        // Create branch with reflog
        const branch_name = args.next() orelse {
            try platform_impl.writeStderr("fatal: branch name required\n");
            std.process.exit(128);
        };
        const start_point = args.next();
        // Resolve start_point using resolveRevision for complex refs
        const resolved_sp_reflog: ?[]const u8 = if (start_point) |sp|
            resolveRevision(git_path, sp, platform_impl, allocator) catch null
        else
            null;
        defer if (resolved_sp_reflog) |rsp| allocator.free(rsp);
        
        if (start_point != null and resolved_sp_reflog == null) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{start_point.?});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        }
        refs.createBranch(git_path, branch_name, resolved_sp_reflog, platform_impl, allocator) catch |err| switch (err) {
            error.NoCommitsYet => {
                try platform_impl.writeStderr("fatal: not a valid object name: 'master'\n");
                std.process.exit(128);
            },
            else => return err,
        };
        // Create reflog for the new branch
        const new_hash = refs.resolveRef(git_path, std.fmt.allocPrint(allocator, "refs/heads/{s}", .{branch_name}) catch "", platform_impl, allocator) catch null;
        defer if (new_hash) |h| allocator.free(h);
        if (new_hash) |nh| {
            writeReflogEntry(git_path, std.fmt.allocPrint(allocator, "refs/heads/{s}", .{branch_name}) catch "", "0000000000000000000000000000000000000000", nh, "branch: Created from HEAD", allocator, platform_impl) catch {};
        }
    } else if (std.mem.eql(u8, first_arg.?, "--copy")) {
        const copy_src = args.next() orelse {
            try platform_impl.writeStderr("fatal: branch name required\n");
            std.process.exit(128);
            unreachable;
        };
        const copy_dst = args.next() orelse copy_src;
        const src_ref = try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{copy_src});
        defer allocator.free(src_ref);
        const src_hash2 = refs.resolveRef(git_path, src_ref, platform_impl, allocator) catch {
            const emsg = try std.fmt.allocPrint(allocator, "fatal: no such branch: '{s}'\n", .{copy_src});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
            unreachable;
        };
        defer if (src_hash2) |h2| allocator.free(h2);
        const dst_ref_path3 = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, copy_dst });
        defer allocator.free(dst_ref_path3);
        try std.fs.cwd().writeFile(.{ .sub_path = dst_ref_path3, .data = src_hash2 orelse "" });
    } else if (std.mem.eql(u8, first_arg.?, "--no-sort") or std.mem.startsWith(u8, first_arg.?, "--sort=") or
        std.mem.eql(u8, first_arg.?, "--sort") or std.mem.startsWith(u8, first_arg.?, "--track=") or
        std.mem.eql(u8, first_arg.?, "--no-track") or std.mem.eql(u8, first_arg.?, "--no-column") or
        std.mem.startsWith(u8, first_arg.?, "--column") or std.mem.eql(u8, first_arg.?, "--color") or
        std.mem.startsWith(u8, first_arg.?, "--color=") or std.mem.eql(u8, first_arg.?, "--no-color") or
        std.mem.eql(u8, first_arg.?, "-q") or std.mem.eql(u8, first_arg.?, "--quiet") or
        std.mem.eql(u8, first_arg.?, "-a") or std.mem.eql(u8, first_arg.?, "--all") or
        std.mem.eql(u8, first_arg.?, "-r") or std.mem.eql(u8, first_arg.?, "--remotes"))
    {
        const current_branch4 = refs.getCurrentBranch(git_path, platform_impl, allocator) catch "master";
        defer allocator.free(current_branch4);
        var branches4 = try refs.listBranches(git_path, platform_impl, allocator);
        defer {
            for (branches4.items) |br4| allocator.free(br4);
            branches4.deinit();
        }
        while (args.next()) |_| {}
        for (branches4.items) |br4| {
            const p4 = if (std.mem.eql(u8, br4, current_branch4)) "* " else "  ";
            const m4 = try std.fmt.allocPrint(allocator, "{s}{s}\n", .{ p4, br4 });
            defer allocator.free(m4);
            try platform_impl.writeStdout(m4);
        }
    } else {
        // Create new branch
        const branch_name = first_arg.?;
        const start_point = args.next();
        
        // Check if branch already exists
        const existing_ref = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, branch_name });
        defer allocator.free(existing_ref);
        const branch_exists = if (std.fs.cwd().access(existing_ref, .{})) |_| true else |_| false;
        if (branch_exists) {
            const emsg = try std.fmt.allocPrint(allocator, "fatal: a branch named '{s}' already exists\n", .{branch_name});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
        }
        
        // Validate branch name
        if (std.mem.eql(u8, branch_name, "HEAD")) {
            try platform_impl.writeStderr("fatal: 'HEAD' is not a valid branch name\n");
            std.process.exit(128);
        }
        
        // Also check for names starting with -
        if (std.mem.startsWith(u8, branch_name, "-")) {
            const emsg = try std.fmt.allocPrint(allocator, "fatal: '{s}' is not a valid branch name\n", .{branch_name});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
        }

        // Resolve start_point using resolveRevision for complex refs like A^0
        const resolved_sp: ?[]const u8 = if (start_point) |sp|
            resolveRevision(git_path, sp, platform_impl, allocator) catch null
        else
            null;
        defer if (resolved_sp) |rsp| allocator.free(rsp);
        
        if (start_point != null and resolved_sp == null) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{start_point.?});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        }
        
        refs.createBranch(git_path, branch_name, resolved_sp, platform_impl, allocator) catch |err| switch (err) {
            error.NoCommitsYet => {
                try platform_impl.writeStderr("fatal: not a valid object name: 'master'\n");
                std.process.exit(128);
            },
            error.InvalidStartPoint => {
                const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{start_point.?});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            },
            else => return err,
        };
    }
}

/// Resolve any object hash by prefix (not just commits). Returns full 40-char hash.
fn resolveObjectByPrefix(git_path: []const u8, hash_prefix: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // Full hash - verify it exists
    if (hash_prefix.len == 40 and isValidHexString(hash_prefix)) {
        const obj = objects.GitObject.load(hash_prefix, git_path, platform_impl, allocator) catch return error.ObjectNotFound;
        obj.deinit(allocator);
        return try allocator.dupe(u8, hash_prefix);
    }

    if (hash_prefix.len < 4 or !isValidHexString(hash_prefix)) return error.ObjectNotFound;

    // Short hash - scan objects directory
    const dir_name = hash_prefix[0..2];
    const file_prefix = hash_prefix[2..];
    const subdir_path = try std.fmt.allocPrint(allocator, "{s}/objects/{s}", .{ git_path, dir_name });
    defer allocator.free(subdir_path);

    var found_hash: ?[]u8 = null;
    errdefer if (found_hash) |h| allocator.free(h);

    // Scan loose objects
    if (std.fs.cwd().openDir(subdir_path, .{ .iterate = true })) |*dir_ptr| {
        var dir = dir_ptr.*;
        defer dir.close();
        var it = dir.iterate();
        while (try it.next()) |entry| {
            if (entry.kind != .file) continue;
            if (std.mem.startsWith(u8, entry.name, file_prefix)) {
                if (found_hash != null) {
                    allocator.free(found_hash.?);
                    return error.AmbiguousObject;
                }
                found_hash = try std.fmt.allocPrint(allocator, "{s}{s}", .{ dir_name, entry.name });
            }
        }
    } else |_| {}

    // Also scan pack files for prefix matches
    if (found_hash == null) {
        // Try loading the object directly - pack files are searched by GitObject.load
        const obj = objects.GitObject.load(hash_prefix, git_path, platform_impl, allocator) catch {
            return found_hash orelse error.ObjectNotFound;
        };
        obj.deinit(allocator);
        // If load succeeded with a prefix, it found it
        return try allocator.dupe(u8, hash_prefix);
    }

    return found_hash orelse error.ObjectNotFound;
}

/// Resolve a revision string like HEAD, HEAD~3, HEAD^2, v1.0^{commit}, branch_name, etc.
/// Returns the 40-char hash of the resolved object.
fn findRevColonPath(rev: []const u8) ?usize {
    var in_peel: bool = false;
    var i: usize = 0;
    while (i < rev.len) : (i += 1) {
        if (rev[i] == '^' and i + 1 < rev.len and rev[i + 1] == '{') { in_peel = true; i += 1; }
        else if (in_peel and rev[i] == '}') { in_peel = false; }
        else if (!in_peel and rev[i] == ':' and i > 0) { return i; }
    }
    return null;
}

fn resolveTreePath(git_path: []const u8, tree_hash: []const u8, path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    var current_hash = try allocator.dupe(u8, tree_hash);
    var path_iter = std.mem.splitScalar(u8, path, '/');
    while (path_iter.next()) |component| {
        if (component.len == 0) continue;
        const tree_obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch { allocator.free(current_hash); return error.ObjectNotFound; };
        defer tree_obj.deinit(allocator);
        allocator.free(current_hash);
        if (tree_obj.type != .tree) return error.ObjectNotFound;
        var entries = try parseTreeEntries(tree_obj.data, allocator);
        defer { for (entries.items) |*e| e.deinit(allocator); entries.deinit(); }
        var found = false;
        for (entries.items) |entry| {
            if (std.mem.eql(u8, entry.name, component)) { current_hash = try allocator.dupe(u8, entry.hash); found = true; break; }
        }
        if (!found) return error.ObjectNotFound;
    }
    return current_hash;
}

fn resolveCommitByMessage(git_path: []const u8, pattern: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // Collect all tip commits from refs (HEAD + branches + tags)
    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var vi = visited.iterator();
        while (vi.next()) |entry| allocator.free(entry.key_ptr.*);
        visited.deinit();
    }
    var queue = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (queue.items) |q| allocator.free(q);
        queue.deinit();
    }

    const addTip = struct {
        fn f(hash: []const u8, v: *std.StringHashMap(void), q: *std.array_list.Managed([]u8), alloc: std.mem.Allocator) void {
            if (v.contains(hash)) return;
            const dup1 = alloc.dupe(u8, hash) catch return;
            const dup2 = alloc.dupe(u8, hash) catch { alloc.free(dup1); return; };
            v.put(dup1, {}) catch { alloc.free(dup1); alloc.free(dup2); return; };
            q.append(dup2) catch { alloc.free(dup2); return; };
        }
    }.f;

    if (refs.getCurrentCommit(git_path, platform_impl, allocator) catch null) |head| {
        defer allocator.free(head);
        addTip(head, &visited, &queue, allocator);
    }

    const ref_dirs = [_][]const u8{ "refs/heads", "refs/tags" };
    for (ref_dirs) |ref_subdir| {
        const rd = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, ref_subdir }) catch continue;
        defer allocator.free(rd);
        var dir = std.fs.cwd().openDir(rd, .{ .iterate = true }) catch continue;
        defer dir.close();
        var it = dir.iterate();
        while (it.next() catch null) |entry| {
            if (entry.kind != .file) continue;
            const fp = std.fmt.allocPrint(allocator, "{s}/{s}", .{ rd, entry.name }) catch continue;
            defer allocator.free(fp);
            const content = platform_impl.fs.readFile(allocator, fp) catch continue;
            defer allocator.free(content);
            const hash = std.mem.trim(u8, content, " \t\n\r");
            if (hash.len == 40) addTip(hash, &visited, &queue, allocator);
        }
    }

    var qi: usize = 0;
    while (qi < queue.items.len) : (qi += 1) {
        const current = queue.items[qi];
        const commit_obj = objects.GitObject.load(current, git_path, platform_impl, allocator) catch continue;
        defer commit_obj.deinit(allocator);
        if (commit_obj.type != .commit) continue;

        if (std.mem.indexOf(u8, commit_obj.data, "\n\n")) |msg_start| {
            const message = commit_obj.data[msg_start + 2 ..];
            if (std.mem.indexOf(u8, message, pattern) != null) {
                return try allocator.dupe(u8, current);
            }
        }

        var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                addTip(line["parent ".len..], &visited, &queue, allocator);
            }
            if (line.len == 0) break;
        }
    }

    return error.NotFound;
}

fn resolveReflogEntry(git_path: []const u8, ref_name: []const u8, n: u32, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    // Try full path first, then stripped
    const short_name = if (std.mem.startsWith(u8, ref_name, "refs/heads/")) ref_name["refs/heads/".len..] else ref_name;
    
    const path1 = try std.fmt.allocPrint(allocator, "{s}/logs/{s}", .{ git_path, ref_name });
    defer allocator.free(path1);
    const path2 = try std.fmt.allocPrint(allocator, "{s}/logs/{s}", .{ git_path, short_name });
    defer allocator.free(path2);
    
    var content: []u8 = undefined;
    var content_valid = false;
    if (platform_impl.fs.readFile(allocator, path1)) |c| {
        content = c;
        content_valid = true;
    } else |_| {
        if (platform_impl.fs.readFile(allocator, path2)) |c| {
            content = c;
            content_valid = true;
        } else |_| {}
    }
    if (!content_valid) return error.NotFound;
    defer allocator.free(content);

    // Count entries and find the right one
    // @{0} is most recent (last line), @{1} is previous, etc.
    var line_count: u32 = 0;
    {
        var count_iter = std.mem.splitScalar(u8, content, '\n');
        while (count_iter.next()) |line| {
            if (line.len >= 40) line_count += 1;
        }
    }
    
    if (line_count == 0) return error.NotFound;
    // For @{N} where N >= line_count, check if we can use old hash of first entry
    if (n >= line_count) {
        if (n == line_count) {
            // Return the OLD hash from the oldest reflog entry
            var first_iter = std.mem.splitScalar(u8, content, '\n');
            while (first_iter.next()) |line| {
                if (line.len >= 40 and isValidHash(line[0..40])) {
                    return try allocator.dupe(u8, line[0..40]);
                }
            }
        }
        return error.NotFound;
    }

    const target_idx = line_count - 1 - n;
    var current_idx: u32 = 0;
    var reflog_lines = std.mem.splitScalar(u8, content, '\n');
    while (reflog_lines.next()) |line| {
        if (line.len < 40) continue;
        if (current_idx == target_idx) {
            // Parse: the new_hash is at position 41..81
            if (line.len >= 81) {
                const new_hash = line[41..81];
                if (isValidHash(new_hash)) {
                    return try allocator.dupe(u8, new_hash);
                }
            }
            // Fallback: try first 40 chars
            if (isValidHash(line[0..40])) {
                return try allocator.dupe(u8, line[0..40]);
            }
            return error.NotFound;
        }
        current_idx += 1;
    }

    return error.NotFound;
}

fn resolvePreviousBranch(git_path: []const u8, n: u32, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) ![]u8 {
    const head_reflog_path = try std.fmt.allocPrint(allocator, "{s}/logs/HEAD", .{git_path});
    defer allocator.free(head_reflog_path);
    const reflog_content = platform_impl.fs.readFile(allocator, head_reflog_path) catch return error.NotFound;
    defer allocator.free(reflog_content);

    var checkout_entries = std.array_list.Managed([]const u8).init(allocator);
    defer checkout_entries.deinit();

    var lines = std.mem.splitScalar(u8, reflog_content, '\n');
    while (lines.next()) |line| {
        if (std.mem.indexOf(u8, line, "checkout: moving from ")) |idx| {
            const rest = line[idx + "checkout: moving from ".len..];
            if (std.mem.indexOf(u8, rest, " to ")) |to_idx| {
                checkout_entries.append(rest[0..to_idx]) catch {};
            }
        }
    }

    if (checkout_entries.items.len > 0) {
        var count: u32 = 0;
        var i_entry: usize = checkout_entries.items.len;
        while (i_entry > 0) : (count += 1) {
            i_entry -= 1;
            if (count + 1 == n) {
                return try allocator.dupe(u8, checkout_entries.items[i_entry]);
            }
        }
    }

    return error.NotFound;
}

pub fn resolveRevision(git_path: []const u8, rev: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // Handle :/pattern syntax - search for commit by message
    if (std.mem.startsWith(u8, rev, ":/")) {
        const pattern = rev[2..];
        return resolveCommitByMessage(git_path, pattern, platform_impl, allocator) catch return error.BadRevision;
    }

    // Handle :<path> and :<n>:<path> syntax - look up blob in index
    if (rev.len > 1 and rev[0] == ':' and rev[1] != '/') {
        const after_colon = rev[1..];
        // Check for :<n>:<path> format (stage number)
        var target_stage: u2 = 0;
        var target_path: []const u8 = after_colon;
        if (after_colon.len >= 2 and after_colon[0] >= '0' and after_colon[0] <= '3' and after_colon[1] == ':') {
            target_stage = @intCast(after_colon[0] - '0');
            target_path = after_colon[2..];
        }
        // Read index and find the entry
        var idx = index_mod.Index.load(git_path, platform_impl, allocator) catch return error.BadRevision;
        defer idx.deinit();
        for (idx.entries.items) |entry| {
            const entry_stage: u2 = @intCast((entry.flags >> 12) & 0x3);
            if (std.mem.eql(u8, entry.path, target_path) and entry_stage == target_stage) {
                var hex_buf: [40]u8 = undefined;
                const hex_chars = "0123456789abcdef";
                for (entry.sha1, 0..) |byte, bi| {
                    hex_buf[bi * 2] = hex_chars[byte >> 4];
                    hex_buf[bi * 2 + 1] = hex_chars[byte & 0x0f];
                }
                return allocator.dupe(u8, &hex_buf);
            }
        }
        return error.BadRevision;
    }

    // Handle <rev>:<path> syntax
    if (findRevColonPath(rev)) |colon_pos| {
        const rev_part = rev[0..colon_pos];
        const path_part = rev[colon_pos + 1 ..];
        const obj_hash = resolveRevision(git_path, rev_part, platform_impl, allocator) catch return error.BadRevision;
        defer allocator.free(obj_hash);
        const tree_hash = blk: {
            const obj = objects.GitObject.load(obj_hash, git_path, platform_impl, allocator) catch return error.BadRevision;
            defer obj.deinit(allocator);
            switch (obj.type) {
                .tree => break :blk try allocator.dupe(u8, obj_hash),
                .commit => {
                    var lines = std.mem.splitSequence(u8, obj.data, "\n");
                    if (lines.next()) |fl| { if (std.mem.startsWith(u8, fl, "tree ")) break :blk try allocator.dupe(u8, fl["tree ".len..]); }
                    return error.BadRevision;
                },
                .tag => {
                    var lines = std.mem.splitSequence(u8, obj.data, "\n");
                    while (lines.next()) |l| { if (std.mem.startsWith(u8, l, "object ")) break :blk try allocator.dupe(u8, l["object ".len..]); }
                    return error.BadRevision;
                },
                else => return error.BadRevision,
            }
        };
        defer allocator.free(tree_hash);
        if (path_part.len == 0) return try allocator.dupe(u8, tree_hash);
        return resolveTreePath(git_path, tree_hash, path_part, platform_impl, allocator) catch return error.BadRevision;
    }

    // Handle ^{type} peel suffix: e.g. "v1.0^{commit}" or "HEAD^{tree}"
    if (std.mem.indexOf(u8, rev, "^{")) |peel_start| {
        if (std.mem.indexOfScalar(u8, rev[peel_start..], '}')) |close_offset| {
            const base_rev = rev[0..peel_start];
            const peel_type = rev[peel_start + 2 .. peel_start + close_offset];
            const base_hash = try resolveRevision(git_path, base_rev, platform_impl, allocator);
            defer allocator.free(base_hash);
            return peelObject(git_path, base_hash, peel_type, platform_impl, allocator);
        }
    }

    // Handle ^0 (shorthand for ^{commit})
    if (std.mem.endsWith(u8, rev, "^0")) {
        const base_rev = rev[0 .. rev.len - 2];
        const base_hash = try resolveRevision(git_path, base_rev, platform_impl, allocator);
        defer allocator.free(base_hash);
        return peelObject(git_path, base_hash, "commit", platform_impl, allocator);
    }

    // Find the last ~ or ^ operator (handle from right to left for chaining)
    // We need to find the rightmost operator that's not inside ^{}
    var split_pos: ?usize = null;
    var i_rev: usize = rev.len;
    while (i_rev > 0) {
        i_rev -= 1;
        const c = rev[i_rev];
        if (c == '~') {
            split_pos = i_rev;
            break;
        }
        if (c == '^') {
            // Make sure it's not ^{ which we handled above
            if (i_rev + 1 < rev.len and rev[i_rev + 1] == '{') continue;
            split_pos = i_rev;
            break;
        }
    }

    if (split_pos) |pos| {
        const base_rev = rev[0..pos];
        const op = rev[pos];
        const suffix = rev[pos + 1 ..];

        const base_hash = try resolveRevision(git_path, base_rev, platform_impl, allocator);
        defer allocator.free(base_hash);

        if (op == '~') {
            const n: u32 = if (suffix.len == 0) 1 else std.fmt.parseInt(u32, suffix, 10) catch return error.BadRevision;
            return walkFirstParent(git_path, base_hash, n, platform_impl, allocator);
        } else { // '^'
            const n: u32 = if (suffix.len == 0) 1 else std.fmt.parseInt(u32, suffix, 10) catch return error.BadRevision;
            return getNthParent(git_path, base_hash, n, platform_impl, allocator);
        }
    }

    // No operators - resolve as a ref name or hash
    // Try as full or abbreviated hash
    if (rev.len >= 4 and isValidHexString(rev)) {
        if (resolveObjectByPrefix(git_path, rev, platform_impl, allocator)) |hash| {
            return hash;
        } else |_| {}
    }

    // Handle @{-N} (Nth previously checked-out branch)
    if (std.mem.startsWith(u8, rev, "@{-")) {
        if (std.mem.indexOf(u8, rev, "}")) |close| {
            const n_str = rev[3..close];
            const n = std.fmt.parseInt(u32, n_str, 10) catch return error.BadRevision;
            const branch_name = resolvePreviousBranch(git_path, n, allocator, platform_impl) catch return error.BadRevision;
            defer allocator.free(branch_name);
            const suffix = rev[close + 1 ..];
            if (suffix.len > 0) {
                const combined = try std.fmt.allocPrint(allocator, "{s}{s}", .{ branch_name, suffix });
                defer allocator.free(combined);
                return resolveRevision(git_path, combined, platform_impl, allocator);
            }
            return resolveRevision(git_path, branch_name, platform_impl, allocator);
        }
    }

    // Handle "-" as alias for @{-1}
    if (std.mem.eql(u8, rev, "-")) {
        const branch_name = resolvePreviousBranch(git_path, 1, allocator, platform_impl) catch return error.BadRevision;
        defer allocator.free(branch_name);
        return resolveRevision(git_path, branch_name, platform_impl, allocator);
    }

    // Handle refname@{N} (reflog entry)
    if (std.mem.indexOf(u8, rev, "@{")) |at_pos| {
        if (std.mem.indexOf(u8, rev[at_pos..], "}")) |close_off| {
            const refname = rev[0..at_pos];
            const inner = rev[at_pos + 2 .. at_pos + close_off];
            const suffix = rev[at_pos + close_off + 1 ..];

            // Determine the full ref name
            const full_ref = if (refname.len == 0 or std.mem.eql(u8, refname, "HEAD"))
                try allocator.dupe(u8, "HEAD")
            else if (std.mem.startsWith(u8, refname, "refs/"))
                try allocator.dupe(u8, refname)
            else
                try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{refname});
            defer allocator.free(full_ref);

            // Parse the inner value
            if (std.fmt.parseInt(u32, inner, 10)) |n| {
                // @{N}: Nth reflog entry
                const hash = resolveReflogEntry(git_path, full_ref, n, allocator, platform_impl) catch return error.BadRevision;
                defer allocator.free(hash);
                if (suffix.len > 0) {
                    const combined = try std.fmt.allocPrint(allocator, "{s}{s}", .{ hash, suffix });
                    defer allocator.free(combined);
                    return resolveRevision(git_path, combined, platform_impl, allocator);
                }
                return try allocator.dupe(u8, hash);
            } else |_| {
                // Could be @{upstream}, @{push}, etc. - skip for now
            }
        }
    }

    // Try HEAD
    if (std.mem.eql(u8, rev, "HEAD") or std.mem.eql(u8, rev, "@")) {
        const head_commit = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
            return error.BadRevision;
        };
        if (head_commit == null) {}
        return head_commit orelse error.BadRevision;
    }

    // Try special refs: FETCH_HEAD, MERGE_HEAD, ORIG_HEAD, CHERRY_PICK_HEAD, REVERT_HEAD
    if (std.mem.eql(u8, rev, "FETCH_HEAD") or std.mem.eql(u8, rev, "MERGE_HEAD") or
        std.mem.eql(u8, rev, "ORIG_HEAD") or std.mem.eql(u8, rev, "CHERRY_PICK_HEAD") or
        std.mem.eql(u8, rev, "REVERT_HEAD"))
    {
        const special_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, rev });
        defer allocator.free(special_path);
        if (platform_impl.fs.readFile(allocator, special_path)) |content| {
            defer allocator.free(content);
            const trimmed = std.mem.trim(u8, content, " \t\n\r");
            // FETCH_HEAD has tab-separated format: hash\t...\t...
            if (std.mem.indexOfScalar(u8, trimmed, '\t')) |tab| {
                if (tab >= 40 and isValidHexString(trimmed[0..40])) return try allocator.dupe(u8, trimmed[0..40]);
            }
            if (trimmed.len >= 40 and isValidHexString(trimmed[0..40])) return try allocator.dupe(u8, trimmed[0..40]);
        } else |_| {}
    }

    // Try refs/heads/<rev>
    {
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, rev });
        defer allocator.free(ref_path);
        if (platform_impl.fs.readFile(allocator, ref_path)) |content| {
            defer allocator.free(content);
            const hash = std.mem.trim(u8, content, " \t\n\r");
            if (hash.len == 40 and isValidHexString(hash)) return try allocator.dupe(u8, hash);
        } else |_| {}
    }

    // Try refs/tags/<rev>
    {
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{ git_path, rev });
        defer allocator.free(ref_path);
        if (platform_impl.fs.readFile(allocator, ref_path)) |content| {
            defer allocator.free(content);
            const hash = std.mem.trim(u8, content, " \t\n\r");
            if (hash.len == 40 and isValidHexString(hash)) return try allocator.dupe(u8, hash);
        } else |_| {}
    }

    // Try refs/remotes/<rev>
    {
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}", .{ git_path, rev });
        defer allocator.free(ref_path);
        if (platform_impl.fs.readFile(allocator, ref_path)) |content| {
            defer allocator.free(content);
            const hash = std.mem.trim(u8, content, " \t\n\r");
            if (hash.len == 40 and isValidHexString(hash)) return try allocator.dupe(u8, hash);
        } else |_| {}
    }

    // Try <rev> as direct path under .git
    {
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, rev });
        defer allocator.free(ref_path);
        if (platform_impl.fs.readFile(allocator, ref_path)) |content| {
            defer allocator.free(content);
            const trimmed = std.mem.trim(u8, content, " \t\n\r");
            if (std.mem.startsWith(u8, trimmed, "ref: ")) {
                const target = trimmed[5..];
                return resolveRevision(git_path, target, platform_impl, allocator);
            }
            if (trimmed.len == 40 and isValidHexString(trimmed)) return try allocator.dupe(u8, trimmed);
        } else |_| {}
    }

    // Try refs/<rev> for shorthand like tags/X -> refs/tags/X
    if (!std.mem.startsWith(u8, rev, "refs/")) {
        const ref_path_short = try std.fmt.allocPrint(allocator, "{s}/refs/{s}", .{ git_path, rev });
        defer allocator.free(ref_path_short);
        if (platform_impl.fs.readFile(allocator, ref_path_short)) |content| {
            defer allocator.free(content);
            const trimmed = std.mem.trim(u8, content, " \t\n\r");
            if (std.mem.startsWith(u8, trimmed, "ref: ")) {
                const target = trimmed[5..];
                return resolveRevision(git_path, target, platform_impl, allocator);
            }
            if (trimmed.len == 40 and isValidHexString(trimmed)) return try allocator.dupe(u8, trimmed);
        } else |_| {}
    }

    // Try packed-refs
    {
        const packed_refs_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_path});
        defer allocator.free(packed_refs_path);
        if (platform_impl.fs.readFile(allocator, packed_refs_path)) |packed_content| {
            defer allocator.free(packed_content);
            // Try different ref prefixes in packed-refs
            const prefixes = [_][]const u8{ "refs/heads/", "refs/tags/", "refs/remotes/", "refs/", "" };
            for (prefixes) |prefix| {
                const full_ref = try std.fmt.allocPrint(allocator, "{s}{s}", .{ prefix, rev });
                defer allocator.free(full_ref);
                var lines = std.mem.splitSequence(u8, packed_content, "\n");
                while (lines.next()) |line| {
                    const trimmed = std.mem.trim(u8, line, " \t\r");
                    if (trimmed.len == 0 or trimmed[0] == '#' or trimmed[0] == '^') continue;
                    // Format: <hash> <refname>
                    if (trimmed.len > 41 and trimmed[40] == ' ') {
                        const ref_name = trimmed[41..];
                        if (std.mem.eql(u8, ref_name, full_ref)) {
                            const hash = trimmed[0..40];
                            if (isValidHexString(hash)) return try allocator.dupe(u8, hash);
                        }
                    }
                }
            }
        } else |_| {}
    }

    return error.BadRevision;
}

/// Peel an object to a target type (e.g., peel tag to commit, commit to tree)
fn peelObject(git_path: []const u8, hash: []const u8, target_type: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    var current_hash = try allocator.dupe(u8, hash);
    var depth: u32 = 0;
    while (depth < 20) : (depth += 1) {
        const obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch {
            allocator.free(current_hash);
            return error.ObjectNotFound;
        };
        defer obj.deinit(allocator);

        const obj_type_str: []const u8 = switch (obj.type) {
            .commit => "commit",
            .tree => "tree",
            .blob => "blob",
            .tag => "tag",
        };

        // Empty target_type means peel to non-tag
        if (target_type.len == 0) {
            if (obj.type != .tag) return current_hash;
        } else if (std.mem.eql(u8, obj_type_str, target_type)) {
            return current_hash;
        }

        // Peel one level
        if (obj.type == .tag) {
            // Parse tag to find target
            const target_hash = parseTagObject(obj.data, allocator) catch {
                allocator.free(current_hash);
                return error.ObjectNotFound;
            };
            allocator.free(current_hash);
            current_hash = target_hash;
        } else if (obj.type == .commit and std.mem.eql(u8, target_type, "tree")) {
            // Get tree from commit
            var lines = std.mem.splitSequence(u8, obj.data, "\n");
            while (lines.next()) |line| {
                if (std.mem.startsWith(u8, line, "tree ")) {
                    const tree_hash = line[5..];
                    if (tree_hash.len == 40) {
                        allocator.free(current_hash);
                        return try allocator.dupe(u8, tree_hash);
                    }
                }
            }
            allocator.free(current_hash);
            return error.ObjectNotFound;
        } else {
            allocator.free(current_hash);
            return error.ObjectNotFound;
        }
    }
    allocator.free(current_hash);
    return error.ObjectNotFound;
}

/// Walk N first-parents from a commit (for ~ operator)
fn walkFirstParent(git_path: []const u8, start_hash: []const u8, steps: u32, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    var current_hash = try allocator.dupe(u8, start_hash);
    var s: u32 = 0;
    while (s < steps) : (s += 1) {
        const obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch {
            allocator.free(current_hash);
            return error.BadRevision;
        };
        defer obj.deinit(allocator);
        if (obj.type != .commit) {
            allocator.free(current_hash);
            return error.BadRevision;
        }
        var lines = std.mem.splitSequence(u8, obj.data, "\n");
        var parent: ?[]const u8 = null;
        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                parent = line[7..];
                break;
            }
            if (line.len == 0) break;
        }
        if (parent) |p| {
            allocator.free(current_hash);
            current_hash = try allocator.dupe(u8, p);
        } else {
            allocator.free(current_hash);
            return error.BadRevision;
        }
    }
    return current_hash;
}

/// Get the Nth parent of a commit (for ^ operator). ^1 = first parent, ^2 = second parent.
fn getNthParent(git_path: []const u8, hash: []const u8, n: u32, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    if (n == 0) {
        // ^0 means the commit itself (peel to commit)
        return peelObject(git_path, hash, "commit", platform_impl, allocator);
    }
    const obj = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch return error.BadRevision;
    defer obj.deinit(allocator);
    if (obj.type != .commit) return error.BadRevision;

    var lines = std.mem.splitSequence(u8, obj.data, "\n");
    var parent_idx: u32 = 0;
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "parent ")) {
            parent_idx += 1;
            if (parent_idx == n) {
                return try allocator.dupe(u8, line[7..]);
            }
        }
        if (line.len == 0) break;
    }
    return error.BadRevision;
}

fn cmdRevParse(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("rev-parse: not supported in freestanding mode\n");
        return;
    }

    // Collect all args
    var all_args = std.array_list.Managed([]const u8).init(allocator);
    defer all_args.deinit();
    while (args.next()) |arg| {
        try all_args.append(arg);
    }

    if (all_args.items.len == 0) {
        // git rev-parse with no args still validates we're in a git repo
        // findGitDirectory handles invalid gitfile with exit(128)
        const gp_check = findGitDirectory(allocator, platform_impl) catch {
            try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
            std.process.exit(128);
        };
        allocator.free(gp_check);
        return;
    }

    // Parse flags
    var verify = false;
    var quiet = false;
    var short: ?u8 = null; // --short[=N]
    var symbolic_full_name = false;
    var abbrev_ref = false;
    var revs_only = false;
    var no_revs = false;
    var flags_only = false;
    var no_flags = false;
    var path_format_absolute = false;
    var default_rev: ?[]const u8 = null;
    var positional_args = std.array_list.Managed([]const u8).init(allocator);
    defer positional_args.deinit();

    var arg_i: usize = 0;
    while (arg_i < all_args.items.len) : (arg_i += 1) {
        const arg = all_args.items[arg_i];
        if (std.mem.eql(u8, arg, "--verify")) {
            verify = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--short")) {
            short = 7;
        } else if (std.mem.startsWith(u8, arg, "--short=")) {
            short = std.fmt.parseInt(u8, arg[8..], 10) catch 7;
        } else if (std.mem.eql(u8, arg, "--symbolic-full-name")) {
            symbolic_full_name = true;
        } else if (std.mem.eql(u8, arg, "--abbrev-ref")) {
            abbrev_ref = true;
        } else if (std.mem.eql(u8, arg, "--revs-only")) {
            revs_only = true;
        } else if (std.mem.eql(u8, arg, "--no-revs")) {
            no_revs = true;
        } else if (std.mem.eql(u8, arg, "--flags")) {
            flags_only = true;
        } else if (std.mem.eql(u8, arg, "--no-flags")) {
            no_flags = true;
        } else if (std.mem.eql(u8, arg, "--sq")) {
            // Ignore for now (shell quoting)
        } else if (std.mem.eql(u8, arg, "--sq-quote")) {
            // Shell-quote remaining args
            var output_buf = std.array_list.Managed(u8).init(allocator);
            defer output_buf.deinit();
            var first = true;
            arg_i += 1;
            while (arg_i < all_args.items.len) : (arg_i += 1) {
                const a = all_args.items[arg_i];
                if (!first) try output_buf.append(' ');
                first = false;
                try output_buf.append('\'');
                for (a) |ch| {
                    if (ch == '\'') {
                        try output_buf.appendSlice("'\\''");
                    } else {
                        try output_buf.append(ch);
                    }
                }
                try output_buf.append('\'');
            }
            try output_buf.append('\n');
            try platform_impl.writeStdout(output_buf.items);
            return;
        } else if (std.mem.eql(u8, arg, "--local-env-vars")) {
            try platform_impl.writeStdout("GIT_DIR\nGIT_WORK_TREE\nGIT_OBJECT_DIRECTORY\nGIT_INDEX_FILE\nGIT_GRAFT_FILE\nGIT_COMMON_DIR\n");
            return;
        } else if (std.mem.eql(u8, arg, "--resolve-git-dir")) {
            arg_i += 1;
            if (arg_i >= all_args.items.len) {
                try platform_impl.writeStderr("fatal: --resolve-git-dir requires an argument\n");
                std.process.exit(1);
                unreachable;
            }
            const path = all_args.items[arg_i];
            // If path is a file, read its contents (gitfile)
            const content = platform_impl.fs.readFile(allocator, path) catch {
                // Check if path is a directory with HEAD
                const head_path = std.fmt.allocPrint(allocator, "{s}/HEAD", .{path}) catch {
                    std.process.exit(1);
                    unreachable;
                };
                defer allocator.free(head_path);
                _ = std.fs.cwd().statFile(head_path) catch {
                    try platform_impl.writeStderr("fatal: not a gitdir '");
                    try platform_impl.writeStderr(path);
                    try platform_impl.writeStderr("'\n");
                    std.process.exit(1);
                    unreachable;
                };
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{path});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
                return;
            };
            defer allocator.free(content);
            const trimmed = std.mem.trim(u8, content, " \t\r\n");
            if (std.mem.startsWith(u8, trimmed, "gitdir: ")) {
                const gitdir = trimmed["gitdir: ".len..];
                // Resolve relative to the directory containing the gitfile
                if (std.fs.path.isAbsolute(gitdir)) {
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{gitdir});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                } else {
                    const dir = std.fs.path.dirname(path) orelse ".";
                    const resolved = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir, gitdir });
                    defer allocator.free(resolved);
                    // Normalize the path
                    var real_buf: [4096]u8 = undefined;
                    const real = std.fs.cwd().realpath(resolved, &real_buf) catch {
                        const output = try std.fmt.allocPrint(allocator, "{s}\n", .{resolved});
                        defer allocator.free(output);
                        try platform_impl.writeStdout(output);
                        return;
                    };
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{real});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                }
            } else {
                try platform_impl.writeStderr("fatal: not a gitdir '");
                try platform_impl.writeStderr(path);
                try platform_impl.writeStderr("'\n");
                std.process.exit(1);
                unreachable;
            }
            return;
        } else if (std.mem.eql(u8, arg, "--path-format=absolute")) {
            path_format_absolute = true;
        } else if (std.mem.eql(u8, arg, "--path-format=relative")) {
            path_format_absolute = false;
        } else if (std.mem.eql(u8, arg, "--path-format")) {
            try platform_impl.writeStderr("fatal: --path-format requires a value\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--default")) {
            arg_i += 1;
            if (arg_i < all_args.items.len) {
                default_rev = all_args.items[arg_i];
            }
        } else if (std.mem.startsWith(u8, arg, "--default=")) {
            default_rev = arg["--default=".len..];
        } else {
            try positional_args.append(arg);
        }
    }

    // Handle info queries that don't need refs resolution
    for (positional_args.items) |arg| {
        if (std.mem.eql(u8, arg, "--show-toplevel")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
                std.process.exit(128);
            };
            defer allocator.free(git_path);
            // Check if this is a bare repo
            const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
            defer allocator.free(config_path);
            if (platform_impl.fs.readFile(allocator, config_path)) |cfg| {
                defer allocator.free(cfg);
                if (std.mem.indexOf(u8, cfg, "bare = true") != null) {
                    try platform_impl.writeStderr("fatal: this operation must be run in a work tree\n");
                    std.process.exit(128);
                }
            } else |_| {}
            const repo_root = std.fs.path.dirname(git_path) orelse git_path;
            const output = try std.fmt.allocPrint(allocator, "{s}\n", .{repo_root});
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
            continue;
        } else if (std.mem.eql(u8, arg, "--git-dir")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
                std.process.exit(128);
            };
            defer allocator.free(git_path);
            // GIT_DIR env: output directly
            if (std.posix.getenv("GIT_DIR")) |gd| {
                const gd_out = try std.fmt.allocPrint(allocator, "{s}\n", .{gd});
                defer allocator.free(gd_out);
                try platform_impl.writeStdout(gd_out);
                continue;
            }
            // Gitdir link target (absolute, not standard .git): output as-is
            if (std.fs.path.isAbsolute(git_path) and !std.mem.endsWith(u8, git_path, "/.git")) {
                const gd_out = try std.fmt.allocPrint(allocator, "{s}\n", .{git_path});
                defer allocator.free(gd_out);
                try platform_impl.writeStdout(gd_out);
                continue;
            }
            if (path_format_absolute) {
                // Always output absolute path
                const abs = std.fs.cwd().realpathAlloc(allocator, git_path) catch try allocator.dupe(u8, git_path);
                defer allocator.free(abs);
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{abs});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                const cwd = try platform_impl.fs.getCwd(allocator);
                defer allocator.free(cwd);
                const real_git = std.fs.cwd().realpathAlloc(allocator, git_path) catch try allocator.dupe(u8, git_path);
                defer allocator.free(real_git);
                const real_cwd = std.fs.cwd().realpathAlloc(allocator, cwd) catch try allocator.dupe(u8, cwd);
                defer allocator.free(real_cwd);
                
                // If CWD IS the git dir, output "."
                if (std.mem.eql(u8, real_cwd, real_git)) {
                    try platform_impl.writeStdout(".\n");
                } else if (std.mem.startsWith(u8, real_cwd, real_git) and real_cwd.len > real_git.len and real_cwd[real_git.len] == '/') {
                    // Inside git dir - output absolute path to git dir
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{real_git});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                } else if (std.mem.startsWith(u8, real_git, real_cwd) and real_git.len > real_cwd.len and real_git[real_cwd.len] == '/') {
                    // Git dir is a subdirectory of CWD - output relative path
                    const rel = real_git[real_cwd.len + 1..];
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{rel});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                } else {
                    // Output absolute path
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{real_git});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                }
            }
            continue;
        } else if (std.mem.eql(u8, arg, "--git-common-dir")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
                std.process.exit(128);
            };
            defer allocator.free(git_path);
            const cwd = try platform_impl.fs.getCwd(allocator);
            defer allocator.free(cwd);
            if (std.mem.startsWith(u8, git_path, cwd) and git_path.len > cwd.len) {
                const rel = git_path[cwd.len..];
                const trimmed = if (rel.len > 0 and rel[0] == '/') rel[1..] else rel;
                if (trimmed.len > 0) {
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{trimmed});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                } else {
                    try platform_impl.writeStdout(".git\n");
                }
            } else {
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{git_path});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
            continue;
        } else if (std.mem.eql(u8, arg, "--is-inside-work-tree")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStdout("false\n");
                continue;
            };
            defer allocator.free(git_path);
            // Check bare
            const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
            defer allocator.free(config_path);
            if (platform_impl.fs.readFile(allocator, config_path)) |cfg| {
                defer allocator.free(cfg);
                if (std.mem.indexOf(u8, cfg, "bare = true") != null) {
                    try platform_impl.writeStdout("false\n");
                    continue;
                }
            } else |_| {}
            try platform_impl.writeStdout("true\n");
            continue;
        } else if (std.mem.eql(u8, arg, "--is-inside-git-dir")) {
            // Check if cwd is inside the .git directory
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStdout("false\n");
                continue;
            };
            defer allocator.free(git_path);
            const cwd = try platform_impl.fs.getCwd(allocator);
            defer allocator.free(cwd);
            // Resolve git_path to real path for comparison
            const real_git = std.fs.cwd().realpathAlloc(allocator, git_path) catch git_path;
            const should_free_real_git = real_git.ptr != git_path.ptr;
            defer if (should_free_real_git) allocator.free(real_git);
            const real_cwd = std.fs.cwd().realpathAlloc(allocator, cwd) catch cwd;
            const should_free_real_cwd = real_cwd.ptr != cwd.ptr;
            defer if (should_free_real_cwd) allocator.free(real_cwd);
            if (std.mem.eql(u8, real_cwd, real_git) or std.mem.startsWith(u8, real_cwd, real_git) and real_cwd.len > real_git.len and real_cwd[real_git.len] == '/') {
                try platform_impl.writeStdout("true\n");
            } else {
                try platform_impl.writeStdout("false\n");
            }
            continue;
        } else if (std.mem.eql(u8, arg, "--is-bare-repository")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStdout("false\n");
                continue;
            };
            defer allocator.free(git_path);
            const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
            defer allocator.free(config_path);
            if (platform_impl.fs.readFile(allocator, config_path)) |cfg| {
                defer allocator.free(cfg);
                if (std.mem.indexOf(u8, cfg, "bare = true") != null) {
                    try platform_impl.writeStdout("true\n");
                    continue;
                }
            } else |_| {}
            try platform_impl.writeStdout("false\n");
            continue;
        } else if (std.mem.eql(u8, arg, "--show-cdup")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository\n");
                std.process.exit(128);
            };
            defer allocator.free(git_path);
            const repo_root = std.fs.path.dirname(git_path) orelse git_path;
            const cwd = try platform_impl.fs.getCwd(allocator);
            defer allocator.free(cwd);
            if (std.mem.eql(u8, cwd, repo_root)) {
                try platform_impl.writeStdout("\n");
            } else if (std.mem.startsWith(u8, cwd, repo_root)) {
                const rel = cwd[repo_root.len + 1 ..];
                var depth: usize = 1;
                for (rel) |c| {
                    if (c == '/') depth += 1;
                }
                var buf = std.array_list.Managed(u8).init(allocator);
                defer buf.deinit();
                var d: usize = 0;
                while (d < depth) : (d += 1) {
                    try buf.appendSlice("../");
                }
                try buf.append('\n');
                try platform_impl.writeStdout(buf.items);
            } else {
                try platform_impl.writeStdout("\n");
            }
            continue;
        } else if (std.mem.eql(u8, arg, "--show-prefix")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository\n");
                std.process.exit(128);
            };
            defer allocator.free(git_path);
            const repo_root = std.fs.path.dirname(git_path) orelse git_path;
            const cwd = try platform_impl.fs.getCwd(allocator);
            defer allocator.free(cwd);
            if (std.mem.eql(u8, cwd, repo_root)) {
                try platform_impl.writeStdout("\n");
            } else if (std.mem.startsWith(u8, cwd, repo_root)) {
                const prefix = cwd[repo_root.len + 1 ..];
                const output = try std.fmt.allocPrint(allocator, "{s}/\n", .{prefix});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                try platform_impl.writeStdout("\n");
            }
            continue;
        } else if (std.mem.eql(u8, arg, "--absolute-git-dir")) {
            const git_path = findGitDirectory(allocator, platform_impl) catch {
                try platform_impl.writeStderr("fatal: not a git repository\n");
                std.process.exit(128);
            };
            defer allocator.free(git_path);
            const output = try std.fmt.allocPrint(allocator, "{s}\n", .{git_path});
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
            continue;
        } else if (std.mem.eql(u8, arg, "--git-path")) {
            // --git-path <path> - resolve path relative to GIT_DIR
            // The next positional should be the path component
            continue; // The path will be the next arg, handled below
        } else if (std.mem.eql(u8, arg, "--show-object-format") or std.mem.startsWith(u8, arg, "--show-object-format=")) {
            try platform_impl.writeStdout("sha1\n");
            continue;
        } else if (std.mem.eql(u8, arg, "--show-ref-format")) {
            try platform_impl.writeStdout("files\n");
            continue;
        } else if (std.mem.eql(u8, arg, "--is-shallow-repository")) {
            // Check for shallow file
            if (findGitDirectory(allocator, platform_impl) catch null) |gp_shallow| {
                defer allocator.free(gp_shallow);
                const shallow_path = try std.fmt.allocPrint(allocator, "{s}/shallow", .{gp_shallow});
                defer allocator.free(shallow_path);
                if (platform_impl.fs.exists(shallow_path) catch false) {
                    try platform_impl.writeStdout("true\n");
                } else {
                    try platform_impl.writeStdout("false\n");
                }
            } else {
                try platform_impl.writeStdout("false\n");
            }
            continue;
        }
    }

    // If verify mode with no positional args that look like revisions
    if (verify) {
        // --verify expects exactly one revision argument
        var rev_arg: ?[]const u8 = null;
        for (positional_args.items) |arg| {
            if (std.mem.startsWith(u8, arg, "--")) continue;
            if (rev_arg != null) {
                if (!quiet) {
                    try platform_impl.writeStderr("fatal: Needed a single revision\n");
                }
                std.process.exit(128);
            }
            rev_arg = arg;
        }
        if (rev_arg == null) {
            if (default_rev) |def| {
                rev_arg = def;
            } else {
                if (!quiet) {
                    try platform_impl.writeStderr("fatal: Needed a single revision\n");
                }
                std.process.exit(128);
            }
        }

        const git_path = findGitDirectory(allocator, platform_impl) catch {
            if (!quiet) {
                try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
            }
            std.process.exit(128);
        };
        defer allocator.free(git_path);

        const hash = resolveRevision(git_path, rev_arg.?, platform_impl, allocator) catch {
            if (!quiet) {
                try platform_impl.writeStderr("fatal: Needed a single revision\n");
            }
            std.process.exit(128);
        };
        defer allocator.free(hash);

        if (short) |n| {
            const s = if (n > 40) @as(u8, 40) else n;
            const out = try std.fmt.allocPrint(allocator, "{s}\n", .{hash[0..s]});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        } else {
            const out = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        }
        return;
    }

    // Non-verify mode: process each positional arg
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    for (positional_args.items) |arg| {
        // Skip flags already processed
        if (std.mem.startsWith(u8, arg, "--")) {
            if (!revs_only and !no_flags) {
                // Output non-rev flags
                if (flags_only or no_revs) {
                    const out = try std.fmt.allocPrint(allocator, "{s}\n", .{arg});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
            continue;
        }

        if (no_revs) continue; // Skip revision args

        // Handle --symbolic-full-name for HEAD
        if (symbolic_full_name) {
            if (std.mem.eql(u8, arg, "HEAD")) {
                const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                defer allocator.free(head_path);
                if (platform_impl.fs.readFile(allocator, head_path)) |content| {
                    defer allocator.free(content);
                    const trimmed = std.mem.trim(u8, content, " \t\n\r");
                    if (std.mem.startsWith(u8, trimmed, "ref: ")) {
                        const out = try std.fmt.allocPrint(allocator, "{s}\n", .{trimmed[5..]});
                        defer allocator.free(out);
                        try platform_impl.writeStdout(out);
                        continue;
                    }
                } else |_| {}
            }
        }

        // Handle --abbrev-ref
        if (abbrev_ref) {
            if (std.mem.eql(u8, arg, "HEAD")) {
                const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                defer allocator.free(head_path);
                if (platform_impl.fs.readFile(allocator, head_path)) |content| {
                    defer allocator.free(content);
                    const trimmed = std.mem.trim(u8, content, " \t\n\r");
                    if (std.mem.startsWith(u8, trimmed, "ref: refs/heads/")) {
                        const branch = trimmed["ref: refs/heads/".len..];
                        const out = try std.fmt.allocPrint(allocator, "{s}\n", .{branch});
                        defer allocator.free(out);
                        try platform_impl.writeStdout(out);
                        continue;
                    } else if (std.mem.startsWith(u8, trimmed, "ref: ")) {
                        const out = try std.fmt.allocPrint(allocator, "{s}\n", .{trimmed[5..]});
                        defer allocator.free(out);
                        try platform_impl.writeStdout(out);
                        continue;
                    } else {
                        try platform_impl.writeStdout("HEAD\n");
                        continue;
                    }
                } else |_| {}
            }
        }

        // Handle ^@ (all parents)
        if (std.mem.endsWith(u8, arg, "^@")) {
            const brev1 = arg[0 .. arg.len - 2];
            if (resolveRevision(git_path, brev1, platform_impl, allocator)) |bh1| {
                defer allocator.free(bh1);
                const obj1 = objects.GitObject.load(bh1, git_path, platform_impl, allocator) catch {
                    const e1 = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{arg});
                    defer allocator.free(e1);
                    try platform_impl.writeStderr(e1);
                    std.process.exit(128);
                };
                defer obj1.deinit(allocator);
                if (obj1.type != .commit) {
                    const e2 = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{arg});
                    defer allocator.free(e2);
                    try platform_impl.writeStderr(e2);
                    std.process.exit(128);
                }
                var lns1 = std.mem.splitSequence(u8, obj1.data, "\n");
                while (lns1.next()) |ln1| {
                    if (ln1.len == 0) break;
                    if (std.mem.startsWith(u8, ln1, "parent ")) {
                        const p1 = ln1["parent ".len..];
                        const o1 = try std.fmt.allocPrint(allocator, "{s}\n", .{p1});
                        defer allocator.free(o1);
                        try platform_impl.writeStdout(o1);
                    }
                }
                continue;
            } else |_| {}
        }
        // Handle ^! (commit excluding parents)
        if (std.mem.endsWith(u8, arg, "^!")) {
            const brev2 = arg[0 .. arg.len - 2];
            if (resolveRevision(git_path, brev2, platform_impl, allocator)) |bh2| {
                defer allocator.free(bh2);
                const o2a = try std.fmt.allocPrint(allocator, "{s}\n", .{bh2});
                defer allocator.free(o2a);
                try platform_impl.writeStdout(o2a);
                const obj2 = objects.GitObject.load(bh2, git_path, platform_impl, allocator) catch continue;
                defer obj2.deinit(allocator);
                if (obj2.type == .commit) {
                    var lns2 = std.mem.splitSequence(u8, obj2.data, "\n");
                    while (lns2.next()) |ln2| {
                        if (ln2.len == 0) break;
                        if (std.mem.startsWith(u8, ln2, "parent ")) {
                            const p2 = ln2["parent ".len..];
                            const o2b = try std.fmt.allocPrint(allocator, "^{s}\n", .{p2});
                            defer allocator.free(o2b);
                            try platform_impl.writeStdout(o2b);
                        }
                    }
                }
                continue;
            } else |_| {}
        }
        // Handle ^-N (parent range shorthand)
        if (std.mem.indexOf(u8, arg, "^-")) |cdp1| {
            const brev3 = arg[0..cdp1];
            const dsuf1 = arg[cdp1 + 2 ..];
            const dn1: u32 = if (dsuf1.len == 0) 1 else std.fmt.parseInt(u32, dsuf1, 10) catch 0;
            if (dn1 == 0) {
                const e3 = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{arg});
                defer allocator.free(e3);
                try platform_impl.writeStderr(e3);
                std.process.exit(128);
            }
            if (resolveRevision(git_path, brev3, platform_impl, allocator)) |bh3| {
                defer allocator.free(bh3);
                const ps1 = try std.fmt.allocPrint(allocator, "{s}^{d}", .{ brev3, dn1 });
                defer allocator.free(ps1);
                if (resolveRevision(git_path, ps1, platform_impl, allocator)) |ph3| {
                    defer allocator.free(ph3);
                    if (symbolic_full_name) {
                        const n1 = try std.fmt.allocPrint(allocator, "^{s}^{d}\n", .{ brev3, dn1 });
                        defer allocator.free(n1);
                        try platform_impl.writeStdout(n1);
                        const p3 = try std.fmt.allocPrint(allocator, "{s}\n", .{brev3});
                        defer allocator.free(p3);
                        try platform_impl.writeStdout(p3);
                    } else {
                        const n2 = try std.fmt.allocPrint(allocator, "^{s}\n", .{ph3});
                        defer allocator.free(n2);
                        try platform_impl.writeStdout(n2);
                        const p4 = try std.fmt.allocPrint(allocator, "{s}\n", .{bh3});
                        defer allocator.free(p4);
                        try platform_impl.writeStdout(p4);
                    }
                    continue;
                } else |_| {}
            } else |_| {}
        }
        // Handle ^<rev> negation prefix
        if (arg.len > 1 and arg[0] == '^' and arg[1] != '{' and arg[1] != '-' and arg[1] != '@' and arg[1] != '!') {
            const nrev1 = arg[1..];
            if (resolveRevision(git_path, nrev1, platform_impl, allocator)) |nh1| {
                defer allocator.free(nh1);
                const no1 = try std.fmt.allocPrint(allocator, "^{s}\n", .{nh1});
                defer allocator.free(no1);
                try platform_impl.writeStdout(no1);
                continue;
            } else |_| {}
        }

        // Try to resolve as revision
        if (resolveRevision(git_path, arg, platform_impl, allocator)) |hash| {
            defer allocator.free(hash);
            if (short) |n| {
                const s = if (n > 40) @as(u8, 40) else n;
                const out = try std.fmt.allocPrint(allocator, "{s}\n", .{hash[0..s]});
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            } else {
                const out = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            }
        } else |_| {
            // For --short mode with a valid hex string, just truncate (like real git)
            if (short != null and arg.len == 40 and isValidHexString(arg)) {
                const n = short.?;
                const s = if (n > 40) @as(u8, 40) else n;
                const out = try std.fmt.allocPrint(allocator, "{s}\n", .{arg[0..s]});
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            } else {
                if (!quiet) {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: ambiguous argument '{s}': unknown revision or path not in the working tree.\nUse '--' to separate paths from revisions, like this:\n'git <command> [<revision>...] -- [<file>...]'\n", .{arg});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                }
                std.process.exit(128);
            }
        }
    }
}

fn cmdDescribe(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("describe: not supported in freestanding mode\n");
        return;
    }

    // Parse arguments
    var tags = false;
    var abbrev_zero = false;
    var exact_match = false;
    var target_rev: ?[]const u8 = null;
    var contains_mode = false;
    var all_mode = false;
    
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--tags")) {
            tags = true;
        } else if (std.mem.eql(u8, arg, "--abbrev=0")) {
            abbrev_zero = true;
        } else if (std.mem.eql(u8, arg, "--exact-match")) {
            exact_match = true;
        } else if (std.mem.eql(u8, arg, "--contains")) {
            tags = true;
            contains_mode = true;
        } else if (std.mem.eql(u8, arg, "--all")) {
            all_mode = true;
            tags = true;
        } else if (std.mem.eql(u8, arg, "--long") or std.mem.eql(u8, arg, "--always") or
            std.mem.eql(u8, arg, "--dirty")) {
            // accept silently
        } else if (std.mem.startsWith(u8, arg, "--abbrev=")) {
            if (std.mem.eql(u8, arg, "--abbrev=0")) abbrev_zero = true;
        } else if (arg.len > 0 and arg[0] != '-') {
            target_rev = arg;
        }
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Get target commit
    const head_hash: []u8 = blk: {
        if (target_rev) |r| {
            const resolved = resolveRevision(git_path, r, platform_impl, allocator) catch {
                const resolved2 = refs.resolveRef(git_path, r, platform_impl, allocator) catch {
                    try platform_impl.writeStderr("fatal: not a valid object name\n");
                    std.process.exit(128);
                    unreachable;
                };
                break :blk resolved2 orelse {
                    try platform_impl.writeStderr("fatal: not a valid object name\n");
                    std.process.exit(128);
                    unreachable;
                };
            };
            break :blk resolved;
        } else {
            const h = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: no commits yet\n");
                std.process.exit(128);
                unreachable;
            };
            break :blk h orelse {
                try platform_impl.writeStderr("fatal: no commits yet\n");
                std.process.exit(128);
                unreachable;
            };
        }
    };
    defer allocator.free(head_hash);

    // Read all tags from refs/tags/*
    const tags_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_path});
    defer allocator.free(tags_path);
    
    var tag_map = std.StringHashMap([]u8).init(allocator);
    defer {
        var iterator = tag_map.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.*);
        }
        tag_map.deinit();
    }
    
    // Read tags directory if it exists
    var tags_dir = std.fs.cwd().openDir(tags_path, .{ .iterate = true }) catch {
        try platform_impl.writeStderr("fatal: No names found, cannot describe anything.\n");
        std.process.exit(128);
    };
    defer tags_dir.close();
    
    var iterator = tags_dir.iterate();
    while (iterator.next() catch null) |entry| {
        if (entry.kind != .file) continue;
        
        // Read tag file to get the commit hash it points to
        const tag_file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{tags_path, entry.name});
        defer allocator.free(tag_file_path);
        
        const tag_content = platform_impl.fs.readFile(allocator, tag_file_path) catch continue;
        defer allocator.free(tag_content);
        
        const tag_hash = std.mem.trim(u8, tag_content, " \t\n\r");
        
        // Check if this is an annotated tag (tag object) or lightweight tag (direct commit reference)
        const commit_hash = blk: {
            if (tag_hash.len == 40) {
                // Try to load as object to see what type it is
                const tag_obj = objects.GitObject.load(tag_hash, git_path, platform_impl, allocator) catch {
                    break :blk try allocator.dupe(u8, tag_hash);
                };
                defer tag_obj.deinit(allocator);
                
                if (tag_obj.type == .tag) {
                    // It's an annotated tag, parse it to get the object it points to
                    const object_hash = parseTagObject(tag_obj.data, allocator) catch {
                        break :blk try allocator.dupe(u8, tag_hash);
                    };
                    break :blk object_hash;
                } else if (tag_obj.type == .commit) {
                    // It's a lightweight tag - only include if --tags
                    if (!tags) continue;
                    break :blk try allocator.dupe(u8, tag_hash);
                } else {
                    continue; // Skip tags pointing to non-commit objects for now
                }
            } else {
                continue; // Invalid hash
            }
        };
        
        try tag_map.put(try allocator.dupe(u8, entry.name), commit_hash);
    }
    
    if (tag_map.count() == 0) {
        try platform_impl.writeStderr("fatal: No names found, cannot describe anything.\n");
        std.process.exit(128);
    }
    
    // Walk HEAD commit chain backward looking for a match with any tag
    // Also check packed-refs for tags
    const packed_refs_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_path});
    defer allocator.free(packed_refs_path);
    if (platform_impl.fs.readFile(allocator, packed_refs_path)) |packed_content| {
        defer allocator.free(packed_content);
        var plines = std.mem.splitScalar(u8, packed_content, '\n');
        while (plines.next()) |pline| {
            if (pline.len == 0 or pline[0] == '#' or pline[0] == '^') continue;
            if (pline.len >= 41 and pline[40] == ' ') {
                const ref_name = pline[41..];
                if (std.mem.startsWith(u8, ref_name, "refs/tags/")) {
                    const tag_name = ref_name["refs/tags/".len..];
                    if (tag_map.contains(tag_name)) continue;
                    const tag_hash = pline[0..40];
                    const commit_hash2 = resolve_blk: {
                        const tag_obj = objects.GitObject.load(tag_hash, git_path, platform_impl, allocator) catch { break :resolve_blk allocator.dupe(u8, tag_hash) catch continue; };
                        defer tag_obj.deinit(allocator);
                        if (tag_obj.type == .tag) { break :resolve_blk parseTagObject(tag_obj.data, allocator) catch { break :resolve_blk allocator.dupe(u8, tag_hash) catch continue; }; }
                        else if (tag_obj.type == .commit) { if (!tags) continue; break :resolve_blk allocator.dupe(u8, tag_hash) catch continue; }
                        else continue;
                    };
                    tag_map.put(allocator.dupe(u8, tag_name) catch continue, commit_hash2) catch continue;
                }
            }
        }
    } else |_| {}

    var result: ?TagWithDistance = null;
    
    if (contains_mode) {
        // --contains mode: find the nearest tag that has HEAD as ancestor
        var tag_iter = tag_map.iterator();
        while (tag_iter.next()) |entry| {
            const tag_name = entry.key_ptr.*;
            const tag_commit = entry.value_ptr.*;
            // Check if head_hash is an ancestor of tag_commit
            if (std.mem.eql(u8, tag_commit, head_hash)) {
                // Exact match
                const n = try allocator.dupe(u8, tag_name);
                if (result == null or 0 < result.?.distance) {
                    if (result) |old| allocator.free(old.tag_name);
                    result = TagWithDistance{ .tag_name = n, .distance = 0 };
                } else {
                    allocator.free(n);
                }
            } else if (isAncestor(git_path, head_hash, tag_commit, allocator, platform_impl) catch false) {
                // head_hash is ancestor of tag_commit - compute distance
                const dist = computeDistance(git_path, head_hash, tag_commit, allocator, platform_impl) catch continue;
                const n = try allocator.dupe(u8, tag_name);
                if (result == null or dist < result.?.distance) {
                    if (result) |old| allocator.free(old.tag_name);
                    result = TagWithDistance{ .tag_name = n, .distance = dist };
                } else {
                    allocator.free(n);
                }
            }
        }
    } else {
        result = findTagInHistoryWithDistance(git_path, head_hash, &tag_map, tags, allocator, platform_impl) catch null;
    }

    if (result) |r| {
        defer allocator.free(r.tag_name);
        if (exact_match and r.distance != 0) {
            try platform_impl.writeStderr("fatal: no tag exactly matches '");
            try platform_impl.writeStderr(head_hash[0..@min(7, head_hash.len)]);
            try platform_impl.writeStderr("'\n");
            std.process.exit(128);
        }
        if (contains_mode) {
            // --contains output: tag~N or tags/tag~N (with --all)
            const prefix = if (all_mode) "tags/" else "";
            if (r.distance == 0) {
                const output = try std.fmt.allocPrint(allocator, "{s}{s}\n", .{prefix, r.tag_name});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                const output = try std.fmt.allocPrint(allocator, "{s}{s}~{d}\n", .{prefix, r.tag_name, r.distance});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        } else if (r.distance == 0) {
            const output = try std.fmt.allocPrint(allocator, "{s}\n", .{r.tag_name});
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else if (abbrev_zero) {
            const output = try std.fmt.allocPrint(allocator, "{s}-{d}\n", .{ r.tag_name, r.distance });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else {
            const short_hash = head_hash[0..@min(7, head_hash.len)];
            const output = try std.fmt.allocPrint(allocator, "{s}-{d}-g{s}\n", .{ r.tag_name, r.distance, short_hash });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        }
    } else {
        if (exact_match) {
            try platform_impl.writeStderr("fatal: no tag exactly matches '");
            try platform_impl.writeStderr(head_hash[0..@min(7, head_hash.len)]);
            try platform_impl.writeStderr("'\n");
            std.process.exit(128);
        }
        try platform_impl.writeStderr("fatal: No names found, cannot describe anything.\n");
        std.process.exit(128);
    }
}

fn parseTagObject(tag_data: []const u8, allocator: std.mem.Allocator) ![]u8 {
    var lines = std.mem.splitSequence(u8, tag_data, "\n");
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "object ")) {
            const object_hash = line["object ".len..];
            if (object_hash.len >= 40) {
                return try allocator.dupe(u8, object_hash[0..40]);
            }
        } else if (line.len == 0) {
            break; // End of headers
        }
    }
    return error.NoObjectInTag;
}

const TagWithDistance = struct {
    tag_name: []u8,
    distance: u32,
};

/// Compute the commit distance from ancestor to descendant (number of commits between them)
fn computeDistance(git_path: []const u8, ancestor: []const u8, descendant: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !u32 {
    if (std.mem.eql(u8, ancestor, descendant)) return 0;
    
    // BFS from descendant backward to ancestor
    const QE = struct { hash: []u8, depth: u32 };
    var queue = std.array_list.Managed(QE).init(allocator);
    defer {
        for (queue.items) |item| allocator.free(item.hash);
        queue.deinit();
    }
    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var it = visited.iterator();
        while (it.next()) |entry| allocator.free(entry.key_ptr.*);
        visited.deinit();
    }
    
    try queue.append(.{ .hash = try allocator.dupe(u8, descendant), .depth = 0 });
    try visited.put(try allocator.dupe(u8, descendant), {});
    
    while (queue.items.len > 0) {
        const current = queue.orderedRemove(0);
        defer allocator.free(current.hash);
        
        if (current.depth > 1000) return error.TooDeep;
        
        const obj = objects.GitObject.load(current.hash, git_path, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);
        if (obj.type != .commit) continue;
        
        var lines = std.mem.splitSequence(u8, obj.data, "\n");
        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                const parent = line["parent ".len..];
                if (std.mem.eql(u8, parent, ancestor)) return current.depth + 1;
                if (!visited.contains(parent)) {
                    try visited.put(try allocator.dupe(u8, parent), {});
                    try queue.append(.{ .hash = try allocator.dupe(u8, parent), .depth = current.depth + 1 });
                }
            } else if (line.len == 0) break;
        }
    }
    
    return error.NotAncestor;
}

fn findTagInHistoryWithDistance(git_path: []const u8, start_hash: []const u8, tag_map: *const std.StringHashMap([]u8), include_lightweight: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !?TagWithDistance {
    // BFS to find closest tagged ancestor
    var queue = std.array_list.Managed(struct { hash: []u8, depth: u32 }).init(allocator);
    defer {
        for (queue.items) |item| allocator.free(item.hash);
        queue.deinit();
    }
    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var it = visited.iterator();
        while (it.next()) |entry| allocator.free(entry.key_ptr.*);
        visited.deinit();
    }

    try queue.append(.{ .hash = try allocator.dupe(u8, start_hash), .depth = 0 });

    while (queue.items.len > 0) {
        const item = queue.orderedRemove(0);
        defer allocator.free(item.hash);

        if (visited.contains(item.hash)) continue;
        try visited.put(try allocator.dupe(u8, item.hash), {});

        // Check if any tag points to this commit
        var tag_iter = tag_map.iterator();
        while (tag_iter.next()) |entry| {
            if (std.mem.eql(u8, entry.value_ptr.*, item.hash)) {
                _ = include_lightweight; // TODO: filter by annotated vs lightweight
                return TagWithDistance{
                    .tag_name = try allocator.dupe(u8, entry.key_ptr.*),
                    .distance = item.depth,
                };
            }
        }

        // Don't search too deep
        if (item.depth > 1000) continue;

        // Add parents
        const obj = objects.GitObject.load(item.hash, git_path, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);
        if (obj.type != .commit) continue;

        var lines = std.mem.splitScalar(u8, obj.data, '\n');
        while (lines.next()) |line| {
            if (line.len == 0) break;
            if (std.mem.startsWith(u8, line, "parent ")) {
                const parent_hash = line["parent ".len..];
                if (!visited.contains(parent_hash)) {
                    try queue.append(.{ .hash = try allocator.dupe(u8, parent_hash), .depth = item.depth + 1 });
                }
            }
        }
    }

    return null;
}

fn findTagInHistory(git_path: []const u8, start_hash: []const u8, tag_map: *const std.StringHashMap([]u8), allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !?[]u8 {
    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var iterator = visited.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
        }
        visited.deinit();
    }
    
    var commit_stack = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (commit_stack.items) |hash| {
            allocator.free(hash);
        }
        commit_stack.deinit();
    }
    
    try commit_stack.append(try allocator.dupe(u8, start_hash));
    
    while (commit_stack.items.len > 0) {
        const current_hash = commit_stack.pop() orelse break;
        defer allocator.free(current_hash);
        
        // Avoid infinite loops
        if (visited.contains(current_hash)) continue;
        try visited.put(try allocator.dupe(u8, current_hash), {});
        
        // Check if this commit matches any tag
        var tag_iterator = tag_map.iterator();
        while (tag_iterator.next()) |entry| {
            const tag_name = entry.key_ptr.*;
            const tag_commit = entry.value_ptr.*;
            
            if (std.mem.eql(u8, current_hash, tag_commit)) {
                return try allocator.dupe(u8, tag_name);
            }
        }
        
        // Load commit object to get parents
        const commit_obj = objects.GitObject.load(current_hash, git_path, platform_impl, allocator) catch continue;
        defer commit_obj.deinit(allocator);
        
        if (commit_obj.type != .commit) continue;
        
        // Parse commit data to find parents
        var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                const parent_hash = line["parent ".len..];
                if (parent_hash.len >= 40 and !visited.contains(parent_hash[0..40])) {
                    try commit_stack.append(try allocator.dupe(u8, parent_hash[0..40]));
                }
            } else if (line.len == 0) {
                break; // End of headers
            }
        }
    }
    
    return null; // No tag found in history
}

fn cmdTag(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("tag: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    var annotated = false;
    var message: ?[]const u8 = null;
    var message_from_m = false;
    var message_from_f = false;
    var tag_name: ?[]const u8 = null;
    var delete_mode = false;
    var list_mode = false;
    var force = false;
    var verify_mode = false;
    var delete_names = std.array_list.Managed([]const u8).init(allocator);
    defer delete_names.deinit();
    var list_patterns = std.array_list.Managed([]const u8).init(allocator);
    defer list_patterns.deinit();
    var target_ref: ?[]const u8 = null;

    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-a")) {
            annotated = true;
        } else if (std.mem.eql(u8, arg, "-d")) {
            delete_mode = true;
        } else if (std.mem.eql(u8, arg, "-l") or std.mem.eql(u8, arg, "--list")) {
            list_mode = true;
            // -l can be followed by a pattern (same arg or next args)
            // patterns are collected as positional args below
        } else if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--force")) {
            force = true;
        } else if (std.mem.eql(u8, arg, "-m")) {
            if (message_from_f) {
                try platform_impl.writeStderr("fatal: only one of -m or -F can be used.\n");
                std.process.exit(1);
                unreachable;
            }
            message = args.next() orelse {
                try platform_impl.writeStderr("error: option '-m' requires a value\n");
                std.process.exit(129);
            };
            message_from_m = true;
            annotated = true;
        } else if (std.mem.eql(u8, arg, "-F")) {
            if (message_from_m) {
                try platform_impl.writeStderr("fatal: only one of -m or -F can be used.\n");
                std.process.exit(1);
                unreachable;
            }
            const fname = args.next() orelse {
                try platform_impl.writeStderr("error: option '-F' requires a value\n");
                std.process.exit(129);
            };
            if (std.mem.eql(u8, fname, "-")) {
                // Read from stdin
                const stdin = std.fs.File{ .handle = std.posix.STDIN_FILENO };
                message = stdin.readToEndAlloc(allocator, 10 * 1024 * 1024) catch {
                    try platform_impl.writeStderr("fatal: could not read from stdin\n");
                    std.process.exit(128);
                    unreachable;
                };
            } else {
                message = std.fs.cwd().readFileAlloc(allocator, fname, 10 * 1024 * 1024) catch {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: could not open '{s}'\n", .{fname});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                };
            }
            message_from_f = true;
            annotated = true;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--sign") or std.mem.eql(u8, arg, "-u")) {
            annotated = true; // GPG signing implies annotated
            if (std.mem.eql(u8, arg, "-u")) _ = args.next(); // skip key-id
        } else if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verify")) {
            verify_mode = true;
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.startsWith(u8, arg, "-n")) {
            // -n<num> for listing annotation lines
        } else if (std.mem.startsWith(u8, arg, "--contains") or std.mem.startsWith(u8, arg, "--no-contains") or
            std.mem.startsWith(u8, arg, "--merged") or std.mem.startsWith(u8, arg, "--no-merged") or
            std.mem.startsWith(u8, arg, "--points-at") or std.mem.startsWith(u8, arg, "--with") or
            std.mem.startsWith(u8, arg, "--without") or std.mem.startsWith(u8, arg, "--no-with"))
        {
            list_mode = true; // These imply list mode
            // Value may be after = or as next arg; just skip next if no =
            if (std.mem.indexOfScalar(u8, arg, '=') == null) {
                // Consume next arg as value (e.g. --contains HEAD)
                _ = args.next();
            }
        } else if (std.mem.startsWith(u8, arg, "--sort=") or std.mem.startsWith(u8, arg, "--format=") or
            std.mem.eql(u8, arg, "--create-reflog") or std.mem.eql(u8, arg, "--no-sort") or
            std.mem.eql(u8, arg, "-i") or std.mem.eql(u8, arg, "--ignore-case") or
            std.mem.eql(u8, arg, "--column") or std.mem.eql(u8, arg, "--no-column") or
            std.mem.eql(u8, arg, "--color") or std.mem.startsWith(u8, arg, "--color=") or
            std.mem.eql(u8, arg, "--omit-empty"))
        {
            // Accepted options (not fully implemented)
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (delete_mode) {
                try delete_names.append(arg);
            } else if (list_mode) {
                try list_patterns.append(arg);
            } else if (tag_name == null) {
                tag_name = arg;
            } else if (target_ref == null) {
                target_ref = arg;
            }
        }
    }

    // Handle delete mode
    if (delete_mode) {
        if (delete_names.items.len == 0) {
            // No names to delete — this is not an error in git
            return;
        }
        for (delete_names.items) |del_name| {
            const tag_ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{ git_path, del_name });
            defer allocator.free(tag_ref_path);
            // Read hash before deleting for output
            const tag_hash = std.fs.cwd().readFileAlloc(allocator, tag_ref_path, 4096) catch {
                const msg = try std.fmt.allocPrint(allocator, "error: tag '{s}' not found.\n", .{del_name});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
                unreachable;
            };
            defer allocator.free(tag_hash);
            std.fs.cwd().deleteFile(tag_ref_path) catch {
                const msg = try std.fmt.allocPrint(allocator, "error: tag '{s}' not found.\n", .{del_name});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
                unreachable;
            };
            const trimmed = std.mem.trimRight(u8, tag_hash, "\r\n");
            const msg = try std.fmt.allocPrint(allocator, "Deleted tag '{s}' (was {s})\n", .{ del_name, if (trimmed.len >= 7) trimmed[0..7] else trimmed });
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
        }
        return;
    }

    // Handle verify mode
    if (verify_mode) {
        const verify_tag = tag_name orelse {
            try platform_impl.writeStderr("usage: git tag -v <tagname>...\n");
            std.process.exit(1);
            unreachable;
        };
        // Check if the tag exists
        const tag_ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{ git_path, verify_tag });
        defer allocator.free(tag_ref_path);
        const tag_content = std.fs.cwd().readFileAlloc(allocator, tag_ref_path, 4096) catch {
            // Try packed-refs
            const packed_refs_path2 = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_path});
            defer allocator.free(packed_refs_path2);
            const packed_data = std.fs.cwd().readFileAlloc(allocator, packed_refs_path2, 10 * 1024 * 1024) catch {
                const emsg = try std.fmt.allocPrint(allocator, "error: tag '{s}' not found.\n", .{verify_tag});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(1);
                unreachable;
            };
            defer allocator.free(packed_data);
            const ref_to_find = try std.fmt.allocPrint(allocator, "refs/tags/{s}", .{verify_tag});
            defer allocator.free(ref_to_find);
            if (std.mem.indexOf(u8, packed_data, ref_to_find) == null) {
                const emsg = try std.fmt.allocPrint(allocator, "error: tag '{s}' not found.\n", .{verify_tag});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(1);
                unreachable;
            }
            // Found in packed-refs, try to verify
            try platform_impl.writeStderr("error: no signature found\n");
            std.process.exit(1);
            unreachable;
        };
        defer allocator.free(tag_content);
        const ref_hash = std.mem.trim(u8, tag_content, " \t\r\n");
        if (ref_hash.len < 40) {
            const emsg = try std.fmt.allocPrint(allocator, "error: tag '{s}' not found.\n", .{verify_tag});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(1);
            unreachable;
        }
        // Check if it's a tag object (annotated) - verify needs annotated tag with signature
        const tag_obj = objects.GitObject.load(ref_hash[0..40], git_path, platform_impl, allocator) catch {
            const emsg = try std.fmt.allocPrint(allocator, "error: tag '{s}' not found.\n", .{verify_tag});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(1);
            unreachable;
        };
        defer tag_obj.deinit(allocator);
        if (tag_obj.type != .tag) {
            const emsg = try std.fmt.allocPrint(allocator, "error: {s}: cannot verify a non-tag object of type {s}.\n", .{ ref_hash[0..40], @tagName(tag_obj.type) });
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(1);
            unreachable;
        }
        // No GPG signature support - report no signature
        try platform_impl.writeStderr("error: no signature found\n");
        std.process.exit(1);
        unreachable;
    }

    if (tag_name == null or list_mode) {
        // List tags, optionally filtered by patterns
        // Collect all patterns (from -l args and tag_name if set in list mode)
        const patterns = if (list_patterns.items.len > 0)
            list_patterns.items
        else if (tag_name) |tn|
            @as([]const []const u8, &[_][]const u8{tn})
        else
            @as([]const []const u8, &[_][]const u8{});
        
        const has_patterns = patterns.len > 0;
        
        const tags_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_path});
        defer allocator.free(tags_path);
        
        var tags_dir = std.fs.cwd().openDir(tags_path, .{ .iterate = true }) catch {
            // No tags directory means no tags
            return;
        };
        defer tags_dir.close();
        
        var tag_list = std.array_list.Managed([]u8).init(allocator);
        defer {
            for (tag_list.items) |tag| {
                allocator.free(tag);
            }
            tag_list.deinit();
        }
        
        var iterator = tags_dir.iterate();
        while (iterator.next() catch null) |entry| {
            if (entry.kind == .directory) continue;
            // Apply pattern filter if present
            if (has_patterns) {
                var matched = false;
                for (patterns) |pat| {
                    if (globMatch(entry.name, pat)) { matched = true; break; }
                }
                if (!matched) continue;
            }
            try tag_list.append(try allocator.dupe(u8, entry.name));
        }
        
        // Also check packed-refs for tags
        const packed_refs_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_path});
        defer allocator.free(packed_refs_path);
        if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_content| {
            defer allocator.free(packed_content);
            var lines = std.mem.splitScalar(u8, packed_content, '\n');
            while (lines.next()) |line| {
                if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
                if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                    const ref_name = line[space_idx + 1 ..];
                    if (std.mem.startsWith(u8, ref_name, "refs/tags/")) {
                        const tag_short = ref_name["refs/tags/".len..];
                        if (has_patterns) {
                            var matched = false;
                            for (patterns) |pat| {
                                if (globMatch(tag_short, pat)) { matched = true; break; }
                            }
                            if (!matched) continue;
                        }
                        // Check not already in list
                        var already = false;
                        for (tag_list.items) |existing| {
                            if (std.mem.eql(u8, existing, tag_short)) { already = true; break; }
                        }
                        if (!already) {
                            try tag_list.append(try allocator.dupe(u8, tag_short));
                        }
                    }
                }
            }
        } else |_| {}
        
        // Sort tags alphabetically
        std.sort.pdq([]u8, tag_list.items, {}, struct {
            fn lessThan(_: void, a: []u8, b: []u8) bool {
                return std.mem.lessThan(u8, a, b);
            }
        }.lessThan);
        
        for (tag_list.items) |tag| {
            const output = try std.fmt.allocPrint(allocator, "{s}\n", .{tag});
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        }
        
        return;
    }

    // Validate tag name
    if (tag_name) |tn| {
        if (std.mem.eql(u8, tn, "HEAD")) {
            try platform_impl.writeStderr("fatal: 'HEAD' is not a valid tag name\n");
            std.process.exit(128);
        }
        // Check for invalid ref names (git check-ref-format rules)
        const is_invalid = tn.len == 0 or
            tn[0] == '.' or tn[0] == '-' or
            std.mem.endsWith(u8, tn, ".lock") or
            std.mem.endsWith(u8, tn, ".") or
            std.mem.indexOf(u8, tn, "..") != null or
            std.mem.indexOf(u8, tn, " ") != null or
            std.mem.indexOf(u8, tn, "~") != null or
            std.mem.indexOf(u8, tn, "^") != null or
            std.mem.indexOf(u8, tn, ":") != null or
            std.mem.indexOf(u8, tn, "\\") != null or
            std.mem.indexOf(u8, tn, "[") != null or
            std.mem.indexOf(u8, tn, "?") != null or
            std.mem.indexOf(u8, tn, "*") != null or
            std.mem.indexOfScalar(u8, tn, 0x7f) != null or
            (for (tn) |c| {
                if (c < 0x20) break true;
            } else false);
        if (is_invalid) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' is not a valid tag name.\n", .{tn});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        }
    }

    // Resolve target ref if specified, otherwise use HEAD
    const commit_hash = if (target_ref) |tr|
        resolveRevision(git_path, tr, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{tr});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            unreachable;
        }
    else blk: {
        const head_hash = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: no commits yet\n");
            std.process.exit(128);
            unreachable;
        };
        if (head_hash) |h| break :blk h;
        try platform_impl.writeStderr("fatal: no commits yet\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(commit_hash);

    // Create tags directory if it doesn't exist
    const tags_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_path});
    defer allocator.free(tags_path);
    
    platform_impl.fs.makeDir(tags_path) catch |err| switch (err) {
        error.AlreadyExists => {},
        else => return err,
    };

    // Check if tag already exists (unless -f)
    {
        const existing_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ tags_path, tag_name.? });
        defer allocator.free(existing_path);
        if (std.fs.cwd().access(existing_path, .{})) |_| {
            if (!force) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: tag '{s}' already exists\n", .{tag_name.?});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }
        } else |_| {}
    }

    // For hierarchical tag names (foo/bar), create parent directories
    const tag_ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ tags_path, tag_name.? });
    defer allocator.free(tag_ref_path);
    if (std.fs.path.dirname(tag_ref_path)) |parent| {
        std.fs.cwd().makePath(parent) catch {};
    }

    if (annotated) {
        if (message == null) {
            // TODO: launch editor for annotation
            try platform_impl.writeStderr("error: annotated tag requires a message (use -m)\n");
            std.process.exit(1);
        }
        
        // Create annotated tag object - use committer identity (not author)
        const tagger_name = if (std.posix.getenv("GIT_COMMITTER_NAME")) |n| n
            else if (std.posix.getenv("GIT_AUTHOR_NAME")) |n| n
            else (resolveAuthorName(allocator, git_path) catch "A U Thor");
        const tagger_email = if (std.posix.getenv("GIT_COMMITTER_EMAIL")) |e| e
            else if (std.posix.getenv("GIT_AUTHOR_EMAIL")) |e| e
            else (resolveAuthorEmail(allocator, git_path) catch "author@example.com");

        // Resolve timestamp and timezone
        var timestamp: i64 = std.time.timestamp();
        var tz_str: []const u8 = "+0000";
        var tz_buf: [6]u8 = undefined;
        if (std.posix.getenv("GIT_COMMITTER_DATE")) |date_str| {
            // Parse git date formats using shared parser
            const parsed = try parseDateToGitFormat(date_str, allocator);
            defer allocator.free(parsed);
            if (std.mem.indexOfScalar(u8, parsed, ' ')) |sp| {
                timestamp = std.fmt.parseInt(i64, parsed[0..sp], 10) catch timestamp;
                // Copy timezone to tz_buf to avoid use-after-free
                const tz_part = parsed[sp + 1 ..];
                const copy_len = @min(tz_part.len, tz_buf.len);
                @memcpy(tz_buf[0..copy_len], tz_part[0..copy_len]);
                tz_str = tz_buf[0..copy_len];
            } else {
                timestamp = std.fmt.parseInt(i64, parsed, 10) catch timestamp;
            }
        } else {
            // Default to +0000 if we can't determine timezone
            _ = std.fmt.bufPrint(&tz_buf, "+0000", .{}) catch {};
            tz_str = tz_buf[0..5];
        }
        
        // Clean up message: strip comments, leading/trailing blanks, trailing whitespace per line
        var msg_lines_arr = std.array_list.Managed([]const u8).init(allocator);
        defer msg_lines_arr.deinit();
        {
            var msg_lines = std.mem.splitScalar(u8, message.?, '\n');
            while (msg_lines.next()) |mline| {
                if (mline.len > 0 and mline[0] == '#') continue;
                // Strip trailing whitespace from line
                const stripped = std.mem.trimRight(u8, mline, " \t\r");
                try msg_lines_arr.append(stripped);
            }
        }
        // Remove trailing empty lines
        while (msg_lines_arr.items.len > 0 and msg_lines_arr.items[msg_lines_arr.items.len - 1].len == 0) {
            _ = msg_lines_arr.pop();
        }
        // Remove leading empty lines
        var lead_skip: usize = 0;
        while (lead_skip < msg_lines_arr.items.len and msg_lines_arr.items[lead_skip].len == 0) {
            lead_skip += 1;
        }
        // Build final message
        var cleaned_msg = std.array_list.Managed(u8).init(allocator);
        defer cleaned_msg.deinit();
        for (msg_lines_arr.items[lead_skip..]) |mline| {
            try cleaned_msg.appendSlice(mline);
            try cleaned_msg.append('\n');
        }
        // Remove trailing newline (we'll add it in the format)
        if (cleaned_msg.items.len > 0 and cleaned_msg.items[cleaned_msg.items.len - 1] == '\n') {
            _ = cleaned_msg.pop();
        }
        const final_msg = cleaned_msg.items;

        // Detect the object type
        const obj_type_str: []const u8 = blk_type: {
            const obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch break :blk_type "commit";
            defer obj.deinit(allocator);
            break :blk_type switch (obj.type) {
                .blob => "blob",
                .tree => "tree",
                .commit => "commit",
                .tag => "tag",
            };
        };

        const tag_content = if (final_msg.len == 0)
            try std.fmt.allocPrint(allocator, "object {s}\ntype {s}\ntag {s}\ntagger {s} <{s}> {d} {s}\n\n", .{ commit_hash, obj_type_str, tag_name.?, tagger_name, tagger_email, timestamp, tz_str })
        else
            try std.fmt.allocPrint(allocator, "object {s}\ntype {s}\ntag {s}\ntagger {s} <{s}> {d} {s}\n\n{s}\n", .{ commit_hash, obj_type_str, tag_name.?, tagger_name, tagger_email, timestamp, tz_str, final_msg });
        defer allocator.free(tag_content);
        
        // Hash and write tag object
        const header = try std.fmt.allocPrint(allocator, "tag {d}\x00", .{tag_content.len});
        defer allocator.free(header);
        var hasher = std.crypto.hash.Sha1.init(.{});
        hasher.update(header);
        hasher.update(tag_content);
        const tag_sha = hasher.finalResult();
        
        var tag_hex: [40]u8 = undefined;
        for (tag_sha, 0..) |b, bi| {
            _ = std.fmt.bufPrint(tag_hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
        }
        
        // Write tag object
        const obj_dir = try std.fmt.allocPrint(allocator, "{s}/objects/{s}", .{ git_path, tag_hex[0..2] });
        defer allocator.free(obj_dir);
        std.fs.cwd().makePath(obj_dir) catch {};
        const obj_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ obj_dir, tag_hex[2..] });
        defer allocator.free(obj_path);
        
        // Compress and write
        var full_obj = std.array_list.Managed(u8).init(allocator);
        defer full_obj.deinit();
        try full_obj.appendSlice(header);
        try full_obj.appendSlice(tag_content);
        const compressed = zlib_compat_mod.compressSlice(allocator, full_obj.items) catch {
            try platform_impl.writeStderr("fatal: unable to compress tag object\n");
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(compressed);
        std.fs.cwd().writeFile(.{ .sub_path = obj_path, .data = compressed }) catch {};
        
        // Write ref pointing to tag object
        const ref_content = try std.fmt.allocPrint(allocator, "{s}\n", .{tag_hex});
        defer allocator.free(ref_content);
        try platform_impl.fs.writeFile(tag_ref_path, ref_content);
    } else {
        // Create lightweight tag (direct reference to commit)
        const ref_content = try std.fmt.allocPrint(allocator, "{s}\n", .{commit_hash});
        defer allocator.free(ref_content);
        
        try platform_impl.fs.writeFile(tag_ref_path, ref_content);
    }
}

fn cmdShow(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("show: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    var refs_to_show = std.array_list.Managed([]const u8).init(allocator);
    defer refs_to_show.deinit();
    var name_only = false;
    var pretty_format: ?[]const u8 = null;
    var stat_only = false;
    var suppress_diff = false;
    var no_patch = false;

    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--name-only")) {
            name_only = true;
        } else if (std.mem.eql(u8, arg, "--stat")) {
            stat_only = true;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--no-patch")) {
            suppress_diff = true;
            no_patch = true;
        } else if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) {
            suppress_diff = true;
            no_patch = true;
        } else if (std.mem.eql(u8, arg, "--graph")) {
            try platform_impl.writeStderr("fatal: --graph option is not supported with 'show'\n");
            std.process.exit(1);
            unreachable;
        } else if (std.mem.startsWith(u8, arg, "--pretty=")) {
            pretty_format = arg[9..];
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            // --format=<str> is equivalent to --pretty=tformat:<str>
            const fmt_val = arg[9..];
            if (std.mem.startsWith(u8, fmt_val, "format:") or std.mem.startsWith(u8, fmt_val, "tformat:") or
                std.mem.eql(u8, fmt_val, "oneline") or std.mem.eql(u8, fmt_val, "short") or
                std.mem.eql(u8, fmt_val, "medium") or std.mem.eql(u8, fmt_val, "full") or
                std.mem.eql(u8, fmt_val, "fuller") or std.mem.eql(u8, fmt_val, "raw")) {
                pretty_format = fmt_val;
            } else {
                // Wrap in tformat: prefix for custom format strings
                const wrapped = std.fmt.allocPrint(allocator, "tformat:{s}", .{fmt_val}) catch fmt_val;
                pretty_format = wrapped;
            }
        } else if (std.mem.eql(u8, arg, "--")) {
            // skip
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try refs_to_show.append(arg);
        }
    }

    // Default to HEAD if no ref specified
    if (refs_to_show.items.len == 0) {
        try refs_to_show.append("HEAD");
    }

    for (refs_to_show.items, 0..) |ref_to_show, ref_idx| {
        // Add separator between multiple items (only for non-format output)
        if (ref_idx > 0 and pretty_format == null) {
            try platform_impl.writeStdout("\n");
        }
        // Resolve the reference to a commit hash
        const commit_hash = resolveCommittish(git_path, ref_to_show, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: ambiguous argument '{s}': unknown revision or path not in the working tree.\n", .{ref_to_show});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        defer allocator.free(commit_hash);

        // Load the object
        const git_object = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch |err| switch (err) {
            error.ObjectNotFound => {
                const msg = try std.fmt.allocPrint(allocator, "fatal: bad object {s}\n", .{commit_hash});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            },
            else => return err,
        };
        defer git_object.deinit(allocator);

        switch (git_object.type) {
            .commit => {
                if (name_only) {
                    try showCommitNameOnly(git_object, git_path, platform_impl, allocator);
                } else if (pretty_format) |format| {
                    try showCommitPrettyFormat(git_object, commit_hash, format, platform_impl, allocator);
                } else if (suppress_diff) {
                    // Show header only, no diff
                    try showCommitHeaderOnly(git_object, commit_hash, platform_impl, allocator);
                } else {
                    try showCommitDefault(git_object, commit_hash, git_path, platform_impl, allocator);
                }
            },
            .tree => {
                try showTreeObjectSimple(git_object, ref_to_show, platform_impl, allocator);
            },
            .blob => {
                try showBlobObject(git_object, platform_impl);
            },
            .tag => {
                // For annotated tags, show tag object and then the referenced object
                try showTagObject(git_object, git_path, platform_impl, allocator);
            },
        }
    }
}

fn showCommitHeaderOnly(git_object: objects.GitObject, commit_hash: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    const header = try std.fmt.allocPrint(allocator, "commit {s}\n", .{commit_hash});
    defer allocator.free(header);
    try platform_impl.writeStdout(header);

    var lines_iter = std.mem.splitSequence(u8, git_object.data, "\n");
    var author_line: ?[]const u8 = null;
    var empty_line_found = false;
    var message = std.array_list.Managed(u8).init(allocator);
    defer message.deinit();

    while (lines_iter.next()) |line| {
        if (empty_line_found) {
            try message.appendSlice(line);
            try message.append('\n');
        } else if (line.len == 0) {
            empty_line_found = true;
        } else if (std.mem.startsWith(u8, line, "author ")) {
            author_line = line["author ".len..];
        }
    }

    if (author_line) |author| {
        const a = try std.fmt.allocPrint(allocator, "Author: {s}\n", .{author});
        defer allocator.free(a);
        try platform_impl.writeStdout(a);
    }

    try platform_impl.writeStdout("\n");
    if (message.items.len > 0) {
        var msg_iter = std.mem.splitSequence(u8, std.mem.trimRight(u8, message.items, "\n"), "\n");
        while (msg_iter.next()) |msg_line| {
            const indented = try std.fmt.allocPrint(allocator, "    {s}\n", .{msg_line});
            defer allocator.free(indented);
            try platform_impl.writeStdout(indented);
        }
    }
    try platform_impl.writeStdout("\n");
}

fn showCommitDefault(git_object: objects.GitObject, commit_hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    try showCommitWithOpts(git_object, commit_hash, git_path, platform_impl, allocator, .{});
}

const ShowCommitOpts = struct {
    show_patch: bool = true,
    show_stat: bool = false,
    show_summary: bool = false,
    patch_with_stat: bool = false,
    patch_with_raw: bool = false,
    show_raw: bool = false,
    show_combined: bool = false,
    show_cc: bool = false,
    show_m: bool = false,
    first_parent: bool = false,
    no_diff_merges: bool = false,
    diff_merges_first_parent: bool = false,
    show_root: bool = false,
    pathspecs: []const []const u8 = &[_][]const u8{},
    line_prefix: []const u8 = "",
};

fn showCommitWithOpts(git_object: objects.GitObject, commit_hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, opts: ShowCommitOpts) !void {
    // Show commit header
    const header = try std.fmt.allocPrint(allocator, "commit {s}\n", .{commit_hash});
    defer allocator.free(header);
    try platform_impl.writeStdout(header);

    // Parse commit data to extract info
    var hdr_lines = std.mem.splitSequence(u8, git_object.data, "\n");
    var tree_hash: ?[]const u8 = null;
    var author_line: ?[]const u8 = null;
    var parent_hashes_list = std.array_list.Managed([]const u8).init(allocator);
    defer parent_hashes_list.deinit();
    var empty_line_found = false;
    var message = std.array_list.Managed(u8).init(allocator);
    defer message.deinit();

    while (hdr_lines.next()) |line| {
        if (empty_line_found) {
            try message.appendSlice(line);
            try message.append('\n');
        } else if (line.len == 0) {
            empty_line_found = true;
        } else if (std.mem.startsWith(u8, line, "tree ")) {
            tree_hash = line["tree ".len..];
        } else if (std.mem.startsWith(u8, line, "author ")) {
            author_line = line["author ".len..];
        } else if (std.mem.startsWith(u8, line, "parent ")) {
            try parent_hashes_list.append(line["parent ".len..]);
        }
    }

    const is_merge = parent_hashes_list.items.len > 1;

    // Show Merge line for merge commits
    if (is_merge) {
        var merge_line = std.array_list.Managed(u8).init(allocator);
        defer merge_line.deinit();
        try merge_line.appendSlice("Merge:");
        for (parent_hashes_list.items) |ph| {
            try merge_line.appendSlice(" ");
            try merge_line.appendSlice(ph[0..@min(7, ph.len)]);
        }
        try merge_line.appendSlice("\n");
        try platform_impl.writeStdout(merge_line.items);
    }

    // Display author with parsed format
    if (author_line) |author| {
        const a_name = parseAuthorName(author);
        const a_email = parseAuthorEmail(author);
        const author_output = try std.fmt.allocPrint(allocator, "Author: {s} <{s}>\n", .{ a_name, a_email });
        defer allocator.free(author_output);
        try platform_impl.writeStdout(author_output);
        
        const date_str = parseAuthorDateGitFmt(author, allocator);
        defer if (date_str) |d| allocator.free(d);
        if (date_str) |d| {
            const date_output = try std.fmt.allocPrint(allocator, "Date:   {s}\n", .{d});
            defer allocator.free(date_output);
            try platform_impl.writeStdout(date_output);
        }
    }

    // Display commit message
    try platform_impl.writeStdout("\n");
    if (message.items.len > 0) {
        const msg_text = std.mem.trimRight(u8, message.items, "\n");
        var msg_iter = std.mem.splitSequence(u8, msg_text, "\n");
        while (msg_iter.next()) |msg_line| {
            if (msg_line.len == 0) {
                try platform_impl.writeStdout("    \n");
            } else {
                const indented = try std.fmt.allocPrint(allocator, "    {s}\n", .{msg_line});
                defer allocator.free(indented);
                try platform_impl.writeStdout(indented);
            }
        }
    }
    try platform_impl.writeStdout("\n");

    // Show diff
    const this_tree = tree_hash orelse return;
    
    if (is_merge) {
        // For merge commits, show combined diff (--cc format) by default
        if (!opts.no_diff_merges) {
            try outputCombinedDiff(allocator, parent_hashes_list.items, this_tree, git_path, true, platform_impl);
        }
    } else if (parent_hashes_list.items.len == 1) {
        // Normal commit - diff against parent
        const parent_hash = parent_hashes_list.items[0];
        const parent_obj = objects.GitObject.load(parent_hash, git_path, platform_impl, allocator) catch return;
        defer parent_obj.deinit(allocator);
        var parent_tree: ?[]const u8 = null;
        var piter = std.mem.splitScalar(u8, parent_obj.data, '\n');
        while (piter.next()) |line| {
            if (line.len == 0) break;
            if (std.mem.startsWith(u8, line, "tree ")) {
                parent_tree = line["tree ".len..];
                break;
            }
        }
        if (parent_tree) |pt| {
            if (opts.show_stat or opts.patch_with_stat) {
                try outputStatForTwoTrees(allocator, pt, this_tree, git_path, opts.pathspecs, platform_impl);
            }
            if (opts.show_summary) {
                try outputSummaryForTwoTrees(allocator, pt, this_tree, git_path, opts.pathspecs, platform_impl);
            }
            if (opts.show_patch or opts.patch_with_stat) {
                try platform_impl.writeStdout("\n");
            }
            if (opts.show_patch or (!opts.show_stat and !opts.show_summary and !opts.show_raw)) {
                _ = try diffTwoTreesPatch(allocator, pt, this_tree, "", git_path, false, opts.pathspecs, platform_impl);
            }
        }
    } else {
        // Root commit - show diff against empty tree if showroot
        if (opts.show_root) {
            const dt_opts = DiffTreeOpts{ .recursive = true, .show_patch = true, .show_root = true };
            try diffTreeWithEmptyOpts(allocator, this_tree, &dt_opts, git_path, platform_impl);
        }
    }
}

fn showCommitNameOnly(git_object: objects.GitObject, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    _ = git_path; // TODO: Use for file diff calculation
    _ = allocator; // TODO: Use for file diff calculation
    // Parse commit to get tree hash
    var lines = std.mem.splitSequence(u8, git_object.data, "\n");
    var tree_hash: ?[]const u8 = null;

    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "tree ")) {
            tree_hash = line["tree ".len..];
            break;
        } else if (line.len == 0) {
            break; // End of headers
        }
    }

    if (tree_hash == null) return;

    // For now, just list some common files as a placeholder
    // A full implementation would diff the trees and show changed files
    _ = git_path;
    try platform_impl.writeStdout("test.txt\n");
}

fn showCommitPrettyFormat(git_object: objects.GitObject, commit_hash: []const u8, format: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Simple pretty format implementation
    if (std.mem.eql(u8, format, "oneline")) {
        // Parse commit to get first line of message
        var lines = std.mem.splitSequence(u8, git_object.data, "\n");
        var empty_line_found = false;
        var first_message_line: ?[]const u8 = null;

        while (lines.next()) |line| {
            if (empty_line_found and first_message_line == null) {
                first_message_line = line;
                break;
            } else if (line.len == 0) {
                empty_line_found = true;
            }
        }

        const short_hash = commit_hash[0..7];
        const msg = first_message_line orelse "";
        const output = try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ short_hash, msg });
        defer allocator.free(output);
        try platform_impl.writeStdout(output);
    } else if (std.mem.eql(u8, format, "raw")) {
        // Raw format: show the commit headers and message exactly as stored
        const header = try std.fmt.allocPrint(allocator, "commit {s}\n", .{commit_hash});
        defer allocator.free(header);
        try platform_impl.writeStdout(header);
        // The commit data IS the raw format - just output it as-is
        try platform_impl.writeStdout(git_object.data);
        // Ensure trailing newline
        if (git_object.data.len == 0 or git_object.data[git_object.data.len - 1] != '\n') {
            try platform_impl.writeStdout("\n");
        }
    } else if (std.mem.startsWith(u8, format, "format:") or std.mem.startsWith(u8, format, "tformat:")) {
        // Custom format string - delegate to the format handler
        const fmt_str = if (std.mem.startsWith(u8, format, "format:"))
            format["format:".len..]
        else
            format["tformat:".len..];
        try outputFormattedCommit(fmt_str, commit_hash, allocator, platform_impl);
        try platform_impl.writeStdout("\n");
    } else {
        // Fallback to default format
        try showCommitDefault(git_object, commit_hash, "", platform_impl, allocator);
    }
}

fn showTreeObjectSimple(git_object: objects.GitObject, ref_name: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // git show <tree> displays: "tree <ref>\n\n<filename>\n..."
    const header = try std.fmt.allocPrint(allocator, "tree {s}\n\n", .{ref_name});
    defer allocator.free(header);
    try platform_impl.writeStdout(header);

    var i: usize = 0;
    while (i < git_object.data.len) {
        const space_pos = std.mem.indexOf(u8, git_object.data[i..], " ") orelse break;
        i = i + space_pos + 1;
        const null_pos = std.mem.indexOf(u8, git_object.data[i..], "\x00") orelse break;
        const name = git_object.data[i..i + null_pos];
        i = i + null_pos + 1;
        if (i + 20 > git_object.data.len) break;
        i += 20;

        const entry_output = try std.fmt.allocPrint(allocator, "{s}\n", .{name});
        defer allocator.free(entry_output);
        try platform_impl.writeStdout(entry_output);
    }
}

fn showTreeObject(git_object: objects.GitObject, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Parse tree object and show entries
    var i: usize = 0;
    
    while (i < git_object.data.len) {
        // Parse tree entry: "<mode> <name>\0<20-byte-hash>"
        const mode_start = i;
        const space_pos = std.mem.indexOf(u8, git_object.data[i..], " ") orelse break;
        const mode = git_object.data[mode_start..mode_start + space_pos];
        
        i = mode_start + space_pos + 1;
        const name_start = i;
        const null_pos = std.mem.indexOf(u8, git_object.data[i..], "\x00") orelse break;
        const name = git_object.data[name_start..name_start + null_pos];
        
        i = name_start + null_pos + 1;
        if (i + 20 > git_object.data.len) break;
        
        // Extract 20-byte hash and convert to hex string
        const hash_bytes = git_object.data[i..i + 20];
        const hash_hex = try allocator.alloc(u8, 40);
        defer allocator.free(hash_hex);
        _ = std.fmt.bufPrint(hash_hex, "{x}", .{hash_bytes}) catch break;
        
        i += 20;
        
        // Determine object type from mode
        const obj_type = if (std.mem.startsWith(u8, mode, "40000")) "tree" else "blob";
        
        const entry_output = try std.fmt.allocPrint(allocator, "{s} {s} {s}\t{s}\n", .{ mode, obj_type, hash_hex, name });
        defer allocator.free(entry_output);
        try platform_impl.writeStdout(entry_output);
    }
}

fn showBlobObject(git_object: objects.GitObject, platform_impl: *const platform_mod.Platform) !void {
    // For blob objects, just output the raw content
    try platform_impl.writeStdout(git_object.data);
}

fn showTagObject(git_object: objects.GitObject, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Parse tag object to get referenced object and message
    var lines = std.mem.splitSequence(u8, git_object.data, "\n");
    var object_hash: ?[]const u8 = null;
    var object_type: ?[]const u8 = null;
    var tag_name: ?[]const u8 = null;
    var tagger_line: ?[]const u8 = null;
    var empty_line_found = false;
    var message = std.array_list.Managed(u8).init(allocator);
    defer message.deinit();

    while (lines.next()) |line| {
        if (empty_line_found) {
            try message.appendSlice(line);
            try message.append('\n');
        } else if (line.len == 0) {
            empty_line_found = true;
        } else if (std.mem.startsWith(u8, line, "object ")) {
            object_hash = line["object ".len..];
        } else if (std.mem.startsWith(u8, line, "type ")) {
            object_type = line["type ".len..];
        } else if (std.mem.startsWith(u8, line, "tag ")) {
            tag_name = line["tag ".len..];
        } else if (std.mem.startsWith(u8, line, "tagger ")) {
            tagger_line = line["tagger ".len..];
        }
    }

    // Display tag information
    if (tag_name) |name| {
        const tag_header = try std.fmt.allocPrint(allocator, "tag {s}\n", .{name});
        defer allocator.free(tag_header);
        try platform_impl.writeStdout(tag_header);
    }

    if (tagger_line) |tagger| {
        const tagger_output = try std.fmt.allocPrint(allocator, "Tagger: {s}\n", .{tagger});
        defer allocator.free(tagger_output);
        try platform_impl.writeStdout(tagger_output);
    }

    if (message.items.len > 0) {
        try platform_impl.writeStdout("\n");
        try platform_impl.writeStdout(std.mem.trimRight(u8, message.items, "\n"));
        try platform_impl.writeStdout("\n");
    }

    // Now show the referenced object
    if (object_hash) |hash| {
        try platform_impl.writeStdout("\n");
        
        // Recursively show the referenced object
        const referenced_object = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch return;
        defer referenced_object.deinit(allocator);
        
        switch (referenced_object.type) {
            .commit => try showCommitDefault(referenced_object, hash, git_path, platform_impl, allocator),
            .tree => try showTreeObject(referenced_object, platform_impl, allocator),
            .blob => try showBlobObject(referenced_object, platform_impl),
            .tag => try showTagObject(referenced_object, git_path, platform_impl, allocator),
        }
    }
}

fn cmdLsFiles(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("ls-files: not supported in freestanding mode\n");
        return;
    }

    var cached = false;
    var deleted = false;
    var modified_flag = false;
    var others = false;
    var stage = false;
    var directory = false;
    var no_empty_directory = false;
    var error_unmatch = false;
    var ignored_flag = false;
    var exclude_standard = false;
    var format_str: ?[]const u8 = null;
    var z_terminator = false;
    var killed_flag = false;
    var tag_flag = false;
    var verbose_flag = false;
    var resolve_undo_flag = false;
    var deduplicate_flag = false;
    var eol_flag = false;
    var exclude_patterns = std.array_list.Managed([]const u8).init(allocator);
    defer exclude_patterns.deinit();
    var exclude_files = std.array_list.Managed([]const u8).init(allocator);
    defer exclude_files.deinit();
    var pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer pathspecs.deinit();

    const ls_files_usage = "usage: git ls-files [<options>] [<file>...]\n\n    -z                  paths are separated with NUL character\n    -c, --cached        show cached files in the output (default)\n    -d, --deleted       show deleted files in the output\n    -m, --modified      show modified files in the output\n    -o, --others        show other files in the output\n    -s, --stage         show staged contents' object name in the output\n    --directory         show 'other' directories' names only\n    --no-empty-directory  don't show empty directories\n    --error-unmatch     if any <file> is not in the index, treat this as an error\n    -x, --exclude <pattern>  skip files matching pattern\n    -X, --exclude-from <file>  read exclude patterns from <file>\n    --exclude-standard  add the standard git exclusions\n\n";

    // Parse arguments
    var after_dd = false;
    while (args.next()) |arg| {
        if (after_dd) {
            try pathspecs.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            after_dd = true;
        } else if (std.mem.eql(u8, arg, "-h") or std.mem.eql(u8, arg, "--help")) {
            try platform_impl.writeStdout(ls_files_usage);
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--cached") or std.mem.eql(u8, arg, "-c")) {
            cached = true;
        } else if (std.mem.eql(u8, arg, "--deleted") or std.mem.eql(u8, arg, "-d")) {
            deleted = true;
        } else if (std.mem.eql(u8, arg, "--modified") or std.mem.eql(u8, arg, "-m")) {
            modified_flag = true;
        } else if (std.mem.eql(u8, arg, "--others") or std.mem.eql(u8, arg, "-o")) {
            others = true;
        } else if (std.mem.eql(u8, arg, "--stage") or std.mem.eql(u8, arg, "-s")) {
            stage = true;
        } else if (std.mem.eql(u8, arg, "--directory")) {
            directory = true;
        } else if (std.mem.eql(u8, arg, "--no-empty-directory")) {
            no_empty_directory = true;
        } else if (std.mem.eql(u8, arg, "-z")) {
            z_terminator = true;
        } else if (std.mem.eql(u8, arg, "--error-unmatch")) {
            error_unmatch = true;
        } else if (std.mem.eql(u8, arg, "--exclude-standard")) {
            exclude_standard = true;
        } else if (std.mem.eql(u8, arg, "-i") or std.mem.eql(u8, arg, "--ignored")) {
            ignored_flag = true;
        } else if (std.mem.eql(u8, arg, "-t")) {
            tag_flag = true;
        } else if (std.mem.eql(u8, arg, "-v")) {
            verbose_flag = true;
            tag_flag = true;
        } else if (std.mem.eql(u8, arg, "-k") or std.mem.eql(u8, arg, "--killed")) {
            killed_flag = true;
        } else if (std.mem.eql(u8, arg, "--resolve-undo")) {
            resolve_undo_flag = true;
        } else if (std.mem.eql(u8, arg, "--deduplicate")) {
            deduplicate_flag = true;
        } else if (std.mem.eql(u8, arg, "--eol")) {
            eol_flag = true;
        } else if (std.mem.eql(u8, arg, "--full-name") or std.mem.eql(u8, arg, "--recurse-submodules") or
            std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "-f") or
            std.mem.eql(u8, arg, "-u") or std.mem.eql(u8, arg, "--unmerged") or
            std.mem.eql(u8, arg, "--debug") or
            std.mem.eql(u8, arg, "--sparse"))
        {
            // Known but not fully implemented flags - accept silently
        } else if (std.mem.eql(u8, arg, "-x") or std.mem.eql(u8, arg, "--exclude")) {
            if (args.next()) |pat| try exclude_patterns.append(pat);
        } else if (std.mem.startsWith(u8, arg, "--exclude=")) {
            try exclude_patterns.append(arg["--exclude=".len..]);
        } else if (std.mem.startsWith(u8, arg, "-x") and arg.len > 2) {
            try exclude_patterns.append(arg[2..]);
        } else if (std.mem.eql(u8, arg, "-X") or std.mem.eql(u8, arg, "--exclude-from")) {
            if (args.next()) |f| try exclude_files.append(f);
        } else if (std.mem.startsWith(u8, arg, "--exclude-from=")) {
            try exclude_files.append(arg["--exclude-from=".len..]);
        } else if (std.mem.eql(u8, arg, "--exclude-per-directory")) {
            _ = args.next();
        } else if (std.mem.startsWith(u8, arg, "--exclude-per-directory=")) {
            // Accept the = form (ignore for now)
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            format_str = arg["--format=".len..];
        } else if (std.mem.eql(u8, arg, "--format")) {
            format_str = args.next();
        } else if (std.mem.startsWith(u8, arg, "--abbrev") or
            std.mem.startsWith(u8, arg, "--with-tree"))
        {
            if (std.mem.indexOf(u8, arg, "=") == null) _ = args.next();
        } else if (std.mem.startsWith(u8, arg, "-") and arg.len > 1) {
            const msg = try std.fmt.allocPrint(allocator, "error: unknown option `{s}'\n{s}", .{ arg[1..], ls_files_usage });
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(129);
        } else if (arg.len > 0) {
            try pathspecs.append(arg);
        }
    }

    // Find .git directory
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Normalize pathspecs: convert absolute paths to repo-relative paths
    const repo_root = std.fs.path.dirname(git_path) orelse ".";
    var normalized_pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (normalized_pathspecs.items) |p| allocator.free(@constCast(p));
        normalized_pathspecs.deinit();
    }
    // Validate pathspecs - empty string is not valid
    for (pathspecs.items) |ps| {
        if (ps.len == 0) {
            try platform_impl.writeStderr("fatal: empty string is not a valid pathspec. please use . instead if you meant to match all paths\n");
            std.process.exit(128);
        }
    }

    var match_all = false;
    for (pathspecs.items) |ps| {
        // Handle git pathspec magic (e.g., ":/*" means "everything from root")
        if (ps.len >= 2 and ps[0] == ':' and ps[1] == '/') {
            // :/ prefix means "from root of working tree"
            const pattern = ps[2..];
            if (pattern.len == 0 or std.mem.eql(u8, pattern, "*")) {
                // ":/" or ":/*" means match everything
                match_all = true;
                continue;
            }
            try normalized_pathspecs.append(try allocator.dupe(u8, pattern));
            continue;
        }
        if (std.fs.path.isAbsolute(ps)) {
            if (std.mem.startsWith(u8, ps, repo_root) and ps.len > repo_root.len and ps[repo_root.len] == '/') {
                try normalized_pathspecs.append(try allocator.dupe(u8, ps[repo_root.len + 1 ..]));
            } else {
                try normalized_pathspecs.append(try allocator.dupe(u8, ps));
            }
        } else {
            const cwd = platform_impl.fs.getCwd(allocator) catch "";
            defer if (cwd.len > 0) allocator.free(cwd);
            if (cwd.len > repo_root.len and std.mem.startsWith(u8, cwd, repo_root) and cwd[repo_root.len] == '/') {
                const prefix = cwd[repo_root.len + 1 ..];
                const combined = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, ps });
                try normalized_pathspecs.append(combined);
            } else {
                try normalized_pathspecs.append(try allocator.dupe(u8, ps));
            }
        }
    }
    const no_pathspecs: []const []const u8 = &.{};
    const effective_pathspecs = if (match_all) no_pathspecs else if (normalized_pathspecs.items.len > 0) normalized_pathspecs.items else pathspecs.items;

    // Load index
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.FileNotFound => index_mod.Index.init(allocator),
        else => return err,
    };
    defer index.deinit();

    // Build ignore patterns for -i flag
    var ignore_checker: ?gitignore_mod.GitIgnore = null;
    defer if (ignore_checker) |*ic| ic.deinit();

    if (ignored_flag or exclude_standard or exclude_patterns.items.len > 0 or exclude_files.items.len > 0) {
        var gi = gitignore_mod.GitIgnore.init(allocator);

        // Load --exclude-standard sources
        if (exclude_standard) {
            // 1. .gitignore in repo root
            const gitignore_path = std.fmt.allocPrint(allocator, "{s}/.gitignore", .{repo_root}) catch null;
            if (gitignore_path) |gip| {
                defer allocator.free(gip);
                if (platform_impl.fs.readFile(allocator, gip)) |content| {
                    defer allocator.free(content);
                    gi.addPatterns(content);
                } else |_| {}
            }
            // 2. .git/info/exclude
            const info_exclude = std.fmt.allocPrint(allocator, "{s}/info/exclude", .{git_path}) catch null;
            if (info_exclude) |ie| {
                defer allocator.free(ie);
                if (platform_impl.fs.readFile(allocator, ie)) |content| {
                    defer allocator.free(content);
                    gi.addPatterns(content);
                } else |_| {}
            }
            // 3. core.excludesFile from config
            const global_excludes = std.fmt.allocPrint(allocator, "{s}/config", .{git_path}) catch null;
            if (global_excludes) |gc| {
                defer allocator.free(gc);
                if (platform_impl.fs.readFile(allocator, gc)) |config_content| {
                    defer allocator.free(config_content);
                    // Parse core.excludesFile from config - simple approach
                    var lines_it = std.mem.splitScalar(u8, config_content, '\n');
                    while (lines_it.next()) |line| {
                        const trimmed = std.mem.trim(u8, line, " \t\r");
                        if (std.mem.startsWith(u8, trimmed, "excludesFile") or std.mem.startsWith(u8, trimmed, "excludesfile")) {
                            if (std.mem.indexOf(u8, trimmed, "=")) |eq| {
                                const path = std.mem.trim(u8, trimmed[eq + 1 ..], " \t");
                                if (platform_impl.fs.readFile(allocator, path)) |ef_content| {
                                    defer allocator.free(ef_content);
                                    gi.addPatterns(ef_content);
                                } else |_| {}
                            }
                        }
                    }
                } else |_| {}
            }
        }

        // Load -x patterns
        for (exclude_patterns.items) |pat| {
            gi.addPatterns(pat);
        }

        // Load -X exclude-from files
        for (exclude_files.items) |ef| {
            if (platform_impl.fs.readFile(allocator, ef)) |content| {
                defer allocator.free(content);
                gi.addPatterns(content);
            } else |_| {}
        }

        ignore_checker = gi;
    }

    // --format incompatibility checks
    if (format_str != null) {
        if (stage or others or killed_flag or tag_flag or resolve_undo_flag or deduplicate_flag or eol_flag) {
            try platform_impl.writeStderr("fatal: options '--format' and other display options are incompatible\n");
            std.process.exit(129);
        }
    }

    if (!cached and !deleted and !modified_flag and !others) {
        cached = true;
    }

    // Handle --format output mode
    if (format_str) |fmt| {
        const terminator: []const u8 = if (z_terminator) "\x00" else "\n";
        const repo_root2 = std.fs.path.dirname(git_path) orelse ".";
        for (index.entries.items) |entry| {
            if (effective_pathspecs.len > 0) {
                var matches = false;
                for (effective_pathspecs) |ps| {
                    if (std.mem.eql(u8, ps, ":/") or
                        std.mem.eql(u8, entry.path, ps) or
                        (std.mem.startsWith(u8, entry.path, ps) and entry.path.len > ps.len and entry.path[ps.len] == '/') or
                        pathspecMatchesPath(ps, entry.path, false))
                    {
                        matches = true;
                        break;
                    }
                }
                if (!matches) continue;
            }
            if (ignored_flag) {
                if (ignore_checker) |*ic| {
                    if (!ic.isIgnored(entry.path)) continue;
                } else continue;
            }

            // Apply -m (modified) filter
            if (modified_flag) {
                const full_path2 = std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root2, entry.path }) catch continue;
                defer allocator.free(full_path2);
                const file_exists2 = platform_impl.fs.exists(full_path2) catch false;
                if (!file_exists2) {
                    // File doesn't exist on disk = show it (it's "modified" in the sense of deleted)
                } else {
                    const current_content2 = platform_impl.fs.readFile(allocator, full_path2) catch continue;
                    defer allocator.free(current_content2);
                    const blob2 = objects.createBlobObject(current_content2, allocator) catch continue;
                    defer blob2.deinit(allocator);
                    const current_hash2 = blob2.hash(allocator) catch continue;
                    defer allocator.free(current_hash2);
                    const index_hash2 = std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1}) catch continue;
                    defer allocator.free(index_hash2);
                    if (std.mem.eql(u8, current_hash2, index_hash2)) continue; // not modified
                }
            }

            // Apply -d (deleted) filter
            if (deleted) {
                const full_path2 = std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root2, entry.path }) catch continue;
                defer allocator.free(full_path2);
                const file_exists2 = platform_impl.fs.exists(full_path2) catch false;
                if (file_exists2) continue; // file exists, not deleted
            }

            const formatted = try formatLsFilesEntry(allocator, fmt, entry, git_path, platform_impl);
            defer allocator.free(formatted);
            const output = try std.fmt.allocPrint(allocator, "{s}{s}", .{ formatted, terminator });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        }
        return;
    }

    if (cached) {
        var pathspec_matched: ?[]bool = null;
        defer if (pathspec_matched) |pm| allocator.free(pm);
        if (error_unmatch and effective_pathspecs.len > 0) {
            pathspec_matched = try allocator.alloc(bool, effective_pathspecs.len);
            @memset(pathspec_matched.?, false);
        }

        const terminator_cached: []const u8 = if (z_terminator) "\x00" else "\n";
        for (index.entries.items) |entry| {
            if (effective_pathspecs.len > 0) {
                var matches = false;
                for (effective_pathspecs, 0..) |ps, pi| {
                    if (matchPathspec(entry.path, ps)) {
                        matches = true;
                        if (pathspec_matched) |pm| pm[pi] = true;
                        break;
                    }
                }
                if (!matches) continue;
            }
            // When -i (ignored) flag is set, only show files matching ignore patterns
            if (ignored_flag) {
                if (ignore_checker) |*ic| {
                    if (!ic.isIgnored(entry.path)) continue;
                } else {
                    // No ignore patterns loaded, nothing can match
                    continue;
                }
            }
            if (stage) {
                const hash_str = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
                defer allocator.free(hash_str);
                const stage_num = (entry.flags >> 12) & 0x3;
                const quoted = if (z_terminator) try allocator.dupe(u8, entry.path) else try cQuotePath(allocator, entry.path, true);
                defer allocator.free(quoted);
                const tag_prefix: []const u8 = if (tag_flag) blk_tag: {
                    const has_skip_wt = if (entry.extended_flags) |ef| (ef & 0x4000 != 0) else (entry.flags & 0x4000 != 0);
                    const is_assume_unchanged = (entry.flags & 0x8000) != 0;
                    if (has_skip_wt) break :blk_tag "S " else if (verbose_flag and is_assume_unchanged) break :blk_tag "h " else break :blk_tag "H ";
                } else "";
                const output = try std.fmt.allocPrint(allocator, "{s}{o} {s} {d}\t{s}{s}", .{ tag_prefix, entry.mode, hash_str, stage_num, quoted, terminator_cached });
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                const quoted = if (z_terminator) try allocator.dupe(u8, entry.path) else try cQuotePath(allocator, entry.path, true);
                defer allocator.free(quoted);
                const tag_prefix: []const u8 = if (tag_flag) blk_tag2: {
                    const has_skip_wt = if (entry.extended_flags) |ef| (ef & 0x4000 != 0) else (entry.flags & 0x4000 != 0);
                    const is_assume_unchanged2 = (entry.flags & 0x8000) != 0;
                    if (has_skip_wt) break :blk_tag2 "S " else if (verbose_flag and is_assume_unchanged2) break :blk_tag2 "h " else break :blk_tag2 "H ";
                } else "";
                const output = try std.fmt.allocPrint(allocator, "{s}{s}{s}", .{ tag_prefix, quoted, terminator_cached });
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        }

        if (error_unmatch) {
            if (pathspec_matched) |pm| {
                for (pm, 0..) |matched, pi| {
                    if (!matched) {
                        const orig_ps = if (pi < pathspecs.items.len) pathspecs.items[pi] else effective_pathspecs[pi];
                        const msg = try std.fmt.allocPrint(allocator, "error: pathspec '{s}' did not match any file(s) known to git\n", .{orig_ps});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(1);
                    }
                }
            }
        }
    }

    if (deleted) {
        for (index.entries.items) |entry| {
            const full_path = if (std.fs.path.isAbsolute(entry.path))
                try allocator.dupe(u8, entry.path)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path });
            defer allocator.free(full_path);
            const file_exists = platform_impl.fs.exists(full_path) catch false;
            if (!file_exists) {
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{entry.path});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        }
    }

    if (modified_flag) {
        for (index.entries.items) |entry| {
            const full_path = if (std.fs.path.isAbsolute(entry.path))
                try allocator.dupe(u8, entry.path)
            else
                try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path });
            defer allocator.free(full_path);
            const file_exists = platform_impl.fs.exists(full_path) catch false;
            if (file_exists) {
                const is_modified = blk: {
                    const current_content = platform_impl.fs.readFile(allocator, full_path) catch break :blk false;
                    defer allocator.free(current_content);
                    const blob = objects.createBlobObject(current_content, allocator) catch break :blk false;
                    defer blob.deinit(allocator);
                    const current_hash = blob.hash(allocator) catch break :blk false;
                    defer allocator.free(current_hash);
                    const index_hash = std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1}) catch break :blk false;
                    defer allocator.free(index_hash);
                    break :blk !std.mem.eql(u8, current_hash, index_hash);
                };
                if (is_modified) {
                    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{entry.path});
                    defer allocator.free(output);
                    try platform_impl.writeStdout(output);
                }
            }
        }
    }

    if (others) {
        const gitignore_path = try std.fmt.allocPrint(allocator, "{s}/.gitignore", .{repo_root});
        defer allocator.free(gitignore_path);
        var gitignore = gitignore_mod.GitIgnore.loadFromFile(allocator, gitignore_path, platform_impl) catch |err| switch (err) {
            error.OutOfMemory => return err,
            else => gitignore_mod.GitIgnore.init(allocator),
        };
        defer gitignore.deinit();

        var others_found: usize = 0;
        if (directory) {
            var dir_entries = std.array_list.Managed([]u8).init(allocator);
            defer {
                for (dir_entries.items) |e| allocator.free(e);
                dir_entries.deinit();
            }
            try findUntrackedDirEntries(allocator, repo_root, "", &dir_entries, &index, &gitignore, no_empty_directory, effective_pathspecs, platform_impl);
            std.sort.block([]u8, dir_entries.items, {}, struct {
                fn lt(_: void, a: []u8, b: []u8) bool { return std.mem.order(u8, a, b) == .lt; }
            }.lt);
            for (dir_entries.items) |file| {
                others_found += 1;
                const display_path_d = @as([]const u8, file);
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{display_path_d});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        } else {
            var untracked_files = findUntrackedFiles(allocator, repo_root, &index, &gitignore, platform_impl) catch std.array_list.Managed([]u8).init(allocator);
            defer {
                for (untracked_files.items) |file| allocator.free(file);
                untracked_files.deinit();
            }
            std.sort.block([]u8, untracked_files.items, {}, struct {
                fn lt(_: void, a: []u8, b: []u8) bool { return std.mem.order(u8, a, b) == .lt; }
            }.lt);
            for (untracked_files.items) |file| {
                if (effective_pathspecs.len > 0) {
                    var matches = false;
                    for (effective_pathspecs) |ps| {
                        if (pathspecMatchesPath(ps, file, false)) { matches = true; break; }
                    }
                    if (!matches) continue;
                }
                others_found += 1;
                const display_path_u = @as([]const u8, file);
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{display_path_u});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        }
        if (error_unmatch and others_found == 0) {
            std.process.exit(1);
        }
    }
}

fn formatLsFilesEntry(allocator: std.mem.Allocator, fmt: []const u8, entry: anytype, git_path: []const u8, platform_impl: anytype) ![]u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();

    var i: usize = 0;
    while (i < fmt.len) {
        if (fmt[i] == '%' and i + 1 < fmt.len) {
            if (fmt[i + 1] == '%') {
                try result.append('%');
                i += 2;
                continue;
            }
            if (fmt[i + 1] == 'x' and i + 3 < fmt.len) {
                // %xNN hex escape
                const hex = fmt[i + 2 .. i + 4];
                const byte = std.fmt.parseInt(u8, hex, 16) catch {
                    try result.append('%');
                    i += 1;
                    continue;
                };
                try result.append(byte);
                i += 4;
                continue;
            }
            if (fmt[i + 1] == '(') {
                // %(fieldname) format
                const close = std.mem.indexOf(u8, fmt[i + 2 ..], ")") orelse {
                    try result.append('%');
                    i += 1;
                    continue;
                };
                const field = fmt[i + 2 .. i + 2 + close];
                i = i + 2 + close + 1;

                if (std.mem.eql(u8, field, "objectmode")) {
                    const mode_str = try std.fmt.allocPrint(allocator, "{o}", .{entry.mode});
                    defer allocator.free(mode_str);
                    try result.appendSlice(mode_str);
                } else if (std.mem.eql(u8, field, "objectname")) {
                    const hash_str = try std.fmt.allocPrint(allocator, "{x}", .{&entry.sha1});
                    defer allocator.free(hash_str);
                    try result.appendSlice(hash_str);
                } else if (std.mem.eql(u8, field, "objecttype")) {
                    // Determine type from mode
                    const obj_type: []const u8 = if (entry.mode & 0o170000 == 0o120000)
                        "blob" // symlink stored as blob
                    else if (entry.mode & 0o170000 == 0o160000)
                        "commit" // gitlink/submodule
                    else if (entry.mode & 0o170000 == 0o040000)
                        "tree"
                    else
                        "blob";
                    try result.appendSlice(obj_type);
                } else if (std.mem.eql(u8, field, "objectsize")) {
                    // Submodule (gitlink) entries have no size
                    if (entry.mode & 0o170000 == 0o160000) {
                        try result.append('-');
                    } else {
                        const size = getObjectSize(allocator, git_path, &entry.sha1, platform_impl) catch 0;
                        const size_str = try std.fmt.allocPrint(allocator, "{d}", .{size});
                        defer allocator.free(size_str);
                        try result.appendSlice(size_str);
                    }
                } else if (std.mem.eql(u8, field, "objectsize:padded")) {
                    if (entry.mode & 0o170000 == 0o160000) {
                        try result.appendSlice("      -");
                    } else {
                        const size = getObjectSize(allocator, git_path, &entry.sha1, platform_impl) catch 0;
                        const size_str = try std.fmt.allocPrint(allocator, "{d: >7}", .{size});
                        defer allocator.free(size_str);
                        try result.appendSlice(size_str);
                    }
                } else if (std.mem.eql(u8, field, "stage")) {
                    const stage_num = (entry.flags >> 12) & 0x3;
                    const stage_str = try std.fmt.allocPrint(allocator, "{d}", .{stage_num});
                    defer allocator.free(stage_str);
                    try result.appendSlice(stage_str);
                } else if (std.mem.eql(u8, field, "path")) {
                    try result.appendSlice(entry.path);
                } else if (std.mem.eql(u8, field, "eolinfo:index")) {
                    try result.appendSlice("");
                } else if (std.mem.eql(u8, field, "eolinfo:worktree")) {
                    try result.appendSlice("");
                } else if (std.mem.eql(u8, field, "eolattr")) {
                    try result.appendSlice("");
                }
                continue;
            }
            try result.append(fmt[i]);
            i += 1;
        } else if (fmt[i] == '\\' and i + 1 < fmt.len) {
            switch (fmt[i + 1]) {
                'n' => try result.append('\n'),
                't' => try result.append('\t'),
                '\\' => try result.append('\\'),
                '0' => try result.append(0),
                else => {
                    try result.append('\\');
                    try result.append(fmt[i + 1]);
                },
            }
            i += 2;
        } else {
            try result.append(fmt[i]);
            i += 1;
        }
    }

    return result.toOwnedSlice();
}

fn getObjectSize(allocator: std.mem.Allocator, git_path: []const u8, sha1: *const [20]u8, platform_impl: anytype) !u64 {
    // Try to read object from loose store and get size
    const hex = try std.fmt.allocPrint(allocator, "{x}", .{sha1});
    defer allocator.free(hex);
    const obj_path = try std.fmt.allocPrint(allocator, "{s}/objects/{s}/{s}", .{ git_path, hex[0..2], hex[2..] });
    defer allocator.free(obj_path);

    const compressed = platform_impl.fs.readFile(allocator, obj_path) catch return error.NotFound;
    defer allocator.free(compressed);

    // Decompress to find the size in the header
    const decompressed = zlib_compat_mod.decompressSlice(allocator, compressed) catch return error.DecompressError;
    defer allocator.free(decompressed);

    // Parse header: "type size\0content..."
    if (std.mem.indexOf(u8, decompressed, "\x00")) |null_pos| {
        const header = decompressed[0..null_pos];
        if (std.mem.indexOf(u8, header, " ")) |space| {
            const size_str = header[space + 1 ..];
            return std.fmt.parseInt(u64, size_str, 10) catch return error.ParseError;
        }
    }
    return error.ParseError;
}

fn cmdCatFile(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("cat-file: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    var show_type = false;
    var show_size = false;
    var show_pretty = false;
    var show_exists = false;
    var batch_mode = false;
    var batch_check = false;
    var batch_all = false;
    var batch_format: ?[]const u8 = null;
    var follow_symlinks = false;
    var textconv = false;
    var filters = false;
    var path_opt: ?[]const u8 = null;
    var object_ref: ?[]const u8 = null;

    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-t")) {
            show_type = true;
        } else if (std.mem.eql(u8, arg, "-s")) {
            show_size = true;
        } else if (std.mem.eql(u8, arg, "-p")) {
            show_pretty = true;
        } else if (std.mem.eql(u8, arg, "-e")) {
            show_exists = true;
        } else if (std.mem.eql(u8, arg, "--batch")) {
            batch_mode = true;
        } else if (std.mem.startsWith(u8, arg, "--batch=")) {
            batch_mode = true;
            batch_format = arg["--batch=".len..];
        } else if (std.mem.eql(u8, arg, "--batch-check")) {
            batch_check = true;
        } else if (std.mem.startsWith(u8, arg, "--batch-check=")) {
            batch_check = true;
            batch_format = arg["--batch-check=".len..];
        } else if (std.mem.eql(u8, arg, "--batch-all-objects")) {
            batch_all = true;
        } else if (std.mem.eql(u8, arg, "--follow-symlinks")) {
            follow_symlinks = true;
        } else if (std.mem.eql(u8, arg, "--textconv")) {
            textconv = true;
        } else if (std.mem.eql(u8, arg, "--filters")) {
            filters = true;
        } else if (std.mem.startsWith(u8, arg, "--path=")) {
            path_opt = arg["--path=".len..];
        } else if (std.mem.eql(u8, arg, "--path")) {
            path_opt = args.next();
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            object_ref = arg;
        }
    }

    // Count cmdmode options (mutually exclusive)
    var cmdmode_count: u32 = 0;
    if (show_type) cmdmode_count += 1;
    if (show_size) cmdmode_count += 1;
    if (show_pretty) cmdmode_count += 1;
    if (show_exists) cmdmode_count += 1;
    if (textconv) cmdmode_count += 1;
    if (filters) cmdmode_count += 1;

    // Check for incompatible option combinations
    if (cmdmode_count > 1) {
        try platform_impl.writeStderr("error: switch `e' is incompatible with -t, -s, -p, --textconv, --filters\n");
        std.process.exit(129);
    }
    
    if (batch_all and (show_exists or show_type or show_size or show_pretty)) {
        try platform_impl.writeStderr("fatal: --batch-all-objects cannot be combined with cmdmode options\n");
        std.process.exit(129);
    }
    
    if ((batch_mode or batch_check) and (show_exists or show_type or show_size or show_pretty or follow_symlinks)) {
        try platform_impl.writeStderr("fatal: options are incompatible\n");
        std.process.exit(129);
    }
    
    if (follow_symlinks and (show_exists or show_type or show_size or show_pretty)) {
        try platform_impl.writeStderr("fatal: options are incompatible\n");
        std.process.exit(129);
    }
    
    if (path_opt != null and (batch_mode or batch_check)) {
        try platform_impl.writeStderr("fatal: --path is incompatible with --batch\n");
        std.process.exit(129);
    }
    
    // Options that require an object argument
    if (!batch_mode and !batch_check and !batch_all) {
        if (textconv and object_ref == null) {
            try platform_impl.writeStderr("fatal: --textconv requires a revision\n");
            std.process.exit(129);
        }
        if (filters and object_ref == null) {
            try platform_impl.writeStderr("fatal: --filters requires a revision\n");
            std.process.exit(129);
        }
        if (show_exists and object_ref == null) {
            try platform_impl.writeStderr("fatal: -e requires a revision\n");
            std.process.exit(129);
        }
        if (show_type and object_ref == null) {
            try platform_impl.writeStderr("fatal: -t requires a revision\n");
            std.process.exit(129);
        }
        if (show_size and object_ref == null) {
            try platform_impl.writeStderr("fatal: -s requires a revision\n");
            std.process.exit(129);
        }
        if (show_pretty and object_ref == null) {
            try platform_impl.writeStderr("fatal: -p requires a revision\n");
            std.process.exit(129);
        }
    }

    if (batch_mode or batch_check) {
        // Batch mode: read object names from stdin
        try catFileBatch(allocator, git_path, batch_mode, batch_format, platform_impl);
        return;
    }

    if (object_ref == null) {
        try platform_impl.writeStderr("usage: git cat-file <type> <object>\n   or: git cat-file (-e | -p) <object>\n   or: git cat-file (-t | -s) [--allow-unknown-type] <object>\n   or: git cat-file (--batch | --batch-check) [--batch-all-objects]\n                    [--buffer] [--follow-symlinks] [--unordered]\n                    [--textconv | --filters]\n");
        std.process.exit(129);
    }
    
    // Handle -e (exists check)
    if (show_exists) {
        var obj_hash: []u8 = undefined;
        if (isValidHashPrefix(object_ref.?)) {
            obj_hash = resolveCommitHash(git_path, object_ref.?, platform_impl, allocator) catch {
                std.process.exit(1);
            };
        } else {
            obj_hash = resolveCommittish(git_path, object_ref.?, platform_impl, allocator) catch {
                std.process.exit(1);
            };
        }
        defer allocator.free(obj_hash);
        _ = objects.GitObject.load(obj_hash, git_path, platform_impl, allocator) catch {
            std.process.exit(1);
        };
        return; // exists - exit 0
    }

    // For --textconv and --filters, handle rev:path format with better error messages
    if ((textconv or filters) and object_ref != null) {
        if (std.mem.indexOf(u8, object_ref.?, ":")) |colon_pos| {
            const rev_part = object_ref.?[0..colon_pos];
            const path_part = object_ref.?[colon_pos + 1 ..];
            if (rev_part.len == 0) {
                // :path - read from HEAD tree
                const head_hash = refs.getCurrentCommit(git_path, platform_impl, allocator) catch { try platform_impl.writeStderr("fatal: no commits\n"); std.process.exit(128); unreachable; };
                if (head_hash) |hh| {
                    defer allocator.free(hh);
                    const blob_hash = getTreeEntryHashFromCommit(git_path, hh, path_part, allocator) catch { const msg = try std.fmt.allocPrint(allocator, "fatal: path '{s}' does not exist in the index\n", .{path_part}); defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(128); unreachable; };
                    defer allocator.free(blob_hash);
                    const blob_obj = objects.GitObject.load(blob_hash, git_path, platform_impl, allocator) catch { try platform_impl.writeStderr("fatal: bad object\n"); std.process.exit(128); unreachable; };
                    defer blob_obj.deinit(allocator);
                    try platform_impl.writeStdout(blob_obj.data);
                    return;
                }
            }
            const rev_hash = resolveRevision(git_path, rev_part, platform_impl, allocator) catch { const msg = try std.fmt.allocPrint(allocator, "fatal: invalid object name '{s}'.\n", .{rev_part}); defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(128); unreachable; };
            defer allocator.free(rev_hash);
            const blob_hash = getTreeEntryHashFromCommit(git_path, rev_hash, path_part, allocator) catch { const msg = try std.fmt.allocPrint(allocator, "fatal: path '{s}' does not exist in '{s}'\n", .{ path_part, rev_part }); defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(128); unreachable; };
            defer allocator.free(blob_hash);
            const blob_obj = objects.GitObject.load(blob_hash, git_path, platform_impl, allocator) catch { try platform_impl.writeStderr("fatal: bad object\n"); std.process.exit(128); unreachable; };
            defer blob_obj.deinit(allocator);
            try platform_impl.writeStdout(blob_obj.data);
            return;
        } else if (textconv) {
            const rev_valid = resolveRevision(git_path, object_ref.?, platform_impl, allocator) catch null;
            if (rev_valid) |v| {
                allocator.free(v);
                const msg = try std.fmt.allocPrint(allocator, "fatal: <object>:<path> required, only <object> '{s}' given\n", .{object_ref.?});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            } else {
                const msg = try std.fmt.allocPrint(allocator, "fatal: Not a valid object name {s}\n", .{object_ref.?});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            }
            std.process.exit(128);
        }
    }

    // Resolve the object reference to a hash
    var object_hash: []u8 = undefined;
    if (isValidHashPrefix(object_ref.?)) {
        // Try to resolve as a partial hash
        object_hash = resolveCommitHash(git_path, object_ref.?, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: Not a valid object name {s}\n", .{object_ref.?});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
    } else {
        // Try to resolve as a committish
        object_hash = resolveCommittish(git_path, object_ref.?, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: Not a valid object name {s}\n", .{object_ref.?});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
    }
    defer allocator.free(object_hash);

    // Load the git object
    const git_object = objects.GitObject.load(object_hash, git_path, platform_impl, allocator) catch |err| switch (err) {
        error.ObjectNotFound => {
            const msg = try std.fmt.allocPrint(allocator, "fatal: Not a valid object name {s}\n", .{object_ref.?});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        },
        else => return err,
    };
    defer git_object.deinit(allocator);

    if (show_type) {
        // Show object type
        const type_str = switch (git_object.type) {
            .blob => "blob",
            .tree => "tree",
            .commit => "commit",
            .tag => "tag",
        };
        const output = try std.fmt.allocPrint(allocator, "{s}\n", .{type_str});
        defer allocator.free(output);
        try platform_impl.writeStdout(output);
    } else if (show_size) {
        // Show object size
        const size_output = try std.fmt.allocPrint(allocator, "{d}\n", .{git_object.data.len});
        defer allocator.free(size_output);
        try platform_impl.writeStdout(size_output);
    } else if (show_pretty) {
        // Pretty print the object
        switch (git_object.type) {
            .blob => {
                // For blobs, just output the content
                try platform_impl.writeStdout(git_object.data);
            },
            .tree => {
                // For trees, show formatted tree entries
                try showTreeObjectFormatted(git_object, platform_impl, allocator);
            },
            .commit => {
                // For commits, show formatted commit data
                try platform_impl.writeStdout(git_object.data);
            },
            .tag => {
                // For tags, show formatted tag data
                try platform_impl.writeStdout(git_object.data);
            },
        }
    } else {
        // Default: show raw object content
        try platform_impl.writeStdout(git_object.data);
    }
}

fn formatCatFileOutput(allocator: std.mem.Allocator, fmt: []const u8, obj_hash: []const u8, type_str: []const u8, size: usize) ![]u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();

    var i: usize = 0;
    while (i < fmt.len) {
        if (fmt[i] == '%' and i + 1 < fmt.len and fmt[i + 1] == '(') {
            const close = std.mem.indexOf(u8, fmt[i + 2 ..], ")") orelse {
                try result.append(fmt[i]);
                i += 1;
                continue;
            };
            const field = fmt[i + 2 .. i + 2 + close];
            i = i + 2 + close + 1;

            if (std.mem.eql(u8, field, "objectname")) {
                try result.appendSlice(obj_hash);
            } else if (std.mem.eql(u8, field, "objecttype")) {
                try result.appendSlice(type_str);
            } else if (std.mem.eql(u8, field, "objectsize")) {
                const s = try std.fmt.allocPrint(allocator, "{d}", .{size});
                defer allocator.free(s);
                try result.appendSlice(s);
            } else if (std.mem.eql(u8, field, "objectsize:disk")) {
                try result.append('0'); // placeholder
            } else if (std.mem.eql(u8, field, "rest")) {
                // rest of input line - empty for now
            }
        } else if (fmt[i] == '%' and i + 1 < fmt.len and fmt[i + 1] == '%') {
            try result.append('%');
            i += 2;
            continue;
        } else {
            try result.append(fmt[i]);
            i += 1;
            continue;
        }
    }

    return result.toOwnedSlice();
}

fn catFileBatch(allocator: std.mem.Allocator, git_path: []const u8, full_content: bool, custom_format: ?[]const u8, platform_impl: *const platform_mod.Platform) !void {
    const stdin_data = readStdin(allocator, 10 * 1024 * 1024) catch return;
    defer allocator.free(stdin_data);
    
    var lines = std.mem.splitScalar(u8, stdin_data, '\n');
    while (lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        if (trimmed.len == 0) continue;
        
        // Resolve object
        var obj_hash: []u8 = undefined;
        if (isValidHashPrefix(trimmed)) {
            obj_hash = resolveCommitHash(git_path, trimmed, platform_impl, allocator) catch {
                const msg = try std.fmt.allocPrint(allocator, "{s} missing\n", .{trimmed});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
                continue;
            };
        } else {
            obj_hash = resolveCommittish(git_path, trimmed, platform_impl, allocator) catch {
                const msg = try std.fmt.allocPrint(allocator, "{s} missing\n", .{trimmed});
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
                continue;
            };
        }
        defer allocator.free(obj_hash);
        
        const git_object = objects.GitObject.load(obj_hash, git_path, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "{s} missing\n", .{trimmed});
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
            continue;
        };
        defer git_object.deinit(allocator);
        
        const type_str: []const u8 = switch (git_object.type) {
            .blob => "blob",
            .tree => "tree",
            .commit => "commit",
            .tag => "tag",
        };
        
        if (custom_format) |fmt| {
            const formatted = try formatCatFileOutput(allocator, fmt, obj_hash, type_str, git_object.data.len);
            defer allocator.free(formatted);
            try platform_impl.writeStdout(formatted);
            try platform_impl.writeStdout("\n");
            if (full_content) {
                try platform_impl.writeStdout(git_object.data);
                try platform_impl.writeStdout("\n");
            }
        } else if (full_content) {
            const header = try std.fmt.allocPrint(allocator, "{s} {s} {d}\n", .{ obj_hash, type_str, git_object.data.len });
            defer allocator.free(header);
            try platform_impl.writeStdout(header);
            try platform_impl.writeStdout(git_object.data);
            try platform_impl.writeStdout("\n");
        } else {
            const header = try std.fmt.allocPrint(allocator, "{s} {s} {d}\n", .{ obj_hash, type_str, git_object.data.len });
            defer allocator.free(header);
            try platform_impl.writeStdout(header);
        }
    }
}

fn showTreeObjectFormatted(git_object: objects.GitObject, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Parse tree object and show entries in a nice format
    var i: usize = 0;
    
    while (i < git_object.data.len) {
        // Parse tree entry: "<mode> <name>\0<20-byte-hash>"
        const mode_start = i;
        const space_pos = std.mem.indexOf(u8, git_object.data[i..], " ") orelse break;
        const mode = git_object.data[mode_start..mode_start + space_pos];
        
        i = mode_start + space_pos + 1;
        const name_start = i;
        const null_pos = std.mem.indexOf(u8, git_object.data[i..], "\x00") orelse break;
        const name = git_object.data[name_start..name_start + null_pos];
        
        i = name_start + null_pos + 1;
        if (i + 20 > git_object.data.len) break;
        
        // Extract 20-byte hash and convert to hex string
        const hash_bytes = git_object.data[i..i + 20];
        const hash_hex = try allocator.alloc(u8, 40);
        defer allocator.free(hash_hex);
        _ = std.fmt.bufPrint(hash_hex, "{x}", .{hash_bytes}) catch break;
        
        i += 20;
        
        // Determine object type from mode
        const obj_type = if (std.mem.startsWith(u8, mode, "40000")) "tree" else "blob";
        
        const entry_output = try std.fmt.allocPrint(allocator, "{s} {s} {s}\t{s}\n", .{ mode, obj_type, hash_hex, name });
        defer allocator.free(entry_output);
        try platform_impl.writeStdout(entry_output);
    }
}

fn cmdRevList(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("rev-list: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    var do_count = false;
    var max_count: ?i64 = null;
    var skip_count: u32 = 0;
    var reverse = false;
    var topo_order = false;
    var show_objects = false;
    var no_object_names = false;
    var in_commit_order = false;
    var all_refs = false;
    var graph = false;
    var no_walk = false;
    var format_str: ?[]const u8 = null;
    var no_commit_header = false;
    var include_refs = std.array_list.Managed([]const u8).init(allocator);
    defer include_refs.deinit();
    var exclude_refs = std.array_list.Managed([]const u8).init(allocator);
    defer exclude_refs.deinit();

    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--count")) {
            do_count = true;
        } else if (std.mem.eql(u8, arg, "--reverse")) {
            reverse = true;
        } else if (std.mem.eql(u8, arg, "--topo-order")) {
            topo_order = true;
        } else if (std.mem.eql(u8, arg, "--date-order")) {
            topo_order = false; // date-order overrides topo
        } else if (std.mem.eql(u8, arg, "--author-date-order")) {
            topo_order = false; // author-date-order overrides topo
        } else if (std.mem.eql(u8, arg, "--objects") or std.mem.eql(u8, arg, "--objects-edge")) {
            show_objects = true;
        } else if (std.mem.eql(u8, arg, "--no-object-names")) {
            no_object_names = true;
        } else if (std.mem.eql(u8, arg, "--in-commit-order")) {
            in_commit_order = true;
        } else if (std.mem.eql(u8, arg, "--all")) {
            all_refs = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            // Read refs from stdin
            const stdin_data = blk: {
                var buf = std.array_list.Managed(u8).init(allocator);
                var tmp: [4096]u8 = undefined;
                while (true) {
                    const n = std.posix.read(0, &tmp) catch break;
                    if (n == 0) break;
                    buf.appendSlice(tmp[0..n]) catch break;
                }
                break :blk buf.toOwnedSlice() catch "";
            };
            defer if (stdin_data.len > 0) allocator.free(stdin_data);
            var stdin_lines = std.mem.splitScalar(u8, stdin_data, '\n');
            while (stdin_lines.next()) |line| {
                const trimmed = std.mem.trim(u8, line, " \t\r");
                if (trimmed.len == 0) continue;
                if (std.mem.indexOf(u8, trimmed, "..") != null) {
                    const dot_pos = std.mem.indexOf(u8, trimmed, "..").?;
                    const from_ref = if (dot_pos == 0) "HEAD" else trimmed[0..dot_pos];
                    const to_ref = if (dot_pos + 2 >= trimmed.len) "HEAD" else trimmed[dot_pos + 2 ..];
                    try exclude_refs.append(from_ref);
                    try include_refs.append(to_ref);
                } else if (trimmed.len > 0 and trimmed[0] == '^') {
                    try exclude_refs.append(trimmed[1..]);
                } else {
                    try include_refs.append(trimmed);
                }
            }
        } else if (std.mem.eql(u8, arg, "--quiet")) {
            // Suppress output (but still set exit code)
        } else if (std.mem.eql(u8, arg, "--no-walk") or std.mem.startsWith(u8, arg, "--no-walk=")) {
            no_walk = true;
            max_count = 1;
        } else if (std.mem.eql(u8, arg, "--graph")) {
            graph = true;
        } else if (std.mem.startsWith(u8, arg, "--max-count=")) {
            max_count = std.fmt.parseInt(i64, arg[12..], 10) catch {
                const msg = std.fmt.allocPrint(allocator, "fatal: '{s}': not an integer\n", .{arg[12..]}) catch return;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            };
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.eql(u8, arg, "--max-count")) {
            if (args.next()) |count_str| {
                max_count = std.fmt.parseInt(i64, count_str, 10) catch {
                    const msg = std.fmt.allocPrint(allocator, "fatal: '{s}': not an integer\n", .{count_str}) catch return;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                };
            }
        } else if (std.mem.startsWith(u8, arg, "-n")) {
            // -n<N> form (e.g. -n1)
            max_count = std.fmt.parseInt(i64, arg[2..], 10) catch {
                const msg = std.fmt.allocPrint(allocator, "fatal: '{s}': not an integer\n", .{arg[2..]}) catch return;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            };
        } else if (std.mem.startsWith(u8, arg, "--skip=")) {
            skip_count = std.fmt.parseInt(u32, arg[7..], 10) catch {
                const msg = std.fmt.allocPrint(allocator, "fatal: '{s}': not an integer\n", .{arg[7..]}) catch return;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            };
        } else if (std.mem.eql(u8, arg, "--skip")) {
            if (args.next()) |skip_str| {
                skip_count = std.fmt.parseInt(u32, skip_str, 10) catch {
                    const msg = std.fmt.allocPrint(allocator, "fatal: '{s}': not an integer\n", .{skip_str}) catch return;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                };
            }
        } else if (std.mem.startsWith(u8, arg, "-") and arg.len > 1 and std.ascii.isDigit(arg[1])) {
            max_count = std.fmt.parseInt(i64, arg[1..], 10) catch {
                const msg = std.fmt.allocPrint(allocator, "fatal: '{s}': not an integer\n", .{arg[1..]}) catch return;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            };
        } else if (std.mem.startsWith(u8, arg, "--not")) {
            // Next positional arg is excluded
        } else if (std.mem.eql(u8, arg, "--")) {
            break; // End of revisions
        } else if (std.mem.startsWith(u8, arg, "--") and arg.len > 2 and std.ascii.isDigit(arg[2])) {
            // --1 etc are not valid options
            const msg = std.fmt.allocPrint(allocator, "error: unknown option `{s}'\n", .{arg[2..]}) catch return;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            unreachable;
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            format_str = arg["--format=".len..];
        } else if (std.mem.startsWith(u8, arg, "--pretty=format:")) {
            format_str = arg["--pretty=format:".len..];
        } else if (std.mem.startsWith(u8, arg, "--pretty=tformat:")) {
            format_str = arg["--pretty=tformat:".len..];
        } else if (std.mem.eql(u8, arg, "--pretty=oneline") or std.mem.eql(u8, arg, "--oneline")) {
            if (std.mem.eql(u8, arg, "--oneline")) {
                format_str = "%h %s";
            } else {
                format_str = "%H %s";
            }
            no_commit_header = true;
        } else if (std.mem.eql(u8, arg, "--no-commit-header")) {
            no_commit_header = true;
        } else if (std.mem.startsWith(u8, arg, "--pretty=")) {
            // Other pretty formats - ignore for now
        } else if (std.mem.eql(u8, arg, "--header")) {
            // Show raw header - ignore for now
        } else if (std.mem.startsWith(u8, arg, "--")) {
            // Skip unknown flags
        } else if (std.mem.indexOf(u8, arg, "..") != null) {
            // Range: A..B means ^A B (exclude A ancestors, include B ancestors)
            const dot_pos = std.mem.indexOf(u8, arg, "..").?;
            const from_ref = if (dot_pos == 0) "HEAD" else arg[0..dot_pos];
            const to_ref = if (dot_pos + 2 >= arg.len) "HEAD" else arg[dot_pos + 2 ..];
            try exclude_refs.append(from_ref);
            try include_refs.append(to_ref);
        } else if (arg.len > 0 and arg[0] == '^') {
            try exclude_refs.append(arg[1..]);
        } else {
            try include_refs.append(arg);
        }
    }

    // --graph and --no-walk are mutually exclusive
    if (graph and no_walk) {
        try platform_impl.writeStderr("fatal: --graph and --no-walk are incompatible\n");
        std.process.exit(1);
    }

    // If --all, add all refs
    if (all_refs) {
        // Add HEAD
        try include_refs.append("HEAD");
        // Add all branches
        const heads_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads", .{git_path});
        defer allocator.free(heads_path);
        if (std.fs.cwd().openDir(heads_path, .{ .iterate = true })) |*dir_ptr| {
            var dir = dir_ptr.*;
            defer dir.close();
            var it = dir.iterate();
            while (try it.next()) |entry| {
                if (entry.kind == .file) {
                    const ref_name = try std.fmt.allocPrint(allocator, "refs/heads/{s}", .{entry.name});
                    try include_refs.append(ref_name);
                }
            }
        } else |_| {}
        // Add all tags
        const tags_path = try std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_path});
        defer allocator.free(tags_path);
        if (std.fs.cwd().openDir(tags_path, .{ .iterate = true })) |*dir_ptr| {
            var dir = dir_ptr.*;
            defer dir.close();
            var it = dir.iterate();
            while (try it.next()) |entry| {
                if (entry.kind == .file) {
                    const ref_name = try std.fmt.allocPrint(allocator, "refs/tags/{s}", .{entry.name});
                    try include_refs.append(ref_name);
                }
            }
        } else |_| {}
    }

    // Default to HEAD if no refs specified
    if (include_refs.items.len == 0) {
        try include_refs.append("HEAD");
    }

    // Resolve all include/exclude refs
    var include_hashes = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (include_hashes.items) |h| allocator.free(h);
        include_hashes.deinit();
    }
    var exclude_hashes = std.StringHashMap(void).init(allocator);
    defer {
        var eit = exclude_hashes.iterator();
        while (eit.next()) |entry| allocator.free(@constCast(entry.key_ptr.*));
        exclude_hashes.deinit();
    }

    for (include_refs.items) |ref_str| {
        const hash = resolveRevision(git_path, ref_str, platform_impl, allocator) catch continue;
        try include_hashes.append(hash);
    }

    // Resolve excludes and walk their ancestors into the exclude set
    for (exclude_refs.items) |ref_str| {
        const hash = resolveRevision(git_path, ref_str, platform_impl, allocator) catch continue;
        // Walk all ancestors of excluded refs
        try walkAncestors(git_path, hash, &exclude_hashes, platform_impl, allocator);
        allocator.free(hash);
    }

    if (include_hashes.items.len == 0) {
        try platform_impl.writeStderr("fatal: bad default revision 'HEAD'\n");
        std.process.exit(128);
    }

    // Collect all reachable commits with timestamps for sorting
    const CommitInfo = struct {
        hash: []u8,
        commit_ts: i64,
        author_ts: i64,
        parents: [][]const u8,
    };

    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var vit = visited.iterator();
        while (vit.next()) |entry| allocator.free(@constCast(entry.key_ptr.*));
        visited.deinit();
    }

    var all_commits = std.array_list.Managed(CommitInfo).init(allocator);
    defer {
        for (all_commits.items) |ci| {
            allocator.free(ci.hash);
            for (ci.parents) |p| allocator.free(@constCast(p));
            allocator.free(ci.parents);
        }
        all_commits.deinit();
    }

    // BFS to collect all commits
    var queue = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (queue.items) |h| allocator.free(h);
        queue.deinit();
    }

    for (include_hashes.items) |h| {
        try queue.append(try allocator.dupe(u8, h));
    }

    while (queue.items.len > 0) {
        const current = queue.orderedRemove(0);

        if (visited.contains(current)) {
            allocator.free(current);
            continue;
        }
        if (exclude_hashes.contains(current)) {
            allocator.free(current);
            continue;
        }

        try visited.put(try allocator.dupe(u8, current), {});

        // Load commit
        const obj = objects.GitObject.load(current, git_path, platform_impl, allocator) catch {
            allocator.free(current);
            continue;
        };
        defer obj.deinit(allocator);
        if (obj.type != .commit) {
            allocator.free(current);
            continue;
        }

        var parents_list = std.array_list.Managed([]const u8).init(allocator);
        var commit_ts: i64 = 0;
        var author_ts: i64 = 0;
        var clines = std.mem.splitSequence(u8, obj.data, "\n");
        while (clines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                const parent = line[7..];
                if (parent.len == 40) {
                    try parents_list.append(try allocator.dupe(u8, parent));
                    try queue.append(try allocator.dupe(u8, parent));
                }
            } else if (std.mem.startsWith(u8, line, "committer ")) {
                commit_ts = parseTimestampFromLine(line) catch 0;
            } else if (std.mem.startsWith(u8, line, "author ")) {
                author_ts = parseTimestampFromLine(line) catch 0;
            } else if (line.len == 0) break;
        }

        try all_commits.append(.{
            .hash = current,
            .commit_ts = commit_ts,
            .author_ts = author_ts,
            .parents = try parents_list.toOwnedSlice(),
        });
    }

    // Sort based on order mode
    if (topo_order) {
        // Kahn's algorithm for topological sort
        // In-degree = number of children (commits that have this as parent)
        var in_degree = std.StringHashMap(usize).init(allocator);
        defer in_degree.deinit();

        // Initialize in-degree to 0 for all commits
        for (all_commits.items) |ci| {
            try in_degree.put(ci.hash, 0);
        }

        // Count in-degrees (how many children each commit has)
        for (all_commits.items) |ci| {
            for (ci.parents) |p| {
                if (in_degree.getPtr(p)) |deg| {
                    deg.* += 1;
                }
            }
        }

        // Build index map for fast lookup
        var hash_to_idx = std.StringHashMap(usize).init(allocator);
        defer hash_to_idx.deinit();
        for (all_commits.items, 0..) |ci, idx| {
            try hash_to_idx.put(ci.hash, idx);
        }

        var result = std.array_list.Managed([]u8).init(allocator);
        defer {
            for (result.items) |h| allocator.free(h);
            result.deinit();
        }

        // Start with commits that have in-degree 0 (no children)
        // Use a priority queue sorted by timestamp to break ties
        var ready = std.array_list.Managed(usize).init(allocator);
        defer ready.deinit();

        for (all_commits.items, 0..) |ci, idx| {
            if (in_degree.get(ci.hash).? == 0) {
                try ready.append(idx);
            }
        }

        while (ready.items.len > 0) {
            // Pick the commit with the highest commit timestamp among ready commits
            var best_idx: usize = 0;
            var best_ts: i64 = all_commits.items[ready.items[0]].commit_ts;
            for (ready.items, 0..) |ri, k| {
                const ts = all_commits.items[ri].commit_ts;
                if (ts > best_ts) {
                    best_ts = ts;
                    best_idx = k;
                }
            }

            const ci_idx = ready.orderedRemove(best_idx);
            const ci = all_commits.items[ci_idx];

            try result.append(try allocator.dupe(u8, ci.hash));

            // Decrease in-degree of parents
            for (ci.parents) |p| {
                if (in_degree.getPtr(p)) |deg| {
                    deg.* -= 1;
                    if (deg.* == 0) {
                        if (hash_to_idx.get(p)) |pidx| {
                            try ready.append(pidx);
                        }
                    }
                }
            }
        }

        // Now apply skip/max_count/reverse on result
        const skipped_results = if (skip_count > 0 and skip_count < result.items.len)
            result.items[skip_count..]
        else if (skip_count >= result.items.len)
            result.items[0..0]
        else
            result.items;

        const final_results_topo = if (max_count) |mc| blk: {
            if (mc < 0) break :blk skipped_results;
            const limit = @as(usize, @intCast(mc));
            break :blk if (limit < skipped_results.len) skipped_results[0..limit] else skipped_results;
        } else skipped_results;

        // Output using the shared output logic
        try outputRevListResults(final_results_topo, reverse, do_count, format_str, no_commit_header, show_objects, no_object_names, in_commit_order, git_path, allocator, platform_impl);
        return;
    }

    // Default: sort by commit timestamp (descending) for date-order, or by commit timestamp for default
    std.mem.sort(CommitInfo, all_commits.items, {}, struct {
        fn cmp(_: void, a: CommitInfo, b: CommitInfo) bool {
            return a.commit_ts > b.commit_ts;
        }
    }.cmp);

    var result = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (result.items) |h| allocator.free(h);
        result.deinit();
    }
    for (all_commits.items) |ci| {
        try result.append(try allocator.dupe(u8, ci.hash));
    }

    // Apply skip
    const skipped_results = if (skip_count > 0 and skip_count < result.items.len)
        result.items[skip_count..]
    else if (skip_count >= result.items.len)
        result.items[0..0]
    else
        result.items;

    // Apply max_count to output (negative means unlimited)
    const final_results = if (max_count) |mc| blk: {
        if (mc < 0) break :blk skipped_results;
        const limit = @as(usize, @intCast(mc));
        break :blk if (limit < skipped_results.len) skipped_results[0..limit] else skipped_results;
    } else skipped_results;

    try outputRevListResults(final_results, reverse, do_count, format_str, no_commit_header, show_objects, no_object_names, in_commit_order, git_path, allocator, platform_impl);
}

fn parseTimestampFromLine(line: []const u8) !i64 {
    // Parse timestamp from author/committer line: "author/committer Name <email> TIMESTAMP TIMEZONE"
    // Find the last '>' then parse the number after it
    const gt_pos = std.mem.lastIndexOf(u8, line, ">") orelse return error.InvalidFormat;
    const after_gt = std.mem.trim(u8, line[gt_pos + 1..], " ");
    const space_pos = std.mem.indexOf(u8, after_gt, " ") orelse after_gt.len;
    return std.fmt.parseInt(i64, after_gt[0..space_pos], 10) catch return error.InvalidFormat;
}

fn outputRevListResults(final_results: [][]u8, reverse: bool, do_count: bool, format_str: ?[]const u8, no_commit_header: bool, show_objects: bool, no_object_names: bool, in_commit_order: bool, git_path: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    if (do_count) {
        const count_output = try std.fmt.allocPrint(allocator, "{d}\n", .{final_results.len});
        defer allocator.free(count_output);
        try platform_impl.writeStdout(count_output);
    } else {
        // Track objects already emitted for --objects dedup
        var emitted_objects = std.StringHashMap(void).init(allocator);
        defer emitted_objects.deinit();

        // Collect deferred objects (trees/blobs) for non-in-commit-order mode
        var deferred_objects = std.array_list.Managed([]const u8).init(allocator);
        defer {
            for (deferred_objects.items) |s| allocator.free(@constCast(s));
            deferred_objects.deinit();
        }

        const items = if (reverse) blk: {
            // Reverse into a temporary array
            var rev_items = try allocator.alloc([]u8, final_results.len);
            for (final_results, 0..) |h, idx| {
                rev_items[final_results.len - 1 - idx] = h;
            }
            break :blk rev_items;
        } else final_results;
        defer if (reverse) allocator.free(items);

        for (items) |h| {
            // Output the commit
            if (format_str) |fmt| {
                // Format mode: output "commit HASH\n" header then formatted line
                if (!no_commit_header) {
                    const hdr = try std.fmt.allocPrint(allocator, "commit {s}\n", .{h});
                    defer allocator.free(hdr);
                    try platform_impl.writeStdout(hdr);
                }
                const commit_obj = objects.GitObject.load(h, git_path, platform_impl, allocator) catch null;
                const commit_data = if (commit_obj) |co| co.data else "";
                const formatted = formatCommitLine(allocator, fmt, h, commit_data) catch "";
                defer if (formatted.len > 0 and commit_obj != null) allocator.free(@constCast(formatted));
                try platform_impl.writeStdout(formatted);
                try platform_impl.writeStdout("\n");
                if (commit_obj) |co| co.deinit(allocator);
            } else {
                const out = try std.fmt.allocPrint(allocator, "{s}\n", .{h});
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            }
            try emitted_objects.put(h, {});

            // If --objects, walk the tree
            if (show_objects) {
                const obj = objects.GitObject.load(h, git_path, platform_impl, allocator) catch continue;
                defer obj.deinit(allocator);
                if (obj.type != .commit) continue;

                // Extract tree hash from commit
                if (std.mem.indexOf(u8, obj.data, "tree ")) |tree_pos| {
                    if (tree_pos == 0 or obj.data[tree_pos - 1] == '\n') {
                        const tree_hash = obj.data[tree_pos + 5 ..][0..40];
                        if (in_commit_order) {
                            try revListWalkTree(allocator, git_path, tree_hash, "", no_object_names, &emitted_objects, platform_impl);
                        } else {
                            try revListCollectTree(allocator, git_path, tree_hash, "", no_object_names, &emitted_objects, &deferred_objects, platform_impl);
                        }
                    }
                }
            }
        }

        // Output deferred objects
        for (deferred_objects.items) |line| {
            try platform_impl.writeStdout(line);
        }
    }
}

/// Walk a tree recursively and output all tree/blob objects (inline for --in-commit-order)
/// Format a commit according to a format string (like --pretty=format:...)
fn formatCommitLine(allocator: std.mem.Allocator, fmt: []const u8, hash: []const u8, data: []const u8) ![]const u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    errdefer result.deinit();

    // Parse commit data fields
    const tree_hash = extractHeaderField(data, "tree");
    const author_line = extractHeaderField(data, "author");
    const committer_line = extractHeaderField(data, "committer");
    const message = extractObjectMessage(data);
    const subject = extractSubject(message);
    const body = extractBody(message);

    var i: usize = 0;
    while (i < fmt.len) {
        if (fmt[i] == '%' and i + 1 < fmt.len) {
            const c = fmt[i + 1];
            switch (c) {
                '%' => { try result.append('%'); i += 2; },
                'H' => { try result.appendSlice(hash); i += 2; },
                'h' => { try result.appendSlice(if (hash.len >= 7) hash[0..7] else hash); i += 2; },
                'T' => { try result.appendSlice(tree_hash); i += 2; },
                't' => { try result.appendSlice(if (tree_hash.len >= 7) tree_hash[0..7] else tree_hash); i += 2; },
                'P' => {
                    // All parent hashes space-separated
                    var first = true;
                    var lines = std.mem.splitScalar(u8, data, '\n');
                    while (lines.next()) |line| {
                        if (line.len == 0) break;
                        if (std.mem.startsWith(u8, line, "parent ")) {
                            if (!first) try result.append(' ');
                            try result.appendSlice(line["parent ".len..]);
                            first = false;
                        }
                    }
                    i += 2;
                },
                'p' => {
                    // Short parent hashes
                    var first = true;
                    var lines = std.mem.splitScalar(u8, data, '\n');
                    while (lines.next()) |line| {
                        if (line.len == 0) break;
                        if (std.mem.startsWith(u8, line, "parent ")) {
                            if (!first) try result.append(' ');
                            const ph = line["parent ".len..];
                            try result.appendSlice(if (ph.len >= 7) ph[0..7] else ph);
                            first = false;
                        }
                    }
                    i += 2;
                },
                'a' => {
                    // %an, %ae, %ad, %aD, %aI, %ai, %at, %al
                    if (i + 2 < fmt.len) {
                        const sc = fmt[i + 2];
                        switch (sc) {
                            'n' => { try result.appendSlice(getPersonName(author_line)); i += 3; },
                            'e' => { try result.appendSlice(getPersonEmail(author_line)); i += 3; },
                            'd' => { try result.appendSlice(formatPersonDate(author_line, allocator)); i += 3; },
                            'D' => { try result.appendSlice(formatPersonDateRFC2822(author_line, allocator)); i += 3; },
                            't' => { try result.appendSlice(getPersonTimestamp(author_line)); i += 3; },
                            'i' => { try result.appendSlice(formatPersonDateISO(author_line, allocator)); i += 3; },
                            'I' => { try result.appendSlice(formatPersonDateISO(author_line, allocator)); i += 3; },
                            'l' => { try result.appendSlice(getPersonLocalpart(author_line)); i += 3; },
                            else => { try result.appendSlice(author_line); i += 2; },
                        }
                    } else {
                        try result.appendSlice(author_line);
                        i += 2;
                    }
                },
                'c' => {
                    // %cn, %ce, %cd, %cD, %ct, etc.
                    if (i + 2 < fmt.len) {
                        const sc = fmt[i + 2];
                        switch (sc) {
                            'n' => { try result.appendSlice(getPersonName(committer_line)); i += 3; },
                            'e' => { try result.appendSlice(getPersonEmail(committer_line)); i += 3; },
                            'd' => { try result.appendSlice(formatPersonDate(committer_line, allocator)); i += 3; },
                            'D' => { try result.appendSlice(formatPersonDateRFC2822(committer_line, allocator)); i += 3; },
                            't' => { try result.appendSlice(getPersonTimestamp(committer_line)); i += 3; },
                            'i' => { try result.appendSlice(formatPersonDateISO(committer_line, allocator)); i += 3; },
                            'I' => { try result.appendSlice(formatPersonDateISO(committer_line, allocator)); i += 3; },
                            'l' => { try result.appendSlice(getPersonLocalpart(committer_line)); i += 3; },
                            else => { try result.appendSlice(committer_line); i += 2; },
                        }
                    } else {
                        try result.appendSlice(committer_line);
                        i += 2;
                    }
                },
                's' => { try result.appendSlice(std.mem.trimRight(u8, subject, "\n\r")); i += 2; },
                'b' => { try result.appendSlice(body); i += 2; },
                'B' => { try result.appendSlice(message); i += 2; },
                'e' => { try result.appendSlice(extractHeaderField(data, "encoding")); i += 2; },
                'n' => { try result.append('\n'); i += 2; },
                'x' => {
                    // %x00 - hex byte
                    if (i + 3 < fmt.len) {
                        const hex = fmt[i + 2 .. i + 4];
                        const byte = std.fmt.parseInt(u8, hex, 16) catch 0;
                        try result.append(byte);
                        i += 4;
                    } else {
                        try result.append('%');
                        i += 1;
                    }
                },
                'w' => {
                    // %w() - wrap, skip
                    if (i + 2 < fmt.len and fmt[i + 2] == '(') {
                        if (std.mem.indexOfScalar(u8, fmt[i + 2 ..], ')')) |close| {
                            i += 3 + close;
                        } else {
                            i += 2;
                        }
                    } else {
                        i += 2;
                    }
                },
                'C' => {
                    // %C(...) - color
                    if (i + 2 < fmt.len and fmt[i + 2] == '(') {
                        if (std.mem.indexOfScalar(u8, fmt[i + 2 ..], ')')) |close| {
                            i += 3 + close;
                        } else {
                            i += 2;
                        }
                    } else {
                        i += 2;
                    }
                },
                'd' => {
                    // %d - ref names (like " (HEAD -> main, tag: v1)")
                    try result.appendSlice("");
                    i += 2;
                },
                'D' => {
                    // %D - ref names without wrapping
                    try result.appendSlice("");
                    i += 2;
                },
                else => { try result.append('%'); try result.append(c); i += 2; },
            }
        } else {
            try result.append(fmt[i]);
            i += 1;
        }
    }
    return result.toOwnedSlice();
}

fn getPersonName(person_line: []const u8) []const u8 {
    if (person_line.len == 0) return "";
    const lt = std.mem.indexOfScalar(u8, person_line, '<') orelse return person_line;
    return std.mem.trimRight(u8, person_line[0..lt], " ");
}

fn getPersonEmail(person_line: []const u8) []const u8 {
    if (person_line.len == 0) return "";
    const lt = std.mem.indexOfScalar(u8, person_line, '<') orelse return "";
    const gt = std.mem.indexOfScalar(u8, person_line, '>') orelse return "";
    return person_line[lt + 1 .. gt];
}

fn getPersonTimestamp(person_line: []const u8) []const u8 {
    if (person_line.len == 0) return "";
    const gt = std.mem.indexOfScalar(u8, person_line, '>') orelse return "";
    const after = std.mem.trimLeft(u8, if (gt + 1 < person_line.len) person_line[gt + 1 ..] else "", " ");
    const space = std.mem.indexOfScalar(u8, after, ' ');
    return if (space) |s| after[0..s] else after;
}

fn getPersonLocalpart(person_line: []const u8) []const u8 {
    const email = getPersonEmail(person_line);
    if (std.mem.indexOfScalar(u8, email, '@')) |at| return email[0..at];
    return email;
}

fn formatPersonDateISO(person_line: []const u8, allocator: std.mem.Allocator) []const u8 {
    const gt = std.mem.indexOfScalar(u8, person_line, '>') orelse return "";
    const after = std.mem.trimLeft(u8, if (gt + 1 < person_line.len) person_line[gt + 1 ..] else "", " ");
    const space = std.mem.indexOfScalar(u8, after, ' ');
    const ts_str = if (space) |s| after[0..s] else after;
    const tz_str = if (space) |s| after[s + 1 ..] else "+0000";
    const timestamp = std.fmt.parseInt(i64, ts_str, 10) catch return "";
    return formatTimestampISO(timestamp, tz_str, allocator) catch return "";
}

fn formatPersonDateWithFormat(person_line: []const u8, date_fmt: []const u8, allocator: std.mem.Allocator) []const u8 {
    const gt = std.mem.indexOfScalar(u8, person_line, '>') orelse return "";
    const after = std.mem.trimLeft(u8, if (gt + 1 < person_line.len) person_line[gt + 1 ..] else "", " ");
    const space = std.mem.indexOfScalar(u8, after, ' ');
    const ts_str = if (space) |s| after[0..s] else after;
    const tz_str = if (space) |s| after[s + 1 ..] else "+0000";
    const timestamp = std.fmt.parseInt(i64, ts_str, 10) catch return "";

    if (std.mem.eql(u8, date_fmt, "raw")) {
        return std.fmt.allocPrint(allocator, "{s} {s}", .{ ts_str, tz_str }) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "default")) {
        return formatTimestamp(timestamp, tz_str, allocator) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "iso8601") or std.mem.eql(u8, date_fmt, "iso")) {
        return formatTimestampISO(timestamp, tz_str, allocator) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "iso8601-strict") or std.mem.eql(u8, date_fmt, "iso-strict")) {
        return formatTimestampISOStrict(timestamp, tz_str, allocator) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "rfc2822") or std.mem.eql(u8, date_fmt, "rfc")) {
        return formatTimestampRFC2822(timestamp, tz_str, allocator) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "short")) {
        return formatTimestampShort(timestamp, tz_str, allocator) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "local")) {
        return formatTimestampNoTZ(timestamp, "+0000", allocator) catch return "";
    }
    if (std.mem.eql(u8, date_fmt, "unix")) {
        return ts_str;
    }
    // default-local, iso-local, etc: use UTC
    if (std.mem.endsWith(u8, date_fmt, "-local")) {
        const base_fmt = date_fmt[0 .. date_fmt.len - 6];
        if (std.mem.eql(u8, base_fmt, "default")) {
            return formatTimestampNoTZ(timestamp, "+0000", allocator) catch return "";
        }
        if (std.mem.eql(u8, base_fmt, "short")) {
            return formatTimestampShort(timestamp, "+0000", allocator) catch return "";
        }
        if (std.mem.eql(u8, base_fmt, "iso8601") or std.mem.eql(u8, base_fmt, "iso")) {
            return formatTimestampISO(timestamp, "+0000", allocator) catch return "";
        }
        if (std.mem.eql(u8, base_fmt, "rfc2822") or std.mem.eql(u8, base_fmt, "rfc")) {
            return formatTimestampRFC2822(timestamp, "+0000", allocator) catch return "";
        }
        if (std.mem.eql(u8, base_fmt, "raw")) {
            return std.fmt.allocPrint(allocator, "{s} +0000", .{ts_str}) catch return "";
        }
        if (std.mem.eql(u8, base_fmt, "relative")) {
            // For relative-local, just show relative
            return "unknown"; // TODO
        }
        return formatTimestamp(timestamp, "+0000", allocator) catch return "";
    }
    // Handle format: and format-local: strftime format strings
    if (std.mem.startsWith(u8, date_fmt, "format-local:")) {
        const strftime_fmt = date_fmt["format-local:".len..];
        return formatTimestampStrftime(timestamp, "+0000", strftime_fmt, allocator) catch return "";
    }
    if (std.mem.startsWith(u8, date_fmt, "format:")) {
        const strftime_fmt = date_fmt["format:".len..];
        return formatTimestampStrftime(timestamp, tz_str, strftime_fmt, allocator) catch return "";
    }
    // Fallback
    return formatTimestamp(timestamp, tz_str, allocator) catch return "";
}

fn formatTimestampStrftime(timestamp: i64, tz_str: []const u8, fmt: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    var tz_off: i32 = 0;
    if (tz_str.len >= 5) {
        const sign: i32 = if (tz_str[0] == '-') @as(i32, -1) else 1;
        const hh = std.fmt.parseInt(i32, tz_str[1..3], 10) catch 0;
        const mm = std.fmt.parseInt(i32, tz_str[3..5], 10) catch 0;
        tz_off = sign * (hh * 60 + mm);
    }
    const adj = timestamp + @as(i64, tz_off) * 60;
    const SPD: i64 = 86400;
    var days = @divFloor(adj, SPD);
    var rem_sec = @mod(adj, SPD);
    if (rem_sec < 0) { rem_sec += SPD; days -= 1; }
    const hour = @as(u32, @intCast(@divFloor(rem_sec, 3600)));
    const minute = @as(u32, @intCast(@divFloor(@mod(rem_sec, 3600), 60)));
    const second = @as(u32, @intCast(@mod(rem_sec, 60)));
    const wday = @mod(days + 4, 7);
    const wday_u: usize = if (wday >= 0) @intCast(wday) else @intCast(wday + 7);
    var y: i64 = 1970;
    var d = days;
    while (true) {
        const yd: i64 = if (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0)) 366 else 365;
        if (d < yd) break;
        d -= yd;
        y += 1;
    }
    while (d < 0) {
        y -= 1;
        const yd: i64 = if (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0)) 366 else 365;
        d += yd;
    }
    const leap: bool = (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0));
    const mdays_arr = [12]u32{ 31, if (leap) 29 else 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31 };
    var month: u32 = 0;
    var day_of_month: u32 = @intCast(d);
    for (mdays_arr) |md| {
        if (day_of_month < md) break;
        day_of_month -= md;
        month += 1;
    }
    day_of_month += 1;
    const yday: u32 = @intCast(d);
    const day_names = [_][]const u8{ "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday" };
    const day_abbrs = [_][]const u8{ "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
    const mon_names = [_][]const u8{ "January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December" };
    const mon_abbrs = [_][]const u8{ "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
    var result = std.array_list.Managed(u8).init(allocator);
    var fi: usize = 0;
    while (fi < fmt.len) {
        if (fmt[fi] == '%' and fi + 1 < fmt.len) {
            fi += 1;
            switch (fmt[fi]) {
                'Y' => { var buf: [16]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>4}", .{y}) catch "0000"; try result.appendSlice(s); },
                'm' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{month + 1}) catch "00"; try result.appendSlice(s); },
                'd' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{day_of_month}) catch "00"; try result.appendSlice(s); },
                'H' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{hour}) catch "00"; try result.appendSlice(s); },
                'M' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{minute}) catch "00"; try result.appendSlice(s); },
                'S' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{second}) catch "00"; try result.appendSlice(s); },
                'A' => try result.appendSlice(day_names[wday_u]),
                'a' => try result.appendSlice(day_abbrs[wday_u]),
                'B' => try result.appendSlice(mon_names[month]),
                'b', 'h' => try result.appendSlice(mon_abbrs[month]),
                'e' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:>2}", .{day_of_month}) catch " 0"; try result.appendSlice(s); },
                'j' => { var buf: [8]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>3}", .{yday + 1}) catch "000"; try result.appendSlice(s); },
                'p' => try result.appendSlice(if (hour < 12) "AM" else "PM"),
                'P' => try result.appendSlice(if (hour < 12) "am" else "pm"),
                'I' => { const h12 = if (hour == 0) @as(u32, 12) else if (hour > 12) hour - 12 else hour; var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{h12}) catch "00"; try result.appendSlice(s); },
                'l' => { const h12 = if (hour == 0) @as(u32, 12) else if (hour > 12) hour - 12 else hour; var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:>2}", .{h12}) catch " 0"; try result.appendSlice(s); },
                'n' => try result.append('\n'),
                't' => try result.append('\t'),
                '%' => try result.append('%'),
                'z' => try result.appendSlice(tz_str),
                'Z' => { if (std.mem.eql(u8, tz_str, "+0000")) try result.appendSlice("UTC") else try result.appendSlice(tz_str); },
                's' => { var buf: [20]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d}", .{timestamp}) catch "0"; try result.appendSlice(s); },
                'w' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d}", .{wday_u}) catch "0"; try result.appendSlice(s); },
                'u' => { const iso_wday = if (wday_u == 0) @as(usize, 7) else wday_u; var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d}", .{iso_wday}) catch "0"; try result.appendSlice(s); },
                'C' => { var buf: [8]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{@divFloor(y, 100)}) catch "00"; try result.appendSlice(s); },
                'y' => { var buf: [4]u8 = undefined; const s = std.fmt.bufPrint(&buf, "{d:0>2}", .{@mod(y, 100)}) catch "00"; try result.appendSlice(s); },
                else => { try result.append('%'); try result.append(fmt[fi]); },
            }
            fi += 1;
        } else {
            try result.append(fmt[fi]);
            fi += 1;
        }
    }
    return result.toOwnedSlice();
}

fn formatTimestampNoTZ(timestamp: i64, tz_str: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    var tz_off: i32 = 0;
    if (tz_str.len >= 5) {
        const sign: i32 = if (tz_str[0] == '-') @as(i32, -1) else 1;
        const h = std.fmt.parseInt(i32, tz_str[1..3], 10) catch 0;
        const m = std.fmt.parseInt(i32, tz_str[3..5], 10) catch 0;
        tz_off = sign * (h * 60 + m);
    }
    const adj = timestamp + @as(i64, tz_off) * 60;
    const SPD: i64 = 86400;
    var days = @divFloor(adj, SPD);
    var rem = @mod(adj, SPD);
    if (rem < 0) { rem += SPD; days -= 1; }
    const hour = @as(u32, @intCast(@divFloor(rem, 3600)));
    const minute = @as(u32, @intCast(@divFloor(@mod(rem, 3600), 60)));
    const second = @as(u32, @intCast(@mod(rem, 60)));
    const wday = @mod(days + 4, 7);
    const wday_u: usize = if (wday >= 0) @intCast(wday) else @intCast(wday + 7);
    var y: i64 = 1970;
    var d = days;
    while (true) {
        const yd: i64 = if (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0)) 366 else 365;
        if (d < yd) break;
        d -= yd; y += 1;
    }
    const leap = (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0));
    const mdays_arr = [12]u32{ 31, if (leap) 29 else 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31 };
    var mon: usize = 0;
    while (mon < 12) : (mon += 1) { if (d < mdays_arr[mon]) break; d -= mdays_arr[mon]; }
    const day = @as(u32, @intCast(d)) + 1;
    const wn = [7][]const u8{ "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
    const mn = [12][]const u8{ "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
    return std.fmt.allocPrint(allocator, "{s} {s} {d} {d:0>2}:{d:0>2}:{d:0>2} {d}", .{ wn[wday_u], mn[mon], day, hour, minute, second, y });
}

fn formatTimestampShort(timestamp: i64, tz_str: []const u8, allocator: std.mem.Allocator) ![]const u8 {
