fn revListWalkTree(allocator: std.mem.Allocator, git_path: []const u8, tree_hash: []const u8, prefix: []const u8, no_names: bool, emitted: *std.StringHashMap(void), platform_impl: *const platform_mod.Platform) !void {
    if (emitted.contains(tree_hash)) return;
    try emitted.put(try allocator.dupe(u8, tree_hash), {});

    // Output the tree itself
    if (no_names or prefix.len == 0) {
        const out = try std.fmt.allocPrint(allocator, "{s}\n", .{tree_hash});
        defer allocator.free(out);
        try platform_impl.writeStdout(out);
    } else {
        const out = try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ tree_hash, prefix });
        defer allocator.free(out);
        try platform_impl.writeStdout(out);
    }

    // Load and parse tree object
    const obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer obj.deinit(allocator);
    if (obj.type != .tree) return;

    // Parse tree entries: each entry is "<mode> <name>\0<20-byte-sha1>"
    var pos: usize = 0;
    while (pos < obj.data.len) {
        // Find space after mode
        const space_pos = std.mem.indexOfScalarPos(u8, obj.data, pos, ' ') orelse break;
        // Find null after name
        const null_pos = std.mem.indexOfScalarPos(u8, obj.data, space_pos + 1, 0) orelse break;
        const mode = obj.data[pos..space_pos];
        const name = obj.data[space_pos + 1 .. null_pos];
        if (null_pos + 21 > obj.data.len) break;
        const raw_hash = obj.data[null_pos + 1 .. null_pos + 21];

        // Convert binary hash to hex
        var hex_hash: [40]u8 = undefined;
        for (raw_hash, 0..) |b, bi| {
            _ = std.fmt.bufPrint(hex_hash[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch break;
        }

        const full_path = if (prefix.len == 0)
            try allocator.dupe(u8, name)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name });
        defer allocator.free(full_path);

        const is_tree = std.mem.eql(u8, mode, "40000");
        if (is_tree) {
            try revListWalkTree(allocator, git_path, &hex_hash, full_path, no_names, emitted, platform_impl);
        } else {
            if (!emitted.contains(&hex_hash)) {
                try emitted.put(try allocator.dupe(u8, &hex_hash), {});
                if (no_names) {
                    const out = try std.fmt.allocPrint(allocator, "{s}\n", .{hex_hash});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else {
                    const out = try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ hex_hash, full_path });
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
        }

        pos = null_pos + 21;
    }
}

/// Collect tree/blob objects into deferred list (for default order: commits first, then objects)
fn revListCollectTree(allocator: std.mem.Allocator, git_path: []const u8, tree_hash: []const u8, prefix: []const u8, no_names: bool, emitted: *std.StringHashMap(void), deferred: *std.array_list.Managed([]const u8), platform_impl: *const platform_mod.Platform) !void {
    if (emitted.contains(tree_hash)) return;
    try emitted.put(try allocator.dupe(u8, tree_hash), {});

    // Output the tree itself
    const tree_line = if (no_names or prefix.len == 0)
        try std.fmt.allocPrint(allocator, "{s}\n", .{tree_hash})
    else
        try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ tree_hash, prefix });
    try deferred.append(tree_line);

    // Load and parse tree object
    const obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer obj.deinit(allocator);
    if (obj.type != .tree) return;

    var pos: usize = 0;
    while (pos < obj.data.len) {
        const space_pos = std.mem.indexOfScalarPos(u8, obj.data, pos, ' ') orelse break;
        const null_pos = std.mem.indexOfScalarPos(u8, obj.data, space_pos + 1, 0) orelse break;
        const mode = obj.data[pos..space_pos];
        const name = obj.data[space_pos + 1 .. null_pos];
        if (null_pos + 21 > obj.data.len) break;
        const raw_hash = obj.data[null_pos + 1 .. null_pos + 21];

        var hex_hash: [40]u8 = undefined;
        for (raw_hash, 0..) |b, bi| {
            _ = std.fmt.bufPrint(hex_hash[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch break;
        }

        const full_path = if (prefix.len == 0)
            try allocator.dupe(u8, name)
        else
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name });
        defer allocator.free(full_path);

        const is_tree = std.mem.eql(u8, mode, "40000");
        if (is_tree) {
            try revListCollectTree(allocator, git_path, &hex_hash, full_path, no_names, emitted, deferred, platform_impl);
        } else {
            if (!emitted.contains(&hex_hash)) {
                try emitted.put(try allocator.dupe(u8, &hex_hash), {});
                const blob_line = if (no_names)
                    try std.fmt.allocPrint(allocator, "{s}\n", .{hex_hash})
                else
                    try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ hex_hash, full_path });
                try deferred.append(blob_line);
            }
        }

        pos = null_pos + 21;
    }
}

/// Walk all ancestors of a commit and add them to the set
fn walkAncestors(git_path: []const u8, start_hash: []const u8, set: *std.StringHashMap(void), platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    var queue = std.array_list.Managed([]u8).init(allocator);
    defer {
        for (queue.items) |h| allocator.free(h);
        queue.deinit();
    }
    try queue.append(try allocator.dupe(u8, start_hash));

    while (queue.items.len > 0) {
        const current = queue.orderedRemove(0);
        defer allocator.free(current);

        if (set.contains(current)) continue;
        try set.put(try allocator.dupe(u8, current), {});

        const obj = objects.GitObject.load(current, git_path, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);
        if (obj.type != .commit) continue;

        var lines = std.mem.splitSequence(u8, obj.data, "\n");
        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                const parent = line[7..];
                if (parent.len == 40) {
                    try queue.append(try allocator.dupe(u8, parent));
                }
            } else if (line.len == 0) break;
        }
    }
}

fn countCommits(git_path: []const u8, start_commit: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !u32 {
    var commit_hash = try allocator.dupe(u8, start_commit);
    defer allocator.free(commit_hash);

    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var iterator = visited.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
        }
        visited.deinit();
    }

    var count: u32 = 0;

    while (true) {
        // Avoid infinite loops
        if (visited.contains(commit_hash)) break;
        try visited.put(try allocator.dupe(u8, commit_hash), {});

        count += 1;

        // Load commit object
        const commit_object = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch break;
        defer commit_object.deinit(allocator);

        if (commit_object.type != .commit) break;

        // Find first parent
        var lines = std.mem.splitSequence(u8, commit_object.data, "\n");
        var parent_hash: ?[]const u8 = null;

        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                parent_hash = line["parent ".len..];
                break;
            } else if (line.len == 0) {
                break; // End of headers
            }
        }

        if (parent_hash == null) {
            break; // No parent, reached the root commit
        }

        // Move to parent
        const new_hash = try allocator.dupe(u8, parent_hash.?);
        allocator.free(commit_hash);
        commit_hash = new_hash;
    }

    return count;
}

fn listCommits(git_path: []const u8, start_commit: []const u8, max_count: ?u32, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    var commit_hash = try allocator.dupe(u8, start_commit);
    defer allocator.free(commit_hash);

    var visited = std.StringHashMap(void).init(allocator);
    defer {
        var iterator = visited.iterator();
        while (iterator.next()) |entry| {
            allocator.free(entry.key_ptr.*);
        }
        visited.deinit();
    }

    var count: u32 = 0;

    while (max_count == null or count < max_count.?) {
        // Avoid infinite loops
        if (visited.contains(commit_hash)) break;
        try visited.put(try allocator.dupe(u8, commit_hash), {});

        // Output commit hash
        const output = try std.fmt.allocPrint(allocator, "{s}\n", .{commit_hash});
        defer allocator.free(output);
        try platform_impl.writeStdout(output);

        count += 1;

        // Load commit object
        const commit_object = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch break;
        defer commit_object.deinit(allocator);

        if (commit_object.type != .commit) break;

        // Find first parent
        var lines = std.mem.splitSequence(u8, commit_object.data, "\n");
        var parent_hash: ?[]const u8 = null;

        while (lines.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) {
                parent_hash = line["parent ".len..];
                break;
            } else if (line.len == 0) {
                break; // End of headers
            }
        }

        if (parent_hash == null) {
            break; // No parent, reached the root commit
        }

        // Move to parent
        const new_hash = try allocator.dupe(u8, parent_hash.?);
        allocator.free(commit_hash);
        commit_hash = new_hash;
    }
}

fn cmdRemote(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("remote: not supported in freestanding mode\n");
        return;
    }

    // Find .git directory first
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any parent up to mount point /)\nStopping at filesystem boundary (GIT_DISCOVERY_ACROSS_FILESYSTEM not set).\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    var verbose = false;
    var subcommand: ?[]const u8 = null;
    var positionals = std.array_list.Managed([]const u8).init(allocator);
    defer positionals.deinit();

    // Parse arguments
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (subcommand == null and !std.mem.startsWith(u8, arg, "-")) {
            subcommand = arg;
        } else {
            try positionals.append(arg);
        }
    }

    // If no subcommand or just -v, list remotes
    if (subcommand == null or std.mem.eql(u8, subcommand.?, "-v") or std.mem.eql(u8, subcommand.?, "--verbose")) {
        if (std.mem.eql(u8, subcommand orelse "", "-v") or std.mem.eql(u8, subcommand orelse "", "--verbose")) {
            verbose = true;
        }
        try listRemotes(git_path, verbose, platform_impl, allocator);
    } else if (std.mem.eql(u8, subcommand.?, "add")) {
        // git remote add [-f] [-t <branch>] [-m <master>] <name> <url>
        var fetch_after_add = false;
        var add_positionals = std.array_list.Managed([]const u8).init(allocator);
        defer add_positionals.deinit();
        {
            var pi: usize = 0;
            while (pi < positionals.items.len) : (pi += 1) {
                const parg = positionals.items[pi];
                if (std.mem.eql(u8, parg, "-f") or std.mem.eql(u8, parg, "--fetch")) {
                    fetch_after_add = true;
                } else if (std.mem.eql(u8, parg, "-t") or std.mem.eql(u8, parg, "-m") or std.mem.eql(u8, parg, "--master")) {
                    pi += 1; // skip the value argument
                } else {
                    try add_positionals.append(parg);
                }
            }
        }
        if (add_positionals.items.len < 2) {
            try platform_impl.writeStderr("usage: git remote add <name> <url>\n");
            std.process.exit(1);
        }
        const name = add_positionals.items[0];
        const url = add_positionals.items[1];

        // Append to config file
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);

        // Check if remote already exists
        const existing = platform_impl.fs.readFile(allocator, config_path) catch try allocator.dupe(u8, "");
        defer allocator.free(existing);

        const remote_section = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{name});
        defer allocator.free(remote_section);

        if (std.mem.indexOf(u8, existing, remote_section) != null) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: remote {s} already exists.\n", .{name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(3);
        }

        const section = try std.fmt.allocPrint(allocator, "\n[remote \"{s}\"]\n\turl = {s}\n\tfetch = +refs/heads/*:refs/remotes/{s}/*\n", .{ name, url, name });
        defer allocator.free(section);

        const f = std.fs.cwd().openFile(config_path, .{ .mode = .write_only }) catch {
            // Create the config file
            const cf = std.fs.cwd().createFile(config_path, .{}) catch {
                try platform_impl.writeStderr("fatal: could not open config file\n");
                std.process.exit(128);
            };
            defer cf.close();
            cf.writeAll(section) catch {};
            return;
        };
        defer f.close();
        f.seekFromEnd(0) catch {};
        f.writeAll(section) catch {};
        
        // If -f flag, fetch from the new remote
        if (fetch_after_add) {
            var is_local = false;
            var local_path = url;
            if (std.mem.startsWith(u8, url, "file://")) { is_local = true; local_path = url["file://".len..]; }
            else if (std.mem.startsWith(u8, url, "/") or std.mem.startsWith(u8, url, "./") or std.mem.startsWith(u8, url, "../") or std.mem.eql(u8, url, ".") or std.mem.eql(u8, url, "..")) { is_local = true; }
            else if (!std.mem.startsWith(u8, url, "http://") and !std.mem.startsWith(u8, url, "https://") and !std.mem.startsWith(u8, url, "ssh://") and !std.mem.startsWith(u8, url, "git://")) {
                if (resolveSourceGitDir(allocator, url)) |sgd| { allocator.free(sgd); is_local = true; } else |_| {}
            }
            if (is_local) {
                const empty_refspecs: []const []const u8 = &.{};
                performLocalFetch(allocator, git_path, local_path, name, false, empty_refspecs, platform_impl, true) catch {};
            }
        }
    } else if (std.mem.eql(u8, subcommand.?, "remove") or std.mem.eql(u8, subcommand.?, "rm")) {
        // git remote remove <name>
        if (positionals.items.len < 1) {
            try platform_impl.writeStderr("usage: git remote remove <name>\n");
            std.process.exit(1);
        }
        const name = positionals.items[0];
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);

        const existing = platform_impl.fs.readFile(allocator, config_path) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote: '{s}'\n", .{name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(2);
            unreachable;
        };
        defer allocator.free(existing);

        const remote_header = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{name});
        defer allocator.free(remote_header);

        if (std.mem.indexOf(u8, existing, remote_header) == null) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote: '{s}'\n", .{name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(2);
        }

        // Remove the section
        var result = std.array_list.Managed(u8).init(allocator);
        defer result.deinit();
        var in_remove_section = false;
        var lines = std.mem.splitScalar(u8, existing, '\n');
        while (lines.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (std.mem.startsWith(u8, trimmed, "[remote \"") and std.mem.endsWith(u8, trimmed, "\"]")) {
                const sec_name = trimmed["[remote \"".len .. trimmed.len - "\"]".len];
                if (std.mem.eql(u8, sec_name, name)) {
                    in_remove_section = true;
                    continue;
                } else {
                    in_remove_section = false;
                }
            } else if (std.mem.startsWith(u8, trimmed, "[") and in_remove_section) {
                in_remove_section = false;
            }
            if (!in_remove_section) {
                try result.appendSlice(line);
                try result.append('\n');
            }
        }
        // Also remove branch.<name> sections that reference this remote
        platform_impl.fs.writeFile(config_path, result.items) catch {};

        // Remove remote tracking refs
        const remote_refs_dir = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}", .{ git_path, name });
        defer allocator.free(remote_refs_dir);
        std.fs.cwd().deleteTree(remote_refs_dir) catch {};
    } else if (std.mem.eql(u8, subcommand.?, "set-url")) {
        // git remote set-url <name> <newurl>
        if (positionals.items.len < 2) {
            try platform_impl.writeStderr("usage: git remote set-url <name> <newurl>\n");
            std.process.exit(1);
        }
        const name = positionals.items[0];
        const new_url = positionals.items[1];

        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const existing = platform_impl.fs.readFile(allocator, config_path) catch {
            try platform_impl.writeStderr("fatal: could not read config\n");
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(existing);

        var result = std.array_list.Managed(u8).init(allocator);
        defer result.deinit();
        var in_target_section = false;
        var url_replaced = false;
        var lines = std.mem.splitScalar(u8, existing, '\n');
        while (lines.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (std.mem.startsWith(u8, trimmed, "[remote \"") and std.mem.endsWith(u8, trimmed, "\"]")) {
                const sec_name = trimmed["[remote \"".len .. trimmed.len - "\"]".len];
                in_target_section = std.mem.eql(u8, sec_name, name);
            } else if (std.mem.startsWith(u8, trimmed, "[") and !std.mem.startsWith(u8, trimmed, "[remote \"")) {
                in_target_section = false;
            }
            if (in_target_section and std.mem.startsWith(u8, trimmed, "url = ")) {
                const new_line = try std.fmt.allocPrint(allocator, "\turl = {s}", .{new_url});
                defer allocator.free(new_line);
                try result.appendSlice(new_line);
                url_replaced = true;
            } else {
                try result.appendSlice(line);
            }
            try result.append('\n');
        }
        if (!url_replaced) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote '{s}'\n", .{name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(2);
        }
        platform_impl.fs.writeFile(config_path, result.items) catch {};
    } else if (std.mem.eql(u8, subcommand.?, "rename")) {
        // git remote rename <old> <new>
        if (positionals.items.len < 2) {
            try platform_impl.writeStderr("usage: git remote rename <old> <new>\n");
            std.process.exit(1);
        }
        const old_name = positionals.items[0];
        const new_name = positionals.items[1];

        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const existing = platform_impl.fs.readFile(allocator, config_path) catch {
            try platform_impl.writeStderr("fatal: could not read config\n");
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(existing);

        const old_header = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{old_name});
        defer allocator.free(old_header);
        if (std.mem.indexOf(u8, existing, old_header) == null) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote: '{s}'\n", .{old_name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(2);
        }

        // Replace remote name in config
        const new_header = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{new_name});
        defer allocator.free(new_header);

        // Simple string replacement for the section header
        var result = std.array_list.Managed(u8).init(allocator);
        defer result.deinit();
        var rest: []const u8 = existing;
        while (std.mem.indexOf(u8, rest, old_header)) |idx| {
            try result.appendSlice(rest[0..idx]);
            try result.appendSlice(new_header);
            rest = rest[idx + old_header.len ..];
        }
        try result.appendSlice(rest);
        platform_impl.fs.writeFile(config_path, result.items) catch {};

        // Rename refs directory
        const old_refs = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}", .{ git_path, old_name });
        defer allocator.free(old_refs);
        const new_refs = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}", .{ git_path, new_name });
        defer allocator.free(new_refs);
        std.fs.cwd().rename(old_refs, new_refs) catch {};
    } else if (std.mem.eql(u8, subcommand.?, "show")) {
        // Basic show - list URL for remote
        if (positionals.items.len < 1) {
            try listRemotes(git_path, verbose, platform_impl, allocator);
        } else {
            const name = positionals.items[0];
            const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
            defer allocator.free(config_path);
            const existing = platform_impl.fs.readFile(allocator, config_path) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote '{s}'\n", .{name});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(2);
                unreachable;
            };
            defer allocator.free(existing);

            const remote_header = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{name});
            defer allocator.free(remote_header);
            if (std.mem.indexOf(u8, existing, remote_header)) |_| {
                const header_msg = try std.fmt.allocPrint(allocator, "* remote {s}\n", .{name});
                defer allocator.free(header_msg);
                try platform_impl.writeStdout(header_msg);

                // Find URL
                var in_section = false;
                var lines = std.mem.splitScalar(u8, existing, '\n');
                while (lines.next()) |line| {
                    const trimmed = std.mem.trim(u8, line, " \t\r");
                    if (std.mem.startsWith(u8, trimmed, "[remote \"")) {
                        const sn = trimmed["[remote \"".len .. trimmed.len - "\"]".len];
                        in_section = std.mem.eql(u8, sn, name);
                    } else if (std.mem.startsWith(u8, trimmed, "[")) {
                        in_section = false;
                    }
                    if (in_section and std.mem.startsWith(u8, trimmed, "url = ")) {
                        const url_line = try std.fmt.allocPrint(allocator, "  Fetch URL: {s}\n  Push  URL: {s}\n", .{ trimmed["url = ".len..], trimmed["url = ".len..] });
                        defer allocator.free(url_line);
                        try platform_impl.writeStdout(url_line);
                    }
                }
            } else {
                const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote '{s}'\n", .{name});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(2);
            }
        }
    } else if (std.mem.eql(u8, subcommand.?, "get-url")) {
        // git remote get-url <name>
        if (positionals.items.len < 1) {
            try platform_impl.writeStderr("usage: git remote get-url <name>\n");
            std.process.exit(1);
        }
        const name = positionals.items[0];
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const existing = platform_impl.fs.readFile(allocator, config_path) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote '{s}'\n", .{name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(2);
            unreachable;
        };
        defer allocator.free(existing);

        var in_section = false;
        var found = false;
        var lines = std.mem.splitScalar(u8, existing, '\n');
        while (lines.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (std.mem.startsWith(u8, trimmed, "[remote \"") and std.mem.endsWith(u8, trimmed, "\"]")) {
                const sn = trimmed["[remote \"".len .. trimmed.len - "\"]".len];
                in_section = std.mem.eql(u8, sn, name);
            } else if (std.mem.startsWith(u8, trimmed, "[")) {
                in_section = false;
            }
            if (in_section and std.mem.startsWith(u8, trimmed, "url = ")) {
                const url_out = try std.fmt.allocPrint(allocator, "{s}\n", .{trimmed["url = ".len..]});
                defer allocator.free(url_out);
                try platform_impl.writeStdout(url_out);
                found = true;
            }
        }
        if (!found) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: No such remote '{s}'\n", .{name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(2);
        }
    } else if (std.mem.eql(u8, subcommand.?, "update")) {
        // git remote update [group|remote...]
        const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
        defer allocator.free(config_path);
        const config_data = platform_impl.fs.readFile(allocator, config_path) catch try allocator.dupe(u8, "");
        defer allocator.free(config_data);

        var remotes_to_fetch = std.array_list.Managed([]const u8).init(allocator);
        defer {
            for (remotes_to_fetch.items) |r| allocator.free(r);
            remotes_to_fetch.deinit();
        }

        if (positionals.items.len == 0 or (positionals.items.len == 1 and std.mem.eql(u8, positionals.items[0], "default"))) {
            // Fetch from all remotes
            var lines = std.mem.splitScalar(u8, config_data, '\n');
            while (lines.next()) |line| {
                const trimmed = std.mem.trim(u8, line, " \t\r");
                if (std.mem.startsWith(u8, trimmed, "[remote \"") and std.mem.endsWith(u8, trimmed, "\"]")) {
                    const rname = trimmed["[remote \"".len .. trimmed.len - "\"]".len];
                    try remotes_to_fetch.append(try allocator.dupe(u8, rname));
                }
            }
        } else {
            for (positionals.items) |group_or_remote| {
                // Check if it's a remote group (remotes.<name> config)
                var found_group = false;
                // Look for [remotes "<group>"] section
                var clines = std.mem.splitScalar(u8, config_data, '\n');
                var in_remotes_section = false;
                while (clines.next()) |cline| {
                    const ctrimmed = std.mem.trim(u8, cline, " \t\r");
                    if (std.mem.startsWith(u8, ctrimmed, "[remotes \"") and std.mem.endsWith(u8, ctrimmed, "\"]")) {
                        const gname = ctrimmed["[remotes \"".len .. ctrimmed.len - "\"]".len];
                        in_remotes_section = std.mem.eql(u8, gname, group_or_remote);
                    } else if (std.mem.startsWith(u8, ctrimmed, "[")) {
                        in_remotes_section = false;
                    }
                    if (in_remotes_section) {
                        // Look for key = value lines
                        if (std.mem.indexOf(u8, ctrimmed, "=")) |eq| {
                            const val = std.mem.trim(u8, ctrimmed[eq + 1..], " \t");
                            var parts = std.mem.splitAny(u8, val, " \t");
                            while (parts.next()) |part| {
                                if (part.len > 0) {
                                    found_group = true;
                                    try remotes_to_fetch.append(try allocator.dupe(u8, part));
                                }
                            }
                        }
                    }
                }

                if (!found_group) {
                    // Check if it's a remote name
                    const remote_section = try std.fmt.allocPrint(allocator, "[remote \"{s}\"]", .{group_or_remote});
                    defer allocator.free(remote_section);
                    if (std.mem.indexOf(u8, config_data, remote_section) != null) {
                        try remotes_to_fetch.append(try allocator.dupe(u8, group_or_remote));
                    } else {
                        const msg = try std.fmt.allocPrint(allocator, "error: No such remote or remote group: {s}\n", .{group_or_remote});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(1);
                    }
                }
            }
        }

        // Fetch from each remote
        for (remotes_to_fetch.items) |rname| {
            const fetch_msg = try std.fmt.allocPrint(allocator, "Fetching {s}\n", .{rname});
            defer allocator.free(fetch_msg);
            try platform_impl.writeStderr(fetch_msg);

            const rurl = getRemoteUrl(git_path, rname, platform_impl, allocator) catch continue;
            defer allocator.free(rurl);

            if (std.mem.startsWith(u8, rurl, "https://") or std.mem.startsWith(u8, rurl, "http://")) {
                const ziggit = @import("ziggit.zig");
                const is_bare_repo = !std.mem.endsWith(u8, git_path, "/.git");
                const repo_path = if (is_bare_repo) git_path else (std.fs.path.dirname(git_path) orelse ".");
                var repo = ziggit.Repository.open(allocator, repo_path) catch continue;
                defer repo.close();
                repo.fetch(rurl) catch continue;
            } else {
                var local_path = rurl;
                if (std.mem.startsWith(u8, rurl, "file://")) local_path = rurl["file://".len..];
                performLocalFetch(allocator, git_path, local_path, rname, false, &.{}, platform_impl, true) catch continue;
            }
        }
    } else if (std.mem.eql(u8, subcommand.?, "set-branches") or
        std.mem.eql(u8, subcommand.?, "prune") or
        std.mem.eql(u8, subcommand.?, "set-head"))
    {
        // Stub - silently accept
    } else {
        const msg = try std.fmt.allocPrint(allocator, "error: Unknown subcommand: {s}\n", .{subcommand.?});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(1);
    }
}

fn listRemotes(git_path: []const u8, verbose: bool, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path});
    defer allocator.free(config_path);
    
    const config_content = platform_impl.fs.readFile(allocator, config_path) catch |err| switch (err) {
        error.FileNotFound => {
            // No config file means no remotes
            return;
        },
        else => return err,
    };
    defer allocator.free(config_content);

    var lines = std.mem.splitSequence(u8, config_content, "\n");
    var current_remote: ?[]u8 = null;
    defer if (current_remote) |r| allocator.free(r);
    
    while (lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        
        // Check for remote section header [remote "name"]
        if (std.mem.startsWith(u8, trimmed, "[remote \"") and std.mem.endsWith(u8, trimmed, "\"]")) {
            if (current_remote) |r| {
                allocator.free(r);
            }
            const start = "[remote \"".len;
            const end = trimmed.len - "\"]".len;
            current_remote = try allocator.dupe(u8, trimmed[start..end]);
        }
        
        // Check for URL in current remote section
        else if (current_remote != null and std.mem.startsWith(u8, trimmed, "url = ")) {
            const url = trimmed["url = ".len..];
            if (verbose) {
                const output = try std.fmt.allocPrint(allocator, "{s}\t{s} (fetch)\n{s}\t{s} (push)\n", .{current_remote.?, url, current_remote.?, url});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                const output = try std.fmt.allocPrint(allocator, "{s}\n", .{current_remote.?});
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        }
    }
}

fn cmdReset(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("reset: not supported in freestanding mode\n");
        return;
    }

    // Find git directory
    const cwd = try platform_impl.fs.getCwd(allocator);
    defer allocator.free(cwd);
    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        return;
    };
    defer allocator.free(git_path);

    // Parse arguments
    var reset_mode: enum { soft, mixed, hard, merge_mode } = .mixed; // default is mixed
    var target_ref: ?[]const u8 = null;
    var reset_paths = std.array_list.Managed([]const u8).init(allocator);
    defer reset_paths.deinit();
    var seen_separator = false;

    while (args.next()) |arg| {
        if (seen_separator) {
            try reset_paths.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_separator = true;
        } else if (std.mem.eql(u8, arg, "--soft")) {
            reset_mode = .soft;
        } else if (std.mem.eql(u8, arg, "--mixed")) {
            reset_mode = .mixed;
        } else if (std.mem.eql(u8, arg, "--hard")) {
            reset_mode = .hard;
        } else if (std.mem.eql(u8, arg, "--merge") or std.mem.eql(u8, arg, "--keep")) {
            reset_mode = .merge_mode;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            // Accepted
        } else if (std.mem.eql(u8, arg, "-N") or std.mem.eql(u8, arg, "--no-refresh")) {
            // Accepted
        } else if (std.mem.startsWith(u8, arg, "-") and arg.len > 1) {
            // Strip leading dashes for error message
            var opt_name = arg;
            while (opt_name.len > 0 and opt_name[0] == '-') opt_name = opt_name[1..];
            const msg = try std.fmt.allocPrint(allocator, "error: unknown option `{s}'\n", .{opt_name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            return;
        } else if (target_ref == null and reset_paths.items.len == 0) {
            target_ref = arg;
        } else {
            try reset_paths.append(arg);
        }
    }

    // Check if we have a worktree (bare repos and inside .git without GIT_WORK_TREE have none)
    const has_worktree = blk: {
        if (std.posix.getenv("GIT_WORK_TREE")) |_| break :blk true;
        // Check config for bare = true
        const config_path = std.fmt.allocPrint(allocator, "{s}/config", .{git_path}) catch break :blk true;
        defer allocator.free(config_path);
        if (std.fs.cwd().readFileAlloc(allocator, config_path, 1024 * 1024)) |config_content| {
            defer allocator.free(config_content);
            if (std.mem.indexOf(u8, config_content, "bare = true")) |_| break :blk false;
        } else |_| {}
        // Check if cwd IS the git dir (we're inside .git dir)
        if (std.mem.eql(u8, cwd, git_path)) break :blk false;
        // If git_path doesn't end with /.git, we might be inside a bare repo
        if (!std.mem.endsWith(u8, git_path, "/.git") and !std.mem.eql(u8, git_path, ".git")) {
            break :blk false;
        }
        break :blk true;
    };
    
    // Check config for bare flag
    const is_bare_repo = blk: {
        const bc_path = std.fmt.allocPrint(allocator, "{s}/config", .{git_path}) catch break :blk false;
        defer allocator.free(bc_path);
        if (std.fs.cwd().readFileAlloc(allocator, bc_path, 1024 * 1024)) |bc_content| {
            defer allocator.free(bc_content);
            if (std.mem.indexOf(u8, bc_content, "bare = true")) |_| break :blk true;
        } else |_| {}
        break :blk false;
    };
    
    if (!has_worktree and (reset_mode == .hard or reset_mode == .merge_mode)) {
        try platform_impl.writeStderr("fatal: this operation must be run in a work tree\n");
        std.process.exit(128);
        unreachable;
    }
    if (is_bare_repo and reset_mode == .mixed) {
        try platform_impl.writeStderr("fatal: this operation must be run in a work tree\n");
        std.process.exit(128);
        unreachable;
    }

    // Track if user explicitly gave a target
    const explicit_target = target_ref != null;
    // If no target ref specified, default to HEAD
    if (target_ref == null) {
        target_ref = "HEAD";
    }

    // Resolve the target commit - use resolveRevision for full expression support
    const target_hash_or_null: ?[]const u8 = resolveRevision(git_path, target_ref.?, platform_impl, allocator) catch blk: {
        // If the target_ref was explicitly provided and doesn't resolve, check if it's a path
        if (explicit_target) {
            // Check if it's a file/path that exists — treat as path reset
            const repo_root = std.fs.path.dirname(git_path) orelse ".";
            const check_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, target_ref.? }) catch break :blk null;
            defer allocator.free(check_path);
            std.fs.cwd().access(check_path, .{}) catch {
                // Not a file either — error
                const msg = std.fmt.allocPrint(allocator, "fatal: ambiguous argument '{s}': unknown revision or path not in the working tree.\n", .{target_ref.?}) catch unreachable;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            };
            // It's a path, add to reset_paths and treat as unborn reset
            try reset_paths.append(target_ref.?);
            break :blk null;
        }
        // On an unborn branch, HEAD doesn't resolve - only OK when user didn't explicitly pass target
        if (!explicit_target and std.mem.eql(u8, target_ref.?, "HEAD")) {
            // Check if we're on an unborn branch
            const head_path = std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path}) catch {
                break :blk null;
            };
            defer allocator.free(head_path);
            const head_content = std.fs.cwd().readFileAlloc(allocator, head_path, 4096) catch break :blk null;
            defer allocator.free(head_content);
            const trimmed = std.mem.trimRight(u8, head_content, "\r\n");
            if (std.mem.startsWith(u8, trimmed, "ref: ")) {
                const ref_name = trimmed[5..];
                const ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, ref_name }) catch break :blk null;
                defer allocator.free(ref_path);
                // If the ref doesn't exist, we're on an unborn branch
                std.fs.cwd().access(ref_path, .{}) catch {
                    // Unborn branch - reset clears the index
                    break :blk null;
                };
            }
        }
        const msg = try std.fmt.allocPrint(allocator, "fatal: ambiguous argument '{s}': unknown revision or path not in the working tree.\n", .{target_ref.?});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
        unreachable;
    };
    defer if (target_hash_or_null) |th| allocator.free(th);

    if (target_hash_or_null) |target_hash| {
        // Update HEAD to point to the target commit
        try updateHead(git_path, target_hash, platform_impl, allocator);

        // Handle different reset modes  
        switch (reset_mode) {
            .soft => {
                // Only update HEAD, leave index and working tree unchanged
            },
            .mixed => {
                // Update HEAD and index, leave working tree unchanged
                resetIndex(git_path, target_hash, platform_impl, allocator) catch {};
            },
            .hard, .merge_mode => {
                // Update HEAD, index, and working tree to match target commit
                resetIndex(git_path, target_hash, platform_impl, allocator) catch {};
                checkoutCommitTree(git_path, target_hash, allocator, platform_impl) catch {};
            },
        }
        // Clean up merge/cherry-pick/revert state on hard/merge reset
        if (reset_mode == .hard or reset_mode == .merge_mode) {
            cleanupMergeState(git_path, allocator);
        }
        // Output "HEAD is now at <short-hash> <subject>" for hard reset
        if (reset_mode == .hard or reset_mode == .merge_mode) {
            const short_hash = if (target_hash.len >= 7) target_hash[0..7] else target_hash;
            const subj = getCommitSubject(target_hash, git_path, platform_impl, allocator) catch "";
            defer if (subj.len > 0) allocator.free(subj);
            const reset_msg = std.fmt.allocPrint(allocator, "HEAD is now at {s} {s}\n", .{ short_hash, subj }) catch "";
            if (reset_msg.len > 0) {
                defer allocator.free(reset_msg);
                platform_impl.writeStdout(reset_msg) catch {};
            }
        }
    } else {
        // Unborn branch: reset clears the index (and working tree for --hard)
        const index_path = std.fmt.allocPrint(allocator, "{s}/index", .{git_path}) catch return;
        defer allocator.free(index_path);

        if (reset_paths.items.len > 0) {
            // Reset specific paths: remove them from the index
            removePathsFromIndex(allocator, index_path, reset_paths.items) catch {};
        } else {
            switch (reset_mode) {
                .soft => {
                    // No-op on unborn branch
                },
                .mixed => {
                    // Write an empty index (not delete — git writes empty index)
                    writeEmptyIndex(allocator, index_path) catch {};
                },
                .hard, .merge_mode => {
                    // Clear the index and remove tracked files
                    const repo_root = std.fs.path.dirname(git_path) orelse ".";
                    removeTrackedFiles(allocator, index_path, repo_root) catch {};
                    writeEmptyIndex(allocator, index_path) catch {};
                },
            }
        }
    }
}

/// Reset the index to match the tree of the given commit
fn getCommitSubject(hash: []const u8, git_path: []const u8, platform_impl: anytype, allocator: std.mem.Allocator) ![]const u8 {
    const obj = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch return "";
    defer obj.deinit(allocator);
    var lines = std.mem.splitSequence(u8, obj.data, "\n");
    var past_header = false;
    while (lines.next()) |line| {
        if (past_header) return allocator.dupe(u8, line) catch "";
        if (line.len == 0) past_header = true;
    }
    return "";
}

fn writeEmptyIndex(allocator: std.mem.Allocator, index_path: []const u8) !void {
    var output = std.array_list.Managed(u8).init(allocator);
    defer output.deinit();
    try output.appendSlice("DIRC");
    try output.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 2))); // version 2
    try output.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 0))); // 0 entries
    var hasher = std.crypto.hash.Sha1.init(.{});
    hasher.update(output.items);
    const checksum = hasher.finalResult();
    try output.appendSlice(&checksum);
    try std.fs.cwd().writeFile(.{ .sub_path = index_path, .data = output.items });
}

fn removePathsFromIndex(allocator: std.mem.Allocator, index_path: []const u8, paths: []const []const u8) !void {
    // Read the index, remove entries matching paths, write it back
    const idx_data = std.fs.cwd().readFileAlloc(allocator, index_path, 10 * 1024 * 1024) catch return;
    defer allocator.free(idx_data);
    if (idx_data.len < 12) return;

    // Parse DIRC header
    if (!std.mem.eql(u8, idx_data[0..4], "DIRC")) return;
    const version = std.mem.readInt(u32, idx_data[4..8], .big);
    _ = version;
    const num_entries = std.mem.readInt(u32, idx_data[8..12], .big);

    // Parse entries, keeping those not in paths
    var new_entries = std.array_list.Managed(u8).init(allocator);
    defer new_entries.deinit();
    var kept_count: u32 = 0;

    var pos: usize = 12;
    var entry_idx: u32 = 0;
    while (entry_idx < num_entries and pos + 62 <= idx_data.len) : (entry_idx += 1) {
        const entry_start = pos;
        // Skip fixed fields (62 bytes minimum)
        pos += 62;
        // Read name (null-terminated, padded to 8-byte boundary)
        const name_start = pos;
        while (pos < idx_data.len and idx_data[pos] != 0) pos += 1;
        const name = idx_data[name_start..pos];
        // Skip to next 8-byte boundary
        pos += 1; // null terminator
        const entry_len = pos - entry_start;
        const padded_len = (entry_len + 7) & ~@as(usize, 7);
        pos = entry_start + padded_len;

        // Check if this path should be removed
        var should_remove = false;
        for (paths) |p| {
            if (std.mem.eql(u8, name, p)) {
                should_remove = true;
                break;
            }
        }
        if (!should_remove) {
            try new_entries.appendSlice(idx_data[entry_start..pos]);
            kept_count += 1;
        }
    }

    // Write new index
    var output = std.array_list.Managed(u8).init(allocator);
    defer output.deinit();
    try output.appendSlice("DIRC");
    try output.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 2)));
    try output.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, kept_count)));
    try output.appendSlice(new_entries.items);

    // Compute and append SHA-1 checksum
    var hasher = std.crypto.hash.Sha1.init(.{});
    hasher.update(output.items);
    const checksum = hasher.finalResult();
    try output.appendSlice(&checksum);

    std.fs.cwd().writeFile(.{ .sub_path = index_path, .data = output.items }) catch {};
}

fn removeTrackedFiles(allocator: std.mem.Allocator, index_path: []const u8, repo_root: []const u8) !void {
    // Parse index, delete tracked files from working tree
    const idx_data = std.fs.cwd().readFileAlloc(allocator, index_path, 10 * 1024 * 1024) catch return;
    defer allocator.free(idx_data);
    if (idx_data.len < 12 or !std.mem.eql(u8, idx_data[0..4], "DIRC")) return;
    const num_entries = std.mem.readInt(u32, idx_data[8..12], .big);

    var pos: usize = 12;
    var entry_idx: u32 = 0;
    while (entry_idx < num_entries and pos + 62 <= idx_data.len) : (entry_idx += 1) {
        const entry_start = pos;
        pos += 62;
        const name_start = pos;
        while (pos < idx_data.len and idx_data[pos] != 0) pos += 1;
        const name = idx_data[name_start..pos];
        pos += 1;
        const entry_len = pos - entry_start;
        const padded_len = (entry_len + 7) & ~@as(usize, 7);
        pos = entry_start + padded_len;

        // Delete the file
        const full_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, name }) catch continue;
        defer allocator.free(full_path);
        std.fs.cwd().deleteFile(full_path) catch {};
    }
}

fn resetIndex(git_path: []const u8, commit_hash: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Load commit to get tree hash
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch return error.InvalidCommitObject;
    defer commit_obj.deinit(allocator);

    var tree_hash: ?[]const u8 = null;
    var lines = std.mem.splitSequence(u8, commit_obj.data, "\n");
    while (lines.next()) |line| {
        if (std.mem.startsWith(u8, line, "tree ")) {
            tree_hash = line[5..];
            break;
        }
    }

    if (tree_hash == null) return error.InvalidCommitObject;

    // Use read-tree to reset the index
    // Build index entries from the tree
    var entries = std.array_list.Managed(index_mod.IndexEntry).init(allocator);
    defer {
        for (entries.items) |*entry| {
            allocator.free(entry.path);
        }
        entries.deinit();
    }

    try collectTreeEntries(git_path, tree_hash.?, "", platform_impl, allocator, &entries);

    // Create and write index
    var idx = index_mod.Index.init(allocator);
    defer idx.deinit();
    for (entries.items) |entry| {
        try idx.entries.append(.{
            .mode = entry.mode,
            .path = try allocator.dupe(u8, entry.path),
            .sha1 = entry.sha1,
            .flags = entry.flags,
            .extended_flags = null,
            .ctime_sec = 0,
            .ctime_nsec = 0,
            .mtime_sec = 0,
            .mtime_nsec = 0,
            .dev = 0,
            .ino = 0,
            .uid = 0,
            .gid = 0,
            .size = 0,
        });
    }
    try idx.save(git_path, platform_impl);
}

/// Recursively collect all blob entries from a tree
fn collectTreeEntries(git_path: []const u8, tree_hash: []const u8, prefix: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, entries: *std.array_list.Managed(index_mod.IndexEntry)) !void {
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);

    if (tree_obj.type != .tree) return;

    // Parse binary tree format: mode SP name NUL hash(20 bytes)
    var i: usize = 0;
    while (i < tree_obj.data.len) {
        // Find space (end of mode)
        const space_pos = std.mem.indexOfScalar(u8, tree_obj.data[i..], ' ') orelse break;
        const mode_str = tree_obj.data[i .. i + space_pos];

        // Find NUL (end of name)
        const name_start = i + space_pos + 1;
        const nul_pos = std.mem.indexOfScalar(u8, tree_obj.data[name_start..], 0) orelse break;
        const name = tree_obj.data[name_start .. name_start + nul_pos];

        // Read 20-byte hash
        const hash_start = name_start + nul_pos + 1;
        if (hash_start + 20 > tree_obj.data.len) break;
        const hash_bytes = tree_obj.data[hash_start .. hash_start + 20];

        // Convert hash to hex
        var hash_hex: [40]u8 = undefined;
        for (hash_bytes, 0..) |b, j| {
            const hex_chars = "0123456789abcdef";
            hash_hex[j * 2] = hex_chars[b >> 4];
            hash_hex[j * 2 + 1] = hex_chars[b & 0xf];
        }

        // Build full path
        const full_path = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);

        // Parse mode
        const mode = std.fmt.parseInt(u32, mode_str, 8) catch 0o100644;

        if (std.mem.eql(u8, mode_str, "40000") or mode_str.len >= 5 and mode_str[0] == '4') {
            // Directory - recurse
            defer allocator.free(full_path);
            try collectTreeEntries(git_path, &hash_hex, full_path, platform_impl, allocator, entries);
        } else {
            // File entry
            var hash_arr: [20]u8 = undefined;
            @memcpy(&hash_arr, hash_bytes);
            try entries.append(.{
                .mode = mode,
                .path = full_path, // ownership transferred
                .sha1 = hash_arr,
                .flags = @intCast(@min(full_path.len, 0xFFF)),
                .extended_flags = null,
                .ctime_sec = 0,
                .ctime_nsec = 0,
                .mtime_sec = 0,
                .mtime_nsec = 0,
                .dev = 0,
                .ino = 0,
                .uid = 0,
                .gid = 0,
                .size = 0,
            });
        }

        i = hash_start + 20;
    }
}

fn pathspecMatch(pattern: []const u8, path: []const u8) bool {
    // Handle simple cases
    if (std.mem.eql(u8, pattern, ".")) return true;
    if (std.mem.eql(u8, pattern, "*")) return std.mem.indexOf(u8, path, "/") == null; // match top-level only
    if (std.mem.eql(u8, pattern, path)) return true;

    // Strip trailing slash from pattern for directory matching
    const has_trailing_slash = pattern.len > 0 and pattern[pattern.len - 1] == '/';
    const pat = if (has_trailing_slash) pattern[0 .. pattern.len - 1] else pattern;

    // If pattern has trailing slash, only match as directory prefix (not exact file)
    if (!has_trailing_slash and std.mem.eql(u8, pat, path)) return true;

    // Prefix/directory match: pattern "dir" or "dir/" matches "dir/file"
    if (pat.len > 0 and std.mem.startsWith(u8, path, pat) and path.len > pat.len and path[pat.len] == '/') return true;

    // Simple glob matching with * and ?
    if (!has_trailing_slash) return pathspecGlobMatch(pattern, path);
    return false;
}

fn pathspecGlobMatch(pattern: []const u8, str: []const u8) bool {
    var pi: usize = 0;
    var si: usize = 0;
    var star_pi: ?usize = null;
    var star_si: usize = 0;

    while (si < str.len) {
        if (pi < pattern.len and (pattern[pi] == str[si] or pattern[pi] == '?')) {
            pi += 1;
            si += 1;
        } else if (pi < pattern.len and pattern[pi] == '*') {
            star_pi = pi;
            star_si = si;
            pi += 1;
        } else if (star_pi) |sp| {
            pi = sp + 1;
            star_si += 1;
            si = star_si;
        } else {
            return false;
        }
    }
    while (pi < pattern.len and pattern[pi] == '*') pi += 1;
    return pi == pattern.len;
}

fn cmdRm(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("rm: not supported in freestanding mode\n");
        return;
    }

    // Find git directory
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        return;
    };
    defer allocator.free(git_path);

    // Parse arguments
    var force = false;
    var cached = false;
    var recursive = false;
    var quiet = false;
    var ignore_unmatch = false;
    var saw_dashdash = false;
    var files = std.array_list.Managed([]const u8).init(allocator);
    defer files.deinit();

    while (args.next()) |arg| {
        if (saw_dashdash) {
            try files.append(arg);
            continue;
        }
        if (std.mem.eql(u8, arg, "--")) {
            saw_dashdash = true;
        } else if (std.mem.eql(u8, arg, "--force")) {
            force = true;
        } else if (std.mem.eql(u8, arg, "--cached")) {
            cached = true;
        } else if (std.mem.eql(u8, arg, "--recursive")) {
            recursive = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--ignore-unmatch")) {
            ignore_unmatch = true;
        } else if (std.mem.startsWith(u8, arg, "-") and !std.mem.eql(u8, arg, "--") and arg.len > 1 and arg[1] != '-') {
            // Handle combined short flags like -rf, -fr, etc.
            for (arg[1..]) |ch| {
                switch (ch) {
                    'f' => force = true,
                    'r' => recursive = true,
                    'q' => quiet = true,
                    else => {
                        const msg = try std.fmt.allocPrint(allocator, "fatal: unknown option '{s}'\n", .{arg});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(128);
                    },
                }
            }
        } else {
            try files.append(arg);
        }
    }

    if (files.items.len == 0) {
        try platform_impl.writeStderr("usage: git rm [-f | --force] [-n] [-r] [--cached] [--ignore-unmatch] [--quiet] [--pathspec-from-file=<file> [--pathspec-file-nul]] [--] [<pathspec>...]\n");
        std.process.exit(128);
        return;
    }

    // Load the index
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.IndexNotFound => {
            try platform_impl.writeStderr("fatal: index file not found\n");
            std.process.exit(128);
            return;
        },
        else => return err,
    };
    defer index.deinit();

    // Collect indices to remove (reverse order to preserve indices)
    var to_remove = std.array_list.Managed(usize).init(allocator);
    defer to_remove.deinit();
    var removed_paths = std.array_list.Managed([]const u8).init(allocator);
    defer removed_paths.deinit();

    for (files.items) |file_path| {
        var found = false;
        for (index.entries.items, 0..) |entry, i| {
            if (pathspecMatch(file_path, entry.path)) {
                // Check if non-recursive and path is in subdirectory
                if (!recursive and !std.mem.eql(u8, file_path, entry.path) and std.mem.indexOf(u8, entry.path, "/") != null) {
                    // Only skip if the pathspec is a directory prefix match and -r not set
                    if (std.mem.startsWith(u8, entry.path, file_path)) {
                        if (!force) {
                            const msg = try std.fmt.allocPrint(allocator, "fatal: not removing '{s}' recursively without -r\n", .{file_path});
                            defer allocator.free(msg);
                            try platform_impl.writeStderr(msg);
                            std.process.exit(128);
                        }
                        continue;
                    }
                }
                found = true;
                try to_remove.append(i);
                try removed_paths.append(entry.path);
            }
        }

        if (!found) {
            if (ignore_unmatch) continue;
            const msg = try std.fmt.allocPrint(allocator, "fatal: pathspec '{s}' did not match any files\n", .{file_path});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            return;
        }
    }

    // Sort removal indices in reverse order to preserve earlier indices
    std.mem.sort(usize, to_remove.items, {}, struct {
        fn cmp(_: void, a: usize, b: usize) bool {
            return a > b; // reverse order
        }
    }.cmp);

    // Remove duplicates and perform removal
    var last_removed: ?usize = null;
    for (to_remove.items) |idx| {
        if (last_removed != null and last_removed.? == idx) continue;
        last_removed = idx;
        _ = index.entries.orderedRemove(idx);
    }

    // Output removed files and remove from working tree
    for (removed_paths.items) |path| {
        if (!quiet) {
            const msg = try std.fmt.allocPrint(allocator, "rm '{s}'\n", .{path});
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }

        if (!cached) {
            const full_path = try std.fmt.allocPrint(allocator, "{s}/../{s}", .{git_path, path});
            defer allocator.free(full_path);

            platform_impl.fs.deleteFile(full_path) catch |err| switch (err) {
                error.FileNotFound => {},
                else => {
                    if (!force) {
                        const msg = try std.fmt.allocPrint(allocator, "fatal: could not remove '{s}': {}\n", .{path, err});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(128);
                    }
                },
            };
        }
    }

    // Write the updated index back
    try index.save(git_path, platform_impl);
}

fn updateHead(git_path: []const u8, target_hash: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Read current HEAD to see if it's a symbolic ref or direct hash
    const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
    defer allocator.free(head_path);

    const head_content = platform_impl.fs.readFile(allocator, head_path) catch {
        try platform_impl.writeStderr("fatal: could not read HEAD\n");
        std.process.exit(128);
        return;
    };
    defer allocator.free(head_content);

    if (std.mem.startsWith(u8, head_content, "ref: ")) {
        // HEAD is a symbolic reference, update the referenced branch
        const ref_path = std.mem.trim(u8, head_content[5..], " \t\n\r");
        const full_ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_path, ref_path });
        defer allocator.free(full_ref_path);

        // Write the new hash to the branch ref
        const hash_with_newline = try std.fmt.allocPrint(allocator, "{s}\n", .{target_hash});
        defer allocator.free(hash_with_newline);

        try platform_impl.fs.writeFile(full_ref_path, hash_with_newline);
    } else {
        // HEAD is a direct hash, update it directly
        const hash_with_newline = try std.fmt.allocPrint(allocator, "{s}\n", .{target_hash});
        defer allocator.free(hash_with_newline);

        try platform_impl.fs.writeFile(head_path, hash_with_newline);
    }
}

// Forward a command to real git, using all original args (preserving global flags like -C, -c)

fn cmdHashObject(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var write_object = false;
    var stdin_mode = false;
    var stdin_paths = false;
    var obj_type: []const u8 = "blob";
    var files = std.array_list.Managed([]const u8).init(allocator);
    defer files.deinit();
    var literally = false;
    var path_opt: ?[]const u8 = null;
    var stdin_count: u32 = 0;

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-w")) {
            write_object = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
            stdin_count += 1;
        } else if (std.mem.eql(u8, arg, "--stdin-paths")) {
            stdin_paths = true;
        } else if (std.mem.eql(u8, arg, "--literally")) {
            literally = true;
        } else if (std.mem.eql(u8, arg, "--path")) {
            path_opt = args.next();
        } else if (std.mem.startsWith(u8, arg, "--path=")) {
            path_opt = arg["--path=".len..];
        } else if (std.mem.eql(u8, arg, "-t")) {
            obj_type = args.next() orelse {
                try platform_impl.writeStderr("fatal: option '-t' requires a value\n");
                std.process.exit(128);
                unreachable;
            };
        } else if (std.mem.startsWith(u8, arg, "-t")) {
            obj_type = arg[2..];
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try files.append(arg);
        }
    }

    // Validate mutually exclusive options
    if (stdin_count > 1) {
        try platform_impl.writeStderr("fatal: --stdin given twice\n");
        std.process.exit(128);
    }
    if (stdin_mode and stdin_paths) {
        try platform_impl.writeStderr("fatal: --stdin and --stdin-paths are mutually exclusive\n");
        std.process.exit(128);
    }
    if (stdin_paths and files.items.len > 0) {
        try platform_impl.writeStderr("fatal: Can't use --stdin-paths with file arguments\n");
        std.process.exit(128);
    }
    if (path_opt != null and stdin_paths) {
        try platform_impl.writeStderr("fatal: Can't use --path with --stdin-paths\n");
        std.process.exit(128);
    }

    const git_dir = if (write_object) (findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    }) else null;
    defer if (git_dir) |gd| allocator.free(gd);

    if (stdin_paths) {
        // Read file paths from stdin, one per line
        const stdin_data = readStdin(allocator, 10 * 1024 * 1024) catch {
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(stdin_data);
        var lines = std.mem.splitScalar(u8, stdin_data, '\n');
        while (lines.next()) |line| {
            const trimmed = std.mem.trimRight(u8, line, "\r");
            if (trimmed.len == 0) continue;
            try hashOneFile(allocator, trimmed, obj_type, write_object, literally, git_dir, platform_impl);
        }
    } else if (stdin_mode) {
        // Read data from stdin first
        const data = readStdin(allocator, 100 * 1024 * 1024) catch {
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(data);
        try hashData(allocator, data, obj_type, write_object, literally, git_dir, platform_impl);
        // Then process any file arguments
        for (files.items) |file_path| {
            try hashOneFile(allocator, file_path, obj_type, write_object, literally, git_dir, platform_impl);
        }
    } else if (files.items.len > 0) {
        for (files.items) |file_path| {
            try hashOneFile(allocator, file_path, obj_type, write_object, literally, git_dir, platform_impl);
        }
    } else {
        try platform_impl.writeStderr("usage: git hash-object [-t <type>] [-w] [--stdin | --stdin-paths | <file>...]\n");
        std.process.exit(128);
    }
}

fn hashOneFile(allocator: std.mem.Allocator, file_path: []const u8, obj_type: []const u8, write_object: bool, literally: bool, git_dir: ?[]const u8, platform_impl: *const platform_mod.Platform) !void {
    const data = std.fs.cwd().readFileAlloc(allocator, file_path, 100 * 1024 * 1024) catch {
        const msg = try std.fmt.allocPrint(allocator, "fatal: Cannot open '{s}': No such file or directory\n", .{file_path});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(data);
    try hashData(allocator, data, obj_type, write_object, literally, git_dir, platform_impl);
}

fn validateTreeObject(data: []const u8, platform_impl: *const platform_mod.Platform) !void {
    // A tree entry is: mode SP name NUL sha1(20 bytes)
    // Minimum valid entry: "100644 x\0" + 20 bytes = 30 bytes
    if (data.len > 0 and data.len < 24) {
        try platform_impl.writeStderr("error: too-short tree object\n");
        return error.InvalidTree;
    }

    var pos: usize = 0;
    var last_name: ?[]const u8 = null;
    while (pos < data.len) {
        // Parse mode
        const mode_start = pos;
        while (pos < data.len and data[pos] != ' ') : (pos += 1) {}
        if (pos >= data.len) {
            try platform_impl.writeStderr("error: too-short tree object\n");
            return error.InvalidTree;
        }
        const mode_str = data[mode_start..pos];
        // Validate mode: must be valid octal and a known git mode
        const valid_modes = [_][]const u8{ "40000", "100644", "100755", "120000", "160000", "100664" };
        var mode_valid = false;
        for (valid_modes) |vm| {
            if (std.mem.eql(u8, mode_str, vm)) {
                mode_valid = true;
                break;
            }
        }
        if (!mode_valid) {
            try platform_impl.writeStderr("error: malformed mode in tree entry\n");
            return error.InvalidTree;
        }
        pos += 1; // skip space

        // Parse name (until NUL)
        const name_start = pos;
        while (pos < data.len and data[pos] != 0) : (pos += 1) {}
        if (pos >= data.len) {
            try platform_impl.writeStderr("error: too-short tree object\n");
            return error.InvalidTree;
        }
        const name = data[name_start..pos];
        if (name.len == 0) {
            try platform_impl.writeStderr("error: empty filename in tree entry\n");
            return error.InvalidTree;
        }

        // Check for duplicate filenames
        if (last_name) |ln| {
            if (std.mem.eql(u8, ln, name)) {
                try platform_impl.writeStderr("error: duplicate filename in tree\n");
                return error.InvalidTree;
            }
        }
        last_name = name;

        pos += 1; // skip NUL

        // Read 20-byte SHA1
        if (pos + 20 > data.len) {
            try platform_impl.writeStderr("error: too-short tree object\n");
            return error.InvalidTree;
        }
        // Check for null SHA1
        var all_zero = true;
        for (data[pos .. pos + 20]) |b| {
            if (b != 0) {
                all_zero = false;
                break;
            }
        }
        if (all_zero) {
            try platform_impl.writeStderr("error: empty filename in tree entry\n");
            return error.InvalidTree;
        }
        pos += 20;
    }
}

fn hashData(allocator: std.mem.Allocator, data: []const u8, obj_type: []const u8, write_object: bool, literally: bool, git_dir: ?[]const u8, platform_impl: *const platform_mod.Platform) !void {
    const parsed_type = objects.ObjectType.fromString(obj_type) orelse {
        const msg = try std.fmt.allocPrint(allocator, "fatal: invalid object type \"{s}\"\n", .{obj_type});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
        unreachable;
    };
    // Validate object format unless --literally is set
    if (!literally) {
        switch (parsed_type) {
            .tree => {
                // Validate tree object format
                validateTreeObject(data, platform_impl) catch {
                    std.process.exit(128);
                    unreachable;
                };
            },
            .commit => {
                // Minimal commit validation: must have "tree " line
                if (!std.mem.startsWith(u8, data, "tree ")) {
                    platform_impl.writeStderr("fatal: corrupt commit\n") catch {};
                    std.process.exit(128);
                    unreachable;
                }
            },
            .tag => {
                // Minimal tag validation: must have "object " line
                if (!std.mem.startsWith(u8, data, "object ")) {
                    platform_impl.writeStderr("fatal: corrupt tag\n") catch {};
                    std.process.exit(128);
                    unreachable;
                }
            },
            else => {},
        }
    }

    const obj = objects.GitObject.init(parsed_type, data);
    const hash = try obj.hash(allocator);
    defer allocator.free(hash);

    if (write_object) {
        if (git_dir) |gd| {
            _ = obj.store(gd, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: unable to write object\n");
                std.process.exit(128);
                unreachable;
            };
        }
    }

    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
    defer allocator.free(output);
    try platform_impl.writeStdout(output);
}

fn cmdWriteTree(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var prefix: ?[]const u8 = null;
    var missing_ok = false;
    while (args.next()) |arg| {
        if (std.mem.startsWith(u8, arg, "--prefix=")) {
            prefix = arg["--prefix=".len..];
        } else if (std.mem.eql(u8, arg, "--prefix")) {
            prefix = args.next();
        } else if (std.mem.eql(u8, arg, "--missing-ok")) {
            missing_ok = true;
        }
    }
    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    // Load the index
    var idx = index_mod.Index.load(git_dir, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: unable to read index\n");
        std.process.exit(128);
        unreachable;
    };
    defer idx.deinit();

    // Unless --missing-ok, validate that all objects referenced in the index exist
    if (!missing_ok) {
        for (idx.entries.items) |entry| {
            // Skip entries not under prefix
            if (prefix) |pfx| {
                if (!std.mem.startsWith(u8, entry.path, pfx)) continue;
            }
            var hash_hex: [40]u8 = undefined;
            for (entry.sha1, 0..) |byte, j| {
                const hex = std.fmt.bytesToHex([1]u8{byte}, .lower);
                hash_hex[j * 2] = hex[0];
                hash_hex[j * 2 + 1] = hex[1];
            }
            // Check if object exists (loose or packed)
            const obj_exists = objectExistsCheck(git_dir, &hash_hex, platform_impl, allocator);
            if (!obj_exists) {
                const msg = try std.fmt.allocPrint(allocator, "error: invalid object {o:0>6} {s} for '{s}'\nfatal: git-write-tree: error building trees\n", .{ entry.mode, &hash_hex, entry.path });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }
        }
    }

    // Build tree from index entries, optionally scoped to prefix
    // Ensure prefix has trailing slash
    const write_prefix = if (prefix) |pfx|
        (if (pfx.len > 0 and pfx[pfx.len - 1] != '/')
            try std.fmt.allocPrint(allocator, "{s}/", .{pfx})
        else
            try allocator.dupe(u8, pfx))
    else
        try allocator.dupe(u8, "");
    defer allocator.free(write_prefix);
    const tree_hash = writeTreeRecursive(allocator, &idx, write_prefix, git_dir, platform_impl) catch {
        try platform_impl.writeStderr("fatal: unable to write tree\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(tree_hash);

    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{tree_hash});
    defer allocator.free(output);
    try platform_impl.writeStdout(output);
}

fn writeTreeFromIndex(allocator: std.mem.Allocator, idx: *index_mod.Index, git_dir: []const u8, platform_impl: *const platform_mod.Platform) ![]u8 {
    return writeTreeRecursive(allocator, idx, "", git_dir, platform_impl);
}

fn writeTreeRecursive(allocator: std.mem.Allocator, idx: *index_mod.Index, prefix: []const u8, git_dir: []const u8, platform_impl: *const platform_mod.Platform) ![]u8 {
    // Collect entries at this level
    var entries = std.array_list.Managed(objects.TreeEntry).init(allocator);
    defer {
        for (entries.items) |*e| e.deinit(allocator);
        entries.deinit();
    }

    // Track subdirectories we've already processed
    var seen_dirs = std.StringHashMap(void).init(allocator);
    defer {
        var it = seen_dirs.iterator();
        while (it.next()) |entry| allocator.free(entry.key_ptr.*);
        seen_dirs.deinit();
    }

    for (idx.entries.items) |entry| {
        const path = entry.path;
        
        // Skip entries not under our prefix
        if (prefix.len > 0) {
            if (!std.mem.startsWith(u8, path, prefix)) continue;
        }
        
        const relative = if (prefix.len > 0) path[prefix.len..] else path;
        
        // Check if this is a direct child or in a subdirectory
        if (std.mem.indexOfScalar(u8, relative, '/')) |slash_pos| {
            // Subdirectory - process it recursively
            const dir_name = relative[0..slash_pos];
            const dir_key = try allocator.dupe(u8, dir_name);
            
            if (seen_dirs.contains(dir_key)) {
                allocator.free(dir_key);
                continue;
            }
            try seen_dirs.put(dir_key, {});
            
            const sub_prefix = try std.fmt.allocPrint(allocator, "{s}{s}/", .{ prefix, dir_name });
            defer allocator.free(sub_prefix);
            
            const sub_tree_hash = try writeTreeRecursive(allocator, idx, sub_prefix, git_dir, platform_impl);
            defer allocator.free(sub_tree_hash);
            
            try entries.append(objects.TreeEntry.init(
                try allocator.dupe(u8, "40000"),
                try allocator.dupe(u8, dir_name),
                try allocator.dupe(u8, sub_tree_hash),
            ));
        } else {
            // Direct child - add as a blob entry
            var hash_hex: [40]u8 = undefined;
            for (entry.sha1, 0..) |byte, j| {
                const hex = std.fmt.bytesToHex([1]u8{byte}, .lower);
                hash_hex[j * 2] = hex[0];
                hash_hex[j * 2 + 1] = hex[1];
            }
            
            const mode_str = try std.fmt.allocPrint(allocator, "{o}", .{entry.mode});
            
            try entries.append(objects.TreeEntry.init(
                mode_str,
                try allocator.dupe(u8, relative),
                try allocator.dupe(u8, &hash_hex),
            ));
        }
    }

    // Sort entries (git sorts trees specially - directories sort as if they had a trailing /)
    std.mem.sort(objects.TreeEntry, entries.items, {}, struct {
        fn lessThan(_: void, a: objects.TreeEntry, b: objects.TreeEntry) bool {
            const a_name = if (std.mem.eql(u8, a.mode, "40000"))
                std.fmt.allocPrint(std.heap.page_allocator, "{s}/", .{a.name}) catch a.name
            else
                a.name;
            const b_name = if (std.mem.eql(u8, b.mode, "40000"))
                std.fmt.allocPrint(std.heap.page_allocator, "{s}/", .{b.name}) catch b.name
            else
                b.name;
            return std.mem.lessThan(u8, a_name, b_name);
        }
    }.lessThan);

    // Create the tree object
    const tree_obj = try objects.createTreeObject(entries.items, allocator);
    defer tree_obj.deinit(allocator);

    const hash = try tree_obj.store(git_dir, platform_impl, allocator);
    return hash;
}

fn cmdCommitTree(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var tree_hash: ?[]const u8 = null;
    var parents = std.array_list.Managed([]const u8).init(allocator);
    defer parents.deinit();
    var message: ?[]const u8 = null;
    var read_stdin = true;
    var gpg_sign: ?[]const u8 = null;

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-p")) {
            if (args.next()) |parent| {
                // Resolve parent to full hash
                const git_dir = findGitDirectory(allocator, platform_impl) catch {
                    try platform_impl.writeStderr("fatal: not a git repository\n");
                    std.process.exit(128);
                    unreachable;
                };
                defer allocator.free(git_dir);
                const resolved = resolveCommittish(git_dir, parent, platform_impl, allocator) catch {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name {s}\n", .{parent});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                };
                try parents.append(resolved);
            }
        } else if (std.mem.eql(u8, arg, "-m")) {
            message = args.next();
            read_stdin = false;
        } else if (std.mem.eql(u8, arg, "-F")) {
            if (args.next()) |file_path| {
                if (std.mem.eql(u8, file_path, "-")) {
                    // Read from stdin
                    read_stdin = true;
                } else {
                    message = std.fs.cwd().readFileAlloc(allocator, file_path, 10 * 1024 * 1024) catch null;
                    read_stdin = false;
                }
            }
        } else if (std.mem.startsWith(u8, arg, "-S") or std.mem.startsWith(u8, arg, "--gpg-sign")) {
            gpg_sign = arg;
        } else if (std.mem.eql(u8, arg, "--no-gpg-sign")) {
            gpg_sign = null;
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (tree_hash == null) tree_hash = arg;
        }
    }

    if (tree_hash == null) {
        try platform_impl.writeStderr("fatal: must specify a tree object\n");
        std.process.exit(128);
        unreachable;
    }

    // Deduplicate parent hashes (git silently removes duplicates)
    {
        var unique = std.array_list.Managed([]const u8).init(allocator);
        for (parents.items) |p| {
            var dup = false;
            for (unique.items) |u| {
                if (std.mem.eql(u8, p, u)) {
                    dup = true;
                    break;
                }
            }
            if (!dup) {
                try unique.append(p);
            }
        }
        parents.deinit();
        parents = unique;
    }

    var final_message: []const u8 = undefined;
    var free_message = false;
    if (read_stdin and message == null) {
        final_message = readStdin(allocator, 10 * 1024 * 1024) catch {
            try platform_impl.writeStderr("fatal: unable to read commit message\n");
            std.process.exit(128);
            unreachable;
        };
        free_message = true;
    } else {
        final_message = message orelse "";
    }
    defer if (free_message) allocator.free(final_message);

    // Get author/committer from env or config
    const author = getAuthorString(allocator) catch {
        try platform_impl.writeStderr("fatal: unable to auto-detect author\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(author);
    const committer = getCommitterString(allocator) catch {
        try platform_impl.writeStderr("fatal: unable to auto-detect committer\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(committer);

    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    // Resolve tree hash
    const resolved_tree = resolveCommittish(git_dir, tree_hash.?, platform_impl, allocator) catch {
        const msg = try std.fmt.allocPrint(allocator, "fatal: not a valid object name {s}\n", .{tree_hash.?});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(resolved_tree);

    const commit_obj = try objects.createCommitObject(
        resolved_tree,
        parents.items,
        author,
        committer,
        final_message,
        allocator,
    );
    defer commit_obj.deinit(allocator);

    const hash = commit_obj.store(git_dir, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: unable to write commit object\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(hash);

    const output = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
    defer allocator.free(output);
    try platform_impl.writeStdout(output);

    // Free parent hashes
    for (parents.items) |p| allocator.free(p);
}

/// Parse a date string into git's internal "epoch timezone" format.
fn parseDateToGitFormat(date_str: []const u8, allocator: std.mem.Allocator) ![]u8 {
    const trimmed = std.mem.trim(u8, date_str, " \t\n\r");
    if (trimmed.len == 0) {
        const now = std.time.timestamp();
        return try std.fmt.allocPrint(allocator, "{d} +0000", .{now});
    }

    // Handle @epoch format
    if (trimmed[0] == '@') {
        const rest = std.mem.trim(u8, trimmed[1..], " ");
        if (std.mem.indexOfScalar(u8, rest, ' ')) |sp| {
            const epoch_str = rest[0..sp];
            const tz_s = std.mem.trim(u8, rest[sp + 1 ..], " ");
            const epoch = std.fmt.parseInt(i64, epoch_str, 10) catch {
                return try allocator.dupe(u8, trimmed);
            };
            return try std.fmt.allocPrint(allocator, "{d} {s}", .{ epoch, tz_s });
        } else {
            const epoch = std.fmt.parseInt(i64, rest, 10) catch {
                return try allocator.dupe(u8, trimmed);
            };
            return try std.fmt.allocPrint(allocator, "{d} +0000", .{epoch});
        }
    }

    // Check if already "epoch +/-tz" format
    if (trimmed.len > 0 and (trimmed[0] >= '0' and trimmed[0] <= '9')) {
        if (std.mem.indexOfScalar(u8, trimmed, ' ')) |sp| {
            const maybe_epoch = trimmed[0..sp];
            const rest = std.mem.trim(u8, trimmed[sp + 1 ..], " ");
            if (std.fmt.parseInt(i64, maybe_epoch, 10)) |epoch| {
                if (rest.len >= 5 and (rest[0] == '+' or rest[0] == '-')) {
                    return try std.fmt.allocPrint(allocator, "{d} {s}", .{ epoch, rest });
                }
            } else |_| {}
        } else {
            if (std.fmt.parseInt(i64, trimmed, 10)) |epoch| {
                return try std.fmt.allocPrint(allocator, "{d} +0000", .{epoch});
            } else |_| {}
        }
    }

    // Try ISO-like date parsing
    var date_part: []const u8 = trimmed;
    var explicit_tz: ?[]const u8 = null;

    // Check for trailing timezone
    if (trimmed.len > 6) {
        const last6 = trimmed[trimmed.len - 6 ..];
        if (last6[0] == ' ' and (last6[1] == '+' or last6[1] == '-')) {
            if (std.fmt.parseInt(i32, last6[2..6], 10)) |_| {
                explicit_tz = last6[1..];
                date_part = std.mem.trim(u8, trimmed[0 .. trimmed.len - 6], " ");
            } else |_| {}
        }
    }

    // Replace 'T' with space
    var dbuf: [64]u8 = undefined;
    var dlen: usize = 0;
    for (date_part) |c| {
        if (dlen >= dbuf.len) break;
        dbuf[dlen] = if (c == 'T') ' ' else c;
        dlen += 1;
    }
    const normalized = dbuf[0..dlen];

    // Parse YYYY-MM-DD HH:MM:SS or YYYY-MM-DD HH:MM or YYYY-MM-DD
    if (normalized.len >= 10 and normalized[4] == '-' and normalized[7] == '-') {
        const year = std.fmt.parseInt(i32, normalized[0..4], 10) catch return try allocator.dupe(u8, trimmed);
        const month = std.fmt.parseInt(u32, normalized[5..7], 10) catch return try allocator.dupe(u8, trimmed);
        const day = std.fmt.parseInt(u32, normalized[8..10], 10) catch return try allocator.dupe(u8, trimmed);

        var hour: u32 = 0;
        var minute: u32 = 0;
        var second: u32 = 0;

        if (normalized.len >= 16 and normalized[10] == ' ' and normalized[13] == ':') {
            hour = std.fmt.parseInt(u32, normalized[11..13], 10) catch 0;
            minute = std.fmt.parseInt(u32, normalized[14..16], 10) catch 0;
            if (normalized.len >= 19 and normalized[16] == ':') {
                second = std.fmt.parseInt(u32, normalized[17..19], 10) catch 0;
            }
        }

        const epoch = dateToEpoch(year, month, day, hour, minute, second);

        if (explicit_tz) |tz| {
            const tz_sign: i64 = if (tz[0] == '-') @as(i64, 1) else @as(i64, -1);
            const tz_hours = std.fmt.parseInt(i64, tz[1..3], 10) catch 0;
            const tz_minutes = std.fmt.parseInt(i64, tz[3..5], 10) catch 0;
            const tz_offset_secs = tz_sign * (tz_hours * 3600 + tz_minutes * 60);
            return try std.fmt.allocPrint(allocator, "{d} {s}", .{ epoch + tz_offset_secs, tz });
        }

        // Check TZ env var
        const tz_env = std.posix.getenv("TZ");
        if (tz_env != null and (std.mem.eql(u8, tz_env.?, "GMT") or std.mem.eql(u8, tz_env.?, "UTC") or std.mem.eql(u8, tz_env.?, "UTC0"))) {
            return try std.fmt.allocPrint(allocator, "{d} +0000", .{epoch});
        }

        return try std.fmt.allocPrint(allocator, "{d} +0000", .{epoch});
    }

    return try allocator.dupe(u8, trimmed);
}

fn dateToEpoch(year: i32, month: u32, day: u32, hour: u32, minute: u32, second: u32) i64 {
    const days_in_months = [_]u32{ 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31 };
    var total_days: i64 = 0;
    var y: i32 = 1970;
    while (y < year) : (y += 1) {
        total_days += if (isLeapYear(y)) @as(i64, 366) else @as(i64, 365);
    }
    while (y > year) {
        y -= 1;
        total_days -= if (isLeapYear(y)) @as(i64, 366) else @as(i64, 365);
    }
    var m: u32 = 1;
    while (m < month) : (m += 1) {
        total_days += days_in_months[m - 1];
        if (m == 2 and isLeapYear(year)) total_days += 1;
    }
    total_days += @as(i64, day) - 1;
    return total_days * 86400 + @as(i64, hour) * 3600 + @as(i64, minute) * 60 + @as(i64, second);
}

fn isLeapYear(year: i32) bool {
    if (@mod(year, 400) == 0) return true;
    if (@mod(year, 100) == 0) return false;
    if (@mod(year, 4) == 0) return true;
    return false;
}

fn getAuthorString(allocator: std.mem.Allocator) ![]u8 {
    const name = std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_NAME") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => try allocator.dupe(u8, "Test User"),
        else => return err,
    };
    defer allocator.free(name);
    const email = std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_EMAIL") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => try allocator.dupe(u8, "test@example.com"),
        else => return err,
    };
    defer allocator.free(email);
    const raw_date = std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_DATE") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => blk: {
            const now = std.time.timestamp();
            break :blk try std.fmt.allocPrint(allocator, "{d} +0000", .{now});
        },
        else => return err,
    };
    defer allocator.free(raw_date);
    const date = try parseDateToGitFormat(raw_date, allocator);
    defer allocator.free(date);

    return try std.fmt.allocPrint(allocator, "{s} <{s}> {s}", .{ name, email, date });
}

fn getCommitterString(allocator: std.mem.Allocator) ![]u8 {
    const name = std.process.getEnvVarOwned(allocator, "GIT_COMMITTER_NAME") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_NAME") catch try allocator.dupe(u8, "Test User"),
        else => return err,
    };
    defer allocator.free(name);
    const email = std.process.getEnvVarOwned(allocator, "GIT_COMMITTER_EMAIL") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_EMAIL") catch try allocator.dupe(u8, "test@example.com"),
        else => return err,
    };
    defer allocator.free(email);
    const raw_date = std.process.getEnvVarOwned(allocator, "GIT_COMMITTER_DATE") catch |err| switch (err) {
        error.EnvironmentVariableNotFound => blk: {
            const now = std.time.timestamp();
            break :blk try std.fmt.allocPrint(allocator, "{d} +0000", .{now});
        },
        else => return err,
    };
    defer allocator.free(raw_date);
    const date = try parseDateToGitFormat(raw_date, allocator);
    defer allocator.free(date);

    return try std.fmt.allocPrint(allocator, "{s} <{s}> {s}", .{ name, email, date });
}

fn simpleRegexMatch(text: []const u8, pattern: []const u8) bool {
    var anchored_start = false;
    var anchored_end = false;
    var ep = pattern;
    if (ep.len > 0 and ep[0] == '^') { anchored_start = true; ep = ep[1..]; }
    if (ep.len > 0 and ep[ep.len - 1] == '$' and (ep.len < 2 or ep[ep.len - 2] != '\\')) {
        anchored_end = true;
        ep = ep[0 .. ep.len - 1];
    }
    const end_pos: usize = if (anchored_start) 1 else text.len + 1;
    var ti: usize = 0;
    while (ti < end_pos) : (ti += 1) {
        if (simpleRegexMatchAt(text, ti, ep, 0)) |match_end| {
            if (anchored_end and match_end != text.len) continue;
            return true;
        }
    }
    return false;
}

fn simpleRegexMatchAt(text: []const u8, tpos: usize, pat: []const u8, ppos: usize) ?usize {
    var tp = tpos;
    var pp = ppos;
    while (pp < pat.len) {
        if (pat[pp] == '[') {
            const close = std.mem.indexOfPos(u8, pat, pp + 1, "]") orelse return null;
            const class = pat[pp + 1 .. close];
            const next_pp = close + 1;
            const cq: u8 = if (next_pp < pat.len and (pat[next_pp] == '*' or pat[next_pp] == '+' or pat[next_pp] == '?')) pat[next_pp] else 0;
            if (cq == '*' or cq == '?') {
                if (simpleRegexMatchAt(text, tp, pat, next_pp + 1)) |end| return end;
            }
            if (cq == '*' or cq == '+') {
                var tp2 = tp;
                while (tp2 < text.len and matchCharClass(text[tp2], class)) tp2 += 1;
                while (tp2 >= tp) {
                    if (simpleRegexMatchAt(text, tp2, pat, next_pp + 1)) |end| return end;
                    if (tp2 == tp) break;
                    tp2 -= 1;
                }
                return null;
            }
            if (cq == '?') {
                if (tp < text.len and matchCharClass(text[tp], class)) {
                    if (simpleRegexMatchAt(text, tp + 1, pat, next_pp + 1)) |end| return end;
                }
                return simpleRegexMatchAt(text, tp, pat, next_pp + 1);
            }
            if (tp >= text.len) return null;
            if (!matchCharClass(text[tp], class)) return null;
            tp += 1; pp = next_pp; continue;
        }
        if (pat[pp] == '\\' and pp + 1 < pat.len) {
            if (tp >= text.len or text[tp] != pat[pp + 1]) return null;
            tp += 1; pp += 2; continue;
        }
        const has_quant = pp + 1 < pat.len and (pat[pp + 1] == '*' or pat[pp + 1] == '+' or pat[pp + 1] == '?');
        if (pat[pp] == '.' and !has_quant) {
            if (tp >= text.len) return null;
            tp += 1; pp += 1; continue;
        }
        if (pat[pp] == '.' and has_quant) {
            const quant = pat[pp + 1];
            if (quant == '*') {
                var tp2 = text.len;
                while (tp2 >= tp) {
                    if (simpleRegexMatchAt(text, tp2, pat, pp + 2)) |end| return end;
                    if (tp2 == 0) break;
                    tp2 -= 1;
                }
                return null;
            }
            if (quant == '+') {
                if (tp >= text.len) return null;
                var tp2 = text.len;
                while (tp2 > tp) {
                    if (simpleRegexMatchAt(text, tp2, pat, pp + 2)) |end| return end;
                    tp2 -= 1;
                }
                return null;
            }
            if (quant == '?') {
                if (tp < text.len) {
                    if (simpleRegexMatchAt(text, tp + 1, pat, pp + 2)) |end| return end;
                }
                return simpleRegexMatchAt(text, tp, pat, pp + 2);
            }
        }
        if (has_quant) {
            const lit = pat[pp];
            const quant = pat[pp + 1];
            if (quant == '*') {
                var tp2 = tp;
                while (tp2 < text.len and text[tp2] == lit) tp2 += 1;
                while (tp2 >= tp) {
                    if (simpleRegexMatchAt(text, tp2, pat, pp + 2)) |end| return end;
                    if (tp2 == tp) break;
                    tp2 -= 1;
                }
                return null;
            }
            if (quant == '+') {
                if (tp >= text.len or text[tp] != lit) return null;
                var tp2 = tp;
                while (tp2 < text.len and text[tp2] == lit) tp2 += 1;
                while (tp2 > tp) {
                    if (simpleRegexMatchAt(text, tp2, pat, pp + 2)) |end| return end;
                    tp2 -= 1;
                }
                return null;
            }
            if (quant == '?') {
                if (tp < text.len and text[tp] == lit) {
                    if (simpleRegexMatchAt(text, tp + 1, pat, pp + 2)) |end| return end;
                }
                return simpleRegexMatchAt(text, tp, pat, pp + 2);
            }
        }
        if (tp >= text.len or text[tp] != pat[pp]) return null;
        tp += 1; pp += 1;
    }
    return tp;
}

fn matchCharClass(c: u8, class: []const u8) bool {
    var negated = false;
    var idx: usize = 0;
    if (idx < class.len and class[idx] == '^') { negated = true; idx += 1; }
    var matched = false;
    while (idx < class.len) {
        if (idx + 2 < class.len and class[idx + 1] == '-') {
            if (c >= class[idx] and c <= class[idx + 2]) matched = true;
            idx += 3;
        } else {
            if (c == class[idx]) matched = true;
            idx += 1;
        }
    }
    return if (negated) !matched else matched;
}

fn simpleGlobMatch(pattern: []const u8, text: []const u8) bool {
    // Simple glob matching supporting * and ?
    var pi: usize = 0;
    var ti: usize = 0;
    var star_pi: ?usize = null;
    var star_ti: usize = 0;
    
    while (ti < text.len) {
        if (pi < pattern.len and (pattern[pi] == text[ti] or pattern[pi] == '?')) {
            pi += 1;
            ti += 1;
        } else if (pi < pattern.len and pattern[pi] == '*') {
            star_pi = pi;
            star_ti = ti;
            pi += 1;
        } else if (star_pi) |sp| {
            pi = sp + 1;
            star_ti += 1;
            ti = star_ti;
        } else {
            return false;
        }
    }
    while (pi < pattern.len and pattern[pi] == '*') pi += 1;
    return pi == pattern.len;
}

fn cleanEmptyRefDirs(git_dir: []const u8, ref_name: []const u8, allocator: std.mem.Allocator) void {
    // After deleting a ref like refs/heads/foo/bar, clean up empty parent dirs
    var path = ref_name;
    while (std.fs.path.dirname(path)) |parent| {
        if (std.mem.eql(u8, parent, "refs") or parent.len == 0) break;
        const full = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, parent }) catch break;
        defer allocator.free(full);
        std.fs.cwd().deleteDir(full) catch break;
        path = parent;
    }
}

fn cmdUpdateRef(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var delete_mode = false;
    var no_deref = false;
    var create_reflog = false;
    var stdin_mode = false;
    var msg: ?[]const u8 = null;
    var positional = std.array_list.Managed([]const u8).init(allocator);
    defer positional.deinit();

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-d")) {
            delete_mode = true;
        } else if (std.mem.eql(u8, arg, "--no-deref")) {
            no_deref = true;
        } else if (std.mem.eql(u8, arg, "--create-reflog")) {
            create_reflog = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
        } else if (std.mem.eql(u8, arg, "-m")) {
            msg = args.next();
        } else if (std.mem.eql(u8, arg, "--")) {
            // rest are positional
            while (args.next()) |rest| try positional.append(rest);
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try positional.append(arg);
        }
    }

    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    if (stdin_mode) {
        try updateRefStdin(git_dir, create_reflog, no_deref, allocator, platform_impl);
        return;
    }

    if (delete_mode) {
        if (positional.items.len < 1) {
            try platform_impl.writeStderr("usage: git update-ref -d <refname> [<old-val>]\n");
            std.process.exit(128);
            unreachable;
        }
        const ref_name = positional.items[0];
        // If old-value was specified, verify it matches current value
        if (positional.items.len >= 2) {
            const old_val = positional.items[1];
            if (old_val.len > 0) {
                const current = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
                defer if (current) |c| allocator.free(c);
                if (current) |cur| {
                    if (!std.mem.eql(u8, cur, old_val)) {
                        const err_msg = try std.fmt.allocPrint(allocator, "error: cannot lock ref '{s}': is at {s} but expected {s}\n", .{ ref_name, cur, old_val });
                        defer allocator.free(err_msg);
                        try platform_impl.writeStderr(err_msg);
                        std.process.exit(1);
                        unreachable;
                    }
                }
            }
        }
        
        // Delete loose ref file
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name });
        defer allocator.free(ref_path);
        std.fs.cwd().deleteFile(ref_path) catch |err| {
            if (err != error.FileNotFound) {
                const err_msg = try std.fmt.allocPrint(allocator, "fatal: cannot delete ref '{s}': {}\n", .{ ref_name, err });
                defer allocator.free(err_msg);
                try platform_impl.writeStderr(err_msg);
                std.process.exit(1);
                unreachable;
            }
        };
        // (loose ref deletion handled above)
        
        // Also remove from packed-refs if present
        const packed_refs_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir});
        defer allocator.free(packed_refs_path);
        if (platform_impl.fs.readFile(allocator, packed_refs_path)) |packed_data| {
            defer allocator.free(packed_data);
            var new_packed = std.array_list.Managed(u8).init(allocator);
            defer new_packed.deinit();
            var lines_iter = std.mem.splitScalar(u8, packed_data, '\n');
            while (lines_iter.next()) |line| {
                if (line.len == 0) continue;
                if (line[0] == '#') {
                    try new_packed.appendSlice(line);
                    try new_packed.append('\n');
                    continue;
                }
                if (line[0] == '^') {
                    // Peeled ref - skip if previous ref was deleted
                    continue;
                }
                // Check if this line references our ref
                if (line.len > 41) {
                    const line_ref = std.mem.trimRight(u8, line[41..], " \t\r");
                    if (std.mem.eql(u8, line_ref, ref_name)) {
                        continue; // skip this ref
                    }
                }
                try new_packed.appendSlice(line);
                try new_packed.append('\n');
            }
            platform_impl.fs.writeFile(packed_refs_path, new_packed.items) catch {};
        } else |_| {}
        
        // Try to clean up empty parent dirs
        cleanEmptyRefDirs(git_dir, ref_name, allocator);
        return;
    }

    if (positional.items.len < 2) {
        try platform_impl.writeStderr("usage: git update-ref [-d] [-m <reason>] <refname> <new-value> [<old-value>]\n");
        std.process.exit(128);
        unreachable;
    }

    const ref_name = positional.items[0];
    const new_value = positional.items[1];

    // Resolve new_value to a full hash
    var resolved_new: []const u8 = undefined;
    var free_resolved = false;
    if (new_value.len == 40 and isValidHashPrefix(new_value)) {
        resolved_new = new_value;
    } else {
        resolved_new = resolveCommittish(git_dir, new_value, platform_impl, allocator) catch {
            const err_msg = try std.fmt.allocPrint(allocator, "fatal: {s}: not a valid SHA1\n", .{new_value});
            defer allocator.free(err_msg);
            try platform_impl.writeStderr(err_msg);
            std.process.exit(128);
            unreachable;
        };
        free_resolved = true;
    }
    defer if (free_resolved) allocator.free(resolved_new);

    // Old value verification
    if (positional.items.len >= 3) {
        const old_val = positional.items[2];
        if (old_val.len > 0 and !std.mem.eql(u8, old_val, "0000000000000000000000000000000000000000")) {
            const current = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
            defer if (current) |c| allocator.free(c);
            if (current) |cur| {
                if (!std.mem.eql(u8, cur, old_val)) {
                    const err_msg2 = try std.fmt.allocPrint(allocator, "error: cannot lock ref '{s}': is at {s} but expected {s}\n", .{ ref_name, cur, old_val });
                    defer allocator.free(err_msg2);
                    try platform_impl.writeStderr(err_msg2);
                    std.process.exit(1);
                    unreachable;
                }
            } else {
                // Ref doesn't exist but old value was specified
                const err_msg2 = try std.fmt.allocPrint(allocator, "error: cannot lock ref '{s}': unable to resolve reference '{s}'\n", .{ ref_name, ref_name });
                defer allocator.free(err_msg2);
                try platform_impl.writeStderr(err_msg2);
                std.process.exit(1);
                unreachable;
            }
        }
    }

    // Get old value for reflog
    const old_hash = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
    defer if (old_hash) |h| allocator.free(h);

    // Write the ref
    try refs.updateRef(git_dir, ref_name, resolved_new, platform_impl, allocator);
    
    // Create reflog dir and write entry if needed
    if (create_reflog or shouldLogRef(git_dir, ref_name, platform_impl, allocator)) {
        writeReflogEntry(git_dir, ref_name, old_hash orelse "0000000000000000000000000000000000000000", resolved_new, msg orelse "", allocator, platform_impl) catch {};
    }

}

fn updateRefStdin(git_dir: []const u8, create_reflog: bool, no_deref: bool, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    _ = no_deref;
    const stdin_data = readStdin(allocator, 10 * 1024 * 1024) catch {
        try platform_impl.writeStderr("fatal: unable to read from stdin\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(stdin_data);
    
    const zero_hash = "0000000000000000000000000000000000000000";
    
    var lines = std.mem.splitScalar(u8, stdin_data, '\n');
    while (lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        if (trimmed.len == 0) continue;
        
        if (std.mem.startsWith(u8, trimmed, "update ")) {
            // update <ref> <new-oid> [<old-oid>]
            const rest = trimmed["update ".len..];
            var parts = std.mem.splitScalar(u8, rest, ' ');
            const ref_name = parts.next() orelse continue;
            const new_val_raw = parts.next() orelse continue;
            const old_val = parts.next();
            
            // Resolve new value
            const new_val = if (new_val_raw.len == 40 and isValidHexString(new_val_raw))
                try allocator.dupe(u8, new_val_raw)
            else
                resolveRevision(git_dir, new_val_raw, platform_impl, allocator) catch {
                    const emsg = try std.fmt.allocPrint(allocator, "fatal: {s}: not a valid SHA1\n", .{ref_name});
                    defer allocator.free(emsg);
                    try platform_impl.writeStderr(emsg);
                    std.process.exit(128);
                    unreachable;
                };
            defer allocator.free(new_val);
            
            // Verify old value if specified
            if (old_val) |ov| {
                if (ov.len > 0) {
                    const resolved_old = if (ov.len == 40 and isValidHexString(ov))
                        try allocator.dupe(u8, ov)
                    else
                        resolveRevision(git_dir, ov, platform_impl, allocator) catch {
                            const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}': unable to resolve reference\n", .{ref_name});
                            defer allocator.free(emsg);
                            try platform_impl.writeStderr(emsg);
                            std.process.exit(128);
                            unreachable;
                        };
                    defer allocator.free(resolved_old);
                    
                    const current = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
                    defer if (current) |c| allocator.free(c);
                    
                    if (std.mem.eql(u8, resolved_old, zero_hash)) {
                        // old=0 means ref must not exist
                        if (current != null) {
                            const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}': reference already exists\n", .{ref_name});
                            defer allocator.free(emsg);
                            try platform_impl.writeStderr(emsg);
                            std.process.exit(128);
                            unreachable;
                        }
                    } else {
                        if (current == null or !std.mem.eql(u8, current.?, resolved_old)) {
                            const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}': is at {s} but expected {s}\n", .{ ref_name, current orelse zero_hash, resolved_old });
                            defer allocator.free(emsg);
                            try platform_impl.writeStderr(emsg);
                            std.process.exit(128);
                            unreachable;
                        }
                    }
                }
            }
            
            const old_hash = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
            defer if (old_hash) |h| allocator.free(h);
            
            try refs.updateRef(git_dir, ref_name, new_val, platform_impl, allocator);
            
            if (create_reflog or shouldLogRef(git_dir, ref_name, platform_impl, allocator)) {
                writeReflogEntry(git_dir, ref_name, old_hash orelse zero_hash, new_val, "", allocator, platform_impl) catch {};
            }
        } else if (std.mem.startsWith(u8, trimmed, "create ")) {
            // create <ref> <new-oid>
            const rest = trimmed["create ".len..];
            var parts = std.mem.splitScalar(u8, rest, ' ');
            const ref_name = parts.next() orelse continue;
            const new_val_raw = parts.next() orelse continue;
            
            // Ref must not exist
            if (refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null) |existing| {
                allocator.free(existing);
                const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}': reference already exists\n", .{ref_name});
                defer allocator.free(emsg);
                try platform_impl.writeStderr(emsg);
                std.process.exit(128);
                unreachable;
            }
            
            const new_val = if (new_val_raw.len == 40 and isValidHexString(new_val_raw))
                try allocator.dupe(u8, new_val_raw)
            else
                resolveRevision(git_dir, new_val_raw, platform_impl, allocator) catch {
                    const emsg = try std.fmt.allocPrint(allocator, "fatal: {s}: not a valid SHA1\n", .{ref_name});
                    defer allocator.free(emsg);
                    try platform_impl.writeStderr(emsg);
                    std.process.exit(128);
                    unreachable;
                };
            defer allocator.free(new_val);
            
            try refs.updateRef(git_dir, ref_name, new_val, platform_impl, allocator);
            
            if (create_reflog or shouldLogRef(git_dir, ref_name, platform_impl, allocator)) {
                writeReflogEntry(git_dir, ref_name, zero_hash, new_val, "", allocator, platform_impl) catch {};
            }
        } else if (std.mem.startsWith(u8, trimmed, "delete ")) {
            // delete <ref> [<old-oid>]
            const rest = trimmed["delete ".len..];
            var parts = std.mem.splitScalar(u8, rest, ' ');
            const ref_name = parts.next() orelse continue;
            const old_val = parts.next();
            
            // Verify old value if specified
            if (old_val) |ov| {
                if (ov.len > 0 and !std.mem.eql(u8, ov, zero_hash)) {
                    const current = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
                    defer if (current) |c| allocator.free(c);
                    
                    const resolved_old = if (ov.len == 40 and isValidHexString(ov))
                        try allocator.dupe(u8, ov)
                    else
                        resolveRevision(git_dir, ov, platform_impl, allocator) catch {
                            try platform_impl.writeStderr("fatal: cannot resolve old value\n");
                            std.process.exit(128);
                            unreachable;
                        };
                    defer allocator.free(resolved_old);
                    
                    if (current == null or !std.mem.eql(u8, current.?, resolved_old)) {
                        const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}'\n", .{ref_name});
                        defer allocator.free(emsg);
                        try platform_impl.writeStderr(emsg);
                        std.process.exit(128);
                        unreachable;
                    }
                }
            }
            
            // Delete the ref
            const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name });
            defer allocator.free(ref_path);
            std.fs.cwd().deleteFile(ref_path) catch {};
            
            // Remove from packed-refs too
            removeFromPackedRefs(git_dir, ref_name, allocator, platform_impl);
            cleanEmptyRefDirs(git_dir, ref_name, allocator);
        } else if (std.mem.startsWith(u8, trimmed, "verify ")) {
            // verify <ref> [<old-oid>]
            const rest = trimmed["verify ".len..];
            var parts = std.mem.splitScalar(u8, rest, ' ');
            const ref_name = parts.next() orelse continue;
            const expected = parts.next();
            
            const current = refs.resolveRef(git_dir, ref_name, platform_impl, allocator) catch null;
            defer if (current) |c| allocator.free(c);
            
            if (expected) |exp| {
                if (std.mem.eql(u8, exp, zero_hash)) {
                    if (current != null) {
                        const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}': reference exists\n", .{ref_name});
                        defer allocator.free(emsg);
                        try platform_impl.writeStderr(emsg);
                        std.process.exit(128);
                        unreachable;
                    }
                } else {
                    if (current == null or !std.mem.eql(u8, current.?, exp)) {
                        const emsg = try std.fmt.allocPrint(allocator, "fatal: cannot lock ref '{s}': is at {s} but expected {s}\n", .{ ref_name, current orelse zero_hash, exp });
                        defer allocator.free(emsg);
                        try platform_impl.writeStderr(emsg);
                        std.process.exit(128);
                        unreachable;
                    }
                }
            }
        }
    }
}

fn removeFromPackedRefs(git_dir: []const u8, ref_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) void {
    const packed_refs_path = std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir}) catch return;
    defer allocator.free(packed_refs_path);
    const packed_data = platform_impl.fs.readFile(allocator, packed_refs_path) catch return;
    defer allocator.free(packed_data);
    var new_packed = std.array_list.Managed(u8).init(allocator);
    defer new_packed.deinit();
    var lines_iter = std.mem.splitScalar(u8, packed_data, '\n');
    var skip_peel = false;
    while (lines_iter.next()) |pline| {
        if (pline.len == 0) continue;
        if (pline[0] == '#') {
            new_packed.appendSlice(pline) catch {};
            new_packed.append('\n') catch {};
            continue;
        }
        if (pline[0] == '^') {
            if (!skip_peel) {
                new_packed.appendSlice(pline) catch {};
                new_packed.append('\n') catch {};
            }
            skip_peel = false;
            continue;
        }
        skip_peel = false;
        if (pline.len > 41) {
            const line_ref = std.mem.trimRight(u8, pline[41..], " \t\r");
            if (std.mem.eql(u8, line_ref, ref_name)) {
                skip_peel = true;
                continue;
            }
        }
        new_packed.appendSlice(pline) catch {};
        new_packed.append('\n') catch {};
    }
    platform_impl.fs.writeFile(packed_refs_path, new_packed.items) catch {};
}

fn shouldLogRef(git_dir: []const u8, ref_name: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) bool {
    // Check core.logAllRefUpdates config
    const config_path = std.fmt.allocPrint(allocator, "{s}/config", .{git_dir}) catch return false;
    defer allocator.free(config_path);
    const config_data = platform_impl.fs.readFile(allocator, config_path) catch return false;
    defer allocator.free(config_data);
    
    if (parseConfigValue(config_data, "core.logallrefupdates", allocator) catch null) |val| {
        defer allocator.free(val);
        if (std.ascii.eqlIgnoreCase(val, "always")) return true;
        if (std.ascii.eqlIgnoreCase(val, "true")) {
            // Only log refs/heads/* and HEAD
            return std.mem.startsWith(u8, ref_name, "refs/heads/") or std.mem.eql(u8, ref_name, "HEAD");
        }
    }
    return false;
}

fn writeReflogEntry(git_dir: []const u8, ref_name: []const u8, old_hash: []const u8, new_hash: []const u8, msg_str: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !void {
    const reflog_path = try std.fmt.allocPrint(allocator, "{s}/logs/{s}", .{ git_dir, ref_name });
    defer allocator.free(reflog_path);
    
    // Create parent directories
    if (std.fs.path.dirname(reflog_path)) |parent| {
        std.fs.cwd().makePath(parent) catch {};
    }
    
    // Get committer info
    const name = std.process.getEnvVarOwned(allocator, "GIT_COMMITTER_NAME") catch try allocator.dupe(u8, "C O Mitter");
    defer allocator.free(name);
    const email = std.process.getEnvVarOwned(allocator, "GIT_COMMITTER_EMAIL") catch try allocator.dupe(u8, "committer@example.com");
    defer allocator.free(email);
    
    var timestamp: i64 = undefined;
    var tz_str: []const u8 = "+0000";
    var tz_needs_free = false;
    if (std.process.getEnvVarOwned(allocator, "GIT_COMMITTER_DATE") catch null) |date_str| {
        defer allocator.free(date_str);
        // Parse date using shared parser
        if (parseDateToGitFormat(date_str, allocator)) |parsed| {
            defer allocator.free(parsed);
            if (std.mem.indexOf(u8, parsed, " ")) |sp| {
                timestamp = std.fmt.parseInt(i64, parsed[0..sp], 10) catch std.time.timestamp();
                tz_str = allocator.dupe(u8, parsed[sp + 1 ..]) catch "+0000";
                tz_needs_free = true;
            } else {
                timestamp = std.fmt.parseInt(i64, parsed, 10) catch std.time.timestamp();
            }
        } else |_| {
            timestamp = std.time.timestamp();
        }
    } else {
        timestamp = std.time.timestamp();
    }
    defer if (tz_needs_free) allocator.free(tz_str);
    
    const entry = try std.fmt.allocPrint(allocator, "{s} {s} {s} <{s}> {d} {s}\t{s}\n", .{ old_hash, new_hash, name, email, timestamp, tz_str, msg_str });
    defer allocator.free(entry);
    
    // Append to reflog file
    const file = std.fs.cwd().openFile(reflog_path, .{ .mode = .write_only }) catch |err| switch (err) {
        error.FileNotFound => {
            // Create new file
            platform_impl.fs.writeFile(reflog_path, entry) catch {};
            return;
        },
        else => return err,
    };
    defer file.close();
    file.seekFromEnd(0) catch {};
    file.writeAll(entry) catch {};
}

fn cmdSymbolicRef(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var quiet = false;
    var short = false;
    var delete = false;
    var positional = std.array_list.Managed([]const u8).init(allocator);
    defer positional.deinit();

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--short")) {
            short = true;
        } else if (std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "--delete")) {
            delete = true;
        } else if (std.mem.eql(u8, arg, "-m")) {
            // Skip the message argument (reflog message, we ignore for now)
            _ = args.next();
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try positional.append(arg);
        }
    }

    if (positional.items.len == 0) {
        try platform_impl.writeStderr("usage: git symbolic-ref [-m <reason>] <name> <ref>\n       git symbolic-ref [-q] [--short] <name>\n       git symbolic-ref --delete [-q] <name>\n");
        std.process.exit(1);
    }

    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    const ref_name = positional.items[0];

    if (delete) {
        // Delete the symbolic ref
        if (std.mem.eql(u8, ref_name, "HEAD")) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: Cannot delete HEAD\n", .{});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
            unreachable;
        }
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name });
        defer allocator.free(ref_path);
        // Check if it exists and is a symbolic ref
        const content = platform_impl.fs.readFile(allocator, ref_path) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: Cannot delete {s}, not a symbolic ref\n", .{ref_name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
            unreachable;
        };
        defer allocator.free(content);
        if (!std.mem.startsWith(u8, content, "ref: ")) {
            const msg = try std.fmt.allocPrint(allocator, "fatal: Cannot delete {s}, not a symbolic ref\n", .{ref_name});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
            unreachable;
        }
        std.fs.cwd().deleteFile(ref_path) catch {
            if (!quiet) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: Cannot delete {s}\n", .{ref_name});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            }
            std.process.exit(1);
            unreachable;
        };
        return;
    }

    if (positional.items.len >= 2) {
        // Write mode: symbolic-ref <name> <ref>
        const target = positional.items[1];
        
        // Validate target
        if (std.mem.eql(u8, ref_name, "HEAD")) {
            if (!std.mem.startsWith(u8, target, "refs/")) {
                try platform_impl.writeStderr("fatal: Refusing to point HEAD outside of refs/\n");
                std.process.exit(1);
                unreachable;
            }
        } else {
            // For non-HEAD, validate that target is a valid ref name
            if (false) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: Refusing to set '{s}' to invalid ref '{s}'\n", .{ ref_name, target });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
                unreachable;
            }
        }
        
        const ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name }) catch {
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(ref_path);

        const content = std.fmt.allocPrint(allocator, "ref: {s}\n", .{target}) catch {
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(content);

        // Ensure parent directories exist
        if (std.fs.path.dirname(ref_path)) |dir| {
            std.fs.cwd().makePath(dir) catch {};
        }

        const file = std.fs.cwd().createFile(ref_path, .{}) catch {
            const msg = std.fmt.allocPrint(allocator, "fatal: Cannot create {s}\n", .{ref_path}) catch "fatal: Cannot create ref\n";
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            unreachable;
        };
        defer file.close();
        file.writeAll(content) catch {
            std.process.exit(128);
            unreachable;
        };
        return;
    }

    // Read mode: symbolic-ref <name>
    const ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name }) catch {
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(ref_path);

    const content = std.fs.cwd().readFileAlloc(allocator, ref_path, 4096) catch {
        if (!quiet) {
            const msg = std.fmt.allocPrint(allocator, "fatal: ref {s} is not a symbolic ref\n", .{ref_name}) catch "fatal: not a symbolic ref\n";
            try platform_impl.writeStderr(msg);
        }
        std.process.exit(1);
        unreachable;
    };
    defer allocator.free(content);

    const trimmed = std.mem.trimRight(u8, content, "\n\r ");
    if (!std.mem.startsWith(u8, trimmed, "ref: ")) {
        if (!quiet) {
            const msg = std.fmt.allocPrint(allocator, "fatal: ref {s} is not a symbolic ref\n", .{ref_name}) catch "fatal: not a symbolic ref\n";
            try platform_impl.writeStderr(msg);
        }
        std.process.exit(1);
        unreachable;
    }

    const target = trimmed["ref: ".len..];
    var output: []const u8 = undefined;
    if (short) {
        // Strip refs/heads/ or refs/tags/ or refs/remotes/ prefix
        if (std.mem.startsWith(u8, target, "refs/heads/")) {
            output = target["refs/heads/".len..];
        } else if (std.mem.startsWith(u8, target, "refs/tags/")) {
            output = target["refs/tags/".len..];
        } else if (std.mem.startsWith(u8, target, "refs/remotes/")) {
            const rest = target["refs/remotes/".len..];
            // For refs/remotes/X/HEAD, shorten to X
            if (std.mem.endsWith(u8, rest, "/HEAD")) {
                output = rest[0 .. rest.len - "/HEAD".len];
            } else {
                output = rest;
            }
        } else if (std.mem.startsWith(u8, target, "refs/")) {
            output = target["refs/".len..];
        } else {
            output = target;
        }
    } else {
        output = target;
    }

    const out_line = std.fmt.allocPrint(allocator, "{s}\n", .{output}) catch {
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(out_line);
    try platform_impl.writeStdout(out_line);
}

fn cmdUpdateIndex(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    var idx = index_mod.Index.load(git_dir, platform_impl, allocator) catch blk: {
        break :blk index_mod.Index.init(allocator);
    };
    defer idx.deinit();

    var modified = false;
    var add_mode = false;
    var remove_mode = false;
    var force_remove = false;
    var refresh = false;
    var cache_info_mode = false;
    var assume_unchanged = false;
    var no_assume_unchanged = false;
    var skip_worktree = false;
    var no_skip_worktree = false;
    var stdin_mode = false;
    var ignore_missing = false;
    var unmerged_mode = false;
    var verbose = false;
    var info_only = false;

    var replace_mode = false;
    var again_mode = false;
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--info-only")) {
            info_only = true;
        } else if (std.mem.eql(u8, arg, "--add")) {
            add_mode = true;
        } else if (std.mem.eql(u8, arg, "--remove")) {
            remove_mode = true;
        } else if (std.mem.eql(u8, arg, "--replace")) {
            replace_mode = true;
        } else if (std.mem.eql(u8, arg, "--force-remove")) {
            force_remove = true;
        } else if (std.mem.eql(u8, arg, "--refresh")) {
            refresh = true;
        } else if (std.mem.eql(u8, arg, "--really-refresh")) {
            refresh = true;
        } else if (std.mem.eql(u8, arg, "--ignore-missing")) {
            ignore_missing = true;
        } else if (std.mem.eql(u8, arg, "--unmerged")) {
            unmerged_mode = true;
        } else if (std.mem.eql(u8, arg, "--again") or std.mem.eql(u8, arg, "-g")) {
            again_mode = true;
        } else if (std.mem.eql(u8, arg, "--ignore-submodules")) {
            // silently accept
        } else if (std.mem.eql(u8, arg, "--cacheinfo")) {
            cache_info_mode = true;
            // Format: --cacheinfo <mode>,<sha1>,<path> or --cacheinfo <mode> <sha1> <path>
            if (args.next()) |info| {
                // Check if it's comma-separated
                if (std.mem.indexOfScalar(u8, info, ',')) |_| {
                    var parts = std.mem.splitScalar(u8, info, ',');
                    const mode_str = parts.next() orelse continue;
                    const hash_str = parts.next() orelse continue;
                    const path = parts.next() orelse continue;
                    addCacheInfo(&idx, mode_str, hash_str, path, allocator) catch |err| {
                        if (err == error.DirectoryFileConflict) {
                            const emsg = try std.fmt.allocPrint(allocator, "error: '{s}' appears as both a file and as a directory\n", .{path});
                            defer allocator.free(emsg);
                            try platform_impl.writeStderr(emsg);
                            std.process.exit(128);
                        }
                        if (err == error.NullSha1) {
                            if (verbose) {
                                const vmsg = try std.fmt.allocPrint(allocator, "add '{s}'\n", .{path});
                                defer allocator.free(vmsg);
                                try platform_impl.writeStdout(vmsg);
                            }
                            const emsg2 = try std.fmt.allocPrint(allocator, "error: Invalid path '{s}': Null sha1\n", .{path});
                            defer allocator.free(emsg2);
                            try platform_impl.writeStderr(emsg2);
                            std.process.exit(128);
                        }
                        return err;
                    };
                    if (verbose) {
                        const vmsg2 = try std.fmt.allocPrint(allocator, "add '{s}'\n", .{path});
                        defer allocator.free(vmsg2);
                        try platform_impl.writeStdout(vmsg2);
                    }
                    modified = true;
                } else {
                    // Three separate args: mode sha1 path
                    const mode_str = info;
                    const hash_str = args.next() orelse continue;
                    const path = args.next() orelse continue;
                    addCacheInfo(&idx, mode_str, hash_str, path, allocator) catch |err| {
                        if (err == error.DirectoryFileConflict) {
                            const emsg = try std.fmt.allocPrint(allocator, "error: '{s}' appears as both a file and as a directory\n", .{path});
                            defer allocator.free(emsg);
                            try platform_impl.writeStderr(emsg);
                            std.process.exit(128);
                        }
                        if (err == error.NullSha1) {
                            if (verbose) {
                                const vmsg = try std.fmt.allocPrint(allocator, "add '{s}'\n", .{path});
                                defer allocator.free(vmsg);
                                try platform_impl.writeStdout(vmsg);
                            }
                            const emsg2 = try std.fmt.allocPrint(allocator, "error: Invalid path '{s}': Null sha1\n", .{path});
                            defer allocator.free(emsg2);
                            try platform_impl.writeStderr(emsg2);
                            std.process.exit(128);
                        }
                        return err;
                    };
                    if (verbose) {
                        const vmsg = try std.fmt.allocPrint(allocator, "add '{s}'\n", .{path});
                        defer allocator.free(vmsg);
                        try platform_impl.writeStdout(vmsg);
                    }
                    modified = true;
                }
            } else {
                try platform_impl.writeStderr("error: option 'cacheinfo' expects <mode>,<sha1>,<path>\n");
                std.process.exit(1);
                unreachable;
            }
        } else if (std.mem.eql(u8, arg, "--assume-unchanged")) {
            assume_unchanged = true;
        } else if (std.mem.eql(u8, arg, "--no-assume-unchanged")) {
            no_assume_unchanged = true;
        } else if (std.mem.eql(u8, arg, "--skip-worktree")) {
            skip_worktree = true;
        } else if (std.mem.eql(u8, arg, "--no-skip-worktree")) {
            no_skip_worktree = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
        } else if (std.mem.eql(u8, arg, "--index-info")) {
            // Read index info from stdin: "<mode> <type> <sha1>\t<path>" or "<mode> <sha1> <stage>\t<path>"
            const stdin_data = readStdin(allocator, 10 * 1024 * 1024) catch {
                try platform_impl.writeStderr("fatal: unable to read from stdin\n");
                std.process.exit(128);
                unreachable;
            };
            defer allocator.free(stdin_data);
            var lines = std.mem.splitScalar(u8, stdin_data, '\n');
            while (lines.next()) |line| {
                if (line.len == 0) continue;
                // Format: "<mode> <sha1> <stage>\t<path>" or "<mode> <type> <sha1>\t<path>"
                if (std.mem.indexOfScalar(u8, line, '\t')) |tab_pos| {
                    const info_part = line[0..tab_pos];
                    const path = line[tab_pos + 1 ..];
                    if (path.len == 0) continue;
                    // Parse info part - split by spaces
                    var parts = std.mem.splitScalar(u8, info_part, ' ');
                    const mode_str = parts.next() orelse continue;
                    const second = parts.next() orelse continue;
                    // Second field could be "blob"/"tree"/"commit" (type) or a sha1 hash
                    var hash_str: []const u8 = undefined;
                    if (second.len == 40) {
                        // It's a hash directly: "<mode> <sha1> <stage>\t<path>"
                        hash_str = second;
                    } else {
                        // It's a type: "<mode> <type> <sha1>\t<path>"
                        hash_str = parts.next() orelse continue;
                    }
                    addCacheInfo(&idx, mode_str, hash_str, path, allocator) catch |err| {
                        if (err == error.DirectoryFileConflict) continue;
                        if (err == error.NullSha1) continue;
                        return err;
                    };
                    modified = true;
                }
            }
        } else if (std.mem.eql(u8, arg, "-q")) {
            // quiet mode
        } else if (std.mem.eql(u8, arg, "--verbose") or std.mem.eql(u8, arg, "-v")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "--chmod=+x")) {
            // Next arg should be a path
            if (args.next()) |path| {
                try setIndexEntryMode(&idx, path, 0o100755);
                if (verbose) {
                    const vmsg = try std.fmt.allocPrint(allocator, "add '{s}'\nchmod +x '{s}'\n", .{ path, path });
                    defer allocator.free(vmsg);
                    try platform_impl.writeStdout(vmsg);
                }
                modified = true;
            }
        } else if (std.mem.eql(u8, arg, "--chmod=-x")) {
            if (args.next()) |path| {
                try setIndexEntryMode(&idx, path, 0o100644);
                if (verbose) {
                    const vmsg = try std.fmt.allocPrint(allocator, "add '{s}'\nchmod -x '{s}'\n", .{ path, path });
                    defer allocator.free(vmsg);
                    try platform_impl.writeStdout(vmsg);
                }
                modified = true;
            }
        } else if (std.mem.eql(u8, arg, "--show-index-version")) {
            // Show the current index version - version 3 if any entries have extended flags
            var has_extended = false;
            for (idx.entries.items) |*entry| {
                if (entry.flags & 0x4000 != 0) {
                    has_extended = true;
                    break;
                }
            }
            if (has_extended) {
                try platform_impl.writeStdout("3\n");
            } else {
                try platform_impl.writeStdout("2\n");
            }
            return;
        } else if (std.mem.eql(u8, arg, "--index-version")) {
            if (args.next()) |ver_str| {
                const new_ver = std.fmt.parseInt(u32, ver_str, 10) catch 2;
                const old_ver = idx.version;
                idx.version = new_ver;
                modified = true;
                if (verbose) {
                    const vmsg = try std.fmt.allocPrint(allocator, "index-version: was {d}, set to {d}\n", .{ old_ver, new_ver });
                    defer allocator.free(vmsg);
                    try platform_impl.writeStdout(vmsg);
                }
            }
        } else if (std.mem.eql(u8, arg, "--")) {
            // rest are paths
            while (args.next()) |path| {
                if (force_remove) {
                    idx.remove(path) catch {};
                    modified = true;
                } else if (add_mode) {
                    if (!replace_mode and checkDFConflict(&idx, path)) {
                        const emdf = std.fmt.allocPrint(allocator, "error: '{s}' appears as both a file and as a directory\nerror: {s}: cannot add to the index - missing --replace option?\nfatal: Unable to process path {s}\n", .{ path, path, path }) catch "error: D/F conflict\n";
                        try platform_impl.writeStderr(emdf);
                        std.process.exit(128);
                    }
                    idx.add(path, path, platform_impl, git_dir) catch {};
                    modified = true;
                } else {
                    var pfound = false;
                    for (idx.entries.items) |entry| {
                        if (std.mem.eql(u8, entry.path, path)) { pfound = true; break; }
                    }
                    if (!pfound) {
                        const enf = std.fmt.allocPrint(allocator, "error: {s}: cannot add to the index - missing --add option?\nfatal: Unable to process path {s}\n", .{ path, path }) catch "error: cannot add\n";
                        try platform_impl.writeStderr(enf);
                        std.process.exit(128);
                    }
                    std.fs.cwd().access(path, .{}) catch {
                        const ene = std.fmt.allocPrint(allocator, "error: {s}: does not exist and --remove not passed\nfatal: Unable to process path {s}\n", .{ path, path }) catch "error: file missing\n";
                        try platform_impl.writeStderr(ene);
                        std.process.exit(128);
                    };
                    idx.add(path, path, platform_impl, git_dir) catch {};
                    modified = true;
                }
            }
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            // File path
            if (assume_unchanged or no_assume_unchanged or skip_worktree or no_skip_worktree) {
                // Set flags on existing entry
                for (idx.entries.items) |*entry| {
                    if (std.mem.eql(u8, entry.path, arg)) {
                        if (assume_unchanged) entry.flags |= 0x8000; // CE_VALID
                        if (no_assume_unchanged) entry.flags &= ~@as(u16, 0x8000);
                        if (skip_worktree) {
                            // Set skip-worktree in extended flags
                            entry.flags |= 0x4000; // CE_EXTENDED
                            entry.extended_flags = (entry.extended_flags orelse 0) | 0x4000; // SKIP_WORKTREE bit
                        }
                        if (no_skip_worktree) {
                            entry.flags &= ~@as(u16, 0x4000);
                            entry.extended_flags = null;
                        }
                        modified = true;
                        break;
                    }
                }
            } else if (force_remove) {
                idx.remove(arg) catch {};
                modified = true;
            } else if (remove_mode and add_mode) {
                // Both --add and --remove: add if exists, remove if not
                if (std.fs.cwd().access(arg, .{})) |_| {
                    // File exists - add it
                    idx.add(arg, arg, platform_impl, git_dir) catch {};
                    modified = true;
                } else |_| {
                    // File doesn't exist - remove from index
                    idx.remove(arg) catch {};
                    modified = true;
                }
            } else if (remove_mode) {
                // Only remove if file doesn't exist
                std.fs.cwd().access(arg, .{}) catch {
                    idx.remove(arg) catch {};
                    modified = true;
                };
            } else if (add_mode) {
                if (replace_mode) {
                    // D/F conflict resolution:
                    // 1. If adding file "X", remove all entries "X/*" (file replaces dir)
                    const prefix_with_slash = std.fmt.allocPrint(allocator, "{s}/", .{arg}) catch arg;
                    const needs_free_pws = !std.mem.eql(u8, prefix_with_slash, arg);
                    var j: usize = 0;
                    while (j < idx.entries.items.len) {
                        if (std.mem.startsWith(u8, idx.entries.items[j].path, prefix_with_slash)) {
                            idx.entries.items[j].deinit(allocator);
                            _ = idx.entries.orderedRemove(j);
                        } else {
                            j += 1;
                        }
                    }
                    if (needs_free_pws) allocator.free(@constCast(prefix_with_slash));
                    // 2. If adding file "X/Y", remove entry "X" (dir replaces file)
                    if (std.mem.indexOfScalar(u8, arg, '/')) |slash_idx| {
                        const parent = arg[0..slash_idx];
                        for (idx.entries.items, 0..) |entry, ei| {
                            if (std.mem.eql(u8, entry.path, parent)) {
                                idx.entries.items[ei].deinit(allocator);
                                _ = idx.entries.orderedRemove(ei);
                                break;
                            }
                        }
                    }
                } else {
                    // Without --replace, check for D/F conflicts and fail
                    if (checkDFConflict(&idx, arg)) {
                        const emdf2 = std.fmt.allocPrint(allocator, "error: '{s}' appears as both a file and as a directory\nerror: {s}: cannot add to the index - missing --replace option?\nfatal: Unable to process path {s}\n", .{ arg, arg, arg }) catch "error: D/F conflict\n";
                        try platform_impl.writeStderr(emdf2);
                        std.process.exit(128);
                    }
                }
                idx.add(arg, arg, platform_impl, git_dir) catch {};
                modified = true;
            } else {
                // No --add/--remove flag: file must already be in the index
                var found_in_index = false;
                for (idx.entries.items) |entry| {
                    if (std.mem.eql(u8, entry.path, arg)) {
                        found_in_index = true;
                        break;
                    }
                }
                if (!found_in_index) {
                    const err_msg = std.fmt.allocPrint(allocator, "error: {s}: cannot add to the index - missing --add option?\nfatal: Unable to process path {s}\n", .{ arg, arg }) catch "error: cannot add to the index\n";
                    try platform_impl.writeStderr(err_msg);
                    std.process.exit(128);
                } else {
                    // File is in index — check if it still exists on disk
                    std.fs.cwd().access(arg, .{}) catch {
                        // File deleted but no --remove flag
                        const err_msg2 = std.fmt.allocPrint(allocator, "error: {s}: does not exist and --remove not passed\nfatal: Unable to process path {s}\n", .{ arg, arg }) catch "error: file does not exist\n";
                        try platform_impl.writeStderr(err_msg2);
                        std.process.exit(128);
                    };
                    // Save old mode for symlink preservation
                    var prev_mode: u32 = 0;
                    for (idx.entries.items) |entry| {
                        if (std.mem.eql(u8, entry.path, arg)) { prev_mode = entry.mode; break; }
                    }
                    // Update existing entry with current file stat
                    idx.add(arg, arg, platform_impl, git_dir) catch {};
                    // Preserve symlink mode when core.symlinks=false
                    if (prev_mode == 0o120000) {
                        const cfp2 = std.fmt.allocPrint(allocator, "{s}/config", .{git_dir}) catch null;
                        if (cfp2) |cp2| {
                            defer allocator.free(cp2);
                            if (platform_impl.fs.readFile(allocator, cp2)) |cd2| {
                                defer allocator.free(cd2);
                                if (parseConfigValue(cd2, "core.symlinks", allocator) catch null) |sv2| {
                                    defer allocator.free(sv2);
                                    if (std.mem.eql(u8, sv2, "false")) {
                                        for (idx.entries.items) |*e2| {
                                            if (std.mem.eql(u8, e2.path, arg)) { e2.mode = 0o120000; break; }
                                        }
                                    }
                                }
                            } else |_| {}
                        }
                    }
                    modified = true;
                }
            }
            // Apply verbose output for file add
            if (verbose and modified) {
                const vmsg = std.fmt.allocPrint(allocator, "add '{s}'\n", .{arg}) catch "";
                if (vmsg.len > 0) {
                    defer allocator.free(vmsg);
                    platform_impl.writeStdout(vmsg) catch {};
                }
            }
            // chmod mode handling removed - handled inline with --chmod=+x/--chmod=-x
        } else {
            // Unknown option starting with -
            if (std.mem.eql(u8, arg, "-h")) {
                try platform_impl.writeStderr("usage: git update-index [<options>] [--] [<file>...]\n");
                std.process.exit(129);
                unreachable;
            }
            const msg = try std.fmt.allocPrint(allocator, "error: unknown option '{s}'\nusage: git update-index [<options>] [--] [<file>...]\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(129);
            unreachable;
        }
    }

    if (refresh) {
        // Refresh stat info for all entries by re-statting files
        const repo_root = std.fs.path.dirname(git_dir) orelse ".";
        var refresh_failed = false;
        for (idx.entries.items) |*entry| {
            // Skip higher-stage (unmerged) entries
            const stage = (entry.flags >> 12) & 0x3;
            if (stage != 0) {
                if (!unmerged_mode) {
                    refresh_failed = true;
                    const umsg = std.fmt.allocPrint(allocator, "{s}: needs merge\n", .{entry.path}) catch continue;
                    defer allocator.free(umsg);
                    platform_impl.writeStderr(umsg) catch {};
                }
                continue;
            }
            // Skip assume-unchanged entries
            if (entry.flags & 0x8000 != 0) continue;
            // Skip submodule entries (mode 160000)
            if (entry.mode == 0o160000) continue;

            const full_path = if (repo_root.len > 0 and !std.mem.eql(u8, repo_root, "."))
                std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path }) catch continue
            else
                allocator.dupe(u8, entry.path) catch continue;
            defer allocator.free(full_path);

            // Check if file exists (use lstatFile for symlinks to avoid following them)
            var link_buf: [4096]u8 = undefined;
            const is_symlink_entry = (entry.mode & 0o170000) == 0o120000;
            const file_exists = blk: {
                if (is_symlink_entry) {
                    // For symlink entries, check if the symlink itself exists (don't follow)
                    _ = std.fs.cwd().readLink(full_path, &link_buf) catch break :blk false;
                    break :blk true;
                } else {
                    std.fs.cwd().access(full_path, .{}) catch break :blk false;
                    break :blk true;
                }
            };
            if (!file_exists) {
                if (!ignore_missing) {
                    refresh_failed = true;
                    const mmsg = std.fmt.allocPrint(allocator, "{s}: needs update\n", .{entry.path}) catch continue;
                    defer allocator.free(mmsg);
                    platform_impl.writeStderr(mmsg) catch {};
                }
                continue;
            }

            // Check if it's a symlink
            if (std.fs.cwd().readLink(full_path, &link_buf)) |link_target| {
                entry.size = @intCast(link_target.len);
                // Use fstatat with SYMLINK_NOFOLLOW for proper symlink stat
                const full_path_z = std.posix.toPosixPath(full_path) catch continue;
                const lstat = std.posix.fstatat(std.posix.AT.FDCWD, &full_path_z, std.posix.AT.SYMLINK_NOFOLLOW) catch continue;
                entry.ctime_sec = @intCast(@max(0, lstat.ctime().sec));
                entry.ctime_nsec = @intCast(@max(0, lstat.ctime().nsec));
                entry.mtime_sec = @intCast(@max(0, lstat.mtime().sec));
                entry.mtime_nsec = @intCast(@max(0, lstat.mtime().nsec));
                entry.ino = @intCast(lstat.ino);
            } else |_| {
                // Regular file - check if content changed
                if (std.fs.cwd().statFile(full_path)) |stat| {
                    const file_size: u32 = @intCast(@min(stat.size, std.math.maxInt(u32)));
                    const new_mtime_sec: u32 = @intCast(@max(0, @divTrunc(stat.mtime, std.time.ns_per_s)));
                    const new_mtime_nsec: u32 = @intCast(@max(0, @rem(stat.mtime, std.time.ns_per_s)));

                    if (entry.size != file_size or entry.mtime_sec != new_mtime_sec or entry.mtime_nsec != new_mtime_nsec) {
                        const content = platform_impl.fs.readFile(allocator, full_path) catch {
                            refresh_failed = true;
                            continue;
                        };
                        defer allocator.free(content);
                        const blob_obj = objects.createBlobObject(content, allocator) catch continue;
                        defer blob_obj.deinit(allocator);
                        const new_hash_str = blob_obj.hash(allocator) catch continue;
                        defer allocator.free(new_hash_str);
                        var new_hash: [20]u8 = undefined;
                        _ = std.fmt.hexToBytes(&new_hash, new_hash_str) catch continue;

                        if (!std.mem.eql(u8, &new_hash, &entry.sha1)) {
                            refresh_failed = true;
                            const nmsg = std.fmt.allocPrint(allocator, "{s}: needs update\n", .{entry.path}) catch continue;
                            defer allocator.free(nmsg);
                            platform_impl.writeStderr(nmsg) catch {};
                        }
                    }

                    entry.ctime_sec = @intCast(@max(0, @divTrunc(stat.ctime, std.time.ns_per_s)));
                    entry.ctime_nsec = @intCast(@max(0, @rem(stat.ctime, std.time.ns_per_s)));
                    entry.mtime_sec = new_mtime_sec;
                    entry.mtime_nsec = new_mtime_nsec;
                    entry.size = file_size;
                    entry.ino = @intCast(stat.inode);
                } else |_| {}
            }
        }
        modified = true;
        if (refresh_failed) {
            idx.save(git_dir, platform_impl) catch {};
            std.process.exit(1);
        }
    }

    // Handle --again: re-stage entries that differ between index and worktree
    if (again_mode) {
        const repo_root2 = std.fs.path.dirname(git_dir) orelse ".";
        var i_ag: usize = 0;
        while (i_ag < idx.entries.items.len) {
            const entry = idx.entries.items[i_ag];
            const full_path2 = if (repo_root2.len > 0 and !std.mem.eql(u8, repo_root2, "."))
                std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root2, entry.path }) catch { i_ag += 1; continue; }
            else
                allocator.dupe(u8, entry.path) catch { i_ag += 1; continue; };
            defer allocator.free(full_path2);

            if (std.fs.cwd().access(full_path2, .{})) |_| {
                if (platform_impl.fs.readFile(allocator, full_path2)) |file_content| {
                    defer allocator.free(file_content);
                    var blob_obj = objects.createBlobObject(file_content, allocator) catch { i_ag += 1; continue; };
                    const new_hash = blob_obj.store(git_dir, platform_impl, allocator) catch { blob_obj.deinit(allocator); i_ag += 1; continue; };
                    blob_obj.deinit(allocator);
                    {
                        var new_sha1: [20]u8 = undefined;
                        _ = std.fmt.hexToBytes(&new_sha1, new_hash) catch { i_ag += 1; continue; };
                        if (!std.mem.eql(u8, &entry.sha1, &new_sha1)) {
                            idx.entries.items[i_ag].sha1 = new_sha1;
                            if (std.fs.cwd().statFile(full_path2)) |stat| {
                                idx.entries.items[i_ag].size = @intCast(@min(stat.size, std.math.maxInt(u32)));
                            } else |_| {}
                            modified = true;
                        }
                    }
                } else |_| {}
            } else |_| {
                if (remove_mode) {
                    _ = idx.entries.orderedRemove(i_ag);
                    modified = true;
                    continue;
                }
            }
            i_ag += 1;
        }
    }

    if (modified) {
        idx.save(git_dir, platform_impl) catch {
            try platform_impl.writeStderr("fatal: unable to write index file\n");
            std.process.exit(128);
        };
    }
}

fn checkDFConflict(idx: *index_mod.Index, path: []const u8) bool {
    // Check if adding this path would conflict with existing entries
    // 1. Does an existing entry have a path that is a prefix of ours + '/'?
    //    (i.e., the new path would be under an existing file)
    for (idx.entries.items) |entry| {
        // Check if existing entry is a prefix of new path (existing file blocks new dir)
        if (path.len > entry.path.len and 
            std.mem.startsWith(u8, path, entry.path) and 
            path[entry.path.len] == '/') {
            return true;
        }
        // Check if new path is a prefix of existing entry (new file blocks existing dir)
        if (entry.path.len > path.len and 
            std.mem.startsWith(u8, entry.path, path) and 
            entry.path[path.len] == '/') {
            return true;
        }
    }
    return false;
}

fn addCacheInfo(idx: *index_mod.Index, mode_str: []const u8, hash_str: []const u8, path: []const u8, allocator: std.mem.Allocator) !void {
    const mode = std.fmt.parseInt(u32, mode_str, 8) catch 0o100644;
    
    // Parse hash
    var sha1: [20]u8 = undefined;
    var i: usize = 0;
    while (i < 20) : (i += 1) {
        sha1[i] = std.fmt.parseInt(u8, hash_str[i * 2 .. i * 2 + 2], 16) catch 0;
    }

    // Reject null SHA1 for blob and gitlink entries
    const is_zero = blk: {
        for (sha1) |b| {
            if (b != 0) break :blk false;
        }
        break :blk true;
    };
    if (is_zero and mode != 0) {
        return error.NullSha1;
    }

    // Check for directory/file conflicts  
    if (checkDFConflict(idx, path)) {
        return error.DirectoryFileConflict;
    }

    // Remove existing entry with same path
    idx.remove(path) catch {};

    // Add new entry
    const entry = index_mod.IndexEntry{
        .ctime_sec = 0,
        .ctime_nsec = 0,
        .mtime_sec = 0,
        .mtime_nsec = 0,
        .dev = 0,
        .ino = 0,
        .mode = mode,
        .uid = 0,
        .gid = 0,
        .size = 0,
        .sha1 = sha1,
        .flags = @as(u16, @intCast(@min(path.len, 0xFFF))),
        .extended_flags = null,
        .path = try allocator.dupe(u8, path),
    };
    try idx.entries.append(entry);
    
    // Sort entries by path
    std.mem.sort(index_mod.IndexEntry, idx.entries.items, {}, struct {
        fn lessThan(_: void, a: index_mod.IndexEntry, b: index_mod.IndexEntry) bool {
            return std.mem.lessThan(u8, a.path, b.path);
        }
    }.lessThan);
}

fn setIndexEntryMode(idx: *index_mod.Index, path: []const u8, new_mode: u32) !void {
    for (idx.entries.items) |*entry| {
        if (std.mem.eql(u8, entry.path, path)) {
            entry.mode = new_mode;
            return;
        }
    }
    return error.FileNotFound;
}

fn cmdLsTree(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    _ = allocator;
    _ = args;
    try platform_impl.writeStderr("fatal: ls-tree requires arguments\n");
    std.process.exit(128);
}

/// Resolve a tree-ish (commit hash, branch name, tree hash) to a tree object hash
fn resolveTreeish(git_path: []const u8, treeish: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) ![]u8 {
    // First resolve the reference to an object hash
    const obj_hash = resolveCommittish(git_path, treeish, platform_impl, allocator) catch {
        // Maybe it's already a tree hash
        if (treeish.len == 40 and isValidHashPrefix(treeish)) {
            return try allocator.dupe(u8, treeish);
        }
        return error.UnknownRevision;
    };
    defer allocator.free(obj_hash);

    // Load the object to check its type
    const obj = objects.GitObject.load(obj_hash, git_path, platform_impl, allocator) catch {
        return error.ObjectNotFound;
    };
    defer obj.deinit(allocator);

    switch (obj.type) {
        .tree => return try allocator.dupe(u8, obj_hash),
        .commit => {
            // Parse "tree <hash>" from the commit data
            var lines = std.mem.splitSequence(u8, obj.data, "\n");
            if (lines.next()) |first_line| {
                if (std.mem.startsWith(u8, first_line, "tree ")) {
                    return try allocator.dupe(u8, first_line["tree ".len..]);
                }
            }
            return error.ObjectNotFound;
        },
        .tag => {
            // Parse "object <hash>" from tag, then resolve that
            var lines = std.mem.splitSequence(u8, obj.data, "\n");
            while (lines.next()) |line| {
                if (std.mem.startsWith(u8, line, "object ")) {
                    const target_hash = line["object ".len..];
                    return resolveTreeish(git_path, target_hash, platform_impl, allocator);
                }
            }
            return error.ObjectNotFound;
        },
        else => return error.ObjectNotFound,
    }
}

/// Parse tree object data and return entries as a list
fn parseTreeEntries(tree_data: []const u8, allocator: std.mem.Allocator) !std.array_list.Managed(LsTreeEntry) {
    var entries = std.array_list.Managed(LsTreeEntry).init(allocator);
    var pos: usize = 0;

    while (pos < tree_data.len) {
        const space_pos = std.mem.indexOfScalarPos(u8, tree_data, pos, ' ') orelse break;
        const mode = tree_data[pos..space_pos];
        pos = space_pos + 1;

        const null_pos = std.mem.indexOfScalarPos(u8, tree_data, pos, 0) orelse break;
        const name = tree_data[pos..null_pos];
        pos = null_pos + 1;

        if (pos + 20 > tree_data.len) break;
        const hash_bytes = tree_data[pos..pos + 20];
        pos += 20;

        var hash_hex: [40]u8 = undefined;
        _ = std.fmt.bufPrint(&hash_hex, "{x}", .{hash_bytes}) catch break;

        const is_tree = std.mem.eql(u8, mode, "40000");
        const is_commit = std.mem.eql(u8, mode, "160000");
        // Pad mode to 6 digits (git format)
        const padded_mode = if (is_tree) "040000" else mode;
        const obj_type_str: []const u8 = if (is_tree) "tree" else if (is_commit) "commit" else "blob";

        try entries.append(LsTreeEntry{
            .mode = try allocator.dupe(u8, padded_mode),
            .obj_type = obj_type_str,
            .hash = try allocator.dupe(u8, &hash_hex),
            .name = try allocator.dupe(u8, name),
        });
    }

    return entries;
}

const LsTreeEntry = struct {
    mode: []const u8,
    obj_type: []const u8, // "blob" or "tree"
    hash: []const u8,
    name: []const u8,

    fn deinit(self: LsTreeEntry, allocator: std.mem.Allocator) void {
        allocator.free(self.mode);
        allocator.free(self.hash);
        allocator.free(self.name);
    }
};

fn nativeCmdLsTree(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var recursive = false;
    var show_trees = false; // -t flag
    var only_trees = false; // -d flag
    var name_only = false;
    var name_status = false;
    var long_format = false;
    var null_terminated = false;
    var abbrev_len: ?usize = null;
    var full_tree = false;
    var full_name = false;
    var object_only = false;
    var has_format = false;
    var format_str: ?[]const u8 = null;
    var treeish: ?[]const u8 = null;
    var pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer pathspecs.deinit();

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-r")) {
            recursive = true;
        } else if (std.mem.eql(u8, arg, "-t")) {
            show_trees = true;
        } else if (std.mem.eql(u8, arg, "-d")) {
            only_trees = true;
        } else if (std.mem.eql(u8, arg, "--name-only")) {
            name_only = true;
        } else if (std.mem.eql(u8, arg, "--name-status")) {
            name_status = true;
        } else if (std.mem.eql(u8, arg, "-l") or std.mem.eql(u8, arg, "--long")) {
            long_format = true;
        } else if (std.mem.eql(u8, arg, "-z")) {
            null_terminated = true;
        } else if (std.mem.eql(u8, arg, "--full-tree")) {
            full_tree = true;
        } else if (std.mem.eql(u8, arg, "--full-name")) {
            full_name = true;
        } else if (std.mem.eql(u8, arg, "--no-full-name")) {
            full_name = false;
        } else if (std.mem.eql(u8, arg, "--object-only")) {
            object_only = true;
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            has_format = true;
            format_str = arg["--format=".len..];
        } else if (std.mem.eql(u8, arg, "--abbrev")) {
            abbrev_len = 7; // default abbrev length
        } else if (std.mem.startsWith(u8, arg, "--abbrev=")) {
            const val = arg["--abbrev=".len..];
            abbrev_len = std.fmt.parseInt(usize, val, 10) catch 7;
        } else if (std.mem.eql(u8, arg, "--")) {
            // Everything after -- is a pathspec
            i += 1;
            while (i < args.len) : (i += 1) {
                try pathspecs.append(args[i]);
            }
            break;
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git ls-tree [<options>] <tree-ish> [<path>...]\n\n    -d                  only show trees\n    -r                  recurse into subtrees\n    -t                  show trees when recursing\n    --name-only         list only filenames\n    --name-status       list only filenames\n    --long              include object size\n    -z                  terminate entries with NUL byte\n");
            return;
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (treeish == null) {
                treeish = arg;
            } else {
                try pathspecs.append(arg);
            }
        }
    }

    // Validate incompatible options
    {
        const name_opts = @as(u8, if (name_only) 1 else 0) + @as(u8, if (object_only) 1 else 0);
        if (long_format and (name_only or name_status)) {
            try platform_impl.writeStderr("error: --long is incompatible with --name-only\n");
            std.process.exit(129);
        }
        if (long_format and object_only) {
            try platform_impl.writeStderr("error: --long is incompatible with --object-only\n");
            std.process.exit(129);
        }
        if (name_only and name_status) {
            try platform_impl.writeStderr("error: --name-status is incompatible with --name-only\n");
            std.process.exit(129);
        }
        if ((name_only or name_status) and object_only) {
            if (name_status) {
                try platform_impl.writeStderr("error: --object-only is incompatible with --name-status\n");
            } else {
                try platform_impl.writeStderr("error: --object-only is incompatible with --name-only\n");
            }
            std.process.exit(129);
        }
        _ = name_opts;
        if (has_format) {
            if (long_format or name_only or name_status or object_only) {
                try platform_impl.writeStderr("error: --format can't be combined with other format-altering options\n");
                std.process.exit(129);
            }
        }
        // Merge name_status into name_only for output purposes
        if (name_status) name_only = true;
    }

    if (treeish == null) {
        try platform_impl.writeStderr("fatal: not enough arguments\n");
        std.process.exit(128);
    }

    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_path);

    // Compute prefix (path from repo root to CWD)
    var prefix_str: []const u8 = "";
    var prefix_allocated = false;
    if (!full_tree) {
        const cwd = platform_impl.fs.getCwd(allocator) catch "";
        defer if (cwd.len > 0) allocator.free(cwd);
        // git_path is like /path/to/repo/.git, repo root is parent
        const repo_root = std.fs.path.dirname(git_path) orelse "";
        if (cwd.len > 0 and repo_root.len > 0 and cwd.len > repo_root.len and
            std.mem.startsWith(u8, cwd, repo_root) and cwd[repo_root.len] == '/')
        {
            prefix_str = allocator.dupe(u8, cwd[repo_root.len + 1 ..]) catch "";
            prefix_allocated = prefix_str.len > 0;
        }
    }
    defer if (prefix_allocated) allocator.free(@constCast(prefix_str));

    // Adjust pathspecs with prefix (prepend prefix to relative pathspecs)
    var adjusted_pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (adjusted_pathspecs.items) |ps| allocator.free(@constCast(ps));
        adjusted_pathspecs.deinit();
    }
    var no_path_restriction = false;
    if (prefix_str.len > 0 and pathspecs.items.len > 0) {
        for (pathspecs.items) |ps| {
            // Resolve relative paths like ../
            const combined = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix_str, ps });
            defer allocator.free(combined);
            const normalized = try normalizePath(allocator, combined);
            if (normalized.len == 0) {
                allocator.free(normalized);
                // Path resolved to root - no restriction
                no_path_restriction = true;
                for (adjusted_pathspecs.items) |existing| allocator.free(@constCast(existing));
                adjusted_pathspecs.clearRetainingCapacity();
                break;
            } else {
                try adjusted_pathspecs.append(normalized);
            }
        }
    } else if (prefix_str.len > 0 and pathspecs.items.len == 0) {
        // When no pathspecs given but in a subdirectory, restrict to prefix
        const adjusted = try std.fmt.allocPrint(allocator, "{s}/", .{prefix_str});
        try adjusted_pathspecs.append(adjusted);
    }

    // Use adjusted pathspecs if we have them, otherwise original
    // Check for --full-tree with ../ pathspec (should error)
    if (full_tree) {
        for (pathspecs.items) |ps| {
            if (std.mem.startsWith(u8, ps, "../") or std.mem.eql(u8, ps, "..")) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: {s}: '{s}' is outside repository\n", .{ ps, ps });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }
        }
    }

    // Use empty pathspecs when path resolved to root (show everything)
    var empty_pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer empty_pathspecs.deinit();
    const effective_pathspecs = if (no_path_restriction)
        &empty_pathspecs
    else if (adjusted_pathspecs.items.len > 0)
        &adjusted_pathspecs
    else
        &pathspecs;

    // Resolve tree-ish to a tree hash
    const tree_hash = resolveTreeish(git_path, treeish.?, platform_impl, allocator) catch {
        const msg = try std.fmt.allocPrint(allocator, "fatal: Not a valid object name {s}\n", .{treeish.?});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(tree_hash);

    // Collect all output entries
    var output_entries = std.array_list.Managed(OutputEntry) .init(allocator);
    defer {
        for (output_entries.items) |*entry| entry.deinit(allocator);
        output_entries.deinit();
    }

    // Walk the tree
    walkTree(allocator, git_path, tree_hash, "", recursive, show_trees, only_trees, effective_pathspecs, platform_impl, &output_entries) catch {
        try platform_impl.writeStderr("fatal: not a tree object\n");
        std.process.exit(128);
        unreachable;
    };

    // Tree entries are already stored in sorted order in the tree object,
    // so we don't re-sort (git's tree sorting uses implicit trailing / for directories)

    // Output
    // Read core.quotePath config (default true)
    var quote_path = true;
    {
        const config_path = std.fmt.allocPrint(allocator, "{s}/config", .{git_path}) catch null;
        if (config_path) |cp| {
            defer allocator.free(cp);
            if (std.fs.cwd().readFileAlloc(allocator, cp, 1024 * 1024)) |config_content| {
                defer allocator.free(config_content);
                // Simple search for quotepath = false
                if (std.mem.indexOf(u8, config_content, "quotepath = false") != null or
                    std.mem.indexOf(u8, config_content, "quotePath = false") != null)
                {
                    quote_path = false;
                }
            } else |_| {}
        }
    }

    const line_end: []const u8 = if (null_terminated) "\x00" else "\n";
    for (output_entries.items) |entry| {
        // Apply hash abbreviation
        const display_hash = if (abbrev_len) |abl|
            entry.hash[0..@min(abl, entry.hash.len)]
        else
            entry.hash;
        // By default, paths are shown relative to CWD (prefix).
        // --full-name shows repo-root-relative paths.
        const raw_display_path = if (!full_name and prefix_str.len > 0) blk: {
            break :blk try makeRelativePath(allocator, prefix_str, entry.full_path);
        } else entry.full_path;
        const raw_display_path_allocated = !full_name and prefix_str.len > 0;
        defer if (raw_display_path_allocated) allocator.free(@constCast(raw_display_path));

        // C-quote the path if it contains special characters
        const quoted_path = try cQuotePath(allocator, raw_display_path, quote_path);
        defer allocator.free(quoted_path);
        const display_path = quoted_path;

        if (format_str) |fmt| {
            // Custom format string
            const formatted = try formatLsTreeEntry(allocator, fmt, entry, display_hash, display_path, git_path, platform_impl);
            defer allocator.free(formatted);
            const output = try std.fmt.allocPrint(allocator, "{s}{s}", .{ formatted, line_end });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else if (object_only) {
            const output = try std.fmt.allocPrint(allocator, "{s}{s}", .{ display_hash, line_end });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else if (name_only) {
            const output = try std.fmt.allocPrint(allocator, "{s}{s}", .{ display_path, line_end });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else if (long_format) {
            // Long format: mode type size\thash\tpath
            const size_str = if (std.mem.eql(u8, entry.obj_type, "tree") or std.mem.eql(u8, entry.obj_type, "commit"))
                try allocator.dupe(u8, "      -")
            else blk: {
                // Load the object to get its size
                const obj = objects.GitObject.load(entry.hash, git_path, platform_impl, allocator) catch {
                    break :blk try allocator.dupe(u8, "      ?");
                };
                defer obj.deinit(allocator);
                break :blk try std.fmt.allocPrint(allocator, "{d:>7}", .{obj.data.len});
            };
            defer allocator.free(size_str);
            const output = try std.fmt.allocPrint(allocator, "{s} {s} {s} {s}\t{s}{s}", .{ entry.mode, entry.obj_type, display_hash, size_str, display_path, line_end });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else {
            const output = try std.fmt.allocPrint(allocator, "{s} {s} {s}\t{s}{s}", .{ entry.mode, entry.obj_type, display_hash, display_path, line_end });
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        }
    }
}

const OutputEntry = struct {
    mode: []const u8,
    obj_type: []const u8,
    hash: []const u8,
    full_path: []const u8,

    fn deinit(self: *OutputEntry, allocator: std.mem.Allocator) void {
        allocator.free(self.mode);
        allocator.free(self.hash);
        allocator.free(self.full_path);
    }
};

fn walkTree(
    allocator: std.mem.Allocator,
    git_path: []const u8,
    tree_hash: []const u8,
    prefix: []const u8,
    recursive: bool,
    show_trees: bool,
    only_trees: bool,
    pathspecs: *std.array_list.Managed([]const u8),
    platform_impl: *const platform_mod.Platform,
    output: *std.array_list.Managed(OutputEntry),
) !void {
    // Load the tree object
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch {
        return error.ObjectNotFound;
    };
    defer tree_obj.deinit(allocator);

    if (tree_obj.type != .tree) return error.ObjectNotFound;

    // Parse tree entries
    var entries = try parseTreeEntries(tree_obj.data, allocator);
    defer {
        for (entries.items) |*entry| entry.deinit(allocator);
        entries.deinit();
    }

    for (entries.items) |entry| {
        const full_path = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name })
        else
            try allocator.dupe(u8, entry.name);

        const is_tree = std.mem.eql(u8, entry.obj_type, "tree");
        const is_submodule = std.mem.eql(u8, entry.obj_type, "commit");
        const is_directory_like = is_tree or is_submodule;

        // Check pathspec filtering
        if (pathspecs.items.len > 0) {
            var matches = false;
            for (pathspecs.items) |pathspec| {
                if (pathMatchesSpec(full_path, pathspec, is_directory_like)) {
                    matches = true;
                    break;
                }
                // Also check if this tree is a prefix of the pathspec (need to recurse into it)
                if (is_tree and pathSpecStartsWith(pathspec, full_path)) {
                    matches = true;
                    break;
                }
            }
            if (!matches) {
                allocator.free(full_path);
                continue;
            }
        }

        if (is_tree) {
            if (recursive) {
                if (show_trees or only_trees) {
                    try output.append(OutputEntry{
                        .mode = try allocator.dupe(u8, entry.mode),
                        .obj_type = entry.obj_type,
                        .hash = try allocator.dupe(u8, entry.hash),
                        .full_path = try allocator.dupe(u8, full_path),
                    });
                }
                if (!only_trees) {
                    try walkTree(allocator, git_path, entry.hash, full_path, recursive, show_trees, only_trees, pathspecs, platform_impl, output);
                } else {
                    // Even with -d, recurse to find subtrees
                    try walkTree(allocator, git_path, entry.hash, full_path, recursive, show_trees, only_trees, pathspecs, platform_impl, output);
                }
            } else {
                // Non-recursive: check if pathspec asks for contents of this tree
                var show_children = false;
                if (pathspecs.items.len > 0) {
                    for (pathspecs.items) |pathspec| {
                        // If pathspec ends with '/' and matches this tree, show children
                        if (std.mem.endsWith(u8, pathspec, "/") and
                            std.mem.eql(u8, full_path, pathspec[0 .. pathspec.len - 1]))
                        {
                            show_children = true;
                            break;
                        }
                        // If pathspec has more components beyond this tree, show children
                        if (pathSpecStartsWith(pathspec, full_path) and
                            pathspec.len > full_path.len and pathspec[full_path.len] == '/')
                        {
                            show_children = true;
                            break;
                        }
                    }
                }

                if (show_children) {
                    // With -t flag, show intermediate tree entries
                    if (show_trees) {
                        try output.append(OutputEntry{
                            .mode = try allocator.dupe(u8, entry.mode),
                            .obj_type = entry.obj_type,
                            .hash = try allocator.dupe(u8, entry.hash),
                            .full_path = try allocator.dupe(u8, full_path),
                        });
                    }
                    // Recursively descend into this tree to find matching entries
                    // (handles deep pathspecs like path1/b/c/1.txt)
                    try walkTree(allocator, git_path, entry.hash, full_path, false, show_trees, only_trees, pathspecs, platform_impl, output);
                } else if (!only_trees or is_tree) {
                    try output.append(OutputEntry{
                        .mode = try allocator.dupe(u8, entry.mode),
                        .obj_type = entry.obj_type,
                        .hash = try allocator.dupe(u8, entry.hash),
                        .full_path = try allocator.dupe(u8, full_path),
                    });
                }
            }
        } else {
            // Blob or submodule entry
            if (!only_trees or is_submodule) {
                try output.append(OutputEntry{
                    .mode = try allocator.dupe(u8, entry.mode),
                    .obj_type = entry.obj_type,
                    .hash = try allocator.dupe(u8, entry.hash),
                    .full_path = try allocator.dupe(u8, full_path),
                });
            }
        }

        allocator.free(full_path);
    }
}

fn walkTreeOneLevel(
    allocator: std.mem.Allocator,
    git_path: []const u8,
    tree_hash: []const u8,
    prefix: []const u8,
    pathspecs: *std.array_list.Managed([]const u8),
    platform_impl: *const platform_mod.Platform,
    output: *std.array_list.Managed(OutputEntry),
    show_trees_flag: bool,
) !void {
    _ = show_trees_flag;
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    if (tree_obj.type != .tree) return;

    var entries = try parseTreeEntries(tree_obj.data, allocator);
    defer {
        for (entries.items) |*entry| entry.deinit(allocator);
        entries.deinit();
    }

    for (entries.items) |entry| {
        const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name });
        defer allocator.free(full_path);

        const is_tree = std.mem.eql(u8, entry.obj_type, "tree");

        // Check pathspec filtering for sub-entries
        if (pathspecs.items.len > 0) {
            var matches = false;
            for (pathspecs.items) |pathspec| {
                if (pathMatchesSpec(full_path, pathspec, is_tree)) {
                    matches = true;
                    break;
                }
                if (is_tree and pathSpecStartsWith(pathspec, full_path)) {
                    matches = true;
                    break;
                }
            }
            if (!matches) continue;
        }

        try output.append(OutputEntry{
            .mode = try allocator.dupe(u8, entry.mode),
            .obj_type = entry.obj_type,
            .hash = try allocator.dupe(u8, entry.hash),
            .full_path = try allocator.dupe(u8, full_path),
        });
    }
}

/// Check if a path matches a pathspec
fn pathMatchesSpec(path: []const u8, spec: []const u8, is_tree: bool) bool {
    // Spec with trailing slash: matches children of the directory but not a blob with the base name
    if (std.mem.endsWith(u8, spec, "/")) {
        const spec_base = spec[0 .. spec.len - 1];
        // path0/ should NOT match the blob path0 (file, not directory)
        if (std.mem.eql(u8, path, spec_base)) {
            return is_tree; // Only match if it's actually a tree
        }
        // Match children of the specified directory (both blobs and trees)
        if (std.mem.startsWith(u8, path, spec)) return true;
        return false;
    }
    // Exact match
    if (std.mem.eql(u8, path, spec)) return true;
    // Path is a child of the spec directory
    if (path.len > spec.len and std.mem.startsWith(u8, path, spec) and path[spec.len] == '/') return true;
    return false;
}

/// Check if pathspec starts with the given prefix (for tree recursion)
/// Normalize a path by resolving . and .. components
/// C-style quote a filename if it contains special characters
fn cQuotePath(allocator: std.mem.Allocator, path: []const u8, quote_high_bytes: bool) ![]u8 {
    // Check if quoting is needed
    var needs_quoting = false;
    for (path) |c| {
        if (c < 0x20 or c == '\\' or c == '"') {
            needs_quoting = true;
            break;
        }
        if (quote_high_bytes and c >= 0x80) {
            needs_quoting = true;
            break;
        }
    }
    if (!needs_quoting) return try allocator.dupe(u8, path);

    var result = std.array_list.Managed(u8).init(allocator);
    try result.append('"');
    for (path) |c| {
        switch (c) {
            '\t' => try result.appendSlice("\\t"),
            '\n' => try result.appendSlice("\\n"),
            '\\' => try result.appendSlice("\\\\"),
            '"' => try result.appendSlice("\\\""),
            else => {
                if (c < 0x20 or (quote_high_bytes and c >= 0x80)) {
                    var buf: [4]u8 = undefined;
                    _ = std.fmt.bufPrint(&buf, "\\{o:0>3}", .{c}) catch unreachable;
                    try result.appendSlice(&buf);
                } else {
                    try result.append(c);
                }
            },
        }
    }
    try result.append('"');
    return try allocator.dupe(u8, result.items);
}

fn formatLsTreeEntry(
    allocator: std.mem.Allocator,
    fmt: []const u8,
    entry: OutputEntry,
    display_hash: []const u8,
    display_path: []const u8,
    git_path: []const u8,
    platform_impl: *const platform_mod.Platform,
) ![]u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    var i: usize = 0;
    while (i < fmt.len) {
        if (fmt[i] == '%' and i + 1 < fmt.len) {
            if (fmt[i + 1] == '(') {
              if (std.mem.indexOf(u8, fmt[i..], ")")) |close_offset| {
                const placeholder = fmt[i + 2 .. i + close_offset];
                if (std.mem.eql(u8, placeholder, "objectmode")) {
                    try result.appendSlice(entry.mode);
                } else if (std.mem.eql(u8, placeholder, "objecttype")) {
                    try result.appendSlice(entry.obj_type);
                } else if (std.mem.eql(u8, placeholder, "objectname")) {
                    try result.appendSlice(display_hash);
                } else if (std.mem.eql(u8, placeholder, "objectsize")) {
                    if (std.mem.eql(u8, entry.obj_type, "tree") or std.mem.eql(u8, entry.obj_type, "commit")) {
                        try result.append('-');
                    } else {
                        const obj = objects.GitObject.load(entry.hash, git_path, platform_impl, allocator) catch {
                            try result.append('-');
                            i += close_offset + 1;
                            continue;
                        };
                        defer obj.deinit(allocator);
                        const sz = try std.fmt.allocPrint(allocator, "{d}", .{obj.data.len});
                        defer allocator.free(sz);
                        try result.appendSlice(sz);
                    }
                } else if (std.mem.eql(u8, placeholder, "objectsize:padded")) {
                    if (std.mem.eql(u8, entry.obj_type, "tree") or std.mem.eql(u8, entry.obj_type, "commit")) {
                        try result.appendSlice("      -");
                    } else {
                        const obj = objects.GitObject.load(entry.hash, git_path, platform_impl, allocator) catch {
                            try result.appendSlice("      -");
                            i += close_offset + 1;
                            continue;
                        };
                        defer obj.deinit(allocator);
                        const sz = try std.fmt.allocPrint(allocator, "{d:>7}", .{obj.data.len});
                        defer allocator.free(sz);
                        try result.appendSlice(sz);
                    }
                } else if (std.mem.eql(u8, placeholder, "path")) {
                    try result.appendSlice(display_path);
                }
                i += close_offset + 1;
              } else {
                try result.append(fmt[i]);
                i += 1;
              }
            } else if (fmt[i + 1] == 'x' and i + 3 < fmt.len) {
                // Hex escape: %xNN
                const hex_str = fmt[i + 2 .. i + 4];
                const byte = std.fmt.parseInt(u8, hex_str, 16) catch {
                    try result.append('%');
                    i += 1;
                    continue;
                };
                try result.append(byte);
                i += 4;
            } else {
                try result.append(fmt[i]);
                i += 1;
            }
        } else {
            try result.append(fmt[i]);
            i += 1;
        }
    }
    return try allocator.dupe(u8, result.items);
}

/// Given a prefix (CWD relative to repo root) and a full_path (relative to repo root),
/// compute the display path relative to prefix. E.g., prefix="aa", full_path="a[a]/three" → "../a[a]/three"
fn makeRelativePath(allocator: std.mem.Allocator, prefix: []const u8, full_path: []const u8) ![]const u8 {
    // Split prefix into components
    var prefix_parts = std.array_list.Managed([]const u8).init(allocator);
    defer prefix_parts.deinit();
    var piter = std.mem.splitScalar(u8, prefix, '/');
    while (piter.next()) |part| {
        if (part.len > 0) try prefix_parts.append(part);
    }

    // Split full_path into components
    var path_parts = std.array_list.Managed([]const u8).init(allocator);
    defer path_parts.deinit();
    var fiter = std.mem.splitScalar(u8, full_path, '/');
    while (fiter.next()) |part| {
        if (part.len > 0) try path_parts.append(part);
    }

    // Find common prefix length
    var common: usize = 0;
    while (common < prefix_parts.items.len and common < path_parts.items.len) {
        if (!std.mem.eql(u8, prefix_parts.items[common], path_parts.items[common])) break;
        common += 1;
    }

    // Number of "../" needed
    const ups = prefix_parts.items.len - common;

    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();
    for (0..ups) |_| {
        try result.appendSlice("../");
    }
    for (path_parts.items[common..], 0..) |part, idx| {
        if (idx > 0) try result.append('/');
        try result.appendSlice(part);
    }

    return try allocator.dupe(u8, result.items);
}

fn normalizePath(allocator: std.mem.Allocator, path: []const u8) ![]u8 {
    var components = std.array_list.Managed([]const u8).init(allocator);
    defer components.deinit();

    // Handle trailing slash
    const has_trailing_slash = std.mem.endsWith(u8, path, "/");
    const clean_path = if (has_trailing_slash) path[0 .. path.len - 1] else path;

    var iter = std.mem.splitScalar(u8, clean_path, '/');
    while (iter.next()) |component| {
        if (component.len == 0 or std.mem.eql(u8, component, ".")) continue;
        if (std.mem.eql(u8, component, "..")) {
            if (components.items.len > 0) {
                _ = components.pop();
            }
            continue;
        }
        try components.append(component);
    }

    if (components.items.len == 0) return try allocator.dupe(u8, "");

    // Join components
    var result = std.array_list.Managed(u8).init(allocator);
    for (components.items, 0..) |comp, idx| {
        if (idx > 0) try result.append('/');
        try result.appendSlice(comp);
    }
    if (has_trailing_slash) try result.append('/');

    return try allocator.dupe(u8, result.items);
}

fn pathSpecStartsWith(spec: []const u8, prefix: []const u8) bool {
    const clean_spec = if (std.mem.endsWith(u8, spec, "/")) spec[0 .. spec.len - 1] else spec;
    if (clean_spec.len <= prefix.len) return false;
    return std.mem.startsWith(u8, clean_spec, prefix) and clean_spec[prefix.len] == '/';
}

fn cmdReadTree(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    var tree_hash: ?[]const u8 = null;
    var empty = false;
    var merge = false;
    var update = false;
    var prefix: ?[]const u8 = null;

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--empty")) {
            empty = true;
        } else if (std.mem.eql(u8, arg, "-m")) {
            merge = true;
        } else if (std.mem.eql(u8, arg, "-u")) {
            update = true;
        } else if (std.mem.eql(u8, arg, "-i")) {
            // index-only, ignore
        } else if (std.mem.startsWith(u8, arg, "--prefix=")) {
            prefix = arg["--prefix=".len..];
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            tree_hash = arg;
        }
    }

    if (empty) {
        // Write an empty index
        var idx = index_mod.Index.init(allocator);
        defer idx.deinit();
        idx.save(git_dir, platform_impl) catch {
            try platform_impl.writeStderr("fatal: unable to write index file\n");
            std.process.exit(128);
        };
        return;
    }

    if (tree_hash == null) {
        try platform_impl.writeStderr("fatal: must specify a tree-ish\n");
        std.process.exit(128);
        unreachable;
    }

    // Resolve tree-ish to tree hash
    const resolved_tree = resolveTreeish(git_dir, tree_hash.?, platform_impl, allocator) catch {
        const err_msg = try std.fmt.allocPrint(allocator, "fatal: not a tree object: {s}\n", .{tree_hash.?});
        defer allocator.free(err_msg);
        try platform_impl.writeStderr(err_msg);
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(resolved_tree);

    // Build index from tree
    var idx = index_mod.Index.init(allocator);
    defer idx.deinit();

    try readTreeIntoIndex(&idx, git_dir, resolved_tree, prefix orelse "", platform_impl, allocator);

    idx.save(git_dir, platform_impl) catch {
        try platform_impl.writeStderr("fatal: unable to write index file\n");
        std.process.exit(128);
    };
}

fn readTreeIntoIndex(idx: *index_mod.Index, git_dir: []const u8, tree_hash: []const u8, prefix: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    const obj = objects.GitObject.load(tree_hash, git_dir, platform_impl, allocator) catch return;
    defer obj.deinit(allocator);

    if (obj.type != .tree) return;

    // Parse tree entries from binary data
    var pos: usize = 0;
    const data = obj.data;
    while (pos < data.len) {
        // Format: <mode> <name>\0<20-byte-sha1>
        const space_pos = std.mem.indexOfScalarPos(u8, data, pos, ' ') orelse break;
        const mode_str = data[pos..space_pos];
        const null_pos = std.mem.indexOfScalarPos(u8, data, space_pos + 1, 0) orelse break;
        const name = data[space_pos + 1 .. null_pos];

        if (null_pos + 21 > data.len) break;
        const entry_sha1 = data[null_pos + 1 .. null_pos + 21];

        var hash_hex: [40]u8 = undefined;
        for (entry_sha1, 0..) |byte, j| {
            const hex = std.fmt.bytesToHex([1]u8{byte}, .lower);
            hash_hex[j * 2] = hex[0];
            hash_hex[j * 2 + 1] = hex[1];
        }

        const full_path = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);

        const mode = std.fmt.parseInt(u32, mode_str, 8) catch 0o100644;

        if (mode == 0o40000) {
            // Directory - recurse
            defer allocator.free(full_path);
            const sub_prefix = try std.fmt.allocPrint(allocator, "{s}/", .{full_path});
            defer allocator.free(sub_prefix);
            try readTreeIntoIndex(idx, git_dir, &hash_hex, sub_prefix, platform_impl, allocator);
        } else {
            // File entry
            var sha1: [20]u8 = undefined;
            @memcpy(&sha1, entry_sha1);

            const entry = index_mod.IndexEntry{
                .ctime_sec = 0,
                .ctime_nsec = 0,
                .mtime_sec = 0,
                .mtime_nsec = 0,
                .dev = 0,
                .ino = 0,
                .mode = mode,
                .uid = 0,
                .gid = 0,
                .size = 0,
                .sha1 = sha1,
                .flags = @as(u16, @intCast(@min(full_path.len, 0xFFF))),
                .extended_flags = null,
                .path = full_path,
            };
            try idx.entries.append(entry);
        }

        pos = null_pos + 21;
    }
}

fn cmdDiffFiles(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    // diff-files: compare index against working tree
    var name_only = false;
    var name_status = false;
    var exit_code = false;
    var df_patch = false;
    var df_suppress = false;
    var df_show_raw = false;
    var df_patch_with_raw = false;
    var df_pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer df_pathspecs.deinit();
    var df_seen_dashdash = false;
    while (args.next()) |arg| {
        if (df_seen_dashdash) {
            try df_pathspecs.append(arg);
            continue;
        }
        if (std.mem.eql(u8, arg, "--")) {
            df_seen_dashdash = true;
            continue;
        }
        if (std.mem.eql(u8, arg, "--name-only")) {
            name_only = true;
            df_suppress = false;
        } else if (std.mem.eql(u8, arg, "--name-status")) {
            name_status = true;
            df_suppress = false;
        } else if (std.mem.eql(u8, arg, "--exit-code")) {
            exit_code = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            exit_code = true;
        } else if (std.mem.eql(u8, arg, "-p") or std.mem.eql(u8, arg, "-u") or std.mem.eql(u8, arg, "--patch")) {
            df_patch = true;
            df_suppress = false;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--no-patch")) {
            df_suppress = true;
            df_patch = false;
            df_patch_with_raw = false;
            df_show_raw = false;
            name_only = false;
            name_status = false;
        } else if (std.mem.eql(u8, arg, "--raw")) {
            df_show_raw = true;
            df_suppress = false;
        } else if (std.mem.eql(u8, arg, "--patch-with-raw")) {
            df_patch = true;
            df_patch_with_raw = true;
            df_suppress = false;
        } else if (std.mem.eql(u8, arg, "--patch-with-stat") or std.mem.eql(u8, arg, "--stat") or
            std.mem.eql(u8, arg, "--numstat") or std.mem.eql(u8, arg, "--shortstat") or
            std.mem.eql(u8, arg, "--compact-summary"))
        {
            df_suppress = false;
        } else if (std.mem.eql(u8, arg, "--summary") or std.mem.eql(u8, arg, "--dirstat") or
            std.mem.eql(u8, arg, "--cumulative") or std.mem.eql(u8, arg, "--dirstat-by-file"))
        {
            df_suppress = true;
            df_patch = false;
            df_show_raw = false;
            name_only = false;
            name_status = false;
        }
    }
    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    const repo_root = std.fs.path.dirname(git_dir) orelse ".";

    var idx = index_mod.Index.load(git_dir, platform_impl, allocator) catch return;
    defer idx.deinit();

    const zero_oid = "0000000000000000000000000000000000000000";
    var has_diffs = false;
    // For --patch-with-raw: collect raw lines and patch output separately
    var pwr_raw_buf = std.array_list.Managed(u8).init(allocator);
    defer pwr_raw_buf.deinit();
    var pwr_patch_buf = std.array_list.Managed(u8).init(allocator);
    defer pwr_patch_buf.deinit();

    for (idx.entries.items) |entry| {
        // Skip assume-unchanged entries
        if ((entry.flags & 0x8000) != 0) continue;

        // Filter by pathspecs
        if (df_pathspecs.items.len > 0) {
            var path_matches = false;
            for (df_pathspecs.items) |ps| {
                if (pathspecMatch(ps, entry.path)) {
                    path_matches = true;
                    break;
                }
            }
            if (!path_matches) continue;
        }

        // Build full path from repo root
        const full_path = if (repo_root.len > 0 and !std.mem.eql(u8, repo_root, "."))
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path })
        else
            try allocator.dupe(u8, entry.path);
        defer allocator.free(full_path);

        // Use lstat (no follow) to properly handle symlinks
        const is_symlink_in_index = (entry.mode & 0o170000) == 0o120000;

        // Check if path exists - for symlinks, check the link itself
        var link_buf: [4096]u8 = undefined;
        const is_symlink_on_disk = if (std.fs.cwd().readLink(full_path, &link_buf)) |_| true else |_| false;

        // Try to get file info
        const file_exists = if (is_symlink_on_disk) true else if (std.fs.cwd().access(full_path, .{})) |_| true else |_| false;

        if (!file_exists) {
            // File deleted
            has_diffs = true;
            if (df_suppress) continue;
            var hash_buf: [40]u8 = undefined;
            _ = std.fmt.bufPrint(&hash_buf, "{x}", .{&entry.sha1}) catch unreachable;
            if (name_only) {
                const line = try std.fmt.allocPrint(allocator, "{s}\n", .{entry.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            } else if (name_status) {
                const line = try std.fmt.allocPrint(allocator, "D\t{s}\n", .{entry.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            } else {
                if (!df_patch or df_patch_with_raw or df_show_raw) {
                    const line = try std.fmt.allocPrint(allocator, ":{o:0>6} 000000 {s} {s} D\t{s}\n", .{ entry.mode, &hash_buf, zero_oid, entry.path });
                    defer allocator.free(line);
                    if (df_patch_with_raw) { try pwr_raw_buf.appendSlice(line); } else { try platform_impl.writeStdout(line); }
                }
                if (df_patch) {
                    const indexed_content = getIndexedFileContent(entry, allocator) catch "";
                    defer if (indexed_content.len > 0) allocator.free(indexed_content);
                    var out = std.array_list.Managed(u8).init(allocator);
                    defer out.deinit();
                    try out.appendSlice("diff --git a/");
                    try out.appendSlice(entry.path);
                    try out.appendSlice(" b/");
                    try out.appendSlice(entry.path);
                    try out.appendSlice("\n");
                    const mode_str = try std.fmt.allocPrint(allocator, "deleted file mode {o:0>6}\n", .{entry.mode});
                    defer allocator.free(mode_str);
                    try out.appendSlice(mode_str);
                    const del_idx_line = try std.fmt.allocPrint(allocator, "index {s}..{s}\n", .{ hash_buf[0..7], zero_oid[0..7] });
                    defer allocator.free(del_idx_line);
                    try out.appendSlice(del_idx_line);
                    try out.appendSlice("--- a/");
                    try out.appendSlice(entry.path);
                    try out.appendSlice("\n+++ /dev/null\n");
                    if (indexed_content.len > 0) {
                        var liter = std.mem.splitScalar(u8, indexed_content, '\n');
                        var lines_arr = std.array_list.Managed([]const u8).init(allocator);
                        defer lines_arr.deinit();
                        while (liter.next()) |ln| try lines_arr.append(ln);
                        if (lines_arr.items.len > 0 and indexed_content[indexed_content.len - 1] == '\n') _ = lines_arr.pop();
                        const hh = try std.fmt.allocPrint(allocator, "@@ -1,{d} +0,0 @@\n", .{lines_arr.items.len});
                        defer allocator.free(hh);
                        try out.appendSlice(hh);
                        for (lines_arr.items) |ln| {
                            try out.append('-');
                            try out.appendSlice(ln);
                            try out.append('\n');
                        }
                        if (indexed_content[indexed_content.len - 1] != '\n') {
                            try out.appendSlice("\\\\ No newline at end of file\n");
                        }
                    }
                    if (df_patch_with_raw) { try pwr_patch_buf.appendSlice(out.items); } else { try platform_impl.writeStdout(out.items); }
                }
            }
            continue;
        }

        // Determine working tree mode
        const wt_mode: u32 = wt_blk: {
            if (is_symlink_on_disk) break :wt_blk 0o120000;
            if (std.fs.cwd().statFile(full_path)) |st| {
                if ((st.mode & 0o111) != 0) break :wt_blk 0o100755;
            } else |_| {}
            break :wt_blk 0o100644;
        };

        // Compare to detect modifications
        var modified = false;

        // If index entry has zeroed stat cache (e.g., from read-tree), always mark as modified
        if (entry.ctime_sec == 0 and entry.ctime_nsec == 0 and entry.mtime_sec == 0 and entry.mtime_nsec == 0 and entry.ino == 0) {
            modified = true;
        } else if (is_symlink_in_index != is_symlink_on_disk) {
            // Type changed (symlink <-> regular file)
            modified = true;
        } else if (!is_symlink_on_disk) {
            // Regular files - check stat
            if (std.fs.cwd().statFile(full_path)) |stat_result| {
                const file_size: u32 = @intCast(@min(stat_result.size, std.math.maxInt(u32)));
                if (entry.size != file_size) {
                    modified = true;
                } else {
                    // Compare mtime
                    const mtime_s: u32 = @intCast(@max(0, @divTrunc(stat_result.mtime, std.time.ns_per_s)));
                    const mtime_ns: u32 = @intCast(@max(0, @rem(stat_result.mtime, std.time.ns_per_s)));
                    if (entry.mtime_sec != mtime_s or entry.mtime_nsec != mtime_ns) {
                        modified = true;
                    }
                }
            } else |_| {
                modified = true;
            }
        } else {
            // Symlink - check stat (mtime/size)
            // For symlinks, size in index is the length of the target path
            // Since we can't easily lstat, compare by content if stat check is uncertain
            const link_target = std.fs.cwd().readLink(full_path, &link_buf) catch {
                modified = true;
                continue;
            };
            // Hash the symlink target to compare with index
            const blob_content = try std.fmt.allocPrint(allocator, "blob {d}\x00{s}", .{ link_target.len, link_target });
            defer allocator.free(blob_content);
            var hash: [20]u8 = undefined;
            std.crypto.hash.Sha1.hash(blob_content, &hash, .{});
            if (!std.mem.eql(u8, &hash, &entry.sha1)) {
                modified = true;
            }
        }

        if (modified) {
            has_diffs = true;
            if (df_suppress) continue;
            var hash_buf: [40]u8 = undefined;
            _ = std.fmt.bufPrint(&hash_buf, "{x}", .{&entry.sha1}) catch unreachable;
            if (name_only) {
                const line = try std.fmt.allocPrint(allocator, "{s}\n", .{entry.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            } else if (name_status) {
                const line = try std.fmt.allocPrint(allocator, "M\t{s}\n", .{entry.path});
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            } else {
                if (!df_patch or df_patch_with_raw or df_show_raw) {
                    const line = try std.fmt.allocPrint(allocator, ":{o:0>6} {o:0>6} {s} {s} M\t{s}\n", .{ entry.mode, wt_mode, &hash_buf, zero_oid, entry.path });
                    defer allocator.free(line);
                    if (df_patch_with_raw) { try pwr_raw_buf.appendSlice(line); } else { try platform_impl.writeStdout(line); }
                }
                if (df_patch) {
                    const indexed_content = getIndexedFileContent(entry, allocator) catch "";
                    defer if (indexed_content.len > 0) allocator.free(indexed_content);
                    const wt_content = blk: {
                        if (is_symlink_on_disk) {
                            const lt = std.fs.cwd().readLink(full_path, &link_buf) catch break :blk try allocator.dupe(u8, "");
                            break :blk try allocator.dupe(u8, lt);
                        }
                        break :blk platform_impl.fs.readFile(allocator, full_path) catch try allocator.dupe(u8, "");
                    };
                    defer allocator.free(wt_content);
                    var out = std.array_list.Managed(u8).init(allocator);
                    defer out.deinit();
                    try out.appendSlice("diff --git a/");
                    try out.appendSlice(entry.path);
                    try out.appendSlice(" b/");
                    try out.appendSlice(entry.path);
                    try out.appendSlice("\n");
                    if (entry.mode != wt_mode) {
                        const old_m = try std.fmt.allocPrint(allocator, "old mode {o:0>6}\n", .{entry.mode});
                        defer allocator.free(old_m);
                        try out.appendSlice(old_m);
                        const new_m = try std.fmt.allocPrint(allocator, "new mode {o:0>6}\n", .{wt_mode});
                        defer allocator.free(new_m);
                        try out.appendSlice(new_m);
                    }
                    if (!std.mem.eql(u8, indexed_content, wt_content)) {
                        if (isBinaryContent(indexed_content) or isBinaryContent(wt_content)) {
                            // Add index line for binary
                            if (entry.mode == wt_mode) {
                                const idx_line = try std.fmt.allocPrint(allocator, "index {s}..{s} {o:0>6}\n", .{ hash_buf[0..7], zero_oid[0..7], entry.mode });
                                defer allocator.free(idx_line);
                                try out.appendSlice(idx_line);
                            }
                            try out.appendSlice("Binary files differ\n");
                        } else {
                            // Add index line
                            if (entry.mode == wt_mode) {
                                const idx_line = try std.fmt.allocPrint(allocator, "index {s}..{s} {o:0>6}\n", .{ hash_buf[0..7], zero_oid[0..7], entry.mode });
                                defer allocator.free(idx_line);
                                try out.appendSlice(idx_line);
                            } else {
                                const idx_line = try std.fmt.allocPrint(allocator, "index {s}..{s}\n", .{ hash_buf[0..7], zero_oid[0..7] });
                                defer allocator.free(idx_line);
                                try out.appendSlice(idx_line);
                            }
                            try out.appendSlice("--- a/");
                            try out.appendSlice(entry.path);
                            try out.appendSlice("\n+++ b/");
                            try out.appendSlice(entry.path);
                            try out.appendSlice("\n");
                            const diff_output = diff_mod.generateUnifiedDiffWithHashes(indexed_content, wt_content, entry.path, hash_buf[0..7], zero_oid[0..7], allocator) catch {
                                if (df_patch_with_raw) { try pwr_patch_buf.appendSlice(out.items); } else { try platform_impl.writeStdout(out.items); }
                                continue;
                            };
                            defer allocator.free(diff_output);
                            if (std.mem.indexOf(u8, diff_output, "\n@@")) |hs| {
                                try out.appendSlice(diff_output[hs + 1 ..]);
                            } else if (std.mem.startsWith(u8, diff_output, "@@")) {
                                try out.appendSlice(diff_output);
                            }
                        }
                    }
                    if (df_patch_with_raw) { try pwr_patch_buf.appendSlice(out.items); } else { try platform_impl.writeStdout(out.items); }
                }
            }
        }
    }

    // Output collected patch-with-raw buffers
    if (df_patch_with_raw and pwr_raw_buf.items.len > 0) {
        try platform_impl.writeStdout(pwr_raw_buf.items);
        try platform_impl.writeStdout("\n");
        if (pwr_patch_buf.items.len > 0) try platform_impl.writeStdout(pwr_patch_buf.items);
    }
    if (exit_code and has_diffs) {
        std.process.exit(1);
    }
}

// =============================================================================
// Phase 2: Pure Zig implementations of previously non-native commands
// =============================================================================

fn objectExistsCheck(git_dir: []const u8, hash_hex: *const [40]u8, platform_impl: anytype, allocator: std.mem.Allocator) bool {
    // Check for loose object first (fast stat)
    const obj_path = std.fmt.allocPrint(allocator, "{s}/objects/{s}/{s}", .{ git_dir, hash_hex[0..2], hash_hex[2..] }) catch return false;
    defer allocator.free(obj_path);
    std.fs.cwd().access(obj_path, .{}) catch {
        // Not a loose object — try to load from pack (will use cache)
        const obj = objects.GitObject.load(hash_hex, git_dir, platform_impl, allocator) catch return false;
        obj.deinit(allocator);
        return true;
    };
    return true;
}

fn findGitDir() ![]const u8 {
    // Check --git-dir override first
    if (global_git_dir_override) |gd| return gd;
    // Check GIT_DIR env
    if (std.posix.getenv("GIT_DIR")) |gd| return gd;

    // Check for .git in current directory (normal repo)
    // .git can be a directory (normal) or a file (gitdir link like "gitdir: /path/to/real")
    if (std.fs.cwd().openDir(".git", .{})) |d| {
        var dd = d;
        dd.close();
        return ".git";
    } else |_| {
        // Check if .git is a gitdir link file
        if (std.fs.cwd().readFileAlloc(std.heap.page_allocator, ".git", 4096)) |content| {
            defer std.heap.page_allocator.free(content);
            const trimmed = std.mem.trim(u8, content, " \t\r\n");
            if (std.mem.startsWith(u8, trimmed, "gitdir: ")) {
                return ".git";
            }
        } else |_| {}
    }

    // Check if current directory IS a bare git repo (has HEAD + objects/)
    if (std.fs.cwd().statFile("HEAD")) |_| {
        if (std.fs.cwd().openDir("objects", .{})) |d| {
            var dd = d;
            dd.close();
            return ".";
        } else |_| {}
    } else |_| {}

    // Walk up from cwd looking for .git
    var path_buf: [4096]u8 = undefined;
    const cwd = std.process.getCwd(&path_buf) catch return error.FileNotFound;

    // Check GIT_CEILING_DIRECTORIES - paths that stop upward traversal
    const ceiling_dirs = std.posix.getenv("GIT_CEILING_DIRECTORIES");

    var dir = cwd;
    while (true) {
        if (std.mem.lastIndexOf(u8, dir, "/")) |idx| {
            dir = dir[0..idx];
            if (dir.len == 0) break;
        } else break;

        // Check if we've hit a ceiling directory
        if (ceiling_dirs) |ceilings| {
            var ceil_iter = std.mem.splitScalar(u8, ceilings, ':');
            while (ceil_iter.next()) |ceil| {
                const trimmed_ceil = std.mem.trimRight(u8, ceil, "/");
                if (trimmed_ceil.len == 0) continue;
                if (std.mem.eql(u8, dir, trimmed_ceil)) return error.FileNotFound;
            }
        }

        var check_buf: [4096]u8 = undefined;
        const check_path = std.fmt.bufPrint(&check_buf, "{s}/.git", .{dir}) catch return error.FileNotFound;
        if (std.fs.cwd().statFile(check_path)) |_| {
            return ".git";
        } else |_| {
            if (std.fs.cwd().openDir(check_path, .{})) |d| {
                var dd = d;
                dd.close();
                return ".git";
            } else |_| {}
        }
    }
    return error.FileNotFound;
}

fn nativeCmdCountObjects(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var verbose = false;
    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "-H") or std.mem.eql(u8, arg, "--human-readable")) {
            // human_readable = true;
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git count-objects [-v] [-H | --human-readable]\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Count loose objects — git uses on-disk size (st_blocks * 512)
    var count: usize = 0;
    var size_disk: u64 = 0;
    var size_pack: u64 = 0;
    var packs: usize = 0;
    var in_pack: u64 = 0;
    var size_garbage: u64 = 0;
    var garbage_count: usize = 0;

    const objects_dir_path = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch unreachable;
    defer allocator.free(objects_dir_path);

    var hex_dirs: usize = 0;
    while (hex_dirs < 256) : (hex_dirs += 1) {
        var hex_buf: [2]u8 = undefined;
        _ = std.fmt.bufPrint(&hex_buf, "{x:0>2}", .{hex_dirs}) catch continue;
        const subdir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path, hex_buf }) catch continue;
        defer allocator.free(subdir_path);

        var subdir = std.fs.cwd().openDir(subdir_path, .{ .iterate = true }) catch continue;
        defer subdir.close();

        var iter = subdir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file) {
                count += 1;
                const file = subdir.openFile(entry.name, .{}) catch continue;
                defer file.close();
                const linux_stat = std.posix.fstat(file.handle) catch continue;
                size_disk += @as(u64, @intCast(linux_stat.blocks)) * 512;
            }
        }
    }

    // Count pack files and objects in packs
    const pack_dir_path = std.fmt.allocPrint(allocator, "{s}/objects/pack", .{git_dir}) catch unreachable;
    defer allocator.free(pack_dir_path);

    if (std.fs.cwd().openDir(pack_dir_path, .{ .iterate = true })) |pack_dir_handle| {
        var pd = pack_dir_handle;
        defer pd.close();

        var pack_iter = pd.iterate();
        while (pack_iter.next() catch null) |entry| {
            if (entry.kind == .file) {
                if (std.mem.endsWith(u8, entry.name, ".pack")) {
                    packs += 1;
                    const pf_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir_path, entry.name }) catch continue;
                    defer allocator.free(pf_path);
                    const stat = std.fs.cwd().statFile(pf_path) catch continue;
                    size_pack += stat.size;
                    // Count objects by reading pack header
                    const pf = std.fs.cwd().openFile(pf_path, .{}) catch continue;
                    defer pf.close();
                    var hdr_buf: [12]u8 = undefined;
                    const hdr_read = pf.readAll(&hdr_buf) catch continue;
                    if (hdr_read == 12 and std.mem.eql(u8, hdr_buf[0..4], "PACK")) {
                        in_pack += std.mem.readInt(u32, hdr_buf[8..12], .big);
                    }
                } else if (std.mem.endsWith(u8, entry.name, ".idx")) {
                    // Git includes .idx size in size-pack
                    const idx_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir_path, entry.name }) catch continue;
                    defer allocator.free(idx_path);
                    const stat = std.fs.cwd().statFile(idx_path) catch continue;
                    size_pack += stat.size;
                } else if (!std.mem.endsWith(u8, entry.name, ".keep") and
                    !std.mem.endsWith(u8, entry.name, ".bitmap") and
                    !std.mem.endsWith(u8, entry.name, ".rev") and
                    !std.mem.endsWith(u8, entry.name, ".mtimes") and
                    !std.mem.endsWith(u8, entry.name, ".promisor"))
                {
                    garbage_count += 1;
                    const garb_file = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir_path, entry.name }) catch continue;
                    defer allocator.free(garb_file);
                    const stat = std.fs.cwd().statFile(garb_file) catch continue;
                    size_garbage += stat.size;
                }
            }
        }
    } else |_| {}

    const size_kb = size_disk / 1024;

    if (verbose) {
        const output = std.fmt.allocPrint(allocator,
            "count: {d}\nsize: {d}\nin-pack: {d}\npacks: {d}\nsize-pack: {d}\nprune-packable: 0\ngarbage: {d}\nsize-garbage: {d}\n",
            .{ count, size_kb, in_pack, packs, size_pack / 1024, garbage_count, size_garbage / 1024 },
        ) catch unreachable;
        defer allocator.free(output);
        try platform_impl.writeStdout(output);

        // Show alternates from info/alternates (recursively)
        {
            var visited = std.StringHashMap(void).init(allocator);
            defer {
                var vit = visited.iterator();
                while (vit.next()) |entry| allocator.free(entry.key_ptr.*);
                visited.deinit();
            }
            var to_visit = std.ArrayListUnmanaged([]const u8){};
            defer {
                for (to_visit.items) |item| allocator.free(item);
                to_visit.deinit(allocator);
            }

            // Start with this repo's objects dir
            const start_obj_dir = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch unreachable;
            try to_visit.append(allocator, start_obj_dir);

            while (to_visit.items.len > 0) {
                const obj_dir = to_visit.orderedRemove(0);
                defer allocator.free(obj_dir);

                const info_alt = std.fmt.allocPrint(allocator, "{s}/info/alternates", .{obj_dir}) catch continue;
                defer allocator.free(info_alt);
                const alt_content = std.fs.cwd().readFileAlloc(allocator, info_alt, 1024 * 1024) catch continue;
                defer allocator.free(alt_content);
                var alt_lines = std.mem.splitScalar(u8, alt_content, '\n');
                while (alt_lines.next()) |aline| {
                    const atrimmed = std.mem.trim(u8, aline, " \t\r");
                    if (atrimmed.len == 0) continue;
                    // Resolve relative paths
                    const abs_alt = if (!std.fs.path.isAbsolute(atrimmed)) blk: {
                        const rel = std.fmt.allocPrint(allocator, "{s}/{s}", .{ obj_dir, atrimmed }) catch continue;
                        defer allocator.free(rel);
                        break :blk std.fs.cwd().realpathAlloc(allocator, rel) catch continue;
                    } else std.fs.cwd().realpathAlloc(allocator, atrimmed) catch try allocator.dupe(u8, atrimmed);
                    defer allocator.free(abs_alt);

                    if (visited.contains(abs_alt)) continue;
                    try visited.put(try allocator.dupe(u8, abs_alt), {});

                    const alt_out = std.fmt.allocPrint(allocator, "alternate: {s}\n", .{abs_alt}) catch continue;
                    defer allocator.free(alt_out);
                    try platform_impl.writeStdout(alt_out);

                    // Queue for recursive visiting
                    try to_visit.append(allocator, try allocator.dupe(u8, abs_alt));
                }
            }
        }
    } else {
        const output = std.fmt.allocPrint(allocator, "{d} objects, {d} kilobytes\n", .{ count, size_kb }) catch unreachable;
        defer allocator.free(output);
        try platform_impl.writeStdout(output);
    }
}

fn nativeCmdShowRef(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var verify = false;
    var exists_mode = false;
    var quiet = false;
    var heads = false;
    var tags = false;
    var hash_only = false;
    var hash_len: usize = 40;
    var dereference = false;
    var patterns = std.array_list.Managed([]const u8).init(allocator);
    defer patterns.deinit();

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git show-ref [--head] [-d | --dereference] [-s | --hash[=<n>]] [--verify] [-q | --quiet] [--tags] [--heads] [--] [<pattern>...]\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--exists")) {
            exists_mode = true;
        } else if (std.mem.eql(u8, arg, "--verify")) {
            verify = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--heads")) {
            heads = true;
        } else if (std.mem.eql(u8, arg, "--tags")) {
            tags = true;
        } else if (std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "--dereference")) {
            dereference = true;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--hash")) {
            hash_only = true;
        } else if (std.mem.startsWith(u8, arg, "--hash=")) {
            hash_only = true;
            hash_len = std.fmt.parseInt(usize, arg["--hash=".len..], 10) catch 40;
        } else if (std.mem.eql(u8, arg, "--head")) {
            // Include HEAD in output
        } else if (std.mem.eql(u8, arg, "--")) {
            i += 1;
            while (i < args.len) : (i += 1) {
                try patterns.append(args[i]);
            }
            break;
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try patterns.append(arg);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    if (exists_mode) {
        // --exists mode: check if a single ref exists, exit 0 if yes, 2 if no
        if (patterns.items.len < 1) {
            try platform_impl.writeStderr("error: --exists requires a ref argument\n");
            std.process.exit(129);
            unreachable;
        }
        const ref_name = patterns.items[0];
        // Check if the ref file or packed-ref entry exists (even dangling symrefs count)
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name });
        defer allocator.free(ref_path);
        if (std.fs.cwd().access(ref_path, .{})) |_| {
            // Check if it's a directory (directories are not refs)
            const stat = std.fs.cwd().statFile(ref_path) catch return; // can't stat, assume it exists
            if (stat.kind == .directory) {
                try platform_impl.writeStderr("error: reference does not exist\n");
                std.process.exit(2);
                unreachable;
            }
            return; // exists (even if symref is dangling)
        } else |_| {
            // Check packed-refs
            const packed_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir});
            defer allocator.free(packed_path);
            const packed_data = platform_impl.fs.readFile(allocator, packed_path) catch {
                try platform_impl.writeStderr("error: reference does not exist\n");
                std.process.exit(2);
                unreachable;
            };
            defer allocator.free(packed_data);
            var lines = std.mem.splitScalar(u8, packed_data, '\n');
            while (lines.next()) |line| {
                if (line.len == 0 or line[0] == '#') continue;
                if (line.len >= 41 and line[40] == ' ') {
                    const packed_ref = std.mem.trim(u8, line[41..], " \t\r");
                    if (std.mem.eql(u8, packed_ref, ref_name)) return; // exists in packed-refs
                }
            }
            try platform_impl.writeStderr("error: reference does not exist\n");
            std.process.exit(2);
            unreachable;
        }
    }
    
    if (verify) {
        // Verify mode: check specific refs (read direct ref value, no tag dereferencing)
        var found_any = false;
        for (patterns.items) |pattern| {
            const resolved = readRefDirect(git_dir, pattern, allocator, platform_impl) catch null;
            if (resolved == null) {
                if (!quiet) {
                    const msg = std.fmt.allocPrint(allocator, "fatal: '{s}' - not a valid ref\n", .{pattern}) catch continue;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                }
                continue;
            }
            if (resolved) |hash| {
                defer allocator.free(hash);
                found_any = true;
                if (!quiet) {
                    const end = @min(hash_len, hash.len);
                    if (hash_only) {
                        const output = std.fmt.allocPrint(allocator, "{s}\n", .{hash[0..end]}) catch continue;
                        defer allocator.free(output);
                        try platform_impl.writeStdout(output);
                    } else {
                        const output = std.fmt.allocPrint(allocator, "{s} {s}\n", .{ hash[0..end], pattern }) catch continue;
                        defer allocator.free(output);
                        try platform_impl.writeStdout(output);
                    }
                }
            } else {
                if (!quiet) {
                    const msg = std.fmt.allocPrint(allocator, "fatal: '{s}' - not a valid ref\n", .{pattern}) catch continue;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                }
            }
        }
        if (!found_any) {
            std.process.exit(1);
        }
        return;
    }

    // List mode: enumerate all refs
    var ref_list = std.array_list.Managed(RefEntry).init(allocator);
    defer {
        for (ref_list.items) |entry| {
            allocator.free(entry.name);
            allocator.free(entry.hash);
        }
        ref_list.deinit();
    }

    // Read packed-refs
    const packed_refs_path = std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir}) catch unreachable;
    defer allocator.free(packed_refs_path);
    if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_content| {
        defer allocator.free(packed_content);
        var lines = std.mem.splitScalar(u8, packed_content, '\n');
        while (lines.next()) |line| {
            if (line.len == 0 or line[0] == '#') continue;
            if (line[0] == '^') continue; // peeled line, handled separately
            // format: <hash> <refname>
            if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                const hash = line[0..space_idx];
                const name = line[space_idx + 1..];
                if (hash.len >= 40) {
                    try ref_list.append(.{
                        .name = try allocator.dupe(u8, name),
                        .hash = try allocator.dupe(u8, hash[0..40]),
                    });
                }
            }
        }
    } else |_| {}

    // Read loose refs
    try collectLooseRefs(allocator, git_dir, "refs", &ref_list, platform_impl);

    // Sort by name
    std.mem.sort(RefEntry, ref_list.items, {}, struct {
        fn lessThan(_: void, a: RefEntry, b: RefEntry) bool {
            return std.mem.order(u8, a.name, b.name).compare(.lt);
        }
    }.lessThan);

    // Filter and output
    var found = false;
    for (ref_list.items) |entry| {
        // Skip broken refs
        if (entry.broken) continue;

        // Apply filters
        if (heads and !std.mem.startsWith(u8, entry.name, "refs/heads/")) continue;
        if (tags and !std.mem.startsWith(u8, entry.name, "refs/tags/")) continue;

        // Apply patterns (match as suffix after /)
        if (patterns.items.len > 0) {
            var matches = false;
            for (patterns.items) |pattern| {
                // Exact match
                if (std.mem.eql(u8, entry.name, pattern)) {
                    matches = true;
                    break;
                }
                // Pattern matches as a suffix after /
                if (std.mem.endsWith(u8, entry.name, pattern)) {
                    // Check there's a / before the match
                    if (entry.name.len > pattern.len and entry.name[entry.name.len - pattern.len - 1] == '/') {
                        matches = true;
                        break;
                    }
                }
                // Pattern with / matches as prefix
                if (std.mem.indexOf(u8, pattern, "/") != null) {
                    if (std.mem.endsWith(u8, entry.name, pattern)) {
                        matches = true;
                        break;
                    }
                }
            }
            if (!matches) continue;
        }

        found = true;
        if (quiet) continue;

        const end = @min(hash_len, entry.hash.len);
        if (hash_only) {
            const output = std.fmt.allocPrint(allocator, "{s}\n", .{entry.hash[0..end]}) catch continue;
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else {
            const output = std.fmt.allocPrint(allocator, "{s} {s}\n", .{ entry.hash[0..end], entry.name }) catch continue;
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        }

        // Dereference tag objects (for any ref, not just refs/tags/)
        if (dereference) {
            // Try to load the object and check if it's a tag
            if (objects.GitObject.load(entry.hash, git_dir, platform_impl, allocator)) |obj| {
                defer obj.deinit(allocator);
                if (obj.type == .tag) {
                    // Parse tag to find object it points to
                    if (std.mem.indexOf(u8, obj.data, "object ")) |obj_start| {
                        const hash_start = obj_start + 7;
                        if (hash_start + 40 <= obj.data.len) {
                            const target_hash = obj.data[hash_start..hash_start + 40];
                            const deref_output = std.fmt.allocPrint(allocator, "{s} {s}^{{}}\n", .{ target_hash, entry.name }) catch continue;
                            defer allocator.free(deref_output);
                            try platform_impl.writeStdout(deref_output);
                        }
                    }
                }
            } else |_| {}
        }
    }

    if (!found) {
        std.process.exit(1);
    }
}

const RefEntry = struct {
    name: []const u8,
    hash: []const u8,
    broken: bool = false,
};

fn collectLooseRefs(allocator: std.mem.Allocator, git_dir: []const u8, prefix: []const u8, ref_list: *std.array_list.Managed(RefEntry), platform_impl: anytype) !void {
    const dir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, prefix }) catch return;
    defer allocator.free(dir_path);

    var dir = std.fs.cwd().openDir(dir_path, .{ .iterate = true }) catch return;
    defer dir.close();

    var iter = dir.iterate();
    while (iter.next() catch null) |entry| {
        const full_name = std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name }) catch continue;

        if (entry.kind == .directory) {
            try collectLooseRefs(allocator, git_dir, full_name, ref_list, platform_impl);
            allocator.free(full_name);
        } else if (entry.kind == .file) {
            const file_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, full_name }) catch {
                allocator.free(full_name);
                continue;
            };
            defer allocator.free(file_path);

            const content = std.fs.cwd().readFileAlloc(allocator, file_path, 1024) catch {
                // Empty or unreadable file = broken ref
                try ref_list.append(.{
                    .name = full_name,
                    .hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                    .broken = true,
                });
                continue;
            };
            defer allocator.free(content);
            const trimmed = std.mem.trim(u8, content, " \t\n\r");
            if (trimmed.len == 0) {
                // Empty ref file = broken ref
                try ref_list.append(.{
                    .name = full_name,
                    .hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                    .broken = true,
                });
                continue;
            }
            // Handle symbolic refs (ref: refs/...)
            if (std.mem.startsWith(u8, trimmed, "ref: ")) {
                const target_ref = trimmed["ref: ".len..];
                const resolved = refs.resolveRef(git_dir, target_ref, platform_impl, allocator) catch {
                    try ref_list.append(.{ .name = full_name, .hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"), .broken = true });
                    continue;
                };
                if (resolved) |rh| {
                    var found_p = false;
                    for (ref_list.items, 0..) |ex, idx| {
                        if (std.mem.eql(u8, ex.name, full_name)) {
                            allocator.free(ex.hash);
                            ref_list.items[idx].hash = rh;
                            ref_list.items[idx].broken = false;
                            found_p = true;
                            allocator.free(full_name);
                            break;
                        }
                    }
                    if (!found_p) try ref_list.append(.{ .name = full_name, .hash = rh, .broken = false });
                } else {
                    try ref_list.append(.{ .name = full_name, .hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"), .broken = true });
                }
                continue;
            }
            if (trimmed.len >= 40) {
                const hash_val = trimmed[0..40];
                const is_null = std.mem.eql(u8, hash_val, "0000000000000000000000000000000000000000");

                // Check if this overrides a packed ref
                var found_packed = false;
                for (ref_list.items, 0..) |existing, idx| {
                    if (std.mem.eql(u8, existing.name, full_name)) {
                        // Replace packed ref with loose ref
                        allocator.free(existing.hash);
                        ref_list.items[idx].hash = allocator.dupe(u8, hash_val) catch {
                            allocator.free(full_name);
                            continue;
                        };
                        ref_list.items[idx].broken = is_null;
                        found_packed = true;
                        allocator.free(full_name);
                        break;
                    }
                }
                if (!found_packed) {
                    try ref_list.append(.{
                        .name = full_name,
                        .hash = try allocator.dupe(u8, hash_val),
                        .broken = is_null,
                    });
                }
            } else {
                // Too short to be a valid hash = broken ref
                try ref_list.append(.{
                    .name = full_name,
                    .hash = try allocator.dupe(u8, "0000000000000000000000000000000000000000"),
                    .broken = true,
                });
            }
        } else {
            allocator.free(full_name);
        }
    }
}

fn nativeCmdForEachRef(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var format: []const u8 = "%(objectname) %(objecttype)\t%(refname)";
    var sort_key: ?[]const u8 = null;
    var sort_reverse = false;
    var count_limit: ?usize = null;
    var quoting_style: enum { none, shell, perl, python, tcl } = .none;
    var patterns = std.array_list.Managed([]const u8).init(allocator);
    defer patterns.deinit();
    var exclude_patterns = std.array_list.Managed([]const u8).init(allocator);
    defer exclude_patterns.deinit();
    var omit_empty = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git for-each-ref [<options>] [<pattern>...]\n");
            std.process.exit(129);
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            format = arg["--format=".len..];
        } else if (std.mem.eql(u8, arg, "--format")) {
            i += 1;
            if (i < args.len) format = args[i];
        } else if (std.mem.startsWith(u8, arg, "--sort=")) {
            const sk = arg["--sort=".len..];
            if (sk.len > 0 and sk[0] == '-') {
                sort_key = sk[1..];
                sort_reverse = true;
            } else {
                sort_key = sk;
                sort_reverse = false;
            }
        } else if (std.mem.eql(u8, arg, "--sort")) {
            i += 1;
            if (i < args.len) {
                const sk = args[i];
                if (sk.len > 0 and sk[0] == '-') {
                    sort_key = sk[1..];
                    sort_reverse = true;
                } else {
                    sort_key = sk;
                    sort_reverse = false;
                }
            }
        } else if (std.mem.startsWith(u8, arg, "--count=")) {
            count_limit = std.fmt.parseInt(usize, arg["--count=".len..], 10) catch null;
        } else if (std.mem.eql(u8, arg, "--count")) {
            i += 1;
            if (i < args.len) count_limit = std.fmt.parseInt(usize, args[i], 10) catch null;
        } else if (std.mem.eql(u8, arg, "--shell") or std.mem.eql(u8, arg, "-s")) {
            if (quoting_style != .none) {
                try platform_impl.writeStderr("error: more than one quoting style?\n");
                std.process.exit(1);
            }
            quoting_style = .shell;
        } else if (std.mem.eql(u8, arg, "--perl") or std.mem.eql(u8, arg, "-p")) {
            if (quoting_style != .none) {
                try platform_impl.writeStderr("error: more than one quoting style?\n");
                std.process.exit(1);
            }
            quoting_style = .perl;
        } else if (std.mem.eql(u8, arg, "--python")) {
            if (quoting_style != .none) {
                try platform_impl.writeStderr("error: more than one quoting style?\n");
                std.process.exit(1);
            }
            quoting_style = .python;
        } else if (std.mem.eql(u8, arg, "--tcl")) {
            if (quoting_style != .none) {
                try platform_impl.writeStderr("error: more than one quoting style?\n");
                std.process.exit(1);
            }
            quoting_style = .tcl;
        } else if (std.mem.startsWith(u8, arg, "--exclude=")) {
            try exclude_patterns.append(arg["--exclude=".len..]);
        } else if (std.mem.eql(u8, arg, "--exclude")) {
            i += 1;
            if (i < args.len) try exclude_patterns.append(args[i]);
        } else if (std.mem.eql(u8, arg, "--ignore-case")) {
            // Accept silently for now
        } else if (std.mem.eql(u8, arg, "--omit-empty")) {
            omit_empty = true;
        } else if (std.mem.eql(u8, arg, "--no-sort")) {
            sort_key = null;
            sort_reverse = false;
        } else if (std.mem.eql(u8, arg, "--color") or std.mem.startsWith(u8, arg, "--color=")) {
            // Accept silently
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            // Read patterns from stdin
            const stdin_data = read_stdin_blk: {
                var buf2 = std.array_list.Managed(u8).init(allocator);
                var tmp2: [4096]u8 = undefined;
                while (true) {
                    const n2 = std.posix.read(0, &tmp2) catch break;
                    if (n2 == 0) break;
                    buf2.appendSlice(tmp2[0..n2]) catch break;
                }
                break :read_stdin_blk buf2.toOwnedSlice() catch "";
            };
            defer if (stdin_data.len > 0) allocator.free(stdin_data);
            var stdin_lines = std.mem.splitScalar(u8, stdin_data, '\n');
            while (stdin_lines.next()) |line| {
                const trimmed2 = std.mem.trim(u8, line, " \t\r");
                if (trimmed2.len > 0) try patterns.append(trimmed2);
            }
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try patterns.append(arg);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Validate format atoms
    {
        var vidx: usize = 0;
        while (vidx < format.len) {
            if (format[vidx] == '%' and vidx + 1 < format.len and format[vidx + 1] == '%') {
                vidx += 2;
                continue;
            }
            if (format[vidx] == '%' and vidx + 1 < format.len and format[vidx + 1] == '(') {
                if (std.mem.indexOfScalar(u8, format[vidx..], ')')) |close| {
                    const field = format[vidx + 2 .. vidx + close];
                    const validation = validateFormatAtom(field, allocator);
                    if (!validation.valid) {
                        if (validation.err_msg) |err_msg| {
                            defer allocator.free(err_msg);
                            try platform_impl.writeStderr(err_msg);
                        } else {
                            const msg = try std.fmt.allocPrint(allocator, "fatal: unknown field name: {s}\n", .{field});
                            defer allocator.free(msg);
                            try platform_impl.writeStderr(msg);
                        }
                        std.process.exit(1);
                    }
                    if (validation.err_msg) |err_msg| allocator.free(err_msg);
                    vidx += close + 1;
                    continue;
                }
            }
            vidx += 1;
        }
    }

    // Collect all refs
    var ref_list = std.array_list.Managed(RefEntry).init(allocator);
    defer {
        for (ref_list.items) |entry| {
            allocator.free(entry.name);
            allocator.free(entry.hash);
        }
        ref_list.deinit();
    }

    // Read packed-refs
    const packed_refs_path = std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir}) catch unreachable;
    defer allocator.free(packed_refs_path);
    if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_content| {
        defer allocator.free(packed_content);
        // Check for unterminated last line
        if (packed_content.len > 0 and packed_content[packed_content.len - 1] != '\n') {
            // Find the last line
            const last_nl = std.mem.lastIndexOfScalar(u8, packed_content, '\n');
            const last_line = if (last_nl) |nl| packed_content[nl + 1 ..] else packed_content;
            if (last_line.len > 0 and last_line[0] != '#') {
                const msg = try std.fmt.allocPrint(allocator, "fatal: unterminated line in {s}: {s}\n", .{ packed_refs_path, last_line });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }
        }
        var lines = std.mem.splitScalar(u8, packed_content, '\n');
        while (lines.next()) |line| {
            if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
            if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                const hash = line[0..space_idx];
                const name = line[space_idx + 1..];
                if (hash.len < 40 or !isValidHexString(hash[0..@min(40, hash.len)])) {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: unexpected line in {s}: {s}\n", .{ packed_refs_path, line });
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                }
                try ref_list.append(.{
                    .name = try allocator.dupe(u8, name),
                    .hash = try allocator.dupe(u8, hash[0..40]),
                });
            } else {
                // Line without space - invalid
                const msg = try std.fmt.allocPrint(allocator, "fatal: unexpected line in {s}: {s}\n", .{ packed_refs_path, line });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }
        }
    } else |_| {}

    try collectLooseRefs(allocator, git_dir, "refs", &ref_list, platform_impl);

    // Sort
    if (sort_reverse) {
        std.mem.sort(RefEntry, ref_list.items, {}, struct {
            fn lessThan(_: void, a: RefEntry, b: RefEntry) bool {
                return std.mem.order(u8, a.name, b.name).compare(.gt);
            }
        }.lessThan);
    } else {
        std.mem.sort(RefEntry, ref_list.items, {}, struct {
            fn lessThan(_: void, a: RefEntry, b: RefEntry) bool {
                return std.mem.order(u8, a.name, b.name).compare(.lt);
            }
        }.lessThan);
    }

    // Filter and format output
    var output_count: usize = 0;
    for (ref_list.items) |entry| {
        if (count_limit) |limit| {
            if (output_count >= limit) break;
        }

        // Handle broken refs - emit warning and skip
        if (entry.broken) {
            const warn_msg = std.fmt.allocPrint(allocator, "warning: ignoring broken ref {s}\n", .{entry.name}) catch continue;
            defer allocator.free(warn_msg);
            try platform_impl.writeStderr(warn_msg);
            continue;
        }

        // Apply patterns (prefix match, with glob support for * and ?)
        if (patterns.items.len > 0) {
            var matches = false;
            for (patterns.items) |pattern| {
                if (refPatternMatch(entry.name, pattern)) {
                    matches = true;
                    break;
                }
            }
            if (!matches) continue;
        }

        // Check exclude patterns
        if (exclude_patterns.items.len > 0) {
            var excluded = false;
            for (exclude_patterns.items) |excl_pattern| {
                if (refPatternMatch(entry.name, excl_pattern)) {
                    excluded = true;
                    break;
                }
            }
            if (excluded) continue;
        }

        // Determine object type
        var obj_type: []const u8 = "commit";
        if (objects.GitObject.load(entry.hash, git_dir, platform_impl, allocator)) |obj| {
            obj_type = obj.type.toString();
            defer obj.deinit(allocator);

            const formatted = try formatRefOutput(allocator, format, entry.name, entry.hash, obj_type, obj.data, quoting_style);
            defer allocator.free(formatted);
            const output = std.fmt.allocPrint(allocator, "{s}\n", .{formatted}) catch continue;
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        } else |_| {
            const formatted = try formatRefOutput(allocator, format, entry.name, entry.hash, obj_type, "", quoting_style);
            defer allocator.free(formatted);
            const output = std.fmt.allocPrint(allocator, "{s}\n", .{formatted}) catch continue;
            defer allocator.free(output);
            try platform_impl.writeStdout(output);
        }
        output_count += 1;
    }
}

fn formatRefOutput(allocator: std.mem.Allocator, format: []const u8, refname: []const u8, objectname: []const u8, objecttype: []const u8, data: []const u8, quoting: anytype) ![]u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();

    var idx: usize = 0;
    while (idx < format.len) {
        if (format[idx] == '%' and idx + 1 < format.len and format[idx + 1] == '(') {
            if (std.mem.indexOfScalar(u8, format[idx..], ')')) |close| {
                const field = format[idx + 2 .. idx + close];
                const value = getRefField(field, refname, objectname, objecttype, data, allocator);
                // Apply quoting
                switch (quoting) {
                    .shell => {
                        try result.append('\'');
                        for (value) |c| {
                            if (c == '\'') {
                                try result.appendSlice("'\\''");
                            } else {
                                try result.append(c);
                            }
                        }
                        try result.append('\'');
                    },
                    .perl => {
                        try result.append('\'');
                        for (value) |c| {
                            if (c == '\'') {
                                try result.appendSlice("'\\''");
                            } else {
                                try result.append(c);
                            }
                        }
                        try result.append('\'');
                    },
                    .python => {
                        try result.append('\'');
                        for (value) |c| {
                            if (c == '\'') {
                                try result.appendSlice("'\\''");
                            } else {
                                try result.append(c);
                            }
                        }
                        try result.append('\'');
                    },
                    .tcl => {
                        try result.append('"');
                        for (value) |c| {
                            if (c == '"' or c == '\\' or c == '$' or c == '[' or c == ']' or c == '{' or c == '}') {
                                try result.append('\\');
                            }
                            try result.append(c);
                        }
                        try result.append('"');
                    },
                    .none => {
                        try result.appendSlice(value);
                    },
                }
                idx += close + 1;
                continue;
            }
        }
        if (format[idx] == '%' and idx + 1 < format.len and format[idx + 1] == '%') {
            try result.append('%');
            idx += 2;
        } else {
            try result.append(format[idx]);
            idx += 1;
        }
    }
    return result.toOwnedSlice();
}

fn getRefField(field: []const u8, refname: []const u8, objectname: []const u8, objecttype: []const u8, data: []const u8, allocator: std.mem.Allocator) []const u8 {
    // refname and refname: (trailing colon = same as bare refname)
    if (std.mem.eql(u8, field, "refname") or std.mem.eql(u8, field, "refname:")) return refname;
    if (std.mem.eql(u8, field, "refname:short")) {
        if (std.mem.startsWith(u8, refname, "refs/heads/")) return refname["refs/heads/".len..];
        if (std.mem.startsWith(u8, refname, "refs/tags/")) return refname["refs/tags/".len..];
        if (std.mem.startsWith(u8, refname, "refs/remotes/")) return refname["refs/remotes/".len..];
        return refname;
    }
    if (std.mem.startsWith(u8, field, "refname:lstrip=") or std.mem.startsWith(u8, field, "refname:strip=")) {
        const eq_pos = std.mem.indexOfScalar(u8, field, '=') orelse return refname;
        return applyLstrip(refname, field[eq_pos + 1 ..]);
    }
    if (std.mem.startsWith(u8, field, "refname:rstrip=")) {
        return applyRstrip(refname, field["refname:rstrip=".len..]);
    }

    if (std.mem.eql(u8, field, "objectname") or std.mem.eql(u8, field, "objectname:")) return objectname;
    if (std.mem.eql(u8, field, "objectname:short")) return if (objectname.len >= 7) objectname[0..7] else objectname;
    if (std.mem.startsWith(u8, field, "objectname:short=")) {
        const n = std.fmt.parseInt(usize, field["objectname:short=".len..], 10) catch return objectname;
        const len = @max(n, 1);
        return objectname[0..@min(len, objectname.len)];
    }
    if (std.mem.eql(u8, field, "objecttype")) return objecttype;

    if (std.mem.eql(u8, field, "objectsize")) {
        return std.fmt.allocPrint(allocator, "{d}", .{data.len}) catch return "";
    }
    if (std.mem.eql(u8, field, "objectsize:disk")) {
        return std.fmt.allocPrint(allocator, "{d}", .{data.len}) catch return "";
    }

    if (std.mem.eql(u8, field, "deltabase") or std.mem.eql(u8, field, "*deltabase")) {
        return "0000000000000000000000000000000000000000";
    }

    // tree field
    if (std.mem.startsWith(u8, field, "tree")) {
        if (!std.mem.eql(u8, objecttype, "commit")) return "";
        const tree_hash = extractHeaderField(data, "tree");
        if (tree_hash.len == 0) return "";
        if (std.mem.eql(u8, field, "tree") or std.mem.eql(u8, field, "tree:")) return tree_hash;
        if (std.mem.eql(u8, field, "tree:short")) return if (tree_hash.len >= 7) tree_hash[0..7] else tree_hash;
        if (std.mem.startsWith(u8, field, "tree:short=")) {
            const n = std.fmt.parseInt(usize, field["tree:short=".len..], 10) catch return tree_hash;
            return tree_hash[0..@min(@max(n, 1), tree_hash.len)];
        }
        return tree_hash;
    }

    // parent field
    if (std.mem.startsWith(u8, field, "parent")) {
        if (!std.mem.eql(u8, objecttype, "commit")) return "";
        const first_parent = extractHeaderField(data, "parent");
        if (std.mem.eql(u8, field, "parent") or std.mem.eql(u8, field, "parent:")) return first_parent;
        if (std.mem.eql(u8, field, "parent:short")) return if (first_parent.len >= 7) first_parent[0..7] else first_parent;
        if (std.mem.startsWith(u8, field, "parent:short=")) {
            const n = std.fmt.parseInt(usize, field["parent:short=".len..], 10) catch return first_parent;
            if (first_parent.len == 0) return first_parent;
            return first_parent[0..@min(@max(n, 1), first_parent.len)];
        }
        return first_parent;
    }

    if (std.mem.eql(u8, field, "numparent")) {
        if (!std.mem.eql(u8, objecttype, "commit")) return "";
        var count: usize = 0;
        var lines_iter = std.mem.splitScalar(u8, data, '\n');
        while (lines_iter.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ")) count += 1
            else if (line.len == 0) break;
        }
        return std.fmt.allocPrint(allocator, "{d}", .{count}) catch return "0";
    }

    // author fields
    if (std.mem.startsWith(u8, field, "author")) {
        if (!std.mem.eql(u8, objecttype, "commit")) return "";
        return extractPersonField(field["author".len..], extractHeaderField(data, "author"), allocator);
    }

    // committer fields
    if (std.mem.startsWith(u8, field, "committer")) {
        if (!std.mem.eql(u8, objecttype, "commit")) return "";
        return extractPersonField(field["committer".len..], extractHeaderField(data, "committer"), allocator);
    }

    // tagger fields
    if (std.mem.startsWith(u8, field, "tagger")) {
        if (!std.mem.eql(u8, objecttype, "tag")) return "";
        return extractPersonField(field["tagger".len..], extractHeaderField(data, "tagger"), allocator);
    }

    if (std.mem.eql(u8, field, "tag")) {
        if (!std.mem.eql(u8, objecttype, "tag")) return "";
        return extractHeaderField(data, "tag");
    }
    if (std.mem.eql(u8, field, "type")) {
        if (!std.mem.eql(u8, objecttype, "tag")) return "";
        return extractHeaderField(data, "type");
    }
    if (std.mem.eql(u8, field, "object")) {
        if (!std.mem.eql(u8, objecttype, "tag")) return "";
        return extractHeaderField(data, "object");
    }
    if (std.mem.eql(u8, field, "*objectname")) {
        if (!std.mem.eql(u8, objecttype, "tag")) return "";
        return extractHeaderField(data, "object");
    }
    if (std.mem.eql(u8, field, "*objecttype")) {
        if (!std.mem.eql(u8, objecttype, "tag")) return "";
        return extractHeaderField(data, "type");
    }

    if (std.mem.eql(u8, field, "raw")) return data;
    if (std.mem.eql(u8, field, "*raw")) return "";

    if (std.mem.eql(u8, field, "creator")) {
        if (std.mem.eql(u8, objecttype, "commit")) return extractHeaderField(data, "committer")
        else if (std.mem.eql(u8, objecttype, "tag")) return extractHeaderField(data, "tagger");
        return "";
    }
    if (std.mem.eql(u8, field, "creatordate")) {
        const pl = if (std.mem.eql(u8, objecttype, "commit")) extractHeaderField(data, "committer")
        else if (std.mem.eql(u8, objecttype, "tag")) extractHeaderField(data, "tagger")
        else "";
        if (pl.len == 0) return "";
        return formatPersonDate(pl, allocator);
    }

    if (std.mem.eql(u8, field, "subject")) {
        const message = extractObjectMessage(data);
        const clean_msg = stripCR(allocator, message) catch message;
        return joinLines(allocator, extractSubject(clean_msg)) catch extractSubject(clean_msg);
    }
    if (std.mem.eql(u8, field, "subject:sanitize")) {
        const message = extractObjectMessage(data);
        const clean_msg = stripCR(allocator, message) catch message;
        const joined = joinLines(allocator, extractSubject(clean_msg)) catch extractSubject(clean_msg);
        return sanitizeSubject(allocator, joined) catch joined;
    }

    if (std.mem.eql(u8, field, "body")) return extractBody(extractObjectMessage(data));

    if (std.mem.eql(u8, field, "HEAD")) {
        const git_dir = findGitDir() catch return " ";
        const head_path = std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_dir}) catch return " ";
        defer allocator.free(head_path);
        const head_content = std.fs.cwd().readFileAlloc(allocator, head_path, 4096) catch return " ";
        defer allocator.free(head_content);
        const trimmed = std.mem.trimRight(u8, head_content, "\n\r ");
        if (std.mem.startsWith(u8, trimmed, "ref: ")) {
            if (std.mem.eql(u8, trimmed["ref: ".len..], refname)) return "*" else return " ";
        }
        return " ";
    }

    if (std.mem.startsWith(u8, field, "upstream")) {
        const upstream_ref = resolveUpstreamRef(refname, allocator) catch return "";
        if (upstream_ref.len == 0) return "";
        if (std.mem.eql(u8, field, "upstream")) return upstream_ref;
        if (std.mem.eql(u8, field, "upstream:short")) {
            if (std.mem.startsWith(u8, upstream_ref, "refs/remotes/")) return upstream_ref["refs/remotes/".len..];
            return upstream_ref;
        }
        if (std.mem.startsWith(u8, field, "upstream:lstrip=") or std.mem.startsWith(u8, field, "upstream:strip=")) {
            const eq = std.mem.indexOfScalar(u8, field, '=') orelse return upstream_ref;
            return applyLstrip(upstream_ref, field[eq + 1 ..]);
        }
        if (std.mem.startsWith(u8, field, "upstream:rstrip=")) {
            return applyRstrip(upstream_ref, field["upstream:rstrip=".len..]);
        }
        // track/trackshort/nobracket - return empty for now
        return "";
    }
    if (std.mem.startsWith(u8, field, "push")) {
        const push_ref = resolvePushRef(refname, allocator) catch return "";
        if (push_ref.len == 0) return "";
        if (std.mem.eql(u8, field, "push")) return push_ref;
        if (std.mem.eql(u8, field, "push:short")) {
            if (std.mem.startsWith(u8, push_ref, "refs/remotes/")) return push_ref["refs/remotes/".len..];
            return push_ref;
        }
        if (std.mem.startsWith(u8, field, "push:lstrip=") or std.mem.startsWith(u8, field, "push:strip=")) {
            const eq = std.mem.indexOfScalar(u8, field, '=') orelse return push_ref;
            return applyLstrip(push_ref, field[eq + 1 ..]);
        }
        if (std.mem.startsWith(u8, field, "push:rstrip=")) {
            return applyRstrip(push_ref, field["push:rstrip=".len..]);
        }
        return "";
    }

    if (std.mem.startsWith(u8, field, "contents")) {
        const message = extractObjectMessage(data);
        if (std.mem.eql(u8, field, "contents")) return message
        else if (std.mem.eql(u8, field, "contents:subject")) {
            const clean_msg = stripCR(allocator, message) catch message;
            return joinLines(allocator, extractSubject(clean_msg)) catch extractSubject(clean_msg);
        } else if (std.mem.eql(u8, field, "contents:body")) return extractBody(message)
        else if (std.mem.eql(u8, field, "contents:signature")) return ""
        else if (std.mem.eql(u8, field, "contents:size")) {
            return std.fmt.allocPrint(allocator, "{d}", .{message.len}) catch return "0";
        }
    }

    return "";
}

const FormatAtomError = struct { valid: bool, err_msg: ?[]const u8 = null };

fn validateFormatAtom(field: []const u8, allocator: std.mem.Allocator) FormatAtomError {
    const valid_atoms = [_][]const u8{
        "refname", "objectname", "objecttype", "objectsize", "deltabase",
        "tree", "parent", "numparent", "object", "type", "tag",
        "author", "authorname", "authoremail", "authordate",
        "committer", "committername", "committeremail", "committerdate",
        "tagger", "taggername", "taggeremail", "taggerdate",
        "creator", "creatordate",
        "subject", "body", "contents", "raw", "HEAD",
        "upstream", "push", "*objectname", "*objecttype", "*raw", "*deltabase",
        "*objectsize", "if", "then", "else", "end", "align", "color",
        "ahead-behind", "describe", "rest", "trailers", "signature",
        "symref", "worktreepath", "flag", "path",
    };
    var matched_atom: ?[]const u8 = null;
    for (valid_atoms) |atom| {
        if (std.mem.eql(u8, field, atom)) return .{ .valid = true };
        if (std.mem.startsWith(u8, field, atom) and field.len > atom.len and field[atom.len] == ':') {
            matched_atom = atom;
            break;
        }
    }
    if (matched_atom == null) return .{ .valid = false };
    const atom = matched_atom.?;
    const options = field[atom.len + 1 ..];
    const email_atoms = [_][]const u8{ "authoremail", "committeremail", "taggeremail" };
    for (email_atoms) |ea| {
        if (std.mem.eql(u8, atom, ea)) return validateEmailOptions(ea, options, allocator);
    }
    const date_atoms = [_][]const u8{ "authordate", "committerdate", "taggerdate", "creatordate" };
    for (date_atoms) |da| {
        if (std.mem.eql(u8, atom, da)) return validateDateOptions(options);
    }
    if (std.mem.eql(u8, atom, "objectname") or std.mem.eql(u8, atom, "*objectname")) return validateObjectnameOptions(options);
    if (std.mem.eql(u8, atom, "refname")) return validateRefnameOptions(options);
    return .{ .valid = true };
}

fn validateEmailOptions(atom_name: []const u8, options: []const u8, allocator: std.mem.Allocator) FormatAtomError {
    const valid_opts = [_][]const u8{ "trim", "localpart", "mailmap" };
    var remaining = options;
    while (remaining.len > 0) {
        var found = false;
        for (valid_opts) |vo| {
            if (std.mem.startsWith(u8, remaining, vo)) {
                remaining = remaining[vo.len..];
                found = true;
                if (remaining.len == 0) return .{ .valid = true };
                if (remaining[0] == ',') { remaining = remaining[1..]; break; }
                const msg = std.fmt.allocPrint(allocator, "fatal: unrecognized %({s}) argument: {s}\n", .{ atom_name, remaining }) catch return .{ .valid = false };
                return .{ .valid = false, .err_msg = msg };
            }
        }
        if (!found) {
            const msg = std.fmt.allocPrint(allocator, "fatal: unrecognized %({s}) argument: {s}\n", .{ atom_name, remaining }) catch return .{ .valid = false };
            return .{ .valid = false, .err_msg = msg };
        }
    }
    const msg = std.fmt.allocPrint(allocator, "fatal: unrecognized %({s}) argument: {s}\n", .{ atom_name, remaining }) catch return .{ .valid = false };
    return .{ .valid = false, .err_msg = msg };
}

fn validateDateOptions(options: []const u8) FormatAtomError {
    const valid = [_][]const u8{ "default", "relative", "relative-local", "short", "short-local", "local", "iso", "iso8601", "iso-strict", "iso8601-strict", "rfc", "rfc2822", "raw", "human", "unix", "default-local", "iso-local", "iso8601-local", "iso-strict-local", "iso8601-strict-local", "rfc-local", "rfc2822-local", "raw-local", "human-local", "unix-local" };
    for (valid) |vf| { if (std.mem.eql(u8, options, vf)) return .{ .valid = true }; }
    if (std.mem.startsWith(u8, options, "format:") or std.mem.startsWith(u8, options, "format-local:")) return .{ .valid = true };
    return .{ .valid = false };
}

fn validateObjectnameOptions(options: []const u8) FormatAtomError {
    if (std.mem.eql(u8, options, "short")) return .{ .valid = true };
    if (std.mem.startsWith(u8, options, "short=")) {
        const n = std.fmt.parseInt(i64, options["short=".len..], 10) catch return .{ .valid = false };
        if (n <= 0) return .{ .valid = false };
        return .{ .valid = true };
    }
    return .{ .valid = true };
}

fn validateRefnameOptions(options: []const u8) FormatAtomError {
    if (options.len == 0) return .{ .valid = true };
    const valid_opts = [_][]const u8{ "short", "strip", "rstrip", "lstrip" };
    for (valid_opts) |vo| {
        if (std.mem.eql(u8, options, vo) or std.mem.startsWith(u8, options, vo)) return .{ .valid = true };
    }
    return .{ .valid = false };
}

fn isValidFormatAtom(field: []const u8) bool {
    const result = validateFormatAtom(field, std.heap.page_allocator);
    if (result.err_msg) |msg| std.heap.page_allocator.free(msg);
    return result.valid;
}

fn applyLstrip(refname: []const u8, n_str: []const u8) []const u8 {
    const n = std.fmt.parseInt(i32, n_str, 10) catch return refname;
    if (n >= 0) {
        var result = refname;
        var count: i32 = 0;
        while (count < n) : (count += 1) {
            if (std.mem.indexOfScalar(u8, result, '/')) |idx| { result = result[idx + 1 ..]; } else break;
        }
        return result;
    } else {
        const abs_n = @as(usize, @intCast(-n));
        var total: usize = 1;
        for (refname) |c| { if (c == '/') total += 1; }
        if (abs_n >= total) return refname;
        const strip = total - abs_n;
        var result = refname;
        var count: usize = 0;
        while (count < strip) : (count += 1) {
            if (std.mem.indexOfScalar(u8, result, '/')) |idx| { result = result[idx + 1 ..]; } else break;
        }
        return result;
    }
}

fn applyRstrip(refname: []const u8, n_str: []const u8) []const u8 {
    const n = std.fmt.parseInt(i32, n_str, 10) catch return refname;
    if (n >= 0) {
        var end = refname.len;
        var count: i32 = 0;
        while (count < n) : (count += 1) {
            if (std.mem.lastIndexOfScalar(u8, refname[0..end], '/')) |idx| { end = idx; } else break;
        }
        return refname[0..end];
    } else {
        const abs_n = @as(usize, @intCast(-n));
        var pos: usize = 0;
        var count: usize = 0;
        for (refname, 0..) |c, idx| {
            if (c == '/') {
                count += 1;
                if (count == abs_n) { pos = idx; break; }
            }
        }
        if (count < abs_n) return refname;
        return refname[0..pos];
    }
}

fn extractHeaderField(data: []const u8, header_name: []const u8) []const u8 {
    var lines_iter = std.mem.splitScalar(u8, data, '\n');
    while (lines_iter.next()) |line| {
        if (line.len == 0) break;
        if (std.mem.startsWith(u8, line, header_name) and line.len > header_name.len and line[header_name.len] == ' ')
            return line[header_name.len + 1 ..];
    }
    return "";
}

fn extractPersonField(suffix: []const u8, person_line: []const u8, allocator: std.mem.Allocator) []const u8 {
    if (person_line.len == 0) return "";
    if (suffix.len == 0) return person_line;
    const lt_pos = std.mem.indexOfScalar(u8, person_line, '<') orelse return person_line;
    const gt_pos = std.mem.indexOfScalar(u8, person_line, '>') orelse return person_line;
    const name = std.mem.trimRight(u8, person_line[0..lt_pos], " ");
    const email_brk = person_line[lt_pos .. gt_pos + 1];
    const email_bare = person_line[lt_pos + 1 .. gt_pos];

    if (std.mem.eql(u8, suffix, "name")) return name;
    if (std.mem.eql(u8, suffix, "name:mailmap")) {
        return applyMailmapName(name, email_bare, allocator) catch name;
    }
    if (std.mem.eql(u8, suffix, "email")) return email_brk;
    if (std.mem.eql(u8, suffix, "email:trim")) return email_bare;
    if (std.mem.eql(u8, suffix, "email:localpart") or std.mem.eql(u8, suffix, "email:trim,localpart") or std.mem.eql(u8, suffix, "email:localpart,trim")) {
        if (std.mem.indexOfScalar(u8, email_bare, '@')) |at| return email_bare[0..at];
        return email_bare;
    }
    if (std.mem.startsWith(u8, suffix, "email:")) {
        const has_mailmap = std.mem.indexOf(u8, suffix, "mailmap") != null;
        const has_trim = std.mem.indexOf(u8, suffix, "trim") != null;
        const has_localpart = std.mem.indexOf(u8, suffix, "localpart") != null;

        var eff_email = email_bare;
        if (has_mailmap) {
            eff_email = applyMailmapEmail(name, email_bare, allocator) catch email_bare;
        }

        if (has_trim and has_localpart) {
            if (std.mem.indexOfScalar(u8, eff_email, '@')) |at| return eff_email[0..at];
            return eff_email;
        }
        if (has_localpart) {
            if (std.mem.indexOfScalar(u8, eff_email, '@')) |at| return eff_email[0..at];
            return eff_email;
        }
        if (has_trim) return eff_email;
        if (has_mailmap) {
            return std.fmt.allocPrint(allocator, "<{s}>", .{eff_email}) catch email_brk;
        }
        return email_brk;
    }
    if (std.mem.eql(u8, suffix, "date")) return formatPersonDate(person_line, allocator);
    if (std.mem.startsWith(u8, suffix, "date:")) {
        const date_fmt = suffix["date:".len..];
        return formatPersonDateWithFormat(person_line, date_fmt, allocator);
    }
    return person_line;
}

fn formatPersonDate(person_line: []const u8, allocator: std.mem.Allocator) []const u8 {
    const gt_pos = std.mem.indexOfScalar(u8, person_line, '>') orelse return "";
    const after = std.mem.trimLeft(u8, if (gt_pos + 1 < person_line.len) person_line[gt_pos + 1 ..] else "", " ");
    const space = std.mem.indexOfScalar(u8, after, ' ');
    const ts_str = if (space) |s| after[0..s] else after;
    const tz_str = if (space) |s| after[s + 1 ..] else "+0000";
    const timestamp = std.fmt.parseInt(i64, ts_str, 10) catch return "";
    return formatTimestamp(timestamp, tz_str, allocator) catch return "";
}

fn formatTimestamp(timestamp: i64, tz_str: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    var tz_off: i32 = 0;
    if (tz_str.len >= 5) {
        const sign: i32 = if (tz_str[0] == '-') @as(i32, -1) else 1;
        const h = std.fmt.parseInt(i32, tz_str[1..3], 10) catch 0;
        const m = std.fmt.parseInt(i32, tz_str[3..5], 10) catch 0;
        tz_off = sign * (h * 60 + m);
    }
    const adj = timestamp + @as(i64, tz_off) * 60;
    const SPD: i64 = 86400;
    var days = @divFloor(adj, SPD);
    var rem = @mod(adj, SPD);
    if (rem < 0) { rem += SPD; days -= 1; }
    const hour = @as(u32, @intCast(@divFloor(rem, 3600)));
    const minute = @as(u32, @intCast(@divFloor(@mod(rem, 3600), 60)));
    const second = @as(u32, @intCast(@mod(rem, 60)));
    const wday = @mod(days + 4, 7);
    const wday_u: usize = if (wday >= 0) @intCast(wday) else @intCast(wday + 7);
    var y: i64 = 1970;
    var d = days;
    while (true) {
        const yd: i64 = if (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0)) 366 else 365;
        if (d < yd) break;
        d -= yd; y += 1;
    }
    const leap = (@mod(y, 4) == 0 and (@mod(y, 100) != 0 or @mod(y, 400) == 0));
    const mdays = [12]u32{ 31, if (leap) 29 else 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31 };
    var mon: usize = 0;
    while (mon < 12) : (mon += 1) { if (d < mdays[mon]) break; d -= mdays[mon]; }
    const day = @as(u32, @intCast(d)) + 1;
    const wn = [7][]const u8{ "Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat" };
    const mn = [12][]const u8{ "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec" };
    return std.fmt.allocPrint(allocator, "{s} {s} {d} {d:0>2}:{d:0>2}:{d:0>2} {d} {s}", .{ wn[wday_u], mn[mon], day, hour, minute, second, y, tz_str });
}

/// Resolve the upstream tracking ref for a branch ref
fn resolveUpstreamRef(refname: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    // Only works for refs/heads/<branch>
    if (!std.mem.startsWith(u8, refname, "refs/heads/")) return "";
    const branch = refname["refs/heads/".len..];
    const git_dir = findGitDir() catch return "";
    const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_dir});
    defer allocator.free(config_path);
    const config_data = std.fs.cwd().readFileAlloc(allocator, config_path, 1024 * 1024) catch return "";
    defer allocator.free(config_data);

    // Find branch.<branch>.remote and branch.<branch>.merge
    const remote = findConfigValue(config_data, "branch", branch, "remote") orelse return "";
    const merge = findConfigValue(config_data, "branch", branch, "merge") orelse return "";

    // merge is like "refs/heads/main", convert to "refs/remotes/<remote>/main"
    if (std.mem.startsWith(u8, merge, "refs/heads/")) {
        const branch_name = merge["refs/heads/".len..];
        return try std.fmt.allocPrint(allocator, "refs/remotes/{s}/{s}", .{ remote, branch_name });
    }
    return "";
}

/// Resolve the push remote ref for a branch ref
fn resolvePushRef(refname: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    if (!std.mem.startsWith(u8, refname, "refs/heads/")) return "";
    const branch = refname["refs/heads/".len..];
    const git_dir = findGitDir() catch return "";
    const config_path = try std.fmt.allocPrint(allocator, "{s}/config", .{git_dir});
    defer allocator.free(config_path);
    const config_data = std.fs.cwd().readFileAlloc(allocator, config_path, 1024 * 1024) catch return "";
    defer allocator.free(config_data);

    // Find remote.pushdefault or branch.<branch>.pushremote
    var push_remote = findConfigValue(config_data, "branch", branch, "pushremote");
    if (push_remote == null) push_remote = findConfigValue(config_data, "remote", null, "pushdefault");
    if (push_remote == null) push_remote = findConfigValue(config_data, "branch", branch, "remote");
    const remote = push_remote orelse return "";

    // push.default=current means push to same branch name
    return try std.fmt.allocPrint(allocator, "refs/remotes/{s}/{s}", .{ remote, branch });
}

/// Find a config value in git config data
fn findConfigValue(config_data: []const u8, section: []const u8, subsection: ?[]const u8, key: []const u8) ?[]const u8 {
    var in_section = false;
    var lines = std.mem.splitScalar(u8, config_data, '\n');
    var last_val: ?[]const u8 = null;
    while (lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        if (trimmed.len == 0 or trimmed[0] == '#' or trimmed[0] == ';') continue;
        if (trimmed[0] == '[') {
            in_section = false;
            // Parse [section "subsection"] or [section]
            if (std.mem.indexOfScalar(u8, trimmed, ']')) |close| {
                const header = trimmed[1..close];
                if (subsection) |sub| {
                    // Look for [section "subsection"]
                    if (std.mem.indexOfScalar(u8, header, '"')) |q1| {
                        const sec = std.mem.trim(u8, header[0..q1], " \t");
                        if (std.mem.lastIndexOfScalar(u8, header, '"')) |q2| {
                            if (q2 > q1) {
                                const sub_val = header[q1 + 1 .. q2];
                                if (std.ascii.eqlIgnoreCase(sec, section) and std.mem.eql(u8, sub_val, sub)) {
                                    in_section = true;
                                }
                            }
                        }
                    }
                } else {
                    // Look for [section] (no subsection)
                    const sec = std.mem.trim(u8, header, " \t");
                    if (std.mem.indexOfScalar(u8, sec, '"') == null and std.ascii.eqlIgnoreCase(sec, section)) {
                        in_section = true;
                    }
                }
            }
        } else if (in_section) {
            // key = value
            if (std.mem.indexOfScalar(u8, trimmed, '=')) |eq| {
                const k = std.mem.trim(u8, trimmed[0..eq], " \t");
                const v = std.mem.trim(u8, trimmed[eq + 1 ..], " \t");
                if (std.ascii.eqlIgnoreCase(k, key)) {
                    last_val = v;
                }
            }
        }
    }
    return last_val;
}

/// Read .mailmap and apply name mapping
fn applyMailmapName(name: []const u8, email: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    const mailmap_data = std.fs.cwd().readFileAlloc(allocator, ".mailmap", 64 * 1024) catch return name;
    defer allocator.free(mailmap_data);
    var lines = std.mem.splitScalar(u8, mailmap_data, '\n');
    while (lines.next()) |line| {
        const t = std.mem.trim(u8, line, " \t\r");
        if (t.len == 0 or t[0] == '#') continue;
        // Format: "Proper Name <proper@email> Original Name <original@email>"
        // or: "Proper Name <proper@email> <original@email>"
        // Match by original name+email
        if (parseMailmapLine(t, name, email)) |mapped_name| {
            return mapped_name;
        }
    }
    return name;
}

/// Read .mailmap and apply email mapping
fn applyMailmapEmail(name: []const u8, email: []const u8, allocator: std.mem.Allocator) ![]const u8 {
    const mailmap_data = std.fs.cwd().readFileAlloc(allocator, ".mailmap", 64 * 1024) catch return email;
    defer allocator.free(mailmap_data);
    var lines = std.mem.splitScalar(u8, mailmap_data, '\n');
    while (lines.next()) |line| {
        const t = std.mem.trim(u8, line, " \t\r");
        if (t.len == 0 or t[0] == '#') continue;
        if (parseMailmapLineEmail(t, name, email)) |mapped_email| {
            return mapped_email;
        }
    }
    return email;
}

/// Parse a mailmap line and check if it matches the given name+email, return mapped name
fn parseMailmapLine(line: []const u8, orig_name: []const u8, orig_email: []const u8) ?[]const u8 {
    // Format: "Proper Name <proper@email> Original Name <original@email>"
    // Find all <email> brackets
    var lt1: ?usize = null;
    var gt1: ?usize = null;
    var lt2: ?usize = null;
    var gt2: ?usize = null;
    var i: usize = 0;
    while (i < line.len) : (i += 1) {
        if (line[i] == '<') {
            if (lt1 == null) { lt1 = i; } else { lt2 = i; }
        } else if (line[i] == '>') {
            if (gt1 == null) { gt1 = i; } else { gt2 = i; }
        }
    }
    if (lt1 == null or gt1 == null) return null;

    if (lt2 != null and gt2 != null) {
        // Two email addresses: "Proper Name <proper@email> Original Name <original@email>"
        const orig_email_in_line = line[lt2.? + 1 .. gt2.?];
        if (std.ascii.eqlIgnoreCase(orig_email_in_line, orig_email)) {
            // Check original name matches too
            const orig_name_in_line = std.mem.trim(u8, line[gt1.? + 1 .. lt2.?], " \t");
            if (orig_name_in_line.len == 0 or std.mem.eql(u8, orig_name_in_line, orig_name)) {
                const proper_name = std.mem.trim(u8, line[0..lt1.?], " \t");
                if (proper_name.len > 0) return proper_name;
            }
        }
    } else {
        // One email: "Proper Name <email>" - matches by email only
        const email_in_line = line[lt1.? + 1 .. gt1.?];
        if (std.ascii.eqlIgnoreCase(email_in_line, orig_email)) {
            const proper_name = std.mem.trim(u8, line[0..lt1.?], " \t");
            if (proper_name.len > 0) return proper_name;
        }
    }
    return null;
}

/// Parse a mailmap line and return mapped email if it matches
fn parseMailmapLineEmail(line: []const u8, orig_name: []const u8, orig_email: []const u8) ?[]const u8 {
    var lt1: ?usize = null;
    var gt1: ?usize = null;
    var lt2: ?usize = null;
    var gt2: ?usize = null;
    var i: usize = 0;
    while (i < line.len) : (i += 1) {
        if (line[i] == '<') {
            if (lt1 == null) { lt1 = i; } else { lt2 = i; }
        } else if (line[i] == '>') {
            if (gt1 == null) { gt1 = i; } else { gt2 = i; }
        }
    }
    if (lt1 == null or gt1 == null) return null;

    if (lt2 != null and gt2 != null) {
        const orig_email_in_line = line[lt2.? + 1 .. gt2.?];
        if (std.ascii.eqlIgnoreCase(orig_email_in_line, orig_email)) {
            const orig_name_in_line = std.mem.trim(u8, line[gt1.? + 1 .. lt2.?], " \t");
            if (orig_name_in_line.len == 0 or std.mem.eql(u8, orig_name_in_line, orig_name)) {
                return line[lt1.? + 1 .. gt1.?];
            }
        }
    } else {
        const email_in_line = line[lt1.? + 1 .. gt1.?];
        if (std.ascii.eqlIgnoreCase(email_in_line, orig_email)) {
            return line[lt1.? + 1 .. gt1.?];
        }
    }
    return null;
}

fn sanitizeSubject(allocator: std.mem.Allocator, text: []const u8) ![]const u8 {
    var result = std.array_list.Managed(u8).init(allocator);
    for (text) |c| {
        if (std.ascii.isAlphanumeric(c)) {
            try result.append(c);
        } else {
            if (result.items.len == 0 or result.items[result.items.len - 1] != '-')
                try result.append('-');
        }
    }
    var len = result.items.len;
    while (len > 0 and result.items[len - 1] == '-') len -= 1;
    return result.items[0..len];
}

/// Match a ref name against a pattern (supports * and ? globs, or prefix match)
fn refPatternMatch(name: []const u8, pattern: []const u8) bool {
    // If pattern contains glob characters, do glob match
    if (std.mem.indexOfAny(u8, pattern, "*?[") != null) {
        return globMatch(name, pattern);
    }
    // Otherwise, prefix match (git for-each-ref treats patterns as prefixes)
    return std.mem.startsWith(u8, name, pattern);
}

/// Simple glob matching (supports * and ? wildcards)
fn globMatch(str: []const u8, pattern: []const u8) bool {
    var si: usize = 0;
    var pi: usize = 0;
    var star_pi: ?usize = null;
    var star_si: usize = 0;

    while (si < str.len) {
        if (pi < pattern.len and (pattern[pi] == '?' or pattern[pi] == str[si])) {
            si += 1;
            pi += 1;
        } else if (pi < pattern.len and pattern[pi] == '*') {
            star_pi = pi;
            star_si = si;
            pi += 1;
        } else if (star_pi) |sp| {
            pi = sp + 1;
            star_si += 1;
            si = star_si;
        } else {
            return false;
        }
    }
    while (pi < pattern.len and pattern[pi] == '*') pi += 1;
    return pi == pattern.len;
}

/// Join multiple lines into a single line with spaces
fn joinLines(allocator: std.mem.Allocator, text: []const u8) ![]const u8 {
    if (std.mem.indexOfScalar(u8, text, '\n') == null) return text;
    var result = std.array_list.Managed(u8).init(allocator);
    var iter = std.mem.splitScalar(u8, text, '\n');
    var first = true;
    while (iter.next()) |line| {
        const trimmed = std.mem.trimRight(u8, line, " \t\r");
        if (trimmed.len == 0) continue;
        if (!first) try result.append(' ');
        try result.appendSlice(trimmed);
        first = false;
    }
    return result.toOwnedSlice();
}

/// Extract the message portion from commit/tag object data (after the blank line)
fn extractObjectMessage(data: []const u8) []const u8 {
    // Find the blank line separator (\n\n)
    if (std.mem.indexOf(u8, data, "\n\n")) |pos| {
        return data[pos + 2 ..];
    }
    // Also handle \r\n\r\n
    if (std.mem.indexOf(u8, data, "\r\n\r\n")) |pos| {
        return data[pos + 4 ..];
    }
    return "";
}

/// Strip \r characters from string
fn stripCR(allocator: std.mem.Allocator, input: []const u8) ![]const u8 {
    if (std.mem.indexOfScalar(u8, input, '\r') == null) return input;
    var result = std.array_list.Managed(u8).init(allocator);
    for (input) |c| {
        if (c != '\r') try result.append(c);
    }
    return result.toOwnedSlice();
}

/// Extract subject line(s) from a commit message.
/// Subject is the first paragraph (up to the first blank line).
/// Multi-line subjects (non-blank lines before the first blank line) are joined with space.
fn extractSubject(message: []const u8) []const u8 {
    if (message.len == 0) return "";
    // Find the end of the subject (first blank line or end of message)
    var end: usize = 0;
    var lines = std.mem.splitScalar(u8, message, '\n');
    var first = true;
    while (lines.next()) |line| {
        const trimmed = std.mem.trimRight(u8, line, " \t\r");
        if (trimmed.len == 0 and !first) break;
        if (trimmed.len == 0 and first) break;
        end = @intFromPtr(line.ptr) - @intFromPtr(message.ptr) + line.len;
        first = false;
    }
    if (end > message.len) end = message.len;
    // Trim trailing newlines
    var subject = message[0..end];
    subject = std.mem.trimRight(u8, subject, "\n\r ");
    return subject;
}

/// Extract body from a commit message (everything after the subject and blank lines)
fn extractBody(message: []const u8) []const u8 {
    if (message.len == 0) return "";
    // Skip subject lines (first paragraph) - find first blank line after non-blank
    var iter = std.mem.splitScalar(u8, message, '\n');
    var pos: usize = 0;
    var found_subject = false;
    var found_blank = false;
    while (iter.next()) |line| {
        pos = @intFromPtr(line.ptr) - @intFromPtr(message.ptr) + line.len + 1;
        const trimmed = std.mem.trimRight(u8, line, " \t\r");
        if (!found_subject) {
            if (trimmed.len > 0) found_subject = true;
            continue;
        }
        if (!found_blank) {
            if (trimmed.len == 0) {
                found_blank = true;
                continue;
            }
            continue;
        }
        // Skip additional blank lines after the separator
        if (trimmed.len == 0) continue;
        // Found first non-blank body line
        const body_start = @intFromPtr(line.ptr) - @intFromPtr(message.ptr);
        if (body_start > message.len) return "";
        return message[body_start..];
    }
    return "";
}

fn nativeCmdVerifyPack(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var verbose = false;
    var stat_only = false;
    var pack_files = std.array_list.Managed([]const u8).init(allocator);
    defer pack_files.deinit();

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--stat-only")) {
            stat_only = true;
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git verify-pack [-v | --verbose] [-s | --stat-only] [--] <pack>.idx...\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--")) {
            i += 1;
            while (i < args.len) : (i += 1) {
                try pack_files.append(args[i]);
            }
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try pack_files.append(arg);
        }
    }

    if (pack_files.items.len == 0) {
        try platform_impl.writeStderr("usage: git verify-pack [-v | --verbose] [-s | --stat-only] [--] <pack>.idx...\n");
        std.process.exit(1);
    }

    var any_error = false;
    for (pack_files.items) |pack_file| {
        // Determine pack and idx file paths
        var pack_path_alloc: ?[]const u8 = null;
        var idx_path_alloc: ?[]const u8 = null;
        defer if (pack_path_alloc) |p| allocator.free(p);
        defer if (idx_path_alloc) |p| allocator.free(p);

        var pack_path: []const u8 = undefined;
        var idx_path: []const u8 = undefined;

        if (std.mem.endsWith(u8, pack_file, ".idx")) {
            idx_path = pack_file;
            const base = pack_file[0 .. pack_file.len - 4];
            pack_path_alloc = std.fmt.allocPrint(allocator, "{s}.pack", .{base}) catch continue;
            pack_path = pack_path_alloc.?;
        } else if (std.mem.endsWith(u8, pack_file, ".pack")) {
            pack_path = pack_file;
            const base = pack_file[0 .. pack_file.len - 5];
            idx_path_alloc = std.fmt.allocPrint(allocator, "{s}.idx", .{base}) catch continue;
            idx_path = idx_path_alloc.?;
        } else {
            pack_path = pack_file;
            idx_path = pack_file;
        }

        // Read pack file
        const pack_data = std.fs.cwd().readFileAlloc(allocator, pack_path, 4 * 1024 * 1024 * 1024) catch {
            const msg = std.fmt.allocPrint(allocator, "error: packfile {s} not found.\n", .{pack_path}) catch continue;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            any_error = true;
            continue;
        };
        defer allocator.free(pack_data);

        // Verify pack header
        if (pack_data.len < 12 or !std.mem.eql(u8, pack_data[0..4], "PACK")) {
            const msg = std.fmt.allocPrint(allocator, "error: {s}: packfile signature mismatch\n", .{pack_path}) catch continue;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            any_error = true;
            continue;
        }

        const pack_version = std.mem.readInt(u32, pack_data[4..8], .big);
        if (pack_version != 2 and pack_version != 3) {
            const msg = std.fmt.allocPrint(allocator, "error: {s}: unsupported pack version {d}\n", .{ pack_path, pack_version }) catch continue;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            any_error = true;
            continue;
        }

        // Verify pack checksum
        if (pack_data.len >= 20) {
            var sha1 = std.crypto.hash.Sha1.init(.{});
            sha1.update(pack_data[0 .. pack_data.len - 20]);
            const computed = sha1.finalResult();
            const stored = pack_data[pack_data.len - 20 ..][0..20];
            if (!std.mem.eql(u8, &computed, stored)) {
                const msg = std.fmt.allocPrint(allocator, "error: {s}: pack checksum mismatch\n", .{pack_path}) catch continue;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                any_error = true;
                continue;
            }
        }

        // Read idx file to verify pack checksum in idx matches
        const idx_data = std.fs.cwd().readFileAlloc(allocator, idx_path, 100 * 1024 * 1024) catch {
            const msg = std.fmt.allocPrint(allocator, "error: packfile {s} index not found.\n", .{idx_path}) catch continue;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            any_error = true;
            continue;
        };
        defer allocator.free(idx_data);

        // Verify idx checksum
        if (idx_data.len >= 40) {
            // The last 20 bytes of idx is the idx SHA1
            // The 20 bytes before that is the pack SHA1
            const idx_pack_checksum = idx_data[idx_data.len - 40 .. idx_data.len - 20];
            const pack_trailing = pack_data[pack_data.len - 20 ..];
            if (!std.mem.eql(u8, idx_pack_checksum, pack_trailing)) {
                const msg = std.fmt.allocPrint(allocator, "error: packfile {s} does not match index\n", .{pack_path}) catch continue;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                any_error = true;
                continue;
            }

            // Verify idx's own checksum
            var idx_sha = std.crypto.hash.Sha1.init(.{});
            idx_sha.update(idx_data[0 .. idx_data.len - 20]);
            const idx_computed = idx_sha.finalResult();
            const idx_stored = idx_data[idx_data.len - 20 ..][0..20];
            if (!std.mem.eql(u8, &idx_computed, idx_stored)) {
                const msg = std.fmt.allocPrint(allocator, "error: index file {s} checksum mismatch\n", .{idx_path}) catch continue;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                any_error = true;
                continue;
            }
        }

        const num_objects = std.mem.readInt(u32, pack_data[8..12], .big);

        if (verbose and !stat_only) {
            // In verbose mode, list each object in the pack
            var pos: usize = 12;
            var obj_idx: u32 = 0;
            while (obj_idx < num_objects and pos < pack_data.len -| 20) : (obj_idx += 1) {
                const entry_offset = pos;
                var c = pack_data[pos];
                pos += 1;
                const obj_type = (pack_data[entry_offset] >> 4) & 0x07;
                var obj_size: u64 = c & 0x0F;
                var shift: u6 = 4;
                while (c & 0x80 != 0 and pos < pack_data.len) {
                    c = pack_data[pos];
                    pos += 1;
                    obj_size |= @as(u64, c & 0x7F) << shift;
                    shift +|= 7;
                }

                // Handle delta base refs
                var delta_base_offset: ?u64 = null;
                var delta_base_ref: ?[20]u8 = null;
                if (obj_type == 6) {
                    c = pack_data[pos];
                    pos += 1;
                    var ofs: u64 = c & 0x7F;
                    while (c & 0x80 != 0 and pos < pack_data.len) {
                        c = pack_data[pos];
                        pos += 1;
                        ofs = ((ofs + 1) << 7) | (c & 0x7F);
                    }
                    delta_base_offset = ofs;
                } else if (obj_type == 7) {
                    if (pos + 20 <= pack_data.len) {
                        delta_base_ref = pack_data[pos..][0..20].*;
                        pos += 20;
                    }
                }

                // Decompress
                const decomp = zlib_compat_mod.decompressSliceWithConsumed(allocator, pack_data[pos..]) catch {
                    pos = pack_data.len -| 20;
                    continue;
                };
                defer allocator.free(decomp.data);
                pos += decomp.consumed;

                // Compute object hash
                const type_str: []const u8 = switch (obj_type) {
                    1 => "commit",
                    2 => "tree",
                    3 => "blob",
                    4 => "tag",
                    6 => "ofs_delta",
                    7 => "ref_delta",
                    else => "unknown",
                };

                if (obj_type >= 1 and obj_type <= 4) {
                    const hdr = std.fmt.allocPrint(allocator, "{s} {d}\x00", .{ type_str, decomp.data.len }) catch continue;
                    defer allocator.free(hdr);
                    var hasher = std.crypto.hash.Sha1.init(.{});
                    hasher.update(hdr);
                    hasher.update(decomp.data);
                    const sha = hasher.finalResult();
                    var hash_hex: [40]u8 = undefined;
                    for (sha, 0..) |b, bi| {
                        const hc = "0123456789abcdef";
                        hash_hex[bi * 2] = hc[b >> 4];
                        hash_hex[bi * 2 + 1] = hc[b & 0xf];
                    }
                    const out = std.fmt.allocPrint(allocator, "{s} {s: <6} {d} {d} {d}\n", .{ hash_hex, type_str, decomp.data.len, pos - entry_offset, entry_offset }) catch continue;
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (obj_type == 6 and delta_base_offset != null) {
                    const out = std.fmt.allocPrint(allocator, "non delta: {s} {d} {d} {d} {d}\n", .{ type_str, obj_size, decomp.data.len, pos - entry_offset, entry_offset }) catch continue;
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (obj_type == 7 and delta_base_ref != null) {
                    const out = std.fmt.allocPrint(allocator, "non delta: {s} {d} {d} {d} {d}\n", .{ type_str, obj_size, decomp.data.len, pos - entry_offset, entry_offset }) catch continue;
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
        }

        // Output summary
        if (verbose and !stat_only) {
            const summary = std.fmt.allocPrint(allocator, "non delta: {d} object{s}\n{s}: ok\n", .{
                num_objects,
                if (num_objects == 1) "" else "s",
                pack_path,
            }) catch "";
            if (summary.len > 0) {
                defer allocator.free(summary);
                try platform_impl.writeStdout(summary);
            }
        }
    }

    if (any_error) {
        std.process.exit(1);
    }
}

fn nativeCmdUpdateServerInfo(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var force = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--force")) {
            force = true;
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git update-server-info [--force]\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Create info directory
    const info_dir = std.fmt.allocPrint(allocator, "{s}/info", .{git_dir}) catch unreachable;
    defer allocator.free(info_dir);
    std.fs.cwd().makePath(info_dir) catch {};

    // Update info/refs
    const info_refs_path = std.fmt.allocPrint(allocator, "{s}/info/refs", .{git_dir}) catch unreachable;
    defer allocator.free(info_refs_path);
    {
        var ref_list = std.array_list.Managed(RefEntry).init(allocator);
        defer {
            for (ref_list.items) |entry| {
                allocator.free(entry.name);
                allocator.free(entry.hash);
            }
            ref_list.deinit();
        }

        // Read packed-refs
        const packed_refs_path = std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir}) catch unreachable;
        defer allocator.free(packed_refs_path);
        if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_content| {
            defer allocator.free(packed_content);
            var lines = std.mem.splitScalar(u8, packed_content, '\n');
            while (lines.next()) |line| {
                if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
                if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                    const hash = line[0..space_idx];
                    const name = line[space_idx + 1..];
                    if (hash.len >= 40) {
                        try ref_list.append(.{
                            .name = try allocator.dupe(u8, name),
                            .hash = try allocator.dupe(u8, hash[0..40]),
                        });
                    }
                }
            }
        } else |_| {}
        try collectLooseRefs(allocator, git_dir, "refs", &ref_list, platform_impl);

        // Sort
        std.mem.sort(RefEntry, ref_list.items, {}, struct {
            fn lessThan(_: void, a: RefEntry, b: RefEntry) bool {
                return std.mem.order(u8, a.name, b.name).compare(.lt);
            }
        }.lessThan);

        // Write info/refs (only if content changed, unless force)
        var content = std.array_list.Managed(u8).init(allocator);
        defer content.deinit();
        for (ref_list.items) |entry| {
            const line = std.fmt.allocPrint(allocator, "{s}\t{s}\n", .{ entry.hash, entry.name }) catch continue;
            defer allocator.free(line);
            try content.appendSlice(line);
        }
        const should_write = if (force) true else blk: {
            const existing = std.fs.cwd().readFileAlloc(allocator, info_refs_path, 10 * 1024 * 1024) catch break :blk true;
            defer allocator.free(existing);
            break :blk !std.mem.eql(u8, existing, content.items);
        };
        if (should_write) {
            std.fs.cwd().writeFile(.{ .sub_path = info_refs_path, .data = content.items }) catch |err| {
                const msg = std.fmt.allocPrint(allocator, "error: unable to update {s}: {s}\n", .{ info_refs_path, @errorName(err) }) catch return;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            };
        }
    }

    // Update info/packs (objects/info/packs)
    const obj_info_dir = std.fmt.allocPrint(allocator, "{s}/objects/info", .{git_dir}) catch unreachable;
    defer allocator.free(obj_info_dir);
    std.fs.cwd().makePath(obj_info_dir) catch {};

    const packs_file_path = std.fmt.allocPrint(allocator, "{s}/objects/info/packs", .{git_dir}) catch unreachable;
    defer allocator.free(packs_file_path);
    {
        var content = std.array_list.Managed(u8).init(allocator);
        defer content.deinit();

        const pack_dir = std.fmt.allocPrint(allocator, "{s}/objects/pack", .{git_dir}) catch unreachable;
        defer allocator.free(pack_dir);

        if (std.fs.cwd().openDir(pack_dir, .{ .iterate = true })) |pd| {
            var pack_d = pd;
            defer pack_d.close();
            var pack_names = std.array_list.Managed([]const u8).init(allocator);
            defer {
                for (pack_names.items) |n| allocator.free(n);
                pack_names.deinit();
            }

            var iter = pack_d.iterate();
            while (iter.next() catch null) |entry| {
                if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".pack")) {
                    try pack_names.append(try allocator.dupe(u8, entry.name));
                }
            }

            // Sort pack names
            std.mem.sort([]const u8, pack_names.items, {}, struct {
                fn lessThan(_: void, a: []const u8, b: []const u8) bool {
                    return std.mem.order(u8, a, b).compare(.lt);
                }
            }.lessThan);

            for (pack_names.items) |name| {
                const line = std.fmt.allocPrint(allocator, "P {s}\n", .{name}) catch continue;
                defer allocator.free(line);
                try content.appendSlice(line);
            }
        } else |_| {}

        // Always write trailing newline
        try content.append('\n');

        const should_write_packs = if (force) true else blk: {
            const existing = std.fs.cwd().readFileAlloc(allocator, packs_file_path, 10 * 1024 * 1024) catch break :blk true;
            defer allocator.free(existing);
            break :blk !std.mem.eql(u8, existing, content.items);
        };
        if (should_write_packs) {
            std.fs.cwd().writeFile(.{ .sub_path = packs_file_path, .data = content.items }) catch |err| {
                const msg = std.fmt.allocPrint(allocator, "error: unable to update {s}: {s}\n", .{ packs_file_path, @errorName(err) }) catch return;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            };
        }
    }
}

fn nativeCmdMktree(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var missing_ok = false;
    var batch = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--missing")) {
            missing_ok = true;
        } else if (std.mem.eql(u8, arg, "--batch")) {
            batch = true;
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git mktree [--missing] [--batch]\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Read tree entries from stdin
    const stdin = std.fs.File{ .handle = std.posix.STDIN_FILENO };
    const stdin_data = stdin.readToEndAlloc(allocator, 100 * 1024 * 1024) catch {
        try platform_impl.writeStderr("fatal: error reading from stdin\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(stdin_data);

    var entries = std.array_list.Managed(objects.TreeEntry).init(allocator);
    defer entries.deinit();

    var lines = std.mem.splitScalar(u8, stdin_data, '\n');
    while (lines.next()) |line| {
        if (line.len == 0) continue;
        // Format: <mode> <type> <hash>\t<name>
        // or: <mode> SP <type> SP <hash> TAB <name>
        if (std.mem.indexOfScalar(u8, line, '\t')) |tab_idx| {
            const name = line[tab_idx + 1..];
            // Reject recursive ls-tree output (paths with '/')
            if (std.mem.indexOfScalar(u8, name, '/') != null) {
                try platform_impl.writeStderr("fatal: path with slash in mktree input: ");
                try platform_impl.writeStderr(name);
                try platform_impl.writeStderr("\n");
                std.process.exit(128);
            }
            const prefix = line[0..tab_idx];
            // Split prefix by spaces
            var parts = std.mem.splitScalar(u8, prefix, ' ');
            const mode = parts.next() orelse continue;
            _ = parts.next(); // type
            const hash = parts.next() orelse continue;
            try entries.append(objects.TreeEntry.init(mode, name, hash));
        }
    }

    // Sort entries by name (git tree sorting: directories get trailing '/' for comparison)
    const SortCtx = struct {
        pub fn lessThan(_: @This(), a: objects.TreeEntry, b: objects.TreeEntry) bool {
            // Git sorts tree entries by comparing names, but directories have
            // an implicit trailing '/' for comparison purposes
            const a_is_dir = std.mem.eql(u8, a.mode, "040000") or std.mem.eql(u8, a.mode, "40000");
            const b_is_dir = std.mem.eql(u8, b.mode, "040000") or std.mem.eql(u8, b.mode, "40000");
            const a_name = a.name;
            const b_name = b.name;

            // Compare byte by byte, appending '/' to directory names
            var ai: usize = 0;
            var bi: usize = 0;
            while (true) {
                const ac: u8 = if (ai < a_name.len) a_name[ai] else if (a_is_dir and ai == a_name.len) '/' else 0;
                const bc: u8 = if (bi < b_name.len) b_name[bi] else if (b_is_dir and bi == b_name.len) '/' else 0;
                if (ac == 0 and bc == 0) return false;
                if (ac < bc) return true;
                if (ac > bc) return false;
                ai += 1;
                bi += 1;
            }
        }
    };
    std.mem.sort(objects.TreeEntry, entries.items, SortCtx{}, SortCtx.lessThan);

    // Create tree object
    const tree_obj = objects.createTreeObject(entries.items, allocator) catch {
        try platform_impl.writeStderr("fatal: error creating tree object\n");
        std.process.exit(128);
        unreachable;
    };
    defer tree_obj.deinit(allocator);

    const hash = tree_obj.store(git_dir, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: error storing tree object\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(hash);

    const output = std.fmt.allocPrint(allocator, "{s}\n", .{hash}) catch unreachable;
    defer allocator.free(output);
    try platform_impl.writeStdout(output);
}

fn nativeCmdMktag(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git mktag\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Read tag content from stdin
    const stdin = std.fs.File{ .handle = std.posix.STDIN_FILENO };
    const stdin_data = stdin.readToEndAlloc(allocator, 10 * 1024 * 1024) catch {
        try platform_impl.writeStderr("fatal: error reading from stdin\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(stdin_data);

    // Validate tag format
    if (std.mem.indexOf(u8, stdin_data, "object ") == null or
        std.mem.indexOf(u8, stdin_data, "type ") == null or
        std.mem.indexOf(u8, stdin_data, "tag ") == null or
        std.mem.indexOf(u8, stdin_data, "tagger ") == null)
    {
        try platform_impl.writeStderr("error: invalid tag format\n");
        std.process.exit(128);
    }

    // Create and store tag object
    const tag_obj = objects.GitObject.init(.tag, stdin_data);
    const hash = tag_obj.store(git_dir, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: error storing tag object\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(hash);

    const output = std.fmt.allocPrint(allocator, "{s}\n", .{hash}) catch unreachable;
    defer allocator.free(output);
    try platform_impl.writeStdout(output);
}

fn nativeCmdNameRev(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var name_only = false;
    var stdin_mode = false;
    var annotate_stdin = false;
    var refs_pattern: ?[]const u8 = null;
    var exclude_patterns = std.array_list.Managed([]const u8).init(allocator);
    defer exclude_patterns.deinit();
    var targets = std.array_list.Managed([]const u8).init(allocator);
    defer targets.deinit();

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--name-only")) {
            name_only = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
        } else if (std.mem.eql(u8, arg, "--annotate-stdin")) {
            stdin_mode = true;
            annotate_stdin = true;
        } else if (std.mem.startsWith(u8, arg, "--refs=")) {
            refs_pattern = arg["--refs=".len..];
        } else if (std.mem.eql(u8, arg, "--tags")) {
            refs_pattern = "refs/tags/*";
        } else if (std.mem.startsWith(u8, arg, "--exclude=")) {
            try exclude_patterns.append(arg["--exclude=".len..]);
        } else if (std.mem.eql(u8, arg, "--exclude")) {
            if (i + 1 < args.len) { i += 1; try exclude_patterns.append(args[i]); }
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git name-rev [<options>] <commit>...\n");
            std.process.exit(129);
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try targets.append(arg);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Collect all refs for naming
    var ref_list = std.array_list.Managed(RefEntry).init(allocator);
    defer {
        for (ref_list.items) |entry| {
            allocator.free(entry.name);
            allocator.free(entry.hash);
        }
        ref_list.deinit();
    }

    const packed_refs_path = std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir}) catch unreachable;
    defer allocator.free(packed_refs_path);
    if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_content| {
        defer allocator.free(packed_content);
        var lines = std.mem.splitScalar(u8, packed_content, '\n');
        while (lines.next()) |line| {
            if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
            if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                const hash = line[0..space_idx];
                const name = line[space_idx + 1..];
                if (hash.len >= 40) {
                    try ref_list.append(.{
                        .name = try allocator.dupe(u8, name),
                        .hash = try allocator.dupe(u8, hash[0..40]),
                    });
                }
            }
        }
    } else |_| {}
    try collectLooseRefs(allocator, git_dir, "refs", &ref_list, platform_impl);

    // Handle annotate-stdin mode
    if (stdin_mode and annotate_stdin) {
        // Build hash -> name map by walking commit history from each ref
        var hash_to_name = std.StringHashMap([]const u8).init(allocator);
        defer hash_to_name.deinit();
        
        for (ref_list.items) |entry| {
            // Filter by refs_pattern
            if (refs_pattern) |pat| {
                if (std.mem.endsWith(u8, pat, "/*")) {
                    if (!std.mem.startsWith(u8, entry.name, pat[0..pat.len - 1])) continue;
                } else if (!std.mem.eql(u8, entry.name, pat)) continue;
            }
            // Check exclude patterns
            var excluded = false;
            for (exclude_patterns.items) |excl| {
                var short = entry.name;
                if (std.mem.startsWith(u8, entry.name, "refs/tags/")) short = entry.name["refs/tags/".len..];
                if (std.mem.eql(u8, short, excl)) { excluded = true; break; }
            }
            if (excluded) continue;
            
            // Resolve to commit hash (dereference tags)
            var commit_hash = entry.hash;
            var tag_target_owned: ?[]u8 = null;
            const obj = objects.GitObject.load(entry.hash, git_dir, platform_impl, allocator) catch continue;
            defer obj.deinit(allocator);
            if (obj.type == .tag) {
                tag_target_owned = parseTagObject(obj.data, allocator) catch continue;
                commit_hash = tag_target_owned.?;
            }
            defer if (tag_target_owned) |t| allocator.free(t);
            
            var short_name = entry.name;
            if (std.mem.startsWith(u8, entry.name, "refs/tags/")) short_name = entry.name["refs/tags/".len..];
            
            // Walk commit chain assigning names
            var walk_hash = allocator.dupe(u8, commit_hash) catch continue;
            var dist: usize = 0;
            while (dist < 1000) : (dist += 1) {
                {
                    const name_str = if (dist == 0) 
                        (allocator.dupe(u8, short_name) catch break)
                    else 
                        (std.fmt.allocPrint(allocator, "{s}~{d}", .{ short_name, dist }) catch break);
                    // Only set if no name exists or new name is shorter (better)
                    if (hash_to_name.get(walk_hash)) |existing| {
                        if (name_str.len < existing.len) {
                            hash_to_name.put(allocator.dupe(u8, walk_hash) catch break, name_str) catch break;
                        } else {
                            allocator.free(name_str);
                        }
                    } else {
                        hash_to_name.put(allocator.dupe(u8, walk_hash) catch break, name_str) catch break;
                    }
                }
                const c_obj = objects.GitObject.load(walk_hash, git_dir, platform_impl, allocator) catch break;
                defer c_obj.deinit(allocator);
                var parent_hash: ?[]const u8 = null;
                var li = std.mem.splitScalar(u8, c_obj.data, '\n');
                while (li.next()) |line| {
                    if (std.mem.startsWith(u8, line, "parent ")) { parent_hash = line["parent ".len..]; break; }
                    if (line.len == 0) break;
                }
                if (parent_hash) |ph| {
                    allocator.free(walk_hash);
                    walk_hash = allocator.dupe(u8, ph) catch break;
                } else break;
            }
            allocator.free(walk_hash);
        }
        
        // Read stdin and annotate
        const stdin_content = readStdin(allocator, 10 * 1024 * 1024) catch "";
        defer if (stdin_content.len > 0) allocator.free(stdin_content);
        
        var lines = std.mem.splitScalar(u8, stdin_content, '\n');
        while (lines.next()) |line| {
            if (line.len == 0) continue;
            var output = std.array_list.Managed(u8).init(allocator);
            defer output.deinit();
            var j: usize = 0;
            while (j < line.len) {
                if (j + 40 <= line.len and isValidHexString(line[j..j + 40])) {
                    const hex = line[j..j + 40];
                    if (hash_to_name.get(hex)) |name| {
                        if (name_only) {
                            try output.appendSlice(name);
                        } else {
                            try output.appendSlice(hex);
                            try output.append(' ');
                            try output.append('(');
                            try output.appendSlice(name);
                            try output.append(')');
                        }
                    } else {
                        try output.appendSlice(hex);
                    }
                    j += 40;
                } else {
                    try output.append(line[j]);
                    j += 1;
                }
            }
            try output.append('\n');
            try platform_impl.writeStdout(output.items);
        }
        return;
    }

    for (targets.items) |target| {
        // Resolve the target to a full hash
        const resolved = refs.resolveRef(git_dir, target, platform_impl, allocator) catch {
            if (name_only) {
                const output = std.fmt.allocPrint(allocator, "undefined\n", .{}) catch continue;
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                const output = std.fmt.allocPrint(allocator, "{s} undefined\n", .{target}) catch continue;
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
            continue;
        };
        const hash = resolved orelse {
            if (name_only) {
                try platform_impl.writeStdout("undefined\n");
            } else {
                const output = std.fmt.allocPrint(allocator, "{s} undefined\n", .{target}) catch continue;
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
            continue;
        };
        defer allocator.free(hash);

        // Find best matching ref
        var best_name: ?[]const u8 = null;
        for (ref_list.items) |entry| {
            if (std.mem.eql(u8, entry.hash, hash)) {
                // Use shortest/best ref name
                if (best_name == null) {
                    best_name = entry.name;
                }
            }
        }

        if (best_name) |name| {
            // Format ref name (strip refs/heads/, refs/tags/, etc.)
            var short_name = name;
            if (std.mem.startsWith(u8, name, "refs/tags/")) {
                short_name = std.fmt.allocPrint(allocator, "tags/{s}", .{name["refs/tags/".len..]}) catch name;
            } else if (std.mem.startsWith(u8, name, "refs/heads/")) {
                short_name = name["refs/heads/".len..];
            } else if (std.mem.startsWith(u8, name, "refs/remotes/")) {
                short_name = std.fmt.allocPrint(allocator, "remotes/{s}", .{name["refs/remotes/".len..]}) catch name;
            }

            if (name_only) {
                const output = std.fmt.allocPrint(allocator, "{s}\n", .{short_name}) catch continue;
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            } else {
                const output = std.fmt.allocPrint(allocator, "{s} {s}\n", .{ target, short_name }) catch continue;
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        } else {
            if (name_only) {
                try platform_impl.writeStdout("undefined\n");
            } else {
                const output = std.fmt.allocPrint(allocator, "{s} undefined\n", .{target}) catch continue;
                defer allocator.free(output);
                try platform_impl.writeStdout(output);
            }
        }
    }
}

fn nativeCmdFsck(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var verbose = false;
    var full = false;
    var unreachable_check = false;
    var connectivity_only = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "--full")) {
            full = true;
        } else if (std.mem.eql(u8, arg, "--unreachable")) {
            unreachable_check = true;
        } else if (std.mem.eql(u8, arg, "--connectivity-only")) {
            connectivity_only = true;
        } else if (std.mem.eql(u8, arg, "--no-dangling") or std.mem.eql(u8, arg, "--no-progress") or
            std.mem.eql(u8, arg, "--strict") or std.mem.eql(u8, arg, "--lost-found") or
            std.mem.eql(u8, arg, "--name-objects") or std.mem.eql(u8, arg, "--progress") or
            std.mem.eql(u8, arg, "--cache") or std.mem.eql(u8, arg, "--no-reflogs") or
            std.mem.eql(u8, arg, "--dangling") or std.mem.eql(u8, arg, "--root") or
            std.mem.eql(u8, arg, "--tags") or std.mem.eql(u8, arg, "--no-full"))
        {
            // Accepted but not all implemented
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git fsck [<options>] [<object>...]\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Verify loose objects
    var checked: usize = 0;
    var bad: usize = 0;
    const objects_dir_path = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch unreachable;
    defer allocator.free(objects_dir_path);

    var hex_dirs: usize = 0;
    while (hex_dirs < 256) : (hex_dirs += 1) {
        var hex_buf: [2]u8 = undefined;
        _ = std.fmt.bufPrint(&hex_buf, "{x:0>2}", .{hex_dirs}) catch continue;
        const subdir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path, hex_buf }) catch continue;
        defer allocator.free(subdir_path);

        var subdir = std.fs.cwd().openDir(subdir_path, .{ .iterate = true }) catch continue;
        defer subdir.close();

        var iter = subdir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file and entry.name.len == 38) {
                checked += 1;
                // Try to load the object to verify it
                var hash_str: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&hash_str, "{s}{s}", .{ hex_buf, entry.name }) catch continue;
                // Verify object by reading the raw file and checking it can be decompressed
                const obj_path = std.fmt.allocPrint(allocator, "{s}/{s}/{s}", .{ objects_dir_path, hex_buf, entry.name }) catch continue;
                defer allocator.free(obj_path);
                const raw_data = std.fs.cwd().readFileAlloc(allocator, obj_path, 100 * 1024 * 1024) catch {
                    bad += 1;
                    const msg = std.fmt.allocPrint(allocator, "error: object {s} is corrupt\n", .{hash_str}) catch continue;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    continue;
                };
                defer allocator.free(raw_data);
                // Object exists and is readable - consider it valid
                // (Full verification would decompress and check header + hash)
                if (verbose) {
                    const msg = std.fmt.allocPrint(allocator, "checking {s}\n", .{hash_str}) catch continue;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                }
            }
        }
    }

    // Verify pack files
    const pack_dir_path = std.fmt.allocPrint(allocator, "{s}/objects/pack", .{git_dir}) catch unreachable;
    defer allocator.free(pack_dir_path);

    if (std.fs.cwd().openDir(pack_dir_path, .{ .iterate = true })) |pd| {
        var pack_d = pd;
        defer pack_d.close();
        var pack_iter = pack_d.iterate();
        while (pack_iter.next() catch null) |entry| {
            if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".idx")) {
                // Verify pack
                const idx_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir_path, entry.name }) catch continue;
                defer allocator.free(idx_path);
                const pack_name = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir_path, entry.name[0 .. entry.name.len - 4] }) catch continue;
                defer allocator.free(pack_name);
                const pack_path = std.fmt.allocPrint(allocator, "{s}.pack", .{pack_name}) catch continue;
                defer allocator.free(pack_path);
                _ = std.fs.cwd().statFile(pack_path) catch {
                    bad += 1;
                    const msg = std.fmt.allocPrint(allocator, "error: pack {s} has no corresponding .pack file\n", .{entry.name}) catch continue;
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    continue;
                };
            }
        }
    } else |_| {}

    // Check HEAD
    const head_path = std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_dir}) catch unreachable;
    defer allocator.free(head_path);
    _ = std.fs.cwd().statFile(head_path) catch {
        try platform_impl.writeStderr("error: HEAD is missing\n");
        bad += 1;
    };

    if (bad > 0) {
        std.process.exit(1);
    }
}

fn nativeCmdGc(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var aggressive = false;
    var auto_mode = false;
    var prune_option: []const u8 = "2.weeks.ago";
    var quiet = false;
    var no_cruft = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--aggressive")) {
            aggressive = true;
        } else if (std.mem.eql(u8, arg, "--auto")) {
            auto_mode = true;
        } else if (std.mem.startsWith(u8, arg, "--prune=")) {
            prune_option = arg["--prune=".len..];
        } else if (std.mem.eql(u8, arg, "--prune")) {
            i += 1;
            if (i < args.len) prune_option = args[i];
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--no-prune")) {
            prune_option = "never";
        } else if (std.mem.eql(u8, arg, "--no-cruft")) {
            no_cruft = true;
        } else if (std.mem.eql(u8, arg, "--no-quiet")) {
            quiet = false;
        } else if (std.mem.eql(u8, arg, "--cruft")) {
            // accepted
        } else if (std.mem.eql(u8, arg, "--force")) {
            // accepted
        } else if (std.mem.eql(u8, arg, "--detach") or std.mem.eql(u8, arg, "--no-detach")) {
            // accepted
        } else if (std.mem.eql(u8, arg, "--keep-largest-pack")) {
            // accepted
        } else if (std.mem.startsWith(u8, arg, "--max-cruft-size=") or
            std.mem.startsWith(u8, arg, "--expire-to="))
        {
            // accepted
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStderr("usage: git gc [--aggressive] [--auto] [--quiet] [--prune=<date>]\n");
            std.process.exit(129);
        } else if (std.mem.startsWith(u8, arg, "-")) {
            try platform_impl.writeStderr("usage: git gc [--aggressive] [--auto] [--quiet] [--prune=<date>]\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Run native repack
    if (!quiet) {
        try platform_impl.writeStderr("Enumerating objects: done.\n");
        try platform_impl.writeStderr("Counting objects: done.\n");
    }

    // Repack objects into a single pack
    try doNativeRepack(allocator, git_dir, platform_impl, quiet);

    // Prune loose objects
    if (!std.mem.eql(u8, prune_option, "never")) {
        try doNativePrune(allocator, git_dir, platform_impl, prune_option);
    }

    // Pack refs
    try packRefs(allocator, git_dir);

    // Remove empty directories
    try cleanEmptyObjectDirs(allocator, git_dir);
}

fn nativeCmdPrune(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var verbose = false;
    var dry_run = false;
    var expire: []const u8 = "";
    var no_expire = false;
    var positional_args = std.ArrayListUnmanaged([]const u8){};
    defer positional_args.deinit(allocator);
    var saw_dashdash = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (saw_dashdash) {
            positional_args.append(allocator, arg) catch {};
            continue;
        }
        if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.eql(u8, arg, "--dry-run")) {
            dry_run = true;
        } else if (std.mem.startsWith(u8, arg, "--expire=")) {
            expire = arg["--expire=".len..];
        } else if (std.mem.eql(u8, arg, "--expire")) {
            i += 1;
            if (i < args.len) {
                expire = args[i];
            } else {
                try platform_impl.writeStderr("error: option `expire' requires a value\n");
                std.process.exit(128);
            }
        } else if (std.mem.eql(u8, arg, "--no-expire")) {
            no_expire = true;
        } else if (std.mem.eql(u8, arg, "--progress") or std.mem.eql(u8, arg, "--no-progress")) {
            // Accepted
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStderr("usage: git prune [-n] [-v] [--progress] [--expire <time>] [--] [<head>...]\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--")) {
            saw_dashdash = true;
        } else if (std.mem.startsWith(u8, arg, "-")) {
            const msg = std.fmt.allocPrint(allocator, "error: unknown option `{s}'\nusage: git prune [-n] [-v] [--progress] [--expire <time>] [--] [<head>...]\n", .{arg}) catch unreachable;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        } else {
            positional_args.append(allocator, arg) catch {};
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    // Validate positional args are valid object refs
    for (positional_args.items) |pos_arg| {
        // Try to resolve the arg as an object reference
        const resolved = resolveRevision(git_dir, pos_arg, platform_impl, allocator) catch {
            const msg = std.fmt.allocPrint(allocator, "fatal: not a valid object name: '{s}'\n", .{pos_arg}) catch unreachable;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        allocator.free(resolved);
    }

    // Validate expire value before proceeding
    if (!no_expire and expire.len > 0) {
        _ = parseExpireTime(expire) catch {
            const msg = std.fmt.allocPrint(allocator, "fatal: malformed expiration date '{s}'\n", .{expire}) catch unreachable;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
    }

    try doNativePrune(allocator, git_dir, platform_impl, expire);
}

fn parseExpireTime(expire: []const u8) error{InvalidFormat}!i128 {
    // Parse expire time strings like "1.day", "2.weeks.ago", "now", "never"
    if (expire.len == 0 or std.mem.eql(u8, expire, "now")) return std.math.maxInt(i128); // prune everything
    if (std.mem.eql(u8, expire, "never")) return 0; // prune nothing

    // Try to parse as a relative time
    const now = std.time.timestamp();
    if (std.mem.indexOf(u8, expire, "day")) |_| {
        // Extract number
        var num: i64 = 1;
        var digits_end: usize = 0;
        while (digits_end < expire.len and std.ascii.isDigit(expire[digits_end])) digits_end += 1;
        if (digits_end > 0) {
            num = std.fmt.parseInt(i64, expire[0..digits_end], 10) catch 1;
        }
        return now - num * 86400;
    }
    if (std.mem.indexOf(u8, expire, "week")) |_| {
        var num: i64 = 1;
        var digits_end: usize = 0;
        while (digits_end < expire.len and std.ascii.isDigit(expire[digits_end])) digits_end += 1;
        if (digits_end > 0) {
            num = std.fmt.parseInt(i64, expire[0..digits_end], 10) catch 1;
        }
        return now - num * 7 * 86400;
    }
    if (std.mem.indexOf(u8, expire, "hour")) |_| {
        var num: i64 = 1;
        var digits_end: usize = 0;
        while (digits_end < expire.len and std.ascii.isDigit(expire[digits_end])) digits_end += 1;
        if (digits_end > 0) {
            num = std.fmt.parseInt(i64, expire[0..digits_end], 10) catch 1;
        }
        return now - num * 3600;
    }
    // Default: 2 weeks ago
    return now - 14 * 86400;
}

fn doNativePrune(allocator: std.mem.Allocator, git_dir: []const u8, platform_impl: anytype, expire: []const u8) !void {
    _ = platform_impl;

    const expire_cutoff = parseExpireTime(expire) catch std.time.timestamp() - 14 * 86400;

    // First, remove stale temporary files in objects/
    const objects_dir_path_tmp = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch return;
    defer allocator.free(objects_dir_path_tmp);
    {
        var obj_dir = std.fs.cwd().openDir(objects_dir_path_tmp, .{ .iterate = true }) catch {
            // no objects dir
            return;
        };
        defer obj_dir.close();
        var iter = obj_dir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file and std.mem.startsWith(u8, entry.name, "tmp_")) {
                // Check mtime
                const file_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path_tmp, entry.name }) catch continue;
                defer allocator.free(file_path);
                const stat = std.fs.cwd().statFile(file_path) catch continue;
                const mtime_sec: i128 = @divTrunc(stat.mtime, 1_000_000_000);
                if (mtime_sec < expire_cutoff) {
                    std.fs.cwd().deleteFile(file_path) catch {};
                }
            }
        }
    }

    // Collect all reachable objects
    var reachable = std.StringHashMap(void).init(allocator);
    defer reachable.deinit();

    // Walk from all refs to find reachable objects
    // Read HEAD
    const head_path = std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_dir}) catch return;
    defer allocator.free(head_path);
    if (std.fs.cwd().readFileAlloc(allocator, head_path, 1024)) |head_content| {
        defer allocator.free(head_content);
        const trimmed = std.mem.trim(u8, head_content, " \t\n\r");
        if (std.mem.startsWith(u8, trimmed, "ref: ")) {
            // Symbolic ref - resolve
            const ref_name = trimmed["ref: ".len..];
            const ref_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name }) catch return;
            defer allocator.free(ref_path);
            if (std.fs.cwd().readFileAlloc(allocator, ref_path, 1024)) |ref_content| {
                defer allocator.free(ref_content);
                const hash = std.mem.trim(u8, ref_content, " \t\n\r");
                if (hash.len >= 40) {
                    try reachable.put(try allocator.dupe(u8, hash[0..40]), {});
                }
            } else |_| {}
        } else if (trimmed.len >= 40) {
            try reachable.put(try allocator.dupe(u8, trimmed[0..40]), {});
        }
    } else |_| {}

    // For now, prune is a no-op for loose objects that are in packs
    // Full implementation would walk commit graphs
    
    // Remove loose objects that are also in pack files
    const pack_dir = std.fmt.allocPrint(allocator, "{s}/objects/pack", .{git_dir}) catch return;
    defer allocator.free(pack_dir);

    var packed_objects = std.StringHashMap(void).init(allocator);
    defer packed_objects.deinit();

    // Read all pack indices to find packed objects
    if (std.fs.cwd().openDir(pack_dir, .{ .iterate = true })) |pd| {
        var pack_d = pd;
        defer pack_d.close();
        var iter = pack_d.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".idx")) {
                const idx_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir, entry.name }) catch continue;
                defer allocator.free(idx_path);
                const idx_data = std.fs.cwd().readFileAlloc(allocator, idx_path, 100 * 1024 * 1024) catch continue;
                defer allocator.free(idx_data);

                // Parse idx v2 to get list of objects
                if (idx_data.len > 8 and std.mem.eql(u8, idx_data[0..4], "\xfftOc")) {
                    const num_objects = std.mem.readInt(u32, idx_data[8 + 255 * 4 ..][0..4], .big);
                    const sha_offset: usize = 8 + 256 * 4;
                    var obj_idx: usize = 0;
                    while (obj_idx < num_objects) : (obj_idx += 1) {
                        const sha_start = sha_offset + obj_idx * 20;
                        if (sha_start + 20 > idx_data.len) break;
                        const sha_bytes = idx_data[sha_start..sha_start + 20];
                        var hex: [40]u8 = undefined;
                        for (sha_bytes, 0..) |b, bi| {
                            _ = std.fmt.bufPrint(hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
                        }
                        try packed_objects.put(try allocator.dupe(u8, &hex), {});
                    }
                }
            }
        }
    } else |_| {}

    // Remove loose objects that are packed
    const objects_dir_path = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch return;
    defer allocator.free(objects_dir_path);

    var hex_dirs: usize = 0;
    while (hex_dirs < 256) : (hex_dirs += 1) {
        var hex_buf: [2]u8 = undefined;
        _ = std.fmt.bufPrint(&hex_buf, "{x:0>2}", .{hex_dirs}) catch continue;
        const subdir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path, hex_buf }) catch continue;
        defer allocator.free(subdir_path);

        var subdir = std.fs.cwd().openDir(subdir_path, .{ .iterate = true }) catch continue;
        defer subdir.close();

        var iter = subdir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file and entry.name.len == 38) {
                var full_hash: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&full_hash, "{s}{s}", .{ hex_buf, entry.name }) catch continue;
                if (packed_objects.contains(&full_hash)) {
                    // Object is in a pack file, can be pruned
                    const file_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ subdir_path, entry.name }) catch continue;
                    defer allocator.free(file_path);
                    std.fs.cwd().deleteFile(file_path) catch {};
                }
            }
        }
    }
}

fn doNativeRepack(allocator: std.mem.Allocator, git_dir: []const u8, platform_impl: anytype, quiet: bool) !void {
    _ = quiet;

    // Simple repack: collect all loose objects and write them into a pack file
    // Also consolidate existing packs
    var all_objects = std.array_list.Managed([20]u8).init(allocator);
    defer all_objects.deinit();

    const objects_dir_path = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch return;
    defer allocator.free(objects_dir_path);

    // Enumerate loose objects
    var hex_dirs: usize = 0;
    while (hex_dirs < 256) : (hex_dirs += 1) {
        var hex_buf: [2]u8 = undefined;
        _ = std.fmt.bufPrint(&hex_buf, "{x:0>2}", .{hex_dirs}) catch continue;
        const subdir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path, hex_buf }) catch continue;
        defer allocator.free(subdir_path);

        var subdir = std.fs.cwd().openDir(subdir_path, .{ .iterate = true }) catch continue;
        defer subdir.close();

        var iter = subdir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file and entry.name.len == 38) {
                var full_hex: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&full_hex, "{s}{s}", .{ hex_buf, entry.name }) catch continue;
                var sha: [20]u8 = undefined;
                for (&sha, 0..) |*b, bi| {
                    b.* = std.fmt.parseInt(u8, full_hex[bi * 2 .. bi * 2 + 2], 16) catch continue;
                }
                try all_objects.append(sha);
            }
        }
    }

    // Also collect objects from existing packs
    var object_hashes = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (object_hashes.items) |h| allocator.free(h);
        object_hashes.deinit();
    }

    // Convert loose object SHAs to hex strings
    for (all_objects.items) |sha| {
        var hex: [40]u8 = undefined;
        for (sha, 0..) |b, bi| {
            _ = std.fmt.bufPrint(hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
        }
        try object_hashes.append(try allocator.dupe(u8, &hex));
    }

    // Also enumerate objects in existing pack files
    const pack_dir = std.fmt.allocPrint(allocator, "{s}/objects/pack", .{git_dir}) catch return;
    defer allocator.free(pack_dir);
    std.fs.cwd().makePath(pack_dir) catch {};

    var existing_packs = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (existing_packs.items) |p| allocator.free(p);
        existing_packs.deinit();
    }

    if (std.fs.cwd().openDir(pack_dir, .{ .iterate = true })) |pd| {
        var pack_d = pd;
        defer pack_d.close();
        var pack_iter = pack_d.iterate();
        while (pack_iter.next() catch null) |entry| {
            if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".idx")) {
                try existing_packs.append(try allocator.dupe(u8, entry.name));
                // Read idx to get object list
                const idx_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir, entry.name }) catch continue;
                defer allocator.free(idx_path);
                const idx_data = std.fs.cwd().readFileAlloc(allocator, idx_path, 100 * 1024 * 1024) catch continue;
                defer allocator.free(idx_data);

                if (idx_data.len > 8 and std.mem.eql(u8, idx_data[0..4], "\xfftOc")) {
                    const num_objects_packed = std.mem.readInt(u32, idx_data[8 + 255 * 4 ..][0..4], .big);
                    const sha_offset: usize = 8 + 256 * 4;
                    var obj_idx: usize = 0;
                    while (obj_idx < num_objects_packed) : (obj_idx += 1) {
                        const sha_start = sha_offset + obj_idx * 20;
                        if (sha_start + 20 > idx_data.len) break;
                        const sha_bytes = idx_data[sha_start .. sha_start + 20];
                        var hex: [40]u8 = undefined;
                        for (sha_bytes, 0..) |b, bi| {
                            _ = std.fmt.bufPrint(hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
                        }
                        // Don't duplicate
                        var already_have = false;
                        for (object_hashes.items) |existing| {
                            if (std.mem.eql(u8, existing, &hex)) {
                                already_have = true;
                                break;
                            }
                        }
                        if (!already_have) {
                            try object_hashes.append(try allocator.dupe(u8, &hex));
                        }
                    }
                }
            }
        }
    } else |_| {}

    // If no objects at all, nothing to do
    if (object_hashes.items.len == 0) return;

    // Build pack data, tracking offsets and SHA-1s for idx generation
    var pack_data = std.array_list.Managed(u8).init(allocator);
    defer pack_data.deinit();

    var pack_entries = std.array_list.Managed(PackIdxEntry).init(allocator);
    defer pack_entries.deinit();

    // Pack header
    try pack_data.appendSlice("PACK");
    const version: u32 = 2;
    try pack_data.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, version)));
    // We'll patch the object count after writing (some objects may fail to load)
    const count_offset = pack_data.items.len;
    try pack_data.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 0)));

    // Write each object
    for (object_hashes.items) |hash| {
        if (objects.GitObject.load(hash, git_dir, platform_impl, allocator)) |obj| {
            defer obj.deinit(allocator);

            // Parse hex hash to binary SHA
            var sha_bytes: [20]u8 = undefined;
            for (&sha_bytes, 0..) |*b, bi| {
                b.* = std.fmt.parseInt(u8, hash[bi * 2 .. bi * 2 + 2], 16) catch 0;
            }

            const entry_offset: u32 = @intCast(pack_data.items.len);
            const type_num: u8 = switch (obj.type) {
                .commit => 1,
                .tree => 2,
                .blob => 3,
                .tag => 4,
            };
            var obj_size = obj.data.len;
            var first_byte: u8 = (type_num << 4) | @as(u8, @intCast(obj_size & 0x0F));
            obj_size >>= 4;
            if (obj_size > 0) first_byte |= 0x80;
            try pack_data.append(first_byte);
            while (obj_size > 0) {
                var byte: u8 = @intCast(obj_size & 0x7F);
                obj_size >>= 7;
                if (obj_size > 0) byte |= 0x80;
                try pack_data.append(byte);
            }
            // Compress data
            const compressed = zlib_compat_mod.compressSlice(allocator, obj.data) catch continue;
            defer allocator.free(compressed);
            try pack_data.appendSlice(compressed);

            // CRC32 over the entire entry (header + compressed data)
            const entry_data = pack_data.items[entry_offset..];
            const crc = std.hash.crc.Crc32.hash(entry_data);

            try pack_entries.append(.{ .sha = sha_bytes, .offset = entry_offset, .crc = crc });
        } else |_| {
            continue;
        }
    }

    // Patch actual object count
    const actual_count: u32 = @intCast(pack_entries.items.len);
    @memcpy(pack_data.items[count_offset..][0..4], &std.mem.toBytes(std.mem.nativeToBig(u32, actual_count)));

    // Compute SHA1 checksum of pack data
    var sha1 = std.crypto.hash.Sha1.init(.{});
    sha1.update(pack_data.items);
    const checksum = sha1.finalResult();
    try pack_data.appendSlice(&checksum);

    // Write pack file
    var hash_hex: [40]u8 = undefined;
    for (checksum, 0..) |b, bi| {
        _ = std.fmt.bufPrint(hash_hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
    }

    const pack_filename = std.fmt.allocPrint(allocator, "{s}/pack-{s}.pack", .{ pack_dir, hash_hex }) catch return;
    defer allocator.free(pack_filename);
    std.fs.cwd().writeFile(.{ .sub_path = pack_filename, .data = pack_data.items }) catch return;

    // Generate idx directly from tracked entries (no re-parsing needed)
    try generatePackIdxFromEntries(allocator, pack_entries.items, &checksum, pack_dir, &hash_hex);

    // Delete old pack files (but not the newly created one)
    const new_idx_name = std.fmt.allocPrint(allocator, "pack-{s}.idx", .{hash_hex}) catch "";
    defer if (new_idx_name.len > 0) allocator.free(new_idx_name);
    for (existing_packs.items) |old_idx| {
        // Skip if this is our newly created pack
        if (std.mem.eql(u8, old_idx, new_idx_name)) continue;
        const old_idx_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir, old_idx }) catch continue;
        defer allocator.free(old_idx_path);
        std.fs.cwd().deleteFile(old_idx_path) catch {};
        // Also delete .pack
        if (std.mem.endsWith(u8, old_idx, ".idx")) {
            const base = old_idx[0 .. old_idx.len - 4];
            const old_pack_path = std.fmt.allocPrint(allocator, "{s}/{s}.pack", .{ pack_dir, base }) catch continue;
            defer allocator.free(old_pack_path);
            std.fs.cwd().deleteFile(old_pack_path) catch {};
        }
    }

    // Delete loose objects that are now in the pack
    for (all_objects.items) |sha| {
        var hex: [40]u8 = undefined;
        for (sha, 0..) |b, bi| {
            _ = std.fmt.bufPrint(hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
        }
        const loose_path = std.fmt.allocPrint(allocator, "{s}/{s}/{s}", .{ objects_dir_path, hex[0..2], hex[2..] }) catch continue;
        defer allocator.free(loose_path);
        std.fs.cwd().deleteFile(loose_path) catch {};
    }

    // Update objects/info/packs to list current pack files
    {
        const obj_info_dir = std.fmt.allocPrint(allocator, "{s}/objects/info", .{git_dir}) catch return;
        defer allocator.free(obj_info_dir);
        std.fs.cwd().makePath(obj_info_dir) catch {};

        const packs_file_path = std.fmt.allocPrint(allocator, "{s}/objects/info/packs", .{git_dir}) catch return;
        defer allocator.free(packs_file_path);

        var content = std.array_list.Managed(u8).init(allocator);
        defer content.deinit();

        if (std.fs.cwd().openDir(pack_dir, .{ .iterate = true })) |pd| {
            var pack_d2 = pd;
            defer pack_d2.close();
            var pack_names2 = std.array_list.Managed([]const u8).init(allocator);
            defer {
                for (pack_names2.items) |n| allocator.free(n);
                pack_names2.deinit();
            }
            var iter2 = pack_d2.iterate();
            while (iter2.next() catch null) |entry| {
                if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".pack")) {
                    pack_names2.append(allocator.dupe(u8, entry.name) catch continue) catch {};
                }
            }
            std.mem.sort([]const u8, pack_names2.items, {}, struct {
                fn lessThan(_: void, a: []const u8, b: []const u8) bool {
                    return std.mem.order(u8, a, b).compare(.lt);
                }
            }.lessThan);
            for (pack_names2.items) |name| {
                const line = std.fmt.allocPrint(allocator, "P {s}\n", .{name}) catch continue;
                defer allocator.free(line);
                content.appendSlice(line) catch {};
            }
        } else |_| {}
        content.append('\n') catch {};
        std.fs.cwd().writeFile(.{ .sub_path = packs_file_path, .data = content.items }) catch {};
    }
}

fn packRefs(allocator: std.mem.Allocator, git_dir: []const u8) !void {
    try packRefsImpl(allocator, git_dir, true);
}

fn packRefsImpl(allocator: std.mem.Allocator, git_dir: []const u8, prune: bool) !void {
    // Collect all refs: both from packed-refs and loose refs
    var ref_map = std.StringHashMap([]const u8).init(allocator);
    defer {
        var it = ref_map.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.*);
        }
        ref_map.deinit();
    }

    // Read existing packed-refs
    const packed_refs_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir});
    defer allocator.free(packed_refs_path);
    if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_content| {
        defer allocator.free(packed_content);
        var lines = std.mem.splitScalar(u8, packed_content, '\n');
        while (lines.next()) |line| {
            if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
            if (std.mem.indexOfScalar(u8, line, ' ')) |space_idx| {
                const hash = line[0..space_idx];
                const name = line[space_idx + 1..];
                if (hash.len >= 40) {
                    const name_dup = try allocator.dupe(u8, name);
                    const hash_dup = try allocator.dupe(u8, hash[0..40]);
                    const gop = try ref_map.getOrPut(name_dup);
                    if (gop.found_existing) {
                        allocator.free(name_dup);
                        allocator.free(gop.value_ptr.*);
                    }
                    gop.value_ptr.* = hash_dup;
                }
            }
        }
    } else |_| {}

    // Collect loose refs from refs/ directory
    var loose_refs = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (loose_refs.items) |r| allocator.free(r);
        loose_refs.deinit();
    }
    try collectLooseRefsForPack(allocator, git_dir, "refs", &ref_map, &loose_refs);

    // Write packed-refs file
    var output = std.array_list.Managed(u8).init(allocator);
    defer output.deinit();
    try output.appendSlice("# pack-refs with: peeled fully-peeled sorted \n");

    // Sort ref names
    var names = std.array_list.Managed([]const u8).init(allocator);
    defer names.deinit();
    var it = ref_map.iterator();
    while (it.next()) |entry| {
        try names.append(entry.key_ptr.*);
    }
    std.mem.sort([]const u8, names.items, {}, struct {
        fn lessThan(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.lessThan);

    for (names.items) |name| {
        if (ref_map.get(name)) |hash| {
            try output.appendSlice(hash);
            try output.append(' ');
            try output.appendSlice(name);
            try output.append('\n');
        }
    }

    std.fs.cwd().writeFile(.{ .sub_path = packed_refs_path, .data = output.items }) catch {};

    // Prune loose refs that are now packed
    if (prune) {
        for (loose_refs.items) |ref_path| {
            const full_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_path }) catch continue;
            defer allocator.free(full_path);
            std.fs.cwd().deleteFile(full_path) catch {};
        }
        // Clean up empty directories
        cleanEmptyRefDirs2(allocator, git_dir, "refs");
    }
}

fn collectLooseRefsForPack(allocator: std.mem.Allocator, git_dir: []const u8, prefix: []const u8, ref_map: *std.StringHashMap([]const u8), loose_refs: *std.array_list.Managed([]const u8)) !void {
    const dir_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, prefix });
    defer allocator.free(dir_path);

    var dir = std.fs.cwd().openDir(dir_path, .{ .iterate = true }) catch return;
    defer dir.close();

    var iter = dir.iterate();
    while (try iter.next()) |entry| {
        const child_prefix = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name });
        defer allocator.free(child_prefix);

        if (entry.kind == .directory) {
            try collectLooseRefsForPack(allocator, git_dir, child_prefix, ref_map, loose_refs);
        } else if (entry.kind == .file) {
            // Read the file to get the hash
            const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, child_prefix });
            defer allocator.free(file_path);
            const content = std.fs.cwd().readFileAlloc(allocator, file_path, 1024) catch continue;
            defer allocator.free(content);
            const trimmed = std.mem.trimRight(u8, content, " \t\r\n");
            // Skip symbolic refs
            if (std.mem.startsWith(u8, trimmed, "ref: ")) continue;
            if (trimmed.len >= 40) {
                const name_dup = try allocator.dupe(u8, child_prefix);
                const hash_dup = try allocator.dupe(u8, trimmed[0..40]);
                const gop = try ref_map.getOrPut(name_dup);
                if (gop.found_existing) {
                    allocator.free(name_dup);
                    allocator.free(gop.value_ptr.*);
                }
                gop.value_ptr.* = hash_dup;
                try loose_refs.append(try allocator.dupe(u8, child_prefix));
            }
        }
    }
}

fn cleanEmptyRefDirs2(allocator: std.mem.Allocator, git_dir: []const u8, prefix: []const u8) void {
    const dir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, prefix }) catch return;
    defer allocator.free(dir_path);

    var dir = std.fs.cwd().openDir(dir_path, .{ .iterate = true }) catch return;
    defer dir.close();

    // Collect subdirectory names first
    var subdirs = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (subdirs.items) |s| allocator.free(s);
        subdirs.deinit();
    }
    var iter = dir.iterate();
    while (iter.next() catch null) |entry| {
        if (entry.kind == .directory) {
            subdirs.append(allocator.dupe(u8, entry.name) catch continue) catch {};
        }
    }

    for (subdirs.items) |subdir| {
        const child_prefix = std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, subdir }) catch continue;
        defer allocator.free(child_prefix);
        cleanEmptyRefDirs2(allocator, git_dir, child_prefix);
    }

    // Try to remove this dir if empty (and not the "refs" root itself)
    if (!std.mem.eql(u8, prefix, "refs")) {
        std.fs.cwd().deleteDir(dir_path) catch {};
    }
}

fn nativeCmdPackRefs(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    _ = platform_impl;
    var prune_flag = false;
    var all_flag = false;
    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--all")) {
            all_flag = true;
        } else if (std.mem.eql(u8, arg, "--prune")) {
            prune_flag = true;
        } else if (std.mem.eql(u8, arg, "--no-prune")) {
            prune_flag = false;
        }
    }
    

    const git_dir = try findGitDir();
    try packRefsImpl(allocator, git_dir, prune_flag);
}

fn cleanEmptyObjectDirs(allocator: std.mem.Allocator, git_dir: []const u8) !void {
    const objects_dir_path = std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir}) catch return;
    defer allocator.free(objects_dir_path);

    var hex_dirs: usize = 0;
    while (hex_dirs < 256) : (hex_dirs += 1) {
        var hex_buf: [2]u8 = undefined;
        _ = std.fmt.bufPrint(&hex_buf, "{x:0>2}", .{hex_dirs}) catch continue;
        const subdir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path, hex_buf }) catch continue;
        defer allocator.free(subdir_path);

        // Try to remove - will fail if not empty (which is fine)
        std.fs.cwd().deleteDir(subdir_path) catch {};
    }
}

fn nativeCmdRepack(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var ad_flag = false;
    var quiet = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "-a") or std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "-A") or std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "-F") or std.mem.eql(u8, arg, "-l")) {
            ad_flag = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--no-repack-all-into-one") or
            std.mem.eql(u8, arg, "--keep-unreachable") or
            std.mem.eql(u8, arg, "--no-write-bitmap-index") or
            std.mem.eql(u8, arg, "--write-bitmap-index") or
            std.mem.eql(u8, arg, "--write-midx") or
            std.mem.eql(u8, arg, "--geometric=2") or
            std.mem.eql(u8, arg, "--no-cruft") or
            std.mem.eql(u8, arg, "--cruft"))
        {
            // Accepted flags
        } else if (std.mem.startsWith(u8, arg, "--geometric=") or
            std.mem.startsWith(u8, arg, "--window=") or
            std.mem.startsWith(u8, arg, "--depth=") or
            std.mem.startsWith(u8, arg, "--threads=") or
            std.mem.startsWith(u8, arg, "--max-pack-size="))
        {
            // Accepted with value
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git repack [<options>]\n");
            std.process.exit(129);
        }
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };

    try doNativeRepack(allocator, git_dir, platform_impl, quiet);
}

fn nativeCmdPackObjects(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var base_name: ?[]const u8 = null;
    var stdout_mode = false;
    var progress = true;
    var revs_mode = false;
    var use_all = false;
    var stdin_packs = false;
    var write_bitmap = false;
    var name_hash_version: i32 = 1;
    var include_tag = false;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--stdin")) {
            try platform_impl.writeStderr("fatal: disallowed abbreviated or ambiguous option 'stdin'\n");
            std.process.exit(1);
            unreachable;
        } else if (std.mem.eql(u8, arg, "--stdout")) {
            stdout_mode = true;
        } else if (std.mem.eql(u8, arg, "--all-progress") or std.mem.eql(u8, arg, "--all-progress-implied")) {
            // accepted
        } else if (std.mem.eql(u8, arg, "-q")) {
            progress = false;
        } else if (std.mem.eql(u8, arg, "--progress")) {
            progress = true;
        } else if (std.mem.eql(u8, arg, "--revs")) {
            revs_mode = true;
        } else if (std.mem.eql(u8, arg, "--stdin-packs")) {
            stdin_packs = true;
        } else if (std.mem.eql(u8, arg, "--all")) {
            use_all = true;
        } else if (std.mem.eql(u8, arg, "--no-reuse-delta") or std.mem.eql(u8, arg, "--no-reuse-object")) {
            // accepted
        } else if (std.mem.eql(u8, arg, "--include-tag")) {
            include_tag = true;
        } else if (std.mem.eql(u8, arg, "--thin") or
            std.mem.eql(u8, arg, "--delta-base-offset") or
            std.mem.eql(u8, arg, "--keep-true-parents") or std.mem.eql(u8, arg, "--honor-pack-keep") or
            std.mem.eql(u8, arg, "--non-empty") or std.mem.eql(u8, arg, "--all") or
            std.mem.eql(u8, arg, "--local") or std.mem.eql(u8, arg, "--incremental") or
            std.mem.eql(u8, arg, "--unpacked") or std.mem.eql(u8, arg, "--no-path-walk") or
            std.mem.eql(u8, arg, "--path-walk") or std.mem.eql(u8, arg, "--reflog") or
            std.mem.eql(u8, arg, "--indexed-objects") or std.mem.eql(u8, arg, "--unpack-unreachable"))
        {
            // Accepted flags
        } else if (std.mem.eql(u8, arg, "--write-bitmap-index")) {
            write_bitmap = true;
        } else if (std.mem.startsWith(u8, arg, "--index-version=")) {
            // Validate --index-version=<ver>[,<offset>]
            const val = arg["--index-version=".len..];
            if (std.mem.indexOfScalar(u8, val, ',')) |comma_pos| {
                const ver_str = val[0..comma_pos];
                const off_str = val[comma_pos + 1 ..];
                const ver = std.fmt.parseInt(u32, ver_str, 10) catch {
                    const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                    unreachable;
                };
                if (ver < 1 or ver > 2) {
                    const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                    unreachable;
                }
                if (off_str.len == 0) {
                    const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                    unreachable;
                }
                // Parse offset (may be hex with 0x prefix)
                if (std.mem.startsWith(u8, off_str, "0x") or std.mem.startsWith(u8, off_str, "0X")) {
                    _ = std.fmt.parseInt(u64, off_str[2..], 16) catch {
                        const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(1);
                        unreachable;
                    };
                } else {
                    _ = std.fmt.parseInt(u64, off_str, 10) catch {
                        const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                        defer allocator.free(msg);
                        try platform_impl.writeStderr(msg);
                        std.process.exit(1);
                        unreachable;
                    };
                }
            } else {
                const ver = std.fmt.parseInt(u32, val, 10) catch {
                    const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                    unreachable;
                };
                if (ver < 1 or ver > 2) {
                    const msg = try std.fmt.allocPrint(allocator, "bad index version '{s}'\n", .{val});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(1);
                    unreachable;
                }
            }
        } else if (std.mem.startsWith(u8, arg, "--name-hash-version=")) {
            // Validate --name-hash-version=<ver>
            const val = arg["--name-hash-version=".len..];
            const ver = std.fmt.parseInt(i32, val, 10) catch {
                const msg = try std.fmt.allocPrint(allocator, "error: invalid --name-hash-version option: '{s}'\n", .{val});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
                unreachable;
            };
            if (ver == 0 or ver > 2) {
                try platform_impl.writeStderr("error: invalid --name-hash-version option\n");
                std.process.exit(1);
                unreachable;
            }
            // Negative values are treated as version 1
            name_hash_version = if (ver < 0) 1 else ver;
        } else if (std.mem.startsWith(u8, arg, "--window=") or
            std.mem.startsWith(u8, arg, "--depth=") or
            std.mem.startsWith(u8, arg, "--threads=") or
            std.mem.startsWith(u8, arg, "--max-pack-size=") or
            std.mem.startsWith(u8, arg, "--compression=") or
            std.mem.startsWith(u8, arg, "--filter=") or
            std.mem.startsWith(u8, arg, "--unpack-unreachable="))
        {
            // Accepted with value
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git pack-objects [<options>] base-name\n");
            std.process.exit(129);
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (base_name != null) {
                try platform_impl.writeStderr("usage: git pack-objects [<options>] base-name\n");
                std.process.exit(1);
            }
            base_name = arg;
        }
    }

    // Check incompatible options
    if (stdin_packs and revs_mode) {
        try platform_impl.writeStderr("error: --stdin-packs is incompatible with --revs\n");
        std.process.exit(1);
        unreachable;
    }

    // Warn about --write-bitmap-index with --name-hash-version=2
    if (write_bitmap and name_hash_version == 2 and !stdout_mode) {
        try platform_impl.writeStderr("warning: currently, --write-bitmap-index requires --name-hash-version=1\n");
    }

    if (base_name == null and !stdout_mode) {
        try platform_impl.writeStderr("usage: git pack-objects [<options>] base-name\n");
        std.process.exit(1);
    }

    const git_dir = findGitDir() catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
        unreachable;
    };

    // Read stdin
    const stdin = std.fs.File{ .handle = std.posix.STDIN_FILENO };
    const stdin_data = stdin.readToEndAlloc(allocator, 100 * 1024 * 1024) catch {
        try platform_impl.writeStderr("fatal: error reading stdin\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(stdin_data);

    // Collect object hashes to pack (deduplicated)
    var object_set = std.StringHashMap(void).init(allocator);
    defer object_set.deinit();
    var object_hashes = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (object_hashes.items) |h| allocator.free(h);
        object_hashes.deinit();
    }

    if (stdin_packs) {
        // --stdin-packs mode: each line is a pack name (without path)
        // Look for matching packs in objects/pack/ directory
        var lines_iter = std.mem.splitScalar(u8, stdin_data, '\n');
        while (lines_iter.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0) continue;
            // Check if the pack exists
            const pack_path = std.fmt.allocPrint(allocator, "{s}/objects/pack/pack-{s}.idx", .{ git_dir, trimmed }) catch continue;
            defer allocator.free(pack_path);
            std.fs.cwd().access(pack_path, .{}) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: could not find pack '{s}'\n", .{trimmed});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
                unreachable;
            };
            // TODO: actually read objects from the pack
        }
    } else if (revs_mode) {
        // --revs mode: treat stdin as revision arguments and walk reachable objects
        // An empty line terminates the revision input (matching git's behavior)
        var lines_iter = std.mem.splitScalar(u8, stdin_data, '\n');
        while (lines_iter.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0) break; // empty line terminates revision input
            if (trimmed[0] == '^') continue; // exclude ref

            var resolved: ?[]const u8 = null;
            if (trimmed.len >= 40) {
                const maybe_hash = trimmed[0..40];
                var is_hex = true;
                for (maybe_hash) |ch| {
                    if (!std.ascii.isHex(ch)) { is_hex = false; break; }
                }
                if (is_hex) resolved = try allocator.dupe(u8, maybe_hash);
            }
            if (resolved == null) {
                resolved = refs.resolveRef(git_dir, trimmed, platform_impl, allocator) catch {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{trimmed});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                };
            }
            if (resolved) |hash| {
                defer allocator.free(hash);
                try packObjectsWalkReachable(allocator, git_dir, hash, &object_set, &object_hashes, platform_impl);
            }
        }
    } else {
        // Non-revs mode: each line is an object ID, optionally followed by a name hint
        // Lines starting with '-' are exclude markers (object should not be packed)
        var exclude_set = std.StringHashMap(void).init(allocator);
        defer exclude_set.deinit();
        var lines_iter = std.mem.splitScalar(u8, stdin_data, '\n');
        while (lines_iter.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0) {
                if (line.len > 0 or (lines_iter.peek() != null)) {
                    const msg = try std.fmt.allocPrint(allocator, "fatal: expected object ID, got garbage:\n {s}\n\n", .{line});
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                    unreachable;
                }
                continue;
            }

            // Handle exclude lines: -<hash>
            const is_exclude = trimmed[0] == '-';
            const id_start: usize = if (is_exclude) 1 else 0;
            const rest = trimmed[id_start..];

            // Extract hash (first 40 hex chars), rest may be " name"
            const hash_end = @min(rest.len, 40);
            if (hash_end < 40) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: expected object ID, got garbage:\n {s}\n\n", .{trimmed});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }
            const hash = rest[0..40];
            var valid = true;
            for (hash) |ch| {
                if (!std.ascii.isHex(ch)) { valid = false; break; }
            }
            if (!valid) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: expected object ID, got garbage:\n {s}\n\n", .{trimmed});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
                unreachable;
            }

            if (is_exclude) {
                const duped = try allocator.dupe(u8, hash);
                try exclude_set.put(duped, {});
            } else {
                if (!object_set.contains(hash)) {
                    const duped = try allocator.dupe(u8, hash);
                    try object_set.put(duped, {});
                    try object_hashes.append(duped);
                }
            }
        }

        // Remove excluded objects
        if (exclude_set.count() > 0) {
            var excl_idx: usize = 0;
            while (excl_idx < object_hashes.items.len) {
                if (exclude_set.contains(object_hashes.items[excl_idx])) {
                    _ = object_set.remove(object_hashes.items[excl_idx]);
                    allocator.free(object_hashes.items[excl_idx]);
                    _ = object_hashes.orderedRemove(excl_idx);
                } else {
                    excl_idx += 1;
                }
            }
        }
    }

    if (use_all) {
        try packObjectsAddAllObjects(allocator, git_dir, &object_set, &object_hashes);
    }

    // --include-tag: find tags whose target is already in the object set
    if (include_tag) {
        // Scan refs/tags/ for tag objects
        const tags_dir_path = std.fmt.allocPrint(allocator, "{s}/refs/tags", .{git_dir}) catch unreachable;
        defer allocator.free(tags_dir_path);
        if (std.fs.cwd().openDir(tags_dir_path, .{ .iterate = true })) |dir_val| {
            var dir = dir_val;
            defer dir.close();
            var iter = dir.iterate();
            while (iter.next() catch null) |entry| {
                if (entry.kind == .directory) continue;
                // Read the ref file directly to get the raw hash (don't peel)
                const ref_file_path = std.fmt.allocPrint(allocator, "{s}/refs/tags/{s}", .{git_dir, entry.name}) catch continue;
                defer allocator.free(ref_file_path);
                const ref_content = std.fs.cwd().readFileAlloc(allocator, ref_file_path, 4096) catch continue;
                defer allocator.free(ref_content);
                const tag_hash = std.mem.trim(u8, ref_content, " \t\r\n");
                if (tag_hash.len < 40) continue;
                const tag_hash_40 = tag_hash[0..40];

                // Check if it's a tag object
                if (objects.GitObject.load(tag_hash_40, git_dir, platform_impl, allocator)) |tag_obj| {
                    defer tag_obj.deinit(allocator);
                    if (tag_obj.type == .tag) {
                        // Parse target from tag object
                        if (std.mem.indexOf(u8, tag_obj.data, "object ")) |obj_start| {
                            const hash_start = obj_start + 7;
                            if (hash_start + 40 <= tag_obj.data.len) {
                                const target_hash = tag_obj.data[hash_start..hash_start + 40];
                                // If target is in the pack, include the tag too
                                if (object_set.contains(target_hash)) {
                                    if (!object_set.contains(tag_hash_40)) {
                                        const duped = allocator.dupe(u8, tag_hash_40) catch continue;
                                        object_set.put(duped, {}) catch continue;
                                        object_hashes.append(duped) catch continue;
                                    }
                                }
                            }
                        }
                    }
                } else |_| {}
            }
        } else |_| {}

        // Also check packed-refs for tags
        const packed_refs_path = std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir}) catch unreachable;
        defer allocator.free(packed_refs_path);
        if (std.fs.cwd().readFileAlloc(allocator, packed_refs_path, 10 * 1024 * 1024)) |packed_data| {
            defer allocator.free(packed_data);
            var plines = std.mem.splitScalar(u8, packed_data, '\n');
            while (plines.next()) |pline| {
                if (pline.len == 0 or pline[0] == '#' or pline[0] == '^') continue;
                if (pline.len < 41) continue;
                const phash = pline[0..40];
                const pref = std.mem.trim(u8, pline[41..], " \t\r");
                if (!std.mem.startsWith(u8, pref, "refs/tags/")) continue;

                // Check if it's a tag object
                if (objects.GitObject.load(phash, git_dir, platform_impl, allocator)) |tag_obj| {
                    defer tag_obj.deinit(allocator);
                    if (tag_obj.type == .tag) {
                        if (std.mem.indexOf(u8, tag_obj.data, "object ")) |obj_start| {
                            const hash_start = obj_start + 7;
                            if (hash_start + 40 <= tag_obj.data.len) {
                                const target_hash = tag_obj.data[hash_start..hash_start + 40];
                                if (object_set.contains(target_hash)) {
                                    if (!object_set.contains(phash)) {
                                        const duped = allocator.dupe(u8, phash) catch continue;
                                        object_set.put(duped, {}) catch continue;
                                        object_hashes.append(duped) catch continue;
                                    }
                                }
                            }
                        }
                    }
                } else |_| {}
            }
        } else |_| {}
    }

    // Build the pack
    var pack_data = std.array_list.Managed(u8).init(allocator);
    defer pack_data.deinit();

    try pack_data.appendSlice("PACK");
    const version: u32 = 2;
    try pack_data.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, version)));
    const count_pos = pack_data.items.len;
    try pack_data.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 0)));

    var actual_count: u32 = 0;
    for (object_hashes.items) |hash| {
        if (objects.GitObject.load(hash, git_dir, platform_impl, allocator)) |obj| {
            defer obj.deinit(allocator);
            const type_num: u8 = switch (obj.type) {
                .commit => 1, .tree => 2, .blob => 3, .tag => 4,
            };
            var obj_size = obj.data.len;
            var first_byte: u8 = (type_num << 4) | @as(u8, @intCast(obj_size & 0x0F));
            obj_size >>= 4;
            if (obj_size > 0) first_byte |= 0x80;
            try pack_data.append(first_byte);
            while (obj_size > 0) {
                var byte: u8 = @intCast(obj_size & 0x7F);
                obj_size >>= 7;
                if (obj_size > 0) byte |= 0x80;
                try pack_data.append(byte);
            }
            const compressed = zlib_compat_mod.compressSlice(allocator, obj.data) catch continue;
            defer allocator.free(compressed);
            try pack_data.appendSlice(compressed);
            actual_count += 1;
        } else |_| { continue; }
    }

    const count_bytes = std.mem.toBytes(std.mem.nativeToBig(u32, actual_count));
    @memcpy(pack_data.items[count_pos..][0..4], &count_bytes);

    var sha1 = std.crypto.hash.Sha1.init(.{});
    sha1.update(pack_data.items);
    const checksum = sha1.finalResult();
    try pack_data.appendSlice(&checksum);

    if (stdout_mode) {
        const stdout = std.fs.File{ .handle = std.posix.STDOUT_FILENO };
        stdout.writeAll(pack_data.items) catch {};
    } else if (base_name) |name| {
        var hash_hex: [40]u8 = undefined;
        for (checksum, 0..) |b, bi| {
            _ = std.fmt.bufPrint(hash_hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
        }
        const pack_filename = std.fmt.allocPrint(allocator, "{s}-{s}.pack", .{ name, hash_hex }) catch unreachable;
        defer allocator.free(pack_filename);
        std.fs.cwd().writeFile(.{ .sub_path = pack_filename, .data = pack_data.items }) catch |err| {
            const msg = std.fmt.allocPrint(allocator, "fatal: unable to write pack file: {s}\n", .{@errorName(err)}) catch unreachable;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        const idx_filename = std.fmt.allocPrint(allocator, "{s}-{s}.idx", .{ name, hash_hex }) catch unreachable;
        defer allocator.free(idx_filename);
        generatePackIdxToFile(allocator, pack_data.items, idx_filename) catch {};
        const output = std.fmt.allocPrint(allocator, "{s}\n", .{hash_hex}) catch unreachable;
        defer allocator.free(output);
        try platform_impl.writeStdout(output);
    }

    if (progress) {
        const count_msg = std.fmt.allocPrint(allocator, "Total {d} (delta 0), reused 0 (delta 0), pack-reused 0\n", .{actual_count}) catch unreachable;
        defer allocator.free(count_msg);
        try platform_impl.writeStderr(count_msg);
    }
}

/// Walk all objects reachable from a commit and add them to the set
fn packObjectsWalkReachable(
    allocator: std.mem.Allocator,
    git_dir: []const u8,
    start_hash: []const u8,
    object_set: *std.StringHashMap(void),
    object_hashes: *std.array_list.Managed([]const u8),
    platform_impl: *const platform_mod.Platform,
) !void {
    var worklist = std.array_list.Managed([]const u8).init(allocator);
    defer {
        for (worklist.items) |item| allocator.free(item);
        worklist.deinit();
    }
    try worklist.append(try allocator.dupe(u8, start_hash));

    while (worklist.items.len > 0) {
        const hash = worklist.pop() orelse break;
        defer allocator.free(hash);

        if (object_set.contains(hash)) continue;

        const obj = objects.GitObject.load(hash, git_dir, platform_impl, allocator) catch continue;
        defer obj.deinit(allocator);

        const duped = try allocator.dupe(u8, hash);
        try object_set.put(duped, {});
        try object_hashes.append(duped);

        switch (obj.type) {
            .commit => {
                var line_iter = std.mem.splitScalar(u8, obj.data, '\n');
                while (line_iter.next()) |line| {
                    if (line.len == 0) break;
                    if (std.mem.startsWith(u8, line, "tree ") and line.len >= 45) {
                        try worklist.append(try allocator.dupe(u8, line[5..45]));
                    } else if (std.mem.startsWith(u8, line, "parent ") and line.len >= 47) {
                        try worklist.append(try allocator.dupe(u8, line[7..47]));
                    }
                }
            },
            .tree => {
                var tpos: usize = 0;
                while (tpos < obj.data.len) {
                    const null_pos = std.mem.indexOfScalarPos(u8, obj.data, tpos, 0) orelse break;
                    if (null_pos + 21 > obj.data.len) break;
                    const entry_hash_bytes = obj.data[null_pos + 1 .. null_pos + 21];
                    var entry_hex: [40]u8 = undefined;
                    for (entry_hash_bytes, 0..) |b, j| {
                        const hc = "0123456789abcdef";
                        entry_hex[j * 2] = hc[b >> 4];
                        entry_hex[j * 2 + 1] = hc[b & 0xf];
                    }
                    try worklist.append(try allocator.dupe(u8, &entry_hex));
                    tpos = null_pos + 21;
                }
            },
            .tag => {
                var line_iter = std.mem.splitScalar(u8, obj.data, '\n');
                while (line_iter.next()) |line| {
                    if (line.len == 0) break;
                    if (std.mem.startsWith(u8, line, "object ") and line.len >= 47) {
                        try worklist.append(try allocator.dupe(u8, line[7..47]));
                    }
                }
            },
            .blob => {},
        }
    }
}

/// Add all loose objects from the repository
fn packObjectsAddAllObjects(
    allocator: std.mem.Allocator,
    git_dir: []const u8,
    object_set: *std.StringHashMap(void),
    object_hashes: *std.array_list.Managed([]const u8),
) !void {
    const objects_dir_path = try std.fmt.allocPrint(allocator, "{s}/objects", .{git_dir});
    defer allocator.free(objects_dir_path);
    var hex_dirs: usize = 0;
    while (hex_dirs < 256) : (hex_dirs += 1) {
        var hex_buf: [2]u8 = undefined;
        _ = std.fmt.bufPrint(&hex_buf, "{x:0>2}", .{hex_dirs}) catch continue;
        const subdir_path = std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir_path, hex_buf }) catch continue;
        defer allocator.free(subdir_path);
        var subdir = std.fs.cwd().openDir(subdir_path, .{ .iterate = true }) catch continue;
        defer subdir.close();
        var iter = subdir.iterate();
        while (iter.next() catch null) |entry| {
            if (entry.kind == .file and entry.name.len == 38) {
                var full_hash: [40]u8 = undefined;
                @memcpy(full_hash[0..2], &hex_buf);
                @memcpy(full_hash[2..40], entry.name[0..38]);
                if (!object_set.contains(&full_hash)) {
                    const duped2 = try allocator.dupe(u8, &full_hash);
                    try object_set.put(duped2, {});
                    try object_hashes.append(duped2);
                }
            }
        }
    }
}

fn nativeCmdIndexPack(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var stdin_mode = false;
    var verify = false;
    var verbose = false;
    var strict = false;
    var pack_file: ?[]const u8 = null;
    var output_path: ?[]const u8 = null;

    var i = command_index + 1;
    while (i < args.len) : (i += 1) {
        const arg = args[i];
        if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
        } else if (std.mem.eql(u8, arg, "--verify")) {
            verify = true;
        } else if (std.mem.eql(u8, arg, "-v")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "-o")) {
            i += 1;
            if (i < args.len) output_path = args[i];
        } else if (std.mem.eql(u8, arg, "--strict") or std.mem.eql(u8, arg, "--fsck-objects")) {
            strict = true;
        } else if (std.mem.startsWith(u8, arg, "--keep")) {
            // --keep or --keep=<msg>: create .keep file
        } else if (std.mem.startsWith(u8, arg, "--index-version=") or
            std.mem.eql(u8, arg, "--fix-thin") or
            std.mem.eql(u8, arg, "--check-self-contained-and-connected") or
            std.mem.startsWith(u8, arg, "--threads=") or
            std.mem.startsWith(u8, arg, "--max-input-size=") or
            std.mem.startsWith(u8, arg, "--object-format="))
        {
            // Accepted flags
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git index-pack [--verify] [--stdin] [-o <index-file>] <pack-file>\n");
            std.process.exit(129);
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            pack_file = arg;
        }
    }

    if (!stdin_mode and pack_file == null) {
        try platform_impl.writeStderr("usage: git index-pack [--verify] [--stdin] [-o <index-file>] <pack-file>\n");
        std.process.exit(1);
    }

    var pack_data: []const u8 = undefined;
    var should_free_pack = false;

    if (stdin_mode) {
        const git_dir = findGitDir() catch {
            try platform_impl.writeStderr("fatal: --stdin requires a git repository\n");
            std.process.exit(128);
            unreachable;
        };
        const stdin = std.fs.File{ .handle = std.posix.STDIN_FILENO };
        pack_data = stdin.readToEndAlloc(allocator, 4 * 1024 * 1024 * 1024) catch {
            try platform_impl.writeStderr("fatal: error reading pack from stdin\n");
            std.process.exit(128);
            unreachable;
        };
        should_free_pack = true;

        // Output progress if verbose
        if (verbose) {
            // Parse num objects from pack header for progress
            if (pack_data.len >= 12 and std.mem.eql(u8, pack_data[0..4], "PACK")) {
                const n = std.mem.readInt(u32, pack_data[8..12], .big);
                const msg = std.fmt.allocPrint(allocator, "Receiving objects: 100% ({d}/{d}), done.\n", .{ n, n }) catch unreachable;
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                const msg2 = std.fmt.allocPrint(allocator, "Resolving deltas: 100% ({d}/{d}), done.\n", .{ @as(u32, 0), @as(u32, 0) }) catch unreachable;
                defer allocator.free(msg2);
                try platform_impl.writeStderr(msg2);
            }
        }

        // Write pack file to objects/pack/
        const pack_dir = std.fmt.allocPrint(allocator, "{s}/objects/pack", .{git_dir}) catch unreachable;
        defer allocator.free(pack_dir);
        std.fs.cwd().makePath(pack_dir) catch {};

        // Compute checksum for pack name
        if (pack_data.len >= 20) {
            const trailing_sha = pack_data[pack_data.len - 20..];
            var hash_hex: [40]u8 = undefined;
            for (trailing_sha, 0..) |b, bi| {
                _ = std.fmt.bufPrint(hash_hex[bi * 2 .. bi * 2 + 2], "{x:0>2}", .{b}) catch continue;
            }

            // In strict mode, check for duplicate objects
            if (strict) {
                if (packHasDuplicates(allocator, pack_data)) {
                    try platform_impl.writeStderr("fatal: pack has duplicate entries\n");
                    std.process.exit(1);
                    unreachable;
                }
            }

            const dest_pack = std.fmt.allocPrint(allocator, "{s}/pack-{s}.pack", .{ pack_dir, hash_hex }) catch unreachable;
            defer allocator.free(dest_pack);
            std.fs.cwd().writeFile(.{ .sub_path = dest_pack, .data = pack_data }) catch {};

            // Generate idx
            try generatePackIdx(allocator, pack_data, pack_dir, &hash_hex);

            const msg = std.fmt.allocPrint(allocator, "pack\t{s}\n", .{hash_hex}) catch unreachable;
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    } else if (pack_file) |pf| {
        pack_data = std.fs.cwd().readFileAlloc(allocator, pf, 4 * 1024 * 1024 * 1024) catch {
            const msg = std.fmt.allocPrint(allocator, "fatal: cannot open packfile '{s}'\n", .{pf}) catch unreachable;
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
            unreachable;
        };
        should_free_pack = true;

        if (verify) {
            // Just verify pack header
            if (pack_data.len < 12 or !std.mem.eql(u8, pack_data[0..4], "PACK")) {
                try platform_impl.writeStderr("fatal: not a valid pack file\n");
                std.process.exit(128);
            }
            // Success for verify
            return;
        }

        // Generate index file
        const idx_path = if (output_path) |op| op else blk: {
            if (std.mem.endsWith(u8, pf, ".pack")) {
                break :blk try std.fmt.allocPrint(allocator, "{s}idx", .{pf[0 .. pf.len - 4]});
            }
            break :blk try std.fmt.allocPrint(allocator, "{s}.idx", .{pf});
        };
        defer if (output_path == null) allocator.free(idx_path);

        try generatePackIdxToFile(allocator, pack_data, idx_path);

        // Create .keep file if --keep was specified
        {
            var ki = command_index + 1;
            while (ki < args.len) : (ki += 1) {
                if (std.mem.startsWith(u8, args[ki], "--keep")) {
                    const keep_msg = if (std.mem.startsWith(u8, args[ki], "--keep="))
                        args[ki]["--keep=".len..]
                    else
                        "";
                    const keep_path = if (std.mem.endsWith(u8, pf, ".pack"))
                        try std.fmt.allocPrint(allocator, "{s}keep", .{pf[0 .. pf.len - 4]})
                    else
                        try std.fmt.allocPrint(allocator, "{s}.keep", .{pf});
                    defer allocator.free(keep_path);
                    const keep_content = try std.fmt.allocPrint(allocator, "{s}\n", .{keep_msg});
                    defer allocator.free(keep_content);
                    std.fs.cwd().writeFile(.{ .sub_path = keep_path, .data = keep_content }) catch {};
                    break;
                }
            }
        }
    }

    if (should_free_pack) {
        allocator.free(pack_data);
    }
}

const PackIdxEntry = struct { sha: [20]u8, offset: u32, crc: u32 };

fn generatePackIdxFromEntries(allocator: std.mem.Allocator, entries: []const PackIdxEntry, pack_checksum: *const [20]u8, output_dir: []const u8, hash_hex: *const [40]u8) !void {
    const n = entries.len;

    // Sort entries by SHA-1
    const indices = try allocator.alloc(usize, n);
    defer allocator.free(indices);
    for (indices, 0..) |*idx_val, j| idx_val.* = j;

    const SortCtx = struct {
        e: []const PackIdxEntry,
    };
    const ctx = SortCtx{ .e = entries };
    std.mem.sort(usize, indices, ctx, struct {
        fn lessThan(c: SortCtx, a: usize, b: usize) bool {
            return std.mem.order(u8, &c.e[a].sha, &c.e[b].sha).compare(.lt);
        }
    }.lessThan);

    var idx = std.array_list.Managed(u8).init(allocator);
    defer idx.deinit();

    // Magic + version
    try idx.appendSlice("\xfftOc");
    try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 2)));

    // Fanout table (256 entries)
    var fanout: [256]u32 = std.mem.zeroes([256]u32);
    for (indices) |idx_val| {
        const first_byte = entries[idx_val].sha[0];
        var fb: usize = first_byte;
        while (fb < 256) : (fb += 1) {
            fanout[fb] += 1;
        }
    }
    for (fanout) |f| {
        try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, f)));
    }

    // SHA-1 table (sorted)
    for (indices) |idx_val| {
        try idx.appendSlice(&entries[idx_val].sha);
    }

    // CRC32 table
    for (indices) |idx_val| {
        try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, entries[idx_val].crc)));
    }

    // 4-byte offset table
    for (indices) |idx_val| {
        try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, entries[idx_val].offset)));
    }

    // Pack checksum
    try idx.appendSlice(pack_checksum);

    // Idx checksum
    var idx_sha = std.crypto.hash.Sha1.init(.{});
    idx_sha.update(idx.items);
    const idx_checksum = idx_sha.finalResult();
    try idx.appendSlice(&idx_checksum);

    // Write idx file
    const idx_filename = std.fmt.allocPrint(allocator, "{s}/pack-{s}.idx", .{ output_dir, hash_hex }) catch return;
    defer allocator.free(idx_filename);
    std.fs.cwd().writeFile(.{ .sub_path = idx_filename, .data = idx.items }) catch {};
}

fn packHasDuplicates(allocator: std.mem.Allocator, pack_data: []const u8) bool {
    if (pack_data.len < 12) return false;
    if (!std.mem.eql(u8, pack_data[0..4], "PACK")) return false;
    const num_objects = std.mem.readInt(u32, pack_data[8..12], .big);

    var seen = std.AutoHashMap([20]u8, void).init(allocator);
    defer seen.deinit();

    var pos: usize = 12;
    var obj_count: usize = 0;
    while (obj_count < num_objects and pos < pack_data.len -| 20) : (obj_count += 1) {
        var c = pack_data[pos];
        const obj_type = (c >> 4) & 0x07;
        pos += 1;
        var obj_size: u64 = c & 0x0F;
        var shift: u6 = 4;
        while (c & 0x80 != 0 and pos < pack_data.len) {
            c = pack_data[pos];
            pos += 1;
            obj_size |= @as(u64, c & 0x7F) << shift;
            shift +|= 7;
        }
        if (obj_type == 6) {
            c = pack_data[pos];
            pos += 1;
            while (c & 0x80 != 0 and pos < pack_data.len) {
                c = pack_data[pos];
                pos += 1;
            }
        } else if (obj_type == 7) {
            pos += 20;
        }
        const decomp_result = zlib_compat_mod.decompressSliceWithConsumed(allocator, pack_data[pos..]) catch return false;
        defer allocator.free(decomp_result.data);
        pos += decomp_result.consumed;

        if (obj_type >= 1 and obj_type <= 4) {
            const type_str: []const u8 = switch (obj_type) {
                1 => "commit",
                2 => "tree",
                3 => "blob",
                4 => "tag",
                else => "blob",
            };
            const header = std.fmt.allocPrint(allocator, "{s} {d}\x00", .{ type_str, decomp_result.data.len }) catch continue;
            defer allocator.free(header);
            var hasher = std.crypto.hash.Sha1.init(.{});
            hasher.update(header);
            hasher.update(decomp_result.data);
            const sha = hasher.finalResult();
            if (seen.contains(sha)) return true;
            seen.put(sha, {}) catch {};
        }
    }
    return false;
}

fn generatePackIdx(allocator: std.mem.Allocator, pack_data: []const u8, output_dir: []const u8, hash_hex: *const [40]u8) !void {
    // Parse pack file to extract object SHAs
    if (pack_data.len < 12) return;
    if (!std.mem.eql(u8, pack_data[0..4], "PACK")) return;

    const num_objects = std.mem.readInt(u32, pack_data[8..12], .big);

    // Collect object hashes by parsing pack entries
    var object_shas = std.array_list.Managed([20]u8).init(allocator);
    defer object_shas.deinit();
    var offsets = std.array_list.Managed(u32).init(allocator);
    defer offsets.deinit();
    var crcs = std.array_list.Managed(u32).init(allocator);
    defer crcs.deinit();

    var pos: usize = 12;
    var obj_count: usize = 0;
    while (obj_count < num_objects and pos < pack_data.len - 20) : (obj_count += 1) {
        const entry_offset = pos;
        try offsets.append(@intCast(entry_offset));

        // Parse object header
        var c = pack_data[pos];
        pos += 1;
        var obj_size: u64 = c & 0x0F;
        var shift: u6 = 4;
        while (c & 0x80 != 0 and pos < pack_data.len) {
            c = pack_data[pos];
            pos += 1;
            obj_size |= @as(u64, c & 0x7F) << shift;
            shift +|= 7;
        }

        const obj_type = (pack_data[entry_offset] >> 4) & 0x07;

        // Skip delta base ref if needed
        if (obj_type == 6) {
            // OFS_DELTA: skip base offset encoding
            c = pack_data[pos];
            pos += 1;
            while (c & 0x80 != 0 and pos < pack_data.len) {
                c = pack_data[pos];
                pos += 1;
            }
        } else if (obj_type == 7) {
            // REF_DELTA: skip 20-byte base SHA
            pos += 20;
        }

        // Decompress using zlib C API for accurate consumed byte count
        const decomp_result = zlib_compat_mod.decompressSliceWithConsumed(allocator, pack_data[pos..]) catch {
            try object_shas.append(std.mem.zeroes([20]u8));
            try crcs.append(0);
            continue;
        };
        defer allocator.free(decomp_result.data);
        pos += decomp_result.consumed;

        // Compute CRC32 for the entry
        const entry_data = pack_data[entry_offset..pos];
        const crc = std.hash.crc.Crc32.hash(entry_data);
        try crcs.append(crc);

        // Compute SHA of the object content (only for non-delta objects)
        var sha: [20]u8 = std.mem.zeroes([20]u8);
        if (obj_type >= 1 and obj_type <= 4) {
            const type_str: []const u8 = switch (obj_type) {
                1 => "commit",
                2 => "tree",
                3 => "blob",
                4 => "tag",
                else => "blob",
            };
            const header = std.fmt.allocPrint(allocator, "{s} {d}\x00", .{ type_str, decomp_result.data.len }) catch continue;
            defer allocator.free(header);
            var hasher = std.crypto.hash.Sha1.init(.{});
            hasher.update(header);
            hasher.update(decomp_result.data);
            sha = hasher.finalResult();
        }
        try object_shas.append(sha);
    }

    // Write v2 idx file
    var idx = std.array_list.Managed(u8).init(allocator);
    defer idx.deinit();

    // Magic + version
    try idx.appendSlice("\xfftOc");
    try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 2)));

    // Fanout table (256 entries)
    // Sort objects by SHA for the fanout
    const SortCtx = struct {
        shas: [][20]u8,
    };
    const indices = try allocator.alloc(usize, object_shas.items.len);
    defer allocator.free(indices);
    for (indices, 0..) |*idx_val, j| idx_val.* = j;

    const ctx = SortCtx{ .shas = object_shas.items };
    std.mem.sort(usize, indices, ctx, struct {
        fn lessThan(c: SortCtx, a: usize, b: usize) bool {
            return std.mem.order(u8, &c.shas[a], &c.shas[b]).compare(.lt);
        }
    }.lessThan);

    // Build fanout
    var fanout: [256]u32 = std.mem.zeroes([256]u32);
    for (indices) |idx_val| {
        const first_byte = object_shas.items[idx_val][0];
        var fb: usize = first_byte;
        while (fb < 256) : (fb += 1) {
            fanout[fb] += 1;
        }
    }
    for (fanout) |f| {
        try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, f)));
    }

    // SHA-1 table (sorted)
    for (indices) |idx_val| {
        try idx.appendSlice(&object_shas.items[idx_val]);
    }

    // CRC32 table
    for (indices) |idx_val| {
        if (idx_val < crcs.items.len) {
            try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, crcs.items[idx_val])));
        } else {
            try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 0)));
        }
    }

    // Offset table
    for (indices) |idx_val| {
        if (idx_val < offsets.items.len) {
            try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, offsets.items[idx_val])));
        } else {
            try idx.appendSlice(&std.mem.toBytes(std.mem.nativeToBig(u32, 0)));
        }
    }

    // Pack SHA-1
    if (pack_data.len >= 20) {
        try idx.appendSlice(pack_data[pack_data.len - 20..]);
    }

    // Idx SHA-1
    var idx_sha = std.crypto.hash.Sha1.init(.{});
    idx_sha.update(idx.items);
    const idx_checksum = idx_sha.finalResult();
    try idx.appendSlice(&idx_checksum);

    // Write idx file
    const idx_filename = std.fmt.allocPrint(allocator, "{s}/pack-{s}.idx", .{ output_dir, hash_hex }) catch return;
    defer allocator.free(idx_filename);
    std.fs.cwd().writeFile(.{ .sub_path = idx_filename, .data = idx.items }) catch {};
}

fn generatePackIdxToFile(allocator: std.mem.Allocator, pack_data: []const u8, output_path: []const u8) !void {
    // Parse pack file to extract object SHAs
    if (pack_data.len < 12) return;
    if (!std.mem.eql(u8, pack_data[0..4], "PACK")) return;

