            }
        } else if (obj_type == 7) {
            // REF_DELTA: skip 20-byte base SHA
            pos += 20;
        }

        // Decompress using zlib C API for accurate consumed byte count
        const decomp_result2 = zlib_compat_mod.decompressSliceWithConsumed(allocator, pack_data[pos..]) catch {
