fn nativeCmdVar(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    const allocator = std.heap.page_allocator;
    const rest = args[command_index + 1 ..];
    if (rest.len == 0) { try platform_impl.writeStderr("usage: git var (-l | <variable>)\n"); std.process.exit(1); }
    var list_mode = false; var var_name_arg: ?[]const u8 = null;
    for (rest) |a| { if (std.mem.eql(u8, a, "-l")) list_mode = true else if (!std.mem.startsWith(u8, a, "-")) var_name_arg = a; }
    if (list_mode and var_name_arg != null) { try platform_impl.writeStderr("error: The argument '-l' cannot be used with '<variable>'\n\nusage: git var (-l | <variable>)\n"); std.process.exit(129); }
    if (list_mode) {
        const var_names = [_][]const u8{ "GIT_COMMITTER_IDENT", "GIT_AUTHOR_IDENT", "GIT_EDITOR", "GIT_SEQUENCE_EDITOR", "GIT_PAGER", "GIT_DEFAULT_BRANCH", "GIT_SHELL_PATH", "GIT_ATTR_SYSTEM", "GIT_ATTR_GLOBAL", "GIT_CONFIG_SYSTEM", "GIT_CONFIG_GLOBAL" };
        for (var_names) |vn| {
            if (std.mem.eql(u8, vn, "GIT_CONFIG_GLOBAL")) { const vals = getVarMulti(allocator, vn) catch continue; defer { for (vals) |v| allocator.free(v); allocator.free(vals); } for (vals) |val| { const line = std.fmt.allocPrint(allocator, "{s}={s}\n", .{ vn, val }) catch continue; defer allocator.free(line); platform_impl.writeStdout(line) catch {}; } continue; }
            if (getVarValueP(allocator, vn, platform_impl)) |val| { defer allocator.free(val); const line = std.fmt.allocPrint(allocator, "{s}={s}\n", .{ vn, val }) catch continue; defer allocator.free(line); platform_impl.writeStdout(line) catch {}; } else |_| {}
        }
        const gpo = findGitDirectory(allocator, platform_impl) catch null; defer if (gpo) |gp| allocator.free(gp);
        if (gpo) |gp| { const cp = std.fmt.allocPrint(allocator, "{s}/config", .{gp}) catch return; defer allocator.free(cp); if (platform_impl.fs.readFile(allocator, cp)) |cd| { defer allocator.free(cd); listConfigEntries(cd, platform_impl, allocator) catch {}; } else |_| {} }
        return;
    }
    const var_name = var_name_arg orelse { try platform_impl.writeStderr("usage: git var (-l | <variable>)\n"); std.process.exit(1); };
    const known = [_][]const u8{ "GIT_AUTHOR_IDENT", "GIT_COMMITTER_IDENT", "GIT_EDITOR", "GIT_PAGER", "GIT_DEFAULT_BRANCH", "GIT_SEQUENCE_EDITOR", "GIT_SHELL_PATH", "GIT_ATTR_SYSTEM", "GIT_ATTR_GLOBAL", "GIT_CONFIG_SYSTEM", "GIT_CONFIG_GLOBAL" };
    var is_known = false; for (known) |k| { if (std.mem.eql(u8, var_name, k)) { is_known = true; break; } }
    if (!is_known) { const msg = std.fmt.allocPrint(allocator, "Unknown variable: '{s}'\n", .{var_name}) catch return; defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(1); }
    if (std.mem.eql(u8, var_name, "GIT_CONFIG_GLOBAL")) { if (std.process.getEnvVarOwned(allocator, "GIT_CONFIG_GLOBAL")) |ev| { defer allocator.free(ev); const o = std.fmt.allocPrint(allocator, "{s}\n", .{ev}) catch return; defer allocator.free(o); try platform_impl.writeStdout(o); return; } else |_| {} const vals = getVarMulti(allocator, var_name) catch { try outputVar(allocator, var_name, platform_impl); return; }; defer { for (vals) |v| allocator.free(v); allocator.free(vals); } for (vals) |val| { const l = std.fmt.allocPrint(allocator, "{s}\n", .{val}) catch continue; defer allocator.free(l); platform_impl.writeStdout(l) catch {}; } return; }
    try outputVar(allocator, var_name, platform_impl);
}

fn outputVar(allocator: std.mem.Allocator, var_name: []const u8, platform_impl: *const platform_mod.Platform) !void {
    const val = getVarValueP(allocator, var_name, platform_impl) catch { const msg = std.fmt.allocPrint(allocator, "fatal: unable to determine {s}\n", .{var_name}) catch return; defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(1); };
    defer allocator.free(val);
    const out = try std.fmt.allocPrint(allocator, "{s}\n", .{val});
    defer allocator.free(out);
    try platform_impl.writeStdout(out);
}

fn listConfigEntries(config_data: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !void {
    // Parse INI-style config and output key=value pairs
    var current_section: ?[]const u8 = null;
    var current_subsection: ?[]const u8 = null;
    var section_buf: [256]u8 = undefined;
    var subsection_buf: [256]u8 = undefined;
    var lines = std.mem.splitScalar(u8, config_data, '\n');
    while (lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        if (trimmed.len == 0 or trimmed[0] == '#' or trimmed[0] == ';') continue;
        
        if (trimmed[0] == '[') {
            // Section header
            if (std.mem.indexOf(u8, trimmed, "\"")) |q1| {
                // Subsection: [section "subsection"]
                const sect = std.mem.trim(u8, trimmed[1..q1], " \t");
                if (std.mem.indexOf(u8, trimmed[q1+1..], "\"")) |q2| {
                    const subsect = trimmed[q1+1..q1+1+q2];
                    const lower_sect = sect[0..@min(sect.len, 255)];
                    for (lower_sect, 0..) |c, ci| {
                        section_buf[ci] = std.ascii.toLower(c);
                    }
                    current_section = section_buf[0..lower_sect.len];
                    @memcpy(subsection_buf[0..@min(subsect.len, 255)], subsect[0..@min(subsect.len, 255)]);
                    current_subsection = subsection_buf[0..@min(subsect.len, 255)];
                }
            } else {
                // Simple section: [section]
                const end = std.mem.indexOf(u8, trimmed, "]") orelse continue;
                const sect = std.mem.trim(u8, trimmed[1..end], " \t");
                const lower_sect = sect[0..@min(sect.len, 255)];
                for (lower_sect, 0..) |c, ci| {
                    section_buf[ci] = std.ascii.toLower(c);
                }
                current_section = section_buf[0..lower_sect.len];
                current_subsection = null;
            }
        } else if (current_section) |sect| {
            // Key = value line
            if (std.mem.indexOf(u8, trimmed, "=")) |eq| {
                const key = std.mem.trim(u8, trimmed[0..eq], " \t");
                const val = std.mem.trim(u8, trimmed[eq+1..], " \t");
                var key_lower_buf: [256]u8 = undefined;
                for (key[0..@min(key.len, 255)], 0..) |c, ki| {
                    key_lower_buf[ki] = std.ascii.toLower(c);
                }
                const key_lower = key_lower_buf[0..@min(key.len, 255)];
                
                if (current_subsection) |subsect| {
                    const out = try std.fmt.allocPrint(allocator, "{s}.{s}.{s}={s}\n", .{ sect, subsect, key_lower, val });
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else {
                    const out = try std.fmt.allocPrint(allocator, "{s}.{s}={s}\n", .{ sect, key_lower, val });
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
        }
    }
}

fn getVarValue(allocator: std.mem.Allocator, var_name: []const u8) ![]u8 { return getVarValueP(allocator, var_name, null); }
fn getVarValueP(allocator: std.mem.Allocator, var_name: []const u8, pi: ?*const platform_mod.Platform) ![]u8 {
    if (std.mem.eql(u8, var_name, "GIT_AUTHOR_IDENT") or std.mem.eql(u8, var_name, "GIT_COMMITTER_IDENT")) return getGitIdent(allocator, if (std.mem.eql(u8, var_name, "GIT_AUTHOR_IDENT")) "GIT_AUTHOR" else "GIT_COMMITTER");
    if (std.mem.eql(u8, var_name, "GIT_EDITOR") or std.mem.eql(u8, var_name, "GIT_SEQUENCE_EDITOR")) {
        if (std.mem.eql(u8, var_name, "GIT_SEQUENCE_EDITOR")) { if (std.process.getEnvVarOwned(allocator, "GIT_SEQUENCE_EDITOR")) |v| return v else |_| {} if (pi) |p| { if (readCfg(allocator, "sequence.editor", p)) |v| return v; } return getVarValueP(allocator, "GIT_EDITOR", pi); }
        if (std.process.getEnvVarOwned(allocator, "GIT_EDITOR")) |v| return v else |_| {} if (pi) |p| { if (readCfg(allocator, "core.editor", p)) |v| return v; } if (std.process.getEnvVarOwned(allocator, "VISUAL")) |v| return v else |_| {} if (std.process.getEnvVarOwned(allocator, "EDITOR")) |v| return v else |_| {} return error.UnknownVariable;
    }
    if (std.mem.eql(u8, var_name, "GIT_PAGER")) { if (std.process.getEnvVarOwned(allocator, "GIT_PAGER")) |v| return v else |_| {} if (pi) |p| { if (readCfg(allocator, "core.pager", p)) |v| return v; } if (std.process.getEnvVarOwned(allocator, "PAGER")) |v| return v else |_| {} return allocator.dupe(u8, "less"); }
    if (std.mem.eql(u8, var_name, "GIT_DEFAULT_BRANCH")) { if (std.process.getEnvVarOwned(allocator, "GIT_TEST_DEFAULT_INITIAL_BRANCH_NAME") catch null) |ev| { if (ev.len > 0) return ev; allocator.free(ev); } if (pi) |p| { if (readCfg(allocator, "init.defaultbranch", p)) |v| return v; } return allocator.dupe(u8, "master"); }
    if (std.mem.eql(u8, var_name, "GIT_SHELL_PATH")) return allocator.dupe(u8, "/bin/sh");
    if (std.mem.eql(u8, var_name, "GIT_ATTR_SYSTEM")) { if (std.process.getEnvVarOwned(allocator, "GIT_ATTR_NOSYSTEM") catch null) |v| { defer allocator.free(v); if (v.len > 0 and !std.mem.eql(u8, v, "0")) return error.UnknownVariable; } return allocator.dupe(u8, "/etc/gitattributes"); }
    if (std.mem.eql(u8, var_name, "GIT_ATTR_GLOBAL")) { const xdg = std.process.getEnvVarOwned(allocator, "XDG_CONFIG_HOME") catch null; if (xdg) |xh| { defer allocator.free(xh); if (xh.len > 0) return std.fmt.allocPrint(allocator, "{s}/git/attributes", .{xh}); } const h = std.process.getEnvVarOwned(allocator, "HOME") catch return error.UnknownVariable; defer allocator.free(h); return std.fmt.allocPrint(allocator, "{s}/.config/git/attributes", .{h}); }
    if (std.mem.eql(u8, var_name, "GIT_CONFIG_SYSTEM")) { if (std.process.getEnvVarOwned(allocator, "GIT_CONFIG_NOSYSTEM") catch null) |v| { defer allocator.free(v); if (v.len > 0 and !std.mem.eql(u8, v, "0")) return error.UnknownVariable; } if (std.process.getEnvVarOwned(allocator, "GIT_CONFIG_SYSTEM")) |v| return v else |_| {} return allocator.dupe(u8, "/etc/gitconfig"); }
    if (std.mem.eql(u8, var_name, "GIT_CONFIG_GLOBAL")) { const xdg = std.process.getEnvVarOwned(allocator, "XDG_CONFIG_HOME") catch null; if (xdg) |xh| { defer allocator.free(xh); if (xh.len > 0) return std.fmt.allocPrint(allocator, "{s}/git/config", .{xh}); } const h = std.process.getEnvVarOwned(allocator, "HOME") catch return error.UnknownVariable; defer allocator.free(h); return std.fmt.allocPrint(allocator, "{s}/.config/git/config", .{h}); }
    return error.UnknownVariable;
}
fn readCfg(allocator: std.mem.Allocator, key: []const u8, p: *const platform_mod.Platform) ?[]u8 {
    const gp = findGitDirectory(allocator, p) catch return null; defer allocator.free(gp);
    const cp = std.fmt.allocPrint(allocator, "{s}/config", .{gp}) catch return null; defer allocator.free(cp);
    const cd = p.fs.readFile(allocator, cp) catch return null; defer allocator.free(cd);
    var pi2 = std.mem.splitScalar(u8, key, '.'); const sw = pi2.next() orelse return null; const kw = pi2.next() orelse return null;
    var cs2: ?[]const u8 = null; var sb2: [256]u8 = undefined; var result2: ?[]u8 = null;
    var ls = std.mem.splitScalar(u8, cd, '\n');
    while (ls.next()) |line| { const tr = std.mem.trim(u8, line, " \t\r"); if (tr.len == 0 or tr[0] == '#' or tr[0] == ';') continue; if (tr[0] == '[') { const e = std.mem.indexOf(u8, tr, "]") orelse continue; const s = std.mem.trim(u8, tr[1..e], " \t"); const ll = @min(s.len, 255); for (s[0..ll], 0..) |ch, ci| sb2[ci] = std.ascii.toLower(ch); cs2 = sb2[0..ll]; } else if (cs2) |sect| { if (std.mem.indexOf(u8, tr, "=")) |eq| { const k = std.mem.trim(u8, tr[0..eq], " \t"); const v = std.mem.trim(u8, tr[eq+1..], " \t"); if (asciiCaseInsensitiveEqual(sect, sw) and asciiCaseInsensitiveEqual(k, kw)) { if (result2) |o| allocator.free(o); result2 = allocator.dupe(u8, v) catch null; } } } }
    return result2;
}
fn getVarMulti(allocator: std.mem.Allocator, var_name: []const u8) ![][]u8 {
    if (std.mem.eql(u8, var_name, "GIT_CONFIG_GLOBAL")) {
        var results = std.array_list.Managed([]u8).init(allocator);
        const xdg = std.process.getEnvVarOwned(allocator, "XDG_CONFIG_HOME") catch null;
        if (xdg) |xh| { defer allocator.free(xh); if (xh.len > 0) { if (std.fmt.allocPrint(allocator, "{s}/git/config", .{xh})) |pp| try results.append(@constCast(pp)) else |_| {} } } else { const h = std.process.getEnvVarOwned(allocator, "HOME") catch null; if (h) |hh| { defer allocator.free(hh); if (std.fmt.allocPrint(allocator, "{s}/.config/git/config", .{hh})) |pp| try results.append(@constCast(pp)) else |_| {} } }
        const h2 = std.process.getEnvVarOwned(allocator, "HOME") catch null;
        if (h2) |hh| { defer allocator.free(hh); if (std.fmt.allocPrint(allocator, "{s}/.gitconfig", .{hh})) |pp| try results.append(@constCast(pp)) else |_| {} }
        return try results.toOwnedSlice();
    }
    return error.NotMultiValue;
}

fn getGitIdent(allocator: std.mem.Allocator, prefix: []const u8) ![]u8 {
    const name_key = try std.fmt.allocPrint(allocator, "{s}_NAME", .{prefix});
    defer allocator.free(name_key);
    const email_key = try std.fmt.allocPrint(allocator, "{s}_EMAIL", .{prefix});
    defer allocator.free(email_key);
    
    const name = std.process.getEnvVarOwned(allocator, name_key) catch
        std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_NAME") catch
        try allocator.dupe(u8, "Unknown");
    defer allocator.free(name);
    
    const email = std.process.getEnvVarOwned(allocator, email_key) catch
        std.process.getEnvVarOwned(allocator, "GIT_AUTHOR_EMAIL") catch
        std.process.getEnvVarOwned(allocator, "EMAIL") catch
        try allocator.dupe(u8, "unknown@example.com");
    defer allocator.free(email);

    const date_key = try std.fmt.allocPrint(allocator, "{s}_DATE", .{prefix});
    defer allocator.free(date_key);
    
    const date_str = std.process.getEnvVarOwned(allocator, date_key) catch null;
    defer if (date_str) |d| allocator.free(d);
    
    if (date_str) |d| {
        return std.fmt.allocPrint(allocator, "{s} <{s}> {s}", .{ name, email, d });
    }
    
    const timestamp = std.time.timestamp();
    return std.fmt.allocPrint(allocator, "{s} <{s}> {d} +0000", .{ name, email, timestamp });
}

fn nativeCmdDiffTree(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    const allocator = std.heap.page_allocator;
    const rest = args[command_index + 1 ..];
    
    var recursive = false;
    var show_patch = false;
    var show_root = false;
    var name_only = false;
    var name_status = false;
    var no_commit_id = false;
    var quiet = false;
    var abbrev_len: ?usize = null; // null = no abbrev, 0 = default (7)
    var full_index = false;
    var show_stat = false;
    var show_summary = false;
    var show_raw = true; // default for diff-tree
    var patch_with_stat = false;
    var patch_with_raw = false;
    var show_shortstat = false;
    var pretty_fmt: ?[]const u8 = null;
    var show_pretty = false;
    var show_cc = false;
    var show_combined = false;
    var show_m = false;
    var first_parent = false;
    var show_notes = false;
    var format_str: ?[]const u8 = null;
    var compact_summary = false;
    var reverse_diff = false;
    var stdin_mode = false;
    var line_prefix: []const u8 = "";
    var tree_refs = std.array_list.Managed([]const u8).init(allocator);
    defer tree_refs.deinit();
    var pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer pathspecs.deinit();
    var seen_dashdash = false;
    
    for (rest) |arg| {
        if (seen_dashdash) {
            try pathspecs.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_dashdash = true;
        } else if (std.mem.eql(u8, arg, "-r")) {
            recursive = true;
        } else if (std.mem.eql(u8, arg, "-t")) {
            recursive = true;
        } else if (std.mem.eql(u8, arg, "-p") or std.mem.eql(u8, arg, "--patch") or std.mem.eql(u8, arg, "-u")) {
            show_patch = true;
            show_raw = false;
            recursive = true;
        } else if (std.mem.eql(u8, arg, "--root")) {
            show_root = true;
        } else if (std.mem.eql(u8, arg, "--name-only")) {
            name_only = true;
        } else if (std.mem.eql(u8, arg, "--name-status")) {
            name_status = true;
        } else if (std.mem.eql(u8, arg, "--no-commit-id")) {
            no_commit_id = true;
        } else if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "--abbrev")) {
            abbrev_len = 0; // default
        } else if (std.mem.startsWith(u8, arg, "--abbrev=")) {
            abbrev_len = std.fmt.parseInt(usize, arg["--abbrev=".len..], 10) catch 7;
        } else if (std.mem.eql(u8, arg, "--full-index")) {
            full_index = true;
        } else if (std.mem.eql(u8, arg, "--stat")) {
            show_stat = true;
            show_raw = false;
        } else if (std.mem.eql(u8, arg, "--summary")) {
            show_summary = true;
            show_raw = false;
        } else if (std.mem.eql(u8, arg, "--shortstat")) {
            show_shortstat = true;
            show_raw = false;
        } else if (std.mem.eql(u8, arg, "--patch-with-stat")) {
            patch_with_stat = true;
            show_patch = true;
            show_stat = true;
            show_raw = false;
            recursive = true;
        } else if (std.mem.eql(u8, arg, "--patch-with-raw")) {
            patch_with_raw = true;
            show_patch = true;
            show_raw = true;
            recursive = true;
        } else if (std.mem.eql(u8, arg, "--pretty") or std.mem.eql(u8, arg, "--pretty=medium")) {
            show_pretty = true;
            pretty_fmt = "medium";
        } else if (std.mem.startsWith(u8, arg, "--pretty=")) {
            show_pretty = true;
            pretty_fmt = arg["--pretty=".len..];
        } else if (std.mem.startsWith(u8, arg, "--format=")) {
            format_str = arg["--format=".len..];
            show_pretty = true;
        } else if (std.mem.eql(u8, arg, "--cc")) {
            show_cc = true;
            show_raw = false;
        } else if (std.mem.eql(u8, arg, "-c")) {
            show_combined = true;
            show_raw = false;
        } else if (std.mem.eql(u8, arg, "-m")) {
            show_m = true;
        } else if (std.mem.eql(u8, arg, "--first-parent")) {
            first_parent = true;
        } else if (std.mem.eql(u8, arg, "--notes")) {
            show_notes = true;
        } else if (std.mem.eql(u8, arg, "--compact-summary")) {
            compact_summary = true;
        } else if (std.mem.eql(u8, arg, "-R")) {
            reverse_diff = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
        } else if (std.mem.startsWith(u8, arg, "--line-prefix=")) {
            line_prefix = arg["--line-prefix=".len..];
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git diff-tree [<options>] <tree-ish> [<tree-ish>] [<path>...]\n");
            std.process.exit(129);
        } else if (std.mem.startsWith(u8, arg, "-")) {
            // skip unknown flags
        } else {
            try tree_refs.append(arg);
        }
    }
    // Build options struct
    const dt_opts = DiffTreeOpts{
        .recursive = recursive,
        .show_patch = show_patch,
        .show_root = show_root,
        .name_only = name_only,
        .name_status = name_status,
        .no_commit_id = no_commit_id,
        .quiet = quiet,
        .abbrev_len = abbrev_len,
        .full_index = full_index,
        .show_stat = show_stat,
        .show_summary = show_summary,
        .show_raw = show_raw,
        .patch_with_stat = patch_with_stat,
        .patch_with_raw = patch_with_raw,
        .show_shortstat = show_shortstat,
        .show_pretty = show_pretty,
        .pretty_fmt = pretty_fmt,
        .show_cc = show_cc,
        .show_combined = show_combined,
        .show_m = show_m,
        .first_parent = first_parent,
        .show_notes = show_notes,
        .format_str = format_str,
        .compact_summary = compact_summary,
        .reverse_diff = reverse_diff,
        .stdin_mode = stdin_mode,
        .line_prefix = line_prefix,
    };
    
    var had_diff = false;
    
    if (tree_refs.items.len == 0) {
        // Read commit hashes from stdin
        const stdin_data = readStdin(allocator, 1024 * 1024) catch return;
        defer allocator.free(stdin_data);
        var line_it = std.mem.splitScalar(u8, stdin_data, '\n');
        while (line_it.next()) |line| {
            const trimmed = std.mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0) continue;
            const d = diffTreeForCommit(allocator, trimmed, &dt_opts, pathspecs.items, platform_impl) catch false;
            if (d) had_diff = true;
        }
    } else if (tree_refs.items.len == 1) {
        had_diff = try diffTreeForCommit(allocator, tree_refs.items[0], &dt_opts, pathspecs.items, platform_impl);
    } else {
        // Resolve both refs to tree hashes
        const git_path = findGitDirectory(allocator, platform_impl) catch {
            try platform_impl.writeStderr("fatal: not a git repository\n");
            std.process.exit(128);
        };
        defer allocator.free(git_path);
        const tree1 = resolveToTree(allocator, tree_refs.items[0], git_path, platform_impl) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: bad object {s}\n", .{tree_refs.items[0]});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        defer allocator.free(tree1);
        const tree2 = resolveToTree(allocator, tree_refs.items[1], git_path, platform_impl) catch {
            const msg = try std.fmt.allocPrint(allocator, "fatal: bad object {s}\n", .{tree_refs.items[1]});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        defer allocator.free(tree2);
        if (dt_opts.show_stat or dt_opts.show_shortstat or (dt_opts.show_summary and !dt_opts.show_patch)) {
            var stat_entries = std.array_list.Managed(DiffStatEntry).init(allocator);
            defer { for (stat_entries.items) |*de| allocator.free(de.path); stat_entries.deinit(); }
            try collectTreeDiffEntries(allocator, tree1, tree2, "", git_path, pathspecs.items, platform_impl, &stat_entries);
            if (stat_entries.items.len > 0) had_diff = true;
            if (dt_opts.show_stat) {
                try formatDiffStat(stat_entries.items, platform_impl, allocator);
            } else if (dt_opts.show_shortstat) {
                try formatDiffShortStat(stat_entries.items, platform_impl, allocator);
            }
            if (dt_opts.show_summary) {
                try outputSummaryForTwoTrees(allocator, tree1, tree2, git_path, pathspecs.items, platform_impl);
            }
        } else {
            const d = try diffTwoTreesFiltered(allocator, tree1, tree2, "", &dt_opts, pathspecs.items, platform_impl);
            if (d) had_diff = true;
        }
    }
    
    // If --quiet, exit 1 when there were differences
    if (quiet and had_diff) {
        std.process.exit(1);
    }
}

fn resolveToTree(allocator: std.mem.Allocator, ref_str: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) ![]u8 {
    const hash = try resolveRevision(git_path, ref_str, platform_impl, allocator);
    defer allocator.free(hash);
    
    const obj = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch return error.BadObject;
    defer obj.deinit(allocator);
    
    if (obj.type == .tree) {
        return allocator.dupe(u8, hash);
    } else if (obj.type == .commit) {
        // Extract tree hash from commit
        var line_iter = std.mem.splitScalar(u8, obj.data, '\n');
        while (line_iter.next()) |line| {
            if (line.len == 0) break;
            if (std.mem.startsWith(u8, line, "tree ")) {
                return allocator.dupe(u8, line["tree ".len..]);
            }
        }
        return error.BadObject;
    } else {
        return error.BadObject;
    }
}

fn outputPrettyCommitHeader(allocator: std.mem.Allocator, commit_hash: []const u8, commit_data: []const u8, opts: *const DiffTreeOpts, platform_impl: *const platform_mod.Platform) !void {
    const pretty_fmt = opts.pretty_fmt orelse "medium";
    
    if (std.mem.eql(u8, pretty_fmt, "oneline")) {
        // One-line format: <hash> <subject>
        const msg = if (std.mem.indexOf(u8, commit_data, "\n\n")) |pos| commit_data[pos + 2 ..] else "";
        const first_line = if (std.mem.indexOf(u8, msg, "\n")) |nl| msg[0..nl] else msg;
        const out = try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ commit_hash, first_line });
        defer allocator.free(out);
        try platform_impl.writeStdout(out);
    } else {
        // Medium format (default)
        const author_line = extractHeaderField(commit_data, "author");
        const msg = if (std.mem.indexOf(u8, commit_data, "\n\n")) |pos| commit_data[pos + 2 ..] else "";
        
        const out1 = try std.fmt.allocPrint(allocator, "commit {s}\n", .{commit_hash});
        defer allocator.free(out1);
        try platform_impl.writeStdout(out1);
        
        // Parse author name and email
        const author_name = parseAuthorName(author_line);
        const author_email = parseAuthorEmail(author_line);
        const out2 = try std.fmt.allocPrint(allocator, "Author: {s} <{s}>\n", .{ author_name, author_email });
        defer allocator.free(out2);
        try platform_impl.writeStdout(out2);
        
        // Parse and format date
        const date_str = parseAuthorDateGitFmt(author_line, allocator);
        defer if (date_str) |d| allocator.free(d);
        const out3 = try std.fmt.allocPrint(allocator, "Date:   {s}\n", .{ date_str orelse "Thu Jan 1 00:00:00 1970 +0000" });
        defer allocator.free(out3);
        try platform_impl.writeStdout(out3);
        
        try platform_impl.writeStdout("\n");
        
        // Output message with 4-space indent
        const trimmed_msg = std.mem.trimRight(u8, msg, "\n");
        var msg_iter = std.mem.splitScalar(u8, trimmed_msg, '\n');
        while (msg_iter.next()) |line| {
            if (line.len == 0) {
                try platform_impl.writeStdout("\n");
            } else {
                const indented = try std.fmt.allocPrint(allocator, "    {s}\n", .{line});
                defer allocator.free(indented);
                try platform_impl.writeStdout(indented);
            }
        }
        // For patch-with-stat, output --- separator; for others, blank line
        if (opts.patch_with_stat) {
            try platform_impl.writeStdout("---\n");
        } else {
            try platform_impl.writeStdout("\n");
        }
    }
}

fn diffTreeForCommit(allocator: std.mem.Allocator, commit_ref: []const u8, opts: *const DiffTreeOpts, pathspecs: []const []const u8, platform_impl: *const platform_mod.Platform) !bool {
    const show_root = opts.show_root;
    const no_commit_id = opts.no_commit_id;
    const quiet = opts.quiet;
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    const commit_hash = try resolveRevision(git_path, commit_ref, platform_impl, allocator);
    defer allocator.free(commit_hash);
    
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch {
        const msg = try std.fmt.allocPrint(allocator, "fatal: bad object {s}\n", .{commit_ref});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    };
    defer commit_obj.deinit(allocator);
    
    var tree_hash: ?[]const u8 = null;
    var parent_hash: ?[]const u8 = null;
    var all_parent_hashes = std.array_list.Managed([]const u8).init(allocator);
    defer all_parent_hashes.deinit();
    var line_iter = std.mem.splitScalar(u8, commit_obj.data, '\n');
    while (line_iter.next()) |line| {
        if (line.len == 0) break;
        if (std.mem.startsWith(u8, line, "tree ")) {
            tree_hash = line["tree ".len..];
        } else if (std.mem.startsWith(u8, line, "parent ")) {
            try all_parent_hashes.append(line["parent ".len..]);
            if (parent_hash == null) parent_hash = line["parent ".len..];
        }
    }
    
    const this_tree = tree_hash orelse return false;
    const is_merge = all_parent_hashes.items.len > 1;
    
    // For merge commits without -m, -c, or --cc, produce no output
    if (is_merge and !opts.show_m and !opts.show_combined and !opts.show_cc) {
        return false;
    }
    
    // For merge commits with -m, diff against each parent
    if (is_merge and opts.show_m) {
        var had_any = false;
        for (all_parent_hashes.items) |ph| {
            const parent_obj2 = objects.GitObject.load(ph, git_path, platform_impl, allocator) catch continue;
            defer parent_obj2.deinit(allocator);
            var pt2: ?[]const u8 = null;
            var piter2 = std.mem.splitScalar(u8, parent_obj2.data, '\n');
            while (piter2.next()) |pline| {
                if (pline.len == 0) break;
                if (std.mem.startsWith(u8, pline, "tree ")) {
                    pt2 = pline["tree ".len..];
                    break;
                }
            }
            if (pt2) |parent_tree| {
                var quiet_opts2 = opts.*;
                quiet_opts2.quiet = true;
                const has_diff2 = try diffTwoTreesFiltered(allocator, parent_tree, this_tree, "", &quiet_opts2, pathspecs, platform_impl);
                if (has_diff2) {
                    had_any = true;
                    if (!quiet) {
                        if (!no_commit_id) {
                            if (opts.show_pretty) {
                                try outputPrettyCommitHeader(allocator, commit_hash, commit_obj.data, opts, platform_impl);
                            } else {
                                const id_line = try std.fmt.allocPrint(allocator, "{s}\n", .{commit_hash});
                                defer allocator.free(id_line);
                                try platform_impl.writeStdout(id_line);
                            }
                        }
                        _ = try diffTwoTreesFiltered(allocator, parent_tree, this_tree, "", opts, pathspecs, platform_impl);
                    }
                }
            }
        }
        return had_any;
    }
    
    // For merge commits with -c or --cc, show combined diff
    if (is_merge and (opts.show_combined or opts.show_cc)) {
        if (!quiet and !no_commit_id) {
            if (opts.show_pretty) {
                try outputPrettyCommitHeader(allocator, commit_hash, commit_obj.data, opts, platform_impl);
            } else {
                const id_line = try std.fmt.allocPrint(allocator, "{s}\n", .{commit_hash});
                defer allocator.free(id_line);
                try platform_impl.writeStdout(id_line);
            }
        }
        if (!quiet) {
            if (opts.show_stat) {
                try outputCombinedStat(allocator, all_parent_hashes.items, this_tree, git_path, opts.show_cc, platform_impl);
            }
            if (opts.show_summary) {
                try outputCombinedSummary(allocator, all_parent_hashes.items, this_tree, git_path, opts.show_cc, platform_impl);
            }
            if (opts.show_shortstat) {
                try outputCombinedShortStat(allocator, all_parent_hashes.items, this_tree, git_path, opts.show_cc, platform_impl);
            }
            if (opts.show_patch or opts.patch_with_stat) {
                if (opts.patch_with_stat) {
                    try outputCombinedStat(allocator, all_parent_hashes.items, this_tree, git_path, opts.show_cc, platform_impl);
                    try platform_impl.writeStdout("\n");
                }
                try outputCombinedDiff(allocator, all_parent_hashes.items, this_tree, git_path, opts.show_cc, platform_impl);
            }
        }
        return true;
    }
    
    if (parent_hash == null) {
        if (show_root) {
            if (!quiet and !no_commit_id) {
                if (opts.show_pretty) {
                    try outputPrettyCommitHeader(allocator, commit_hash, commit_obj.data, opts, platform_impl);
                } else {
                    const id_line = try std.fmt.allocPrint(allocator, "{s}\n", .{commit_hash});
                    defer allocator.free(id_line);
                    try platform_impl.writeStdout(id_line);
                }
            }
            if (!quiet) {
                if (opts.patch_with_raw) {
                    // Output raw first, then patch
                    var raw_opts = opts.*;
                    raw_opts.show_patch = false;
                    raw_opts.show_raw = true;
                    try diffTreeWithEmptyOpts(allocator, this_tree, &raw_opts, git_path, platform_impl);
                    try platform_impl.writeStdout("\n");
                    var patch_opts = opts.*;
                    patch_opts.show_patch = true;
                    try diffTreeWithEmptyOpts(allocator, this_tree, &patch_opts, git_path, platform_impl);
                } else if (opts.patch_with_stat) {
                    // Output stat first, then patch
                    try outputStatForEmptyTree(allocator, this_tree, git_path, platform_impl);
                    try platform_impl.writeStdout("\n");
                    var patch_opts = opts.*;
                    patch_opts.show_patch = true;
                    try diffTreeWithEmptyOpts(allocator, this_tree, &patch_opts, git_path, platform_impl);
                } else {
                    // Handle various display modes
                    if (opts.show_stat) {
                        try outputStatForEmptyTree(allocator, this_tree, git_path, platform_impl);
                    }
                    if (opts.show_raw and !opts.show_stat and !opts.show_summary and !opts.show_patch) {
                        try diffTreeWithEmptyOpts(allocator, this_tree, opts, git_path, platform_impl);
                    }
                    if (opts.show_summary) {
                        try outputSummaryForEmptyTree(allocator, this_tree, git_path, platform_impl);
                    }
                    if (opts.show_patch and !opts.patch_with_raw and !opts.patch_with_stat) {
                        var patch_opts = opts.*;
                        patch_opts.show_patch = true;
                        try diffTreeWithEmptyOpts(allocator, this_tree, &patch_opts, git_path, platform_impl);
                    }
                }
            }
            return true;
        }
        return false;
    }
    
    // Get parent tree
    const parent_obj = objects.GitObject.load(parent_hash.?, git_path, platform_impl, allocator) catch return false;
    defer parent_obj.deinit(allocator);
    
    var parent_tree: ?[]const u8 = null;
    var piter = std.mem.splitScalar(u8, parent_obj.data, '\n');
    while (piter.next()) |line| {
        if (line.len == 0) break;
        if (std.mem.startsWith(u8, line, "tree ")) {
            parent_tree = line["tree ".len..];
            break;
        }
    }
    
    if (parent_tree) |pt| {
        // Check for any changes (content or mode)
        var quiet_opts = opts.*;
        quiet_opts.quiet = true;
        const has_diff = try diffTwoTreesFiltered(allocator, pt, this_tree, "", &quiet_opts, pathspecs, platform_impl);
        // Also check for mode-only changes for --summary
        const has_mode_change = if (opts.show_summary and !has_diff) try hasModeChanges(allocator, pt, this_tree, git_path, platform_impl) else false;
        if (has_diff or has_mode_change) {
            if (!quiet) {
                if (!no_commit_id) {
                    if (opts.show_pretty) {
                        try outputPrettyCommitHeader(allocator, commit_hash, commit_obj.data, opts, platform_impl);
                    } else {
                        const id_line = try std.fmt.allocPrint(allocator, "{s}\n", .{commit_hash});
                        defer allocator.free(id_line);
                        try platform_impl.writeStdout(id_line);
                    }
                }
                if (opts.show_stat or opts.patch_with_stat) {
                    try outputStatForTwoTrees(allocator, pt, this_tree, git_path, pathspecs, platform_impl);
                    if (opts.patch_with_stat) {
                        try platform_impl.writeStdout("\n");
                    }
                }
                if (opts.show_summary) {
                    try outputSummaryForTwoTrees(allocator, pt, this_tree, git_path, pathspecs, platform_impl);
                }
                if (opts.patch_with_raw) {
                    // Output raw before patch
                    var raw_opts = opts.*;
                    raw_opts.show_patch = false;
                    raw_opts.show_raw = true;
                    _ = try diffTwoTreesFiltered(allocator, pt, this_tree, "", &raw_opts, pathspecs, platform_impl);
                    try platform_impl.writeStdout("\n");
                }
                if (opts.show_raw and !opts.show_stat and !opts.show_summary and !opts.patch_with_stat) {
                    _ = try diffTwoTreesFiltered(allocator, pt, this_tree, "", opts, pathspecs, platform_impl);
                }
                if (opts.show_patch and !opts.patch_with_raw) {
                    var patch_opts = opts.*;
                    patch_opts.show_patch = true;
                    _ = try diffTwoTreesFiltered(allocator, pt, this_tree, "", &patch_opts, pathspecs, platform_impl);
                }
            }
            return true;
        }
    }
    return false;
}

const DiffTreeOpts = struct {
    recursive: bool = false,
    show_patch: bool = false,
    show_root: bool = false,
    name_only: bool = false,
    name_status: bool = false,
    no_commit_id: bool = false,
    quiet: bool = false,
    abbrev_len: ?usize = null,
    full_index: bool = false,
    show_stat: bool = false,
    show_summary: bool = false,
    show_raw: bool = true,
    patch_with_stat: bool = false,
    patch_with_raw: bool = false,
    show_shortstat: bool = false,
    show_pretty: bool = false,
    pretty_fmt: ?[]const u8 = null,
    show_cc: bool = false,
    show_combined: bool = false,
    show_m: bool = false,
    first_parent: bool = false,
    show_notes: bool = false,
    format_str: ?[]const u8 = null,
    compact_summary: bool = false,
    reverse_diff: bool = false,
    stdin_mode: bool = false,
    line_prefix: []const u8 = "",
    
    fn abbrevHash(self: @This(), hash: []const u8) []const u8 {
        if (self.full_index) return hash;
        if (self.abbrev_len) |abl| {
            const len = if (abl == 0) 7 else abl;
            return hash[0..@min(len, hash.len)];
        }
        return hash;
    }
    
    fn hashSuffix(self: @This()) []const u8 {
        if (self.full_index) return "";
        if (self.abbrev_len != null) {
            // Check GIT_PRINT_SHA1_ELLIPSIS env var
            if (std.posix.getenv("GIT_PRINT_SHA1_ELLIPSIS")) |v| {
                if (std.mem.eql(u8, v, "yes")) return "...";
            }
            return "";
        }
        return "";
    }
};

fn padMode6(buf: *[6]u8, mode: []const u8) []const u8 {
    if (mode.len >= 6) return mode[0..6];
    const pad_len = 6 - mode.len;
    @memset(buf[0..pad_len], '0');
    @memcpy(buf[pad_len..6], mode);
    return buf[0..6];
}

fn padMode(allocator: std.mem.Allocator, mode: []const u8) ![]const u8 {
    if (mode.len >= 6) return try allocator.dupe(u8, mode[0..6]);
    const result = try allocator.alloc(u8, 6);
    const pad_len = 6 - mode.len;
    @memset(result[0..pad_len], '0');
    @memcpy(result[pad_len..6], mode);
    return result;
}

fn isTreeMode(mode: []const u8) bool {
    return std.mem.eql(u8, mode, "40000") or std.mem.eql(u8, mode, "040000");
}

fn diffTreeWithEmpty(allocator: std.mem.Allocator, tree_hash_str: []const u8, recursive: bool, show_patch: bool, name_only: bool, name_status: bool, git_path: []const u8, platform_impl: *const platform_mod.Platform) !void {
    const default_opts = DiffTreeOpts{ .recursive = recursive, .show_patch = show_patch, .name_only = name_only, .name_status = name_status };
    try diffTreeWithEmptyPrefix(allocator, tree_hash_str, "", &default_opts, git_path, platform_impl);
}

const FileStatEntry = struct { name: []const u8, lines: usize };

fn outputStatForEmptyTree(allocator: std.mem.Allocator, tree_hash_str: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) !void {
    // Collect all files and their line counts
    var files = std.array_list.Managed(FileStatEntry).init(allocator);
    defer {
        for (files.items) |f| allocator.free(f.name);
        files.deinit();
    }
    try collectFilesFromTree(allocator, tree_hash_str, "", git_path, platform_impl, &files);
    
    if (files.items.len == 0) return;
    
    // Find max filename width and max line count width
    var max_name_len: usize = 0;
    var total_insertions: usize = 0;
    for (files.items) |f| {
        if (f.name.len > max_name_len) max_name_len = f.name.len;
        total_insertions += f.lines;
    }
    
    // Output each file stat line
    for (files.items) |f| {
        const padding = max_name_len - f.name.len;
        const pad_buf = try allocator.alloc(u8, padding);
        defer allocator.free(pad_buf);
        @memset(pad_buf, ' ');
        
        const plus_buf = try allocator.alloc(u8, f.lines);
        defer allocator.free(plus_buf);
        @memset(plus_buf, '+');
        
        const line = try std.fmt.allocPrint(allocator, " {s}{s} | {d} {s}\n", .{ f.name, pad_buf, f.lines, plus_buf });
        defer allocator.free(line);
        try platform_impl.writeStdout(line);
    }
    
    // Summary line
    const summary = try std.fmt.allocPrint(allocator, " {d} file{s} changed, {d} insertion{s}(+)\n", .{
        files.items.len,
        if (files.items.len != 1) "s" else "",
        total_insertions,
        if (total_insertions != 1) "s" else "",
    });
    defer allocator.free(summary);
    try platform_impl.writeStdout(summary);
}

fn collectFilesFromTree(allocator: std.mem.Allocator, tree_hash_str: []const u8, prefix: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, files: *std.array_list.Managed(FileStatEntry)) !void {
    const tree_obj = objects.GitObject.load(tree_hash_str, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    
    var entries = tree_mod.parseTree(tree_obj.data, allocator) catch return;
    defer entries.deinit();
    
    for (entries.items) |entry| {
        const full_name = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name })
        else
            try allocator.dupe(u8, entry.name);
        
        if (isTreeMode(entry.mode)) {
            defer allocator.free(full_name);
            try collectFilesFromTree(allocator, entry.hash, full_name, git_path, platform_impl, files);
        } else {
            // Count lines in the blob
            const content = loadBlobContent(allocator, entry.hash, git_path, platform_impl) catch "";
            defer if (content.len > 0) allocator.free(content);
            var line_count: usize = 0;
            if (content.len > 0) {
                var iter = std.mem.splitScalar(u8, content, '\n');
                while (iter.next()) |_| line_count += 1;
                if (content[content.len - 1] == '\n') line_count -= 1;
            }
            try files.append(.{ .name = full_name, .lines = line_count });
        }
    }
}

fn outputStatForTwoTrees(allocator: std.mem.Allocator, tree1_hash: []const u8, tree2_hash: []const u8, git_path: []const u8, pathspecs: []const []const u8, platform_impl: *const platform_mod.Platform) !void {
    var entries = std.array_list.Managed(diff_stats_mod.StatEntry).init(allocator);
    defer {
        for (entries.items) |*e| allocator.free(e.path);
        entries.deinit();
    }
    try diff_stats_mod.collectAccurate(allocator, tree1_hash, tree2_hash, "", git_path, pathspecs, platform_impl, &entries);
    if (entries.items.len == 0) return;
    try diff_stats_mod.formatStat(entries.items, platform_impl, allocator);
}

fn outputSummaryForTwoTrees(allocator: std.mem.Allocator, tree1_hash: []const u8, tree2_hash: []const u8, git_path: []const u8, pathspecs: []const []const u8, platform_impl: *const platform_mod.Platform) !void {
    var diff_entries = std.array_list.Managed(DiffStatEntry).init(allocator);
    defer {
        for (diff_entries.items) |*de| allocator.free(de.path);
        diff_entries.deinit();
    }
    try collectTreeDiffEntries(allocator, tree1_hash, tree2_hash, "", git_path, pathspecs, platform_impl, &diff_entries);
    for (diff_entries.items) |de| {
        if (de.is_new) {
            const mode_str = if (de.new_mode.len > 0) de.new_mode else "100644";
            const padded = try padMode(allocator, mode_str);
            const out = try std.fmt.allocPrint(allocator, " create mode {s} {s}\n", .{padded, de.path});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        } else if (de.is_deleted) {
            const mode_str = if (de.old_mode.len > 0) de.old_mode else "100644";
            const padded = try padMode(allocator, mode_str);
            const out = try std.fmt.allocPrint(allocator, " delete mode {s} {s}\n", .{padded, de.path});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        } else if (de.old_mode.len > 0 and de.new_mode.len > 0 and !std.mem.eql(u8, de.old_mode, de.new_mode)) {
            const padded_old = try padMode(allocator, de.old_mode);
            const padded_new = try padMode(allocator, de.new_mode);
            const out = try std.fmt.allocPrint(allocator, " mode change {s} => {s} {s}\n", .{padded_old, padded_new, de.path});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        }
    }
}

fn outputSummaryForEmptyTree(allocator: std.mem.Allocator, tree_hash_str: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) !void {
    // Use collectTreeDiffEntries with empty tree to get proper mode info
    var diff_entries = std.array_list.Managed(DiffStatEntry).init(allocator);
    defer {
        for (diff_entries.items) |*de| allocator.free(de.path);
        diff_entries.deinit();
    }
    const empty_tree = "4b825dc642cb6eb9a060e54bf899d69f82cf0101";
    try collectTreeDiffEntries(allocator, empty_tree, tree_hash_str, "", git_path, &.{}, platform_impl, &diff_entries);
    
    for (diff_entries.items) |de| {
        const mode_str = if (de.new_mode.len > 0) de.new_mode else "100644";
        const padded = try padMode(allocator, mode_str);
        const out = try std.fmt.allocPrint(allocator, " create mode {s} {s}\n", .{padded, de.path});
        defer allocator.free(out);
        try platform_impl.writeStdout(out);
    }
}

fn hasModeChanges(allocator: std.mem.Allocator, tree1_hash: []const u8, tree2_hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) !bool {
    var files1 = std.StringHashMap(TreeFileInfo).init(allocator);
    defer {
        var it = files1.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.hash);
            allocator.free(entry.value_ptr.mode);
        }
        files1.deinit();
    }
    var files2 = std.StringHashMap(TreeFileInfo).init(allocator);
    defer {
        var it = files2.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.hash);
            allocator.free(entry.value_ptr.mode);
        }
        files2.deinit();
    }
    try collectTreeFiles(allocator, tree1_hash, "", git_path, platform_impl, &files1);
    try collectTreeFiles(allocator, tree2_hash, "", git_path, platform_impl, &files2);
    
    var kit = files1.keyIterator();
    while (kit.next()) |key| {
        const f1 = files1.get(key.*) orelse continue;
        const f2 = files2.get(key.*) orelse continue;
        if (!std.mem.eql(u8, f1.mode, f2.mode)) return true;
    }
    return false;
}

fn getTreeForCommit(allocator: std.mem.Allocator, commit_hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) ![]u8 {
    const obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch return error.ObjectNotFound;
    defer obj.deinit(allocator);
    var iter = std.mem.splitScalar(u8, obj.data, '\n');
    while (iter.next()) |line| {
        if (line.len == 0) break;
        if (std.mem.startsWith(u8, line, "tree ")) {
            return allocator.dupe(u8, line["tree ".len..]);
        }
    }
    return error.ObjectNotFound;
}

fn getParentsForCommit(allocator: std.mem.Allocator, commit_hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) !std.array_list.Managed([]u8) {
    const obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch return error.ObjectNotFound;
    defer obj.deinit(allocator);
    var parents = std.array_list.Managed([]u8).init(allocator);
    var iter = std.mem.splitScalar(u8, obj.data, '\n');
    while (iter.next()) |line| {
        if (line.len == 0) break;
        if (std.mem.startsWith(u8, line, "parent ")) {
            try parents.append(try allocator.dupe(u8, line["parent ".len..]));
        }
    }
    return parents;
}

/// Collect files from a tree recursively into a flat list with full paths
fn collectTreeFiles(allocator: std.mem.Allocator, tree_hash: []const u8, prefix: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, result: *std.StringHashMap(TreeFileInfo)) !void {
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    var entries = tree_mod.parseTree(tree_obj.data, allocator) catch return;
    defer entries.deinit();
    for (entries.items) |entry| {
        const full_name = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name })
        else
            try allocator.dupe(u8, entry.name);
        if (isTreeMode(entry.mode)) {
            try collectTreeFiles(allocator, entry.hash, full_name, git_path, platform_impl, result);
            allocator.free(full_name);
        } else {
            try result.put(full_name, .{ .hash = try allocator.dupe(u8, entry.hash), .mode = try allocator.dupe(u8, entry.mode) });
        }
    }
}

const TreeFileInfo = struct {
    hash: []const u8,
    mode: []const u8,
};

/// Output combined stat for merge commits
fn outputCombinedStat(allocator: std.mem.Allocator, parent_hashes: []const []const u8, merge_tree_hash: []const u8, git_path: []const u8, dense: bool, platform_impl: *const platform_mod.Platform) !void {
    // Get files that differ from all parents (or any parent for -c)
    var merge_files = std.StringHashMap(TreeFileInfo).init(allocator);
    defer {
        var it = merge_files.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.hash);
            allocator.free(entry.value_ptr.mode);
        }
        merge_files.deinit();
    }
    try collectTreeFiles(allocator, merge_tree_hash, "", git_path, platform_impl, &merge_files);
    
    var parent_file_maps = std.array_list.Managed(std.StringHashMap(TreeFileInfo)).init(allocator);
    defer {
        for (parent_file_maps.items) |*pf| {
            var it = pf.iterator();
            while (it.next()) |entry| {
                allocator.free(entry.key_ptr.*);
                allocator.free(entry.value_ptr.hash);
                allocator.free(entry.value_ptr.mode);
            }
            pf.deinit();
        }
        parent_file_maps.deinit();
    }
    for (parent_hashes) |ph| {
        const parent_tree = getTreeForCommit(allocator, ph, git_path, platform_impl) catch {
            try parent_file_maps.append(std.StringHashMap(TreeFileInfo).init(allocator));
            continue;
        };
        defer allocator.free(parent_tree);
        var pf = std.StringHashMap(TreeFileInfo).init(allocator);
        try collectTreeFiles(allocator, parent_tree, "", git_path, platform_impl, &pf);
        try parent_file_maps.append(pf);
    }
    
    var total_ins: usize = 0;
    var total_dels: usize = 0;
    var files_changed: usize = 0;
    var max_name_len: usize = 0;
    
    // Collect changed files
    const ChangedFile = struct { name: []const u8, insertions: usize, deletions: usize };
    var changed = std.array_list.Managed(ChangedFile).init(allocator);
    defer changed.deinit();
    
    var name_it = merge_files.keyIterator();
    var all_names2 = std.array_list.Managed([]const u8).init(allocator);
    defer all_names2.deinit();
    while (name_it.next()) |key| try all_names2.append(key.*);
    std.mem.sort([]const u8, all_names2.items, {}, struct {
        fn cmp(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.cmp);
    
    for (all_names2.items) |file_name| {
        const merge_info = merge_files.get(file_name) orelse continue;
        var differs_from_all = true;
        var same_as_some = false;
        for (parent_file_maps.items) |pf| {
            if (pf.get(file_name)) |pi| {
                if (std.mem.eql(u8, pi.hash, merge_info.hash)) {
                    same_as_some = true;
                    differs_from_all = false;
                }
            }
        }
        if (dense and same_as_some) continue;
        if (!dense and !differs_from_all and same_as_some) continue;
        
        // Count insertions/deletions (simplified - count against first differing parent)
        var ins: usize = 0;
        var dels: usize = 0;
        const merge_content = loadBlobContent(allocator, merge_info.hash, git_path, platform_impl) catch "";
        defer if (merge_content.len > 0) allocator.free(merge_content);
        
        for (parent_file_maps.items) |pf| {
            if (pf.get(file_name)) |pi| {
                if (!std.mem.eql(u8, pi.hash, merge_info.hash)) {
                    const parent_content = loadBlobContent(allocator, pi.hash, git_path, platform_impl) catch "";
                    defer if (parent_content.len > 0) allocator.free(parent_content);
                    ins = countLines(merge_content);
                    dels = countLines(parent_content);
                    // Simple approximation: common lines
                    const common = @min(ins, dels);
                    if (ins >= common) ins -= common;
                    if (dels >= common) dels -= common;
                    break;
                }
            } else {
                ins = countLines(merge_content);
                break;
            }
        }
        
        if (file_name.len > max_name_len) max_name_len = file_name.len;
        try changed.append(.{ .name = file_name, .insertions = ins, .deletions = dels });
        total_ins += ins;
        total_dels += dels;
        files_changed += 1;
    }
    
    // Output stat lines
    for (changed.items) |cf| {
        const total = cf.insertions + cf.deletions;
        const bar_len = @min(total, 40);
        var bar = std.array_list.Managed(u8).init(allocator);
        defer bar.deinit();
        if (total > 0) {
            const plus_len = if (bar_len > 0) (cf.insertions * bar_len + total - 1) / total else 0;
            const minus_len = bar_len - plus_len;
            for (0..plus_len) |_| try bar.append('+');
            for (0..minus_len) |_| try bar.append('-');
        }
        const out = try std.fmt.allocPrint(allocator, " {s}{s} | {d:>4} {s}\n", .{
            cf.name,
            (" " ** 80)[0..@min(80, if (max_name_len > cf.name.len) max_name_len - cf.name.len else 0)],
            total,
            bar.items,
        });
        defer allocator.free(out);
        try platform_impl.writeStdout(out);
    }
    try formatDiffStatSummary(files_changed, total_ins, total_dels, platform_impl, allocator);
}

fn countLines(content: []const u8) usize {
    if (content.len == 0) return 0;
    var count: usize = 0;
    var iter = std.mem.splitScalar(u8, content, '\n');
    while (iter.next()) |_| count += 1;
    if (content[content.len - 1] == '\n') count -= 1;
    return count;
}

/// Output combined summary for merge commits
fn outputCombinedSummary(allocator: std.mem.Allocator, parent_hashes: []const []const u8, merge_tree_hash: []const u8, git_path: []const u8, dense: bool, platform_impl: *const platform_mod.Platform) !void {
    _ = dense;
    // Check for new files in merge that don't exist in any parent
    var merge_files2 = std.StringHashMap(TreeFileInfo).init(allocator);
    defer {
        var it = merge_files2.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.hash);
            allocator.free(entry.value_ptr.mode);
        }
        merge_files2.deinit();
    }
    try collectTreeFiles(allocator, merge_tree_hash, "", git_path, platform_impl, &merge_files2);
    
    var parent_file_maps2 = std.array_list.Managed(std.StringHashMap(TreeFileInfo)).init(allocator);
    defer {
        for (parent_file_maps2.items) |*pf| {
            var it = pf.iterator();
            while (it.next()) |entry| {
                allocator.free(entry.key_ptr.*);
                allocator.free(entry.value_ptr.hash);
                allocator.free(entry.value_ptr.mode);
            }
            pf.deinit();
        }
        parent_file_maps2.deinit();
    }
    for (parent_hashes) |ph| {
        const parent_tree = getTreeForCommit(allocator, ph, git_path, platform_impl) catch {
            try parent_file_maps2.append(std.StringHashMap(TreeFileInfo).init(allocator));
            continue;
        };
        defer allocator.free(parent_tree);
        var pf = std.StringHashMap(TreeFileInfo).init(allocator);
        try collectTreeFiles(allocator, parent_tree, "", git_path, platform_impl, &pf);
        try parent_file_maps2.append(pf);
    }
    
    var all_names3 = std.array_list.Managed([]const u8).init(allocator);
    defer all_names3.deinit();
    var nit = merge_files2.keyIterator();
    while (nit.next()) |key| try all_names3.append(key.*);
    std.mem.sort([]const u8, all_names3.items, {}, struct {
        fn cmp(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.cmp);
    
    for (all_names3.items) |file_name| {
        const merge_info = merge_files2.get(file_name) orelse continue;
        var in_all_parents = true;
        for (parent_file_maps2.items) |pf| {
            if (!pf.contains(file_name)) {
                in_all_parents = false;
                break;
            }
        }
        if (!in_all_parents) {
            var mode_str: []const u8 = merge_info.mode;
            if (mode_str.len < 6) mode_str = "100644";
            const out = try std.fmt.allocPrint(allocator, " create mode {s} {s}\n", .{ mode_str, file_name });
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        }
    }
}

/// Output combined shortstat for merge commits
fn outputCombinedShortStat(allocator: std.mem.Allocator, parent_hashes: []const []const u8, merge_tree_hash: []const u8, git_path: []const u8, dense: bool, platform_impl: *const platform_mod.Platform) !void {
    _ = parent_hashes;
    _ = merge_tree_hash;
    _ = git_path;
    _ = dense;
    // Simplified: just output a placeholder for now
    try platform_impl.writeStdout(" 0 files changed\n");
    _ = allocator;
}

/// Output combined diff (--cc format) for a merge commit
fn outputCombinedDiff(allocator: std.mem.Allocator, parent_hashes: []const []const u8, merge_tree_hash: []const u8, git_path: []const u8, dense: bool, platform_impl: *const platform_mod.Platform) !void {
    // Collect files from merge tree
    var merge_files = std.StringHashMap(TreeFileInfo).init(allocator);
    defer {
        var it = merge_files.iterator();
        while (it.next()) |entry| {
            allocator.free(entry.key_ptr.*);
            allocator.free(entry.value_ptr.hash);
            allocator.free(entry.value_ptr.mode);
        }
        merge_files.deinit();
    }
    try collectTreeFiles(allocator, merge_tree_hash, "", git_path, platform_impl, &merge_files);
    
    // Collect files from each parent tree
    var parent_files = std.array_list.Managed(std.StringHashMap(TreeFileInfo)).init(allocator);
    defer {
        for (parent_files.items) |*pf| {
            var it = pf.iterator();
            while (it.next()) |entry| {
                allocator.free(entry.key_ptr.*);
                allocator.free(entry.value_ptr.hash);
                allocator.free(entry.value_ptr.mode);
            }
            pf.deinit();
        }
        parent_files.deinit();
    }
    for (parent_hashes) |ph| {
        const parent_tree = getTreeForCommit(allocator, ph, git_path, platform_impl) catch {
            try parent_files.append(std.StringHashMap(TreeFileInfo).init(allocator));
            continue;
        };
        defer allocator.free(parent_tree);
        var pf = std.StringHashMap(TreeFileInfo).init(allocator);
        try collectTreeFiles(allocator, parent_tree, "", git_path, platform_impl, &pf);
        try parent_files.append(pf);
    }
    
    // Collect all file names from merge tree
    var all_names = std.array_list.Managed([]const u8).init(allocator);
    defer all_names.deinit();
    var name_iter = merge_files.keyIterator();
    while (name_iter.next()) |key| try all_names.append(key.*);
    std.mem.sort([]const u8, all_names.items, {}, struct {
        fn cmp(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.cmp);
    
    for (all_names.items) |file_name| {
        const merge_info = merge_files.get(file_name) orelse continue;
        
        // Check if file differs from any parent
        var differs_from_any = false;
        var all_same_as_some_parent = false;
        for (parent_files.items) |pf| {
            if (pf.get(file_name)) |pi| {
                if (std.mem.eql(u8, pi.hash, merge_info.hash)) {
                    all_same_as_some_parent = true;
                } else {
                    differs_from_any = true;
                }
            } else {
                differs_from_any = true;
            }
        }
        
        if (!differs_from_any) continue;
        // In dense (--cc) mode, skip files that match at least one parent
        if (dense and all_same_as_some_parent) continue;
        
        // Load merge content
        const merge_content = loadBlobContent(allocator, merge_info.hash, git_path, platform_impl) catch "";
        defer if (merge_content.len > 0) allocator.free(merge_content);
        
        // Load parent contents
        var parent_contents = std.array_list.Managed([]const u8).init(allocator);
        defer {
            for (parent_contents.items) |pc| {
                if (pc.len > 0) allocator.free(pc);
            }
            parent_contents.deinit();
        }
        var parent_short_hashes = std.array_list.Managed([]const u8).init(allocator);
        defer parent_short_hashes.deinit();
        
        for (parent_files.items) |pf| {
            if (pf.get(file_name)) |pi| {
                const content = loadBlobContent(allocator, pi.hash, git_path, platform_impl) catch "";
                try parent_contents.append(content);
                try parent_short_hashes.append(pi.hash[0..@min(7, pi.hash.len)]);
            } else {
                try parent_contents.append("");
                try parent_short_hashes.append("0000000");
            }
        }
        
        // Output combined diff header
        const merge_short = merge_info.hash[0..@min(7, merge_info.hash.len)];
        
        // diff --cc filename
        const diff_hdr = try std.fmt.allocPrint(allocator, "diff --cc {s}\n", .{file_name});
        defer allocator.free(diff_hdr);
        try platform_impl.writeStdout(diff_hdr);
        
        // index line: index hash1,hash2..merge_hash
        var idx_line = std.array_list.Managed(u8).init(allocator);
        defer idx_line.deinit();
        try idx_line.appendSlice("index ");
        for (parent_short_hashes.items, 0..) |psh, i| {
            if (i > 0) try idx_line.append(',');
            try idx_line.appendSlice(psh);
        }
        try idx_line.appendSlice("..");
        try idx_line.appendSlice(merge_short);
        try idx_line.append('\n');
        try platform_impl.writeStdout(idx_line.items);
        
        // --- a/file and +++ b/file
        const minus_line = try std.fmt.allocPrint(allocator, "--- a/{s}\n+++ b/{s}\n", .{ file_name, file_name });
        defer allocator.free(minus_line);
        try platform_impl.writeStdout(minus_line);
        
        // Generate combined diff hunks
        try outputCombinedDiffHunks(allocator, parent_contents.items, merge_content, platform_impl);
    }
}

/// Generate combined diff hunks for --cc format
fn outputCombinedDiffHunks(allocator: std.mem.Allocator, parent_contents: []const []const u8, merge_content: []const u8, platform_impl: *const platform_mod.Platform) !void {
    const num_parents = parent_contents.len;
    
    // Split all contents into lines
    var merge_lines = std.array_list.Managed([]const u8).init(allocator);
    defer merge_lines.deinit();
    {
        var iter = std.mem.splitScalar(u8, merge_content, '\n');
        while (iter.next()) |line| try merge_lines.append(line);
        // Remove trailing empty line from final newline
        if (merge_lines.items.len > 0 and merge_lines.items[merge_lines.items.len - 1].len == 0) {
            _ = merge_lines.pop();
        }
    }
    
    var parent_lines_list = std.array_list.Managed(std.array_list.Managed([]const u8)).init(allocator);
    defer {
        for (parent_lines_list.items) |*pl| pl.deinit();
        parent_lines_list.deinit();
    }
    for (parent_contents) |pc| {
        var pl = std.array_list.Managed([]const u8).init(allocator);
        var iter = std.mem.splitScalar(u8, pc, '\n');
        while (iter.next()) |line| try pl.append(line);
        if (pl.items.len > 0 and pl.items[pl.items.len - 1].len == 0) {
            _ = pl.pop();
        }
        try parent_lines_list.append(pl);
    }
    
    // Compute LCS-based diff for each parent against merge
    // For simplicity, we'll use a line-by-line approach
    // Mark each merge line with which parents it came from
    
    // For each parent, compute which merge lines match
    var parent_matches = std.array_list.Managed([]bool).init(allocator);
    defer {
        for (parent_matches.items) |pm| allocator.free(pm);
        parent_matches.deinit();
    }
    
    for (parent_lines_list.items) |pl| {
        const matches = try allocator.alloc(bool, merge_lines.items.len);
        @memset(matches, false);
        
        // Simple LCS matching
        var pi: usize = 0;
        for (merge_lines.items, 0..) |ml, mi| {
            if (pi < pl.items.len and std.mem.eql(u8, ml, pl.items[pi])) {
                matches[mi] = true;
                pi += 1;
            }
        }
        try parent_matches.append(matches);
    }
    
    // Build hunk header
    // @@@ -start1,len1 -start2,len2 +start_merge,len_merge @@@
    var hunk_header = std.array_list.Managed(u8).init(allocator);
    defer hunk_header.deinit();
    // Use @@@ markers with num_parents @ signs
    for (0..num_parents) |_| try hunk_header.append('@');
    try hunk_header.append(' ');
    for (parent_lines_list.items) |pl| {
        try hunk_header.append('-');
        const len = pl.items.len;
        if (len == 1) {
            try hunk_header.appendSlice("1");
        } else {
            const s = try std.fmt.allocPrint(allocator, "1,{d}", .{len});
            defer allocator.free(s);
            try hunk_header.appendSlice(s);
        }
        try hunk_header.append(' ');
    }
    try hunk_header.append('+');
    if (merge_lines.items.len == 1) {
        try hunk_header.appendSlice("1");
    } else {
        const s = try std.fmt.allocPrint(allocator, "1,{d}", .{merge_lines.items.len});
        defer allocator.free(s);
        try hunk_header.appendSlice(s);
    }
    try hunk_header.append(' ');
    for (0..num_parents) |_| try hunk_header.append('@');
    try hunk_header.append('\n');
    try platform_impl.writeStdout(hunk_header.items);
    
    // Output lines with combined prefix
    for (merge_lines.items, 0..) |line, i| {
        for (parent_matches.items) |pm| {
            if (pm[i]) {
                try platform_impl.writeStdout(" ");
            } else {
                try platform_impl.writeStdout("+");
            }
        }
        try platform_impl.writeStdout(line);
        try platform_impl.writeStdout("\n");
    }
}

fn diffTreeWithEmptyOpts(allocator: std.mem.Allocator, tree_hash_str: []const u8, opts: *const DiffTreeOpts, git_path: []const u8, platform_impl: *const platform_mod.Platform) !void {
    try diffTreeWithEmptyPrefix(allocator, tree_hash_str, "", opts, git_path, platform_impl);
}

fn diffTreeWithEmptyPrefix(allocator: std.mem.Allocator, tree_hash_str: []const u8, prefix: []const u8, opts: *const DiffTreeOpts, git_path: []const u8, platform_impl: *const platform_mod.Platform) !void {
    const recursive = opts.recursive;
    const show_patch = opts.show_patch;
    const name_only = opts.name_only;
    const name_status = opts.name_status;
    const tree_obj = objects.GitObject.load(tree_hash_str, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    
    var entries = tree_mod.parseTree(tree_obj.data, allocator) catch return;
    defer entries.deinit();
    
    const zero_hash = "0000000000000000000000000000000000000000";
    
    for (entries.items) |entry| {
        const full_name = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, entry.name })
        else
            try allocator.dupe(u8, entry.name);
        defer allocator.free(full_name);
        
        if (recursive and isTreeMode(entry.mode)) {
            try diffTreeWithEmptyPrefix(allocator, entry.hash, full_name, opts, git_path, platform_impl);
            continue;
        }
        
        if (show_patch) {
            // Generate unified diff for new file
            const new_content = loadBlobContent(allocator, entry.hash, git_path, platform_impl) catch "";
            defer if (new_content.len > 0) allocator.free(new_content);
            var mbuf: [6]u8 = undefined;
            const padded_mode = padMode6(&mbuf, entry.mode);
            // full_index overrides abbrev for index line
            const idx_zero = if (opts.full_index) zero_hash else if (opts.abbrev_len) |abl| zero_hash[0..@min(if (abl == 0) 7 else abl, zero_hash.len)] else zero_hash[0..7];
            const idx_hash = if (opts.full_index) entry.hash else if (opts.abbrev_len) |abl| entry.hash[0..@min(if (abl == 0) 7 else abl, entry.hash.len)] else entry.hash[0..@min(7, entry.hash.len)];
            const header = try std.fmt.allocPrint(allocator, "diff --git a/{s} b/{s}\nnew file mode {s}\nindex {s}..{s}\n--- /dev/null\n+++ b/{s}\n", .{ full_name, full_name, padded_mode, idx_zero, idx_hash, full_name });
            defer allocator.free(header);
            try platform_impl.writeStdout(header);
            
            // Output hunk header and content
            if (new_content.len > 0) {
                var line_count: usize = 0;
                var iter = std.mem.splitScalar(u8, new_content, '\n');
                while (iter.next()) |_| line_count += 1;
                // Remove trailing empty line from count
                if (new_content.len > 0 and new_content[new_content.len - 1] == '\n') line_count -= 1;
                
                const hunk_header = try std.fmt.allocPrint(allocator, "@@ -0,0 +1,{d} @@\n", .{line_count});
                defer allocator.free(hunk_header);
                try platform_impl.writeStdout(hunk_header);
                
                var line_iter = std.mem.splitScalar(u8, new_content, '\n');
                var printed: usize = 0;
                while (line_iter.next()) |line| {
                    if (printed >= line_count) break;
                    const line_out = try std.fmt.allocPrint(allocator, "+{s}\n", .{line});
                    defer allocator.free(line_out);
                    try platform_impl.writeStdout(line_out);
                    printed += 1;
                }
            }
        } else if (name_only) {
            const out = try std.fmt.allocPrint(allocator, "{s}\n", .{full_name});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        } else if (name_status) {
            const out = try std.fmt.allocPrint(allocator, "A\t{s}\n", .{full_name});
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        } else {
            var mbuf: [6]u8 = undefined;
            const ah1 = opts.abbrevHash(zero_hash);
            const ah2 = opts.abbrevHash(entry.hash);
            const suf = opts.hashSuffix();
            const out = try std.fmt.allocPrint(allocator, ":000000 {s} {s}{s} {s}{s} A\t{s}\n", .{ padMode6(&mbuf, entry.mode), ah1, suf, ah2, suf, full_name });
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        }
    }
}

fn collectTreeDiffEntries(allocator: std.mem.Allocator, tree1_hash: []const u8, tree2_hash: []const u8, prefix: []const u8, git_path: []const u8, pathspecs: []const []const u8, platform_impl: *const platform_mod.Platform, diff_entries_out: *std.array_list.Managed(DiffStatEntry)) !void {
    const empty_tree_hash = "4b825dc642cb6eb9a060e54bf899d69f82cf0101";
    const is_empty1 = std.mem.eql(u8, tree1_hash, empty_tree_hash);
    const is_empty2 = std.mem.eql(u8, tree2_hash, empty_tree_hash);

    var tree1_obj_opt: ?objects.GitObject = if (!is_empty1) (objects.GitObject.load(tree1_hash, git_path, platform_impl, allocator) catch return) else null;
    defer if (tree1_obj_opt) |*o| o.deinit(allocator);
    var tree2_obj_opt: ?objects.GitObject = if (!is_empty2) (objects.GitObject.load(tree2_hash, git_path, platform_impl, allocator) catch return) else null;
    defer if (tree2_obj_opt) |*o| o.deinit(allocator);

    const data1: []const u8 = if (tree1_obj_opt) |o| o.data else "";
    const data2: []const u8 = if (tree2_obj_opt) |o| o.data else "";

    var parsed1 = tree_mod.parseTree(data1, allocator) catch return;
    defer parsed1.deinit();
    var parsed2 = tree_mod.parseTree(data2, allocator) catch return;
    defer parsed2.deinit();

    var map1 = std.StringHashMap(tree_mod.TreeEntry).init(allocator);
    defer map1.deinit();
    var map2 = std.StringHashMap(tree_mod.TreeEntry).init(allocator);
    defer map2.deinit();
    for (parsed1.items) |e| map1.put(e.name, e) catch {};
    for (parsed2.items) |e| map2.put(e.name, e) catch {};

    var all_names = std.StringHashMap(void).init(allocator);
    defer all_names.deinit();
    for (parsed1.items) |e| all_names.put(e.name, {}) catch {};
    for (parsed2.items) |e| all_names.put(e.name, {}) catch {};

    var name_list = std.array_list.Managed([]const u8).init(allocator);
    defer name_list.deinit();
    var niter = all_names.keyIterator();
    while (niter.next()) |key| try name_list.append(key.*);
    std.mem.sort([]const u8, name_list.items, {}, struct {
        fn cmp(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.cmp);

    for (name_list.items) |name| {
        const e1 = map1.get(name);
        const e2 = map2.get(name);

        const full_name = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);

        if (e1 != null and e2 != null) {
            if (std.mem.eql(u8, e1.?.hash, e2.?.hash) and std.mem.eql(u8, e1.?.mode, e2.?.mode)) {
                allocator.free(full_name);
                continue;
            }
            // Mode-only change: same hash, different mode
            if (std.mem.eql(u8, e1.?.hash, e2.?.hash)) {
                if (!matchesPathspecs(full_name, pathspecs)) { allocator.free(full_name); continue; }
                try diff_entries_out.append(.{ .path = full_name, .insertions = 0, .deletions = 0, .is_binary = false, .is_new = false, .is_deleted = false, .old_hash = "", .new_hash = "", .old_mode = try allocator.dupe(u8, e1.?.mode), .new_mode = try allocator.dupe(u8, e2.?.mode) });
                continue;
            }
            if (isTreeMode(e1.?.mode) and isTreeMode(e2.?.mode)) {
                try collectTreeDiffEntries(allocator, e1.?.hash, e2.?.hash, full_name, git_path, pathspecs, platform_impl, diff_entries_out);
                allocator.free(full_name);
                continue;
            }
            if (!matchesPathspecs(full_name, pathspecs)) { allocator.free(full_name); continue; }
            try diff_entries_out.append(.{ .path = full_name, .insertions = 1, .deletions = 1, .is_binary = false, .is_new = false, .is_deleted = false, .old_hash = "", .new_hash = "", .old_mode = try allocator.dupe(u8, e1.?.mode), .new_mode = try allocator.dupe(u8, e2.?.mode) });
        } else if (e1 != null and e2 == null) {
            if (isTreeMode(e1.?.mode)) {
                try collectTreeDiffEntries(allocator, e1.?.hash, "4b825dc642cb6eb9a060e54bf899d69f82cf0101", full_name, git_path, pathspecs, platform_impl, diff_entries_out);
                allocator.free(full_name);
                continue;
            }
            if (!matchesPathspecs(full_name, pathspecs)) { allocator.free(full_name); continue; }
            try diff_entries_out.append(.{ .path = full_name, .insertions = 0, .deletions = 1, .is_binary = false, .is_new = false, .is_deleted = true, .old_hash = "", .new_hash = "", .old_mode = try allocator.dupe(u8, e1.?.mode), .new_mode = "" });
        } else if (e2 != null) {
            if (isTreeMode(e2.?.mode)) {
                try collectTreeDiffEntries(allocator, "4b825dc642cb6eb9a060e54bf899d69f82cf0101", e2.?.hash, full_name, git_path, pathspecs, platform_impl, diff_entries_out);
                allocator.free(full_name);
                continue;
            }
            if (!matchesPathspecs(full_name, pathspecs)) { allocator.free(full_name); continue; }
            try diff_entries_out.append(.{ .path = full_name, .insertions = 1, .deletions = 0, .is_binary = false, .is_new = true, .is_deleted = false, .old_hash = "", .new_hash = "", .old_mode = "", .new_mode = try allocator.dupe(u8, e2.?.mode) });
        } else {
            allocator.free(full_name);
        }
    }
}

fn diffTwoTreesPatch(allocator: std.mem.Allocator, tree1_hash: []const u8, tree2_hash: []const u8, prefix: []const u8, git_path: []const u8, quiet: bool, pathspecs: []const []const u8, platform_impl: *const platform_mod.Platform) !bool {
    const tree1_obj = objects.GitObject.load(tree1_hash, git_path, platform_impl, allocator) catch return false;
    defer tree1_obj.deinit(allocator);
    const tree2_obj = objects.GitObject.load(tree2_hash, git_path, platform_impl, allocator) catch return false;
    defer tree2_obj.deinit(allocator);
    
    var entries1 = tree_mod.parseTree(tree1_obj.data, allocator) catch return false;
    defer entries1.deinit();
    var entries2 = tree_mod.parseTree(tree2_obj.data, allocator) catch return false;
    defer entries2.deinit();
    
    var map1 = std.StringHashMap(tree_mod.TreeEntry).init(allocator);
    defer map1.deinit();
    var map2 = std.StringHashMap(tree_mod.TreeEntry).init(allocator);
    defer map2.deinit();
    for (entries1.items) |e| map1.put(e.name, e) catch {};
    for (entries2.items) |e| map2.put(e.name, e) catch {};
    
    var all_names = std.StringHashMap(void).init(allocator);
    defer all_names.deinit();
    for (entries1.items) |e| all_names.put(e.name, {}) catch {};
    for (entries2.items) |e| all_names.put(e.name, {}) catch {};
    
    var name_list = std.array_list.Managed([]const u8).init(allocator);
    defer name_list.deinit();
    var niter = all_names.keyIterator();
    while (niter.next()) |key| try name_list.append(key.*);
    std.mem.sort([]const u8, name_list.items, {}, struct {
        fn cmp(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.cmp);
    
    var had_diff = false;
    for (name_list.items) |name| {
        const e1 = map1.get(name);
        const e2 = map2.get(name);
        
        const full_name = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);
        defer allocator.free(full_name);
        
        if (e1 != null and e2 != null) {
            if (std.mem.eql(u8, e1.?.hash, e2.?.hash) and std.mem.eql(u8, e1.?.mode, e2.?.mode)) continue;
            if (isTreeMode(e1.?.mode) and isTreeMode(e2.?.mode)) {
                const sub = try diffTwoTreesPatch(allocator, e1.?.hash, e2.?.hash, full_name, git_path, quiet, pathspecs, platform_impl);
                if (sub) had_diff = true;
                continue;
            }
            if (!matchesPathspecs(full_name, pathspecs)) continue;
            had_diff = true;
            if (!quiet) {
                // Load both blob contents and generate unified diff
                const old_content = loadBlobContent(allocator, e1.?.hash, git_path, platform_impl) catch "";
                defer if (old_content.len > 0) allocator.free(old_content);
                const new_content = loadBlobContent(allocator, e2.?.hash, git_path, platform_impl) catch "";
                defer if (new_content.len > 0) allocator.free(new_content);
                const short1 = e1.?.hash[0..@min(7, e1.?.hash.len)];
                const short2 = e2.?.hash[0..@min(7, e2.?.hash.len)];
                const diff_out = diff_mod.generateUnifiedDiffWithHashes(old_content, new_content, full_name, short1, short2, allocator) catch continue;
                defer allocator.free(diff_out);
                try platform_impl.writeStdout(diff_out);
            }
        } else if (e1 != null and e2 == null) {
            if (!matchesPathspecs(full_name, pathspecs)) continue;
            had_diff = true;
            if (!quiet) {
                const old_content = loadBlobContent(allocator, e1.?.hash, git_path, platform_impl) catch "";
                defer if (old_content.len > 0) allocator.free(old_content);
                const short1 = e1.?.hash[0..@min(7, e1.?.hash.len)];
                const diff_out = diff_mod.generateUnifiedDiffWithHashes(old_content, "", full_name, short1, "0000000", allocator) catch continue;
                defer allocator.free(diff_out);
                try platform_impl.writeStdout(diff_out);
            }
        } else if (e2 != null) {
            if (!matchesPathspecs(full_name, pathspecs)) continue;
            had_diff = true;
            if (!quiet) {
                const new_content = loadBlobContent(allocator, e2.?.hash, git_path, platform_impl) catch "";
                defer if (new_content.len > 0) allocator.free(new_content);
                const short2 = e2.?.hash[0..@min(7, e2.?.hash.len)];
                const diff_out = diff_mod.generateUnifiedDiffWithHashes("", new_content, full_name, "0000000", short2, allocator) catch continue;
                defer allocator.free(diff_out);
                try platform_impl.writeStdout(diff_out);
            }
        }
    }
    return had_diff;
}

fn loadBlobContent(allocator: std.mem.Allocator, hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform) ![]u8 {
    const obj = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch return error.ObjectNotFound;
    defer obj.deinit(allocator);
    if (obj.type != .blob) return error.NotABlob;
    return allocator.dupe(u8, obj.data);
}

fn matchesPathspecs(path: []const u8, pathspecs: []const []const u8) bool {
    if (pathspecs.len == 0) return true;
    for (pathspecs) |ps| {
        if (pathspecMatch(ps, path)) return true;
        // Also allow matching when path is a parent directory of the pathspec
        if (std.mem.startsWith(u8, ps, path) and ps.len > path.len and ps[path.len] == '/') return true;
    }
    return false;
}

fn diffTwoTreesFiltered(allocator: std.mem.Allocator, tree1_hash: []const u8, tree2_hash: []const u8, prefix: []const u8, opts: *const DiffTreeOpts, pathspecs: []const []const u8, platform_impl: *const platform_mod.Platform) !bool {
    const recursive = opts.recursive;
    const name_only = opts.name_only;
    const name_status = opts.name_status;
    const quiet = opts.quiet;
    const git_path = findGitDirectory(allocator, platform_impl) catch return false;
    defer allocator.free(git_path);
    
    const tree1_obj = objects.GitObject.load(tree1_hash, git_path, platform_impl, allocator) catch return false;
    defer tree1_obj.deinit(allocator);
    const tree2_obj = objects.GitObject.load(tree2_hash, git_path, platform_impl, allocator) catch return false;
    defer tree2_obj.deinit(allocator);
    
    var entries1 = tree_mod.parseTree(tree1_obj.data, allocator) catch return false;
    defer entries1.deinit();
    var entries2 = tree_mod.parseTree(tree2_obj.data, allocator) catch return false;
    defer entries2.deinit();
    
    const zero_hash = "0000000000000000000000000000000000000000";
    
    // Build lookup maps
    var map1 = std.StringHashMap(tree_mod.TreeEntry).init(allocator);
    defer map1.deinit();
    var map2 = std.StringHashMap(tree_mod.TreeEntry).init(allocator);
    defer map2.deinit();
    for (entries1.items) |e| map1.put(e.name, e) catch {};
    for (entries2.items) |e| map2.put(e.name, e) catch {};
    
    // Collect and sort all names
    var all_names = std.StringHashMap(void).init(allocator);
    defer all_names.deinit();
    for (entries1.items) |e| all_names.put(e.name, {}) catch {};
    for (entries2.items) |e| all_names.put(e.name, {}) catch {};
    
    var name_list = std.array_list.Managed([]const u8).init(allocator);
    defer name_list.deinit();
    var niter = all_names.keyIterator();
    while (niter.next()) |key| try name_list.append(key.*);
    std.mem.sort([]const u8, name_list.items, {}, struct {
        fn cmp(_: void, a: []const u8, b: []const u8) bool {
            return std.mem.order(u8, a, b) == .lt;
        }
    }.cmp);
    
    var had_diff = false;
    for (name_list.items) |name| {
        const e1 = map1.get(name);
        const e2 = map2.get(name);
        
        const full_name = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);
        defer allocator.free(full_name);
        
        if (e1 != null and e2 != null) {
            if (std.mem.eql(u8, e1.?.hash, e2.?.hash) and std.mem.eql(u8, e1.?.mode, e2.?.mode)) continue;
            if (recursive and isTreeMode(e1.?.mode) and isTreeMode(e2.?.mode)) {
                const sub = try diffTwoTreesFiltered(allocator, e1.?.hash, e2.?.hash, full_name, opts, pathspecs, platform_impl);
                if (sub) had_diff = true;
                continue;
            }
            if (!matchesPathspecs(full_name, pathspecs)) continue;
            had_diff = true;
            if (!quiet) {
                if (name_only) {
                    const out = try std.fmt.allocPrint(allocator, "{s}\n", .{full_name});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (name_status) {
                    const out = try std.fmt.allocPrint(allocator, "M\t{s}\n", .{full_name});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (opts.show_patch) {
                    // Generate unified diff for modified file
                    const old_content = loadBlobContent(allocator, e1.?.hash, git_path, platform_impl) catch "";
                    defer if (old_content.len > 0) allocator.free(old_content);
                    const new_content = loadBlobContent(allocator, e2.?.hash, git_path, platform_impl) catch "";
                    defer if (new_content.len > 0) allocator.free(new_content);
                    const idx_h1 = if (opts.full_index) e1.?.hash else e1.?.hash[0..@min(7, e1.?.hash.len)];
                    const idx_h2 = if (opts.full_index) e2.?.hash else e2.?.hash[0..@min(7, e2.?.hash.len)];
                    const diff_out = diff_mod.generateUnifiedDiffWithHashes(old_content, new_content, full_name, idx_h1, idx_h2, allocator) catch "";
                    defer if (diff_out.len > 0) allocator.free(diff_out);
                    if (diff_out.len > 0) try platform_impl.writeStdout(diff_out);
                } else {
                    var mb1: [6]u8 = undefined;
                    var mb2: [6]u8 = undefined;
                    const suf = opts.hashSuffix();
                    const out = try std.fmt.allocPrint(allocator, ":{s} {s} {s}{s} {s}{s} M\t{s}\n", .{ padMode6(&mb1, e1.?.mode), padMode6(&mb2, e2.?.mode), opts.abbrevHash(e1.?.hash), suf, opts.abbrevHash(e2.?.hash), suf, full_name });
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
        } else if (e1 != null and e2 == null) {
            if (!matchesPathspecs(full_name, pathspecs)) continue;
            had_diff = true;
            if (!quiet) {
                if (name_only) {
                    const out = try std.fmt.allocPrint(allocator, "{s}\n", .{full_name});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (name_status) {
                    const out = try std.fmt.allocPrint(allocator, "D\t{s}\n", .{full_name});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (opts.show_patch) {
                    // Generate diff for deleted file
                    const old_content = loadBlobContent(allocator, e1.?.hash, git_path, platform_impl) catch "";
                    defer if (old_content.len > 0) allocator.free(old_content);
                    var mb1: [6]u8 = undefined;
                    const idx_h1 = if (opts.full_index) e1.?.hash else e1.?.hash[0..@min(7, e1.?.hash.len)];
                    const header = try std.fmt.allocPrint(allocator, "diff --git a/{s} b/{s}\ndeleted file mode {s}\nindex {s}..0000000\n--- a/{s}\n+++ /dev/null\n", .{ full_name, full_name, padMode6(&mb1, e1.?.mode), idx_h1, full_name });
                    defer allocator.free(header);
                    try platform_impl.writeStdout(header);
                    if (old_content.len > 0) {
                        var line_count: usize = 0;
                        var citer = std.mem.splitScalar(u8, old_content, '\n');
                        while (citer.next()) |_| line_count += 1;
                        if (old_content[old_content.len - 1] == '\n') line_count -= 1;
                        const hunk = try std.fmt.allocPrint(allocator, "@@ -1,{d} +0,0 @@\n", .{line_count});
                        defer allocator.free(hunk);
                        try platform_impl.writeStdout(hunk);
                        var liter = std.mem.splitScalar(u8, old_content, '\n');
                        var printed: usize = 0;
                        while (liter.next()) |line| {
                            if (printed >= line_count) break;
                            const lo = try std.fmt.allocPrint(allocator, "-{s}\n", .{line});
                            defer allocator.free(lo);
                            try platform_impl.writeStdout(lo);
                            printed += 1;
                        }
                    }
                } else {
                    var mb1: [6]u8 = undefined;
                    const suf = opts.hashSuffix();
                    const out = try std.fmt.allocPrint(allocator, ":{s} 000000 {s}{s} {s}{s} D\t{s}\n", .{ padMode6(&mb1, e1.?.mode), opts.abbrevHash(e1.?.hash), suf, opts.abbrevHash(zero_hash), suf, full_name });
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
        } else if (e2 != null) {
            if (!matchesPathspecs(full_name, pathspecs)) continue;
            had_diff = true;
            if (!quiet) {
                if (name_only) {
                    const out = try std.fmt.allocPrint(allocator, "{s}\n", .{full_name});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (name_status) {
                    const out = try std.fmt.allocPrint(allocator, "A\t{s}\n", .{full_name});
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                } else if (opts.show_patch) {
                    // Generate diff for new file
                    const new_content = loadBlobContent(allocator, e2.?.hash, git_path, platform_impl) catch "";
                    defer if (new_content.len > 0) allocator.free(new_content);
                    var mb2: [6]u8 = undefined;
                    const idx_h2 = if (opts.full_index) e2.?.hash else e2.?.hash[0..@min(7, e2.?.hash.len)];
                    const header = try std.fmt.allocPrint(allocator, "diff --git a/{s} b/{s}\nnew file mode {s}\nindex 0000000..{s}\n--- /dev/null\n+++ b/{s}\n", .{ full_name, full_name, padMode6(&mb2, e2.?.mode), idx_h2, full_name });
                    defer allocator.free(header);
                    try platform_impl.writeStdout(header);
                    if (new_content.len > 0) {
                        var line_count: usize = 0;
                        var citer = std.mem.splitScalar(u8, new_content, '\n');
                        while (citer.next()) |_| line_count += 1;
                        if (new_content[new_content.len - 1] == '\n') line_count -= 1;
                        const hunk = try std.fmt.allocPrint(allocator, "@@ -0,0 +1,{d} @@\n", .{line_count});
                        defer allocator.free(hunk);
                        try platform_impl.writeStdout(hunk);
                        var liter = std.mem.splitScalar(u8, new_content, '\n');
                        var printed: usize = 0;
                        while (liter.next()) |line| {
                            if (printed >= line_count) break;
                            const lo = try std.fmt.allocPrint(allocator, "+{s}\n", .{line});
                            defer allocator.free(lo);
                            try platform_impl.writeStdout(lo);
                            printed += 1;
                        }
                    }
                } else {
                    var mb2: [6]u8 = undefined;
                    const suf = opts.hashSuffix();
                    const out = try std.fmt.allocPrint(allocator, ":000000 {s} {s}{s} {s}{s} A\t{s}\n", .{ padMode6(&mb2, e2.?.mode), opts.abbrevHash(zero_hash), suf, opts.abbrevHash(e2.?.hash), suf, full_name });
                    defer allocator.free(out);
                    try platform_impl.writeStdout(out);
                }
            }
        }
    }
    return had_diff;
}


const TreeEntryInfo = struct { mode: u32, hash: [20]u8 };

// checkRefFormatValid_crf is at end of file

fn nativeCmdDiffIndex(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    const allocator = std.heap.page_allocator;
    const rest = args[command_index + 1 ..];
    var cached = false;
    var exit_code_flag = false;
    var patch_mode = false;
    var suppress_output = false;
    var name_status = false;
    var name_only = false;
    var tree_ish: ?[]const u8 = null;
    var pathspecs = std.array_list.Managed([]const u8).init(allocator);
    defer pathspecs.deinit();
    var seen_dashdash = false;

    for (rest) |arg| {
        if (seen_dashdash) {
            try pathspecs.append(arg);
        } else if (std.mem.eql(u8, arg, "-h")) {
            try platform_impl.writeStdout("usage: git diff-index [<options>] <tree-ish> [<path>...]\n");
            std.process.exit(129);
        } else if (std.mem.eql(u8, arg, "--cached") or std.mem.eql(u8, arg, "--staged")) {
            cached = true;
        } else if (std.mem.eql(u8, arg, "--exit-code")) {
            exit_code_flag = true;
        } else if (std.mem.eql(u8, arg, "-p") or std.mem.eql(u8, arg, "--patch")) {
            patch_mode = true;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--no-patch")) {
            suppress_output = true;
            patch_mode = false;
        } else if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) {
            suppress_output = true;
            exit_code_flag = true;
        } else if (std.mem.eql(u8, arg, "--name-status")) {
            name_status = true;
        } else if (std.mem.eql(u8, arg, "--name-only")) {
            name_only = true;
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_dashdash = true;
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (tree_ish == null) {
                tree_ish = arg;
            } else {
                try pathspecs.append(arg);
            }
        }
    }

    if (tree_ish == null) return;

    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    var idx = index_mod.Index.load(git_dir, platform_impl, allocator) catch return;
    defer idx.deinit();

    const tree_hash = resolveToTree(allocator, tree_ish.?, git_dir, platform_impl) catch return;
    defer allocator.free(tree_hash);

    var tree_entries = std.StringHashMap(TreeEntryInfo).init(allocator);
    defer {
        var kit = tree_entries.keyIterator();
        while (kit.next()) |k| allocator.free(k.*);
        tree_entries.deinit();
    }
    try walkTreeForDiffIndex(allocator, git_dir, tree_hash, "", &tree_entries, platform_impl);

    const zero_oid = "0000000000000000000000000000000000000000";
    var has_diffs = false;

    for (idx.entries.items) |entry| {
        if (pathspecs.items.len > 0) {
            var matches = false;
            for (pathspecs.items) |ps| {
                if (pathspecMatch(ps, entry.path)) {
                    matches = true;
                    break;
                }
            }
            if (!matches) continue;
        }

        if (tree_entries.get(entry.path)) |te| {
            if (!std.mem.eql(u8, &te.hash, &entry.sha1) or te.mode != entry.mode) {
                has_diffs = true;
                var old_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&te.hash}) catch unreachable;
                var new_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&new_hash_buf, "{x}", .{&entry.sha1}) catch unreachable;
                if (!suppress_output) {
                    const line = if (name_status)
                        try std.fmt.allocPrint(allocator, "M\t{s}\n", .{entry.path})
                    else if (name_only)
                        try std.fmt.allocPrint(allocator, "{s}\n", .{entry.path})
                    else
                        try std.fmt.allocPrint(allocator, ":{o:0>6} {o:0>6} {s} {s} M\t{s}\n", .{ te.mode, entry.mode, &old_hash_buf, &new_hash_buf, entry.path });
                    defer allocator.free(line);
                    try platform_impl.writeStdout(line);
                }
            }
        } else {
            has_diffs = true;
            if (!suppress_output) {
                var new_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&new_hash_buf, "{x}", .{&entry.sha1}) catch unreachable;
                const line = if (name_status)
                    try std.fmt.allocPrint(allocator, "A\t{s}\n", .{entry.path})
                else if (name_only)
                    try std.fmt.allocPrint(allocator, "{s}\n", .{entry.path})
                else
                    try std.fmt.allocPrint(allocator, ":000000 {o:0>6} {s} {s} A\t{s}\n", .{ entry.mode, zero_oid, &new_hash_buf, entry.path });
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            }
        }
    }

    var tree_it = tree_entries.iterator();
    while (tree_it.next()) |kv| {
        var found = false;
        for (idx.entries.items) |entry| {
            if (std.mem.eql(u8, entry.path, kv.key_ptr.*)) {
                found = true;
                break;
            }
        }
        if (!found) {
            if (pathspecs.items.len > 0) {
                var matches = false;
                for (pathspecs.items) |ps| {
                    if (pathspecMatch(ps, kv.key_ptr.*)) {
                        matches = true;
                        break;
                    }
                }
                if (!matches) continue;
            }
            has_diffs = true;
            if (!suppress_output) {
                var old_hash_buf: [40]u8 = undefined;
                _ = std.fmt.bufPrint(&old_hash_buf, "{x}", .{&kv.value_ptr.hash}) catch unreachable;
                const line = if (name_status)
                    try std.fmt.allocPrint(allocator, "D\t{s}\n", .{kv.key_ptr.*})
                else if (name_only)
                    try std.fmt.allocPrint(allocator, "{s}\n", .{kv.key_ptr.*})
                else
                    try std.fmt.allocPrint(allocator, ":{o:0>6} 000000 {s} {s} D\t{s}\n", .{ kv.value_ptr.mode, &old_hash_buf, zero_oid, kv.key_ptr.* });
                defer allocator.free(line);
                try platform_impl.writeStdout(line);
            }
        }
    }

    if (exit_code_flag and has_diffs) {
        std.process.exit(1);
    }
}

fn walkTreeForDiffIndex(allocator: std.mem.Allocator, git_dir: []const u8, tree_hash: []const u8, prefix: []const u8, entries: *std.StringHashMap(TreeEntryInfo), platform_impl: *const platform_mod.Platform) !void {
    const git_object = objects.GitObject.load(tree_hash, git_dir, platform_impl, allocator) catch return;
    defer git_object.deinit(allocator);
    if (git_object.type != .tree) return;

    var pos: usize = 0;
    while (pos < git_object.data.len) {
        const space_pos = std.mem.indexOfScalar(u8, git_object.data[pos..], ' ') orelse break;
        const mode_str = git_object.data[pos .. pos + space_pos];
        pos += space_pos + 1;
        const null_pos = std.mem.indexOfScalar(u8, git_object.data[pos..], 0) orelse break;
        const name = git_object.data[pos .. pos + null_pos];
        pos += null_pos + 1;
        if (pos + 20 > git_object.data.len) break;
        var hash: [20]u8 = undefined;
        @memcpy(&hash, git_object.data[pos .. pos + 20]);
        pos += 20;
        const mode = std.fmt.parseInt(u32, mode_str, 8) catch continue;
        const full_path = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);
        if ((mode & 0o170000) == 0o040000) {
            defer allocator.free(full_path);
            var sub_hash_hex: [40]u8 = undefined;
            _ = std.fmt.bufPrint(&sub_hash_hex, "{x}", .{&hash}) catch continue;
            try walkTreeForDiffIndex(allocator, git_dir, &sub_hash_hex, full_path, entries, platform_impl);
        } else {
            try entries.put(full_path, .{ .mode = mode, .hash = hash });
        }
    }
}

fn nativeCmdShowIndex(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    _ = args;
    _ = command_index;
    const allocator = std.heap.page_allocator;
    const stdin = std.fs.File{ .handle = std.posix.STDIN_FILENO };
    
    var header: [8]u8 = undefined;
    const nread = stdin.read(&header) catch {
        try platform_impl.writeStderr("fatal: unable to read pack index\n");
        std.process.exit(128);
    };
    if (nread < 8) {
        try platform_impl.writeStderr("fatal: unable to read pack index\n");
        std.process.exit(128);
    }
    
    const magic = std.mem.readInt(u32, header[0..4], .big);
    const version = std.mem.readInt(u32, header[4..8], .big);
    
    if (magic == 0xff744f63 and version == 2) {
        var fanout_bytes: [256 * 4]u8 = undefined;
        const fr = stdin.readAll(&fanout_bytes) catch {
            try platform_impl.writeStderr("fatal: unable to read fanout\n");
            std.process.exit(128);
        };
        if (fr < 256 * 4) {
            try platform_impl.writeStderr("fatal: truncated pack index\n");
            std.process.exit(128);
        }
        const num_objects = std.mem.readInt(u32, fanout_bytes[255 * 4 ..][0..4], .big);
        
        const hash_data = allocator.alloc(u8, num_objects * 20) catch {
            std.process.exit(128);
        };
        defer allocator.free(hash_data);
        _ = stdin.readAll(hash_data) catch {};
        
        const crc_data = allocator.alloc(u8, num_objects * 4) catch {
            std.process.exit(128);
        };
        defer allocator.free(crc_data);
        _ = stdin.readAll(crc_data) catch {};
        
        const offset_data = allocator.alloc(u8, num_objects * 4) catch {
            std.process.exit(128);
        };
        defer allocator.free(offset_data);
        _ = stdin.readAll(offset_data) catch {};
        
        var i: u32 = 0;
        while (i < num_objects) : (i += 1) {
            const offset = std.mem.readInt(u32, offset_data[i * 4 ..][0..4], .big);
            const hash_bytes = hash_data[i * 20 ..][0..20];
            var hash_hex: [40]u8 = undefined;
            for (hash_bytes, 0..) |b, j| {
                const hex_chars = "0123456789abcdef";
                hash_hex[j * 2] = hex_chars[b >> 4];
                hash_hex[j * 2 + 1] = hex_chars[b & 0xf];
            }
            const crc = std.mem.readInt(u32, crc_data[i * 4 ..][0..4], .big);
            const out = try std.fmt.allocPrint(allocator, "{d} {s} ({x:0>8})\n", .{ offset, hash_hex, crc });
            defer allocator.free(out);
            try platform_impl.writeStdout(out);
        }
    } else {
        try platform_impl.writeStderr("fatal: unsupported pack index version\n");
        std.process.exit(128);
    }
}

fn nativeCmdPrunePacked(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    _ = args;
    _ = command_index;
    const allocator = std.heap.page_allocator;
    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    const objects_dir = try std.fmt.allocPrint(allocator, "{s}/objects", .{git_path});
    defer allocator.free(objects_dir);
    const pack_dir = try std.fmt.allocPrint(allocator, "{s}/pack", .{objects_dir});
    defer allocator.free(pack_dir);
    
    // Collect packed object hashes from idx files
    var packed_objs = std.StringHashMap(void).init(allocator);
    defer {
        var kit = packed_objs.keyIterator();
        while (kit.next()) |key| allocator.free(@constCast(key.*));
        packed_objs.deinit();
    }
    
    if (std.fs.cwd().openDir(pack_dir, .{ .iterate = true })) |*dir| {
        defer @constCast(dir).close();
        var diter = dir.iterate();
        while (diter.next() catch null) |entry| {
            if (std.mem.endsWith(u8, entry.name, ".idx")) {
                const idx_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ pack_dir, entry.name });
                defer allocator.free(idx_path);
                const idx_data = platform_impl.fs.readFile(allocator, idx_path) catch continue;
                defer allocator.free(idx_data);
                if (idx_data.len < 8 + 256 * 4) continue;
                const idx_magic = std.mem.readInt(u32, idx_data[0..4], .big);
                const idx_ver = std.mem.readInt(u32, idx_data[4..8], .big);
                if (idx_magic != 0xff744f63 or idx_ver != 2) continue;
                const n = std.mem.readInt(u32, idx_data[8 + 255 * 4 ..][0..4], .big);
                const hash_start: usize = 8 + 256 * 4;
                var oi: u32 = 0;
                while (oi < n) : (oi += 1) {
                    const off = hash_start + oi * 20;
                    if (off + 20 > idx_data.len) break;
                    var hex: [40]u8 = undefined;
                    for (idx_data[off..][0..20], 0..) |b, j| {
                        const hc = "0123456789abcdef";
                        hex[j * 2] = hc[b >> 4];
                        hex[j * 2 + 1] = hc[b & 0xf];
                    }
                    const key = allocator.dupe(u8, &hex) catch continue;
                    packed_objs.put(key, {}) catch {};
                }
            }
        }
    } else |_| {}
    
    // Remove loose objects that are in packs
    for (0..256) |pv| {
        const ph = try std.fmt.allocPrint(allocator, "{x:0>2}", .{pv});
        defer allocator.free(ph);
        const ld = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ objects_dir, ph });
        defer allocator.free(ld);
        if (std.fs.cwd().openDir(ld, .{ .iterate = true })) |*dir| {
            defer @constCast(dir).close();
            var diter = dir.iterate();
            while (diter.next() catch null) |entry| {
                if (entry.name.len == 38) {
                    const fh = try std.fmt.allocPrint(allocator, "{s}{s}", .{ ph, entry.name });
                    defer allocator.free(fh);
                    if (packed_objs.contains(fh)) {
                        const fp = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ ld, entry.name });
                        defer allocator.free(fp);
                        std.fs.cwd().deleteFile(fp) catch {};
                    }
                }
            }
        } else |_| {}
    }
}

fn nativeCmdVerifyCommit(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    const allocator = std.heap.page_allocator;
    const rest = args[command_index + 1 ..];
    
    for (rest) |arg| {
        if (arg.len > 0 and arg[0] == '-') continue;
        
        const git_path = findGitDirectory(allocator, platform_impl) catch {
            try platform_impl.writeStderr("fatal: not a git repository\n");
            std.process.exit(128);
        };
        defer allocator.free(git_path);
        
        const hash = resolveRevision(git_path, arg, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "error: {s}: no such commit\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };
        defer allocator.free(hash);
        
        const obj = objects.GitObject.load(hash, git_path, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "error: {s}: cannot read object\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };
        defer obj.deinit(allocator);
        
        if (std.mem.indexOf(u8, obj.data, "gpgsig ") == null) {
            try platform_impl.writeStderr("error: no signature found\n");
            std.process.exit(1);
        }
    }
}

fn nativeCmdVerifyTag(_: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    const allocator = std.heap.page_allocator;
    const rest = args[command_index + 1 ..];
    
    for (rest) |arg| {
        if (arg.len > 0 and arg[0] == '-') continue;
        
        const git_path = findGitDirectory(allocator, platform_impl) catch {
            try platform_impl.writeStderr("fatal: not a git repository\n");
            std.process.exit(128);
        };
        defer allocator.free(git_path);
        
        const ref_str = try std.fmt.allocPrint(allocator, "refs/tags/{s}", .{arg});
        defer allocator.free(ref_str);
        
        const tag_hash_opt = refs.resolveRef(git_path, ref_str, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "error: {s}: no such tag\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };
        const tag_hash = tag_hash_opt orelse {
            const msg = try std.fmt.allocPrint(allocator, "error: {s}: no such tag\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };
        defer allocator.free(tag_hash);
        
        const obj = objects.GitObject.load(tag_hash, git_path, platform_impl, allocator) catch {
            const msg = try std.fmt.allocPrint(allocator, "error: {s}: cannot read tag\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        };
        defer obj.deinit(allocator);
        
        if (obj.type != .tag) {
            const msg = try std.fmt.allocPrint(allocator, "error: {s}: cannot verify a non-tag object\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(1);
        }
        
        if (std.mem.indexOf(u8, obj.data, "-----BEGIN") == null) {
            try platform_impl.writeStderr("error: no signature found\n");
            std.process.exit(1);
        }
    }
}

fn nativeCmdBisect(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    const subcmd = args.next() orelse {
        try platform_impl.writeStdout("usage: git bisect [help|start|bad|good|new|old|terms|skip|next|reset|visualize|view|replay|log|run]\n");
        std.process.exit(1);
    };
    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    const bisect_log_path = try std.fmt.allocPrint(allocator, "{s}/BISECT_LOG", .{git_path});
    defer allocator.free(bisect_log_path);
    const bisect_start_path = try std.fmt.allocPrint(allocator, "{s}/BISECT_START", .{git_path});
    defer allocator.free(bisect_start_path);
    
    if (std.mem.eql(u8, subcmd, "help")) {
        try platform_impl.writeStdout("usage: git bisect [help|start|bad|good|new|old|terms|skip|next|reset|visualize|view|replay|log|run]\n");
    } else if (std.mem.eql(u8, subcmd, "start")) {
        // Start bisect session
        // Write BISECT_START
        try platform_impl.fs.writeFile(bisect_start_path, "");
        // Clear bisect log
        try platform_impl.fs.writeFile(bisect_log_path, "# git bisect start\n");
        
        // Parse optional arguments: [--term-new=X] [--term-old=X] [bad [good...]] [--]
        var positional_refs = std.array_list.Managed([]const u8).init(allocator);
        defer positional_refs.deinit();
        while (args.next()) |start_arg| {
            if (std.mem.startsWith(u8, start_arg, "--term-new=") or std.mem.startsWith(u8, start_arg, "--term-old=") or
                std.mem.eql(u8, start_arg, "--term-new") or std.mem.eql(u8, start_arg, "--term-old") or
                std.mem.eql(u8, start_arg, "--no-checkout") or std.mem.eql(u8, start_arg, "--first-parent"))
            {
                // Skip term options (consume value if separate)
                if (std.mem.eql(u8, start_arg, "--term-new") or std.mem.eql(u8, start_arg, "--term-old")) {
                    _ = args.next();
                }
            } else if (std.mem.eql(u8, start_arg, "--")) {
                break;
            } else {
                try positional_refs.append(start_arg);
            }
        }
        
        // Check for optional bad/good refs from positional args
        if (positional_refs.items.len > 0) {
            const bad_ref = positional_refs.items[0];
            const hash = resolveRevision(git_path, bad_ref, platform_impl, allocator) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{bad_ref});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            };
            defer allocator.free(hash);
            
            // Write BISECT_BAD
            const bad_path = try std.fmt.allocPrint(allocator, "{s}/refs/bisect/bad", .{git_path});
            defer allocator.free(bad_path);
            
            // Create refs/bisect directory
            const bisect_dir = try std.fmt.allocPrint(allocator, "{s}/refs/bisect", .{git_path});
            defer allocator.free(bisect_dir);
            std.fs.cwd().makePath(bisect_dir) catch {};
            
            const hash_nl = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
            defer allocator.free(hash_nl);
            try platform_impl.fs.writeFile(bad_path, hash_nl);
            
            // Handle good refs (remaining positional args)
            for (positional_refs.items[1..]) |good_ref| {
                const good_hash = resolveRevision(git_path, good_ref, platform_impl, allocator) catch continue;
                defer allocator.free(good_hash);
                
                // Write good ref
                const good_path = try std.fmt.allocPrint(allocator, "{s}/refs/bisect/good-{s}", .{git_path, good_hash});
                defer allocator.free(good_path);
                const good_hash_nl = try std.fmt.allocPrint(allocator, "{s}\n", .{good_hash});
                defer allocator.free(good_hash_nl);
                try platform_impl.fs.writeFile(good_path, good_hash_nl);
            }
        }
        
        try platform_impl.writeStderr("status: waiting for both good and bad commits\n");
    } else if (std.mem.eql(u8, subcmd, "bad") or std.mem.eql(u8, subcmd, "new")) {
        const rev = args.next() orelse "HEAD";
        const hash = resolveRevision(git_path, rev, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: bad revision\n");
            std.process.exit(128);
        };
        defer allocator.free(hash);
        
        const bisect_dir = try std.fmt.allocPrint(allocator, "{s}/refs/bisect", .{git_path});
        defer allocator.free(bisect_dir);
        std.fs.cwd().makePath(bisect_dir) catch {};
        
        const bad_path = try std.fmt.allocPrint(allocator, "{s}/refs/bisect/bad", .{git_path});
        defer allocator.free(bad_path);
        const hash_nl = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
        defer allocator.free(hash_nl);
        try platform_impl.fs.writeFile(bad_path, hash_nl);
    } else if (std.mem.eql(u8, subcmd, "good") or std.mem.eql(u8, subcmd, "old")) {
        const rev = args.next() orelse "HEAD";
        const hash = resolveRevision(git_path, rev, platform_impl, allocator) catch {
            try platform_impl.writeStderr("fatal: bad revision\n");
            std.process.exit(128);
        };
        defer allocator.free(hash);
        
        const bisect_dir = try std.fmt.allocPrint(allocator, "{s}/refs/bisect", .{git_path});
        defer allocator.free(bisect_dir);
        std.fs.cwd().makePath(bisect_dir) catch {};
        
        // Write good-<hash> ref
        const good_path = try std.fmt.allocPrint(allocator, "{s}/refs/bisect/good-{s}", .{ git_path, hash });
        defer allocator.free(good_path);
        const hash_nl = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
        defer allocator.free(hash_nl);
        try platform_impl.fs.writeFile(good_path, hash_nl);
    } else if (std.mem.eql(u8, subcmd, "reset")) {
        // Clean up bisect state
        std.fs.cwd().deleteFile(bisect_log_path) catch {};
        std.fs.cwd().deleteFile(bisect_start_path) catch {};
        const bisect_dir = try std.fmt.allocPrint(allocator, "{s}/refs/bisect", .{git_path});
        defer allocator.free(bisect_dir);
        std.fs.cwd().deleteTree(bisect_dir) catch {};
        
        // Also clean BISECT_EXPECTED_REV, BISECT_HEAD, etc.
        const be = try std.fmt.allocPrint(allocator, "{s}/BISECT_EXPECTED_REV", .{git_path});
        defer allocator.free(be);
        std.fs.cwd().deleteFile(be) catch {};
        const bh = try std.fmt.allocPrint(allocator, "{s}/BISECT_HEAD", .{git_path});
        defer allocator.free(bh);
        std.fs.cwd().deleteFile(bh) catch {};
        
        try platform_impl.writeStdout("Previous HEAD position was...\n");
    } else if (std.mem.eql(u8, subcmd, "log")) {
        const log_data = platform_impl.fs.readFile(allocator, bisect_log_path) catch {
            try platform_impl.writeStderr("We are not bisecting.\n");
            std.process.exit(1);
        };
        defer allocator.free(log_data);
        try platform_impl.writeStdout(log_data);
    } else {
        const msg = try std.fmt.allocPrint(allocator, "error: unknown bisect subcommand '{s}'\n", .{subcmd});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(1);
    }
}

fn nativeCmdMv(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var force = false;
    var dry_run = false;
    var skip_errors = false;
    var verbose = false;
    var sources = std.array_list.Managed([]const u8).init(allocator);
    defer sources.deinit();
    
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--force")) {
            force = true;
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.eql(u8, arg, "--dry-run")) {
            dry_run = true;
        } else if (std.mem.eql(u8, arg, "-k")) {
            skip_errors = true;
        } else if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "--")) {
            while (args.next()) |a| try sources.append(a);
            break;
        } else {
            try sources.append(arg);
        }
    }
    
    if (sources.items.len < 2) {
        try platform_impl.writeStderr("usage: git mv [<options>] <source>... <destination>\n");
        std.process.exit(128);
    }
    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    const dest = sources.items[sources.items.len - 1];
    const srcs = sources.items[0 .. sources.items.len - 1];
    
    // Load index
    var index = index_mod.Index.load(git_path, platform_impl, allocator) catch |err| switch (err) {
        error.FileNotFound => index_mod.Index.init(allocator),
        else => return err,
    };
    defer index.deinit();
    
    // Check if dest is a directory
    const dest_is_dir = if (std.fs.cwd().statFile(dest)) |stat|
        stat.kind == .directory
    else |_|
        false;
    
    if (srcs.len > 1 and !dest_is_dir) {
        try platform_impl.writeStderr("fatal: destination is not a directory\n");
        std.process.exit(128);
    }
    
    for (srcs) |src| {
        const target = if (dest_is_dir) blk: {
            const basename = std.fs.path.basename(src);
            break :blk try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dest, basename });
        } else try allocator.dupe(u8, dest);
        defer allocator.free(target);
        
        // Check source exists
        if (!(std.fs.cwd().statFile(src) catch null != null)) {
            if (skip_errors) continue;
            const msg = try std.fmt.allocPrint(allocator, "fatal: bad source, source={s}, destination={s}\n", .{ src, target });
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        }
        
        // Check target doesn't exist (unless -f or case-change rename)
        if (!force) {
            if ((std.fs.cwd().statFile(target) catch null) != null) {
                // Allow case-change rename: same name different case
                const is_case_change = std.ascii.eqlIgnoreCase(src, target) and !std.mem.eql(u8, src, target);
                if (!is_case_change) {
                    if (skip_errors) continue;
                    const msg = try std.fmt.allocPrint(allocator, "fatal: destination exists, source={s}, destination={s}\n", .{ src, target });
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                }
            }
        }
        
        if (!dry_run) {
            // Move the file
            std.fs.cwd().rename(src, target) catch |err| {
                if (skip_errors) continue;
                const msg = try std.fmt.allocPrint(allocator, "fatal: renaming '{s}' failed: {}\n", .{ src, err });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            };
            
            // Update index: remove old entry, add new entry
            var new_entries = std.array_list.Managed(index_mod.IndexEntry).init(allocator);
            defer new_entries.deinit();
            
            for (index.entries.items) |entry| {
                if (std.mem.eql(u8, entry.path, src)) {
                    var new_entry = entry;
                    new_entry.path = try allocator.dupe(u8, target);
                    // Update flags to reflect new path length (lower 12 bits)
                    const path_len_bits: u16 = if (target.len >= 0xFFF) 0xFFF else @intCast(target.len);
                    new_entry.flags = (entry.flags & 0xF000) | path_len_bits;
                    try new_entries.append(new_entry);
                } else {
                    try new_entries.append(entry);
                }
            }
            index.entries.clearRetainingCapacity();
            for (new_entries.items) |e| try index.entries.append(e);
        }
        
        if (verbose or dry_run) {
            const msg = try std.fmt.allocPrint(allocator, "Renaming {s} to {s}\n", .{ src, target });
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    }
    
    if (!dry_run) {
        index.save(git_path, platform_impl) catch {};
    }
}

fn nativeCmdStash(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    const subcmd = args.next() orelse "push";
    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    if (std.mem.eql(u8, subcmd, "list")) {
        // List stash entries
        const stash_log = try std.fmt.allocPrint(allocator, "{s}/refs/stash", .{git_path});
        defer allocator.free(stash_log);
        _ = platform_impl.fs.readFile(allocator, stash_log) catch {
            // No stash entries - exit silently
            return;
        };
        // TODO: parse reflog to show stash entries
    } else if (std.mem.eql(u8, subcmd, "push") or std.mem.eql(u8, subcmd, "save")) {
        // Stub: stash push requires saving working tree and index state as commits
        try platform_impl.writeStderr("error: stash push not yet fully implemented natively\n");
        std.process.exit(1);
    } else if (std.mem.eql(u8, subcmd, "pop") or std.mem.eql(u8, subcmd, "apply")) {
        try platform_impl.writeStderr("error: stash pop/apply not yet fully implemented natively\n");
        std.process.exit(1);
    } else if (std.mem.eql(u8, subcmd, "drop")) {
        try platform_impl.writeStderr("error: stash drop not yet fully implemented natively\n");
        std.process.exit(1);
    } else if (std.mem.eql(u8, subcmd, "clear")) {
        // Delete stash ref
        const stash_ref = try std.fmt.allocPrint(allocator, "{s}/refs/stash", .{git_path});
        defer allocator.free(stash_ref);
        std.fs.cwd().deleteFile(stash_ref) catch {};
        const stash_log = try std.fmt.allocPrint(allocator, "{s}/logs/refs/stash", .{git_path});
        defer allocator.free(stash_log);
        std.fs.cwd().deleteFile(stash_log) catch {};
    } else if (std.mem.eql(u8, subcmd, "show")) {
        try platform_impl.writeStderr("error: stash show not yet fully implemented natively\n");
        std.process.exit(1);
    } else {
        const msg = try std.fmt.allocPrint(allocator, "error: unknown stash subcommand '{s}'\n", .{subcmd});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(1);
    }
}

fn nativeCmdApply(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var check_only = false;
    var stat_only = false;
    var summary_only = false;
    var numstat_flag = false;
    var reverse = false;
    var cached = false;
    var index_flag = false;
    var apply_flag = true; // default is to apply
    var recount = false;
    var allow_empty = false;
    var verbose = false;
    var p_value: u32 = 1;
    var patch_files = std.array_list.Managed([]const u8).init(allocator);
    defer patch_files.deinit();

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--check")) {
            check_only = true;
        } else if (std.mem.eql(u8, arg, "--stat")) {
            stat_only = true;
            apply_flag = false;
        } else if (std.mem.eql(u8, arg, "--summary")) {
            summary_only = true;
            apply_flag = false;
        } else if (std.mem.eql(u8, arg, "--numstat")) {
            numstat_flag = true;
            apply_flag = false;
        } else if (std.mem.eql(u8, arg, "-R") or std.mem.eql(u8, arg, "--reverse")) {
            reverse = true;
        } else if (std.mem.eql(u8, arg, "--cached")) {
            cached = true;
        } else if (std.mem.eql(u8, arg, "--index")) {
            index_flag = true;
        } else if (std.mem.eql(u8, arg, "--apply")) {
            apply_flag = true;
        } else if (std.mem.eql(u8, arg, "--recount")) {
            recount = true;
        } else if (std.mem.eql(u8, arg, "--allow-empty")) {
            allow_empty = true;
        } else if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.startsWith(u8, arg, "-p")) {
            if (arg.len > 2) {
                p_value = std.fmt.parseInt(u32, arg[2..], 10) catch 1;
            } else if (args.next()) |next| {
                p_value = std.fmt.parseInt(u32, next, 10) catch 1;
            }
        } else if (std.mem.eql(u8, arg, "--no-add") or
            std.mem.eql(u8, arg, "--binary") or
            std.mem.eql(u8, arg, "--3way") or std.mem.eql(u8, arg, "-3") or
            std.mem.eql(u8, arg, "--reject") or
            std.mem.eql(u8, arg, "--unidiff-zero") or
            std.mem.eql(u8, arg, "--allow-overlap") or
            std.mem.eql(u8, arg, "--inaccurate-eof") or
            std.mem.eql(u8, arg, "--unsafe-paths"))
        {
            // Accept known flags
        } else if (std.mem.startsWith(u8, arg, "--whitespace=") or
            std.mem.startsWith(u8, arg, "--directory=") or
            std.mem.startsWith(u8, arg, "--exclude=") or
            std.mem.startsWith(u8, arg, "--include="))
        {
            // Accept known flags with values
        } else if (std.mem.eql(u8, arg, "--whitespace") or
            std.mem.eql(u8, arg, "--directory") or
            std.mem.eql(u8, arg, "--exclude") or
            std.mem.eql(u8, arg, "--include"))
        {
            _ = args.next();
        } else if (std.mem.eql(u8, arg, "-")) {
            // Read from stdin
            try patch_files.append("-");
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try patch_files.append(arg);
        }
    }

    _ = &cached;
    _ = &index_flag;
    _ = &recount;

    // Read patch content
    var all_patch_data = std.array_list.Managed(u8).init(allocator);
    defer all_patch_data.deinit();

    if (patch_files.items.len == 0) {
        // Read from stdin
        const stdin_data = readStdin(allocator, 100 * 1024 * 1024) catch |err| {
            const msg = try std.fmt.allocPrint(allocator, "error: reading stdin: {}\n", .{err});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        };
        defer allocator.free(stdin_data);
        try all_patch_data.appendSlice(stdin_data);
    } else {
        for (patch_files.items) |pf| {
            if (std.mem.eql(u8, pf, "-")) {
                const stdin_data = readStdin(allocator, 100 * 1024 * 1024) catch continue;
                defer allocator.free(stdin_data);
                try all_patch_data.appendSlice(stdin_data);
            } else {
                const data = platform_impl.fs.readFile(allocator, pf) catch |err| {
                    const msg = try std.fmt.allocPrint(allocator, "error: can't open patch '{s}': {}\n", .{ pf, err });
                    defer allocator.free(msg);
                    try platform_impl.writeStderr(msg);
                    std.process.exit(128);
                };
                defer allocator.free(data);
                try all_patch_data.appendSlice(data);
            }
        }
    }

    // Parse patches
    var corrupt_line: usize = 0;
    var patches = parsePatchSet(allocator, all_patch_data.items, p_value, &corrupt_line) catch |err| {
        if (err == error.InvalidPatch) {
            try platform_impl.writeStderr("error: invalid combination in patch header\n");
            std.process.exit(128);
        }
        if (err == error.CorruptPatch) {
            const msg = try std.fmt.allocPrint(allocator, "error: corrupt patch at line {d}\n", .{corrupt_line});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        }
        const msg = try std.fmt.allocPrint(allocator, "error: patch parsing failed: {}\n", .{err});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(128);
    };
    defer {
        for (patches.items) |*p| p.deinit(allocator);
        patches.deinit();
    }

    if (patches.items.len == 0 and !stat_only and !numstat_flag and !summary_only) {
        if (allow_empty) return; // --allow-empty: empty patch is OK
        // No patches found - could be unrecognized input
        try platform_impl.writeStderr("error: unrecognized input\n");
        std.process.exit(128);
    }

    // Validate patches
    for (patches.items) |*p| {
        // Check for invalid combinations
        if (p.is_new_file) {
            // new file + copy/rename is invalid - check if it was parsed as such
            // (handled during parsing but verify here for edge cases)
        }

        // Check for no-op patches (only context, no adds/removes) unless --recount
        if (!recount) {
            var has_changes = false;
            for (p.hunks.items) |h| {
                for (h.lines.items) |l| {
                    if (l.line_type == .add or l.line_type == .remove) {
                        has_changes = true;
                        break;
                    }
                }
                if (has_changes) break;
            }
            if (!has_changes and p.hunks.items.len > 0 and !p.is_new_file and !p.is_delete) {
                const path = p.new_path orelse p.old_path orelse "unknown";
                const msg = try std.fmt.allocPrint(allocator, "error: No changes in patch for {s}\n", .{path});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(128);
            }
        }
    }

    // Handle stat/numstat/summary output modes (collect all then output)
    if (stat_only or numstat_flag or summary_only) {
        if (stat_only) {
            try outputAllPatchStats(allocator, patches.items, platform_impl);
        }
        if (numstat_flag) {
            for (patches.items) |*patch| {
                try outputPatchNumstat(allocator, patch, platform_impl);
            }
        }
        if (summary_only or stat_only) {
            for (patches.items) |*patch| {
                try outputPatchSummary(allocator, patch, platform_impl);
            }
        }
        return;
    }

    // Apply or check each patch
    for (patches.items) |*patch| {

        if (check_only) {
            // Just verify the patch can apply
            _ = applyOnePatch(allocator, patch, reverse, true, platform_impl) catch |err| {
                if (err == error.PatchAlreadyApplied and recount) {
                    // --recount allows no-op patches
                    continue;
                }
                const msg = try std.fmt.allocPrint(allocator, "error: patch failed: {s}: {}\n", .{ patch.new_path orelse patch.old_path orelse "unknown", err });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            };
        } else if (apply_flag) {
            _ = applyOnePatch(allocator, patch, reverse, false, platform_impl) catch |err| {
                const msg = try std.fmt.allocPrint(allocator, "error: patch failed: {s}: {}\n", .{ patch.new_path orelse patch.old_path orelse "unknown", err });
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            };
            if (verbose) {
                const path = patch.new_path orelse patch.old_path orelse "unknown";
                const msg = try std.fmt.allocPrint(allocator, "Applying: {s}\n", .{path});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
            }
        }
    }
}

const PatchHunk = struct {
    old_start: u32,
    old_count: u32,
    new_start: u32,
    new_count: u32,
    lines: std.array_list.Managed(PatchLine),

    fn deinit(self: *PatchHunk, alloc: std.mem.Allocator) void {
        for (self.lines.items) |*l| l.deinit(alloc);
        self.lines.deinit();
    }
};

const PatchLineType = enum { context, add, remove };

const PatchLine = struct {
    line_type: PatchLineType,
    content: []const u8,
    no_newline: bool = false, // "\ No newline at end of file" follows this line

    fn deinit(self: *PatchLine, alloc: std.mem.Allocator) void {
        alloc.free(self.content);
    }
};

const Patch = struct {
    old_path: ?[]const u8,
    new_path: ?[]const u8,
    is_new_file: bool,
    is_delete: bool,
    new_mode: ?u32,
    old_mode: ?u32,
    is_binary: bool,
    is_rename: bool = false,
    is_copy: bool = false,
    is_rewrite: bool = false,
    similarity: ?u32 = null, // similarity index percentage
    dissimilarity: ?u32 = null, // dissimilarity index percentage
    hunks: std.array_list.Managed(PatchHunk),
    added: u32,
    removed: u32,

    fn deinit(self: *Patch, alloc: std.mem.Allocator) void {
        if (self.old_path) |p| alloc.free(p);
        if (self.new_path) |p| alloc.free(p);
        for (self.hunks.items) |*h| h.deinit(alloc);
        self.hunks.deinit();
    }
};

fn parsePatchSet(allocator: std.mem.Allocator, data: []const u8, p_value: u32, corrupt_line: *usize) !std.array_list.Managed(Patch) {
    var patches = std.array_list.Managed(Patch).init(allocator);
    var lines_iter = std.mem.splitScalar(u8, data, '\n');
    var lines = std.array_list.Managed([]const u8).init(allocator);
    defer lines.deinit();
    while (lines_iter.next()) |line| try lines.append(line);

    var i: usize = 0;
    while (i < lines.items.len) {
        // Look for "diff --git" or "---" header
        const line = lines.items[i];
        if (std.mem.startsWith(u8, line, "diff --git ") or std.mem.startsWith(u8, line, "diff -")) {
            const saved_i = i;
            var patch = parseSinglePatch(allocator, lines.items, &i, p_value) catch |err| {
                if (err == error.CorruptPatch) {
                    corrupt_line.* = i + 1; // 1-indexed
                }
                return err;
            };
            _ = saved_i;
            _ = &patch;
            try patches.append(patch);
        } else if (std.mem.startsWith(u8, line, "--- ") and i + 1 < lines.items.len and std.mem.startsWith(u8, lines.items[i + 1], "+++ ")) {
            // Traditional diff format without "diff --git" header
            var patch = parseTraditionalPatch(allocator, lines.items, &i, p_value) catch |err| {
                if (err == error.CorruptPatch) {
                    corrupt_line.* = i + 1;
                }
                return err;
            };
            _ = &patch;
            try patches.append(patch);
        } else {
            i += 1;
        }
    }
    return patches;
}

fn stripPath(path: []const u8, p_value: u32) []const u8 {
    var result = path;
    var strips: u32 = 0;
    while (strips < p_value) {
        if (std.mem.indexOf(u8, result, "/")) |slash| {
            result = result[slash + 1 ..];
            strips += 1;
        } else break;
    }
    return result;
}

fn parseSinglePatch(allocator: std.mem.Allocator, lines: []const []const u8, pos: *usize, p_value: u32) !Patch {
    var patch = Patch{
        .old_path = null,
        .new_path = null,
        .is_new_file = false,
        .is_delete = false,
        .new_mode = null,
        .old_mode = null,
        .is_binary = false,
        .hunks = std.array_list.Managed(PatchHunk).init(allocator),
        .added = 0,
        .removed = 0,
    };

    // Parse "diff --git a/path b/path"
    const diff_line = lines[pos.*];
    if (std.mem.startsWith(u8, diff_line, "diff --git ")) {
        const rest = diff_line["diff --git ".len..];
        // Find the separator " b/" - tricky because paths can have spaces
        if (std.mem.indexOf(u8, rest, " b/")) |bpos| {
            const a_path = rest[0..bpos];
            const b_path = rest[bpos + 1 ..];
            patch.old_path = try allocator.dupe(u8, stripPath(a_path, p_value));
            patch.new_path = try allocator.dupe(u8, stripPath(b_path, p_value));
        }
    }
    pos.* += 1;

    // Parse extended header lines
    while (pos.* < lines.len) {
        const line = lines[pos.*];
        if (std.mem.startsWith(u8, line, "new file mode ")) {
            patch.is_new_file = true;
            patch.new_mode = std.fmt.parseInt(u32, std.mem.trim(u8, line["new file mode ".len..], " \t\r"), 8) catch null;
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "deleted file mode ")) {
            patch.is_delete = true;
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "old mode ")) {
            patch.old_mode = std.fmt.parseInt(u32, std.mem.trim(u8, line["old mode ".len..], " \t\r"), 8) catch null;
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "new mode ")) {
            patch.new_mode = std.fmt.parseInt(u32, std.mem.trim(u8, line["new mode ".len..], " \t\r"), 8) catch null;
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "index ")) {
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "similarity index") or
            std.mem.startsWith(u8, line, "dissimilarity index") or
            std.mem.startsWith(u8, line, "rename from ") or
            std.mem.startsWith(u8, line, "rename to ") or
            std.mem.startsWith(u8, line, "copy from ") or
            std.mem.startsWith(u8, line, "copy to "))
        {
            // Detect invalid combination: new file + copy/rename
            if (patch.is_new_file and (std.mem.startsWith(u8, line, "rename from ") or
                std.mem.startsWith(u8, line, "copy from ") or
                std.mem.startsWith(u8, line, "rename to ") or
                std.mem.startsWith(u8, line, "copy to ")))
            {
                return error.InvalidPatch;
            }
            if (std.mem.startsWith(u8, line, "rename from ")) {
                patch.is_rename = true;
            } else if (std.mem.startsWith(u8, line, "copy from ")) {
                patch.is_copy = true;
            } else if (std.mem.startsWith(u8, line, "similarity index ")) {
                const pct = std.mem.trim(u8, line["similarity index ".len..], " \t\r%");
                patch.similarity = std.fmt.parseInt(u32, pct, 10) catch null;
            } else if (std.mem.startsWith(u8, line, "dissimilarity index ")) {
                const pct = std.mem.trim(u8, line["dissimilarity index ".len..], " \t\r%");
                patch.dissimilarity = std.fmt.parseInt(u32, pct, 10) catch null;
                patch.is_rewrite = true;
            }
            if (std.mem.startsWith(u8, line, "rename to ") or std.mem.startsWith(u8, line, "copy to ")) {
                const new_name = std.mem.trim(u8, line[std.mem.indexOf(u8, line, " to ").? + 4 ..], " \t\r");
                if (patch.new_path) |p| allocator.free(p);
                patch.new_path = try allocator.dupe(u8, new_name);
            }
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "Binary files") or std.mem.startsWith(u8, line, "GIT binary patch")) {
            patch.is_binary = true;
            pos.* += 1;
            // Skip binary content
            while (pos.* < lines.len and !std.mem.startsWith(u8, lines[pos.*], "diff --git ")) {
                pos.* += 1;
            }
            break;
        } else if (std.mem.startsWith(u8, line, "--- ")) {
            // Start of actual diff content
            break;
        } else if (std.mem.startsWith(u8, line, "diff --git ")) {
            // Next patch
            break;
        } else {
            pos.* += 1;
        }
    }

    // Parse --- and +++ lines
    if (pos.* < lines.len and std.mem.startsWith(u8, lines[pos.*], "--- ")) {
        const old_line = lines[pos.*]["--- ".len..];
        if (!std.mem.eql(u8, old_line, "/dev/null")) {
            const stripped = stripPath(old_line, p_value);
            if (patch.old_path == null) {
                patch.old_path = try allocator.dupe(u8, stripped);
            }
        }
        pos.* += 1;
    }
    if (pos.* < lines.len and std.mem.startsWith(u8, lines[pos.*], "+++ ")) {
        const new_line = lines[pos.*]["+++ ".len..];
        if (!std.mem.eql(u8, new_line, "/dev/null")) {
            const stripped = stripPath(new_line, p_value);
            if (patch.new_path) |p| allocator.free(p);
            patch.new_path = try allocator.dupe(u8, stripped);
        }
        pos.* += 1;
    }

    // Parse hunks
    while (pos.* < lines.len) {
        const line = lines[pos.*];
        if (std.mem.startsWith(u8, line, "@@ ")) {
            const hunk = try parseHunk(allocator, lines, pos);
            patch.added += hunk.new_count;
            patch.removed += hunk.old_count;
            try patch.hunks.append(hunk);
        } else if (std.mem.startsWith(u8, line, "diff --git ")) {
            break;
        } else {
            pos.* += 1;
        }
    }

    return patch;
}

fn parseTraditionalPatch(allocator: std.mem.Allocator, lines: []const []const u8, pos: *usize, p_value: u32) !Patch {
    var patch = Patch{
        .old_path = null,
        .new_path = null,
        .is_new_file = false,
        .is_delete = false,
        .new_mode = null,
        .old_mode = null,
        .is_binary = false,
        .hunks = std.array_list.Managed(PatchHunk).init(allocator),
        .added = 0,
        .removed = 0,
    };

    // Parse --- line
    if (pos.* < lines.len and std.mem.startsWith(u8, lines[pos.*], "--- ")) {
        const old_line = lines[pos.*]["--- ".len..];
        if (!std.mem.eql(u8, old_line, "/dev/null")) {
            patch.old_path = try allocator.dupe(u8, stripPath(old_line, p_value));
        } else {
            patch.is_new_file = true;
        }
        pos.* += 1;
    }
    if (pos.* < lines.len and std.mem.startsWith(u8, lines[pos.*], "+++ ")) {
        const new_line = lines[pos.*]["+++ ".len..];
        if (!std.mem.eql(u8, new_line, "/dev/null")) {
            patch.new_path = try allocator.dupe(u8, stripPath(new_line, p_value));
        } else {
            patch.is_delete = true;
        }
        pos.* += 1;
    }

    // Parse hunks
    while (pos.* < lines.len) {
        const line = lines[pos.*];
        if (std.mem.startsWith(u8, line, "@@ ")) {
            const hunk = try parseHunk(allocator, lines, pos);
            patch.added += hunk.new_count;
            patch.removed += hunk.old_count;
            try patch.hunks.append(hunk);
        } else if (std.mem.startsWith(u8, line, "diff ") or
            std.mem.startsWith(u8, line, "--- "))
        {
            break;
        } else {
            pos.* += 1;
        }
    }

    return patch;
}

fn parseHunk(allocator: std.mem.Allocator, lines: []const []const u8, pos: *usize) !PatchHunk {
    const header = lines[pos.*];
    // Parse @@ -old_start,old_count +new_start,new_count @@
    var old_start: u32 = 1;
    var old_count: u32 = 1;
    var new_start: u32 = 1;
    var new_count: u32 = 1;

    if (std.mem.indexOf(u8, header, "-")) |minus_pos| {
        const after_minus = header[minus_pos + 1 ..];
        if (std.mem.indexOf(u8, after_minus, " +")) |plus_pos| {
            const old_part = after_minus[0..plus_pos];
            if (std.mem.indexOf(u8, old_part, ",")) |comma| {
                old_start = std.fmt.parseInt(u32, old_part[0..comma], 10) catch return error.CorruptPatch;
                old_count = std.fmt.parseInt(u32, old_part[comma + 1 ..], 10) catch return error.CorruptPatch;
            } else {
                old_start = std.fmt.parseInt(u32, old_part, 10) catch return error.CorruptPatch;
                old_count = 1;
            }
            const after_plus = after_minus[plus_pos + 2 ..];
            const new_end = std.mem.indexOf(u8, after_plus, " ") orelse std.mem.indexOf(u8, after_plus, "@") orelse after_plus.len;
            const new_part = after_plus[0..new_end];
            if (std.mem.indexOf(u8, new_part, ",")) |comma| {
                new_start = std.fmt.parseInt(u32, new_part[0..comma], 10) catch return error.CorruptPatch;
                new_count = std.fmt.parseInt(u32, new_part[comma + 1 ..], 10) catch return error.CorruptPatch;
            } else {
                new_start = std.fmt.parseInt(u32, new_part, 10) catch 1;
                new_count = 1;
            }
        }
    }

    pos.* += 1;

    var hunk = PatchHunk{
        .old_start = old_start,
        .old_count = old_count,
        .new_start = new_start,
        .new_count = new_count,
        .lines = std.array_list.Managed(PatchLine).init(allocator),
    };

    while (pos.* < lines.len) {
        const line = lines[pos.*];
        if (line.len == 0) {
            // Empty line could be context (empty line in diff) or end of patch
            // Check if there are more diff lines after this
            var has_more_diff = false;
            var look_ahead = pos.* + 1;
            while (look_ahead < lines.len) : (look_ahead += 1) {
                const la = lines[look_ahead];
                if (la.len == 0) continue;
                if (la[0] == '+' or la[0] == '-' or la[0] == ' ' or la[0] == '@') {
                    has_more_diff = true;
                    break;
                }
                if (std.mem.startsWith(u8, la, "diff ") or std.mem.startsWith(u8, la, "--- ")) {
                    break;
                }
                break;
            }
            if (!has_more_diff) {
                // End of patch/hunk
                pos.* += 1;
                break;
            }
            // Treat empty line as context (empty line in diff output)
            try hunk.lines.append(.{ .line_type = .context, .content = try allocator.dupe(u8, "") });
            pos.* += 1;
        } else if (line[0] == '+') {
            try hunk.lines.append(.{ .line_type = .add, .content = try allocator.dupe(u8, line[1..]) });
            pos.* += 1;
        } else if (line[0] == '-') {
            try hunk.lines.append(.{ .line_type = .remove, .content = try allocator.dupe(u8, line[1..]) });
            pos.* += 1;
        } else if (line[0] == ' ') {
            try hunk.lines.append(.{ .line_type = .context, .content = try allocator.dupe(u8, line[1..]) });
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "\\ No newline at end of file")) {
            // Mark last line as having no trailing newline
            if (hunk.lines.items.len > 0) {
                hunk.lines.items[hunk.lines.items.len - 1].no_newline = true;
            }
            pos.* += 1;
        } else if (std.mem.startsWith(u8, line, "@@") or
            std.mem.startsWith(u8, line, "diff ") or
            std.mem.startsWith(u8, line, "--- "))
        {
            break;
        } else {
            pos.* += 1;
        }
    }

    return hunk;
}

fn applyOnePatch(allocator: std.mem.Allocator, patch: *const Patch, reverse: bool, check_only: bool, platform_impl: anytype) !void {
    const target_path = if (reverse)
        patch.old_path orelse return error.NoPath
    else
        patch.new_path orelse patch.old_path orelse return error.NoPath;

    const source_path = if (reverse)
        patch.new_path orelse patch.old_path orelse return error.NoPath
    else
        patch.old_path;

    // Handle new file creation
    if ((patch.is_new_file and !reverse) or (patch.is_delete and reverse)) {
        if (check_only) return;
        var content = std.array_list.Managed(u8).init(allocator);
        defer content.deinit();
        for (patch.hunks.items) |hunk| {
            for (hunk.lines.items) |line| {
                const lt = if (reverse) reverseLineType(line.line_type) else line.line_type;
                if (lt == .add) {
                    try content.appendSlice(line.content);
                    try content.append('\n');
                }
            }
        }
        // Create parent directories if needed
        if (std.fs.path.dirname(target_path)) |dir| {
            if (dir.len > 0) {
                std.fs.cwd().makePath(dir) catch {};
            }
        }
        platform_impl.fs.writeFile(target_path, content.items) catch return error.WriteError;
        return;
    }

    // Handle file deletion
    if ((patch.is_delete and !reverse) or (patch.is_new_file and reverse)) {
        if (check_only) return;
        std.fs.cwd().deleteFile(target_path) catch {};
        return;
    }

    // Read existing file
    const read_path = source_path orelse target_path;
    const original = platform_impl.fs.readFile(allocator, read_path) catch {
        // File doesn't exist - if all hunks are additions from line 0/1, create it
        if (patch.hunks.items.len > 0) {
            var content = std.array_list.Managed(u8).init(allocator);
            defer content.deinit();
            for (patch.hunks.items) |hunk| {
                for (hunk.lines.items) |line| {
                    const lt = if (reverse) reverseLineType(line.line_type) else line.line_type;
                    if (lt == .add) {
                        try content.appendSlice(line.content);
                        try content.append('\n');
                    }
                }
            }
            if (!check_only) {
                if (std.fs.path.dirname(target_path)) |dir| {
                    if (dir.len > 0) std.fs.cwd().makePath(dir) catch {};
                }
                platform_impl.fs.writeFile(target_path, content.items) catch return error.WriteError;
            }
            return;
        }
        return error.FileNotFound;
    };
    defer allocator.free(original);

    // Split into lines
    var orig_lines = std.array_list.Managed([]const u8).init(allocator);
    defer orig_lines.deinit();
    var line_iter = std.mem.splitScalar(u8, original, '\n');
    while (line_iter.next()) |line| try orig_lines.append(line);
    // Remove trailing empty line from split if file ended with newline
    if (orig_lines.items.len > 0 and orig_lines.items[orig_lines.items.len - 1].len == 0) {
        _ = orig_lines.pop();
    }

    // Apply hunks using context matching
    var result_lines = std.array_list.Managed([]const u8).init(allocator);
    defer result_lines.deinit();
    var last_line_no_newline = false;

    var orig_idx: usize = 0;

    for (patch.hunks.items) |hunk| {
        // Build the context/remove lines for matching
        var match_lines = std.array_list.Managed([]const u8).init(allocator);
        defer match_lines.deinit();
        for (hunk.lines.items) |pline| {
            const lt = if (reverse) reverseLineType(pline.line_type) else pline.line_type;
            if (lt == .context or lt == .remove) {
                try match_lines.append(pline.content);
            }
        }

        // Find where the context matches in the original, starting from suggested position
        const suggested: usize = if (reverse)
            (if (hunk.new_start > 0) hunk.new_start - 1 else 0)
        else
            (if (hunk.old_start > 0) hunk.old_start - 1 else 0);

        const match_pos = findContextMatch(orig_lines.items, match_lines.items, suggested, orig_idx);

        if (match_pos == null and match_lines.items.len > 0) {
            return error.PatchFailed;
        }

        const start_line = match_pos orelse (if (suggested < orig_lines.items.len) suggested else orig_idx);

        // Validate: for hunks starting at line 1 (beginning of file) with no leading context,
        // the match must be at position 0
        if (match_pos != null and match_pos.? != suggested) {
            // Check if hunk has leading context
            var has_leading_context = false;
            if (hunk.lines.items.len > 0) {
                const first_lt = if (reverse) reverseLineType(hunk.lines.items[0].line_type) else hunk.lines.items[0].line_type;
                has_leading_context = (first_lt == .context);
            }
            if (!has_leading_context) {
                // No leading context and match position differs - verify it makes sense
                const old_start_val: usize = if (reverse)
                    (if (hunk.new_start > 0) hunk.new_start else 1)
                else
                    (if (hunk.old_start > 0) hunk.old_start else 1);
                if (old_start_val == 1 and match_pos.? != 0) {
                    // Hunk should start at beginning of file but doesn't match there
                    return error.PatchFailed;
                }
            }
        }

        // Validate: if the hunk has no trailing context, it must go to end of file
        if (hunk.lines.items.len > 0) {
            const last_line_type = if (reverse) reverseLineType(hunk.lines.items[hunk.lines.items.len - 1].line_type) else hunk.lines.items[hunk.lines.items.len - 1].line_type;
            if (last_line_type == .add or last_line_type == .remove) {
                // No trailing context - hunk should cover to end of file
                const old_count: usize = @intCast(if (reverse) hunk.new_count else hunk.old_count);
                if (start_line + old_count < orig_lines.items.len) {
                    // File has more lines than hunk accounts for and no trailing context
                    return error.PatchFailed;
                }
            }
        }

        // Copy lines before this hunk
        while (orig_idx < start_line and orig_idx < orig_lines.items.len) {
            try result_lines.append(orig_lines.items[orig_idx]);
            orig_idx += 1;
        }

        // Apply hunk lines
        for (hunk.lines.items) |pline| {
            const lt = if (reverse) reverseLineType(pline.line_type) else pline.line_type;
            const pline_no_newline = if (reverse)
                // When reversing, add becomes remove and vice versa
                // no_newline flag applies to the reversed line type
                pline.no_newline
            else
                pline.no_newline;
            switch (lt) {
                .context => {
                    if (orig_idx < orig_lines.items.len) {
                        try result_lines.append(orig_lines.items[orig_idx]);
                        orig_idx += 1;
                        last_line_no_newline = pline_no_newline;
                    }
                },
                .add => {
                    try result_lines.append(pline.content);
                    last_line_no_newline = pline_no_newline;
                },
                .remove => {
                    // Skip this line from original
                    if (orig_idx < orig_lines.items.len) {
                        orig_idx += 1;
                    }
                },
            }
        }
    }

    // Copy remaining lines
    while (orig_idx < orig_lines.items.len) {
        try result_lines.append(orig_lines.items[orig_idx]);
        orig_idx += 1;
    }

    // Write result
    var output = std.array_list.Managed(u8).init(allocator);
    defer output.deinit();
    for (result_lines.items, 0..) |line, idx| {
        try output.appendSlice(line);
        if (idx + 1 < result_lines.items.len) {
            try output.append('\n');
        } else {
            // Last line: add newline unless no_newline flag is set
            if (!last_line_no_newline) {
                try output.append('\n');
            }
        }
    }

    // Check if patch resulted in no change (already applied)
    if (std.mem.eql(u8, output.items, original)) {
        return error.PatchAlreadyApplied;
    }

    if (check_only) return;

    // Create parent directories if needed
    if (std.fs.path.dirname(target_path)) |dir| {
        if (dir.len > 0) std.fs.cwd().makePath(dir) catch {};
    }
    platform_impl.fs.writeFile(target_path, output.items) catch return error.WriteError;
}

fn findContextMatch(orig_lines: []const []const u8, match_lines: []const []const u8, suggested: usize, min_pos: usize) ?usize {
    if (match_lines.len == 0) return suggested;

    // Try exact position first
    if (suggested >= min_pos and matchesAt(orig_lines, match_lines, suggested)) {
        return suggested;
    }

    // Search with increasing fuzz around suggested position
    var fuzz: usize = 1;
    const max_fuzz = if (orig_lines.len > 0) orig_lines.len else 1;
    while (fuzz <= max_fuzz) : (fuzz += 1) {
        if (suggested >= fuzz + min_pos) {
            const pos = suggested - fuzz;
            if (pos >= min_pos and matchesAt(orig_lines, match_lines, pos)) return pos;
        }
        const pos = suggested + fuzz;
        if (pos >= min_pos and matchesAt(orig_lines, match_lines, pos)) return pos;
    }

    return null;
}

fn matchesAt(orig_lines: []const []const u8, match_lines: []const []const u8, pos: usize) bool {
    if (pos + match_lines.len > orig_lines.len) return false;
    for (match_lines, 0..) |ml, i| {
        if (!std.mem.eql(u8, orig_lines[pos + i], ml)) return false;
    }
    return true;
}

fn reverseLineType(lt: PatchLineType) PatchLineType {
    return switch (lt) {
        .add => .remove,
        .remove => .add,
        .context => .context,
    };
}

fn outputAllPatchStats(allocator: std.mem.Allocator, patches: []Patch, platform_impl: anytype) !void {
    // Collect stats for all patches
    const StatInfo = struct { path: []const u8, added: u32, removed: u32, is_binary: bool, is_rename: bool };
    var stats = std.array_list.Managed(StatInfo).init(allocator);
    defer stats.deinit();

    var total_ins: u32 = 0;
    var total_del: u32 = 0;
    var max_path_len: usize = 0;
    var max_count: u32 = 0;

    for (patches) |*patch| {
        const path = patch.new_path orelse patch.old_path orelse "unknown";
        var added: u32 = 0;
        var removed: u32 = 0;
        for (patch.hunks.items) |hunk| {
            for (hunk.lines.items) |line| {
                switch (line.line_type) {
                    .add => added += 1,
                    .remove => removed += 1,
                    .context => {},
                }
            }
        }
        total_ins += added;
        total_del += removed;
        if (path.len > max_path_len) max_path_len = path.len;
        const count = added + removed;
        if (count > max_count) max_count = count;
        try stats.append(.{
            .path = path,
            .added = added,
            .removed = removed,
            .is_binary = patch.is_binary,
            .is_rename = false, // TODO: detect renames
        });
    }

    // Determine column widths (minimum 4 like git)
    const count_width = @max(countDigits(max_count), @as(u32, 4));
    // Calculate available graph width based on terminal width (default 80)
    // Format: " path | count graph\n"
    // 1 (space) + max_path_len + 3 ( | ) + count_width + 1 (space) = overhead
    const overhead = 1 + @as(u32, @intCast(max_path_len)) + 3 + count_width + 1;
    const term_width: u32 = 79; // max line width (80 cols minus newline)
    const graph_width: u32 = if (overhead < term_width) term_width - overhead else 10;

    for (stats.items) |stat| {
        // " path | count +++---"
        const count = stat.added + stat.removed;
        const count_str = try std.fmt.allocPrint(allocator, "{d}", .{count});
        defer allocator.free(count_str);

        // Build graph bar
        var plus_count: u32 = stat.added;
        var minus_count: u32 = stat.removed;
        if (max_count > graph_width) {
            // Scale down proportionally using rounding (like git)
            const total64 = @as(u64, count);
            const max64 = @as(u64, max_count);
            const gw64 = @as(u64, graph_width);
            // Scale total count, then distribute between + and -
            var scaled_total = @as(u32, @intCast((total64 * gw64 + max64 / 2) / max64));
            if (scaled_total > graph_width) scaled_total = graph_width;
            if (scaled_total == 0) {
                plus_count = 0;
                minus_count = 0;
            } else if (stat.added > 0 and stat.removed > 0) {
                const add_ratio = @as(u64, stat.added) * @as(u64, scaled_total);
                plus_count = @intCast((add_ratio + count / 2) / count);
                if (plus_count == 0) plus_count = 1;
                minus_count = scaled_total - plus_count;
                if (minus_count == 0 and stat.removed > 0) {
                    minus_count = 1;
                    if (plus_count > 1) plus_count -= 1;
                }
            } else if (stat.added > 0) {
                plus_count = scaled_total;
                minus_count = 0;
            } else {
                plus_count = 0;
                minus_count = scaled_total;
            }
        }

        var graph_buf: [256]u8 = undefined;
        var gi: usize = 0;
        var pi: u32 = 0;
        while (pi < plus_count and gi < graph_buf.len) : (pi += 1) {
            graph_buf[gi] = '+';
            gi += 1;
        }
        var mi: u32 = 0;
        while (mi < minus_count and gi < graph_buf.len) : (mi += 1) {
            graph_buf[gi] = '-';
            gi += 1;
        }
        const graph = graph_buf[0..gi];

        // Format: " path | count_padded graph"
        // Path is left-aligned, padded to max_path_len
        var path_padded = try allocator.alloc(u8, max_path_len);
        defer allocator.free(path_padded);
        @memset(path_padded, ' ');
        @memcpy(path_padded[0..stat.path.len], stat.path);

        // Right-align count string
        var count_padded_buf: [20]u8 = undefined;
        var cpi: usize = 0;
        if (count_str.len < count_width) {
            var pad = count_width - @as(u32, @intCast(count_str.len));
            while (pad > 0 and cpi < count_padded_buf.len) : (pad -= 1) {
                count_padded_buf[cpi] = ' ';
                cpi += 1;
            }
        }
        @memcpy(count_padded_buf[cpi .. cpi + count_str.len], count_str);
        cpi += count_str.len;
        const count_padded = count_padded_buf[0..cpi];

        const msg = try std.fmt.allocPrint(allocator, " {s} | {s} {s}\n", .{ path_padded, count_padded, graph });
        defer allocator.free(msg);
        try platform_impl.writeStdout(msg);
    }

    // Summary line
    const nfiles = stats.items.len;
    var summary = std.array_list.Managed(u8).init(allocator);
    defer summary.deinit();
    const nfiles_str = try std.fmt.allocPrint(allocator, " {d} file{s} changed", .{ nfiles, if (nfiles != 1) "s" else "" });
    defer allocator.free(nfiles_str);
    try summary.appendSlice(nfiles_str);
    if (total_ins > 0 or total_del > 0) {
        if (total_ins > 0) {
            const add_str = try std.fmt.allocPrint(allocator, ", {d} insertion{s}(+)", .{ total_ins, if (total_ins != 1) "s" else "" });
            defer allocator.free(add_str);
            try summary.appendSlice(add_str);
        }
        if (total_del > 0) {
            const del_str = try std.fmt.allocPrint(allocator, ", {d} deletion{s}(-)", .{ total_del, if (total_del != 1) "s" else "" });
            defer allocator.free(del_str);
            try summary.appendSlice(del_str);
        }
    } else {
        try summary.appendSlice(", 0 insertions(+), 0 deletions(-)");
    }
    try summary.append('\n');
    try platform_impl.writeStdout(summary.items);
}

fn countDigits(n: u32) u32 {
    if (n == 0) return 1;
    var count: u32 = 0;
    var val = n;
    while (val > 0) : (val /= 10) count += 1;
    return count;
}

fn outputPatchStat(allocator: std.mem.Allocator, patch: *const Patch, platform_impl: anytype) !void {
    // Single patch stat (for non-collected output)
    var p_array = [_]Patch{patch.*};
    try outputAllPatchStats(allocator, &p_array, platform_impl);
}

fn outputPatchNumstat(allocator: std.mem.Allocator, patch: *const Patch, platform_impl: anytype) !void {
    const path = patch.new_path orelse patch.old_path orelse "unknown";
    var added: u32 = 0;
    var removed: u32 = 0;
    for (patch.hunks.items) |hunk| {
        for (hunk.lines.items) |line| {
            switch (line.line_type) {
                .add => added += 1,
                .remove => removed += 1,
                .context => {},
            }
        }
    }
    const msg = try std.fmt.allocPrint(allocator, "{d}\t{d}\t{s}\n", .{ added, removed, path });
    defer allocator.free(msg);
    try platform_impl.writeStdout(msg);
}

fn outputPatchSummary(allocator: std.mem.Allocator, patch: *const Patch, platform_impl: anytype) !void {
    if (patch.is_new_file) {
        const path = patch.new_path orelse "unknown";
        const mode_str = if (patch.new_mode) |m|
            try std.fmt.allocPrint(allocator, " create mode {o} {s}\n", .{ m, path })
        else
            try std.fmt.allocPrint(allocator, " create {s}\n", .{path});
        defer allocator.free(mode_str);
        try platform_impl.writeStdout(mode_str);
    } else if (patch.is_delete) {
        const path = patch.old_path orelse "unknown";
        const mode_str = if (patch.old_mode) |m|
            try std.fmt.allocPrint(allocator, " delete mode {o} {s}\n", .{ m, path })
        else
            try std.fmt.allocPrint(allocator, " delete {s}\n", .{path});
        defer allocator.free(mode_str);
        try platform_impl.writeStdout(mode_str);
    }
    if (patch.is_rename or patch.is_copy) {
        const old_p = patch.old_path orelse "unknown";
        const new_p = patch.new_path orelse "unknown";
        const action: []const u8 = if (patch.is_rename) "rename" else "copy";

        // Try to find common prefix/suffix for {old => new} format
        const formatted = try formatRenamePath(allocator, old_p, new_p);
        defer allocator.free(formatted);

        if (patch.similarity) |sim| {
            const msg = try std.fmt.allocPrint(allocator, " {s} {s} ({d}%)\n", .{ action, formatted, sim });
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        } else {
            const msg = try std.fmt.allocPrint(allocator, " {s} {s}\n", .{ action, formatted });
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    }
    if (patch.is_rewrite) {
        const path = patch.new_path orelse patch.old_path orelse "unknown";
        if (patch.dissimilarity) |dis| {
            const msg = try std.fmt.allocPrint(allocator, " rewrite {s} ({d}%)\n", .{ path, dis });
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    }
    if (patch.old_mode != null and patch.new_mode != null and patch.old_mode.? != patch.new_mode.? and !patch.is_new_file and !patch.is_delete) {
        const msg = try std.fmt.allocPrint(allocator, " mode change {o} => {o} {s}\n", .{ patch.old_mode.?, patch.new_mode.?, patch.new_path orelse patch.old_path orelse "unknown" });
        defer allocator.free(msg);
        try platform_impl.writeStdout(msg);
    }
}

fn formatRenamePath(allocator: std.mem.Allocator, old_path: []const u8, new_path: []const u8) ![]u8 {
    // Find common prefix (directory)
    var prefix_end: usize = 0;
    var last_slash: usize = 0;
    while (prefix_end < old_path.len and prefix_end < new_path.len and old_path[prefix_end] == new_path[prefix_end]) {
        if (old_path[prefix_end] == '/') last_slash = prefix_end + 1;
        prefix_end += 1;
    }
    // Use up to last slash as prefix
    const prefix = old_path[0..last_slash];
    const old_suffix = old_path[last_slash..];
    const new_suffix = new_path[last_slash..];

    // Find common suffix (only at '/' boundaries, like git)
    var suffix_len: usize = 0;
    {
        var s: usize = 0;
        while (s < old_suffix.len and s < new_suffix.len and
            old_suffix[old_suffix.len - 1 - s] == new_suffix[new_suffix.len - 1 - s])
        {
            s += 1;
            // Lock in suffix at '/' boundaries
            if (old_suffix[old_suffix.len - s] == '/') {
                suffix_len = s;
            }
        }
        // If the entire remaining parts match, use full match
        if (s == old_suffix.len and s == new_suffix.len) {
            suffix_len = s;
        }
    }

    if (prefix.len > 0 or suffix_len > 0) {
        const old_mid = old_suffix[0 .. old_suffix.len - suffix_len];
        const new_mid = new_suffix[0 .. new_suffix.len - suffix_len];
        const common_suffix = old_suffix[old_suffix.len - suffix_len ..];
        return std.fmt.allocPrint(allocator, "{s}{{{s} => {s}}}{s}", .{ prefix, old_mid, new_mid, common_suffix });
    } else {
        return std.fmt.allocPrint(allocator, "{s} => {s}", .{ old_path, new_path });
    }
}

fn nativeCmdColumn(_: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    // git column formats stdin into columns
    const allocator = std.heap.page_allocator;
    var mode: []const u8 = "always";
    var width: u32 = if (std.process.getEnvVarOwned(allocator, "COLUMNS")) |cols_str| blk: {
        defer allocator.free(cols_str);
        break :blk std.fmt.parseInt(u32, cols_str, 10) catch 80;
    } else |_| 80;
    var padding: u32 = 1;
    var indent: []const u8 = "";
    var nl: []const u8 = "\n";
    
    while (args.next()) |arg| {
        if (std.mem.startsWith(u8, arg, "--mode=")) {
            mode = arg["--mode=".len..];
        } else if (std.mem.startsWith(u8, arg, "--width=")) {
            width = std.fmt.parseInt(u32, arg["--width=".len..], 10) catch 80;
        } else if (std.mem.startsWith(u8, arg, "--padding=")) {
            const pad_str = arg["--padding=".len..];
            if (pad_str.len > 0 and pad_str[0] == '-') {
                try platform_impl.writeStdout("fatal: --padding must be non-negative\n");
                std.process.exit(128);
            }
            padding = std.fmt.parseInt(u32, pad_str, 10) catch 1;
        } else if (std.mem.eql(u8, arg, "--padding")) {
            if (args.next()) |next| {
                if (next.len > 0 and next[0] == '-') {
                    try platform_impl.writeStdout("fatal: --padding must be non-negative\n");
                    std.process.exit(128);
                }
                padding = std.fmt.parseInt(u32, next, 10) catch 1;
            }
        } else if (std.mem.startsWith(u8, arg, "--indent=")) {
            indent = arg["--indent=".len..];
        } else if (std.mem.eql(u8, arg, "--indent")) {
            if (args.next()) |next| indent = next;
        } else if (std.mem.startsWith(u8, arg, "--nl=")) {
            nl = arg["--nl=".len..];
        } else if (std.mem.eql(u8, arg, "--raw-mode")) {
            // Ignore
        }
    }
    
    if (std.mem.eql(u8, mode, "never")) {
        // Pass through without formatting
        const data = readStdin(allocator, 10 * 1024 * 1024) catch return;
        defer allocator.free(data);
        try platform_impl.writeStdout(data);
        return;
    }
    
    if (std.mem.eql(u8, mode, "plain")) {
        // Each line gets indent prefix and nl suffix
        const data = readStdin(allocator, 10 * 1024 * 1024) catch return;
        defer allocator.free(data);
        var line_it = std.mem.splitScalar(u8, data, '\n');
        while (line_it.next()) |line| {
            if (line.len == 0) continue;
            try platform_impl.writeStdout(indent);
            try platform_impl.writeStdout(line);
            try platform_impl.writeStdout(nl);
        }
        return;
    }
    
    // Read all lines from stdin
    const data = readStdin(allocator, 10 * 1024 * 1024) catch return;
    defer allocator.free(data);
    
    var lines = std.array_list.Managed([]const u8).init(allocator);
    defer lines.deinit();
    var max_len: u32 = 0;
    
    var line_iter = std.mem.splitScalar(u8, data, '\n');
    while (line_iter.next()) |line| {
        if (line.len == 0 and lines.items.len > 0) continue;
        if (line.len > 0) {
            try lines.append(line);
            if (line.len > max_len) max_len = @intCast(line.len);
        }
    }
    
    if (lines.items.len == 0) return;
    
    const dense = std.mem.indexOf(u8, mode, "dense") != null and std.mem.indexOf(u8, mode, "nodense") == null;
    const row_first = std.mem.indexOf(u8, mode, "row") != null;
    const effective_width = if (width > @as(u32, @intCast(indent.len))) width - @as(u32, @intCast(indent.len)) else width;

    if (dense) {
        // Dense mode: find the maximum number of columns that fit, using per-column widths
        // Try from max possible columns down to 1
        const max_possible_cols = @max(1, effective_width / 2); // minimum 2 chars per col
        var best_cols: usize = 1;
        var best_rows: usize = lines.items.len;
        // Store per-column widths for best layout
        var best_col_widths: [256]u32 = undefined;
        best_col_widths[0] = max_len + padding;

        var try_cols: usize = if (max_possible_cols > 256) 256 else max_possible_cols;
        while (try_cols > 1) : (try_cols -= 1) {
            const try_rows = (lines.items.len + try_cols - 1) / try_cols;
            // Compute per-column widths
            var col_widths: [256]u32 = undefined;
            var total_w: u32 = 0;
            var fits = true;
            var c: usize = 0;
            while (c < try_cols) : (c += 1) {
                var cw: u32 = 0;
                var r: usize = 0;
                while (r < try_rows) : (r += 1) {
                    const idx = if (row_first) r * try_cols + c else c * try_rows + r;
                    if (idx < lines.items.len) {
                        const l: u32 = @intCast(lines.items[idx].len);
                        if (l > cw) cw = l;
                    }
                }
                col_widths[c] = if (c + 1 < try_cols) cw + padding else cw;
                total_w += col_widths[c];
                if (total_w > effective_width) {
                    fits = false;
                    break;
                }
            }
            if (fits) {
                best_cols = try_cols;
                best_rows = try_rows;
                @memcpy(best_col_widths[0..try_cols], col_widths[0..try_cols]);
                break;
            }
        }

        if (row_first) {
            var i: usize = 0;
            while (i < lines.items.len) {
                if (indent.len > 0) try platform_impl.writeStdout(indent);
                var col: usize = 0;
                while (col < best_cols and i + col < lines.items.len) : (col += 1) {
                    try platform_impl.writeStdout(lines.items[i + col]);
                    if (col + 1 < best_cols and i + col + 1 < lines.items.len) {
                        var p: usize = lines.items[i + col].len;
                        while (p < best_col_widths[col]) : (p += 1) {
                            try platform_impl.writeStdout(" ");
                        }
                    }
                }
                try platform_impl.writeStdout("\n");
                i += best_cols;
            }
        } else {
            var row: usize = 0;
            while (row < best_rows) : (row += 1) {
                if (indent.len > 0) try platform_impl.writeStdout(indent);
                var col: usize = 0;
                while (col < best_cols) : (col += 1) {
                    const idx = col * best_rows + row;
                    if (idx >= lines.items.len) break;
                    try platform_impl.writeStdout(lines.items[idx]);
                    const next_idx = (col + 1) * best_rows + row;
                    if (col + 1 < best_cols and next_idx < lines.items.len) {
                        var p: usize = lines.items[idx].len;
                        while (p < best_col_widths[col]) : (p += 1) {
                            try platform_impl.writeStdout(" ");
                        }
                    }
                }
                try platform_impl.writeStdout("\n");
            }
        }
    } else {
        // Non-dense: uniform column widths
        const col_width = max_len + padding;
        const num_cols = if (col_width > 0) @max(1, effective_width / col_width) else 1;
        const num_rows = (lines.items.len + num_cols - 1) / num_cols;

        if (row_first) {
            // Row-first layout
            var i: usize = 0;
            while (i < lines.items.len) {
                if (indent.len > 0) try platform_impl.writeStdout(indent);
                var col: usize = 0;
                while (col < num_cols and i + col < lines.items.len) : (col += 1) {
                    try platform_impl.writeStdout(lines.items[i + col]);
                    // Pad unless last item on line
                    if (col + 1 < num_cols and i + col + 1 < lines.items.len) {
                        var pad_c: usize = lines.items[i + col].len;
                        while (pad_c < col_width) : (pad_c += 1) {
                            try platform_impl.writeStdout(" ");
                        }
                    }
                }
                try platform_impl.writeStdout("\n");
                i += num_cols;
            }
        } else {
            // Column-first layout (default)
            var row: usize = 0;
            while (row < num_rows) : (row += 1) {
                if (indent.len > 0) try platform_impl.writeStdout(indent);
                var col: usize = 0;
                while (col < num_cols) : (col += 1) {
                    const idx = col * num_rows + row;
                    if (idx >= lines.items.len) break;
                    try platform_impl.writeStdout(lines.items[idx]);
                    // Pad to col_width unless it's the last item on the line
                    const next_idx = (col + 1) * num_rows + row;
                    if (col + 1 < num_cols and next_idx < lines.items.len) {
                        var pad_amt: usize = lines.items[idx].len;
                        while (pad_amt < col_width) : (pad_amt += 1) {
                            try platform_impl.writeStdout(" ");
                        }
                    }
                }
                try platform_impl.writeStdout("\n");
            }
        }
    }
}

fn nativeCmdCheckIgnore(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var verbose = false;
    var quiet = false;
    var use_stdin = false;
    var use_z = false;
    var non_matching = false;
    var paths = std.array_list.Managed([]const u8).init(allocator);
    defer paths.deinit();

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-v") or std.mem.eql(u8, arg, "--verbose")) {
            verbose = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            quiet = true;
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.eql(u8, arg, "--non-matching")) {
            non_matching = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            use_stdin = true;
        } else if (std.mem.eql(u8, arg, "-z")) {
            use_z = true;
        } else if (std.mem.eql(u8, arg, "--no-index")) {
            // accepted but not used differently yet
        } else if (std.mem.eql(u8, arg, "--")) {
            while (args.next()) |a| try paths.append(a);
            break;
        } else if (arg.len > 0 and arg[0] == '-') {
            // Unknown option - ignore
        } else {
            try paths.append(arg);
        }
    }

    // Validate option combinations
    if (quiet and verbose) {
        try platform_impl.writeStderr("fatal: cannot have both --quiet and --verbose\n");
        std.process.exit(128);
    }

    if (use_z and !use_stdin) {
        try platform_impl.writeStderr("fatal: -z only makes sense with --stdin\n");
        std.process.exit(128);
    }

    if (use_stdin and paths.items.len > 0) {
        try platform_impl.writeStderr("fatal: cannot specify pathnames with --stdin\n");
        std.process.exit(128);
    }

    if (!use_stdin and paths.items.len == 0) {
        try platform_impl.writeStderr("fatal: no path specified\n");
        std.process.exit(128);
    }

    if (quiet and !use_stdin and paths.items.len > 1) {
        try platform_impl.writeStderr("fatal: --quiet is only valid with a single pathname\n");
        std.process.exit(128);
    }

    // Read paths from stdin if needed
    var stdin_buf: ?[]u8 = null;
    defer if (stdin_buf) |b| allocator.free(b);
    if (use_stdin) {
        const stdin_file = std.fs.File{ .handle = std.posix.STDIN_FILENO };
        stdin_buf = stdin_file.readToEndAlloc(allocator, 10 * 1024 * 1024) catch null;
        if (stdin_buf) |buf| {
            if (use_z) {
                var it = std.mem.splitScalar(u8, buf, 0);
                while (it.next()) |entry| {
                    if (entry.len > 0) try paths.append(entry);
                }
            } else {
                var it = std.mem.splitScalar(u8, buf, '\n');
                while (it.next()) |line| {
                    if (line.len > 0) try paths.append(line);
                }
            }
        }
    }

    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    const repo_root = std.fs.path.dirname(git_path) orelse ".";

    const cwd = try platform_impl.fs.getCwd(allocator);
    defer allocator.free(cwd);

    // Build a combined gitignore that loads from multiple sources
    var gitignore = gitignore_mod.GitIgnore.init(allocator);
    defer gitignore.deinit();

    // Load from $GIT_DIR/info/exclude
    const exclude_path = try std.fmt.allocPrint(allocator, "{s}/info/exclude", .{git_path});
    defer allocator.free(exclude_path);
    if (platform_impl.fs.readFile(allocator, exclude_path)) |content| {
        defer allocator.free(content);
        gitignore.addPatternsFromSource(content, ".git/info/exclude");
    } else |_| {}

    // Load from core.excludesfile (global)
    {
        var config = config_mod.loadGitConfig(git_path, allocator) catch null;
        defer if (config) |*c| c.deinit();
        const global_path_val: ?[]const u8 = if (config) |c| c.get("core", null, "excludesfile") else null;
        if (global_path_val) |gp| {
            const gpath = allocator.dupe(u8, gp) catch null;
            if (gpath) |global_path| {
                defer allocator.free(global_path);
                const expanded = if (global_path.len > 0 and global_path[0] == '~') epath: {
                    const home = std.process.getEnvVarOwned(allocator, "HOME") catch break :epath global_path;
                    defer allocator.free(home);
                    break :epath std.fmt.allocPrint(allocator, "{s}{s}", .{ home, global_path[1..] }) catch break :epath global_path;
                } else global_path;
                defer if (expanded.ptr != global_path.ptr) allocator.free(expanded);
                if (platform_impl.fs.readFile(allocator, expanded)) |content| {
                    defer allocator.free(content);
                    gitignore.addPatternsFromSource(content, expanded);
                } else |_| {}
            }
        }
    }

    // Load repo-level .gitignore
    const gitignore_path = try std.fmt.allocPrint(allocator, "{s}/.gitignore", .{repo_root});
    defer allocator.free(gitignore_path);
    if (platform_impl.fs.readFile(allocator, gitignore_path)) |content| {
        defer allocator.free(content);
        gitignore.addPatternsFromSource(content, ".gitignore");
    } else |_| {}

    const line_end: []const u8 = if (use_z) "\x00" else "\n";
    const sep: []const u8 = "\t";
    var found_any = false;

    for (paths.items) |path| {
        // Resolve path relative to repo root
        var check_path: []const u8 = path;
        var allocated_check_path: ?[]u8 = null;
        defer if (allocated_check_path) |p| allocator.free(p);

        if (std.mem.eql(u8, path, ".")) {
            if (cwd.len > repo_root.len and std.mem.startsWith(u8, cwd, repo_root) and cwd[repo_root.len] == '/') {
                check_path = cwd[repo_root.len + 1 ..];
            }
        } else if (!std.fs.path.isAbsolute(path)) {
            if (cwd.len > repo_root.len and std.mem.startsWith(u8, cwd, repo_root) and cwd[repo_root.len] == '/') {
                const prefix = cwd[repo_root.len + 1 ..];
                allocated_check_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, path });
                check_path = allocated_check_path.?;
            }
        }

        // Load directory-specific .gitignore files along the path
        var dir_gitignore = gitignore_mod.GitIgnore.init(allocator);
        defer dir_gitignore.deinit();
        {
            var prefix_end: usize = 0;
            while (std.mem.indexOfPos(u8, check_path, prefix_end, "/")) |slash| {
                const subdir = check_path[0..slash];
                const sub_gi_path = try std.fmt.allocPrint(allocator, "{s}/{s}/.gitignore", .{ repo_root, subdir });
                defer allocator.free(sub_gi_path);
                if (platform_impl.fs.readFile(allocator, sub_gi_path)) |content| {
                    defer allocator.free(content);
                    const rel_source = try std.fmt.allocPrint(allocator, "{s}/.gitignore", .{subdir});
                    defer allocator.free(rel_source);
                    dir_gitignore.addPatternsFromSource(content, rel_source);
                } else |_| {}
                prefix_end = slash + 1;
            }
        }

        // Check if it's a directory
        const is_dir = blk: {
            const full = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, check_path });
            defer allocator.free(full);
            var dir = std.fs.cwd().openDir(full, .{}) catch break :blk false;
            dir.close();
            break :blk true;
        };

        // Check directory-specific gitignore first, then repo-level
        var match_result = dir_gitignore.getMatchInfo(check_path, is_dir);
        if (!match_result.matched) {
            match_result = gitignore.getMatchInfo(check_path, is_dir);
        }

        if (match_result.matched) {
            found_any = true;
            if (!quiet) {
                if (verbose) {
                    const msg = try std.fmt.allocPrint(allocator, "{s}:{d}:{s}{s}{s}{s}", .{
                        match_result.source,
                        match_result.line_number,
                        match_result.pattern,
                        sep,
                        path,
                        line_end,
                    });
                    defer allocator.free(msg);
                    try platform_impl.writeStdout(msg);
                } else {
                    const msg = try std.fmt.allocPrint(allocator, "{s}{s}", .{ path, line_end });
                    defer allocator.free(msg);
                    try platform_impl.writeStdout(msg);
                }
            }
        } else if (verbose and non_matching) {
            // Show non-matching entry
            const msg = try std.fmt.allocPrint(allocator, "::{s}{s}{s}", .{ sep, path, line_end });
            defer allocator.free(msg);
            try platform_impl.writeStdout(msg);
        }
    }

    if (!found_any) std.process.exit(1);
}

fn nativeCmdCheckAttr(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var attr_names = std.array_list.Managed([]const u8).init(allocator);
    defer attr_names.deinit();
    var file_paths = std.array_list.Managed([]const u8).init(allocator);
    defer file_paths.deinit();
    var all_attrs = false;
    var use_stdin = false;
    var cached = false;
    var source: ?[]const u8 = null;
    var after_dashdash = false;

    while (args.next()) |arg| {
        if (after_dashdash) {
            try file_paths.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            after_dashdash = true;
        } else if (std.mem.eql(u8, arg, "--all") or std.mem.eql(u8, arg, "-a")) {
            all_attrs = true;
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            use_stdin = true;
        } else if (std.mem.eql(u8, arg, "--cached")) {
            cached = true;
        } else if (std.mem.eql(u8, arg, "-z")) {
            // null termination - ignore for now
        } else if (std.mem.eql(u8, arg, "--source")) {
            source = args.next();
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (!all_attrs and attr_names.items.len == 0 and file_paths.items.len == 0) {
                try attr_names.append(arg);
            } else {
                try file_paths.append(arg);
            }
        }
    }

    // Read paths from stdin if --stdin
    var stdin_buf: ?[]u8 = null;
    defer if (stdin_buf) |b| allocator.free(b);
    if (use_stdin) {
        const stdin_file = std.fs.File{ .handle = std.posix.STDIN_FILENO };
        stdin_buf = stdin_file.readToEndAlloc(allocator, 1024 * 1024) catch null;
        if (stdin_buf) |buf| {
            var iter = std.mem.splitScalar(u8, buf, '\n');
            while (iter.next()) |line| {
                const trimmed = std.mem.trim(u8, line, " \t\r");
                if (trimmed.len > 0) try file_paths.append(trimmed);
            }
        }
    }

    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    const repo_root = std.fs.path.dirname(git_path) orelse ".";

    const cwd = try platform_impl.fs.getCwd(allocator);
    defer allocator.free(cwd);

    // Load gitattributes from various sources
    var attr_rules = std.array_list.Managed(AttrRule).init(allocator);
    defer {
        for (attr_rules.items) |*rule| rule.deinit(allocator);
        attr_rules.deinit();
    }

    // Load repo .gitattributes
    if (!cached) {
        try loadAttrFile(allocator, repo_root, "", platform_impl, &attr_rules);
    }

    // Load global attributes if core.attributesfile is set
    // Load info/attributes
    const info_attr_path = try std.fmt.allocPrint(allocator, "{s}/info/attributes", .{git_path});
    defer allocator.free(info_attr_path);
    if (platform_impl.fs.readFile(allocator, info_attr_path)) |content| {
        defer allocator.free(content);
        parseAttrContent(allocator, content, "", &attr_rules) catch {};
    } else |_| {}

    for (file_paths.items) |path| {
        // Resolve path relative to repo root
        var check_path: []const u8 = path;
        var allocated_path: ?[]u8 = null;
        defer if (allocated_path) |p| allocator.free(p);

        if (!std.fs.path.isAbsolute(path)) {
            if (cwd.len > repo_root.len and std.mem.startsWith(u8, cwd, repo_root) and cwd[repo_root.len] == '/') {
                const prefix = cwd[repo_root.len + 1..];
                allocated_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, path });
                check_path = allocated_path.?;
            }
        }

        // Load directory-specific .gitattributes from each directory in path
        var dir_rules = std.array_list.Managed(AttrRule).init(allocator);
        defer {
            for (dir_rules.items) |*rule| rule.deinit(allocator);
            dir_rules.deinit();
        }
        if (!cached) {
            // Walk up the path hierarchy loading .gitattributes from each dir
            // e.g. for "a/b/d/g", load a/.gitattributes, a/b/.gitattributes, a/b/d/.gitattributes
            var remaining = check_path;
            while (std.mem.indexOf(u8, remaining, "/")) |slash_pos| {
                const subdir = check_path[0 .. @intFromPtr(remaining.ptr) - @intFromPtr(check_path.ptr) + slash_pos];
                if (subdir.len > 0) {
                    try loadAttrFile(allocator, repo_root, subdir, platform_impl, &dir_rules);
                }
                remaining = remaining[slash_pos + 1 ..];
            }
        }

        if (all_attrs) {
            // Show all defined attributes for the path
            var shown = std.StringHashMap([]const u8).init(allocator);
            defer shown.deinit();

            // Check dir rules first (higher priority), then repo rules
            for (dir_rules.items) |rule| {
                if (attrPatternMatches(rule.pattern, check_path)) {
                    for (rule.attrs.items) |attr| {
                        if (!shown.contains(attr.name)) {
                            shown.put(attr.name, attr.value) catch {};
                        }
                    }
                }
            }
            for (attr_rules.items) |rule| {
                if (attrPatternMatches(rule.pattern, check_path)) {
                    for (rule.attrs.items) |attr| {
                        if (!shown.contains(attr.name)) {
                            shown.put(attr.name, attr.value) catch {};
                        }
                    }
                }
            }

            var iter = shown.iterator();
            while (iter.next()) |entry| {
                const msg = try std.fmt.allocPrint(allocator, "{s}: {s}: {s}\n", .{ path, entry.key_ptr.*, entry.value_ptr.* });
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            }
        } else {
            // Show specific attributes
            for (attr_names.items) |attr_name| {
                var value: []const u8 = "unspecified";

                // Search dir rules first (higher priority), then repo rules
                // Last matching pattern wins (within each file, last match wins)
                for (attr_rules.items) |rule| {
                    if (attrPatternMatches(rule.pattern, check_path)) {
                        for (rule.attrs.items) |attr| {
                            if (std.mem.eql(u8, attr.name, attr_name)) {
                                value = attr.value;
                            }
                        }
                    }
                }
                for (dir_rules.items) |rule| {
                    if (attrPatternMatches(rule.pattern, check_path)) {
                        for (rule.attrs.items) |attr| {
                            if (std.mem.eql(u8, attr.name, attr_name)) {
                                value = attr.value;
                            }
                        }
                    }
                }

                const msg = try std.fmt.allocPrint(allocator, "{s}: {s}: {s}\n", .{ path, attr_name, value });
                defer allocator.free(msg);
                try platform_impl.writeStdout(msg);
            }
        }
    }
}

const AttrValue = struct {
    name: []const u8,
    value: []const u8,
    fn deinit(self: *AttrValue, alloc: std.mem.Allocator) void {
        alloc.free(self.name);
        alloc.free(self.value);
    }
};

const AttrRule = struct {
    pattern: []const u8,
    attrs: std.array_list.Managed(AttrValue),
    fn deinit(self: *AttrRule, alloc: std.mem.Allocator) void {
        alloc.free(self.pattern);
        for (self.attrs.items) |*attr| attr.deinit(alloc);
        self.attrs.deinit();
    }
};

fn loadAttrFile(allocator: std.mem.Allocator, repo_root: []const u8, subdir: []const u8, platform_impl: *const platform_mod.Platform, rules: *std.array_list.Managed(AttrRule)) !void {
    const attr_path = if (subdir.len > 0)
        try std.fmt.allocPrint(allocator, "{s}/{s}/.gitattributes", .{ repo_root, subdir })
    else
        try std.fmt.allocPrint(allocator, "{s}/.gitattributes", .{repo_root});
    defer allocator.free(attr_path);

    const content = platform_impl.fs.readFile(allocator, attr_path) catch return;
    defer allocator.free(content);
    try parseAttrContent(allocator, content, subdir, rules);
}

fn parseAttrContent(allocator: std.mem.Allocator, content: []const u8, prefix: []const u8, rules: *std.array_list.Managed(AttrRule)) !void {
    var lines = std.mem.splitScalar(u8, content, '\n');
    while (lines.next()) |line| {
        const trimmed = std.mem.trim(u8, line, " \t\r");
        if (trimmed.len == 0 or trimmed[0] == '#') continue;
        // Skip macro definitions [attr]
        if (std.mem.startsWith(u8, trimmed, "[attr]")) continue;

        // Parse: pattern attr1=val1 attr2 -attr3 !attr4
        var parts = std.mem.tokenizeAny(u8, trimmed, " \t");
        const raw_pattern = parts.next() orelse continue;

        // Handle quoted patterns
        var pattern: []const u8 = raw_pattern;
        if (pattern.len > 0 and pattern[0] == '"') {
            // Skip quoted patterns for now - they're complex
            continue;
        }

        // If pattern starts with /, it's anchored to the directory
        var is_anchored = false;
        if (pattern.len > 0 and pattern[0] == '/') {
            is_anchored = true;
            pattern = pattern[1..];
        }

        // Prepend prefix for subdirectory patterns
        var full_pattern: []u8 = undefined;
        if (prefix.len > 0 and !is_anchored) {
            // For non-anchored patterns, they can match anywhere
            full_pattern = try allocator.dupe(u8, pattern);
        } else if (prefix.len > 0 and is_anchored) {
            full_pattern = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, pattern });
        } else {
            full_pattern = try allocator.dupe(u8, pattern);
        }

        var attrs = std.array_list.Managed(AttrValue).init(allocator);
        while (parts.next()) |attr_spec| {
            if (attr_spec.len == 0) continue;

            if (std.mem.indexOf(u8, attr_spec, "=")) |eq| {
                // attr=value
                const name = try allocator.dupe(u8, attr_spec[0..eq]);
                const val = try allocator.dupe(u8, attr_spec[eq + 1..]);
                try attrs.append(.{ .name = name, .value = val });
            } else if (attr_spec[0] == '-') {
                // -attr (unset)
                const name = try allocator.dupe(u8, attr_spec[1..]);
                const val = try allocator.dupe(u8, "unset");
                try attrs.append(.{ .name = name, .value = val });
            } else if (attr_spec[0] == '!') {
                // !attr (unspecified)
                const name = try allocator.dupe(u8, attr_spec[1..]);
                const val = try allocator.dupe(u8, "unspecified");
                try attrs.append(.{ .name = name, .value = val });
            } else {
                // attr (set to true)
                const name = try allocator.dupe(u8, attr_spec);
                const val = try allocator.dupe(u8, "set");
                try attrs.append(.{ .name = name, .value = val });
            }
        }

        if (attrs.items.len > 0) {
            try rules.append(.{ .pattern = full_pattern, .attrs = attrs });
        } else {
            allocator.free(full_pattern);
            attrs.deinit();
        }
    }
}

fn attrPatternMatches(pattern: []const u8, path: []const u8) bool {
    // Use the gitignore glob matching
    if (gitignore_mod.GitignoreEntry.init(pattern, std.heap.page_allocator)) |entry| {
        defer entry.deinit(std.heap.page_allocator);
        return entry.matches(path, false);
    } else |_| {
        return false;
    }
}

fn checkIfDifferentFromTree(entry: index_mod.IndexEntry, tree_hash: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator) !bool {
    const tree_blob_hash = try lookupBlobInTree(tree_hash, entry.path, git_path, platform_impl, allocator);
    if (tree_blob_hash) |hash_bytes| {
        return !std.mem.eql(u8, &hash_bytes, &entry.sha1);
    }
    // File not found in tree - it's new, so it's staged
    return true;
}

fn buildTreeMap(tree_hash: []const u8, prefix: []const u8, git_path: []const u8, platform_impl: *const platform_mod.Platform, allocator: std.mem.Allocator, map: *std.StringHashMap([20]u8)) !void {
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    if (tree_obj.type != .tree) return;
    
    var i: usize = 0;
    while (i < tree_obj.data.len) {
        const space_pos = std.mem.indexOfScalarPos(u8, tree_obj.data, i, ' ') orelse break;
        const mode_str = tree_obj.data[i..space_pos];
        const null_pos = std.mem.indexOfScalarPos(u8, tree_obj.data, space_pos + 1, 0) orelse break;
        const name = tree_obj.data[space_pos + 1 .. null_pos];
        const hash_start = null_pos + 1;
        if (hash_start + 20 > tree_obj.data.len) break;
        const hash_bytes = tree_obj.data[hash_start .. hash_start + 20];
        
        const full_path = if (prefix.len > 0)
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name })
        else
            try allocator.dupe(u8, name);
        
        if (std.mem.eql(u8, mode_str, "40000") or std.mem.eql(u8, mode_str, "040000")) {
            // Directory - recurse
            const sub_hash = try std.fmt.allocPrint(allocator, "{x}", .{hash_bytes[0..20]});
            defer allocator.free(sub_hash);
            buildTreeMap(sub_hash, full_path, git_path, platform_impl, allocator, map) catch {};
            allocator.free(full_path);
        } else {
            // File - store in map
            var sha1: [20]u8 = undefined;
            @memcpy(&sha1, hash_bytes[0..20]);
            try map.put(full_path, sha1);
        }
        
        i = hash_start + 20;
    }
}

fn cmdSwitch(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    if (@import("builtin").target.os.tag == .freestanding) {
        try platform_impl.writeStderr("switch: not supported in freestanding mode\n");
        return;
    }
    
    var create_branch: ?[]const u8 = null;
    var force_create: ?[]const u8 = null;
    var detach = false;
    var orphan: ?[]const u8 = null;
    var target: ?[]const u8 = null;
    var discard_changes = false;
    
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-c") or std.mem.eql(u8, arg, "--create")) {
            create_branch = args.next();
        } else if (std.mem.startsWith(u8, arg, "-c") and arg.len > 2 and arg[1] == 'c') {
            // This doesn't make sense, skip
        } else if (std.mem.eql(u8, arg, "-C") or std.mem.eql(u8, arg, "--force-create")) {
            force_create = args.next();
        } else if (std.mem.eql(u8, arg, "-d") or std.mem.eql(u8, arg, "--detach")) {
            detach = true;
        } else if (std.mem.eql(u8, arg, "--orphan")) {
            orphan = args.next();
        } else if (std.mem.eql(u8, arg, "--discard-changes") or std.mem.eql(u8, arg, "--force") or std.mem.eql(u8, arg, "-f")) {
            discard_changes = true;
        } else if (std.mem.eql(u8, arg, "--guess") or std.mem.eql(u8, arg, "--no-guess") or std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            // ignore
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            if (target == null) target = arg;
        }
    }

    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    if (orphan) |orphan_name| {
        // Create orphan branch
        const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
        defer allocator.free(head_path);
        const ref_content = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{orphan_name});
        defer allocator.free(ref_content);
        platform_impl.fs.writeFile(head_path, ref_content) catch {};
        // Remove index
        const index_path = try std.fmt.allocPrint(allocator, "{s}/index", .{git_path});
        defer allocator.free(index_path);
        std.fs.cwd().deleteFile(index_path) catch {};
        const msg = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{orphan_name});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        return;
    }
    
    if (create_branch) |branch_name| {
        refs.createBranch(git_path, branch_name, target, platform_impl, allocator) catch |err| {
            switch (err) {
                error.NoCommitsYet, error.RefNotFound, error.FileNotFound => {
                    const head_path2 = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                    defer allocator.free(head_path2);
                    const ref_content2 = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{branch_name});
                    defer allocator.free(ref_content2);
                    platform_impl.fs.writeFile(head_path2, ref_content2) catch {};
                    const msg2 = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
                    defer allocator.free(msg2);
                    try platform_impl.writeStderr(msg2);
                    return;
                },
                else => return err,
            }
        };
        refs.updateHEAD(git_path, branch_name, platform_impl, allocator) catch {};
        const msg = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        return;
    }
    
    if (force_create) |branch_name| {
        // Delete existing branch if it exists
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/refs/heads/{s}", .{ git_path, branch_name });
        defer allocator.free(ref_path);
        std.fs.cwd().deleteFile(ref_path) catch {};
        
        refs.createBranch(git_path, branch_name, target, platform_impl, allocator) catch |err| {
            switch (err) {
                error.NoCommitsYet, error.RefNotFound, error.FileNotFound => {
                    const head_path2 = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
                    defer allocator.free(head_path2);
                    const ref_content2 = try std.fmt.allocPrint(allocator, "ref: refs/heads/{s}\n", .{branch_name});
                    defer allocator.free(ref_content2);
                    platform_impl.fs.writeFile(head_path2, ref_content2) catch {};
                    const msg2 = try std.fmt.allocPrint(allocator, "Switched to a new branch '{s}'\n", .{branch_name});
                    defer allocator.free(msg2);
                    try platform_impl.writeStderr(msg2);
                    return;
                },
                else => return err,
            }
        };
        refs.updateHEAD(git_path, branch_name, platform_impl, allocator) catch {};
        const msg = try std.fmt.allocPrint(allocator, "Switched to and reset branch '{s}'\n", .{branch_name});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        return;
    }
    
    if (detach) {
        const t = target orelse {
            try platform_impl.writeStderr("fatal: missing branch or commit argument\n");
            std.process.exit(128);
        };
        const hash = resolveRevision(git_path, t, platform_impl, allocator) catch {
            const emsg = try std.fmt.allocPrint(allocator, "fatal: invalid reference: {s}\n", .{t});
            defer allocator.free(emsg);
            try platform_impl.writeStderr(emsg);
            std.process.exit(128);
        };
        defer allocator.free(hash);
        try checkoutCommitTree(git_path, hash, allocator, platform_impl);
        const head_path = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{git_path});
        defer allocator.free(head_path);
        const head_content = try std.fmt.allocPrint(allocator, "{s}\n", .{hash});
        defer allocator.free(head_content);
        platform_impl.fs.writeFile(head_path, head_content) catch {};
        return;
    }
    
    // Default: switch to existing branch
    if (target) |t| {
        refs.updateHEAD(git_path, t, platform_impl, allocator) catch {};
        // Checkout files
        if (refs.resolveRef(git_path, "HEAD", platform_impl, allocator) catch null) |head_hash| {
            defer allocator.free(head_hash);
            checkoutCommitTree(git_path, head_hash, allocator, platform_impl) catch {};
        }
        const msg = try std.fmt.allocPrint(allocator, "Switched to branch '{s}'\n", .{t});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
    } else {
        try platform_impl.writeStderr("fatal: missing branch or commit argument\n");
        std.process.exit(128);
    }
}

fn cmdRestore(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    // Basic restore command - restore working tree files
    var source: ?[]const u8 = null;
    var staged = false;
    var worktree = true;
    var paths = std.array_list.Managed([]const u8).init(allocator);
    defer paths.deinit();
    var seen_separator = false;
    
    while (args.next()) |arg| {
        if (seen_separator) {
            try paths.append(arg);
        } else if (std.mem.eql(u8, arg, "--")) {
            seen_separator = true;
        } else if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--source")) {
            source = args.next();
        } else if (std.mem.startsWith(u8, arg, "--source=")) {
            source = arg["--source=".len..];
        } else if (std.mem.eql(u8, arg, "-S") or std.mem.eql(u8, arg, "--staged")) {
            staged = true;
        } else if (std.mem.eql(u8, arg, "-W") or std.mem.eql(u8, arg, "--worktree")) {
            worktree = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            // quiet
        } else if (!std.mem.startsWith(u8, arg, "-")) {
            try paths.append(arg);
        }
    }



    
    if (paths.items.len == 0) {
        try platform_impl.writeStderr("fatal: you must specify path(s) to restore\n");
        std.process.exit(128);
    }
    
    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);
    
    // Restore files from index to working tree
    var idx = index_mod.Index.load(git_path, platform_impl, allocator) catch return;
    defer idx.deinit();
    
    for (paths.items) |path| {
        for (idx.entries.items) |entry| {
            if (std.mem.eql(u8, entry.path, path)) {
                // Load blob and write to working tree
                var hash_hex: [40]u8 = undefined;
                for (entry.sha1, 0..) |byte, bi| {
                    hash_hex[bi * 2] = "0123456789abcdef"[byte >> 4];
                    hash_hex[bi * 2 + 1] = "0123456789abcdef"[byte & 0xf];
                }
                const blob = objects.GitObject.load(&hash_hex, git_path, platform_impl, allocator) catch continue;
                defer blob.deinit(allocator);
                const repo_root = std.fs.path.dirname(git_path) orelse ".";
                const full_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry.path });
                defer allocator.free(full_path);
                platform_impl.fs.writeFile(full_path, blob.data) catch {};
                break;
            }
        }
    }
}

fn cmdWorktree(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    const subcmd = args.next() orelse {
        try platform_impl.writeStderr("usage: git worktree add <path> [<branch>]\n       git worktree list\n       git worktree remove <path>\n");
        std.process.exit(129);
    };
    _ = allocator;
    
    if (std.mem.eql(u8, subcmd, "add") or std.mem.eql(u8, subcmd, "list") or 
        std.mem.eql(u8, subcmd, "remove") or std.mem.eql(u8, subcmd, "prune") or
        std.mem.eql(u8, subcmd, "lock") or std.mem.eql(u8, subcmd, "unlock") or
        std.mem.eql(u8, subcmd, "move") or std.mem.eql(u8, subcmd, "repair")) {
        try platform_impl.writeStderr("fatal: worktree command not yet implemented in ziggit\n");
        std.process.exit(128);
    } else {
        try platform_impl.writeStderr("fatal: unknown worktree subcommand\n");
        std.process.exit(129);
    }
}

fn cmdStripspace(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var strip_comments = false;
    var comment_lines = false;
    
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-s") or std.mem.eql(u8, arg, "--strip-comments")) {
            strip_comments = true;
        } else if (std.mem.eql(u8, arg, "-c") or std.mem.eql(u8, arg, "--comment-lines")) {
            comment_lines = true;
        }
    }
    
    // Resolve comment character
    var cc: []const u8 = "#";
    var cc_needs_free = false;
    
    // Check -c overrides first
    if (getConfigOverride("core.commentchar") orelse getConfigOverride("core.commentChar")) |override_val| {
        if (override_val.len == 0) {
            try platform_impl.writeStderr("fatal: core.commentchar must have at least one character\n");
            std.process.exit(128);
        }
        if (std.mem.indexOfScalar(u8, override_val, '\n') != null) {
            try platform_impl.writeStderr("fatal: core.commentchar cannot contain newline\n");
            std.process.exit(128);
        }
        cc = override_val;
    } else {
        // Check .git/config
        const git_dir_result = findGitDirectory(allocator, platform_impl) catch null;
        if (git_dir_result) |gd| {
            defer allocator.free(gd);
            const config_path = std.fs.path.join(allocator, &.{ gd, "config" }) catch null;
            if (config_path) |cp| {
                defer allocator.free(cp);
                const config_data = std.fs.cwd().readFileAlloc(allocator, cp, 1024 * 1024) catch null;
                if (config_data) |cd| {
                    defer allocator.free(cd);
                    if (parseConfigValue(cd, "core.commentchar", allocator) catch null) |val| {
                        if (val.len > 0) {
                            cc = val;
                            cc_needs_free = true;
                        } else {
                            allocator.free(val);
                        }
                    }
                }
            }
        }
    }
    defer if (cc_needs_free) allocator.free(cc);
    
    const stdin_data = readStdin(allocator, 10 * 1024 * 1024) catch {
        return;
    };
    defer allocator.free(stdin_data);
    
    if (comment_lines) {
        // Prefix each line with comment char + space
        var data = stdin_data;
        // Remove trailing newline for splitting
        if (data.len > 0 and data[data.len - 1] == '\n') {
            data = data[0 .. data.len - 1];
        }
        var lines = std.mem.splitScalar(u8, data, '\n');
        while (lines.next()) |line| {
            if (line.len == 0) {
                try platform_impl.writeStdout(cc);
                try platform_impl.writeStdout("\n");
            } else if (line[0] == '\t') {
                // Avoid SP-HT sequence: use commentchar+tab directly
                try platform_impl.writeStdout(cc);
                const out = try std.fmt.allocPrint(allocator, "{s}\n", .{line});
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            } else {
                const out = try std.fmt.allocPrint(allocator, "{s} {s}\n", .{ cc, line });
                defer allocator.free(out);
                try platform_impl.writeStdout(out);
            }
        }
        return;
    }
    
    // Strip trailing whitespace, collapse blank lines, strip comments
    var result = std.array_list.Managed(u8).init(allocator);
    defer result.deinit();
    var blank_count: u32 = 0;
    var lines = std.mem.splitScalar(u8, stdin_data, '\n');
    var has_content = false;
    
    while (lines.next()) |line| {
        const trimmed = std.mem.trimRight(u8, line, " \t\r");
        
        if (strip_comments and trimmed.len >= cc.len and std.mem.startsWith(u8, trimmed, cc)) {
            continue; // skip comment lines
        }
        
        if (trimmed.len == 0) {
            blank_count += 1;
            continue;
        }
        
        // Add at most one blank line between content
        if (has_content and blank_count > 0) {
            try result.append('\n');
        }
        blank_count = 0;
        has_content = true;
        
        try result.appendSlice(trimmed);
        try result.append('\n');
    }
    
    try platform_impl.writeStdout(result.items);
}

fn cmdCheckoutIndex(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var force = false;
    var all = false;
    var update_stat = false;
    var prefix: ?[]const u8 = null;
    var no_create = false;
    var temp_mode = false;
    var stdin_mode = false;
    var stdin_z = false;
    var paths = std.array_list.Managed([]const u8).init(allocator);
    defer paths.deinit();

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-f") or std.mem.eql(u8, arg, "--force")) {
            force = true;
        } else if (std.mem.eql(u8, arg, "-a") or std.mem.eql(u8, arg, "--all")) {
            all = true;
        } else if (std.mem.eql(u8, arg, "-u")) {
            update_stat = true;
        } else if (std.mem.eql(u8, arg, "-n") or std.mem.eql(u8, arg, "--no-create")) {
            no_create = true;
        } else if (std.mem.eql(u8, arg, "--temp")) {
            temp_mode = true;
        } else if (std.mem.startsWith(u8, arg, "--prefix=")) {
            prefix = arg["--prefix=".len..];
        } else if (std.mem.eql(u8, arg, "--prefix")) {
            prefix = args.next();
        } else if (std.mem.startsWith(u8, arg, "--stage=")) {
            // stage selection - not fully supported yet
        } else if (std.mem.eql(u8, arg, "--stage")) {
            _ = args.next();
        } else if (std.mem.eql(u8, arg, "--stdin")) {
            stdin_mode = true;
        } else if (std.mem.eql(u8, arg, "-z")) {
            stdin_z = true;
        } else if (std.mem.eql(u8, arg, "-q") or std.mem.eql(u8, arg, "--quiet")) {
            // quiet mode
        } else if (std.mem.eql(u8, arg, "-h") or std.mem.eql(u8, arg, "--help")) {
            try platform_impl.writeStdout("usage: git checkout-index [<options>] [--] [<file>...]\n\n    -u, --index           update stat information in the index file\n    -q, --quiet           be quiet if files exist or are not in the index\n    -f, --force           force overwrite of existing files\n    -a, --all             check out all files in the index\n    -n, --no-create       don't checkout new files\n    --temp                write the content to temporary files\n    --prefix <string>     when creating files, prepend <string>\n    --stage <number>      copy out the files from named stage\n    --stdin               read list of paths from the standard input\n    -z                    paths are separated with NUL character\n");
            std.process.exit(129);
            unreachable;
        } else if (std.mem.eql(u8, arg, "--")) {
            while (args.next()) |p| {
                try paths.append(p);
            }
        } else if (arg.len > 0 and arg[0] == '-') {
            const msg = try std.fmt.allocPrint(allocator, "error: unknown option '{s}'\nusage: git checkout-index [<options>] [--] [<file>...]\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(129);
            unreachable;
        } else {
            try paths.append(arg);
        }
    }

    const git_dir = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository (or any of the parent directories): .git\n");
        std.process.exit(128);
        unreachable;
    };
    defer allocator.free(git_dir);

    const repo_root = std.fs.path.dirname(git_dir) orelse ".";

    var idx = index_mod.Index.load(git_dir, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: unable to read index\n");
        std.process.exit(128);
        unreachable;
    };
    defer idx.deinit();

    // Read core.symlinks config (default true)
    var core_symlinks = true;
    {
        var cfg = config_mod.GitConfig.init(allocator);
        defer cfg.deinit();
        const config_path = std.fmt.allocPrint(allocator, "{s}/config", .{git_dir}) catch "";
        defer if (config_path.len > 0) allocator.free(config_path);
        cfg.parseFromFile(config_path) catch {};
        if (cfg.get("core", null, "symlinks")) |val| {
            if (std.mem.eql(u8, val, "false") or std.mem.eql(u8, val, "0")) {
                core_symlinks = false;
            }
        }
    }

    // Read paths from stdin if requested
    if (stdin_mode) {
        const stdin_data = readStdin(allocator, 10 * 1024 * 1024) catch "";
        defer allocator.free(stdin_data);
        if (stdin_z) {
            var it = std.mem.splitScalar(u8, stdin_data, 0);
            while (it.next()) |p| {
                if (p.len > 0) try paths.append(try allocator.dupe(u8, p));
            }
        } else {
            var it = std.mem.splitScalar(u8, stdin_data, '\n');
            while (it.next()) |p| {
                if (p.len > 0) try paths.append(try allocator.dupe(u8, p));
            }
        }
    }

    var did_update_stat = false;
    var has_errors = false;
    var temp_counter: u32 = 0;

    for (idx.entries.items) |*entry| {
        // Skip higher stages (unmerged) unless specifically requested
        const stage = (entry.flags >> 12) & 0x3;
        if (stage != 0) continue;

        const entry_path = entry.path;

        // If not --all, check if this path is requested
        if (!all and paths.items.len > 0) {
            var found = false;
            for (paths.items) |p| {
                if (std.mem.eql(u8, p, entry_path)) {
                    found = true;
                    break;
                }
            }
            if (!found) continue;
        } else if (!all) {
            continue;
        }

        // Build output path
        const out_path = if (prefix) |pfx|
            try std.fmt.allocPrint(allocator, "{s}{s}", .{ pfx, entry_path })
        else if (repo_root.len > 0 and !std.mem.eql(u8, repo_root, "."))
            try std.fmt.allocPrint(allocator, "{s}/{s}", .{ repo_root, entry_path })
        else
            try allocator.dupe(u8, entry_path);
        defer allocator.free(out_path);

        // Check if file exists and we need -f to overwrite (skip for temp mode)
        if (!force and !temp_mode) {
            if (std.fs.cwd().access(out_path, .{})) |_| {
                // File exists - report error and track failure
                const emsg = std.fmt.allocPrint(allocator, "error: {s} already exists, no checkout\n", .{entry_path}) catch "error: file already exists\n";
                platform_impl.writeStderr(emsg) catch {};
                has_errors = true;
                continue;
            } else |_| {}
        }

        if (no_create and !temp_mode) continue;

        // Load the blob content
        var hash_buf: [40]u8 = undefined;
        _ = std.fmt.bufPrint(&hash_buf, "{x}", .{&entry.sha1}) catch continue;

        const obj = objects.GitObject.load(&hash_buf, git_dir, platform_impl, allocator) catch {
            const msg = std.fmt.allocPrint(allocator, "error: unable to read sha1 file of {s} ({s})\n", .{ entry_path, &hash_buf }) catch continue;
            defer allocator.free(msg);
            platform_impl.writeStderr(msg) catch {};
            continue;
        };
        defer obj.deinit(allocator);

        const content = obj.data;

        // Temp mode: write to a temporary file and output mapping
        if (temp_mode) {
            const stage_num = (entry.flags >> 12) & 0x3;
            // Create temp file with unique name
            var temp_name_buf: [256]u8 = undefined;
            const final_name = std.fmt.bufPrint(&temp_name_buf, ".merge_file_{s}_{d}", .{ hash_buf[0..8], temp_counter }) catch continue;
            temp_counter += 1;
            const temp_file = std.fs.cwd().createFile(final_name, .{}) catch continue;
            defer temp_file.close();
            temp_file.writeAll(content) catch continue;
            // Output: tempfile\tpath
            if (stage_num == 0) {
                const tmsg = std.fmt.allocPrint(allocator, "{s}\t{s}\n", .{ final_name, entry_path }) catch continue;
                defer allocator.free(tmsg);
                platform_impl.writeStdout(tmsg) catch {};
            } else {
                // For unmerged stages, output with stage info
                const tmsg = std.fmt.allocPrint(allocator, "{s}\t{s}\n", .{ final_name, entry_path }) catch continue;
                defer allocator.free(tmsg);
                platform_impl.writeStdout(tmsg) catch {};
            }
            continue;
        }

        // When force, remove any existing file/dir that conflicts
        if (force) {
            // Remove the output path if it exists (file or dir)
            std.fs.cwd().deleteFile(out_path) catch {};
            std.fs.cwd().deleteDir(out_path) catch {};
            // For files under a dir-turned-file, remove the dir tree
            std.fs.cwd().deleteTree(out_path) catch {};
        }

        // Create parent directories
        if (std.fs.path.dirname(out_path)) |dir| {
            // If a file/symlink exists where a parent directory should be, remove it when force
            if (force) {
                // Check if any parent path component is a non-directory
                var check_path = dir;
                while (check_path.len > 0) {
                    var link_buf2: [4096]u8 = undefined;
                    if (std.fs.cwd().readLink(check_path, &link_buf2)) |_| {
                        // It's a symlink - remove it so we can create a dir
                        std.fs.cwd().deleteFile(check_path) catch {};
                        break;
                    } else |_| {
                        if (std.fs.cwd().statFile(check_path)) |st| {
                            if (st.kind != .directory) {
                                std.fs.cwd().deleteFile(check_path) catch {};
                                break;
                            } else break; // It's already a directory, good
                        } else |_| break; // Doesn't exist, makePath will create it
                    }
                    check_path = std.fs.path.dirname(check_path) orelse break;
                }
            }
            std.fs.cwd().makePath(dir) catch {};
        }

        const is_symlink = (entry.mode & 0o170000) == 0o120000;
        const is_executable = (entry.mode & 0o100) != 0;

        if (is_symlink and core_symlinks) {
            // Remove existing file/symlink first
            std.fs.cwd().deleteFile(out_path) catch {};
            std.fs.cwd().symLink(content, out_path, .{}) catch |err| {
                const msg = std.fmt.allocPrint(allocator, "error: unable to create symlink {s}: {}\n", .{ entry_path, err }) catch continue;
                defer allocator.free(msg);
                platform_impl.writeStderr(msg) catch {};
                continue;
            };
        } else {
            // Write regular file
            const file = std.fs.cwd().createFile(out_path, .{}) catch |err| {
                const msg = std.fmt.allocPrint(allocator, "error: unable to create file {s}: {}\n", .{ entry_path, err }) catch continue;
                defer allocator.free(msg);
                platform_impl.writeStderr(msg) catch {};
                continue;
            };
            defer file.close();
            file.writeAll(content) catch continue;

            if (is_executable) {
                const st = file.stat() catch continue;
                const new_mode = st.mode | 0o111;
                std.posix.fchmod(file.handle, new_mode) catch {};
            }
        }

        // Update stat info in index if -u flag
        if (update_stat) {
            if (std.fs.cwd().statFile(out_path)) |stat_result| {
                const mtime_s: u32 = @intCast(@max(0, @divTrunc(stat_result.mtime, std.time.ns_per_s)));
                const mtime_ns: u32 = @intCast(@max(0, @rem(stat_result.mtime, std.time.ns_per_s)));
                const ctime_s: u32 = @intCast(@max(0, @divTrunc(stat_result.ctime, std.time.ns_per_s)));
                const ctime_ns: u32 = @intCast(@max(0, @rem(stat_result.ctime, std.time.ns_per_s)));
                entry.mtime_sec = mtime_s;
                entry.mtime_nsec = mtime_ns;
                entry.ctime_sec = ctime_s;
                entry.ctime_nsec = ctime_ns;
                entry.size = @intCast(@min(stat_result.size, std.math.maxInt(u32)));
                entry.ino = @intCast(stat_result.inode);
                entry.dev = 0;
                did_update_stat = true;
            } else |_| {}
        }
    }

    // Save index if stat info was updated
    // Check that all explicitly requested paths were found in the index
    if (!all and paths.items.len > 0) {
        for (paths.items) |p| {
            var found = false;
            for (idx.entries.items) |entry| {
                if (std.mem.eql(u8, entry.path, p)) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                const emsg2 = std.fmt.allocPrint(allocator, "git checkout-index: {s} is not in the cache\n", .{p}) catch continue;
                defer allocator.free(emsg2);
                platform_impl.writeStderr(emsg2) catch {};
                has_errors = true;
            }
        }
    }

    if (did_update_stat) {
        idx.save(git_dir, platform_impl) catch {};
    }

    if (has_errors) {
        std.process.exit(1);
    }
}

// === T5 agent functions ===
fn performLocalFetch(allocator: std.mem.Allocator, git_path: []const u8, source_path: []const u8, remote_name: []const u8, quiet: bool, cmd_refspecs: []const []const u8, platform_impl: *const platform_mod.Platform, copy_tags: bool) !void {
    const src_git_dir = resolveSourceGitDir(allocator, source_path) catch { const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' does not appear to be a git repository\n", .{source_path}); defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(128); };
    defer allocator.free(src_git_dir);
    const fkey = try std.fmt.allocPrint(allocator, "remote.{s}.fetch", .{remote_name}); defer allocator.free(fkey);
    const cfgp = try std.fmt.allocPrint(allocator, "{s}/config", .{git_path}); defer allocator.free(cfgp);
    const cfgc = platform_impl.fs.readFile(allocator, cfgp) catch ""; defer if (cfgc.len > 0) allocator.free(cfgc);
    var rspecs = std.array_list.Managed([]const u8).init(allocator);
    defer { for (rspecs.items) |rs| allocator.free(rs); rspecs.deinit(); }
    if (cmd_refspecs.len > 0) { for (cmd_refspecs) |rs| try rspecs.append(try allocator.dupe(u8, rs)); }
    else { var fr: ?[]const u8 = null; if (cfgc.len > 0) fr = (parseConfigValue(cfgc, fkey, allocator) catch null) orelse null;
        if (fr) |f| { try rspecs.append(f); } else { try rspecs.append(try std.fmt.allocPrint(allocator, "+refs/heads/*:refs/remotes/{s}/*", .{remote_name})); } }
    const so = try std.fmt.allocPrint(allocator, "{s}/objects", .{src_git_dir}); defer allocator.free(so);
    const do2 = try std.fmt.allocPrint(allocator, "{s}/objects", .{git_path}); defer allocator.free(do2);
    t5CopyMissingObjects(so, do2) catch {};
    const sp2 = try std.fmt.allocPrint(allocator, "{s}/pack", .{so}); defer allocator.free(sp2);
    const dp2 = try std.fmt.allocPrint(allocator, "{s}/pack", .{do2}); defer allocator.free(dp2);
    std.fs.cwd().makePath(dp2) catch {}; t5CopyMissingPackFiles(sp2, dp2) catch {};
    var srl = std.array_list.Managed(RefEntry).init(allocator);
    defer { for (srl.items) |e| { allocator.free(e.name); allocator.free(e.hash); } srl.deinit(); }
    const srp = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{src_git_dir}); defer allocator.free(srp);
    if (std.fs.cwd().readFileAlloc(allocator, srp, 10*1024*1024)) |pc| { defer allocator.free(pc);
        var lines = std.mem.splitScalar(u8, pc, '\n');
        while (lines.next()) |line| { if (line.len == 0 or line[0] == '#' or line[0] == '^') continue;
            if (std.mem.indexOfScalar(u8, line, ' ')) |si| { const h = line[0..si]; const n = line[si+1..]; if (h.len >= 40) try srl.append(.{ .name = try allocator.dupe(u8, n), .hash = try allocator.dupe(u8, h[0..40]) }); } }
    } else |_| {}
    try collectLooseRefs(allocator, src_git_dir, "refs", &srl, platform_impl);
    var fetch_failed = false;
    for (rspecs.items) |rs| { var cs = rs; var cd: ?[]const u8 = null; var force_ref = false;
        if (cs.len > 0 and cs[0] == '+') { force_ref = true; cs = cs[1..]; }
        if (std.mem.indexOf(u8, cs, ":")) |c| { cd = cs[c+1..]; cs = cs[0..c]; }
        for (srl.items) |entry| { if (t5Match(entry.name, cs)) |suffix| { if (cd) |d| { if (d.len > 0) {
            const dn = t5Map(allocator, suffix, d) catch continue; defer allocator.free(dn);
            const drp = try std.fmt.allocPrint(allocator, "{s}/{s}", .{git_path, dn}); defer allocator.free(drp);
            if (std.mem.lastIndexOfScalar(u8, drp, '/')) |ls| std.fs.cwd().makePath(drp[0..ls]) catch {};
            // Check fast-forward if not forced
            if (!force_ref) {
                if (std.fs.cwd().readFileAlloc(allocator, drp, 256)) |old_content| {
                    defer allocator.free(old_content);
                    const old_hash = std.mem.trim(u8, old_content, " \t\r\n");
                    if (old_hash.len >= 40 and !std.mem.eql(u8, old_hash[0..40], entry.hash)) {
                        const is_ff = isAncestor(git_path, old_hash[0..40], entry.hash, allocator, platform_impl) catch false;
                        if (!is_ff) {
                            const emsg = try std.fmt.allocPrint(allocator, " ! [rejected]        {s} -> {s}  (non-fast-forward)\n", .{entry.name, dn});
                            defer allocator.free(emsg);
                            try platform_impl.writeStderr(emsg);
                            fetch_failed = true;
                            continue;
                        }
                    }
                } else |_| {}
            }
            const hnl = try std.fmt.allocPrint(allocator, "{s}\n", .{entry.hash}); defer allocator.free(hnl);
            std.fs.cwd().writeFile(.{ .sub_path = drp, .data = hnl }) catch {};
        } } } } }
    // FETCH_HEAD
    const fhp = try std.fmt.allocPrint(allocator, "{s}/FETCH_HEAD", .{git_path}); defer allocator.free(fhp);
    const shp = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{src_git_dir}); defer allocator.free(shp);
    if (std.fs.cwd().readFileAlloc(allocator, shp, 4096)) |hc| { defer allocator.free(hc);
        const tr = std.mem.trim(u8, hc, " \t\r\n");
        var hh: ?[]const u8 = null; var ho = false;
        if (std.mem.startsWith(u8, tr, "ref: ")) { hh = (refs.resolveRef(src_git_dir, tr["ref: ".len..], platform_impl, allocator) catch null); ho = true; }
        else if (tr.len >= 40) { hh = tr[0..40]; }
        if (hh) |h| { const bn = if (std.mem.startsWith(u8, tr, "ref: refs/heads/")) tr["ref: refs/heads/".len..] else "HEAD";
            const fhc = try std.fmt.allocPrint(allocator, "{s}\t\tbranch '{s}' of {s}\n", .{h, bn, source_path}); defer allocator.free(fhc);
            std.fs.cwd().writeFile(.{ .sub_path = fhp, .data = fhc }) catch {};
            if (ho) allocator.free(h); } } else |_| {}
    // Create remote HEAD symbolic ref
    {
        const src_head_p2 = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{src_git_dir});
        defer allocator.free(src_head_p2);
        if (std.fs.cwd().readFileAlloc(allocator, src_head_p2, 4096)) |hcont| {
            defer allocator.free(hcont);
            const th = std.mem.trim(u8, hcont, " \t\r\n");
            if (std.mem.startsWith(u8, th, "ref: refs/heads/")) {
                const def_branch = th["ref: refs/heads/".len..];
                const rh_path = try std.fmt.allocPrint(allocator, "{s}/refs/remotes/{s}/HEAD", .{ git_path, remote_name });
                defer allocator.free(rh_path);
                if (std.fs.path.dirname(rh_path)) |pd| std.fs.cwd().makePath(pd) catch {};
                const sc = try std.fmt.allocPrint(allocator, "ref: refs/remotes/{s}/{s}\n", .{ remote_name, def_branch });
                defer allocator.free(sc);
                std.fs.cwd().writeFile(.{ .sub_path = rh_path, .data = sc }) catch {};
            }
        } else |_| {}
    }

    // Copy tags (unless --no-tags)
    if (copy_tags) {
        for (srl.items) |entry| { if (std.mem.startsWith(u8, entry.name, "refs/tags/")) {
            const dtp = try std.fmt.allocPrint(allocator, "{s}/{s}", .{git_path, entry.name}); defer allocator.free(dtp);
            if (std.mem.lastIndexOfScalar(u8, dtp, '/')) |ls| std.fs.cwd().makePath(dtp[0..ls]) catch {};
            const hnl = try std.fmt.allocPrint(allocator, "{s}\n", .{entry.hash}); defer allocator.free(hnl);
            std.fs.cwd().writeFile(.{ .sub_path = dtp, .data = hnl }) catch {}; } }
    }
    _ = quiet;
    if (fetch_failed) {
        std.process.exit(1);
    }
}
fn t5Match(rn: []const u8, p: []const u8) ?[]const u8 {
    if (std.mem.endsWith(u8, p, "*")) { const pfx = p[0..p.len-1]; if (std.mem.startsWith(u8, rn, pfx)) return rn[pfx.len..]; }
    else if (std.mem.eql(u8, rn, p)) return "";
    // Handle short refspecs: "main" should match "refs/heads/main"
    if (!std.mem.startsWith(u8, p, "refs/")) {
        if (std.mem.startsWith(u8, rn, "refs/heads/")) {
            const branch = rn["refs/heads/".len..];
            if (std.mem.eql(u8, branch, p)) return "";
        }
        if (std.mem.startsWith(u8, rn, "refs/tags/")) {
            const tag = rn["refs/tags/".len..];
            if (std.mem.eql(u8, tag, p)) return "";
        }
    }
    return null;
}
fn t5Map(a: std.mem.Allocator, suffix: []const u8, dp: []const u8) ![]u8 {
    if (std.mem.endsWith(u8, dp, "*")) return std.fmt.allocPrint(a, "{s}{s}", .{dp[0..dp.len-1], suffix});
    // Expand short ref names
    if (!std.mem.startsWith(u8, dp, "refs/") and dp.len > 0) {
        return std.fmt.allocPrint(a, "refs/heads/{s}", .{dp});
    }
    return a.dupe(u8, dp);
}
fn t5CopyMissingObjects(src: []const u8, dst: []const u8) !void {
    var sd = std.fs.cwd().openDir(src, .{ .iterate = true }) catch return; defer sd.close();
    var it = sd.iterate();
    while (it.next() catch null) |e| { if (e.kind != .directory or e.name.len != 2) continue;
        var sb: [4096]u8 = undefined; var db: [4096]u8 = undefined;
        const ss = std.fmt.bufPrint(&sb, "{s}/{s}", .{src, e.name}) catch continue;
        const dd = std.fmt.bufPrint(&db, "{s}/{s}", .{dst, e.name}) catch continue;
        std.fs.cwd().makePath(dd) catch {};
        var sub = std.fs.cwd().openDir(ss, .{ .iterate = true }) catch continue; defer sub.close();
        var si = sub.iterate();
        while (si.next() catch null) |oe| { if (oe.kind != .file) continue;
            var os: [4096]u8 = undefined; var od: [4096]u8 = undefined;
            const fs = std.fmt.bufPrint(&os, "{s}/{s}", .{ss, oe.name}) catch continue;
            const fd = std.fmt.bufPrint(&od, "{s}/{s}", .{dd, oe.name}) catch continue;
            std.fs.cwd().access(fd, .{}) catch { std.fs.cwd().copyFile(fs, std.fs.cwd(), fd, .{}) catch {}; }; } }
}
fn t5CopyMissingPackFiles(src: []const u8, dst: []const u8) !void {
    var sd = std.fs.cwd().openDir(src, .{ .iterate = true }) catch return; defer sd.close();
    var it = sd.iterate();
    while (it.next() catch null) |e| { if (e.kind != .file) continue;
        if (!std.mem.endsWith(u8, e.name, ".pack") and !std.mem.endsWith(u8, e.name, ".idx") and !std.mem.endsWith(u8, e.name, ".rev") and !std.mem.endsWith(u8, e.name, ".bitmap")) continue;
        var sb: [4096]u8 = undefined; var db: [4096]u8 = undefined;
        const fs = std.fmt.bufPrint(&sb, "{s}/{s}", .{src, e.name}) catch continue;
        const fd = std.fmt.bufPrint(&db, "{s}/{s}", .{dst, e.name}) catch continue;
        std.fs.cwd().access(fd, .{}) catch { std.fs.cwd().copyFile(fs, std.fs.cwd(), fd, .{}) catch {}; }; }
}
fn nativeCmdLsRemote(allocator: std.mem.Allocator, args: [][]const u8, command_index: usize, platform_impl: *const platform_mod.Platform) !void {
    var show_tags = false; var show_heads = false; var symref_flag = false;
    var quiet = false; var ecf = false; var get_url = false;
    var patterns = std.array_list.Managed([]const u8).init(allocator); defer patterns.deinit();
    var remote_arg: ?[]const u8 = null; var saw_dd = false;
    var ii = command_index + 1;
    while (ii < args.len) : (ii += 1) { const arg = args[ii];
        if (saw_dd) { try patterns.append(arg); continue; }
        if (std.mem.eql(u8, arg, "--")) { saw_dd = true; }
        else if (std.mem.eql(u8, arg, "--tags") or std.mem.eql(u8, arg, "-t")) { show_tags = true; }
        else if (std.mem.eql(u8, arg, "--heads") or std.mem.eql(u8, arg, "--branches") or std.mem.eql(u8, arg, "-h") or std.mem.eql(u8, arg, "-b")) { show_heads = true; }
        else if (std.mem.eql(u8, arg, "--quiet") or std.mem.eql(u8, arg, "-q")) { quiet = true; }
        else if (std.mem.eql(u8, arg, "--exit-code")) { ecf = true; }
