        const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' does not appear to be a git repository\nfatal: Could not read from remote repository.\n\nPlease make sure you have the correct access rights\nand the repository exists.\n", .{rn});
        defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(128); };
    defer allocator.free(tgd);
    if (get_url) { var du: []const u8 = rn; var duo: ?[]u8 = null; defer if (duo) |u| allocator.free(u);
        if (findGitDir() catch null) |gd| { if (getRemoteUrl(gd, rn, platform_impl, allocator)) |u| { duo = u; du = u; } else |_| {} }
        const o = try std.fmt.allocPrint(allocator, "{s}\n", .{du}); defer allocator.free(o); try platform_impl.writeStdout(o); return; }
    if (quiet) return;
    { var du: []const u8 = rn; var duo: ?[]u8 = null; defer if (duo) |u| allocator.free(u);
      if (findGitDir() catch null) |gd| { if (getRemoteUrl(gd, rn, platform_impl, allocator)) |u| { duo = u; du = u; } else |_| {} }
      const fm = try std.fmt.allocPrint(allocator, "From {s}\n", .{du}); defer allocator.free(fm); try platform_impl.writeStderr(fm); }
    var rl = std.array_list.Managed(RefEntry).init(allocator);
    defer { for (rl.items) |e| { allocator.free(e.name); allocator.free(e.hash); } rl.deinit(); }
    var pm = std.StringHashMap([]const u8).init(allocator);
    defer { var pit = pm.iterator(); while (pit.next()) |e| { allocator.free(e.key_ptr.*); allocator.free(e.value_ptr.*); } pm.deinit(); }
    var hs: ?[]const u8 = null; defer if (hs) |t| allocator.free(t);
    const hp = try std.fmt.allocPrint(allocator, "{s}/HEAD", .{tgd}); defer allocator.free(hp);
    if (std.fs.cwd().readFileAlloc(allocator, hp, 4096)) |hc| { defer allocator.free(hc); const tr = std.mem.trim(u8, hc, " \t\r\n");
        if (std.mem.startsWith(u8, tr, "ref: ")) { hs = try allocator.dupe(u8, tr["ref: ".len..]);
            if (refs.resolveRef(tgd, tr["ref: ".len..], platform_impl, allocator) catch null) |h2| { defer allocator.free(h2); try rl.append(.{ .name = try allocator.dupe(u8, "HEAD"), .hash = try allocator.dupe(u8, h2) }); }
        } else if (tr.len >= 40) { try rl.append(.{ .name = try allocator.dupe(u8, "HEAD"), .hash = try allocator.dupe(u8, tr[0..40]) }); } } else |_| {}
    const pp = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{tgd}); defer allocator.free(pp);
    if (std.fs.cwd().readFileAlloc(allocator, pp, 10*1024*1024)) |pc| { defer allocator.free(pc); var lines = std.mem.splitScalar(u8, pc, '\n'); var lrn3: ?[]const u8 = null;
        while (lines.next()) |line| { if (line.len == 0 or line[0] == '#') continue;
            if (line[0] == '^') { if (lrn3) |l| { const ph = std.mem.trim(u8, line[1..], " \t\r\n"); if (ph.len >= 40) try pm.put(try allocator.dupe(u8, l), try allocator.dupe(u8, ph[0..40])); } continue; }
            if (std.mem.indexOfScalar(u8, line, ' ')) |si| { const h = line[0..si]; const n = line[si+1..]; if (h.len >= 40) { var d = false; for (rl.items) |e| { if (std.mem.eql(u8, e.name, n)) { d = true; break; } } if (!d) { try rl.append(.{ .name = try allocator.dupe(u8, n), .hash = try allocator.dupe(u8, h[0..40]) }); lrn3 = rl.items[rl.items.len-1].name; } } } } } else |_| {}
    try collectLooseRefs(allocator, tgd, "refs", &rl, platform_impl);
    std.mem.sort(RefEntry, rl.items, {}, struct { fn lt(_: void, a: RefEntry, b: RefEntry) bool { if (std.mem.eql(u8, a.name, "HEAD")) return true; if (std.mem.eql(u8, b.name, "HEAD")) return false; return std.mem.order(u8, a.name, b.name).compare(.lt); } }.lt);
    var fa = false;
    for (rl.items) |entry| { if (entry.broken) continue;
        if (show_tags and !show_heads and !std.mem.startsWith(u8, entry.name, "refs/tags/")) continue;
        if (show_heads and !show_tags and !std.mem.startsWith(u8, entry.name, "refs/heads/")) continue;
        if (show_heads and show_tags and !std.mem.startsWith(u8, entry.name, "refs/heads/") and !std.mem.startsWith(u8, entry.name, "refs/tags/")) continue;
        if (patterns.items.len > 0) { var m = false; for (patterns.items) |p| { if (t5LsMatch(entry.name, p)) { m = true; break; } } if (!m) continue; }
        fa = true;
        if (symref_flag and std.mem.eql(u8, entry.name, "HEAD")) { if (hs) |t| { const so = try std.fmt.allocPrint(allocator, "ref: {s}\tHEAD\n", .{t}); defer allocator.free(so); try platform_impl.writeStdout(so); } }
        const o = try std.fmt.allocPrint(allocator, "{s}\t{s}\n", .{entry.hash, entry.name}); defer allocator.free(o); try platform_impl.writeStdout(o);
        if (std.mem.startsWith(u8, entry.name, "refs/tags/")) { if (pm.get(entry.name)) |ph| { const po = try std.fmt.allocPrint(allocator, "{s}\t{s}^{{}}\n", .{ph, entry.name}); defer allocator.free(po); try platform_impl.writeStdout(po); } } }
    if (ecf and !fa) std.process.exit(2);
}
fn t5LsMatch(rn: []const u8, p: []const u8) bool {
    if (std.mem.eql(u8, rn, p)) return true;
    if (std.mem.endsWith(u8, p, "*")) { const pfx = p[0..p.len-1]; if (std.mem.startsWith(u8, rn, pfx)) return true;
        if (!std.mem.startsWith(u8, p, "refs/") and std.mem.startsWith(u8, rn, "refs/")) { if (std.mem.startsWith(u8, rn["refs/".len..], pfx)) return true; } }
    if (std.mem.endsWith(u8, rn, p)) { if (rn.len == p.len) return true; if (rn.len > p.len and rn[rn.len-p.len-1] == '/') return true; }
    if (!std.mem.startsWith(u8, p, "refs/") and std.mem.startsWith(u8, rn, "refs/")) { const s = rn["refs/".len..]; if (std.mem.eql(u8, s, p)) return true;
        if (std.mem.endsWith(u8, s, p) and s.len > p.len and s[s.len-p.len-1] == '/') return true; }
    return false;
}
fn t5ResolveRemote(allocator: std.mem.Allocator, rn: []const u8, platform_impl: *const platform_mod.Platform) ![]const u8 {
    var path = rn;
    if (std.mem.startsWith(u8, path, "file://")) { path = path["file://".len..]; return resolveSourceGitDir(allocator, path); }
    if (std.mem.startsWith(u8, path, "/") or std.mem.startsWith(u8, path, "./") or std.mem.startsWith(u8, path, "../") or std.mem.eql(u8, path, ".") or std.mem.eql(u8, path, "..") or std.mem.endsWith(u8, path, ".git")) return resolveSourceGitDir(allocator, path);
    const gd = findGitDir() catch return error.NotAGitRepository;
    const url = getRemoteUrl(gd, rn, platform_impl, allocator) catch return error.NotAGitRepository;
    defer allocator.free(url);
    if (std.mem.startsWith(u8, url, "file://")) return resolveSourceGitDir(allocator, url["file://".len..]);
    if (std.mem.startsWith(u8, url, "/") or std.mem.startsWith(u8, url, "./") or std.mem.startsWith(u8, url, "../") or std.mem.eql(u8, url, ".") or std.mem.eql(u8, url, "..")) return resolveSourceGitDir(allocator, url);
    return resolveSourceGitDir(allocator, rn) catch return error.NotAGitRepository;
}
fn t5FindSingle(allocator: std.mem.Allocator, git_dir: []const u8) ?[]u8 {
    const cp = std.fmt.allocPrint(allocator, "{s}/config", .{git_dir}) catch return null; defer allocator.free(cp);
    const cc = std.fs.cwd().readFileAlloc(allocator, cp, 10*1024*1024) catch return null; defer allocator.free(cc);
    var first: ?[]u8 = null; var count: usize = 0;
    var li = std.mem.splitScalar(u8, cc, '\n');
    while (li.next()) |lr| { const lt = std.mem.trim(u8, lr, " \t\r");
        if (std.mem.startsWith(u8, lt, "[remote \"")) { const rest = lt["[remote \"".len..];
            if (std.mem.indexOf(u8, rest, "\"")) |end| { if (count == 0) first = allocator.dupe(u8, rest[0..end]) catch return null; count += 1; if (count > 1) { if (first) |f| allocator.free(f); return null; } } } }
    if (count == 1) return first; if (first) |f| allocator.free(f); return null;
}

fn readRefDirect(git_dir: []const u8, ref_name: []const u8, allocator: std.mem.Allocator, platform_impl: *const platform_mod.Platform) !?[]u8 {
    var current_ref = try allocator.dupe(u8, ref_name);
    defer allocator.free(current_ref);
    var depth: u32 = 0;
    while (depth < 20) : (depth += 1) {
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, current_ref });
        defer allocator.free(ref_path);
        const content = platform_impl.fs.readFile(allocator, ref_path) catch {
            const packed_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir});
            defer allocator.free(packed_path);
            const packed_data = platform_impl.fs.readFile(allocator, packed_path) catch return null;
            defer allocator.free(packed_data);
            var lines = std.mem.splitScalar(u8, packed_data, '\n');
            while (lines.next()) |line| {
                if (line.len == 0 or line[0] == '#') continue;
                if (line.len >= 41 and line[40] == ' ') {
                    const packed_ref = std.mem.trim(u8, line[41..], " \t\r");
                    if (std.mem.eql(u8, packed_ref, current_ref)) return try allocator.dupe(u8, line[0..40]);
                }
            }
            return null;
        };
        defer allocator.free(content);
        const trimmed = std.mem.trim(u8, content, " \t\r\n");
        if (std.mem.startsWith(u8, trimmed, "ref: ")) {
            const target = trimmed["ref: ".len..];
            allocator.free(current_ref);
            current_ref = try allocator.dupe(u8, target);
            continue;
        }
        if (trimmed.len >= 40) return try allocator.dupe(u8, trimmed[0..40]);
        return null;
    }
    return null;
}

fn cmdDaemon(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    while (args.next()) |arg| {
        if (std.mem.startsWith(u8, arg, "--init-timeout=")) {
            const val = arg["--init-timeout=".len..];
            const parsed = std.fmt.parseInt(i64, val, 10) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: invalid init-timeout '{s}', expecting a non-negative integer\n", .{val});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            };
            if (parsed < 0) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: invalid init-timeout '{s}', expecting a non-negative integer\n", .{val});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            }
        } else if (std.mem.startsWith(u8, arg, "--timeout=")) {
            const val = arg["--timeout=".len..];
            const parsed = std.fmt.parseInt(i64, val, 10) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: invalid timeout '{s}', expecting a non-negative integer\n", .{val});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            };
            if (parsed < 0) {
                const msg = try std.fmt.allocPrint(allocator, "fatal: invalid timeout '{s}', expecting a non-negative integer\n", .{val});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            }
        } else if (std.mem.startsWith(u8, arg, "--max-connections=")) {
            const val = arg["--max-connections=".len..];
            _ = std.fmt.parseInt(i64, val, 10) catch {
                const msg = try std.fmt.allocPrint(allocator, "fatal: invalid max-connections '{s}', expecting an integer\n", .{val});
                defer allocator.free(msg);
                try platform_impl.writeStderr(msg);
                std.process.exit(1);
            };
        }
    }
    try platform_impl.writeStderr("fatal: daemon not fully implemented\n");
    std.process.exit(1);
}

fn cmdCheckRefFormat(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var allow_onelevel = false;
    var refspec_pattern = false;
    var normalize = false;
    var no_allow_onelevel = false;
    var branch_mode = false;
    var refname: ?[]const u8 = null;
    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "--allow-onelevel")) { allow_onelevel = true; }
        else if (std.mem.eql(u8, arg, "--no-allow-onelevel")) { no_allow_onelevel = true; }
        else if (std.mem.eql(u8, arg, "--refspec-pattern")) { refspec_pattern = true; }
        else if (std.mem.eql(u8, arg, "--normalize")) { normalize = true; }
        else if (std.mem.eql(u8, arg, "--branch")) { branch_mode = true; }
        else if (std.mem.eql(u8, arg, "--print")) { normalize = true; }
        else if (arg.len > 0 and arg[0] != '-') { if (refname == null) refname = arg; }
    }
    if (branch_mode) {
        const name = refname orelse { std.process.exit(128); unreachable; };
        if (name.len > 2 and name[0] == '@' and name[1] == '{' and name[name.len - 1] == '}') {
            try platform_impl.writeStderr("fatal: no previous branch\n"); std.process.exit(128); unreachable;
        }
        if (name.len > 0 and name[0] == '-') {
            const msg = try std.fmt.allocPrint(allocator, "fatal: '{s}' is not a valid branch name\n", .{name});
            defer allocator.free(msg); try platform_impl.writeStderr(msg); std.process.exit(128); unreachable;
        }
        const output = try std.fmt.allocPrint(allocator, "{s}\n", .{name});
        defer allocator.free(output); try platform_impl.writeStdout(output); return;
    }
    const name = refname orelse { std.process.exit(1); unreachable; };
    if (normalize) {
        const nrm = normalizeRefName_crf(allocator, name, allow_onelevel, refspec_pattern) catch { std.process.exit(1); unreachable; };
        defer allocator.free(nrm);
        const output = try std.fmt.allocPrint(allocator, "{s}\n", .{nrm});
        defer allocator.free(output); try platform_impl.writeStdout(output); return;
    }
    if (!checkRefFormatValid_crf(name, allow_onelevel, no_allow_onelevel, refspec_pattern)) { std.process.exit(1); unreachable; }
}

fn normalizeRefName_crf(allocator: std.mem.Allocator, name: []const u8, allow_onelevel: bool, refspec_pattern: bool) ![]u8 {
    if (name.len == 0) return error.InvalidRefName;
    var buf: [4096]u8 = undefined;
    var pos: usize = 0;
    var prev_slash = true;
    for (name) |ch| {
        if (ch == '/') { if (!prev_slash) { if (pos >= buf.len) return error.InvalidRefName; buf[pos] = '/'; pos += 1; } prev_slash = true; }
        else { prev_slash = false; if (pos >= buf.len) return error.InvalidRefName; buf[pos] = ch; pos += 1; }
    }
    while (pos > 0 and buf[pos - 1] == '/') pos -= 1;
    if (pos == 0) return error.InvalidRefName;
    if (!checkRefFormatValid_crf(buf[0..pos], allow_onelevel, false, refspec_pattern)) return error.InvalidRefName;
    return try allocator.dupe(u8, buf[0..pos]);
}

fn checkRefFormatValid_crf(name: []const u8, allow_onelevel: bool, no_allow_onelevel: bool, refspec_pattern: bool) bool {
    if (name.len == 0) return false;
    if (name.len == 1 and name[0] == '/') return false;
    const has_slash = std.mem.indexOfScalar(u8, name, '/') != null;
    if (!has_slash and !allow_onelevel) return false;
    if (!has_slash and no_allow_onelevel) return false;
    var star_count: usize = 0;
    var it = std.mem.splitScalar(u8, name, '/');
    while (it.next()) |component| {
        if (component.len == 0) return false;
        if (component[0] == '.') return false;
        if (std.mem.endsWith(u8, component, ".lock")) return false;
        for (component, 0..) |ch, ci| {
            if (ch < 0x20 or ch == 0x7f) return false;
            if (ch == ' ' or ch == '~' or ch == '^' or ch == ':' or ch == '[' or ch == '\\') return false;
            if (ch == '?') return false;
            if (ch == '*') { if (!refspec_pattern) return false; star_count += 1; if (star_count > 1) return false; }
            if (ch == '@' and ci + 1 < component.len and component[ci + 1] == '{') return false;
        }
        if (std.mem.indexOf(u8, component, "..") != null) return false;
    }
    if (name[name.len - 1] == '/') return false;
    if (name[name.len - 1] == '.') return false;
    return true;
}

const LastModTreeEntry = struct { path: []const u8, is_tree: bool };

fn cmdLastModified(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    var recursive = false;
    var show_trees = false;
    var rev: ?[]const u8 = null;
    var lm_paths = std.array_list.Managed([]const u8).init(allocator);
    defer lm_paths.deinit();

    while (args.next()) |arg| {
        if (std.mem.eql(u8, arg, "-r")) {
            recursive = true;
        } else if (std.mem.eql(u8, arg, "-t")) {
            show_trees = true;
        } else if (std.mem.eql(u8, arg, "--")) {
            while (args.next()) |p| try lm_paths.append(p);
            break;
        } else if (arg.len > 1 and arg[0] == '-' and arg[1] == '-') {
            const msg = try std.fmt.allocPrint(allocator, "unknown last-modified argument: {s}\n", .{arg});
            defer allocator.free(msg);
            try platform_impl.writeStderr(msg);
            std.process.exit(128);
        } else {
            // Could be rev or path - collect for later disambiguation
            try lm_paths.append(arg);
        }
    }

    // Disambiguate: first positional arg might be a rev
    // Try to resolve it; if it fails, treat as path

    const git_path = findGitDirectory(allocator, platform_impl) catch {
        try platform_impl.writeStderr("fatal: not a git repository\n");
        std.process.exit(128);
    };
    defer allocator.free(git_path);

    // Try to resolve first positional arg as revision
    if (lm_paths.items.len > 0 and rev == null) {
        const first_arg = lm_paths.items[0];
        const resolved_try = resolveRevision(git_path, first_arg, platform_impl, allocator) catch null;
        if (resolved_try) |r| {
            allocator.free(r);
            rev = first_arg;
            // Remove from paths
            _ = lm_paths.orderedRemove(0);
        }
    }

    // Check for multiple revisions
    if (rev != null and lm_paths.items.len > 0) {
        // Check if any remaining args look like revisions
        for (lm_paths.items) |p| {
            const r2 = resolveRevision(git_path, p, platform_impl, allocator) catch null;
            if (r2) |r| {
                allocator.free(r);
                try platform_impl.writeStderr("last-modified can only operate on one commit at a time\n");
                std.process.exit(128);
            }
        }
    }

    const commit_hash: []u8 = blk: {
        if (rev) |r| {
            const resolved = resolveRevision(git_path, r, platform_impl, allocator) catch {
                const msg2 = try std.fmt.allocPrint(allocator, "fatal: bad revision '{s}'\n", .{r});
                defer allocator.free(msg2);
                try platform_impl.writeStderr(msg2);
                std.process.exit(128);
                unreachable;
            };
            // Check if it resolves to a tree (not a commit)
            const obj = objects.GitObject.load(resolved, git_path, platform_impl, allocator) catch break :blk resolved;
            defer obj.deinit(allocator);
            if (obj.type == .tree) {
                const msg2 = try std.fmt.allocPrint(allocator, "revision argument '{s}' is a tree, not a commit-ish\n", .{r});
                defer allocator.free(msg2);
                try platform_impl.writeStderr(msg2);
                allocator.free(resolved);
                std.process.exit(128);
            }
            if (obj.type == .tag) {
                const tag_target = parseTagObject(obj.data, allocator) catch break :blk resolved;
                allocator.free(resolved);
                break :blk tag_target;
            }
            break :blk resolved;
        } else {
            const h = refs.getCurrentCommit(git_path, platform_impl, allocator) catch {
                try platform_impl.writeStderr("fatal: no commits\n");
                std.process.exit(128);
                unreachable;
            };
            break :blk h orelse {
                try platform_impl.writeStderr("fatal: no commits\n");
                std.process.exit(128);
                unreachable;
            };
        }
    };
    defer allocator.free(commit_hash);

    // Get tree hash from commit
    const commit_obj = objects.GitObject.load(commit_hash, git_path, platform_impl, allocator) catch {
        try platform_impl.writeStderr("fatal: bad commit\n");
        std.process.exit(128);
        unreachable;
    };
    defer commit_obj.deinit(allocator);
    var tree_hash: ?[]const u8 = null;
    var tli = std.mem.splitScalar(u8, commit_obj.data, '\n');
    while (tli.next()) |line| {
        if (std.mem.startsWith(u8, line, "tree ")) { tree_hash = line["tree ".len..]; break; }
        if (line.len == 0) break;
    }
    if (tree_hash == null) { try platform_impl.writeStderr("fatal: bad commit\n"); std.process.exit(128); }

    var entries = std.array_list.Managed(LastModTreeEntry).init(allocator);
    defer { for (entries.items) |e| allocator.free(e.path); entries.deinit(); }

    if (recursive) {
        try lmCollectRecursive(allocator, git_path, tree_hash.?, "", &entries, show_trees, platform_impl);
    } else {
        try lmCollectTopLevel(allocator, git_path, tree_hash.?, &entries, platform_impl);
    }

    // Filter by paths if specified
    for (entries.items) |entry| {
        if (lm_paths.items.len > 0) {
            var matched = false;
            for (lm_paths.items) |p| {
                if (std.mem.eql(u8, entry.path, p) or std.mem.startsWith(u8, entry.path, p)) { matched = true; break; }
            }
            if (!matched) continue;
        }
        const last_commit = lmFindLastModified(allocator, git_path, commit_hash, entry.path, platform_impl) catch commit_hash;
        const out = try std.fmt.allocPrint(allocator, "{s}\t{s}\n", .{ last_commit, entry.path });
        defer allocator.free(out);
        try platform_impl.writeStdout(out);
    }
}

fn lmCollectTopLevel(allocator: std.mem.Allocator, git_path: []const u8, tree_hash: []const u8, entries: *std.array_list.Managed(LastModTreeEntry), platform_impl: *const platform_mod.Platform) !void {
    const tree_obj = try objects.GitObject.load(tree_hash, git_path, platform_impl, allocator);
    defer tree_obj.deinit(allocator);
    var pos: usize = 0;
    while (pos < tree_obj.data.len) {
        const sp = std.mem.indexOfScalarPos(u8, tree_obj.data, pos, ' ') orelse break;
        const mode = tree_obj.data[pos..sp];
        pos = sp + 1;
        const np = std.mem.indexOfScalarPos(u8, tree_obj.data, pos, 0) orelse break;
        const name = tree_obj.data[pos..np];
        pos = np + 1;
        if (pos + 20 > tree_obj.data.len) break;
        pos += 20;
        try entries.append(.{ .path = try allocator.dupe(u8, name), .is_tree = std.mem.eql(u8, mode, "40000") });
    }
}

fn lmCollectRecursive(allocator: std.mem.Allocator, git_path: []const u8, tree_hash: []const u8, prefix: []const u8, entries: *std.array_list.Managed(LastModTreeEntry), show_trees: bool, platform_impl: *const platform_mod.Platform) !void {
    const tree_obj = objects.GitObject.load(tree_hash, git_path, platform_impl, allocator) catch return;
    defer tree_obj.deinit(allocator);
    var pos: usize = 0;
    while (pos < tree_obj.data.len) {
        const sp = std.mem.indexOfScalarPos(u8, tree_obj.data, pos, ' ') orelse break;
        const mode = tree_obj.data[pos..sp];
        pos = sp + 1;
        const np = std.mem.indexOfScalarPos(u8, tree_obj.data, pos, 0) orelse break;
        const name = tree_obj.data[pos..np];
        pos = np + 1;
        if (pos + 20 > tree_obj.data.len) break;
        const hash_bytes = tree_obj.data[pos..pos + 20];
        pos += 20;
        const full_path = if (prefix.len > 0) try std.fmt.allocPrint(allocator, "{s}/{s}", .{ prefix, name }) else try allocator.dupe(u8, name);
        const is_tree = std.mem.eql(u8, mode, "40000");
        if (is_tree) {
            if (show_trees) try entries.append(.{ .path = try allocator.dupe(u8, full_path), .is_tree = true });
            var hash_hex: [40]u8 = undefined;
            for (hash_bytes, 0..) |b, bi| { hash_hex[bi * 2] = "0123456789abcdef"[b >> 4]; hash_hex[bi * 2 + 1] = "0123456789abcdef"[b & 0xf]; }
            try lmCollectRecursive(allocator, git_path, &hash_hex, full_path, entries, show_trees, platform_impl);
            allocator.free(full_path);
        } else {
            try entries.append(.{ .path = full_path, .is_tree = false });
        }
    }
}

fn lmFindLastModified(allocator: std.mem.Allocator, git_path: []const u8, start_hash: []const u8, path: []const u8, platform_impl: *const platform_mod.Platform) ![]const u8 {
    var current = try allocator.dupe(u8, start_hash);
    var iterations: usize = 0;
    while (iterations < 10000) : (iterations += 1) {
        const co = objects.GitObject.load(current, git_path, platform_impl, allocator) catch break;
        defer co.deinit(allocator);
        var parent: ?[]const u8 = null;
        var li = std.mem.splitScalar(u8, co.data, '\n');
        while (li.next()) |line| {
            if (std.mem.startsWith(u8, line, "parent ") and parent == null) parent = line["parent ".len..];
            if (line.len == 0) break;
        }
        if (parent == null) return current;
        const cur_hash = getTreeEntryHashFromCommit(git_path, current, path, allocator) catch return current;
        defer allocator.free(cur_hash);
        const par_hash = getTreeEntryHashFromCommit(git_path, parent.?, path, allocator) catch return current;
        defer allocator.free(par_hash);
        if (!std.mem.eql(u8, cur_hash, par_hash)) return current;
        const next = try allocator.dupe(u8, parent.?);
        allocator.free(current);
        current = next;
    }
    return current;
}

fn cmdRefs(allocator: std.mem.Allocator, args: *platform_mod.ArgIterator, platform_impl: *const platform_mod.Platform) !void {
    const subcmd = args.next() orelse {
        try platform_impl.writeStderr("usage: git refs <subcommand>\n");
        std.process.exit(129);
        unreachable;
    };
    
    if (std.mem.eql(u8, subcmd, "exists")) {
        const ref_name = args.next() orelse {
            try platform_impl.writeStderr("error: refs exists requires a ref argument\n");
            std.process.exit(129);
            unreachable;
        };
        
        const git_dir = findGitDirectory(allocator, platform_impl) catch {
            try platform_impl.writeStderr("fatal: not a git repository\n");
            std.process.exit(128);
            unreachable;
        };
        defer allocator.free(git_dir);
        
        const ref_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ git_dir, ref_name });
        defer allocator.free(ref_path);
        
        if (std.fs.cwd().access(ref_path, .{})) |_| {
            // Check not a directory
            const stat = std.fs.cwd().statFile(ref_path) catch return;
            if (stat.kind == .directory) {
                try platform_impl.writeStderr("error: reference does not exist\n");
                std.process.exit(2);
                unreachable;
            }
            return; // exists
        } else |_| {
            // Check packed-refs
            const packed_path = try std.fmt.allocPrint(allocator, "{s}/packed-refs", .{git_dir});
            defer allocator.free(packed_path);
            const packed_data = platform_impl.fs.readFile(allocator, packed_path) catch {
                try platform_impl.writeStderr("error: reference does not exist\n");
                std.process.exit(2);
                unreachable;
            };
            defer allocator.free(packed_data);
            var lines = std.mem.splitScalar(u8, packed_data, '\n');
            while (lines.next()) |line| {
                if (line.len == 0 or line[0] == '#') continue;
                if (line.len >= 41 and line[40] == ' ') {
                    const packed_ref = std.mem.trim(u8, line[41..], " \t\r");
                    if (std.mem.eql(u8, packed_ref, ref_name)) return;
                }
            }
            try platform_impl.writeStderr("error: reference does not exist\n");
            std.process.exit(2);
            unreachable;
        }
    } else {
        const msg = try std.fmt.allocPrint(allocator, "error: unknown subcommand '{s}'\n", .{subcmd});
        defer allocator.free(msg);
        try platform_impl.writeStderr(msg);
        std.process.exit(1);
        unreachable;
    }
}

